# v3.280: 统一日志函数 - 同时print和写入server.log
# v3.560 P1-11a: 使用RotatingFileHandler替代bare open()
# v3.660+: 修复 OneDrive 路径下 stream.tell() OSError [Errno 22]
_SERVER_LOG_PATH_EARLY = os.path.join(LOG_DIR, "server.log")
import logging as _logging_server
from logging.handlers import RotatingFileHandler as _RotatingFileHandler

class _SafeRotatingFileHandler(_RotatingFileHandler):
    """RotatingFileHandler 子类：捕获 OneDrive/网络路径上所有 OSError [Errno 22]。
    - shouldRollover: stream.tell() 失败时跳过轮转
    - flush: stream.flush() 失败时静默忽略
    - emit: 整体捕获，确保写入失败不产生 '--- Logging error ---' 输出
    """
    def shouldRollover(self, record):
        try:
            return super().shouldRollover(record)
        except OSError:
            return 0

    def flush(self):
        try:
            super().flush()
        except OSError:
            pass

    def emit(self, record):
        try:
            super().emit(record)
        except OSError:
            pass

_server_log_handler = _SafeRotatingFileHandler(
    _SERVER_LOG_PATH_EARLY, maxBytes=50*1024*1024, backupCount=5, encoding='utf-8'
)
_server_log_handler.setFormatter(_logging_server.Formatter('%(asctime)s %(message)s', datefmt='%Y-%m-%d %H:%M:%S'))
_server_logger = _logging_server.getLogger("server_log")
_server_logger.addHandler(_server_log_handler)
_server_logger.setLevel(_logging_server.INFO)

def log_to_server(msg: str):
    """v3.280: 统一日志输出函数，同时print到控制台和写入server.log"""
    print(msg, flush=True)
    try:
        _server_logger.info(msg)
    except Exception:
        pass

