# v3.679: 观察模式结构化日志 — S1/S2/S3/S4/P0/CycleSwitch信号写入JSONL
_OBSERVE_LOG_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "state", "gcc_observe_log.jsonl")
def _log_observe_signal(channel: str, symbol: str, action: str, price: float, reason: str = ""):
    """写入观察模式信号到结构化日志"""
    try:
        from datetime import datetime as _obs_dt
        import json as _obs_json
        entry = _obs_json.dumps({
            "ts": _obs_dt.now().strftime("%Y-%m-%d %H:%M:%S"),
            "channel": channel,
            "symbol": symbol,
            "action": action,
            "price": round(price, 4),
            "reason": reason,
        }, ensure_ascii=False)
        with open(_OBSERVE_LOG_PATH, "a", encoding="utf-8") as f:
            f.write(entry + "\n")
    except Exception:
        pass

# -----------------------------------------------------------------------------
# 0.8a 品种参数加载器 (v3.661: PARAM_YAML)
# -----------------------------------------------------------------------------
# Phase1: 读YAML→与硬编码值比对→log差异, 实际仍用硬编码值
_symbol_params_cache = {}  # {symbol: {params_dict}}
_PARAM_YAML_PHASE2 = False  # Phase2全局开关（保持False直到所有参数验证完毕）
# v3.662: 按section独立开启Phase2，避免全量切换风险
# timing.side_cooldown_hours: CRWV→8h, HIMS/NBIS/RKLB→6h (2026-02-20 whipsaw降频)
_PARAM_YAML_PHASE2_SECTIONS = {"timing"}  # 已验证可开启的section

def load_symbol_params(symbol: str) -> dict:
    """
    v3.661: 读取品种参数YAML, 无文件返回空dict(使用默认值)
    缓存结果避免重复IO。
    """
    if symbol in _symbol_params_cache:
        return _symbol_params_cache[symbol]
    try:
        import yaml
        param_path = os.path.join(".gcc", "params", f"{symbol}.yaml")
        if os.path.exists(param_path):
            with open(param_path, 'r', encoding='utf-8') as f:
                data = yaml.safe_load(f) or {}
            _symbol_params_cache[symbol] = data
            return data
    except Exception as e:
        log_to_server(f"[PARAM_YAML] {symbol} YAML读取异常: {e}")
    _symbol_params_cache[symbol] = {}
    return {}


def _log_param_yaml(symbol: str, param_name: str, yaml_val, hardcoded_val):
    """v3.661: Phase1参数比对日志"""
    tag = "SAME" if yaml_val == hardcoded_val else "DIFF"
    log_to_server(f"[PARAM_YAML] {symbol} {param_name}: yaml={yaml_val} hardcoded={hardcoded_val} {tag}")


def get_symbol_param(symbol: str, *keys, default=None):
    """
    v3.661: 从YAML获取品种参数, 支持嵌套key路径。
    例: get_symbol_param("NBIS", "n_gate", "side_max_trades", default=1)
    Phase2=True时返回YAML值, Phase1返回default(硬编码值)。
    """
    params = load_symbol_params(symbol)
    val = params
    for k in keys:
        if isinstance(val, dict):
            val = val.get(k)
        else:
            val = None
            break
    if val is None:
        return default
    # v3.662: section级Phase2 — timing已开启, 其余仍Phase1记录
    section = keys[0] if keys else ""
    phase2_active = _PARAM_YAML_PHASE2 or (section in _PARAM_YAML_PHASE2_SECTIONS)
    if not phase2_active:
        _log_param_yaml(symbol, ".".join(keys), val, default)
        return default
    # Phase2: 使用YAML值
    log_to_server(f"[PARAM_YAML][P2] {symbol} {'.'.join(keys)}: {val} (was {default})")
    return val

