def _find_sub_timeframe(symbol: str, current_tf: int) -> tuple:
    """
    v3.640: 查找缠论算法的子周期数据源

    规则:
    1. 理想子周期 = 当前周期 / 4
    2. 如果后台缓存有 → 使用, 窗口=12根 (3个当前周期K线, 确保三段判定)
    3. 如果没有 → 选最小的可用后台周期, 窗口=当前周期/该周期*3
    4. 都没有 → 返回 None

    窗口=12根的原因:
      当前周期4H, 子周期1H → 12根1H = 3根4H
      缠论三段判定需要至少3根合并后K线
      12根子K线经过包含关系合并后, 保证有>=3根独立K线做判定

    Returns: (sub_tf, window_size, source_desc) or (None, 0, "none")
    """
    bg_tfs = BACKGROUND_TIMEFRAMES.get(symbol, [])
    ideal_sub = current_tf // 4  # 240→60, 120→30

    if ideal_sub in bg_tfs:
        return ideal_sub, 12, f"12x{ideal_sub}m"

    # 理想不可用 → 找最小可用的(但要比当前周期小)
    smaller = sorted([tf for tf in bg_tfs if tf < current_tf])
    if smaller:
        best = smaller[0]  # 最小的
        ratio = current_tf // best
        window = ratio * 3  # 前3个当前周期K线
        return best, window, f"{window}x{best}m"

    return None, 0, "none"

