def _vision_call_inline(symbol: str, ohlcv_bars: list) -> dict:
    """
    v3.670: 直接调用GPT Vision API分析，使用主程序已有的OHLCV数据
    Returns: {"current": {...}, "source": "inline"} 或 None
    """
    if not _VISION_INLINE_AVAILABLE:
        return None
    if not ohlcv_bars or len(ohlcv_bars) < 15:
        log_to_server(f"[VISION_INLINE][{symbol}] K线不足({len(ohlcv_bars) if ohlcv_bars else 0}根)，跳过")
        return None

    try:
        # 取最近30根K线生成图表
        bars_for_chart = ohlcv_bars[-30:]
        chart_b64 = generate_simple_trend_chart(bars_for_chart, f"{symbol} - {len(bars_for_chart)} bars")
        if not chart_b64:
            log_to_server(f"[VISION_INLINE][{symbol}] 图表生成失败")
            return None

        # 获取动态label
        _tf = read_symbol_timeframe(symbol, default=240)
        _is_crypto = symbol in _VISION_SYMBOLS and _VISION_SYMBOLS[symbol].get("type") == "crypto"
        _params = get_timeframe_params(_tf, is_crypto=_is_crypto)

        # 调用API (仅当前周期)
        log_to_server(f"[VISION_INLINE][{symbol}] 调用GPT Vision API...")
        current_result = call_vision_api(chart_b64, period="current",
                                          current_label=_params["current_label"],
                                          x4_label=_params["x4_label"])

        if not current_result:
            log_to_server(f"[VISION_INLINE][{symbol}] API返回空")
            return None

        log_to_server(
            f"[VISION_INLINE][{symbol}] 成功: {current_result.get('regime','?')} "
            f"{current_result.get('direction','?')} conf={current_result.get('confidence',0):.0%}"
        )

        # 保存到latest.json供后续读取
        try:
            _vision_save_latest(symbol, current_result, None)
        except Exception:
            pass

        return {
            "current": current_result,
            "x4": None,
            "source": "inline",
        }

    except Exception as e:
        log_to_server(f"[VISION_INLINE][{symbol}] 异常: {e}")
        return None


def read_vision_result(symbol: str, ignore_ttl: bool = False, ohlcv_bars: list = None,
                       force_refresh: bool = False) -> dict:
    """
    v3.670: 读取Vision结果，过期时自动调用API刷新

    优先级: 内存缓存 → 文件缓存 → 在线调用API

    Args:
        symbol: 品种代码
        ignore_ttl: 忽略TTL (校准器用)
        ohlcv_bars: 主程序OHLCV数据 (用于inline调用)
        force_refresh: 强制刷新 — 跳过所有缓存+冷却，直接调API
                       (GCC-TM candle open时使用，确保新K线拿到新鲜Vision)
    """
    import time as _time
    now = _time.time()

    # force_refresh: 跳过所有缓存，直接调API
    if force_refresh:
        log_to_server(f"[v3.670] {symbol} Vision force_refresh — 跳过缓存和冷却")
        vision_result = _vision_call_inline(symbol, ohlcv_bars)
        if vision_result:
            _vision_mem_cache[symbol] = {"result": vision_result, "ts": now}
            return vision_result
        # API失败时回退到缓存
        log_to_server(f"[v3.670] {symbol} Vision force_refresh API失败，回退到缓存")

    # 1. 检查内存缓存
    mem = _vision_mem_cache.get(symbol)
    if mem and (now - mem["ts"]) < VISION_RESULT_TTL_SECONDS:
        log_to_server(f"[v3.670] {symbol} Vision内存缓存命中 ({int(now - mem['ts'])}秒前)")
        return mem["result"]

    # 2. 检查文件缓存
    try:
        if os.path.exists(VISION_LATEST_FILE):
            with open(VISION_LATEST_FILE, "r", encoding="utf-8") as f:
                data = json.load(f)
            result = data.get(symbol)
            if result:
                ts_str = result.get("timestamp")
                if ts_str:
                    try:
                        from datetime import datetime
                        ts = datetime.fromisoformat(ts_str)
                        age_seconds = (datetime.now() - ts).total_seconds()
                        if ignore_ttl or age_seconds <= VISION_RESULT_TTL_SECONDS:
                            vision_result = {
                                "current": result.get("current"),
                                "x4": result.get("x4"),
                                "source": "vision_analyzer",
                            }
                            # 更新内存缓存
                            _vision_mem_cache[symbol] = {"result": vision_result, "ts": now}
                            c = result.get("current")
                            c_str = f"{c['regime']} {c['direction']}(conf={c['confidence']:.2f})" if c else "N/A"
                            log_to_server(f"[v3.670] {symbol} Vision文件缓存有效: {int(age_seconds)}秒前, {c_str}")
                            return vision_result
                    except Exception:
                        pass
    except Exception:
        pass

    # 3. 文件过期或不存在 → 在线调用API (有冷却)
    if mem and (now - mem["ts"]) < VISION_PER_SYMBOL_COOLDOWN:
        # 冷却中，返回过期数据也比没有好
        log_to_server(f"[v3.670] {symbol} Vision API冷却中 ({int(now - mem['ts'])}秒/{VISION_PER_SYMBOL_COOLDOWN}秒)")
        return mem.get("result")

    vision_result = _vision_call_inline(symbol, ohlcv_bars)
    if vision_result:
        _vision_mem_cache[symbol] = {"result": vision_result, "ts": now}
        return vision_result

    # 4. API也失败，标记尝试时间(避免频繁重试)
    _vision_mem_cache[symbol] = {"result": None, "ts": now}
    return None


