# -----------------------------------------------------------------------------
# 扫描引擎配置
# -----------------------------------------------------------------------------
class ScanEngineConfig:
    """扫描引擎配置"""
    ENABLED = True                          # 是否启用扫描引擎
    SIGNAL_FILE = "scan_signals.json"       # 信号文件
    HEARTBEAT_FILE = "scan_heartbeat.json"  # 心跳文件
    HEARTBEAT_TIMEOUT = 120                 # 心跳超时(秒)
    
    # 符号映射 (主程序符号 -> 扫描引擎符号)
    SYMBOL_MAP = {
        "BTCUSDC": "BTCUSDT",
        "ETHUSDC": "ETHUSDT",
        "SOLUSDC": "SOLUSDT",
        "ZECUSDC": "ZECUSDT",
    }

# -----------------------------------------------------------------------------
# 扫描引擎信号读取器 (内置版本，不依赖外部导入)
# -----------------------------------------------------------------------------
class ScanSignalReader:
    """扫描引擎信号读取器"""
    
    def __init__(self):
        self.signal_file = ScanEngineConfig.SIGNAL_FILE
        self.heartbeat_file = ScanEngineConfig.HEARTBEAT_FILE
        self.heartbeat_timeout = ScanEngineConfig.HEARTBEAT_TIMEOUT
    
    def _safe_json_read(self, filepath: str):
        """安全读取JSON文件 (v3.560 P1-10: 3次重试+指数退避)"""
        import time as _time_sjr
        for attempt in range(3):
            try:
                if os.path.exists(filepath):
                    with open(filepath, 'r', encoding='utf-8') as f:
                        return json.load(f)
                return None
            except Exception as e:
                if attempt < 2:
                    _time_sjr.sleep(0.1 * (2 ** attempt))
                else:
                    print(f"[SCAN_ENGINE] 读取 {filepath} 失败(3次重试): {e}")
        return None
    
    def is_engine_alive(self) -> bool:
        """检查扫描引擎是否存活"""
        from datetime import datetime
        heartbeat = self._safe_json_read(self.heartbeat_file)
        if not heartbeat:
            return False
        
        try:
            last_beat = datetime.fromisoformat(heartbeat["timestamp"])
            elapsed = (datetime.now() - last_beat).total_seconds()
            return elapsed < self.heartbeat_timeout
        except Exception as e:
            print(f"[SCAN_ENGINE] 心跳检查异常: {e}")
            return False
    
    def get_signal(self, symbol: str):
        """获取指定品种的P0信号"""
        if not self.is_engine_alive():
            return None
        
        data = self._safe_json_read(self.signal_file)
        if not data:
            return None
        
        signals = data.get("signals", {})
        return signals.get(symbol)
    
    def get_all_signals(self):
        """获取所有P0信号"""
        if not self.is_engine_alive():
            return {}
        
        data = self._safe_json_read(self.signal_file)
        if not data:
            return {}
        
        return data.get("signals", {})

# -----------------------------------------------------------------------------
# 初始化扫描引擎读取器
# -----------------------------------------------------------------------------
SCAN_ENGINE_READER = None
if ScanEngineConfig.ENABLED:
    try:
        SCAN_ENGINE_READER = ScanSignalReader()
        print(f"[v2.986] 扫描引擎集成: [OK] 已启用")
    except Exception as e:
        print(f"[v2.986] 扫描引擎集成: [ERROR] 初始化失败: {e}")
else:
    print(f"[v2.986] 扫描引擎集成: [OFF] 未启用")

def check_p0_scan_signal(symbol: str) -> dict:
    """
    检查扫描引擎P0信号 (v2.970)
    
    Args:
        symbol: 交易品种
        
    Returns:
        None - 无信号，继续正常流程
        dict - 有信号，包含 action, reason, confidence, source
    """
    global SCAN_ENGINE_READER
    
    if not ScanEngineConfig.ENABLED or not SCAN_ENGINE_READER:
        return None
    
    if not SCAN_ENGINE_READER.is_engine_alive():
        return None
    
    # 符号映射 (主程序USDC -> 扫描引擎USDT)
    scan_symbol = ScanEngineConfig.SYMBOL_MAP.get(symbol, symbol)
    
    signal = SCAN_ENGINE_READER.get_signal(scan_symbol)
    if not signal:
        return None
    
    print("=" * 60)
    print(f"[P0 扫描引擎触发] {symbol}")
    print(f"  信号: {signal['signal']}")
    print(f"  价差: {signal['change_pct']:+.2f}%")
    print(f"  基准价: {signal['base_price']}")
    print(f"  当前价: {signal['price']}")
    print(f"  周期: {signal.get('timeframe', '1h')}")
    print("=" * 60)
    
    return {
        "action": signal["signal"],  # "BUY" or "SELL"
        "reason": f"P0_SCAN: {signal['change_pct']:+.2f}% vs 基准",
        "confidence": 0.95,
        "source": "scan_engine",
        "signal_details": signal,
    }

