class OHLCVWindow:
    """维护最近N根K线的OHLCV数据窗口"""
    def __init__(self, max_size=30, timeframe_minutes=240):
        self.max_size = max_size
        self.timeframe_minutes = timeframe_minutes  # v3.600: 动态容差用
        self.bars = []  # [{open, high, low, close, volume, sr_zone, timestamp}, ...]
        self.tv_signals = []  # [PATCHED] 每根K线的TV五信号历史
    
    def append(self, bar: dict, tv_signals: dict = None):  # [PATCHED]
        """添加新K线 (v3.003: 添加数据验证, v3.679: high>=low校验)"""
        # v3.003: 拒绝无效K线（close/high/low <= 0）
        close_val = bar.get("close", 0)
        if close_val <= 0:
            return False  # 拒绝添加
        # v3.679: 拒绝high<low的异常K线
        h_val, l_val = bar.get("high", 0), bar.get("low", 0)
        if h_val > 0 and l_val > 0 and h_val < l_val:
            return False

        self.bars.append(bar)
        
        # [PATCHED] 保存TV信号
        if tv_signals is None:
            tv_signals = {
                "pa_buy_edge": False,
                "pa_sell_edge": False,
                "sr_zone": "MID",
                "pa_tag": "NONE",
                "two_b_tag": "NONE",
                "volume_state": "NORMAL",
            }
        self.tv_signals.append(tv_signals)

        if len(self.bars) > self.max_size:
            self.bars.pop(0)
            self.tv_signals.pop(0)  # [PATCHED]

        return True  # v3.003: 添加成功

    def get_bars(self):
        """v3.679: 返回浅拷贝，防止锁外读取时被其他线程append/pop修改"""
        return list(self.bars)

    def get_tv_signals(self):
        """[PATCHED] 获取TV信号历史 (v3.679: 浅拷贝)"""
        return list(self.tv_signals)
    
    def size(self):
        return len(self.bars)

    def check_staleness(self, max_age_seconds: int = 300) -> dict:
        """v3.654: 数据新鲜度检测 (SYS-021)"""
        if not self.bars:
            return {"stale": True, "age_seconds": -1, "reason": "无数据"}
        last_bar = self.bars[-1]
        ts = last_bar.get("timestamp") or last_bar.get("ts") or last_bar.get("time")
        if not ts:
            return {"stale": False, "age_seconds": -1, "reason": "无时间戳"}
        try:
            if isinstance(ts, (int, float)):
                bar_time = ts
            else:
                bar_time = datetime.strptime(str(ts)[:19], "%Y-%m-%d %H:%M:%S").timestamp()
            age = time.time() - bar_time
            is_stale = age > max_age_seconds
            return {"stale": is_stale, "age_seconds": int(age),
                    "reason": f"数据延迟{int(age)}s" if is_stale else ""}
        except Exception:
            return {"stale": False, "age_seconds": -1, "reason": "时间戳解析失败"}

    def clear(self):
        """v3.446: 清空窗口数据"""
        self.bars = []
        self.tv_signals = []

    def update_last_tv_signals(self, tv_signals: dict):
        """v3.470: 用TradingView干净数据更新最后一根K线的信号

        每次TV推送时调用，逐步用干净数据覆盖旧的默认数据，
        直到整个缓存都变成TV的真实数据。
        """
        if self.tv_signals and tv_signals:
            self.tv_signals[-1] = tv_signals
            return True
        return False

    def update_latest_bar(self, bar: dict, tv_signals: dict = None):
        """v3.472: 用TV数据更新/替换最新K线

        - 如果缓存为空，直接append
        - 如果最新K线时间戳接近，替换（更新）
        - 如果是新K线，追加

        Returns:
            str: "updated" / "appended" / "skipped"
        """
        if not bar or bar.get("close", 0) <= 0:
            return "skipped"

        if not self.bars:
            # 缓存为空，直接添加
            self.append(bar, tv_signals)
            return "appended"

        last_bar = self.bars[-1]
        last_ts = last_bar.get("timestamp", 0)
        new_ts = bar.get("timestamp", 0)

        # 判断是否为同一根K线（时间戳接近或相同）
        # TV推送的是已确认K线，所以用时间戳判断
        is_same_bar = False
        if last_ts > 0 and new_ts > 0:
            # v3.600: 动态容差 = 周期的一半 (避免30min周期下误判)
            _half_bar_sec = self.timeframe_minutes * 60 / 2
            is_same_bar = abs(new_ts - last_ts) < _half_bar_sec
        else:
            # 没有时间戳，用价格判断（收盘价相同认为是更新）
            is_same_bar = abs(last_bar.get("close", 0) - bar.get("close", 0)) < 0.0001

        if is_same_bar:
            # 替换最新K线
            self.bars[-1] = bar
            if tv_signals and self.tv_signals:
                self.tv_signals[-1] = tv_signals
            return "updated"
        else:
            # 新K线，追加
            self.append(bar, tv_signals)
            return "appended"

    def is_ready(self):
        """v3.150: 至少61根才认为就绪（支持60周期斜率计算）"""
        return len(self.bars) >= 61

    def get_tv_coverage_stats(self):
        """v16.2: 统计TV数据覆盖情况

        Returns:
            dict: {
                "total": 总K线数,
                "tv_replaced": TV覆盖的K线数,
                "coverage_pct": 覆盖百分比,
                "yfinance_count": 未被TV覆盖的数量
            }
        """
        total = len(self.tv_signals)
        tv_count = 0

        # TV推送的数据会包含这些v3.470字段，yfinance/Coinbase初始化的不会有
        tv_markers = ["donchian_upper", "ema20", "macd_line", "bb_upper", "atr14"]

        for sig in self.tv_signals:
            # 检查是否有任何TV特有字段且不为None
            has_tv_data = any(sig.get(marker) is not None for marker in tv_markers)
            if has_tv_data:
                tv_count += 1

        coverage_pct = (tv_count / total * 100) if total > 0 else 0

        return {
            "total": total,
            "tv_replaced": tv_count,
            "coverage_pct": round(coverage_pct, 1),
            "yfinance_count": total - tv_count
        }

    # v2.987: 方案2 - 持久化支持
    def to_dict(self):
        """序列化为字典，用于持久化"""
        return {
            "bars": self.bars,
            "tv_signals": self.tv_signals,
            "max_size": self.max_size,
        }
    
    def from_dict(self, data: dict):
        """从字典恢复，用于加载缓存"""
        self.bars = data.get("bars", [])[-self.max_size:]
        self.tv_signals = data.get("tv_signals", [])[-self.max_size:]
        # 确保tv_signals和bars长度一致
        while len(self.tv_signals) < len(self.bars):
            self.tv_signals.append({
                "pa_buy_edge": False, "pa_sell_edge": False,
                "sr_zone": "MID", "pa_tag": "NONE",
                "two_b_tag": "NONE", "volume_state": "NORMAL",
            })
    
    # v2.987: 方案1 - 预加载支持
    def preload_from_closes(self, closes: list, symbol: str = ""):
        """从收盘价列表预加载（用于启动时快速初始化）"""
        if not closes or len(closes) < 5:
            return 0
        
        loaded = 0
        use_closes = closes[-self.max_size:] if len(closes) > self.max_size else closes
        
        for i, c in enumerate(use_closes):
            try:
                bar = {
                    "open": float(c),
                    "high": float(c) * 1.001,  # 模拟高点
                    "low": float(c) * 0.999,   # 模拟低点
                    "close": float(c),
                    "volume": 0,
                    "sr_zone": "MID",
                    "timestamp": i,
                }
                self.bars.append(bar)
                self.tv_signals.append({
                    "pa_buy_edge": False, "pa_sell_edge": False,
                    "sr_zone": "MID", "pa_tag": "NONE",
                    "two_b_tag": "NONE", "volume_state": "NORMAL",
                })
                loaded += 1
            except Exception as e:
                print(f"[OHLCV] 预加载K线{i}失败: {e}")
                continue
        
        # 保持最大长度
        if len(self.bars) > self.max_size:
            self.bars = self.bars[-self.max_size:]
            self.tv_signals = self.tv_signals[-self.max_size:]
        
        if loaded > 0:
            print(f"[v2.987] {symbol} OHLCV窗口预加载: {loaded}根K线")

        return loaded

    def fill_indicators_from_ohlcv(self, symbol: str = ""):
        """
        v3.470: 基于缓存的OHLCV数据计算并填充所有K线的技术指标

        逻辑：
        1. 如果tv_signals中已有MACD/EMA等数据 → 跳过（用缓存）
        2. 如果没有 → 本地计算并填充

        这样TradingView推送新数据覆盖OHLCV后，指标会自动计算填充
        """
        if len(self.bars) < 20:
            return 0  # 数据不足，无法计算

        # 提取价格序列
        closes = [float(b.get("close", b.get("c", 0))) for b in self.bars]
        highs = [float(b.get("high", b.get("h", 0))) for b in self.bars]
        lows = [float(b.get("low", b.get("l", 0))) for b in self.bars]
        volumes = [float(b.get("volume", b.get("v", 0))) for b in self.bars]

        # 计算指标
        ema20_values = _calc_ema(closes, 20)
        macd_values = _calc_macd(closes, 12, 26, 9)
        bb_values = _calc_bollinger(closes, 20, 2.0)
        atr_values = _calc_atr(highs, lows, closes, 14)
        rsi_values = _calc_rsi(closes, 14)

        # 计算成交量比率
        vol_ratios = []
        for i in range(len(volumes)):
            if i < 20:
                vol_ratios.append(1.0)
            else:
                avg_vol = sum(volumes[i-20:i]) / 20
                vol_ratios.append(volumes[i] / avg_vol if avg_vol > 0 else 1.0)

        # 确保tv_signals长度与bars一致
        while len(self.tv_signals) < len(self.bars):
            self.tv_signals.append({
                "pa_buy_edge": False, "pa_sell_edge": False,
                "sr_zone": "MID", "pa_tag": "NONE",
                "two_b_tag": "NONE", "volume_state": "NORMAL",
            })

        filled_count = 0
        for i in range(len(self.bars)):
            sig = self.tv_signals[i]

            # 检查是否已有数据（非None即有数据）
            if sig.get("macd_line") is not None and sig.get("ema20") is not None:
                continue  # 已有数据，跳过

            # 填充指标数据
            # EMA20
            sig["ema20"] = ema20_values[i] if i < len(ema20_values) else None
            if i >= 3 and ema20_values[i] is not None and ema20_values[i-3] is not None:
                slope = ema20_values[i] - ema20_values[i-3]
                sig["ema_trend"] = "up" if slope > 0 else "down" if slope < 0 else "flat"
            else:
                sig["ema_trend"] = "flat"
            sig["price_above_ema"] = closes[i] > ema20_values[i] if ema20_values[i] else None

            # MACD
            if i < len(macd_values):
                sig["macd_line"] = macd_values[i]["line"]
                sig["macd_signal"] = macd_values[i]["signal"]
                sig["macd_hist"] = macd_values[i]["hist"]
                sig["macd_trend"] = "bullish" if macd_values[i]["line"] and macd_values[i]["signal"] and macd_values[i]["line"] > macd_values[i]["signal"] else "bearish"
                # 金叉/死叉检测
                if i > 0 and macd_values[i-1]["line"] is not None and macd_values[i-1]["signal"] is not None:
                    prev_diff = macd_values[i-1]["line"] - macd_values[i-1]["signal"]
                    curr_diff = (macd_values[i]["line"] or 0) - (macd_values[i]["signal"] or 0)
                    sig["macd_cross_over"] = prev_diff <= 0 and curr_diff > 0
                    sig["macd_cross_under"] = prev_diff >= 0 and curr_diff < 0
                else:
                    sig["macd_cross_over"] = False
                    sig["macd_cross_under"] = False

            # 布林带
            if i < len(bb_values):
                sig["bb_upper"] = bb_values[i]["upper"]
                sig["bb_lower"] = bb_values[i]["lower"]
                sig["bb_basis"] = bb_values[i]["basis"]
                width = (bb_values[i]["upper"] or 0) - (bb_values[i]["lower"] or 0)
                sig["bb_width_pct"] = (width / bb_values[i]["basis"] * 100) if bb_values[i]["basis"] and bb_values[i]["basis"] > 0 else 0
                sig["pos_in_bb"] = ((closes[i] - (bb_values[i]["lower"] or 0)) / width * 100) if width > 0 else 50
                # 挤压检测：当前宽度 < 20周期平均宽度的80%
                if i >= 20:
                    avg_width = sum((bb_values[j]["upper"] or 0) - (bb_values[j]["lower"] or 0) for j in range(i-20, i)) / 20
                    sig["bb_squeeze"] = width < avg_width * 0.8
                else:
                    sig["bb_squeeze"] = False

            # ATR和RSI
            sig["atr14"] = atr_values[i] if i < len(atr_values) else None
            sig["rsi14"] = rsi_values[i] if i < len(rsi_values) else None

            # 成交量比率
            sig["vol_ratio"] = vol_ratios[i] if i < len(vol_ratios) else 1.0

            # Donchian通道（基于前一根K线）
            if i >= 30:
                dc_high = max(highs[i-30:i])
                dc_low = min(lows[i-30:i])
                dc_basis = (dc_high + dc_low) / 2
                sig["donchian_upper"] = dc_high
                sig["donchian_lower"] = dc_low
                sig["donchian_basis"] = dc_basis
                dc_range = dc_high - dc_low
                sig["pos_in_channel"] = ((closes[i] - dc_low) / dc_range * 100) if dc_range > 0 else 50

            filled_count += 1

        if filled_count > 0:
            print(f"[v3.470] {symbol} 本地计算指标: 填充{filled_count}根K线")

        return filled_count

    def get_indicator(self, name: str, index: int = -1) -> any:
        """
        v3.470: 获取指定K线的指标值（缓存优先）

        优先级：
        1. 缓存中有数据 → 直接返回（TV推送或之前计算的）
        2. 缓存中没有 → 返回None（调用fill_indicators_from_ohlcv填充后再获取）

        Args:
            name: 指标名称 (macd_line, ema20, bb_upper, rsi14, etc.)
            index: K线索引，默认-1表示最后一根

        Returns:
            指标值或None
        """
        if not self.tv_signals or abs(index) > len(self.tv_signals):
            return None
        return self.tv_signals[index].get(name)

    def get_indicators_for_bar(self, index: int = -1) -> dict:
        """
        v3.470: 获取指定K线的所有指标（缓存优先）

        Returns:
            包含所有指标的字典，缺失的指标值为None
        """
        if not self.tv_signals or abs(index) > len(self.tv_signals):
            return {}
        return self.tv_signals[index].copy()

    def get_indicator_series(self, name: str, length: int = None) -> list:
        """
        v3.470: 获取指标序列（用于趋势分析）

        Args:
            name: 指标名称
            length: 返回长度，None表示全部

        Returns:
            指标值列表，最老的在前，最新的在后
        """
        if not self.tv_signals:
            return []

        series = [sig.get(name) for sig in self.tv_signals]
        if length:
            return series[-length:]
        return series

    def has_indicator_data(self, index: int = -1) -> bool:
        """
        v3.470: 检查指定K线是否有完整指标数据（非默认值）
        """
        if not self.tv_signals or abs(index) > len(self.tv_signals):
            return False
        sig = self.tv_signals[index]
        # 检查关键指标是否有数据
        return sig.get("macd_line") is not None and sig.get("ema20") is not None


def _calc_ema(prices: list, period: int) -> list:
    """计算EMA"""
    if len(prices) < period:
        return [None] * len(prices)

    result = [None] * len(prices)
    multiplier = 2 / (period + 1)

    # 初始SMA
    sma = sum(prices[:period]) / period
    result[period - 1] = sma

    # EMA
    for i in range(period, len(prices)):
        result[i] = (prices[i] - result[i-1]) * multiplier + result[i-1]

    return result


def _calc_macd(prices: list, fast: int = 12, slow: int = 26, signal: int = 9) -> list:
    """计算MACD"""
    result = [{"line": None, "signal": None, "hist": None} for _ in range(len(prices))]

    if len(prices) < slow + signal:
        return result

    ema_fast = _calc_ema(prices, fast)
    ema_slow = _calc_ema(prices, slow)

    # MACD Line
    macd_line = []
    for i in range(len(prices)):
        if ema_fast[i] is not None and ema_slow[i] is not None:
            macd_line.append(ema_fast[i] - ema_slow[i])
        else:
            macd_line.append(None)

    # Signal Line (EMA of MACD Line)
    valid_macd = [m for m in macd_line if m is not None]
    if len(valid_macd) >= signal:
        signal_line = _calc_ema([m if m is not None else 0 for m in macd_line], signal)
    else:
        signal_line = [None] * len(prices)

    # Histogram
    for i in range(len(prices)):
        if macd_line[i] is not None and signal_line[i] is not None:
            result[i] = {
                "line": round(macd_line[i], 6),
                "signal": round(signal_line[i], 6),
                "hist": round(macd_line[i] - signal_line[i], 6)
            }

    return result


def _calc_bollinger(prices: list, period: int = 20, std_dev: float = 2.0) -> list:
    """计算布林带"""
    result = [{"upper": None, "lower": None, "basis": None} for _ in range(len(prices))]

    if len(prices) < period:
        return result

    for i in range(period - 1, len(prices)):
        window = prices[i - period + 1:i + 1]
        basis = sum(window) / period
        variance = sum((x - basis) ** 2 for x in window) / period
        std = variance ** 0.5

        result[i] = {
            "upper": round(basis + std_dev * std, 4),
            "lower": round(basis - std_dev * std, 4),
            "basis": round(basis, 4)
        }

    return result


def _calc_atr(highs: list, lows: list, closes: list, period: int = 14) -> list:
    """计算ATR"""
    if len(closes) < period + 1:
        return [None] * len(closes)

    result = [None] * len(closes)
    tr_values = []

    for i in range(1, len(closes)):
        tr = max(
            highs[i] - lows[i],
            abs(highs[i] - closes[i-1]),
            abs(lows[i] - closes[i-1])
        )
        tr_values.append(tr)

    # 初始ATR (SMA)
    if len(tr_values) >= period:
        atr = sum(tr_values[:period]) / period
        result[period] = round(atr, 6)

        # 后续ATR (EMA方式)
        for i in range(period + 1, len(closes)):
            atr = (atr * (period - 1) + tr_values[i - 1]) / period
            result[i] = round(atr, 6)

    return result


def _calc_rsi(prices: list, period: int = 14) -> list:
    """计算RSI"""
    if len(prices) < period + 1:
        return [None] * len(prices)

    result = [None] * len(prices)

    # 计算价格变化
    changes = [prices[i] - prices[i-1] for i in range(1, len(prices))]

    # 分离涨跌
    gains = [max(0, c) for c in changes]
    losses = [max(0, -c) for c in changes]

    # 初始平均
    avg_gain = sum(gains[:period]) / period
    avg_loss = sum(losses[:period]) / period

    if avg_loss == 0:
        result[period] = 100.0
    else:
        rs = avg_gain / avg_loss
        result[period] = round(100 - (100 / (1 + rs)), 2)

    # 后续RSI
    for i in range(period + 1, len(prices)):
        avg_gain = (avg_gain * (period - 1) + gains[i - 1]) / period
        avg_loss = (avg_loss * (period - 1) + losses[i - 1]) / period

        if avg_loss == 0:
            result[i] = 100.0
        else:
            rs = avg_gain / avg_loss
            result[i] = round(100 - (100 / (1 + rs)), 2)

    return result


