import threading as _threading_ohlcv  # v3.003: 提前导入用于锁
_ohlcv_windows = {}
_ohlcv_lock = _threading_ohlcv.Lock()  # v3.003: 添加锁保护
_symbol_current_timeframe = {}  # v3.445: 记录每个品种当前使用的周期

# ============================================================================
# v3.510: 预计算缓存 - 把非激活时间可计算的指标提前算好
# ============================================================================
# 目标: 减少/llm_decide激活时的计算压力，提升响应速度
#
# 预计算项目 (仅依赖历史K线，不需要实时价格):
#   - 道氏理论趋势 (x4, x8周期)
#   - 技术指标 (ADX, Choppiness, DI方向)
#   - 120根K线高低点
#   - 摆动点 (swing highs/lows)
#   - Wyckoff初步分析
#   - 双底双顶形态检测
#
# 触发时机: K线收盘时 (TV webhook更新OHLCV后 / 后台更新器更新后)
# ============================================================================

_precomputed_cache = {}  # {"SYMBOL_TIMEFRAME": {缓存数据}}
_precomputed_lock = _threading_ohlcv.Lock()  # 线程安全
_precomputed_version = "3.660"  # 缓存版本，版本变化时清空

class PrecomputedIndicators:
    """
    v3.510: 预计算指标缓存类

    存储仅依赖历史K线的计算结果，避免激活时重复计算
    """
    def __init__(self):
        # 元数据
        self.last_bar_timestamp = 0     # 最后一根K线时间戳
        self.last_compute_time = 0      # 最后计算时间
        self.bar_count = 0              # K线数量
        self.version = _precomputed_version

        # 道氏理论趋势
        self.trend_x4 = "unknown"       # x4周期趋势
        self.trend_x8 = "unknown"       # x8周期趋势
        self.dow_x4_details = {}
        self.dow_x8_details = {}

        # 120K线统计
        self.high_120 = 0.0
        self.low_120 = 0.0

        # 技术指标
        self.adx = 0.0
        self.choppiness = 50.0
        self.di_plus = 0.0
        self.di_minus = 0.0
        self.di_direction = "NEUTRAL"

        # 摆动点
        self.swing_highs = []           # [(index, price), ...]
        self.swing_lows = []            # [(index, price), ...]

        # 形态检测 (双底双顶)
        self.double_bottom = None       # 双底检测结果
        self.double_top = None          # 双顶检测结果

        # Wyckoff初步分析
        self.wyckoff_volume_analysis = {}

        # v3.520: Vegas隧道 (EMA 144/169)
        self.ema_144 = 0.0
        self.ema_169 = 0.0

    def is_valid(self, current_bar_timestamp: int, max_age_seconds: int = 1800) -> bool:
        """
        检查缓存是否有效

        Args:
            current_bar_timestamp: 当前最新K线时间戳
            max_age_seconds: 最大缓存年龄(秒)，默认30分钟

        Returns:
            缓存是否有效
        """
        import time

        # 版本不匹配，无效
        if self.version != _precomputed_version:
            return False

        # K线时间戳变化(新K线收盘)，无效
        if current_bar_timestamp != self.last_bar_timestamp and current_bar_timestamp > 0:
            return False

        # 缓存太老，无效
        if time.time() - self.last_compute_time > max_age_seconds:
            return False

        return True

    def to_dict(self) -> dict:
        """导出为字典"""
        return {
            "last_bar_timestamp": self.last_bar_timestamp,
            "last_compute_time": self.last_compute_time,
            "bar_count": self.bar_count,
            "version": self.version,
            "trend_x4": self.trend_x4,
            "trend_x8": self.trend_x8,
            "high_120": self.high_120,
            "low_120": self.low_120,
            "adx": self.adx,
            "choppiness": self.choppiness,
            "di_direction": self.di_direction,
            "ema_144": self.ema_144,
            "ema_169": self.ema_169,
        }


def precompute_indicators(symbol: str, timeframe: int, ohlcv_bars: list, force: bool = False) -> PrecomputedIndicators:
    """
    v3.510: 预计算技术指标

    在K线收盘时调用，计算所有仅依赖历史K线的指标

    Args:
        symbol: 品种代码
        timeframe: K线周期(分钟)
        ohlcv_bars: OHLCV数据 (正序，最老在前)
        force: 是否强制重新计算

    Returns:
        PrecomputedIndicators对象
    """
    import time

    cache_key = f"{symbol}_{timeframe}"

    # 检查现有缓存
    with _precomputed_lock:
        existing = _precomputed_cache.get(cache_key)

    # 获取最新K线时间戳
    current_ts = 0
    if ohlcv_bars and len(ohlcv_bars) > 0:
        last_bar = ohlcv_bars[-1]
        current_ts = last_bar.get("timestamp", 0)
        if current_ts == 0:
            # 用bar数量作为伪时间戳
            current_ts = len(ohlcv_bars)

    # 如果缓存有效且不强制，返回现有缓存
    if existing and existing.is_valid(current_ts) and not force:
        return existing

    # 需要重新计算
    indicators = PrecomputedIndicators()
    indicators.last_bar_timestamp = current_ts
    indicators.last_compute_time = time.time()
    indicators.bar_count = len(ohlcv_bars)

    if len(ohlcv_bars) < 30:
        print(f"[v3.510 PRECOMPUTE] {symbol}: K线不足({len(ohlcv_bars)}根)，跳过预计算")
        with _precomputed_lock:
            _precomputed_cache[cache_key] = indicators
        return indicators

    start_time = time.time()

    try:
        # 提取价格序列
        closes = [bar["close"] for bar in ohlcv_bars]
        highs = [bar["high"] for bar in ohlcv_bars]
        lows = [bar["low"] for bar in ohlcv_bars]
        volumes = [bar.get("volume", 0) for bar in ohlcv_bars]

        # 1. 计算高低点 (v3.600: 动态回看窗口，不再硬编码120)
        _pc_params = get_timeframe_params(timeframe, is_crypto=is_crypto_symbol(symbol))
        _pc_buf = _pc_params["ohlcv_buffer_size"]
        if len(closes) >= _pc_buf:
            indicators.high_120 = max(closes[-_pc_buf:])
            indicators.low_120 = min(closes[-_pc_buf:])
        elif len(closes) >= 30:
            indicators.high_120 = max(closes)
            indicators.low_120 = min(closes)

        # 2. 道氏理论趋势 (x4, x8周期)
        if len(ohlcv_bars) >= 32:  # x8需要至少4*8=32根
            # x4周期
            highs_x4, lows_x4 = aggregate_ohlc(ohlcv_bars, 4)
            if len(highs_x4) >= 10:
                indicators.trend_x4, indicators.dow_x4_details = compute_trend_dow_swing(
                    highs_x4, lows_x4, n_swing=2, min_swings=2
                )
            elif len(highs_x4) >= 4:
                indicators.trend_x4, indicators.dow_x4_details = compute_trend_dow(
                    highs_x4, lows_x4, n_bars=4
                )

            # x8周期
            highs_x8, lows_x8 = aggregate_ohlc(ohlcv_bars, 8)
            if len(highs_x8) >= 10:
                indicators.trend_x8, indicators.dow_x8_details = compute_trend_dow_swing(
                    highs_x8, lows_x8, n_swing=2, min_swings=2
                )
            elif len(highs_x8) >= 4:
                indicators.trend_x8, indicators.dow_x8_details = compute_trend_dow(
                    highs_x8, lows_x8, n_bars=4
                )

        # 3. 技术指标 (ADX, Choppiness)
        if len(ohlcv_bars) >= 20:
            try:
                indicators.adx, indicators.di_plus, indicators.di_minus = calculate_adx_v2900(
                    ohlcv_bars, period=14
                )

                # DI方向
                di_diff = indicators.di_plus - indicators.di_minus
                if di_diff > 5:
                    indicators.di_direction = "BULLISH"
                elif di_diff < -5:
                    indicators.di_direction = "BEARISH"
                else:
                    indicators.di_direction = "NEUTRAL"

                indicators.choppiness = calculate_choppiness_index_v2900(ohlcv_bars, period=14)
            except Exception as e:
                print(f"[v3.510 PRECOMPUTE] {symbol}: 技术指标计算失败 - {e}")

        # 4. 摆动点识别 (用于后续形态检测)
        if len(ohlcv_bars) >= 10:
            try:
                indicators.swing_highs, indicators.swing_lows = _find_swing_points_simple(
                    highs, lows, lookback=5
                )
            except Exception as e:
                pass

        # 5. v3.520: Vegas隧道 EMA 144/169
        if len(closes) >= 169:
            try:
                # EMA计算
                def calc_ema(data, period):
                    ema = [data[0]]
                    multiplier = 2 / (period + 1)
                    for i in range(1, len(data)):
                        ema.append((data[i] - ema[-1]) * multiplier + ema[-1])
                    return ema[-1]

                indicators.ema_144 = calc_ema(closes, 144)
                indicators.ema_169 = calc_ema(closes, 169)
            except Exception as e:
                print(f"[v3.520 PRECOMPUTE] {symbol}: Vegas EMA计算失败 - {e}")

        elapsed = (time.time() - start_time) * 1000
        print(f"[v3.520 PRECOMPUTE] {symbol}_{timeframe}: 预计算完成 | "
              f"x4={indicators.trend_x4}, x8={indicators.trend_x8}, "
              f"ADX={indicators.adx:.1f}, Chop={indicators.choppiness:.1f}, "
              f"EMA144={indicators.ema_144:.2f}, EMA169={indicators.ema_169:.2f} | "
              f"耗时={elapsed:.1f}ms")

    except Exception as e:
        print(f"[v3.510 PRECOMPUTE] {symbol}: 预计算异常 - {e}")
        import traceback
        traceback.print_exc()

    # 保存到缓存
    with _precomputed_lock:
        _precomputed_cache[cache_key] = indicators

    return indicators


def get_precomputed_cache(symbol: str, timeframe: int) -> PrecomputedIndicators:
    """
    v3.510: 获取预计算缓存

    Args:
        symbol: 品种代码
        timeframe: K线周期

    Returns:
        PrecomputedIndicators对象，如果不存在返回空对象
    """
    cache_key = f"{symbol}_{timeframe}"
    with _precomputed_lock:
        return _precomputed_cache.get(cache_key, PrecomputedIndicators())


def _find_swing_points_simple(highs: list, lows: list, lookback: int = 5) -> tuple:
    """
    v3.510: 简化版摆动点识别

    Returns:
        (swing_highs, swing_lows): [(index, price), ...]
    """
    swing_highs = []
    swing_lows = []

    n = len(highs)
    if n < lookback * 2 + 1:
        return swing_highs, swing_lows

    for i in range(lookback, n - lookback):
        # 检查是否是局部最高点
        is_high = True
        for j in range(i - lookback, i + lookback + 1):
            if j != i and highs[j] >= highs[i]:
                is_high = False
                break
        if is_high:
            swing_highs.append((i, highs[i]))

        # 检查是否是局部最低点
        is_low = True
        for j in range(i - lookback, i + lookback + 1):
            if j != i and lows[j] <= lows[i]:
                is_low = False
                break
        if is_low:
            swing_lows.append((i, lows[i]))

    return swing_highs, swing_lows


# v3.487: Wyckoff阶段确认缓存 (防止ZEC等品种阶段跳变)
