# ============================================================================
# v3.499: 唐纳奇通道状态缓存 - L2位置确认反馈到L1
# ============================================================================
class DonchianState:
    """
    v3.499: 唐纳奇通道状态缓存类

    跟踪唐纳奇通道位置的稳定性，用于：
    1. 确认L1趋势判断的可靠性
    2. 检测极端位置（高位/低位）的持续性
    3. 为L1提供位置反馈，优化趋势判断

    策略逻辑：
    - 位置 > 0.8 连续N根 → 强势上涨，支持L1 UP判断
    - 位置 < 0.2 连续N根 → 强势下跌，支持L1 DOWN判断
    - 位置在 0.3-0.7 震荡 → 支持L1 SIDE判断
    """
    def __init__(self):
        self.positions = []          # 最近N根K线的位置值
        self.high_count = 0          # 连续高位(>0.8)计数
        self.low_count = 0           # 连续低位(<0.2)计数
        self.last_update = None      # 最后更新时间
        self.trend_bias = "NEUTRAL"  # 趋势倾向: BULLISH/BEARISH/NEUTRAL
        self.confidence = 0.0        # 置信度 0-1

    def update(self, pos_in_channel: float, timestamp=None):
        """
        更新位置状态

        Args:
            pos_in_channel: 当前价格在唐纳奇通道中的位置 (0-1)
            timestamp: 更新时间戳
        """
        import time
        self.last_update = timestamp or time.time()

        # 保留最近20根K线的位置
        self.positions.append(pos_in_channel)
        if len(self.positions) > 20:
            self.positions.pop(0)

        # 更新连续计数
        if pos_in_channel > 0.8:
            self.high_count += 1
            self.low_count = 0
        elif pos_in_channel < 0.2:
            self.low_count += 1
            self.high_count = 0
        else:
            # 中间区域，逐渐衰减计数
            self.high_count = max(0, self.high_count - 1)
            self.low_count = max(0, self.low_count - 1)

        # 计算趋势倾向和置信度
        self._compute_trend_bias()

    def _compute_trend_bias(self):
        """计算趋势倾向和置信度"""
        if len(self.positions) < 3:
            self.trend_bias = "NEUTRAL"
            self.confidence = 0.0
            return

        avg_pos = sum(self.positions[-5:]) / min(5, len(self.positions))

        # 连续高位 → 看涨
        if self.high_count >= 3:
            self.trend_bias = "BULLISH"
            self.confidence = min(1.0, self.high_count / 5)
        # 连续低位 → 看跌
        elif self.low_count >= 3:
            self.trend_bias = "BEARISH"
            self.confidence = min(1.0, self.low_count / 5)
        # 平均位置判断
        elif avg_pos > 0.65:
            self.trend_bias = "BULLISH"
            self.confidence = (avg_pos - 0.5) * 2
        elif avg_pos < 0.35:
            self.trend_bias = "BEARISH"
            self.confidence = (0.5 - avg_pos) * 2
        else:
            self.trend_bias = "NEUTRAL"
            self.confidence = 1.0 - abs(avg_pos - 0.5) * 2

    def get_l1_feedback(self) -> dict:
        """
        获取对L1判断的反馈

        Returns:
            dict: {
                "bias": "BULLISH"/"BEARISH"/"NEUTRAL",
                "confidence": 0-1,
                "suggestion": "支持UP"/"支持DOWN"/"建议SIDE"/"无明确建议"
            }
        """
        if self.confidence < 0.3:
            suggestion = "无明确建议"
        elif self.trend_bias == "BULLISH":
            suggestion = "支持UP"
        elif self.trend_bias == "BEARISH":
            suggestion = "支持DOWN"
        else:
            suggestion = "建议SIDE"

        return {
            "bias": self.trend_bias,
            "confidence": self.confidence,
            "suggestion": suggestion,
            "high_count": self.high_count,
            "low_count": self.low_count,
            "recent_avg": sum(self.positions[-5:]) / max(1, min(5, len(self.positions))) if self.positions else 0.5
        }

