# KEY-002: N字每日统计 (完美N/不完美N/SIDE × 扫描次数/实际交易次数)
_n_daily_stats = {"date": "", "symbols": {}}
_n_daily_stats_lock = _threading_ohlcv.Lock()

def _n_daily_ensure_date():
    """确保_n_daily_stats是今天的数据,跨日自动重置"""
    today = datetime.now(ZoneInfo("America/New_York")).strftime("%Y-%m-%d")
    if _n_daily_stats["date"] != today:
        _n_daily_stats["date"] = today
        _n_daily_stats["symbols"] = {}

def _n_daily_get_symbol(symbol):
    """获取品种统计,不存在则初始化"""
    if symbol not in _n_daily_stats["symbols"]:
        _n_daily_stats["symbols"][symbol] = {
            "perfect_n": {"scans": 0, "trades": 0, "by_source": {}},
            "imperfect_n": {"scans": 0, "trades": 0, "by_source": {}},
            "side": {"scans": 0, "trades": 0, "by_source": {}},
        }
    return _n_daily_stats["symbols"][symbol]

def _n_daily_category(state):
    """N字状态→统计分类"""
    if state in ("PERFECT_N", "UP_BREAK", "DOWN_BREAK"):
        return "perfect_n"
    elif state in ("PULLBACK", "DEEP_PULLBACK"):
        return "imperfect_n"
    else:
        return "side"

def _n_daily_record_scan(symbol, state):
    """N字扫描时记录状态"""
    with _n_daily_stats_lock:
        _n_daily_ensure_date()
        cat = _n_daily_category(state)
        _n_daily_get_symbol(symbol)[cat]["scans"] += 1

def _n_daily_record_trade(symbol, source="L1/L2"):
    """实际交易执行时记录(查当前N字状态+来源)"""
    with _n_daily_stats_lock:
        _n_daily_ensure_date()
        # 从n_structure模块获取当前状态
        try:
            from n_structure import get_n_state
            ns = get_n_state(symbol)
            cat = _n_daily_category(ns.state)
        except Exception:
            cat = "side"
        _bucket = _n_daily_get_symbol(symbol)[cat]
        _bucket["trades"] += 1
        # 按来源细分
        _src = source or "L1/L2"
        _bucket["by_source"][_src] = _bucket["by_source"].get(_src, 0) + 1

def _n_daily_save():
    """保存到state文件供monitor读取"""
    try:
        import json as _j
        with _n_daily_stats_lock:
            with open("state/n_daily_stats.json", "w", encoding="utf-8") as f:
                _j.dump(_n_daily_stats, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

# ── Signal Gate: 微观结构过滤状态读取 (v3.660) ──────────────────
_signal_gate_state_cache = {"data": None, "ts": 0}
_SG_CACHE_SEC = 300        # 5分钟内存缓存
_SG_FILE_TTL  = 4 * 3600   # 文件超4小时视为过期 → fail-open
# 主程序符号 → JSON文件中的key (加密用yfinance格式存储)
_SG_SYM_MAP = {
    "BTCUSDC": "BTCUSDC", "ETHUSDC": "ETHUSDC",
    "SOLUSDC": "SOLUSDC", "ZECUSDC": "ZECUSDC",
}

def _read_signal_gate_state(symbol: str, direction: str):
    """读取 state/signal_gate_state.json 中的预热结果 (5分钟缓存).
    返回 dict(go, regime, vr, reason) 或 None (文件不存在/过期 → fail-open)."""
    import time as _sgt
    import json as _sgj
    now = _sgt.time()
    # 内存缓存命中
    if (_signal_gate_state_cache["data"] is not None
            and now - _signal_gate_state_cache["ts"] < _SG_CACHE_SEC):
        data = _signal_gate_state_cache["data"]
    else:
        _sg_path = os.path.join("state", "signal_gate_state.json")
        if not os.path.exists(_sg_path):
            return None
        try:
            with open(_sg_path, "r", encoding="utf-8") as f:
                data = _sgj.load(f)
            _signal_gate_state_cache["data"] = data
            _signal_gate_state_cache["ts"] = now
        except Exception:
            return None
    # 检查文件新鲜度
    _meta = data.get("_meta", {})
    _updated = _meta.get("updated_at", "")
    if _updated:
        try:
            from datetime import datetime, timezone
            _dt = datetime.fromisoformat(_updated.replace("Z", "+00:00"))
            _age = now - _dt.timestamp()
            if _age > _SG_FILE_TTL:
                return None  # 文件过期, fail-open
        except Exception:
            pass
    sym_key = _SG_SYM_MAP.get(symbol, symbol)
    sym_data = data.get(sym_key, {})
    dir_data = sym_data.get(direction.upper())
    if not dir_data or dir_data.get("go") is None:
        return None
    return dir_data

# ── FilterChain 三道闸门状态读取 (v3.667) ──────────────────────────
_filter_chain_cache = {"data": None, "ts": 0}
_FC_CACHE_SEC = 300        # 5分钟内存缓存
_FC_FILE_TTL  = 4 * 3600   # 文件超4小时视为过期 → fail-open

_fc_warn_ts = {}  # 各告警类型上次打印时间，30min节流
_FC_WARN_INTERVAL = 1800

def _read_filter_chain_state(symbol: str, direction: str):
    """读取 state/filter_chain_state.json (5分钟缓存).
    返回 dict(passed, vision, volume_score, micro_go, blocked_by, reason) 或 None (fail-open).
    v3.671: 无声失败场景加日志（30min节流）"""
    import time as _fct
    import json as _fcj
    now = _fct.time()

    def _fc_warn(key: str, msg: str):
        if now - _fc_warn_ts.get(key, 0) >= _FC_WARN_INTERVAL:
            log_to_server(msg)
            _fc_warn_ts[key] = now

    if (_filter_chain_cache["data"] is not None
            and now - _filter_chain_cache["ts"] < _FC_CACHE_SEC):
        data = _filter_chain_cache["data"]
    else:
        _fc_path = os.path.join("state", "filter_chain_state.json")
        if not os.path.exists(_fc_path):
            _fc_warn("no_file", "[FILTER_CHAIN][WARN] filter_chain_state.json 不存在 → fail-open (本地worker未运行?)")
            return None
        try:
            with open(_fc_path, "r", encoding="utf-8") as f:
                data = _fcj.load(f)
            _filter_chain_cache["data"] = data
            _filter_chain_cache["ts"] = now
        except Exception:
            return None

    _meta = data.get("_meta", {})
    _updated = _meta.get("updated_at", "")
    if _updated:
        try:
            from datetime import datetime, timezone
            _dt = datetime.fromisoformat(_updated.replace("Z", "+00:00"))
            _age_h = (now - _dt.timestamp()) / 3600
            if _age_h > _FC_FILE_TTL / 3600:
                _fc_warn("stale", f"[FILTER_CHAIN][WARN] filter_chain_state.json 已过期 {_age_h:.1f}h > {_FC_FILE_TTL/3600:.0f}h → fail-open")
                return None
        except Exception:
            pass

    sym_data = data.get(symbol, {})
    dir_data = sym_data.get(direction.upper())
    if not dir_data or dir_data.get("passed") is None:
        _fc_warn(f"no_sym_{symbol}", f"[FILTER_CHAIN][WARN] {symbol} {direction} 无数据 → fail-open (worker尚未计算?)")
        return None
    return dir_data

