def _key004_load_governance():
    """读取治理动作文件，缓存5分钟避免频繁IO。
    返回 {"crypto": {plugin: decision}, "stock": {plugin: decision}}"""
    import time as _t004
    now = _t004.time()
    if _key004_governance_cache["data"] is not None and (now - _key004_governance_cache["ts"]) < _KEY004_GOV_CACHE_SEC:
        return _key004_governance_cache["data"]
    result = {"crypto": {}, "stock": {}}
    try:
        import json as _j004
        _gov_path = os.path.join("state", "plugin_governance_actions.json")
        if os.path.exists(_gov_path):
            with open(_gov_path, "r", encoding="utf-8") as f:
                _gov = _j004.load(f)
            for _atype in ("crypto", "stock"):
                for _row in _gov.get("by_asset", {}).get(_atype, []):
                    if isinstance(_row, dict):
                        result[_atype][_row.get("plugin", "")] = {
                            "decision": _row.get("decision", "KEEP"),
                            "score": _row.get("quality_score", 100),
                        }
    except Exception:
        pass
    _key004_governance_cache["data"] = result
    _key004_governance_cache["ts"] = now
    return result

# ── KEY-009: 结构化规则消费 ────────────────────────────────
_key009_rules_cache = {"data": None, "ts": 0}
_KEY009_RULES_CACHE_SEC = 300  # 5分钟缓存

def _key009_load_rules():
    """读取KEY-009审计生成的结构化规则，缓存5分钟。
    返回 {source_name: {"action": str, "confidence": float}} — 只包含ACTIVE/DISCOVERED规则"""
    import time as _t009
    now = _t009.time()
    if _key009_rules_cache["data"] is not None and (now - _key009_rules_cache["ts"]) < _KEY009_RULES_CACHE_SEC:
        return _key009_rules_cache["data"]
    result = {}
    try:
        import json as _j009
        _rules_path = os.path.join("state", "key009_rules.json")
        if os.path.exists(_rules_path):
            with open(_rules_path, "r", encoding="utf-8") as f:
                _data = _j009.load(f)
            for _r in _data.get("rules", []):
                status = _r.get("status", "DISCOVERED")
                if status in ("DISCOVERED", "VALIDATING", "ACTIVE"):
                    trigger = _r.get("trigger_condition", "")
                    # 提取 source=XXX 形式
                    if trigger.startswith("source=") or trigger.startswith("block_reason="):
                        src = trigger.split("=", 1)[1]
                        result[src] = {
                            "action": _r.get("action", "OBSERVE"),
                            "confidence": _r.get("confidence", 0),
                            "rule_id": _r.get("rule_id", ""),
                            "win_rate": _r.get("win_rate", 0),
                            "status": status,
                        }
    except Exception:
        pass
    _key009_rules_cache["data"] = result
    _key009_rules_cache["ts"] = now
    return result


