_KEY004_TRANSITION_EVAL_PHASE2 = False  # Phase1: 观察模式

def _n_track_transition(symbol, old_state, old_dir, new_state, new_dir, price):
    """记录一次N字状态转换事件"""
    from datetime import datetime as _dt_nt
    from zoneinfo import ZoneInfo as _zi_nt
    ts = _dt_nt.now(_zi_nt("America/New_York")).isoformat()
    event = {
        "symbol": symbol,
        "ts": ts,
        "old_state": old_state, "old_dir": old_dir,
        "new_state": new_state, "new_dir": new_dir,
        "price_at": round(price, 4),
        "eval_after_bars": 4,
        "price_after": None,
        "outcome": None,
    }
    with _n_transition_events_lock:
        _n_transition_events.append(event)
    log_to_server(f"[KEY-004][N_TRANSITION] {symbol} {old_state}/{old_dir} → {new_state}/{new_dir} price={price:.2f}")
    _n_transition_save()

def _n_transition_save():
    """保存到 state/n_transition_events.json"""
    try:
        import json as _j_nt
        from datetime import datetime as _dt_ns
        from zoneinfo import ZoneInfo as _zi_ns
        today = _dt_ns.now(_zi_ns("America/New_York")).strftime("%Y-%m-%d")
        _path = os.path.join("state", "n_transition_events.json")
        # 读取已有数据合并reliability
        _existing = {}
        if os.path.exists(_path):
            with open(_path, "r", encoding="utf-8") as f:
                _existing = _j_nt.load(f)
        _reliability = _existing.get("reliability", {}) if _existing.get("date") == today else {}
        with _n_transition_events_lock:
            _data = {
                "date": today,
                "events": list(_n_transition_events),
                "reliability": _reliability,
            }
        with open(_path, "w", encoding="utf-8") as f:
            _j_nt.dump(_data, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

def _n_transition_eval_backfill():
    """回填评估: 检查4根K线后价格验证转换正确性(Phase1观察)"""
    from datetime import datetime as _dt_ev, timedelta as _td_ev
    from zoneinfo import ZoneInfo as _zi_ev
    now = _dt_ev.now(_zi_ev("America/New_York"))
    updated = False
    with _n_transition_events_lock:
        for evt in _n_transition_events:
            if evt.get("outcome") is not None:
                continue  # 已回填
            try:
                evt_ts = _dt_ev.fromisoformat(evt["ts"])
            except Exception:
                continue
            # 4根4H K线 = 16小时
            if (now - evt_ts) < _td_ev(hours=16):
                continue
            # 获取当前价格
            sym = evt["symbol"]
            _price_now = None
            if sym in symbol_state:
                _price_now = symbol_state[sym].get("last_price", 0)
            if not _price_now or _price_now <= 0:
                continue
            evt["price_after"] = round(_price_now, 4)
            _price_at = evt["price_at"]
            if _price_at <= 0:
                continue
            _change_pct = (_price_now - _price_at) / _price_at * 100
            new_dir = evt["new_dir"]
            if abs(_change_pct) < 0.2:
                outcome = "NEUTRAL"
            elif (new_dir == "UP" and _change_pct > 0) or (new_dir == "DOWN" and _change_pct < 0):
                outcome = "CORRECT"
            else:
                outcome = "INCORRECT"
            evt["outcome"] = outcome
            log_to_server(f"[KEY-004][N_EVAL] {sym} {evt['old_state']}/{evt['old_dir']}→{evt['new_state']}/{evt['new_dir']} "
                          f"price_at={_price_at:.2f} price_after={_price_now:.2f} change={_change_pct:+.2f}% outcome={outcome}")
            updated = True
    if updated:
        _n_transition_update_reliability()
        _n_transition_save()

def _n_transition_update_reliability():
    """按品种×转换类型累积正确率"""
    import json as _j_rel
    _path = os.path.join("state", "n_transition_events.json")
    _reliability = {}
    with _n_transition_events_lock:
        for evt in _n_transition_events:
            if evt.get("outcome") is None:
                continue
            sym = evt["symbol"]
            key = f"{evt['old_state']}_{evt['old_dir']}→{evt['new_state']}_{evt['new_dir']}"
            if sym not in _reliability:
                _reliability[sym] = {}
            if key not in _reliability[sym]:
                _reliability[sym][key] = {"correct": 0, "total": 0, "rate": 0.0}
            _reliability[sym][key]["total"] += 1
            if evt["outcome"] == "CORRECT":
                _reliability[sym][key]["correct"] += 1
            t = _reliability[sym][key]["total"]
            c = _reliability[sym][key]["correct"]
            _reliability[sym][key]["rate"] = round(c / t, 3) if t > 0 else 0.0
    # 写入缓存供save使用
    try:
        if os.path.exists(_path):
            with open(_path, "r", encoding="utf-8") as f:
                _data = _j_rel.load(f)
            _data["reliability"] = _reliability
            with open(_path, "w", encoding="utf-8") as f:
                _j_rel.dump(_data, f, ensure_ascii=False, indent=2)
    except Exception:
        pass


def _build_key002_rollout_plan(total_count: int, diff_count: int) -> dict:
    """KEY-002 T04: 生成entry/risk/timing接入预案（仅计划，不直接改交易参数）。"""
    _total = max(0, int(total_count or 0))
    _diff = max(0, int(diff_count or 0))
    _diff_rate = (_diff / _total) if _total > 0 else 0.0

    _ready = _total >= 120
    _phase = "observe_only"
    _entry = "保持统一阈值，继续收集样本"
    _risk = "保持统一风控，暂不差异化"
    _timing = "保持统一节奏，暂不差异化"

    if _ready and _diff_rate >= 0.35:
        _phase = "rollout_candidate"
        _entry = "候选：放宽顺势入场，收紧逆势入场"
        _risk = "候选：下调逆势仓位上限，保留顺势仓位"
        _timing = "候选：延长逆势冷却，维持顺势冷却"
    elif _ready:
        _phase = "conservative_candidate"
        _entry = "候选：仅做小幅入场阈值微调"
        _risk = "候选：仅做轻量仓位修正"
        _timing = "候选：仅做轻量节奏修正"

    return {
        "phase": _phase,
        "ready_for_rollout": _ready,
        "sample_threshold": 120,
        "diff_rate": round(_diff_rate, 4),
        "entry": _entry,
        "risk": _risk,
        "timing": _timing,
        "rollback_triggers": [
            "diff_rate日内突变>20%",
            "连续2天样本缺失",
            "接入后24h内拦截率异常偏移",
        ],
    }

def get_donchian_state(symbol: str) -> DonchianState:
    """v3.499: 获取或创建品种的唐纳奇状态缓存"""
    with _donchian_state_lock:
        if symbol not in _donchian_state_cache:
            _donchian_state_cache[symbol] = DonchianState()
        return _donchian_state_cache[symbol]

def update_donchian_state(symbol: str, pos_in_channel: float, verbose: bool = False) -> dict:
    """
    v3.499: 更新唐纳奇通道状态并返回L1反馈

    在每次接收到TradingView信号时调用，更新位置状态缓存。

    Args:
        symbol: 品种代码
        pos_in_channel: 当前价格在唐纳奇通道中的位置 (0-1)
        verbose: 是否打印详细日志

    Returns:
        dict: L1反馈信息 {bias, confidence, suggestion, ...}
    """
    state = get_donchian_state(symbol)
    state.update(pos_in_channel)
    feedback = state.get_l1_feedback()

    if verbose:
        print(f"[v3.499 Donchian] {symbol}: pos={pos_in_channel:.2%}, "
              f"bias={feedback['bias']}, conf={feedback['confidence']:.2f}, "
              f"high_cnt={feedback['high_count']}, low_cnt={feedback['low_count']}")

    return feedback

def apply_donchian_strategy(symbol: str, l1_trend: str, pos_in_channel: float) -> dict:
    """
    v3.499: 应用唐纳奇通道策略，生成评分和建议

    基于唐纳奇通道位置和L1趋势判断，生成策略评分。

    策略规则：
    1. L1=UP + 位置>0.7 → 强势延续，+2分
    2. L1=UP + 位置<0.3 → 回调买入机会，+1分 (回调入场)
    3. L1=DOWN + 位置<0.3 → 弱势延续，-2分
    4. L1=DOWN + 位置>0.7 → 反弹卖出机会，-1分 (反弹出场)
    5. L1=SIDE → 纯位置策略 (高抛低吸)

    Args:
        symbol: 品种代码
        l1_trend: L1趋势判断 (UP/DOWN/SIDE)
        pos_in_channel: 当前位置 (0-1)

    Returns:
        dict: {
            "score": int (-3 to +3),
            "reason": str,
            "action_hint": "BUY"/"SELL"/"HOLD"
        }
    """
    state = get_donchian_state(symbol)
    feedback = state.get_l1_feedback()

    score = 0
    reasons = []
    action_hint = "HOLD"

    # 根据L1趋势和位置生成策略
    if l1_trend == "UP":
        if pos_in_channel > 0.7:
            # 强势上涨延续
            score = 2
            reasons.append(f"强势延续(pos={pos_in_channel:.0%}>70%)")
            action_hint = "BUY"
        elif pos_in_channel < 0.3:
            # 回调买入机会
            score = 1
            reasons.append(f"回调买入(pos={pos_in_channel:.0%}<30%)")
            action_hint = "BUY"
        else:
            # 中间区域，跟随趋势
            score = 1
            reasons.append(f"趋势跟随(UP)")
            action_hint = "HOLD"

    elif l1_trend == "DOWN":
        if pos_in_channel < 0.3:
            # 弱势下跌延续
            score = -2
            reasons.append(f"弱势延续(pos={pos_in_channel:.0%}<30%)")
            action_hint = "SELL"
        elif pos_in_channel > 0.7:
            # 反弹卖出机会
            score = -1
            reasons.append(f"反弹卖出(pos={pos_in_channel:.0%}>70%)")
            action_hint = "SELL"
        else:
            # 中间区域，跟随趋势
            score = -1
            reasons.append(f"趋势跟随(DOWN)")
            action_hint = "HOLD"

    else:  # SIDE
        # 震荡市场：纯位置策略
        if pos_in_channel < 0.2:
            score = 2
            reasons.append(f"震荡低位(pos={pos_in_channel:.0%}<20%)")
            action_hint = "BUY"
        elif pos_in_channel > 0.8:
            score = -2
            reasons.append(f"震荡高位(pos={pos_in_channel:.0%}>80%)")
            action_hint = "SELL"
        else:
            score = 0
            reasons.append(f"震荡中间(pos={pos_in_channel:.0%})")
            action_hint = "HOLD"

    # 加入唐纳奇状态的置信度调整
    if feedback["confidence"] > 0.6:
        if feedback["bias"] == "BULLISH" and score < 0:
            score += 1
            reasons.append("Donchian偏多修正")
        elif feedback["bias"] == "BEARISH" and score > 0:
            score -= 1
            reasons.append("Donchian偏空修正")

    return {
        "score": max(-3, min(3, score)),  # 限制在-3到+3
        "reason": " + ".join(reasons),
        "action_hint": action_hint,
        "donchian_feedback": feedback
    }

def apply_donchian_feedback_to_l1(symbol: str, current_trend: str, pos_in_channel: float) -> dict:
    """
    v3.499: 将唐纳奇通道位置反馈应用到L1当前周期趋势(current_trend)

    当唐纳奇通道位置与L1当前周期趋势不一致时，提供修正建议。
    注意：修正的是current_trend(当前周期)，不是big_trend(x4大周期)。

    修正规则：
    1. current_trend=UP 但 连续低位(low_count>=3) → 建议修正为DOWN或SIDE
    2. current_trend=DOWN 但 连续高位(high_count>=3) → 建议修正为UP或SIDE
    3. current_trend=SIDE 但 连续极端位置 → 建议修正为趋势方向

    Args:
        symbol: 品种代码
        current_trend: L1当前周期趋势 (UP/DOWN/SIDE)
        pos_in_channel: 当前位置 (0-1)

    Returns:
        dict: {
            "should_adjust": bool,
            "suggested_trend": str,
            "confidence": float,
            "reason": str
        }
    """
    state = get_donchian_state(symbol)
    feedback = state.get_l1_feedback()

    result = {
        "should_adjust": False,
        "suggested_trend": current_trend,
        "confidence": feedback["confidence"],
        "reason": "无需修正"
    }

    # 规则1: current_trend=UP 但持续低位
    if current_trend == "UP" and feedback["low_count"] >= 3:
        result["should_adjust"] = True
        result["suggested_trend"] = "DOWN" if feedback["low_count"] >= 5 else "SIDE"
        result["reason"] = f"当前=UP但连续{feedback['low_count']}根低位，建议修正"

    # 规则2: current_trend=DOWN 但持续高位
    elif current_trend == "DOWN" and feedback["high_count"] >= 3:
        result["should_adjust"] = True
        result["suggested_trend"] = "UP" if feedback["high_count"] >= 5 else "SIDE"
        result["reason"] = f"当前=DOWN但连续{feedback['high_count']}根高位，建议修正"

    # 规则3: current_trend=SIDE 但持续极端位置
    elif current_trend == "SIDE":
        if feedback["high_count"] >= 5:
            result["should_adjust"] = True
            result["suggested_trend"] = "UP"
            result["reason"] = f"当前=SIDE但连续{feedback['high_count']}根高位，可能转为上涨"
        elif feedback["low_count"] >= 5:
            result["should_adjust"] = True
            result["suggested_trend"] = "DOWN"
            result["reason"] = f"当前=SIDE但连续{feedback['low_count']}根低位，可能转为下跌"

    # 规则4: 位置与趋势严重背离
    if not result["should_adjust"]:
        if current_trend == "UP" and pos_in_channel < 0.15 and feedback["recent_avg"] < 0.25:
            result["should_adjust"] = True
            result["suggested_trend"] = "SIDE"
            result["reason"] = f"当前=UP但位置极低({pos_in_channel:.0%})且均值低({feedback['recent_avg']:.0%})"
        elif current_trend == "DOWN" and pos_in_channel > 0.85 and feedback["recent_avg"] > 0.75:
            result["should_adjust"] = True
            result["suggested_trend"] = "SIDE"
            result["reason"] = f"当前=DOWN但位置极高({pos_in_channel:.0%})且均值高({feedback['recent_avg']:.0%})"

    return result

# ============================================================================
# v3.501: 突破状态跟踪类
# ============================================================================

@dataclass
class BreakoutState:
    """
    v3.501: 突破状态跟踪

    跟踪价格突破唐纳奇通道上/下轨的状态：
    - BREAKOUT模式: close > upper (向上突破) 或 close < lower (向下跌破)
    - RANGING模式: lower < close < upper (震荡模式)

    用于：
    1. L2大周期: 根据模式给予额外加分 (±3)
    2. L2小周期: 验证突破是否站稳（连续2根K线确认）
    3. 失败后下一大周期强制进入震荡模式
    4. 验证成功后标记趋势强化
    """
    mode: str = "RANGING"           # BREAKOUT / RANGING
    direction: str = None           # UP / DOWN / None
    breakout_price: float = None    # 突破时的价格
    breakout_level: float = None    # 突破的阻力/支撑位
    breakout_time: str = None       # 突破时间
    confirmed: bool = False         # 小周期是否确认站稳
    last_upper: float = None        # 最后一次的upper值
    last_lower: float = None        # 最后一次的lower值
    big_cycle_time: str = None      # 大周期激活时间

    # v3.501 小周期监控
    fallback_count: int = 0         # 连续失败计数（小周期K线）
    already_handled: bool = False   # 本大周期已处理标记（一个大周期只处理一次）

    # v3.501 失败记忆（影响下一大周期）
    last_breakout_failed: bool = False  # 上次突破是否失败
    failed_direction: str = None        # 失败的方向

    # v3.501 趋势强化（验证成功后）
    trend_strengthened: bool = False    # 是否已验证成功进入趋势强化
    strengthen_direction: str = None    # 强化方向 UP/DOWN

# v3.501: 突破状态全局缓存
_breakout_states: dict[str, BreakoutState] = {}  # Python 3.9+ 使用小写dict
_breakout_state_lock = _threading_ohlcv.Lock()

def get_breakout_state(symbol: str) -> BreakoutState:
    """v3.501: 获取或创建品种的突破状态"""
    with _breakout_state_lock:
        if symbol not in _breakout_states:
            _breakout_states[symbol] = BreakoutState()
        return _breakout_states[symbol]

def reset_breakout_state_for_new_big_cycle(symbol: str) -> dict:
    """
    v3.501: 大周期激活时重置突破状态

    在新的大周期K线激活时调用，重置小周期计数但保留失败记忆和趋势强化状态。

    Args:
        symbol: 品种代码

    Returns:
        dict: {
            "last_failed": bool,         # 上次是否失败
            "trend_strengthened": bool,  # 是否趋势强化
            "strengthen_direction": str  # 强化方向
        }
    """
    from datetime import datetime
    from zoneinfo import ZoneInfo

    with _breakout_state_lock:
        state = _breakout_states.get(symbol)
        if not state:
            state = BreakoutState()
            _breakout_states[symbol] = state

        now_ny = datetime.now(ZoneInfo("America/New_York"))

        # 记录上一周期的状态
        result = {
            "last_failed": state.last_breakout_failed,
            "failed_direction": state.failed_direction,
            "trend_strengthened": state.trend_strengthened,
            "strengthen_direction": state.strengthen_direction
        }

        # 重置小周期监控状态
        state.fallback_count = 0
        state.already_handled = False
        state.big_cycle_time = now_ny.strftime("%Y-%m-%d %H:%M")

        # 如果上次验证成功（没有失败），检查是否要标记趋势强化
        # 注意：这个逻辑在大周期结束时检查，如果整个周期内没有触发反向信号，说明验证成功
        if state.mode == "BREAKOUT" and not state.last_breakout_failed and not state.already_handled:
            # 上次是突破模式且没有失败 → 标记趋势强化
            if not state.trend_strengthened:
                state.trend_strengthened = True
                state.strengthen_direction = state.direction
                print(f"[v3.501] {symbol} 趋势强化: {state.strengthen_direction}")

        # 清除失败记忆（已在本周期使用过）
        if state.last_breakout_failed:
            print(f"[v3.501] {symbol} 上次突破失败，本周期强制RANGING模式")
        state.last_breakout_failed = False
        state.failed_direction = None

        return result

def update_symbol_breakout_state(symbol: str, close: float,
                                  donchian_upper: float, donchian_lower: float,
                                  is_big_cycle: bool = True) -> dict:
    """
    v3.501: 更新品种的突破状态

    Args:
        symbol: 品种代码
        close: 当前收盘价
        donchian_upper: 唐纳奇通道上轨
        donchian_lower: 唐纳奇通道下轨
        is_big_cycle: 是否是大周期调用（大周期时检测模式，小周期时只验证）

    Returns:
        dict: {
            "mode": "BREAKOUT"/"RANGING",
            "direction": "UP"/"DOWN"/None,
            "changed": bool,
            "breakout_level": float,
            "force_ranging": bool,       # v3.501: 是否强制震荡模式
            "trend_bonus": int           # v3.501: 趋势强化加分
        }
    """
    from datetime import datetime
    from zoneinfo import ZoneInfo

    with _breakout_state_lock:
        state = _breakout_states.get(symbol)
        if not state:
            state = BreakoutState()
            _breakout_states[symbol] = state

        old_mode = state.mode
        old_direction = state.direction
        now_ny = datetime.now(ZoneInfo("America/New_York"))

        # 更新唐纳奇通道值
        state.last_upper = donchian_upper
        state.last_lower = donchian_lower

        result = {
            "mode": state.mode,
            "direction": state.direction,
            "changed": False,
            "breakout_level": state.breakout_level,
            "force_ranging": False,
            "trend_bonus": 0
        }

        # v3.501: 检查是否强制震荡模式（上次突破失败）
        if state.last_breakout_failed:
            result["force_ranging"] = True
            result["mode"] = "RANGING"
            print(f"[v3.501] {symbol} 强制震荡模式(上次{state.failed_direction}失败)")
            # 不改变state.mode，让正常检测逻辑继续，但返回值标记force_ranging

        # v3.501: 检查趋势强化加分
        if state.trend_strengthened:
            if state.strengthen_direction == "UP":
                result["trend_bonus"] = +1
            elif state.strengthen_direction == "DOWN":
                result["trend_bonus"] = -1
            print(f"[v3.501] {symbol} 趋势强化加分: {result['trend_bonus']:+d} ({state.strengthen_direction})")
            # 使用后清除趋势强化
            state.trend_strengthened = False
            state.strengthen_direction = None

        # 检测突破模式（只在大周期时检测）
        if is_big_cycle:
            if close > donchian_upper:
                # 向上突破
                if state.mode != "BREAKOUT" or state.direction != "UP":
                    state.mode = "BREAKOUT"
                    state.direction = "UP"
                    state.breakout_price = close
                    state.breakout_level = donchian_upper
                    state.breakout_time = now_ny.strftime("%Y-%m-%d %H:%M")
                    state.confirmed = False
                    state.fallback_count = 0  # 重置小周期计数
                    state.already_handled = False
                    result["changed"] = True
                    print(f"[v3.501] {symbol} 新突破: UP @ {donchian_upper:.2f} (close={close:.2f})")

            elif close < donchian_lower:
                # 向下跌破
                if state.mode != "BREAKOUT" or state.direction != "DOWN":
                    state.mode = "BREAKOUT"
                    state.direction = "DOWN"
                    state.breakout_price = close
                    state.breakout_level = donchian_lower
                    state.breakout_time = now_ny.strftime("%Y-%m-%d %H:%M")
                    state.confirmed = False
                    state.fallback_count = 0  # 重置小周期计数
                    state.already_handled = False
                    result["changed"] = True
                    print(f"[v3.501] {symbol} 新跌破: DOWN @ {donchian_lower:.2f} (close={close:.2f})")

            else:
                # 震荡模式 (lower < close < upper)
                if state.mode == "BREAKOUT":
                    print(f"[v3.501] {symbol} 回归震荡: {state.direction} @ {state.breakout_level:.2f}")
                    result["changed"] = True
                state.mode = "RANGING"
                state.direction = None
                state.confirmed = False

        result["mode"] = state.mode
        result["direction"] = state.direction
        result["breakout_level"] = state.breakout_level

        return result

def check_small_cycle_breakout_validation(symbol: str, small_close: float) -> dict:
    """
    v3.501: 小周期验证突破是否站稳（带连续计数）

    每根L2小周期K线收盘时调用，检查是否站稳或失败。
    连续2根小周期K线失败才触发反向信号。

    Args:
        symbol: 品种代码
        small_close: 小周期K线收盘价

    Returns:
        dict: {
            "mode": str,                  # 当前模式
            "direction": str,             # 突破方向
            "is_holding": bool,           # 是否站稳
            "fallback_count": int,        # 连续失败计数
            "trigger_reverse": bool,      # 是否触发反向信号
            "reverse_action": str,        # 反向动作 "BUY"/"SELL"/None
            "reason": str                 # 说明
        }
    """
    with _breakout_state_lock:
        state = _breakout_states.get(symbol)
        if not state:
            return {
                "mode": "RANGING",
                "direction": None,
                "is_holding": True,
                "fallback_count": 0,
                "trigger_reverse": False,
                "reverse_action": None,
                "reason": "无突破状态"
            }

        result = {
            "mode": state.mode,
            "direction": state.direction,
            "is_holding": True,
            "fallback_count": state.fallback_count,
            "trigger_reverse": False,
            "reverse_action": None,
            "reason": ""
        }

        # 震荡模式: 不需要验证
        if state.mode != "BREAKOUT":
            result["reason"] = "震荡模式，无需验证"
            return result

        # 已经处理过，本大周期不再处理
        if state.already_handled:
            result["reason"] = f"本大周期已处理反向信号"
            return result

        # 检查站稳/失败
        is_holding = False
        if state.direction == "UP":
            is_holding = small_close > state.breakout_level
        elif state.direction == "DOWN":
            is_holding = small_close < state.breakout_level

        result["is_holding"] = is_holding

        if is_holding:
            # 站稳: 重置失败计数
            state.fallback_count = 0
            state.confirmed = True
            result["fallback_count"] = 0
            result["reason"] = f"站稳{state.direction}@{state.breakout_level:.2f}"
        else:
            # 失败: 增加计数
            state.fallback_count += 1
            result["fallback_count"] = state.fallback_count

            if state.fallback_count >= 2:
                # 连续2根失败 → 触发反向信号
                result["trigger_reverse"] = True
                if state.direction == "UP":
                    result["reverse_action"] = "SELL"
                    result["reason"] = f"突破UP失败(连续{state.fallback_count}根跌回{state.breakout_level:.2f})→触发SELL"
                elif state.direction == "DOWN":
                    result["reverse_action"] = "BUY"
                    result["reason"] = f"跌破DOWN失败(连续{state.fallback_count}根反弹{state.breakout_level:.2f})→触发BUY"

                # 标记已处理，设置失败记忆
                state.already_handled = True
                state.last_breakout_failed = True
                state.failed_direction = state.direction
                print(f"[v3.501] {symbol} {result['reason']}")
            else:
                result["reason"] = f"失败计数{state.fallback_count}/2，等待下一根K线确认"

        return result

def verify_breakout_confirmation(symbol: str, current_close: float) -> dict:
    """
    v3.501: 小周期验证突破是否站稳（简化版，兼容旧调用）

    在L2小周期检查时调用，验证价格是否仍然站在突破位之上/之下。

    Args:
        symbol: 品种代码
        current_close: 当前收盘价

    Returns:
        dict: {
            "confirmed": bool,    # 是否确认站稳
            "action": str,        # "ALLOW" / "REJECT" / "WAIT"
            "reason": str,        # 说明
            "mode": str,          # 当前模式
            "direction": str      # 突破方向
        }
    """
    # 调用新的验证函数
    validation = check_small_cycle_breakout_validation(symbol, current_close)

    result = {
        "confirmed": validation["is_holding"],
        "action": "ALLOW",
        "reason": validation["reason"],
        "mode": validation["mode"],
        "direction": validation["direction"],
        "trigger_reverse": validation["trigger_reverse"],
        "reverse_action": validation["reverse_action"]
    }

    # 如果触发反向信号，action设为REVERSE
    if validation["trigger_reverse"]:
        result["action"] = "REVERSE"
    elif not validation["is_holding"] and validation["fallback_count"] < 2:
        result["action"] = "WAIT"  # 等待第2根K线确认

    return result

def get_breakout_mode_score(symbol: str) -> tuple:
    """
    v3.501: 获取突破模式评分

    根据当前的突破/震荡模式返回评分加成。

    Returns:
        tuple: (score, reason)
        - 突破模式UP: +3
        - 跌破模式DOWN: -3
        - 震荡模式: 0
    """
    with _breakout_state_lock:
        state = _breakout_states.get(symbol)
        if not state or state.mode != "BREAKOUT":
            return (0, "震荡模式")

        if state.direction == "UP":
            return (+3, f"突破模式UP@{state.breakout_level:.2f}")
        elif state.direction == "DOWN":
            return (-3, f"跌破模式DOWN@{state.breakout_level:.2f}")

        return (0, "未知模式")

def get_ranging_mode_score(pos_in_channel: float) -> tuple:
    """
    v3.501: 震荡模式低买高卖评分

    在震荡模式下，根据通道位置给予额外加分：
    - 低位 (pos < 0.25): +2 (买入机会)
    - 高位 (pos > 0.75): -2 (卖出机会)
    - 中间: 0

    Args:
        pos_in_channel: 通道位置 (0-1)

    Returns:
        tuple: (score, reason)
    """
    if pos_in_channel < 0.25:
        return (+2, f"震荡低位{pos_in_channel:.0%}→买入")
    elif pos_in_channel > 0.75:
        return (-2, f"震荡高位{pos_in_channel:.0%}→卖出")
    else:
        return (0, f"震荡中间{pos_in_channel:.0%}")

# ============================================================================

def get_ohlcv_window(symbol: str, timeframe: int = None) -> OHLCVWindow:
    """
    获取或创建窗口
    v3.003: 线程安全
    v3.320: 增加到120根支持完整分析
    v3.445: 按symbol+timeframe分离缓存，切换周期时自动预加载

    Args:
        symbol: 品种代码
        timeframe: 周期(分钟)，None时使用SYMBOL_TIMEFRAMES配置
    """
    # v3.445: 如果未指定timeframe，使用品种配置的默认周期
    if timeframe is None:
        timeframe = get_symbol_timeframe(symbol)

    key = f"{symbol}_{timeframe}"

    with _ohlcv_lock:
        # v3.445: 检测周期切换
        old_timeframe = _symbol_current_timeframe.get(symbol)
        if old_timeframe and old_timeframe != timeframe:
            print(f"[v3.445] {symbol}: 检测到周期切换 {old_timeframe}min → {timeframe}min")
        _symbol_current_timeframe[symbol] = timeframe

        if key not in _ohlcv_windows:
            # v3.600: 动态缓冲区大小，根据周期自动计算
            _tf_params = get_timeframe_params(timeframe, is_crypto=is_crypto_symbol(symbol))
            _buf_size = _tf_params["ohlcv_buffer_size"]
            _ohlcv_windows[key] = OHLCVWindow(max_size=_buf_size, timeframe_minutes=timeframe)
            print(f"[v3.600] {symbol}: 创建新缓存 key={key}, max_size={_buf_size}")
            # v3.445: 新周期缓存为空，触发预加载
            _trigger_single_preload(symbol, timeframe)
        return _ohlcv_windows[key]

def _trigger_single_preload(symbol: str, timeframe: int):
    """v3.450: 单品种预加载 + P0-CycleSwitch完整分析"""
    import threading
    def _preload_thread():
        try:
            print(f"[v3.450] {symbol}: 开始预加载 {timeframe}min K线...")
            _preload_single_symbol(symbol, timeframe)

            # v3.450 P0-CycleSwitch: 预加载完成后立即运行完整分析
            print(f"[v3.450] {symbol}: 预加载完成，触发P0-CycleSwitch分析...")
            _run_cycle_switch_analysis(symbol, timeframe)

        except Exception as e:
            print(f"[v3.450] {symbol}: 预加载/分析失败 - {e}")
            import traceback
            traceback.print_exc()
    # 异步预加载，不阻塞主线程
    t = threading.Thread(target=_preload_thread, daemon=True)
    t.start()


