# v3.450: P0-CycleSwitch - 周期切换立即完整分析
# ============================================================
def _run_cycle_switch_analysis(symbol: str, timeframe: int):
    """
    v3.450 P0-CycleSwitch: 周期切换后立即运行完整三方协商分析

    流程:
    1. 获取预加载的OHLCV数据
    2. 获取当前仓位信息
    3. 计算Tech信号 (ADX/MACD/RSI)
    4. 计算Human信号 (趋势/位置)
    5. 调用DeepSeek进行趋势仲裁
    6. 三方协商得出统一信号
    7. 输出BUY/HOLD/SELL
    8. 执行交易 (正常流程)
    9. 发送邮件通知

    Args:
        symbol: 品种代码
        timeframe: 周期(分钟)
    """
    from datetime import datetime
    try:
        from zoneinfo import ZoneInfo
    except ImportError:
        from backports.zoneinfo import ZoneInfo

    try:
        key = f"{symbol}_{timeframe}"
        print(f"\n{'='*70}")
        print(f"[P0-CycleSwitch] {symbol}: 开始完整三方协商分析 (周期={timeframe}min)")
        print(f"{'='*70}")

        # 1. 获取OHLCV数据
        with _ohlcv_lock:
            window = _ohlcv_windows.get(key)
            if not window or window.size() < 20:
                print(f"[P0-CycleSwitch] {symbol}: K线不足({window.size() if window else 0}根)，跳过分析")
                return
            ohlcv_bars = window.get_bars()

        print(f"[P0-CycleSwitch] {symbol}: 获取到 {len(ohlcv_bars)} 根K线")

        # 2. 获取当前价格和仓位信息
        current_price = float(ohlcv_bars[-1].get("close", 0))
        if current_price <= 0:
            print(f"[P0-CycleSwitch] {symbol}: 无效价格({current_price})，跳过分析")
            return

        # 获取仓位信息
        state = symbol_state.get(symbol, {})
        position_units = state.get("position_units", 0)
        max_units = state.get("max_units", 5)
        pos_ratio = position_units / max_units if max_units > 0 else 0

        print(f"[P0-CycleSwitch] {symbol}: 价格={current_price:.4f}, 仓位={position_units}/{max_units} ({pos_ratio:.0%})")

        # 3. 计算Tech信号
        tech_signals = compute_tech_signals_v2940(ohlcv_bars, tv_data=None, trend_x4=None, trend_x8=None)
        tech_signal = tech_signals.get("signal", "HOLD")
        tech_trend = tech_signals.get("trend", "SIDE")
        adx = tech_signals.get("adx", 0)

        print(f"[P0-CycleSwitch] {symbol}: Tech信号={tech_signal}, 趋势={tech_trend}, ADX={adx:.1f}")

        # 4. 计算Human信号
        human_signals = compute_human_signals_v2900(ohlcv_bars, pos_ratio, None, None, symbol, None)
        human_signal = human_signals.get("signal", "HOLD")
        human_trend = human_signals.get("visual_slope", "side")

        print(f"[P0-CycleSwitch] {symbol}: Human信号={human_signal}, 趋势={human_trend}")

        # 5. 调用DeepSeek趋势仲裁
        closes = [b.get("close", 0) for b in ohlcv_bars]
        market_data = {
            "price": current_price,
            "pos_ratio": pos_ratio,
            "trend_mid": human_trend,
            "close_prices": closes,
            "rsi": tech_signals.get("rsi", 50),
            "volume_ratio": tech_signals.get("volume_ratio", 1.0),
        }

        deepseek_result = call_deepseek_trend_arbiter_v3330(
            ai_regime="RANGING",  # 无LLM输入，使用RANGING
            tech_regime=tech_trend.upper() if tech_trend else "RANGING",
            market_data=market_data,
            symbol=symbol,
        )

        final_trend = deepseek_result.get("final_trend", "SIDE")
        confidence = deepseek_result.get("confidence", 0.5)
        deepseek_reason = deepseek_result.get("reason", "")

        print(f"[P0-CycleSwitch] {symbol}: DeepSeek仲裁={final_trend}, 置信度={confidence:.0%}")

        # 6. 趋势转换为动作
        trend_to_action = {"UP": "BUY", "DOWN": "SELL", "SIDE": "HOLD", "RANGING": "HOLD"}
        action = trend_to_action.get(final_trend, "HOLD")

        # 市场状态
        regime = "TRENDING" if adx >= 20 else "RANGING"

        # 7. 输出结果
        print(f"\n{'='*70}")
        print(f"[P0-CycleSwitch] {symbol} 周期切换分析结果 ({timeframe}min)")
        print(f"  {'='*60}")
        print(f"  信号: {action} ({final_trend}) | 置信度: {confidence:.0%}")
        print(f"  市场状态: {regime} (ADX={adx:.1f})")
        print(f"  当前价格: {current_price:.4f}")
        print(f"  位置比例: {pos_ratio:.0%} ({position_units}/{max_units})")
        print(f"  Tech: {tech_signal} | Human: {human_signal}")
        print(f"  DeepSeek: {deepseek_reason[:80] if deepseek_reason else 'N/A'}")
        print(f"{'='*70}\n")

        # 8. 执行交易 (可开关)
        executed = False
        trade_reason = ""
        CYCLE_SWITCH_ORDER_ENABLED = False  # 用户要求：关闭 _run_cycle_switch_analysis 下单功能

        is_crypto = is_crypto_symbol(symbol)

        # GCC-0194: N-Gate/HOLD_BAND已移除，外挂只被Vision过滤(扫描引擎FilterChain)
        if not CYCLE_SWITCH_ORDER_ENABLED:
            trade_reason = "P0-CycleSwitch下单已禁用"
            print(f"[P0-CycleSwitch] {symbol}: {trade_reason}")
        elif action == "BUY":
            if position_units >= max_units:
                trade_reason = f"满仓({position_units}/{max_units})，跳过买入"
                print(f"[P0-CycleSwitch] {symbol}: {trade_reason}")
                print(f"[v3.510] {symbol} 仓位门控生效: {trade_reason}")
            else:
                # v3.678: CycleSwitch观察模式 — 不直接下单，只走GCC-TM
                log_to_server(f"[v3.678][OBSERVE] CycleSwitch BUY: {symbol} @ {current_price:.4f} (观察模式,不下单)")
                _log_observe_signal("P0", symbol, "BUY", current_price, "CycleSwitch")
                send_ok = False
                try:
                    if False:  # v3.678: 原执行路径保留
                        if is_crypto:
                            send_ok = send_3commas_signal("BUY", current_price, symbol)
                        else:
                            send_ok = send_signalstack_order("BUY", symbol)

                    if send_ok is True:  # v3.560 P2-1: 严格检查，排除COOLDOWN
                        executed = True
                        trade_reason = "买入执行成功"
                        # 更新仓位
                        if symbol not in symbol_state:
                            symbol_state[symbol] = {}
                        new_pos = min(max_units, position_units + 1)
                        symbol_state[symbol]["position_units"] = new_pos
                        # v3.560 P1-1: BUY成功后补open_buys更新
                        if "open_buys" not in symbol_state[symbol]:
                            symbol_state[symbol]["open_buys"] = []
                        symbol_state[symbol]["open_buys"].append(current_price)
                        _save_state_to_disk()
                        print(f"[P0-CycleSwitch] {symbol}: ✅ 买入成功! 新仓位={new_pos}")
                        print(f"[v3.510] {symbol} BUY 执行成功 | 价格:{current_price:.4f} | 仓位:{new_pos}/{max_units}")
                    else:
                        trade_reason = "买入被门控拦截" if send_ok is None else "买入发送失败"
                except Exception as e:
                    trade_reason = f"买入执行失败: {e}"
                    print(f"[P0-CycleSwitch] {symbol}: {trade_reason}")

        elif action == "SELL":
            if position_units <= 0:
                trade_reason = f"空仓({position_units}/{max_units})，跳过卖出"
                print(f"[P0-CycleSwitch] {symbol}: {trade_reason}")
                print(f"[v3.510] {symbol} 仓位门控生效: {trade_reason}")
            else:
                # v3.678: CycleSwitch观察模式 — 不直接下单，只走GCC-TM
                log_to_server(f"[v3.678][OBSERVE] CycleSwitch SELL: {symbol} @ {current_price:.4f} (观察模式,不下单)")
                _log_observe_signal("P0", symbol, "SELL", current_price, "CycleSwitch")
                send_ok = False
                try:
                    if False:  # v3.678: 原执行路径保留
                        if is_crypto:
                            send_ok = send_3commas_signal("SELL", current_price, symbol)
                        else:
                            send_ok = send_signalstack_order("SELL", symbol)

                    if send_ok is True:  # v3.560 P2-1: 严格检查，排除COOLDOWN
                        executed = True
                        trade_reason = "卖出执行成功"
                        # 更新仓位
                        if symbol not in symbol_state:
                            symbol_state[symbol] = {}
                        new_pos = max(0, position_units - 1)
                        symbol_state[symbol]["position_units"] = new_pos
                        _save_state_to_disk()
                        print(f"[P0-CycleSwitch] {symbol}: ✅ 卖出成功! 新仓位={new_pos}")
                        print(f"[v3.510] {symbol} SELL 执行成功 | 价格:{current_price:.4f} | 仓位:{new_pos}/{max_units}")
                    else:
                        trade_reason = "卖出被门控拦截" if send_ok is None else "卖出发送失败"
                except Exception as e:
                    trade_reason = f"卖出执行失败: {e}"
                    print(f"[P0-CycleSwitch] {symbol}: {trade_reason}")
        else:
            trade_reason = "信号为HOLD，不执行交易"
            print(f"[P0-CycleSwitch] {symbol}: {trade_reason}")

        # 9. 发送邮件通知
        now_ny = datetime.now(ZoneInfo("America/New_York"))
        time_str = now_ny.strftime("%Y-%m-%d %H:%M:%S")

        email_subject = f"[P0-CycleSwitch] {symbol} {timeframe}min → {action}"
        if executed:
            email_subject = f"⚡ {email_subject} ✅"

        email_body = f"""
========================================
🔄 P0-CycleSwitch 周期切换分析
========================================

时间: {time_str} (纽约时间)
品种: {symbol}
新周期: {timeframe}分钟
K线数量: {len(ohlcv_bars)}根

----------------------------------------
分析结果:
----------------------------------------
信号: {action} ({final_trend})
置信度: {confidence:.0%}
市场状态: {regime} (ADX={adx:.1f})
当前价格: {current_price:.4f}
仓位: {position_units}/{max_units} ({pos_ratio:.0%})

----------------------------------------
三方信号:
----------------------------------------
Tech: {tech_signal} (趋势={tech_trend})
Human: {human_signal} (趋势={human_trend})
AI(DeepSeek): {final_trend}

DeepSeek分析:
{deepseek_reason[:200] if deepseek_reason else 'N/A'}

----------------------------------------
交易执行:
----------------------------------------
动作: {action}
执行: {'✅ 成功' if executed else '❌ 未执行'}
原因: {trade_reason}
新仓位: {symbol_state.get(symbol, {}).get('position_units', position_units)}/{max_units}

========================================
触发来源: P0-CycleSwitch (v3.450)
========================================
"""

        # v3.677: 只有真正成交才发邮件，未成交仅保留日志
        if executed:
            try:
                send_email_notification(email_subject, email_body)
                print(f"[P0-CycleSwitch] {symbol}: 成交邮件已发送")
            except Exception as e:
                print(f"[P0-CycleSwitch] {symbol}: 邮件发送失败 - {e}")
        else:
            log_to_server(f"[P0-CycleSwitch] {symbol}: {action} 未成交({trade_reason})，跳过邮件")

    except Exception as e:
        print(f"[P0-CycleSwitch] {symbol}: 分析失败 - {e}")
        import traceback
        traceback.print_exc()


