# v3.493: 完整L1刷新函数 - 解决启动时L1趋势判断不更新的问题
# ============================================================
def _refresh_l1_full_analysis(symbol: str, timeframe: int):
    """
    v3.493: 完整L1刷新函数

    问题: _run_cycle_switch_analysis 没有调用 compute_l1_five_module_v3300
         也没有更新 symbol_state 中的 v3300_five_module 结构
         导致监控程序显示的 x4趋势/当前趋势 不更新

    解决: 此函数执行完整的L1五模块计算并更新状态

    流程:
    1. 获取OHLCV数据
    2. 计算Tech信号 (ADX/MACD/RSI)
    3. 计算Human信号 (道氏趋势/位置)
    4. 计算趋势 (trend_x4/trend_x8)
    5. 调用 compute_l1_five_module_v3300
    6. 将结果写入 symbol_state[symbol]["_last_final_decision"]["three_way_signals"]["v3300_five_module"]
    7. 保存状态到磁盘
    """
    try:
        key = f"{symbol}_{timeframe}"
        print(f"\n{'='*70}")
        print(f"[v3.493] {symbol}: 开始完整L1五模块刷新 (周期={timeframe}min)")
        print(f"{'='*70}")

        # 1. 获取OHLCV数据
        with _ohlcv_lock:
            window = _ohlcv_windows.get(key)
            if not window or window.size() < 30:
                print(f"[v3.493] {symbol}: K线不足({window.size() if window else 0}根)，跳过刷新")
                return False
            ohlcv_bars = window.get_bars()

        print(f"[v3.493] {symbol}: 获取到 {len(ohlcv_bars)} 根K线")

        # v3.654: 数据新鲜度检测 (SYS-021)
        # v3.668+: 按主周期动态阈值，避免4H等长周期被固定5分钟/1小时误拦截
        _tf_sec = max(60, int(timeframe) * 60)
        _STALE_WARN_SEC = max(300, _tf_sec + 300)   # 至少1个bar+5分钟
        _STALE_BLOCK_SEC = max(3600, _tf_sec * 2)   # 至少2个bar才硬拦截
        if window:
            _skip_stale_gate = False
            if is_us_stock(symbol) and not _is_us_market_open():
                _skip_stale_gate = True
            _staleness = window.check_staleness(max_age_seconds=_STALE_WARN_SEC)
            system_availability_record("data", success=(_skip_stale_gate or not _staleness.get("stale")))
            if _staleness.get("stale"):
                _stale_age = _staleness.get("age_seconds", 0)
                if _skip_stale_gate:
                    log_to_server(
                        f"[DATA_STALE_SKIP][{symbol}] market_closed age={_stale_age}s "
                        f"warn>{_STALE_WARN_SEC}s block>{_STALE_BLOCK_SEC}s"
                    )
                else:
                    log_to_server(
                        f"[DATA_STALE][{symbol}] {_staleness['reason']} "
                        f"(warn>{_STALE_WARN_SEC}s, block>{_STALE_BLOCK_SEC}s)"
                    )
                    if _stale_age > _STALE_BLOCK_SEC:
                        # 加密品种在硬拦截前做一次API自救刷新，避免因单次推送中断长期卡死
                        _is_crypto_sym = symbol.endswith("USDC") or symbol.endswith("USDT")
                        if _is_crypto_sym:
                            try:
                                _rescued = False
                                _api_bars = fetch_ohlcv_from_api(symbol, timeframe, limit=3)
                                if _api_bars:
                                    with _ohlcv_lock:
                                        _existing = window.get_bars()
                                        _last_ts = 0
                                        if _existing:
                                            _last = _existing[-1]
                                            _last_ts = _last.get("timestamp") or _last.get("ts") or _last.get("time") or 0
                                        for _b in _api_bars[-2:]:
                                            _new_ts = _b.get("timestamp") or _b.get("ts") or _b.get("time") or 0
                                            if _new_ts and _last_ts and _new_ts <= _last_ts:
                                                continue
                                            window.append(_b)
                                            _rescued = True
                                if _rescued:
                                    _staleness2 = window.check_staleness(max_age_seconds=_STALE_WARN_SEC)
                                    if not _staleness2.get("stale"):
                                        log_to_server(f"[DATA_STALE_RECOVER][{symbol}] api_backfill success，继续L1执行")
                                    else:
                                        log_to_server(
                                            f"[DATA_STALE_RECOVER][{symbol}] api_backfill未恢复 "
                                            f"age={_staleness2.get('age_seconds', -1)}s"
                                        )
                                        log_to_server(
                                            f"[DATA_STALE_BLOCK][{symbol}] 数据过期{_stale_age}s>{_STALE_BLOCK_SEC}s，跳过L1执行"
                                        )
                                        return False
                                else:
                                    log_to_server(
                                        f"[DATA_STALE_RECOVER][{symbol}] api_backfill no_new_bars"
                                    )
                                    log_to_server(
                                        f"[DATA_STALE_BLOCK][{symbol}] 数据过期{_stale_age}s>{_STALE_BLOCK_SEC}s，跳过L1执行"
                                    )
                                    return False
                            except Exception as _stale_recover_e:
                                log_to_server(f"[DATA_STALE_RECOVER][{symbol}] 异常: {_stale_recover_e}")
                                log_to_server(
                                    f"[DATA_STALE_BLOCK][{symbol}] 数据过期{_stale_age}s>{_STALE_BLOCK_SEC}s，跳过L1执行"
                                )
                                return False
                            # 自救成功后重新检查并刷新本地bars快照
                            if window.check_staleness(max_age_seconds=_STALE_WARN_SEC).get("stale"):
                                return False
                            ohlcv_bars = window.get_bars()
                        log_to_server(
                            f"[DATA_STALE_BLOCK][{symbol}] 数据过期{_stale_age}s>{_STALE_BLOCK_SEC}s，跳过L1执行"
                        )
                        return False

        # 2. 获取当前价格和仓位信息
        current_price = float(ohlcv_bars[-1].get("close", ohlcv_bars[-1].get("c", 0)))
        if current_price <= 0:
            print(f"[v3.493] {symbol}: 无效价格({current_price})，跳过刷新")
            return False

        state = symbol_state.get(symbol, {})
        position_units = state.get("position_units", 0)
        max_units = state.get("max_units", 5)
        pos_ratio = position_units / max_units if max_units > 0 else 0

        # 3. 计算趋势 (trend_x4/trend_x8)
        # 从ohlcv_bars计算道氏理论趋势
        highs = [float(b.get("high", b.get("h", 0))) for b in ohlcv_bars]
        lows = [float(b.get("low", b.get("l", 0))) for b in ohlcv_bars]
        closes = [float(b.get("close", b.get("c", 0))) for b in ohlcv_bars]

        # GCC-0194: x4用EMA三线排列(7/14/20), x8保留道氏摆点
        trend_x4 = "side"
        trend_x4_dow = "side"  # 保留变量供下游兼容
        trend_x4_chan = "side"  # 保留变量避免NameError
        trend_x4_chan_score = 0.0
        trend_x8 = "side"
        x4_method = "EMA排列"
        try:
            # A: x4 EMA三线排列 — 聚合成x4周期后计算EMA(7/14/20)
            highs_x4, lows_x4 = aggregate_ohlc(ohlcv_bars, 4)
            if len(highs_x4) >= 20:
                # 聚合x4 close序列
                _x4_closes = []
                for _i in range(0, len(ohlcv_bars) - 3, 4):
                    _x4_closes.append(float(ohlcv_bars[_i + 3].get("close", ohlcv_bars[_i + 3].get("c", 0))))
                if len(_x4_closes) >= 20:
                    # EMA计算
                    def _ema_calc(data, period):
                        r = [data[0]]
                        k = 2.0 / (period + 1)
                        for v in data[1:]:
                            r.append(v * k + r[-1] * (1 - k))
                        return r
                    _e7 = _ema_calc(_x4_closes, 7)
                    _e14 = _ema_calc(_x4_closes, 14)
                    _e20 = _ema_calc(_x4_closes, 20)
                    # 最新值判断排列
                    _v7, _v14, _v20 = _e7[-1], _e14[-1], _e20[-1]
                    if _v7 > _v14 > _v20:
                        trend_x4 = "up"
                    elif _v7 < _v14 < _v20:
                        trend_x4 = "down"
                    else:
                        trend_x4 = "side"
            else:
                # K线不足20根时回退道氏
                if len(highs_x4) >= 10:
                    trend_x4 = dow_trend_from_ohlc_v3493(highs_x4, lows_x4)
            trend_x4_dow = trend_x4  # 兼容下游读取

            # B: x8保留道氏摆点
            highs_x8, lows_x8 = aggregate_ohlc(ohlcv_bars, 8)
            if len(highs_x8) >= 5:
                trend_x8 = dow_trend_from_ohlc_v3493(highs_x8, lows_x8)
        except Exception as e:
            log_to_server(f"[TREND_CALC][{symbol}] 趋势计算异常: {e}")

        log_to_server(f"[X4_EMA][{symbol}] x4={trend_x4}({x4_method}), x8={trend_x8}")

        # 4. 计算Tech信号
        tech_signals = compute_tech_signals_v2940(ohlcv_bars, tv_data=None, trend_x4=trend_x4, trend_x8=trend_x8)
        adx = tech_signals.get("raw", {}).get("adx", 0)
        chop = tech_signals.get("raw", {}).get("chop", 50)

        print(f"[v3.493] {symbol}: Tech - ADX={adx:.1f}, Chop={chop:.1f}")

        # 5. 计算Human信号
        human_signals = compute_human_signals_v2900(ohlcv_bars, pos_ratio, None, None, symbol, None)

        # 6. 构造空的AI信号 (使用Tech兜底模式)
        ai_signals = {
            "x4_regime": "UNKNOWN",      # 触发TECH_ONLY模式
            "current_regime": "UNKNOWN",
            "trend120": "UNKNOWN",
            "swing_feel": "UNKNOWN",
            "candle_now": "UNKNOWN",
            "instinct": "HOLD",
            "ai_signal": "HOLD",
            "confidence": 0.5,
            "reason": "L1刷新模式-无LLM输入",
        }

        # 7. 调用完整的L1五模块计算
        # v3.499: 计算价格在通道中的位置
        _pos_in_channel_refresh = None
        if ohlcv_bars and len(ohlcv_bars) >= 20:
            highs_20 = [float(b.get("high", b.get("h", 0))) for b in ohlcv_bars[-20:]]
            lows_20 = [float(b.get("low", b.get("l", 0))) for b in ohlcv_bars[-20:]]
            high_20 = max(highs_20)
            low_20 = min(lows_20)
            if high_20 > low_20:
                _pos_in_channel_refresh = (current_price - low_20) / (high_20 - low_20)

        l1_result = compute_l1_five_module_v3300(
            ai_signals=ai_signals,
            human_signals=human_signals,
            tech_signals=tech_signals,
            ohlcv_bars=ohlcv_bars,
            trend_x4=trend_x4,
            trend_x8=trend_x8,
            deepseek_result=None,
            deepseek_trend_override=None,
            symbol=symbol,
            pos_in_channel=_pos_in_channel_refresh,  # v3.499: 唐纳奇通道位置
        )

        big_trend = l1_result.get("ai_module", {}).get("big_trend", "SIDE")
        consensus = l1_result.get("ai_module", {}).get("consensus", "N/A")
        current_trend = l1_result.get("human_module", {}).get("current_trend", "SIDE")
        # v3.572: 读取当前周期和x4周期的震荡/趋势状态
        current_regime = l1_result.get("ai_module", {}).get("current_regime", "UNKNOWN")
        ai_x4_regime = l1_result.get("ai_module", {}).get("detail", {}).get("ai_x4_regime", "UNKNOWN")

        # v3.493: 刷新模式下，用Tech判断值覆盖ai_x4_regime，避免显示UNKNOWN
        tech_regime = l1_result.get("ai_module", {}).get("detail", {}).get("tech_regime", "RANGING")
        if "ai_module" in l1_result and "detail" in l1_result["ai_module"]:
            l1_result["ai_module"]["detail"]["ai_x4_regime"] = tech_regime
            print(f"[v3.493] {symbol}: 刷新模式 - ai_x4_regime设为{tech_regime} (原UNKNOWN)")

        print(f"[v3.493] {symbol}: L1五模块结果 - big_trend={big_trend}({consensus}), current_trend={current_trend}")

        # 8. 更新状态文件
        if symbol not in symbol_state:
            symbol_state[symbol] = {}

        # v3.510: 检测趋势转折并发送邮件
        old_big_trend = None
        try:
            old_mr = symbol_state.get(symbol, {}).get("_last_final_decision", {}).get("three_way_signals", {}).get("market_regime", {})
            old_big_trend = old_mr.get("direction")
        except Exception:  # v3.560 P2-2
            pass

        # v3.640: 检测趋势转折 - 邮件通知 (含算法详情)
        if old_big_trend and old_big_trend != big_trend:
            log_to_server(f"[TREND_CHANGE][{symbol}] 趋势转折检测: {old_big_trend} → {big_trend}")
            send_trend_change_email_v3510(
                symbol, old_big_trend, big_trend, f"L1五模块({consensus})",
                current_trend=current_trend,
                x4_method=x4_method,
                trend_x4_dow=trend_x4_dow,
                # GCC-0194: x4_chan不再传递
                # trend_x4_chan=trend_x4_chan,
            )

        # AUD-052: L1 current_trend 方向翻转检测 — 记录翻转时间供 direction_flip_cooldown 使用
        try:
            import time as _flip_time_mod
            _old_ct = old_mr.get("current_trend", "SIDE") if old_mr else "SIDE"
            if (_old_ct in ("UP", "DOWN") and current_trend in ("UP", "DOWN")
                    and _old_ct != current_trend):
                symbol_state[symbol]["_last_direction_flip_time"] = _flip_time_mod.time()
                symbol_state[symbol]["_last_direction_flip_from"] = _old_ct
                symbol_state[symbol]["_last_direction_flip_to"] = current_trend
                log_to_server(f"[DIR_FLIP] {symbol} current_trend {_old_ct}→{current_trend} 已记录翻转时间")
        except Exception as _flip_ex:
            log_to_server(f"[DIR_FLIP][ERROR] {symbol}: {_flip_ex}")

        # v3.572fix: L1刷新后始终同步到扫描引擎（不管趋势是否变化）
        # 解决: 趋势不变时扫描引擎缓存过期的问题
        # v3.586: big_trend作为唯一大周期趋势，删除trend_x4参数
        # GCC-0194: x4_chan_trend不再传递
        sync_trend_to_scan_engine_v3540(symbol, old_big_trend or "L1_REFRESH", big_trend, f"L1刷新({consensus})",
                                       current_trend=current_trend,
                                       current_regime=current_regime, regime_x4=ai_x4_regime,
                                       x4_dow_trend=trend_x4_dow.upper())

        if "_last_final_decision" not in symbol_state[symbol]:
            symbol_state[symbol]["_last_final_decision"] = {}

        if "three_way_signals" not in symbol_state[symbol]["_last_final_decision"]:
            symbol_state[symbol]["_last_final_decision"]["three_way_signals"] = {}

        # 写入v3300_five_module结果
        symbol_state[symbol]["_last_final_decision"]["three_way_signals"]["v3300_five_module"] = l1_result

        # 同时更新market_regime以保持一致性
        if "market_regime" not in symbol_state[symbol]["_last_final_decision"]["three_way_signals"]:
            symbol_state[symbol]["_last_final_decision"]["three_way_signals"]["market_regime"] = {}

        mr = symbol_state[symbol]["_last_final_decision"]["three_way_signals"]["market_regime"]
        if big_trend == "SIDE":
            mr["regime"] = "RANGING"
            mr["direction"] = "SIDE"
            mr["l2_strategy"] = "RANGE_REVERSAL"
        else:
            mr["regime"] = "TRENDING"
            mr["direction"] = big_trend
            mr["l2_strategy"] = "TREND_PULLBACK"
        mr["current_trend"] = current_trend
        mr["trend_x4"] = big_trend  # v3.581fix: 统一用big_trend (五模块综合判断)，避免与道氏理论原始计算混淆
        mr["x4_dow_trend"] = trend_x4_dow.upper()  # v3.640: 道氏x4原始结果
        # GCC-0194: x4_chan不再计算，注释掉存储
        # mr["x4_chan_trend"] = trend_x4_chan.upper()  # v3.640: 缠论x4原始结果
        # mr["x4_chan_score"] = trend_x4_chan_score     # v3.640: 缠论x4 score
        mr["current_regime"] = current_regime  # v3.572: 当前周期震荡/趋势
        mr["regime_x4"] = ai_x4_regime  # v3.572: x4周期震荡/趋势
        if _pos_in_channel_refresh is not None:  # v3.660fix: 写入position_pct供扫描引擎节奏评分
            mr["position_pct"] = round(_pos_in_channel_refresh * 100, 1)

        # 9. 保存到磁盘
        _save_state_to_disk()

        print(f"[v3.493] ✅ {symbol}: L1刷新完成 - x4趋势={big_trend}, 当前趋势={current_trend}")
        return True

    except Exception as e:
        print(f"[v3.493] ❌ {symbol}: L1刷新失败 - {e}")
        import traceback
        traceback.print_exc()
        return False


# v3.493: DOW-Swing趋势计算函数 (使用新参数 n_swing=2, min_swings=2)
def dow_trend_from_ohlc_v3493(highs: list, lows: list) -> str:
    """
    v3.493: 使用道氏理论计算趋势

    参数修正: n_swing=2, min_swings=2 (从3改为2)
    原理: 道氏理论标准定义 - 2个波峰+2个波谷即可确认趋势
    """
    if len(highs) < 10:
        return "side"

    n = len(highs)
    n_swing = 2  # v3.493: 从3改为2

    # 找摆点
    swing_highs = []
    swing_lows = []

    for i in range(n_swing, n - n_swing):
        # 检查是否是局部高点
        is_high = True
        for j in range(1, n_swing + 1):
            if highs[i] < highs[i - j] or highs[i] < highs[i + j]:
                is_high = False
                break
        if is_high:
            swing_highs.append((i, highs[i]))

        # 检查是否是局部低点
        is_low = True
        for j in range(1, n_swing + 1):
            if lows[i] > lows[i - j] or lows[i] > lows[i + j]:
                is_low = False
                break
        if is_low:
            swing_lows.append((i, lows[i]))

    min_swings = 2  # v3.493: 从3改为2
    if len(swing_highs) < min_swings or len(swing_lows) < min_swings:
        # 摆点不足，使用整体趋势兜底
        if len(highs) >= 10:
            first_half_avg = sum(highs[:len(highs)//2]) / (len(highs)//2)
            second_half_avg = sum(highs[len(highs)//2:]) / (len(highs) - len(highs)//2)
            change_pct = (second_half_avg - first_half_avg) / first_half_avg * 100 if first_half_avg > 0 else 0
            if change_pct >= 5:
                return "up"
            elif change_pct <= -5:
                return "down"
        return "side"

    # 检查趋势 (HH+HL = UP, LH+LL = DOWN)
    recent_sh = swing_highs[-min_swings:]
    recent_sl = swing_lows[-min_swings:]

    hh_count = 0
    lh_count = 0
    for i in range(1, len(recent_sh)):
        if recent_sh[i][1] > recent_sh[i-1][1]:
            hh_count += 1
        elif recent_sh[i][1] < recent_sh[i-1][1]:
            lh_count += 1

    hl_count = 0
    ll_count = 0
    for i in range(1, len(recent_sl)):
        if recent_sl[i][1] > recent_sl[i-1][1]:
            hl_count += 1
        elif recent_sl[i][1] < recent_sl[i-1][1]:
            ll_count += 1

    # 判断趋势
    if hh_count >= 1 and hl_count >= 1:
        return "up"
    elif lh_count >= 1 and ll_count >= 1:
        return "down"
    else:
        return "side"


# ============================================================
# v2.987: 方案1 - 启动时预加载历史数据
# v3.002: 添加 yfinance 超时保护
# ============================================================
YFINANCE_TIMEOUT = 30  # yfinance 单个品种超时时间（秒）

def _fetch_yfinance_history(yf_symbol: str, period: str, interval: str, timeout: int = 30):
    """v3.002: 独立函数用于超时包装
    v16.2: 添加实际超时保护，防止yfinance无限阻塞
    """
    import yfinance as yf
    from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeoutError

    def _do_fetch():
        ticker = yf.Ticker(yf_symbol)
        return ticker.history(period=period, interval=interval)

    executor = ThreadPoolExecutor(max_workers=1)
    future = executor.submit(_do_fetch)
    try:
        result = future.result(timeout=timeout)
        executor.shutdown(wait=False)
        return result
    except FuturesTimeoutError:
        print(f"[v16.2] yfinance超时({timeout}秒): {yf_symbol} period={period} interval={interval}")
        executor.shutdown(wait=False)
        return None
    except Exception as e:
        print(f"[v16.2] yfinance异常: {yf_symbol} - {e}")
        executor.shutdown(wait=False)
        return None


# v3.003: Coinbase API 作为加密货币的主数据源（使用你的API密钥）
def _fetch_coinbase_candles(symbol: str, granularity: int = 1800, limit: int = 30):
    """
    从 Coinbase API 获取 K 线数据（最可靠，使用你的 API）

    Args:
        symbol: 交易对，如 "BTCUSDC" -> "BTC-USDC"
        granularity: K线周期秒数 (1800=30m, 3600=1h)
        limit: 获取数量

    Returns:
        list of dicts: [{open, high, low, close, volume, timestamp}, ...]
    """
    import requests
    import time
    import secrets

    try:
        import jwt
        from cryptography.hazmat.primitives import serialization
    except ImportError:
        print("[v3.003] Coinbase API 需要 PyJWT 和 cryptography")
        return None

    # Coinbase API 配置 (与 coinbase_sync_v6.py 相同)
    API_KEY_NAME = "organizations/84119b71-e971-4844-8f91-bcfe54504c66/apiKeys/7d69e6f2-88a1-45e7-b806-0821bf0f3848"
    API_PRIVATE_KEY = """-----BEGIN EC PRIVATE KEY-----
MHcCAQEEICBNdsz8FxLsQV/OCaDkEjkpKgBHG6GYqapzBDmrmaCnoAoGCCqGSM49
AwEHoUQDQgAEYrjK0/oRfzzn+7LyIOrh+EX5eJ8Fzka04aENf18uVkAbqyzoGEuD
V4+auZ+gdWHPb5UXeVIWwMQhEe+a9xp34g==
-----END EC PRIVATE KEY-----"""

    # 符号映射: BTCUSDC -> BTC-USDC
    symbol_map = {
        "BTCUSDC": "BTC-USDC",
        "ETHUSDC": "ETH-USDC",
        "SOLUSDC": "SOL-USDC",
        "ZECUSDC": "ZEC-USDC",
    }
    product_id = symbol_map.get(symbol, symbol.replace("USDC", "-USDC"))

    # 计算时间范围
    end_time = int(time.time())
    start_time = end_time - (granularity * limit)

    path = f"/api/v3/brokerage/products/{product_id}/candles"
    uri = f"GET api.coinbase.com{path}"

    try:
        # 构建 JWT
        private_key = serialization.load_pem_private_key(
            API_PRIVATE_KEY.encode('utf-8'),
            password=None
        )
        payload = {
            "sub": API_KEY_NAME,
            "iss": "cdp",
            "nbf": int(time.time()),
            "exp": int(time.time()) + 120,
            "uri": uri,
        }
        token = jwt.encode(
            payload,
            private_key,
            algorithm="ES256",
            headers={"kid": API_KEY_NAME, "nonce": secrets.token_hex(16)}
        )

        # 请求 K 线
        headers = {
            "Authorization": f"Bearer {token}",
            "Content-Type": "application/json"
        }

        # v3.470: Coinbase API granularity需要字符串枚举值，不是秒数
        GRANULARITY_MAP = {
            60: "ONE_MINUTE",
            300: "FIVE_MINUTE",
            900: "FIFTEEN_MINUTE",
            1800: "THIRTY_MINUTE",
            3600: "ONE_HOUR",
            7200: "TWO_HOUR",
            21600: "SIX_HOUR",
            86400: "ONE_DAY",
        }
        granularity_str = GRANULARITY_MAP.get(granularity, "ONE_HOUR")

        params = {
            "start": str(start_time),
            "end": str(end_time),
            "granularity": granularity_str  # v3.470: 使用字符串枚举值
        }

        response = requests.get(
            f"https://api.coinbase.com{path}",
            headers=headers,
            params=params,
            timeout=15
        )

        if response.status_code != 200:
            print(f"[v3.003] Coinbase API {symbol}: HTTP {response.status_code}")
            return None

        data = response.json()
        candles = data.get("candles", [])

        bars = []
        for c in candles:
            bar = {
                "open": float(c.get("open", 0)),
                "high": float(c.get("high", 0)),
                "low": float(c.get("low", 0)),
                "close": float(c.get("close", 0)),
                "volume": float(c.get("volume", 0)),
                "sr_zone": "MID",
                "timestamp": int(c.get("start", 0)),
            }
            # 数据验证
            if bar["close"] > 0 and bar["high"] > 0 and bar["low"] > 0:
                bars.append(bar)

        # Coinbase 返回的是倒序，需要反转
        bars.reverse()
        print(f"[v3.003] ✅ Coinbase {symbol}: 获取 {len(bars)} 根有效K线")
        return bars

    except Exception as e:
        print(f"[v3.003] Coinbase API 错误 {symbol}: {e}")
        return None


_DATA_SOURCE_HEALTH_PATH = os.path.join("state", "data_source_health.json")
_data_source_stats = {
    "updated_at": 0.0,
    "crypto": {
        "coinbase": {"success": 0, "fail": 0, "last_success_ts": 0.0, "last_fail_ts": 0.0},
        "yfinance": {"success": 0, "fail": 0, "last_success_ts": 0.0, "last_fail_ts": 0.0},
    },
    "stock": {
        "yfinance": {"success": 0, "fail": 0, "last_success_ts": 0.0, "last_fail_ts": 0.0},
        "schwab": {"success": 0, "fail": 0, "last_success_ts": 0.0, "last_fail_ts": 0.0},
        "fallback_alert": {"last_alert_ts": 0.0, "no_success_hours_threshold": 6},
    },
}


def _bump_data_source_stat(market: str, provider: str, ok: bool):
    import time as _t
    try:
        bucket = _data_source_stats.get(market, {}).get(provider, {})
        if not bucket:
            return
        now_ts = _t.time()
        if ok:
            bucket["success"] = int(bucket.get("success", 0)) + 1
            bucket["last_success_ts"] = now_ts
        else:
            bucket["fail"] = int(bucket.get("fail", 0)) + 1
            bucket["last_fail_ts"] = now_ts
        _data_source_stats["updated_at"] = now_ts
    except Exception:
        pass


def _flush_data_source_health():
    try:
        os.makedirs(os.path.dirname(_DATA_SOURCE_HEALTH_PATH), exist_ok=True)
        with open(_DATA_SOURCE_HEALTH_PATH, "w", encoding="utf-8") as f:
            json.dump(_data_source_stats, f, ensure_ascii=False, indent=2)
    except Exception:
        pass


def _get_data_source_health_snapshot():
    import time as _t
    now_ts = _t.time()
    snap = json.loads(json.dumps(_data_source_stats, ensure_ascii=False))
    try:
        for mk in ("crypto", "stock"):
            for pr, v in snap.get(mk, {}).items():
                if not isinstance(v, dict) or pr == "fallback_alert":
                    continue
                lss = float(v.get("last_success_ts", 0.0) or 0.0)
                v["last_success_age_min"] = round((now_ts - lss) / 60.0, 1) if lss > 0 else None
                lfs = float(v.get("last_fail_ts", 0.0) or 0.0)
                v["last_fail_age_min"] = round((now_ts - lfs) / 60.0, 1) if lfs > 0 else None
    except Exception:
        pass
    return snap


def _fetch_stock_ohlcv_from_schwab(symbol: str, timeframe: int, limit: int = 120):
    """
    股票数据二级回退：Schwab（统一入口）
    """
    import time as _t
    import pandas as _pd

    interval_map = {
        1: "1m",
        5: "5m",
        10: "10m",
        15: "15m",
        30: "30m",
        60: "30m",   # Schwab适配层无1h，回退用30m
        90: "30m",
        120: "30m",
        240: "4h",
        1440: "1d",
    }
    interval = interval_map.get(int(timeframe), "1d")
    bars_need = max(int(limit or 120), 10)
    try:
        from schwab_data_provider import get_provider
        provider = get_provider()
        if not hasattr(_fetch_stock_ohlcv_from_schwab, "_mode_logged"):
            log_to_server("[SCHWAB_FALLBACK] mode=active provider_available=True")
            _fetch_stock_ohlcv_from_schwab._mode_logged = True

        if interval in ("1d", "1wk"):
            df = provider.download(symbol, period="6mo", interval=interval)
            if df is not None and not df.empty and len(df) > bars_need:
                df = df.tail(bars_need)
        else:
            df = provider.get_kline(symbol, interval=interval, bars=bars_need)

        if df is None or getattr(df, "empty", True):
            _bump_data_source_stat("stock", "schwab", ok=False)
            log_to_server(f"[SCHWAB_FALLBACK] {symbol} tf={timeframe} no_data")
            return None

        out = []
        for idx, row in df.tail(bars_need).iterrows():
            close_val = float(row.get("close", row.get("Close", 0))) if not _pd.isna(row.get("close", row.get("Close", 0))) else 0
            if close_val <= 0:
                continue
            open_val = float(row.get("open", row.get("Open", close_val))) if not _pd.isna(row.get("open", row.get("Open", close_val))) else close_val
            high_val = float(row.get("high", row.get("High", close_val))) if not _pd.isna(row.get("high", row.get("High", close_val))) else close_val
            low_val = float(row.get("low", row.get("Low", close_val))) if not _pd.isna(row.get("low", row.get("Low", close_val))) else close_val
            if any(math.isinf(x) for x in (open_val, high_val, low_val, close_val)):
                continue
            if high_val > 0 and low_val > 0 and high_val < low_val:
                continue
            ts = idx.timestamp() if hasattr(idx, "timestamp") else 0
            out.append({
                "open": open_val,
                "high": high_val,
                "low": low_val,
                "close": close_val,
                "volume": float(row.get("volume", row.get("Volume", 0))) if not _pd.isna(row.get("volume", row.get("Volume", 0))) else 0,
                "sr_zone": "MID",
                "timestamp": int(ts),
            })

        if out:
            _bump_data_source_stat("stock", "schwab", ok=True)
            log_to_server(f"[SCHWAB_FALLBACK] {symbol} tf={timeframe} success bars={len(out)} interval={interval}")
            return out

        _bump_data_source_stat("stock", "schwab", ok=False)
        log_to_server(f"[SCHWAB_FALLBACK] {symbol} tf={timeframe} no_valid_bars interval={interval}")
        return None
    except Exception as e:
        _bump_data_source_stat("stock", "schwab", ok=False)
        log_to_server(f"[SCHWAB_FALLBACK] {symbol} tf={timeframe} failed: {e}")
        return None
    finally:
        _data_source_stats["updated_at"] = _t.time()
        _flush_data_source_health()


def _check_stock_fallback_health_alert():
    import time as _t
    now_ts = _t.time()
    try:
        cfg = _data_source_stats.get("stock", {}).get("fallback_alert", {})
        threshold_h = int(cfg.get("no_success_hours_threshold", 6) or 6)
        last_success = float(_data_source_stats.get("stock", {}).get("schwab", {}).get("last_success_ts", 0.0) or 0.0)
        if last_success <= 0:
            first_seen = float(_data_source_stats.get("updated_at", 0.0) or 0.0)
            fail_cnt = int(_data_source_stats.get("stock", {}).get("schwab", {}).get("fail", 0) or 0)
            if first_seen <= 0 or fail_cnt <= 0:
                return
            silent_sec = now_ts - first_seen
        else:
            silent_sec = now_ts - last_success
        if silent_sec < threshold_h * 3600:
            return
        last_alert = float(cfg.get("last_alert_ts", 0.0) or 0.0)
        if (now_ts - last_alert) < 3600:
            return
        cfg["last_alert_ts"] = now_ts
        _data_source_stats["updated_at"] = now_ts
        log_to_server(
            f"[RISK][DATA-SOURCE] stock schwab fallback no_success_for={silent_sec/3600:.1f}h "
            f"threshold={threshold_h}h (check token/provider/env)"
        )
    except Exception:
        pass
    finally:
        _flush_data_source_health()


def fetch_ohlcv_from_api(symbol: str, timeframe: int, limit: int = 120):
    """
    v3.472: 统一的OHLCV获取接口
    根据品种类型自动选择 Coinbase（加密货币）或 yfinance（美股）

    Args:
        symbol: 品种代码，如 "BTCUSDC" 或 "TSLA"
        timeframe: 周期（分钟）
        limit: 获取K线数量

    Returns:
        list of dicts: [{open, high, low, close, volume, timestamp, sr_zone}, ...]
    """
    # 判断是否为加密货币
    crypto_symbols = ["BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"]
    is_crypto = symbol in crypto_symbols or symbol.endswith("USDC") or symbol.endswith("USDT")

    if is_crypto:
        # 加密货币用 Coinbase API
        granularity = timeframe * 60  # 分钟转秒
        bars = _fetch_coinbase_candles(symbol, granularity=granularity, limit=limit)
        if bars:
            _bump_data_source_stat("crypto", "coinbase", ok=True)
            print(f"[v3.472] {symbol} 从Coinbase获取 {len(bars)} 根K线")
            _flush_data_source_health()
            return bars
        _bump_data_source_stat("crypto", "coinbase", ok=False)
        # Coinbase失败后，回退到 yfinance（加密双源兜底）
        try:
            symbol_map = {
                "BTCUSDC": "BTC-USD",
                "ETHUSDC": "ETH-USD",
                "SOLUSDC": "SOL-USD",
                "ZECUSDC": "ZEC-USD",
            }
            yf_symbol = symbol_map.get(symbol, symbol.replace("USDC", "-USD").replace("USDT", "-USD"))

            yf_interval_map = {
                15: ("15m", "5d"),
                30: ("30m", "7d"),
                60: ("1h", "1mo"),
                90: ("90m", "1mo"),
                120: ("1h", "1mo"),   # yfinance无2h，使用1h
                240: ("4h", "3mo"),
                1440: ("1d", "1y"),
            }
            if timeframe in yf_interval_map:
                interval, period = yf_interval_map[timeframe]
            else:
                supported_tfs = sorted(yf_interval_map.keys())
                closest_tf = min(supported_tfs, key=lambda x: abs(x - timeframe))
                interval, period = yf_interval_map[closest_tf]

            df = _fetch_yfinance_history(yf_symbol, period=period, interval=interval)
            if df is not None and len(df) >= 10:
                bars = []
                for idx, row in df.tail(limit).iterrows():
                    bar = {
                        "open": float(row.get("Open", 0)),
                        "high": float(row.get("High", 0)),
                        "low": float(row.get("Low", 0)),
                        "close": float(row.get("Close", 0)),
                        "volume": float(row.get("Volume", 0)),
                        "sr_zone": "MID",
                        "timestamp": int(idx.timestamp()) if hasattr(idx, "timestamp") else 0,
                    }
                    if bar["close"] > 0 and bar["high"] > 0 and bar["low"] > 0 and bar["high"] >= bar["low"]:
                        bars.append(bar)
                if bars:
                    _bump_data_source_stat("crypto", "yfinance", ok=True)
                    print(f"[v3.472] {symbol} 从yfinance回退获取 {len(bars)} 根K线")
                    _flush_data_source_health()
                    return bars
        except Exception as e:
            print(f"[v3.472] crypto yfinance回退失败 {symbol}: {e}")
        _bump_data_source_stat("crypto", "yfinance", ok=False)
    else:
        # 美股用 yfinance
        try:
            # 映射周期
            interval_map = {
                1: "1m", 5: "5m", 15: "15m", 30: "30m",
                60: "1h", 120: "2h", 240: "4h", 1440: "1d"
            }
            interval = interval_map.get(timeframe, "1h")

            # v3.472: 计算需要的天数（美股每天只有6.5小时交易）
            # 目标120根K线，按每天6.5小时计算
            if timeframe <= 30:
                period = "7d"      # 30m: 7天×13根=91根
            elif timeframe <= 60:
                period = "1mo"     # 1h: 22天×6.5根=143根 ✓
            elif timeframe <= 240:
                period = "3mo"     # 4h: 66天×1.6根=106根 (x4需要更多数据)
            else:
                period = "1y"

            df = _fetch_yfinance_history(symbol, period=period, interval=interval)
            if df is not None and len(df) >= 10:
                bars = []
                for idx, row in df.tail(limit).iterrows():
                    bar = {
                        "open": float(row.get("Open", 0)),
                        "high": float(row.get("High", 0)),
                        "low": float(row.get("Low", 0)),
                        "close": float(row.get("Close", 0)),
                        "volume": float(row.get("Volume", 0)),
                        "sr_zone": "MID",
                        "timestamp": int(idx.timestamp()) if hasattr(idx, 'timestamp') else 0,
                    }
                    if bar["close"] > 0:
                        bars.append(bar)
                _bump_data_source_stat("stock", "yfinance", ok=True)
                print(f"[v3.472] {symbol} 从yfinance获取 {len(bars)} 根K线")
                _flush_data_source_health()
                return bars
        except Exception as e:
            print(f"[v3.472] yfinance获取失败 {symbol}: {e}")
        _bump_data_source_stat("stock", "yfinance", ok=False)
        schwab_bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=timeframe, limit=limit)
        if schwab_bars:
            print(f"[v3.472] {symbol} 从Schwab回退获取 {len(schwab_bars)} 根K线")
            return schwab_bars

    _flush_data_source_health()
    return None


# === v3.610: MACD 30m数据预加载 ===
_macd_preloaded = {}  # {symbol: True} 记录已预加载的品种
# GCC-0199: MACD震荡过滤 — RANGING时要求连续2周期确认
_macd_ranging_confirm = {}  # {symbol_action: {"ts": float, "count": int}}

def _preload_macd_30m_data(symbol: str) -> list:
    """
    v3.610: 从API拉取30m数据，供MACD背离立即使用

    直接使用fetch_ohlcv_from_api(symbol, 30, 120):
    - 美股: yfinance interval="30m", period="7d" → ~91根
    - crypto: Coinbase granularity=1800 → 120根
    """
    try:
        bars = fetch_ohlcv_from_api(symbol, timeframe=30, limit=120)
        if not bars or len(bars) < 50:
            print(f"[v3.610] {symbol} MACD预加载: 30m数据不足({len(bars) if bars else 0}根)")
            return []
        print(f"[v3.610] {symbol} MACD预加载: 获取{len(bars)}根30m K线")
        return bars
    except Exception as e:
        print(f"[v3.610] {symbol} MACD预加载失败(不阻塞): {e}")
        return []


def preload_ohlcv_from_yfinance(symbols: list, timeframe: int = 30):
    """
    启动时预加载历史K线数据
    v3.003: 优先使用 Coinbase API，yfinance 作为备用
    v3.445: 使用品种独立周期配置，支持2h/4h周期

    Args:
        symbols: 品种列表
        timeframe: 周期（分钟）- 现作为默认值，实际使用 get_symbol_timeframe()
    """
    print(f"[v3.445] 🚀 启动预加载OHLCV数据 (品种独立周期)...")

    # 加密货币符号列表 (使用 Coinbase)
    crypto_symbols = {"BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"}

    loaded_count = 0

    # === 第一步: 尝试 Coinbase API (加密货币) ===
    for symbol in symbols:
        if symbol in crypto_symbols:
            window = get_ohlcv_window(symbol)
            if window.is_ready():
                print(f"[v3.445] ⏭️ {symbol}: 窗口已就绪，跳过")
                loaded_count += 1
                continue

            # v3.445: 使用品种独立周期确定 granularity
            # v21.5: 4H周期用1H granularity + resample (Coinbase无原生4H)
            symbol_tf = get_symbol_timeframe(symbol)
            need_resample = False
            if symbol_tf <= 15:
                granularity = 900    # 15分钟
                cb_limit = 100
            elif symbol_tf <= 30:
                granularity = 1800   # 30分钟
                cb_limit = 100
            elif symbol_tf <= 60:
                granularity = 3600   # 1小时
                cb_limit = 120
            elif symbol_tf <= 120:
                granularity = 7200   # 2小时 (v3.445新增)
                cb_limit = 120
            else:
                # v21.5: 4H周期 → 用1H获取再resample, 避免6H粒度不匹配
                granularity = 3600   # 1小时
                cb_limit = 300       # 300根1H ≈ 12天, resample后75根4H
                need_resample = True

            print(f"[v21.5] {symbol}: 周期={symbol_tf}min, granularity={granularity}s, limit={cb_limit}, resample={need_resample}")
            bars = _fetch_coinbase_candles(symbol, granularity=granularity, limit=cb_limit)
            if bars and len(bars) >= 8:
                if need_resample and len(bars) >= 4:
                    # v21.5: 1H → 4H resample (每4根合并为1根)
                    resampled = []
                    for i in range(0, len(bars) - 3, 4):
                        chunk = bars[i:i+4]
                        resampled.append({
                            "open": chunk[0]["open"],
                            "high": max(b["high"] for b in chunk),
                            "low": min(b["low"] for b in chunk),
                            "close": chunk[-1]["close"],
                            "volume": sum(b.get("volume", 0) for b in chunk),
                            "sr_zone": chunk[-1].get("sr_zone", "MID"),
                        })
                    bars = resampled
                    print(f"[v21.5] {symbol}: 1H→4H resample完成, {len(bars)}根4H K线")
                for bar in bars:
                    window.append(bar)
                loaded_count += 1
                print(f"[v21.5] ✅ {symbol}: Coinbase 预加载 {window.size()} 根K线 (周期={symbol_tf}min)")
                continue
            else:
                print(f"[v3.445] ⚠️ {symbol}: Coinbase 失败，尝试 yfinance...")

    # === 第二步: yfinance 备用 (Coinbase 失败的或非加密货币) ===
    try:
        import yfinance as yf
        import pandas as pd
    except ImportError:
        print("[v3.445] ⚠️ yfinance未安装，跳过备用预加载")
        return

    from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeoutError

    symbol_map = {
        "BTCUSDC": "BTC-USD",
        "ETHUSDC": "ETH-USD",
        "SOLUSDC": "SOL-USD",
        "ZECUSDC": "ZEC-USD",
    }

    for symbol in symbols:
        try:
            # v3.003: 跳过已就绪的窗口 (Coinbase 已加载)
            window = get_ohlcv_window(symbol)
            if window.is_ready():
                continue

            # 获取yfinance符号
            yf_symbol = symbol_map.get(symbol, symbol)

            # v3.472: 根据品种独立周期确定 interval/period（优化美股数据量，支持x4分析）
            symbol_tf = get_symbol_timeframe(symbol)
            if symbol_tf <= 15:
                interval = "15m"
                period = "5d"
            elif symbol_tf <= 30:
                interval = "30m"
                period = "7d"
            elif symbol_tf <= 60:
                interval = "1h"
                period = "1mo"    # v3.472: 22天×6.5=143根
            elif symbol_tf <= 120:
                interval = "2h"
                period = "1mo"    # v3.472: 22天×3.25=72根
            else:
                interval = "4h"
                period = "3mo"    # v3.472: 66天×1.6=106根 (x4需要更多)

            print(f"[v3.445] {symbol}: yfinance interval={interval}, period={period}")

            # v3.002: 使用 ThreadPoolExecutor 添加超时保护
            hist = None
            try:
                with ThreadPoolExecutor(max_workers=1) as executor:
                    future = executor.submit(_fetch_yfinance_history, yf_symbol, period, interval)
                    hist = future.result(timeout=YFINANCE_TIMEOUT)
            except FuturesTimeoutError:
                print(f"[v3.445] ⚠️ {symbol}: yfinance 超时 ({YFINANCE_TIMEOUT}秒)，跳过")
                if symbol not in crypto_symbols:
                    _bump_data_source_stat("stock", "yfinance", ok=False)
                    schwab_bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=symbol_tf, limit=120)
                    if schwab_bars:
                        for bar in schwab_bars:
                            window.append(bar)
                        print(f"[v3.445] ✅ {symbol}: Schwab预加载 {window.size()} 根K线 (周期={symbol_tf}min)")
                        loaded_count += 1
                continue
            except Exception as e:
                print(f"[v3.445] ⚠️ {symbol}: yfinance 错误 - {e}")
                if symbol not in crypto_symbols:
                    _bump_data_source_stat("stock", "yfinance", ok=False)
                    schwab_bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=symbol_tf, limit=120)
                    if schwab_bars:
                        for bar in schwab_bars:
                            window.append(bar)
                        print(f"[v3.445] ✅ {symbol}: Schwab预加载 {window.size()} 根K线 (周期={symbol_tf}min)")
                        loaded_count += 1
                continue

            if hist is None or hist.empty:
                print(f"[v3.445] {symbol}: yfinance 无历史数据")
                if symbol not in crypto_symbols:
                    _bump_data_source_stat("stock", "yfinance", ok=False)
                    schwab_bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=symbol_tf, limit=120)
                    if schwab_bars:
                        for bar in schwab_bars:
                            window.append(bar)
                        print(f"[v3.445] ✅ {symbol}: Schwab预加载 {window.size()} 根K线 (周期={symbol_tf}min)")
                        loaded_count += 1
                continue

            # 填充数据 (v3.445: 添加数据质量验证)
            valid_bars = 0
            skipped_bars = 0
            for idx, row in hist.iterrows():
                try:
                    close_val = float(row["Close"]) if not pd.isna(row["Close"]) else 0
                    open_val = float(row["Open"]) if not pd.isna(row["Open"]) else close_val
                    high_val = float(row["High"]) if not pd.isna(row["High"]) else close_val
                    low_val = float(row["Low"]) if not pd.isna(row["Low"]) else close_val

                    # 跳过无效数据（close=0, NaN, Inf, high<low）v3.680
                    if close_val <= 0 or high_val <= 0 or low_val <= 0:
                        skipped_bars += 1
                        continue
                    if any(math.isinf(x) for x in (open_val, high_val, low_val, close_val)):
                        skipped_bars += 1
                        continue
                    if high_val < low_val:
                        skipped_bars += 1
                        continue

                    bar = {
                        "open": open_val,
                        "high": high_val,
                        "low": low_val,
                        "close": close_val,
                        "volume": float(row["Volume"]) if "Volume" in row and not pd.isna(row["Volume"]) else 0,
                        "sr_zone": "MID",
                        "timestamp": idx.timestamp() if hasattr(idx, 'timestamp') else 0,
                    }
                    window.append(bar)
                    valid_bars += 1
                except Exception as e:
                    skipped_bars += 1

            # 显示有效/跳过的K线数
            if skipped_bars > 0:
                print(f"[v3.445] ⚠️ {symbol}: 跳过 {skipped_bars} 根无效K线")
            if valid_bars > 0:
                _bump_data_source_stat("stock", "yfinance", ok=True)
                print(f"[v3.445] ✅ {symbol}: yfinance 预加载 {window.size()} 根K线 (周期={symbol_tf}min)")
                loaded_count += 1
            elif symbol not in crypto_symbols:
                _bump_data_source_stat("stock", "yfinance", ok=False)
                schwab_bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=symbol_tf, limit=120)
                if schwab_bars:
                    for bar in schwab_bars:
                        window.append(bar)
                    print(f"[v3.445] ✅ {symbol}: Schwab预加载 {window.size()} 根K线 (周期={symbol_tf}min)")
                    loaded_count += 1

        except Exception as e:
            print(f"[v3.445] ❌ {symbol}: 预加载失败 - {e}")

    print(f"[v3.445] 🎯 预加载完成: {loaded_count}/{len(symbols)} 品种")
    return loaded_count


def _preload_single_symbol(symbol: str, timeframe: int, force_update: bool = False):
    """
    v3.445: 单品种预加载（切换周期时调用）
    v3.470: 添加force_update参数支持后台定时更新

    Args:
        symbol: 品种代码
        timeframe: 周期(分钟)
        force_update: 是否强制更新（忽略缓存大小检查）
    """
    crypto_symbols = {"BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"}
    key = f"{symbol}_{timeframe}"

    # v3.600: 动态缓冲区大小
    _tf_params = get_timeframe_params(timeframe, is_crypto=is_crypto_symbol(symbol))
    _buf_size = _tf_params["ohlcv_buffer_size"]

    # 获取窗口（不触发递归预加载）
    with _ohlcv_lock:
        if key not in _ohlcv_windows:
            _ohlcv_windows[key] = OHLCVWindow(max_size=_buf_size, timeframe_minutes=timeframe)
        window = _ohlcv_windows[key]

    # 已有足够数据，跳过（除非强制更新）
    if not force_update and window.size() >= 20:
        print(f"[v3.445] {symbol}: 缓存已有{window.size()}根K线，跳过预加载")
        return

    # === v3.470: 精确的API周期映射表 ===
    # Coinbase支持: 15m(900), 30m(1800), 1H(3600), 2H(7200), 6H(21600), 1D(86400)
    # yfinance支持: 15m, 30m, 1h, 90m, 4h, 1d (不支持2h, 3h!)
    COINBASE_GRANULARITY = {
        15: 900,      # 15分钟
        30: 1800,     # 30分钟
        60: 3600,     # 1小时
        120: 7200,    # 2小时
        360: 21600,   # 6小时
        1440: 86400,  # 1天
    }

    YFINANCE_INTERVAL = {
        15: ("15m", "5d"),
        30: ("30m", "5d"),
        60: ("1h", "7d"),
        90: ("90m", "7d"),
        240: ("4h", "30d"),   # 4小时
        1440: ("1d", "60d"),  # 1天
    }

    # === Coinbase (加密货币) ===
    if symbol in crypto_symbols:
        granularity = COINBASE_GRANULARITY.get(timeframe)
        if granularity:
            bars = _fetch_coinbase_candles(symbol, granularity=granularity, limit=_buf_size)
        else:
            print(f"[v3.470] {symbol}: {timeframe}min 周期Coinbase不支持，使用yfinance")
            bars = []
        if bars and len(bars) >= 8:
            for bar in bars:
                window.append(bar)
            print(f"[v3.445] ✅ {symbol}: Coinbase预加载 {window.size()}根 {timeframe}min K线")
            return

    # === yfinance (美股或Coinbase失败/不支持) ===
    try:
        import yfinance as yf
        import pandas as pd
        from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeoutError

        symbol_map = {
            "BTCUSDC": "BTC-USD",
            "ETHUSDC": "ETH-USD",
            "SOLUSDC": "SOL-USD",
            "ZECUSDC": "ZEC-USD",
        }

        yf_symbol = symbol_map.get(symbol, symbol)

        # v3.470: 使用精确映射表，不支持的周期用最接近的
        if timeframe in YFINANCE_INTERVAL:
            interval, period = YFINANCE_INTERVAL[timeframe]
        else:
            # 找最接近的支持周期
            supported_tfs = sorted(YFINANCE_INTERVAL.keys())
            closest_tf = min(supported_tfs, key=lambda x: abs(x - timeframe))
            interval, period = YFINANCE_INTERVAL[closest_tf]
            print(f"[v3.470] {symbol}: {timeframe}min yfinance不支持，使用{closest_tf}min ({interval})")

        with ThreadPoolExecutor(max_workers=1) as executor:
            future = executor.submit(_fetch_yfinance_history, yf_symbol, period, interval)
            hist = future.result(timeout=YFINANCE_TIMEOUT)

        if hist is not None and not hist.empty:
            valid_bars = 0
            for idx, row in hist.iterrows():
                try:
                    close_val = float(row["Close"]) if not pd.isna(row["Close"]) else 0
                    if close_val <= 0:
                        continue
                    open_val = float(row["Open"]) if not pd.isna(row["Open"]) else close_val
                    high_val = float(row["High"]) if not pd.isna(row["High"]) else close_val
                    low_val = float(row["Low"]) if not pd.isna(row["Low"]) else close_val
                    # v3.680: Inf/high<low过滤
                    if any(math.isinf(x) for x in (open_val, high_val, low_val, close_val)):
                        continue
                    if high_val > 0 and low_val > 0 and high_val < low_val:
                        continue
                    bar = {
                        "open": open_val,
                        "high": high_val,
                        "low": low_val,
                        "close": close_val,
                        "volume": float(row["Volume"]) if "Volume" in row and not pd.isna(row["Volume"]) else 0,
                        "sr_zone": "MID",
                        "timestamp": idx.timestamp() if hasattr(idx, 'timestamp') else 0,
                    }
                    window.append(bar)
                    valid_bars += 1
                except Exception:  # v3.560 P2-2
                    pass
            if valid_bars > 0:
                if symbol not in crypto_symbols:
                    _bump_data_source_stat("stock", "yfinance", ok=True)
                print(f"[v3.445] ✅ {symbol}: yfinance预加载 {window.size()}根 {timeframe}min K线")
                return
        if symbol not in crypto_symbols:
            _bump_data_source_stat("stock", "yfinance", ok=False)
            schwab_bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=timeframe, limit=_buf_size)
            if schwab_bars:
                for bar in schwab_bars:
                    window.append(bar)
                print(f"[v3.445] ✅ {symbol}: Schwab预加载 {window.size()}根 {timeframe}min K线")
    except Exception as e:
        print(f"[v3.445] ⚠️ {symbol}: 预加载失败 - {e}")


# ============================================================
# v3.472: 启动时预加载BACKGROUND_TIMEFRAMES所有周期
# ============================================================
def preload_background_timeframes():
    """
    v3.472: 启动时预加载BACKGROUND_TIMEFRAMES中所有symbol+timeframe组合

    解决问题: 原预加载只加载默认交易周期，BACKGROUND_TIMEFRAMES中的额外周期没有数据
    """
    print(f"\n[v3.472] {'='*50}")
    print(f"[v3.472] 🚀 预加载BACKGROUND_TIMEFRAMES所有周期")
    print(f"[v3.472] {'='*50}")

    loaded_count = 0
    total_count = sum(len(tfs) for tfs in BACKGROUND_TIMEFRAMES.values())

    for symbol, timeframes in BACKGROUND_TIMEFRAMES.items():
        for tf in timeframes:
            try:
                key = f"{symbol}_{tf}"

                # v3.600: 动态缓冲区大小
                _tf_params = get_timeframe_params(tf, is_crypto=is_crypto_symbol(symbol))
                _buf_size = _tf_params["ohlcv_buffer_size"]

                # 获取或创建窗口
                with _ohlcv_lock:
                    if key not in _ohlcv_windows:
                        _ohlcv_windows[key] = OHLCVWindow(max_size=_buf_size, timeframe_minutes=tf)
                    window = _ohlcv_windows[key]

                # v3.472: 如果已有足够数据，跳过（阈值100，确保x4分析有足够数据）
                if window.size() >= 100:
                    print(f"[v3.472] {key}: 已有{window.size()}根，跳过")
                    loaded_count += 1
                    continue

                # v3.600: 动态limit，与缓冲区大小一致
                print(f"[v3.600] 📥 {key}: 预加载中 (limit={_buf_size})...")
                bars = fetch_ohlcv_from_api(symbol, tf, limit=_buf_size)

                if bars and len(bars) >= 10:
                    # 清空并重新填充
                    window.clear()
                    for bar in bars:
                        window.append(bar)
                    print(f"[v3.472] ✅ {key}: 预加载 {window.size()} 根K线")
                    loaded_count += 1
                else:
                    print(f"[v3.472] ⚠️ {key}: 预加载失败，只有{len(bars) if bars else 0}根")

                # 每个请求间隔1秒，避免API限流
                import time
                time.sleep(1)

            except Exception as e:
                print(f"[v3.472] ❌ {symbol}_{tf}: 预加载异常 - {e}")

    print(f"\n[v3.472] 📊 预加载完成: {loaded_count}/{total_count} 个周期")
    print(f"[v3.472] {'='*50}\n")


# ============================================================
# v3.551: 美股市场状态检测 (用于后台L1定时刷新)
# ============================================================
def _is_us_market_open() -> bool:
    """v3.551: 检查美股市场是否开盘 (纽约时间 9:30-16:00, 工作日)"""
    try:
        from zoneinfo import ZoneInfo
    except ImportError:
        from backports.zoneinfo import ZoneInfo
    ny_now = datetime.now(ZoneInfo("America/New_York"))
    weekday = ny_now.weekday()
    if weekday >= 5:  # 周六日
        return False
    hour, minute = ny_now.hour, ny_now.minute
    if hour < 9 or (hour == 9 and minute < 30):
        return False
    if hour >= 16:
        return False
    return True


# ============================================================
# v3.470: 后台OHLCV定时更新
# ============================================================
_background_updater_running = False
_background_updater_thread = None

def _background_ohlcv_updater():
    """
    v3.470: 后台定时更新所有配置周期的OHLCV
    v3.551: 美股盘中定时L1趋势刷新(1H K线)

    功能：
    - 定时从Coinbase/yfinance获取最新K线
    - 更新非当前交易周期的缓存
    - 确保切换周期时数据是最新的
    - v3.551: 每30分钟用1H K线刷新美股L1趋势判断
    """
    global _background_updater_running
    import time

    print(f"[v3.470] 🔄 后台OHLCV更新器启动，间隔={BACKGROUND_UPDATE_INTERVAL}秒")

    # v3.551: 美股L1刷新轮次计数器
    stock_l1_round_counter = 0

    # v3.551: 美股品种列表(从BACKGROUND_TIMEFRAMES中排除加密货币)
    crypto_set = {"BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"}
    stock_symbols = [s for s in BACKGROUND_TIMEFRAMES if s not in crypto_set]

    while _background_updater_running:
        try:
            update_count = 0

            for symbol, timeframes in BACKGROUND_TIMEFRAMES.items():
                for tf in timeframes:
                    try:
                        key = f"{symbol}_{tf}"

                        # v3.600: 动态缓冲区大小
                        _tf_params = get_timeframe_params(tf, is_crypto=is_crypto_symbol(symbol))
                        _buf_size = _tf_params["ohlcv_buffer_size"]

                        # 获取或创建窗口
                        with _ohlcv_lock:
                            if key not in _ohlcv_windows:
                                _ohlcv_windows[key] = OHLCVWindow(max_size=_buf_size, timeframe_minutes=tf)
                            window = _ohlcv_windows[key]

                        old_size = window.size()

                        # 强制更新最新K线
                        _update_latest_bar(symbol, tf, window)

                        new_size = window.size()
                        if new_size > old_size or new_size > 0:
                            update_count += 1
                            # v3.510: 后台更新后触发预计算
                            try:
                                bars_for_precompute = window.get_bars()
                                if len(bars_for_precompute) >= 30:
                                    precompute_indicators(symbol, tf, bars_for_precompute, force=False)
                            except Exception as pre_e:
                                pass  # 预计算失败不影响主流程

                    except Exception as e:
                        print(f"[v3.470] ⚠️ 后台更新失败 {symbol}_{tf}: {e}")

                    # 每个请求间隔1秒，避免API限流
                    time.sleep(1)

            _check_stock_fallback_health_alert()

            if update_count > 0:
                print(f"[v3.470] ✅ 后台OHLCV更新完成: {update_count}个周期")

            # 保存缓存
            try:
                save_ohlcv_cache()
            except Exception:  # v3.560 P2-2
                pass

            # =============================================================
            # v3.551: 美股L1趋势盘中定时刷新
            # 每STOCK_L1_REFRESH_ROUNDS轮(30min)，用TV周期K线刷新美股L1判断
            # 解决: 自适应DOW回看窗口(16根4H=10天) + 30分钟定时刷新
            # =============================================================
            stock_l1_round_counter += 1
            if stock_l1_round_counter >= STOCK_L1_REFRESH_ROUNDS:
                stock_l1_round_counter = 0
                if _is_us_market_open() and stock_symbols:
                    print(f"\n[v3.600] 🔄 美股L1趋势定时刷新 ({len(stock_symbols)}个品种)...")
                    refresh_ok = 0
                    for s_symbol in stock_symbols:
                        try:
                            _s_tf = _get_stock_l1_refresh_timeframe(s_symbol)
                            if _refresh_l1_full_analysis(s_symbol, _s_tf):
                                refresh_ok += 1
                            time.sleep(2)  # 避免API调用过快
                        except Exception as e:
                            print(f"[v3.551] ⚠️ {s_symbol} L1刷新失败: {e}")
                    print(f"[v3.551] ✅ 美股L1趋势刷新完成 ({refresh_ok}/{len(stock_symbols)})")

                # v3.640: 加密货币L1定时刷新 (24/7, 不受盘中限制)
                crypto_refresh_list = [s for s in crypto_set if s in BACKGROUND_TIMEFRAMES]
                if crypto_refresh_list:
                    log_to_server(f"[CRYPTO_REFRESH] 加密货币L1趋势定时刷新 ({len(crypto_refresh_list)}个品种)...")
                    crypto_ok = 0
                    for c_symbol in crypto_refresh_list:
                        try:
                            c_tf = _get_stock_l1_refresh_timeframe(c_symbol)
                            if _refresh_l1_full_analysis(c_symbol, c_tf):
                                crypto_ok += 1
                            time.sleep(2)
                        except Exception as e:
                            log_to_server(f"[CRYPTO_REFRESH] {c_symbol} L1刷新失败: {e}")
                    log_to_server(f"[CRYPTO_REFRESH] 加密L1刷新完成 ({crypto_ok}/{len(crypto_refresh_list)})")

                # v3.572fix: 定期同步所有趋势到扫描引擎（每30分钟，与美股刷新周期一致）
                # 解决: 趋势不变时扫描引擎缓存过期的问题
                try:
                    print(f"[v3.572fix] 🔄 定期同步所有趋势到扫描引擎...")
                    _sync_all_trends_to_scan_engine()
                    print(f"[v3.572fix] ✅ 趋势同步完成")
                except Exception as sync_e:
                    print(f"[v3.572fix] ⚠️ 趋势同步失败: {sync_e}")

        except Exception as e:
            print(f"[v3.470] ❌ 后台更新器错误: {e}")

        # 等待下一次更新
        for _ in range(BACKGROUND_UPDATE_INTERVAL):
            if not _background_updater_running:
                break
            time.sleep(1)

    print(f"[v3.470] 🛑 后台OHLCV更新器已停止")


def _update_latest_bar(symbol: str, timeframe: int, window: 'OHLCVWindow'):
    """
    v3.470: 更新缓存中最新的K线（增量更新）

    只获取最新1-2根K线，合并到缓存中
    """
    crypto_symbols = {"BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"}

    # Coinbase周期映射
    COINBASE_GRANULARITY = {
        15: 900, 30: 1800, 60: 3600, 120: 7200, 360: 21600, 1440: 86400
    }

    # yfinance周期映射
    YFINANCE_INTERVAL = {
        15: ("15m", "1d"), 30: ("30m", "1d"), 60: ("1h", "2d"),
        90: ("90m", "2d"), 240: ("4h", "5d"), 1440: ("1d", "7d")
    }

    bars = []

    # 加密货币优先用Coinbase
    if symbol in crypto_symbols:
        granularity = COINBASE_GRANULARITY.get(timeframe)
        if granularity:
            bars = _fetch_coinbase_candles(symbol, granularity=granularity, limit=3)

    # 如果没拿到数据，用yfinance
    if not bars:
        try:
            import yfinance as yf
            import pandas as pd
            from concurrent.futures import ThreadPoolExecutor

            symbol_map = {
                "BTCUSDC": "BTC-USD", "ETHUSDC": "ETH-USD",
                "SOLUSDC": "SOL-USD", "ZECUSDC": "ZEC-USD"
            }
            yf_symbol = symbol_map.get(symbol, symbol)

            if timeframe in YFINANCE_INTERVAL:
                interval, period = YFINANCE_INTERVAL[timeframe]
            else:
                # 找最接近的
                supported_tfs = sorted(YFINANCE_INTERVAL.keys())
                closest_tf = min(supported_tfs, key=lambda x: abs(x - timeframe))
                interval, period = YFINANCE_INTERVAL[closest_tf]

            with ThreadPoolExecutor(max_workers=1) as executor:
                future = executor.submit(_fetch_yfinance_history, yf_symbol, period, interval)
                hist = future.result(timeout=10)

            if hist is not None and not hist.empty:
                # 只取最后3根
                for idx, row in hist.tail(3).iterrows():
                    close_val = float(row["Close"]) if not pd.isna(row["Close"]) else 0
                    if close_val <= 0:
                        continue
                    open_val = float(row["Open"]) if not pd.isna(row["Open"]) else close_val
                    high_val = float(row["High"]) if not pd.isna(row["High"]) else close_val
                    low_val = float(row["Low"]) if not pd.isna(row["Low"]) else close_val
                    # v3.680: Inf/high<low过滤
                    if any(math.isinf(x) for x in (open_val, high_val, low_val, close_val)):
                        continue
                    if high_val > 0 and low_val > 0 and high_val < low_val:
                        continue
                    bars.append({
                        "open": open_val,
                        "high": high_val,
                        "low": low_val,
                        "close": close_val,
                        "volume": float(row["Volume"]) if "Volume" in row and not pd.isna(row["Volume"]) else 0,
                        "sr_zone": "MID",
                        "timestamp": idx.timestamp() if hasattr(idx, 'timestamp') else 0,
                    })
                if bars and symbol not in crypto_symbols:
                    _bump_data_source_stat("stock", "yfinance", ok=True)
        except Exception as e:
            pass

    if not bars and symbol not in crypto_symbols:
        _bump_data_source_stat("stock", "yfinance", ok=False)
        bars = _fetch_stock_ohlcv_from_schwab(symbol, timeframe=timeframe, limit=3) or []

    # v3.472: 更新最新K线到窗口（不覆盖TV数据）
    # 使用统一的_last_tv_update_time检查所有维护周期
    if bars:
        latest = bars[-1] if bars else None
        if latest and latest.get("close", 0) > 0:
            import time
            current_time = time.time()
            cache_key = f"{symbol}_{timeframe}"

            # v3.472: 统一检查 - 如果TV在过去5分钟内更新过，跳过API更新
            last_tv_time = _last_tv_update_time.get(cache_key, 0)
            if last_tv_time > 0 and (current_time - last_tv_time) < 300:
                # TV在5分钟内更新过此symbol+timeframe，不覆盖
                return

            # 额外检查：时间戳比较（备用）
            existing_bars = window.get_bars()
            if existing_bars:
                last_bar = existing_bars[-1]
                last_ts = last_bar.get("timestamp", 0)
                new_ts = latest.get("timestamp", 0)

                # 如果时间戳相同，不更新
                if last_ts > 0 and new_ts > 0 and abs(new_ts - last_ts) < 60:
                    return

            # 安全：追加新K线
            window.append(latest)


def start_background_ohlcv_updater():
    """v3.470: 启动后台OHLCV更新器"""
    global _background_updater_running, _background_updater_thread
    import threading

    if _background_updater_running:
        print("[v3.470] 后台OHLCV更新器已在运行")
        return

    _background_updater_running = True
    _background_updater_thread = threading.Thread(
        target=_background_ohlcv_updater,
        daemon=True,
        name="BackgroundOHLCVUpdater"
    )
    _background_updater_thread.start()
    print("[v3.470] ✅ 后台OHLCV更新器已启动")


def stop_background_ohlcv_updater():
    """v3.470: 停止后台OHLCV更新器"""
    global _background_updater_running
    _background_updater_running = False
    print("[v3.470] 后台OHLCV更新器停止中...")


# ============================================================
# v2.987: 方案2 - OHLCV窗口持久化
# ============================================================
OHLCV_CACHE_FILE = "logs/ohlcv_cache.json"

def save_ohlcv_cache():
    """
    保存所有OHLCV窗口到文件
    v3.445: 支持symbol_timeframe格式的key
    """
    try:
        cache_data = {
            "version": "3.445",  # v3.445: 更新版本号
            "timestamp": datetime.now().isoformat(),
            "windows": {}
        }

        # v3.445: key现在是symbol_timeframe格式(如BTCUSDC_120)
        for key, window in _ohlcv_windows.items():
            cache_data["windows"][key] = window.to_dict()

        # 确保目录存在
        os.makedirs(os.path.dirname(OHLCV_CACHE_FILE), exist_ok=True)

        with open(OHLCV_CACHE_FILE, 'w', encoding='utf-8') as f:
            json.dump(cache_data, f, ensure_ascii=False, default=str)

        print(f"[v3.445] 💾 OHLCV缓存已保存: {len(_ohlcv_windows)}个缓存(按品种+周期)")
        return True
    except Exception as e:
        print(f"[v3.445] ❌ 保存OHLCV缓存失败: {e}")
        return False


def load_ohlcv_cache():
    """
    从文件加载OHLCV窗口
    v3.445: 支持symbol_timeframe格式的key，兼容旧格式
    """
    try:
        if not os.path.exists(OHLCV_CACHE_FILE):
            print(f"[v3.445] ℹ️ OHLCV缓存文件不存在，跳过加载")
            return 0

        with open(OHLCV_CACHE_FILE, 'r', encoding='utf-8') as f:
            cache_data = json.load(f)

        # 检查缓存版本和时效性
        cache_version = cache_data.get("version", "")
        cache_time = cache_data.get("timestamp", "")
        try:
            cache_dt = datetime.fromisoformat(cache_time)
            age_hours = (datetime.now() - cache_dt).total_seconds() / 3600
            if age_hours > 24:
                print(f"[v3.445] ⚠️ OHLCV缓存过期({age_hours:.1f}小时)，将重新预加载")
                return 0
        except Exception as e:
            print(f"[v3.445] 缓存时间解析失败: {e}")
            pass

        windows_data = cache_data.get("windows", {})
        loaded = 0

        for key, data in windows_data.items():
            # v3.445: key可能是symbol_timeframe(新格式)或symbol(旧格式)
            if "_" in key and key.split("_")[-1].isdigit():
                # 新格式: BTCUSDC_120 -> 直接使用
                parts = key.rsplit("_", 1)
                symbol = parts[0]
                timeframe = int(parts[1])
            else:
                # 旧格式: 只有symbol，使用配置的周期
                symbol = key
                timeframe = get_symbol_timeframe(symbol)
                key = f"{symbol}_{timeframe}"

            # v3.600: 动态缓冲区大小
            _tf_params = get_timeframe_params(timeframe, is_crypto=is_crypto_symbol(symbol))
            _buf_size = _tf_params["ohlcv_buffer_size"]

            # 直接操作_ohlcv_windows避免触发预加载
            with _ohlcv_lock:
                if key not in _ohlcv_windows:
                    _ohlcv_windows[key] = OHLCVWindow(max_size=_buf_size, timeframe_minutes=timeframe)
                window = _ohlcv_windows[key]

            window.from_dict(data)
            if window.size() > 0:
                loaded += 1
                print(f"[v3.445] 📂 {key}: 从缓存加载 {window.size()} 根K线")

        print(f"[v3.445] ✅ OHLCV缓存加载完成: {loaded}个缓存")
        return loaded
    except Exception as e:
        print(f"[v3.445] ❌ 加载OHLCV缓存失败: {e}")
        return 0


def init_ohlcv_on_startup(symbols: list, timeframe: int = 30):
    """
    v2.987: 启动时初始化OHLCV窗口
    
    优先级:
    1. 尝试从缓存加载
    2. 如果缓存不足，从yfinance预加载
    """
    print(f"\n[v2.987] {'='*50}")
    print(f"[v2.987] 🚀 OHLCV窗口初始化开始")
    print(f"[v2.987] {'='*50}")
    
    # 步骤1: 尝试加载缓存
    cached = load_ohlcv_cache()
    
    # 步骤2: 检查哪些品种需要预加载
    need_preload = []
    for symbol in symbols:
        window = get_ohlcv_window(symbol)
        if not window.is_ready():
            need_preload.append(symbol)
    
    # 步骤3: 预加载不足的品种
    if need_preload:
        print(f"[v2.987] 需要预加载: {need_preload}")
        preload_ohlcv_from_yfinance(need_preload, timeframe)
    else:
        print(f"[v2.987] ✅ 所有品种OHLCV窗口已就绪，无需预加载")
    
    # 打印最终状态
    print(f"\n[v2.987] 📊 OHLCV窗口状态:")
    for symbol in symbols:
        window = get_ohlcv_window(symbol)
        status = "✅就绪" if window.is_ready() else "⚠️不足"
        print(f"         {symbol}: {window.size()}根 {status}")
    
    print(f"[v2.987] {'='*50}\n")


def analyze_pa_from_bars(bars: list) -> str:
    """
    基于K线序列分析PA结构
    
    检测：
    1. Higher Low（看多）
    2. Lower High（看空）
    3. 趋势延续确认
    """
    if len(bars) < 10:
        return "NONE"
    
    recent = bars[-10:]
    lows = [b["low"] for b in recent]
    highs = [b["high"] for b in recent]
    closes = [b["close"] for b in recent]
    
    # 1. Higher Low检测
    local_lows = []
    for i in range(1, len(lows)-1):
        if lows[i] <= lows[i-1] and lows[i] <= lows[i+1]:
            local_lows.append((i, lows[i]))
    
    if len(local_lows) >= 2:
        _, low1 = local_lows[-2]
        _, low2 = local_lows[-1]
        if low2 > low1 * 1.002 and closes[-1] > closes[-5]:
            return "BULL_PA"
    
    # 2. Lower High检测
    local_highs = []
    for i in range(1, len(highs)-1):
        if highs[i] >= highs[i-1] and highs[i] >= highs[i+1]:
            local_highs.append((i, highs[i]))
    
    if len(local_highs) >= 2:
        _, high1 = local_highs[-2]
        _, high2 = local_highs[-1]
        if high2 < high1 * 0.998 and closes[-1] < closes[-5]:
            return "BEAR_PA"
    
    # 3. 趋势延续（连续同方向）
    recent_closes = closes[-5:]
    ups = sum(1 for i in range(1, len(recent_closes)) if recent_closes[i] > recent_closes[i-1])
    if ups >= 4:
        return "BULL_PA"
    if ups <= 1:
        return "BEAR_PA"
    
    return "NONE"


def analyze_2b_from_bars(bars: list) -> str:
    """
    检测2B假突破
    
    规则：突破前高/前低后快速回落/反弹
    """
    if len(bars) < 8:
        return "NONE"
    
    recent = bars[-8:]
    highs = [b["high"] for b in recent]
    lows = [b["low"] for b in recent]
    closes = [b["close"] for b in recent]
    
    # 多头2B：突破前高后回落
    early_high = max(highs[:5])
    mid_highs = highs[5:7]
    if mid_highs and max(mid_highs) > early_high * 1.002:
        if closes[-1] < early_high:
            return "TWO_B_BULL"
    
    # 空头2B：跌破前低后反弹
    early_low = min(lows[:5])
    mid_lows = lows[5:7]
    if mid_lows and min(mid_lows) < early_low * 0.998:
        if closes[-1] > early_low:
            return "TWO_B_BEAR"
    
    return "NONE"


def analyze_123_from_bars(bars: list) -> str:
    """
    检测1-2-3模式（极简版）
    
    看多123：低→高→回踩不破
    看空123：高→低→反弹不过
    """
    if len(bars) < 10:
        return "NONE"
    
    recent = bars[-10:]
    lows = [b["low"] for b in recent]
    highs = [b["high"] for b in recent]
    
    # 看多123
    try:
        min_idx_1 = lows.index(min(lows[:4]))
        max_idx_2 = min_idx_1 + highs[min_idx_1:min_idx_1+4].index(max(highs[min_idx_1:min_idx_1+4]))
        min_idx_3 = max_idx_2 + lows[max_idx_2:].index(min(lows[max_idx_2:]))
        
        if min_idx_1 < max_idx_2 < min_idx_3:
            low_1 = lows[min_idx_1]
            low_3 = lows[min_idx_3]
            if low_3 > low_1 * 1.002:
                return "BULL_123"
    except (ValueError, IndexError):
        pass
    
    # 看空123
    try:
        max_idx_1 = highs.index(max(highs[:4]))
        min_idx_2 = max_idx_1 + lows[max_idx_1:max_idx_1+4].index(min(lows[max_idx_1:max_idx_1+4]))
        max_idx_3 = min_idx_2 + highs[min_idx_2:].index(max(highs[min_idx_2:]))
        
        if max_idx_1 < min_idx_2 < max_idx_3:
            high_1 = highs[max_idx_1]
            high_3 = highs[max_idx_3]
            if high_3 < high_1 * 0.998:
                return "BEAR_123"
    except (ValueError, IndexError):
        pass
    
    return "NONE"


def analyze_pa_from_bars_enhanced(bars: list, tv_signals: list = None) -> str:
    """[PATCHED] 基于K线序列分析PA结构（增强版：结合TV信号历史）"""
    if len(bars) < 10:
        return "NONE"
    
    recent = bars[-10:]
    lows = [b["low"] for b in recent]
    highs = [b["high"] for b in recent]
    closes = [b["close"] for b in recent]
    
    # TV信号趋势分析
    tv_bull_count = 0
    tv_bear_count = 0
    if tv_signals and len(tv_signals) >= 10:
        recent_tv = tv_signals[-10:]
        tv_bull_count = sum(1 for sig in recent_tv if sig.get("pa_buy_edge", False))
        tv_bear_count = sum(1 for sig in recent_tv if sig.get("pa_sell_edge", False))
    
    # Higher Low检测
    local_lows = []
    for i in range(1, len(lows)-1):
        if lows[i] <= lows[i-1] and lows[i] <= lows[i+1]:
            local_lows.append((i, lows[i]))
    
    if len(local_lows) >= 2:
        _, low1 = local_lows[-2]
        _, low2 = local_lows[-1]
        if low2 > low1 * 1.002 and closes[-1] > closes[-5]:
            return "BULL_PA"
    
    # Lower High检测
    local_highs = []
    for i in range(1, len(highs)-1):
        if highs[i] >= highs[i-1] and highs[i] >= highs[i+1]:
            local_highs.append((i, highs[i]))
    
    if len(local_highs) >= 2:
        _, high1 = local_highs[-2]
        _, high2 = local_highs[-1]
        if high2 < high1 * 0.998 and closes[-1] < closes[-5]:
            return "BEAR_PA"
    
    # 趋势延续
    recent_closes = closes[-5:]
    ups = sum(1 for i in range(1, len(recent_closes)) if recent_closes[i] > recent_closes[i-1])
    if ups >= 4:
        return "BULL_PA"
    if ups <= 1:
        return "BEAR_PA"
    
    # TV信号趋势
    if tv_bull_count >= 5:
        return "BULL_PA"
    if tv_bear_count >= 5:
        return "BEAR_PA"
    
    return "NONE"




