def check_side_market_cooldown(symbol: str, trend_state: str) -> tuple:
    """
    v3.230: 检查SIDE市场冷却期
    v3.340: ZEC单独1小时，其他保持3小时

    Returns:
        (can_trade: bool, cooldown_remaining: float in hours)
    """
    import time

    if trend_state.upper() != "SIDE":
        return True, 0.0

    # v3.340: ZEC使用1小时冷却，其他品种3小时
    # v3.661: PARAM_YAML品种参数化
    _default_cd = SIDE_MARKET_COOLDOWN_HOURS_ZEC if symbol == "ZECUSDC" else SIDE_MARKET_COOLDOWN_HOURS
    cooldown = get_symbol_param(symbol, "timing", "side_cooldown_hours", default=_default_cd)

    current_time = time.time()
    last_trade_time = _side_market_last_trade.get(symbol, 0)
    elapsed_hours = (current_time - last_trade_time) / 3600

    if elapsed_hours < cooldown:
        remaining = cooldown - elapsed_hours
        return False, remaining

    return True, 0.0

def record_side_market_trade(symbol: str, trend_state: str):
    """v3.230: 记录SIDE市场交易时间"""
