# CNN网络定义
if CNN_TORCH_AVAILABLE:
    class CNN1DNetwork(nn.Module):
        """1D-CNN网络，用于K线趋势分类 (v2.960: 3层卷积)"""
        def __init__(self):
            super(CNN1DNetwork, self).__init__()
            self.conv1 = nn.Conv1d(in_channels=6, out_channels=64, kernel_size=3, padding=1)
            self.bn1 = nn.BatchNorm1d(64)
            self.pool1 = nn.MaxPool1d(kernel_size=2)
            
            self.conv2 = nn.Conv1d(in_channels=64, out_channels=128, kernel_size=3, padding=1)
            self.bn2 = nn.BatchNorm1d(128)
            self.pool2 = nn.MaxPool1d(kernel_size=2)
            
            self.conv3 = nn.Conv1d(in_channels=128, out_channels=256, kernel_size=3, padding=1)
            self.bn3 = nn.BatchNorm1d(256)
            
            self.fc1 = nn.Linear(256, 128)
            self.dropout = nn.Dropout(0.4)
            self.fc2 = nn.Linear(128, 3)
        
        def forward(self, x):
            x = x.permute(0, 2, 1)  # (batch, seq, feat) → (batch, feat, seq)
            
            x = F.relu(self.bn1(self.conv1(x)))
            x = self.pool1(x)
            
            x = F.relu(self.bn2(self.conv2(x)))
            x = self.pool2(x)
            
            x = F.relu(self.bn3(self.conv3(x)))
            
            x = x.mean(dim=2)  # Global Average Pooling
            
            x = F.relu(self.fc1(x))
            x = self.dropout(x)
            x = self.fc2(x)
            return x
        
        def predict_proba(self, x):
            return F.softmax(self.forward(x), dim=1)

# 全局CNN模型实例
