def cnn_extract_features(klines: list) -> 'np.ndarray':
    """从K线数据提取CNN特征"""
    features = []
    for bar in klines:
        o = float(bar.get("open", bar.get("o", 0)))
        h = float(bar.get("high", bar.get("h", 0)))
        l = float(bar.get("low", bar.get("l", 0)))
        c = float(bar.get("close", bar.get("c", 0)))
        v = float(bar.get("volume", bar.get("v", 0)))
        change_pct = (c - o) / o * 100 if o > 0 else 0
        features.append([o, h, l, c, v, change_pct])
    
    features = np.array(features, dtype=np.float32)
    
    # 确保50根K线
    if len(features) < 50:
        pad = np.zeros((50 - len(features), 6), dtype=np.float32)
        features = np.vstack([pad, features])
    elif len(features) > 50:
        features = features[-50:]
    
    # 标准化
    base_price = 1.0
    for i in range(len(features)):
        if features[i, 0] > 0:
            base_price = features[i, 0]
            break
    
    normalized = features.copy()
    for i in range(4):  # OHLC
        normalized[:, i] = (features[:, i] - base_price) / base_price * 100
    
    vol = features[:, 4]
    vol_nonzero = vol[vol > 0]
    if len(vol_nonzero) > 0:
        vol_mean = np.log1p(vol_nonzero).mean()
        vol_std = np.log1p(vol_nonzero).std() + 1e-8
        normalized[:, 4] = (np.log1p(vol) - vol_mean) / vol_std
    
    normalized[:, 5] = features[:, 5] / 10.0
    
    return normalized

def cnn_predict(klines: list) -> dict:
    """使用CNN模型预测"""
    result = {
        "signal": "HOLD",
        "confidence": 0.5,
        "probabilities": {"UP": 0.33, "SIDE": 0.34, "DOWN": 0.33},
        "model_used": False,
    }
    
    if not CNN_HUMAN_LOADED or CNN_HUMAN_MODEL is None:
        return result
    
    if not klines or len(klines) < 5:
        return result
    
    try:
        features = cnn_extract_features(klines)
        device = next(CNN_HUMAN_MODEL.parameters()).device
        x = torch.tensor(features, dtype=torch.float32).unsqueeze(0).to(device)
        
        with torch.no_grad():
            probs = CNN_HUMAN_MODEL.predict_proba(x)
            probs = probs.cpu().numpy()[0]
        
        prob_up, prob_side, prob_down = float(probs[0]), float(probs[1]), float(probs[2])
        
        result["probabilities"] = {
            "UP": round(prob_up, 4),
            "SIDE": round(prob_side, 4),
            "DOWN": round(prob_down, 4),
        }
        
        # 映射到5级信号
        max_prob = max(prob_up, prob_side, prob_down)
        if prob_up > 0.70:
            result["signal"], result["confidence"] = "STRONG_BUY", max_prob
        elif prob_up > 0.50:
            result["signal"], result["confidence"] = "BUY", max_prob
        elif prob_down > 0.70:
            result["signal"], result["confidence"] = "STRONG_SELL", max_prob
        elif prob_down > 0.50:
            result["signal"], result["confidence"] = "SELL", max_prob
        else:
            result["signal"], result["confidence"] = "HOLD", max_prob
        
        result["model_used"] = True
        
    except Exception as e:
        print(f"[CNN_HUMAN] 预测错误: {e}")
    
    return result


