# v3.003: 请求计时器，用于诊断慢请求
import time as _time_module
_request_start_times = {}

@app.before_request
def _log_request_start():
    """v3.003: 记录请求开始时间"""
    from flask import request, g
    from datetime import datetime
    g.request_start_time = _time_module.time()
    symbol = "UNKNOWN"
    try:
        data = request.get_json(force=True, silent=True) or {}
        symbol = data.get("symbol", "UNKNOWN")
    except Exception:
        pass
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    msg = f"[REQ_START] {timestamp} {request.path} symbol={symbol}"
    print(msg, flush=True)
    # v3.003: 也写入server.log便于追踪
    try:
        with open("logs/server.log", "a", encoding="utf-8") as f:
            f.write(msg + "\n")
    except Exception:
        pass

@app.after_request
def _log_request_end(response):
    """v3.003: 记录请求耗时"""
    from flask import request, g
    from datetime import datetime
    duration = _time_module.time() - getattr(g, 'request_start_time', _time_module.time())
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    if duration > 5:  # 超过5秒的请求打印警告
        msg = f"[REQ_SLOW] {timestamp} ⚠️ {request.path} 耗时 {duration:.1f}s"
    else:
        msg = f"[REQ_END] {timestamp} {request.path} 耗时 {duration:.1f}s"
    print(msg, flush=True)
    # v3.003: 也写入server.log便于追踪
    try:
        with open("logs/server.log", "a", encoding="utf-8") as f:
            f.write(msg + "\n")
    except Exception:
        pass
    return response

