def record_l1_plugin_trigger(symbol: str, plugin_name: str, signal: str, freeze_hours: float = 1.0):
    """
    v3.530: 记录L1外挂触发

    Args:
        symbol: 交易品种
        plugin_name: 外挂名称 (SuperTrend/RobHoffman/双底双顶/飞云/MACD背离)
        signal: 触发信号 (BUY/SELL/STRONG_BUY/STRONG_SELL等)
        freeze_hours: 冻结时长(小时)
    """
    global _l1_plugin_state

    with _l1_plugin_lock:
        if symbol not in _l1_plugin_state:
            _l1_plugin_state[symbol] = {}

        trigger_time = datetime.now()
        freeze_until = trigger_time + timedelta(hours=freeze_hours)

        _l1_plugin_state[symbol][plugin_name] = {
            "last_signal": signal,
            "trigger_time": trigger_time.isoformat(),
            "freeze_until": freeze_until.isoformat(),
        }

        _save_l1_plugin_state()
        print(f"[v3.530] L1外挂触发记录: {symbol} {plugin_name} → {signal}, 冻结至 {freeze_until.strftime('%H:%M:%S')}")

# 内存中的门卫状态 (per symbol)
# {
#   "BTCUSDC": {
#     "big_cycle_decision": "STRONG_BUY",  # L2大周期最新决定
#     "big_cycle_timestamp": 1705430400,   # 大周期信号时间戳
#     "small_cycle_traded": False,         # 小周期是否已交易
#     "small_cycle_trade_time": None,      # 小周期交易时间
#     "frozen_until_next_big": True,       # 冻结直到下一个大周期
#   }
# }
_l2_gate_state = {}
_l2_gate_lock = threading.Lock()  # v3.490: L2 Gate线程安全锁

def _load_l2_gate_state():
    """加载L2门卫状态 (v3.490: 线程安全)"""
    global _l2_gate_state
    with _l2_gate_lock:
        try:
            if os.path.exists(L2_GATE_STATE_FILE):
                with open(L2_GATE_STATE_FILE, "r", encoding="utf-8") as f:
                    _l2_gate_state = json.load(f)
        except Exception as e:
            print(f"[v3.460] L2门卫状态加载失败: {e}")
            _l2_gate_state = {}

def _save_l2_gate_state():
    """保存L2门卫状态 (注意: 调用方需持有_l2_gate_lock)"""
    try:
        with open(L2_GATE_STATE_FILE, "w", encoding="utf-8") as f:
            json.dump(_l2_gate_state, f, indent=2, ensure_ascii=False)
    except Exception as e:
        print(f"[v3.460] L2门卫状态保存失败: {e}")

def update_l2_big_cycle_decision(symbol: str, decision: str, timestamp: float = None):
    """
    v3.460: 更新L2大周期决定，并重置小周期交易状态
    v3.490: 添加线程锁保护
    v3.499: 只有方向真正变化时才重置冻结状态（修复来回买卖问题）

    Args:
        symbol: 交易品种
        decision: STRONG_BUY / BUY / HOLD / SELL / STRONG_SELL
        timestamp: 信号时间戳
    """
    global _l2_gate_state

    with _l2_gate_lock:  # v3.490: 线程安全
        if symbol not in _l2_gate_state:
            _l2_gate_state[symbol] = {}

        old_decision = _l2_gate_state[symbol].get("big_cycle_decision", "HOLD")

        # v3.499: 判断方向是否真正变化
        # BUY方向: STRONG_BUY, BUY
        # SELL方向: STRONG_SELL, SELL
        # HOLD方向: HOLD, HOLD_SUGGEST
        def get_direction(dec):
            if dec in ("STRONG_BUY", "BUY"):
                return "BUY"
            elif dec in ("STRONG_SELL", "SELL"):
                return "SELL"
            else:
                return "HOLD"

        old_direction = get_direction(old_decision)
        new_direction = get_direction(decision)
        direction_changed = (old_direction != new_direction)

        # 更新大周期决定
        _l2_gate_state[symbol]["big_cycle_decision"] = decision
        _l2_gate_state[symbol]["big_cycle_timestamp"] = timestamp or _time_module.time()

        # v3.499: 只有方向真正变化时才重置小周期交易状态
        # 修复: 每次TV推送都重置导致来回买卖的问题
        if direction_changed:
            _l2_gate_state[symbol]["small_cycle_traded"] = False
            _l2_gate_state[symbol]["small_cycle_trade_time"] = None
            _l2_gate_state[symbol]["frozen_until_next_big"] = False
            print(f"[v3.499] L2大周期方向变化: {symbol} {old_decision}({old_direction}) → {decision}({new_direction})")
            print(f"         小周期交易状态已重置")
        else:
            print(f"[v3.499] L2大周期更新(方向不变): {symbol} {old_decision} → {decision} (冻结状态保持)")

        _save_l2_gate_state()

def check_l2_gate(symbol: str, small_cycle_decision: str, small_close: float = None) -> dict:
    """
    v3.460: 检查L2门卫是否允许小周期交易
    v3.490: 添加线程锁保护
    v3.498: HOLD时门卫开放，让L1外挂自己判断趋势
    v3.501: 添加突破验证，连续2根小周期失败触发反向信号

    Args:
        symbol: 交易品种
        small_cycle_decision: L2小周期决定 (STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL)
        small_close: v3.501 小周期K线收盘价（用于突破验证）

    Returns:
        {
            "allow_trade": bool,          # 是否允许交易
            "trade_action": str or None,  # BUY / SELL / None
            "reason": str,                # 原因说明
            "big_decision": str,          # 大周期决定
            "small_decision": str,        # 小周期决定
            "breakout_reverse": bool,     # v3.501: 是否是突破失败的反向信号
        }
    """
    global _l2_gate_state

    with _l2_gate_lock:  # v3.490: 线程安全
        state = _l2_gate_state.get(symbol, {})
        big_decision = state.get("big_cycle_decision", "HOLD")
        small_traded = state.get("small_cycle_traded", False)
        frozen = state.get("frozen_until_next_big", False)

    result = {
        "allow_trade": False,
        "trade_action": None,
        "reason": "",
        "big_decision": big_decision,
        "small_decision": small_cycle_decision,
        "breakout_reverse": False,
    }

    # v3.501: 突破验证（如果提供了小周期收盘价）
    if small_close is not None:
        breakout_validation = check_small_cycle_breakout_validation(symbol, small_close)

        # 如果触发反向信号，优先处理
        if breakout_validation.get("trigger_reverse"):
            result["allow_trade"] = True
            result["trade_action"] = breakout_validation["reverse_action"]
            result["reason"] = f"v3.501 突破验证失败: {breakout_validation['reason']}"
            result["breakout_reverse"] = True
            print(f"[v3.501] {symbol} 门卫触发反向信号: {result['trade_action']}")
            return result

        # 如果正在等待第2根K线确认，记录但不阻止正常流程
        if breakout_validation.get("fallback_count", 0) == 1:
            print(f"[v3.501] {symbol} 突破验证: 等待第2根K线确认 (count=1)")

    # 检查是否已冻结
    if frozen or small_traded:
        result["reason"] = f"小周期已交易，等待下一个大周期信号 (traded={small_traded}, frozen={frozen})"
        return result

    # v3.540: 规则1: 大周期=STRONG_BUY → 小周期BUY/STRONG_BUY允许买入 (BUY不再激活)
    if big_decision == "STRONG_BUY":
        if small_cycle_decision in ("STRONG_BUY", "BUY"):
            result["allow_trade"] = True
            result["trade_action"] = "BUY"
            result["reason"] = f"门卫放行: 大周期{big_decision} + 小周期{small_cycle_decision} → 允许买入"
        else:
            result["reason"] = f"门卫阻止: 大周期{big_decision}但小周期{small_cycle_decision}不是BUY"

    # v3.540: 规则2: 大周期=STRONG_SELL → 小周期SELL/STRONG_SELL允许卖出 (SELL不再激活)
    elif big_decision == "STRONG_SELL":
        if small_cycle_decision in ("STRONG_SELL", "SELL"):
            result["allow_trade"] = True
            result["trade_action"] = "SELL"
            result["reason"] = f"门卫放行: 大周期{big_decision} + 小周期{small_cycle_decision} → 允许卖出"
        else:
            result["reason"] = f"门卫阻止: 大周期{big_decision}但小周期{small_cycle_decision}不是SELL"

    # v3.540: 规则3: 大周期=BUY/SELL → 门卫阻止，信号不够强
    elif big_decision in ("BUY", "SELL"):
        result["reason"] = f"门卫阻止(v3.540): 大周期{big_decision}信号强度不足，只有STRONG_BUY/STRONG_SELL才激活"

    # v3.499修复: 大周期=HOLD → 门卫关闭，阻止L2小周期交易
    # 注意: L1外挂(SuperTrend/飞云/Rob Hoffman)使用plugin_bypass_l2，不经过此门卫
    # v3.498错误地在此放行，但L2小周期没有趋势过滤能力，导致来回买卖
    elif big_decision == "HOLD":
        result["reason"] = f"门卫阻止(v3.499): 大周期{big_decision}=震荡，L2小周期不允许交易"

    # 其他情况（理论上不会到达）
    else:
        result["reason"] = f"门卫状态未知: 大周期{big_decision}"

    return result

def mark_l2_small_cycle_traded(symbol: str):
    """
    v3.460: 标记小周期已交易，进入冻结状态
    v3.490: 添加线程锁保护
    """
    global _l2_gate_state

    with _l2_gate_lock:  # v3.490: 线程安全
        if symbol not in _l2_gate_state:
            _l2_gate_state[symbol] = {}

        _l2_gate_state[symbol]["small_cycle_traded"] = True
        _l2_gate_state[symbol]["small_cycle_trade_time"] = _time_module.time()
        _l2_gate_state[symbol]["frozen_until_next_big"] = True

        _save_l2_gate_state()

    print(f"[v3.460] {symbol} 小周期已交易，冻结直到下一个大周期信号")

def compute_l2_small_cycle_decision(ohlcv_bars: list, symbol: str = "") -> dict:
    """
    v3.540: 计算L2小周期决定（极简版：K线形态 + 成交量）

    评分体系:
    - K线形态分 (-3 ~ +3): 反转/持续形态识别
    - 成交量分 (-3 ~ +3): 放量确认

    总分范围: -6 ~ +6
    阈值: >=3 确认买入, <=-3 确认卖出, 其他等待

    Args:
        ohlcv_bars: 小周期OHLCV数据
        symbol: 交易品种

    Returns:
        {
            "decision": "BUY" / "HOLD" / "SELL",
            "score": int,
            "candle_score": int,
            "candle_pattern": str,
            "volume_score": int,
            "volume_ratio": float,
            "details": str,
        }
    """
    result = {
        "decision": "HOLD",
        "score": 0,
        "candle_score": 0,
        "candle_pattern": "UNKNOWN",
        "volume_score": 0,
        "volume_ratio": 1.0,
        "details": "",
    }

    if not ohlcv_bars or len(ohlcv_bars) < 20:
        result["details"] = "数据不足"
        return result

    # 获取最近的K线数据
    current_bar = ohlcv_bars[-1]
    prev_bar = ohlcv_bars[-2]

    o = float(current_bar.get("open", 0))
    h = float(current_bar.get("high", 0))
    l = float(current_bar.get("low", 0))
    c = float(current_bar.get("close", 0))
    v = float(current_bar.get("volume", 0))

    prev_o = float(prev_bar.get("open", 0))
    prev_h = float(prev_bar.get("high", 0))
    prev_l = float(prev_bar.get("low", 0))
    prev_c = float(prev_bar.get("close", 0))

    # ========== 1. K线形态评分 (-3 ~ +3) ==========
    candle_score = 0
    candle_pattern = "NEUTRAL"
    body = abs(c - o)
    upper_wick = h - max(o, c)
    lower_wick = min(o, c) - l
    total_range = h - l if h > l else 0.0001

    # 判断阴阳
    is_bullish = c > o
    is_bearish = c < o

    # --- 强看涨形态 (+3) ---
    # 锤子线: 下影线>=实体2倍，上影线很短，在下跌后出现
    if lower_wick >= body * 2 and upper_wick <= body * 0.3 and prev_c > c:
        candle_score = 3
        candle_pattern = "HAMMER"
    # 看涨吞没: 当前阳线完全包住前一根阴线
    elif is_bullish and prev_c < prev_o and c > prev_o and o < prev_c:
        candle_score = 3
        candle_pattern = "BULLISH_ENGULF"

    # --- 中等看涨形态 (+2) ---
    # 大阳线: 实体占比>70%
    elif is_bullish and body / total_range > 0.7:
        candle_score = 2
        candle_pattern = "STRONG_BULLISH"
    # 倒锤子: 上影线>=实体2倍，下影线很短
    elif upper_wick >= body * 2 and lower_wick <= body * 0.3 and prev_c > c:
        candle_score = 2
        candle_pattern = "INVERTED_HAMMER"

    # --- 弱看涨形态 (+1) ---
    elif is_bullish and body / total_range > 0.5:
        candle_score = 1
        candle_pattern = "BULLISH"

    # --- 强看跌形态 (-3) ---
    # 上吊线/射击之星: 上影线>=实体2倍，下影线很短，在上涨后出现
    elif upper_wick >= body * 2 and lower_wick <= body * 0.3 and prev_c < c:
        candle_score = -3
        candle_pattern = "SHOOTING_STAR"
    # 看跌吞没: 当前阴线完全包住前一根阳线
    elif is_bearish and prev_c > prev_o and c < prev_o and o > prev_c:
        candle_score = -3
        candle_pattern = "BEARISH_ENGULF"

    # --- 中等看跌形态 (-2) ---
    # 大阴线: 实体占比>70%
    elif is_bearish and body / total_range > 0.7:
        candle_score = -2
        candle_pattern = "STRONG_BEARISH"

    # --- 弱看跌形态 (-1) ---
    elif is_bearish and body / total_range > 0.5:
        candle_score = -1
        candle_pattern = "BEARISH"

    # --- 十字星 (0，需要结合位置判断) ---
    elif body / total_range < 0.1:
        candle_score = 0
        candle_pattern = "DOJI"

    result["candle_score"] = candle_score
    result["candle_pattern"] = candle_pattern

    # ========== 2. 成交量评分 (-3 ~ +3) ==========
    # 计算平均成交量 (最近20根)
    volumes = [float(bar.get("volume", 0)) for bar in ohlcv_bars[-20:]]
    avg_volume = sum(volumes[:-1]) / len(volumes[:-1]) if len(volumes) > 1 else v
    volume_ratio = v / avg_volume if avg_volume > 0 else 1.0
    result["volume_ratio"] = round(volume_ratio, 2)

    volume_score = 0
    if is_bullish:
        # 上涨+放量 = 确认
        if volume_ratio >= 2.0:
            volume_score = 3  # 强放量
        elif volume_ratio >= 1.5:
            volume_score = 2  # 明显放量
        elif volume_ratio >= 1.2:
            volume_score = 1  # 温和放量
        elif volume_ratio < 0.7:
            volume_score = -1  # 上涨缩量，不可靠
    elif is_bearish:
        # 下跌+放量 = 确认
        if volume_ratio >= 2.0:
            volume_score = -3  # 强放量下跌
        elif volume_ratio >= 1.5:
            volume_score = -2  # 明显放量下跌
        elif volume_ratio >= 1.2:
            volume_score = -1  # 温和放量下跌
        elif volume_ratio < 0.7:
            volume_score = 1  # 下跌缩量，可能反转

    result["volume_score"] = volume_score

    # ========== 3. 总分与决定 ==========
    total_score = candle_score + volume_score
    result["score"] = total_score

    # 阈值: >=3 买入确认, <=-3 卖出确认
    if total_score >= 3:
        result["decision"] = "BUY"
    elif total_score <= -3:
        result["decision"] = "SELL"
    else:
        result["decision"] = "HOLD"

    result["details"] = (f"K线={candle_pattern}({candle_score:+d}) "
                        f"成交量={volume_ratio:.1f}x({volume_score:+d}) "
                        f"总分={total_score:+d}")

    print(f"[v3.540] {symbol} L2小周期评分: {result['details']} → {result['decision']}")

    return result

def _compute_rsi_simple(closes: list, period: int = 14) -> float:
    """简单RSI计算"""
    if len(closes) < period + 1:
        return 50.0

    gains = []
    losses = []

    for i in range(1, len(closes)):
        change = closes[i] - closes[i-1]
        if change > 0:
            gains.append(change)
            losses.append(0)
        else:
            gains.append(0)
            losses.append(abs(change))

    # 使用最近period个数据
    recent_gains = gains[-period:]
    recent_losses = losses[-period:]

    avg_gain = sum(recent_gains) / period
    avg_loss = sum(recent_losses) / period

    if avg_loss == 0:
        return 100.0

    rs = avg_gain / avg_loss
    rsi = 100 - (100 / (1 + rs))

    return round(rsi, 1)

