L2_DEBUG_VERBOSE = False  # 主程序可在运行时修改此变量

def compute_candle_features_enhanced(ohlcv_bars):
    """
    增强K线特征提取：基于OHLC五点数据
    
    返回最近1根K线的特征：
    {
        "body_pct": float,          # 实体占全高比例
        "upper_shadow_pct": float,  # 上影线占全高比例
        "lower_shadow_pct": float,  # 下影线占全高比例
        "is_long_body": bool,       # 实体>60%
        "is_bullish": bool,         # 阳线
        "is_bearish": bool,         # 阴线
        "is_doji": bool,            # 十字星（实体<10%）
        "is_pin_bar_bull": bool,    # 看多pin bar
        "is_pin_bar_bear": bool,    # 看空pin bar
        "is_marubozu_bull": bool,   # 光头光脚阳线
        "is_marubozu_bear": bool,   # 光头光脚阴线
    }
    """
    if not ohlcv_bars or len(ohlcv_bars) < 1:
        return {}
    
    last = ohlcv_bars[-1]
    o, h, l, c = last["open"], last["high"], last["low"], last["close"]
    
    # 防止除零
    full_range = max(h - l, 1e-9)
    body = abs(c - o)
    
    body_pct = body / full_range
    upper_shadow = h - max(o, c)
    lower_shadow = min(o, c) - l
    upper_shadow_pct = upper_shadow / full_range
    lower_shadow_pct = lower_shadow / full_range
    
    is_bullish = c > o
    is_bearish = c < o
    is_doji = body_pct < 0.1
    is_long_body = body_pct > 0.6
    
    # Pin bar: 长影线>50% + 实体小<30% + 收盘在另一端
    is_pin_bar_bull = (lower_shadow_pct > 0.5 and body_pct < 0.3 and 
                       c > (h + l) / 2)
    is_pin_bar_bear = (upper_shadow_pct > 0.5 and body_pct < 0.3 and 
                       c < (h + l) / 2)
    
    # Marubozu: 实体>80% + 影线极小
    is_marubozu_bull = (is_bullish and body_pct > 0.8 and 
                        upper_shadow_pct < 0.1 and lower_shadow_pct < 0.1)
    is_marubozu_bear = (is_bearish and body_pct > 0.8 and 
                        upper_shadow_pct < 0.1 and lower_shadow_pct < 0.1)
    
    return {
        "body_pct": body_pct,
        "upper_shadow_pct": upper_shadow_pct,
        "lower_shadow_pct": lower_shadow_pct,
        "is_long_body": is_long_body,
        "is_bullish": is_bullish,
        "is_bearish": is_bearish,
        "is_doji": is_doji,
        "is_pin_bar_bull": is_pin_bar_bull,
        "is_pin_bar_bear": is_pin_bar_bear,
        "is_marubozu_bull": is_marubozu_bull,
        "is_marubozu_bear": is_marubozu_bear,
    }


# ============================================================================
# v3.455: 单根K线形态评分函数
# ============================================================================
def compute_candle_shape_score(ohlcv_bar: dict) -> tuple:
    """
    v3.455: 计算单根K线形态分

    用于L2打分的核心层，评估当前K线本身的形态

    Returns:
        (score, shape_name)
        score: -1 ~ +1
        shape_name: 形态名称

    评分规则:
        +1.0: 大阳线(实体≥70%) / 锤子线(下影>2倍实体+收上半区)
        +0.5: 普通阳线(30%<实体<70%)
         0.0: 十字星/纺锤(实体≤30%+影线均衡)
        -0.5: 普通阴线(30%<实体<70%)
        -1.0: 大阴线(实体≥70%) / 射击之星(上影>2倍实体+收下半区)
    """
    if not ohlcv_bar:
        return (0.0, "UNKNOWN")

    o = float(ohlcv_bar.get("open", ohlcv_bar.get("o", 0)))
    h = float(ohlcv_bar.get("high", ohlcv_bar.get("h", 0)))
    l = float(ohlcv_bar.get("low", ohlcv_bar.get("l", 0)))
    c = float(ohlcv_bar.get("close", ohlcv_bar.get("c", 0)))

    body = abs(c - o)
    bar_range = h - l if h > l else 0.0001
    upper_shadow = h - max(o, c)
    lower_shadow = min(o, c) - l

    body_ratio = body / bar_range
    is_bullish = c > o
    is_bearish = c < o

    # 锤子线: 下影>2倍实体 + 收在上半区
    if lower_shadow > body * 2 and c > (h + l) / 2:
        return (1.0, "HAMMER")

    # 射击之星: 上影>2倍实体 + 收在下半区
    if upper_shadow > body * 2 and c < (h + l) / 2:
        return (-1.0, "SHOOTING_STAR")

    # 大阳线: 实体>=70%
    if body_ratio >= 0.7 and is_bullish:
        return (1.0, "STRONG_BULL")

    # 大阴线: 实体>=70%
    if body_ratio >= 0.7 and is_bearish:
        return (-1.0, "STRONG_BEAR")

    # 普通阳线: 30% < 实体 < 70%
    if 0.3 < body_ratio < 0.7 and is_bullish:
        return (0.5, "BULL")

    # 普通阴线: 30% < 实体 < 70%
    if 0.3 < body_ratio < 0.7 and is_bearish:
        return (-0.5, "BEAR")

    # 十字星/纺锤: 实体<=30%
    if body_ratio <= 0.3:
        return (0.0, "DOJI")

    return (0.0, "UNKNOWN")


def identify_swing_points(ohlcv_bars, lookback=3):
    """
    识别swing high/low（分形法）
    
    v2.747: lookback从5改为3，更容易识别震荡市场的swing点
    - lookback=5: 需要11根K线，条件严格
    - lookback=3: 需要7根K线，更敏感
    
    返回：
    {
        "swing_highs": [(index, price), ...],  # 最近N个swing high
        "swing_lows": [(index, price), ...],   # 最近N个swing low
        "last_swing_high": (index, price) or None,
        "last_swing_low": (index, price) or None,
    }
    """
    if not ohlcv_bars or len(ohlcv_bars) < lookback * 2 + 1:
        return {"swing_highs": [], "swing_lows": [], 
                "last_swing_high": None, "last_swing_low": None}
    
    swing_highs = []
    swing_lows = []
    
    for i in range(lookback, len(ohlcv_bars) - lookback):
        # Swing high: 中心高于前后lookback根
        is_high = True
        center_high = ohlcv_bars[i]["high"]
        for j in range(i - lookback, i + lookback + 1):
            if j != i and ohlcv_bars[j]["high"] >= center_high:
                is_high = False
                break
        if is_high:
            swing_highs.append((i, center_high))
        
        # Swing low: 中心低于前后lookback根
        is_low = True
        center_low = ohlcv_bars[i]["low"]
        for j in range(i - lookback, i + lookback + 1):
            if j != i and ohlcv_bars[j]["low"] <= center_low:
                is_low = False
                break
        if is_low:
            swing_lows.append((i, center_low))
    
    return {
        "swing_highs": swing_highs[-10:],  # 保留最近10个
        "swing_lows": swing_lows[-10:],
        "last_swing_high": swing_highs[-1] if swing_highs else None,
        "last_swing_low": swing_lows[-1] if swing_lows else None,
    }


