# v2.850: 统一视觉素材 + 量价背离 + AI历史反馈
# ============================================================================
# ============================================================================
#
# 核心理念：AI和人类视野共享同一套预计算的素材
#
# 模块组成:
#   1. compute_unified_visual_material() - 统一视觉素材计算
#   2. detect_volume_price_divergence() - 量价背离检测
#   3. detect_candle_patterns() - K线形态检测
#   4. get_ai_decision_history() - AI历史反馈
#   5. compute_l1_ai_vision_fusion() - AI+Vision融合 (新架构)
#
# ============================================================================

def detect_volume_price_divergence_v2850(ohlcv_bars: list, lookback: int = 20) -> dict:
    """
    v2.850: 量价背离检测 (L1 AI+Vision融合模块专用)

    注意: v3.160重命名避免与P0增强函数冲突

    检测逻辑:
    - 看跌背离: 价格创新高，但量能萎缩
    - 看涨背离: 价格创新低，但量能萎缩
    - 天量警告: 量能突然放大到均量3倍以上

    Args:
        ohlcv_bars: K线数据列表
        lookback: 回看周期

    Returns:
        {
            "divergence": str,       # BULL_DIV/BEAR_DIV/NONE
            "vol_trend": str,        # RISING/FALLING/FLAT
            "vol_ratio": float,      # 当前量/均量
            "climax_warning": bool,  # 天量警告
            "detail": dict,
        }
    """
    result = {
        "divergence": "NONE",
        "vol_trend": "FLAT",
        "vol_ratio": 1.0,
        "climax_warning": False,
        "detail": {},
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < lookback:
        return result
    
    try:
        bars = ohlcv_bars[-lookback:]
        closes = [b.get("close", 0) for b in bars]
        volumes = [b.get("volume", 0) for b in bars]
        highs = [b.get("high", 0) for b in bars]
        lows = [b.get("low", 0) for b in bars]
        
        if not all(closes) or not all(volumes):
            return result
        
        # 计算量能趋势
        vol_early = sum(volumes[:lookback//2]) / max(lookback//2, 1)
        vol_late = sum(volumes[lookback//2:]) / max(lookback//2, 1)
        vol_avg = sum(volumes) / len(volumes)
        vol_current = volumes[-1]
        
        result["vol_ratio"] = round(vol_current / max(vol_avg, 1e-9), 2)
        
        # 量能趋势判断
        if vol_late > vol_early * 1.2:
            result["vol_trend"] = "RISING"
        elif vol_late < vol_early * 0.8:
            result["vol_trend"] = "FALLING"
        else:
            result["vol_trend"] = "FLAT"
        
        # 天量警告
        if vol_current > vol_avg * 3:
            result["climax_warning"] = True
        
        # 背离检测 - 使用最近5根K线
        recent_highs = highs[-5:]
        recent_lows = lows[-5:]
        recent_vols = volumes[-5:]
        early_vols = volumes[-10:-5] if len(volumes) >= 10 else volumes[:5]
        
        avg_recent_vol = sum(recent_vols) / len(recent_vols)
        avg_early_vol = sum(early_vols) / max(len(early_vols), 1)
        
        # 价格创新高
        current_high = highs[-1]
        prev_max_high = max(highs[:-1]) if len(highs) > 1 else current_high
        price_making_high = current_high >= prev_max_high * 0.998
        
        # 价格创新低
        current_low = lows[-1]
        prev_min_low = min(lows[:-1]) if len(lows) > 1 else current_low
        price_making_low = current_low <= prev_min_low * 1.002
        
        # 量能萎缩
        volume_declining = avg_recent_vol < avg_early_vol * 0.75
        
        # 看跌背离: 价格新高 + 量能萎缩
        if price_making_high and volume_declining:
            result["divergence"] = "BEAR_DIV"
            result["detail"]["reason"] = "价格创新高但量能萎缩"
        
        # 看涨背离: 价格新低 + 量能萎缩
        elif price_making_low and volume_declining:
            result["divergence"] = "BULL_DIV"
            result["detail"]["reason"] = "价格创新低但量能萎缩"
        
        result["detail"]["price_high"] = price_making_high
        result["detail"]["price_low"] = price_making_low
        result["detail"]["vol_declining"] = volume_declining
        
    except Exception as e:
        result["detail"]["error"] = str(e)
    
    return result


def detect_candle_patterns(ohlcv_bars: list) -> dict:
    """
    v2.850: K线形态检测
    
    检测最近K线的形态特征，供AI和Vision共享使用
    
    Returns:
        {
            "last_body_ratio": float,    # 实体/总长比
            "last_direction": str,       # BULL/BEAR/DOJI
            "last_shape": str,           # STRONG_BULL/STRONG_BEAR/DOJI/PINBAR_UP/PINBAR_DOWN
            "pattern_2bar": str,         # ENGULF_BULL/ENGULF_BEAR/NONE
            "pattern_3bar": str,         # MORNING_STAR/EVENING_STAR/NONE
            "consecutive_up": int,       # 连续上涨数
            "consecutive_down": int,     # 连续下跌数
        }
    """
    result = {
        "last_body_ratio": 0.5,
        "last_direction": "DOJI",
        "last_shape": "UNKNOWN",
        "pattern_2bar": "NONE",
        "pattern_3bar": "NONE",
        "consecutive_up": 0,
        "consecutive_down": 0,
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 3:
        return result
    
    try:
        # 最后一根K线分析
        last = ohlcv_bars[-1]
        o, h, l, c = last.get("open", 0), last.get("high", 0), last.get("low", 0), last.get("close", 0)
        
        body = abs(c - o)
        total_range = h - l if h > l else 0.0001
        upper_wick = h - max(o, c)
        lower_wick = min(o, c) - l
        
        # 实体比例
        result["last_body_ratio"] = round(body / total_range, 2) if total_range > 0 else 0.5
        
        # 方向
        if c > o * 1.001:
            result["last_direction"] = "BULL"
        elif c < o * 0.999:
            result["last_direction"] = "BEAR"
        else:
            result["last_direction"] = "DOJI"
        
        # 形态判断
        if result["last_body_ratio"] >= 0.7:
            if result["last_direction"] == "BULL":
                result["last_shape"] = "STRONG_BULL"
            elif result["last_direction"] == "BEAR":
                result["last_shape"] = "STRONG_BEAR"
        elif result["last_body_ratio"] <= 0.3:
            if lower_wick > upper_wick * 2:
                result["last_shape"] = "PINBAR_UP"  # 长下影，看涨
            elif upper_wick > lower_wick * 2:
                result["last_shape"] = "PINBAR_DOWN"  # 长上影，看跌
            else:
                result["last_shape"] = "DOJI"
        else:
            result["last_shape"] = result["last_direction"]
        
        # 连续方向计算
        up_count = 0
        down_count = 0
        for i in range(len(ohlcv_bars) - 1, -1, -1):
            bar = ohlcv_bars[i]
            if bar.get("close", 0) > bar.get("open", 0):
                if down_count == 0:
                    up_count += 1
                else:
                    break
            elif bar.get("close", 0) < bar.get("open", 0):
                if up_count == 0:
                    down_count += 1
                else:
                    break
            else:
                break
        
        result["consecutive_up"] = up_count
        result["consecutive_down"] = down_count
        
        # 2根组合形态
        if len(ohlcv_bars) >= 2:
            prev = ohlcv_bars[-2]
            prev_body = abs(prev.get("close", 0) - prev.get("open", 0))
            curr_body = body
            
            # 看涨吞没
            if (prev.get("close", 0) < prev.get("open", 0) and  # 前阴
                c > o and  # 当前阳
                c > prev.get("open", 0) and  # 收盘高于前开盘
                o < prev.get("close", 0) and  # 开盘低于前收盘
                curr_body > prev_body):  # 实体更大
                result["pattern_2bar"] = "ENGULF_BULL"
            
            # 看跌吞没
            elif (prev.get("close", 0) > prev.get("open", 0) and  # 前阳
                  c < o and  # 当前阴
                  c < prev.get("open", 0) and  # 收盘低于前开盘
                  o > prev.get("close", 0) and  # 开盘高于前收盘
                  curr_body > prev_body):  # 实体更大
                result["pattern_2bar"] = "ENGULF_BEAR"
        
        # 3根组合形态 (简化版)
        if len(ohlcv_bars) >= 3:
            bar1, bar2, bar3 = ohlcv_bars[-3], ohlcv_bars[-2], ohlcv_bars[-1]
            
            # 早晨之星 (简化)
            if (bar1.get("close", 0) < bar1.get("open", 0) and  # 第1根阴线
                abs(bar2.get("close", 0) - bar2.get("open", 0)) < abs(bar1.get("close", 0) - bar1.get("open", 0)) * 0.5 and  # 第2根小实体
                bar3.get("close", 0) > bar3.get("open", 0) and  # 第3根阳线
                bar3.get("close", 0) > (bar1.get("open", 0) + bar1.get("close", 0)) / 2):  # 收盘过半
                result["pattern_3bar"] = "MORNING_STAR"
            
            # 黄昏之星 (简化)
            elif (bar1.get("close", 0) > bar1.get("open", 0) and  # 第1根阳线
                  abs(bar2.get("close", 0) - bar2.get("open", 0)) < abs(bar1.get("close", 0) - bar1.get("open", 0)) * 0.5 and  # 第2根小实体
                  bar3.get("close", 0) < bar3.get("open", 0) and  # 第3根阴线
                  bar3.get("close", 0) < (bar1.get("open", 0) + bar1.get("close", 0)) / 2):  # 收盘过半
                result["pattern_3bar"] = "EVENING_STAR"
    
    except Exception as e:
        pass
    
    return result


def detect_hh_hl_sequence(ohlcv_bars: list, lookback: int = 20) -> dict:
    """
    v2.850: 检测HH/HL/LH/LL序列
    
    - HH (Higher High): 更高的高点
    - HL (Higher Low): 更高的低点
    - LH (Lower High): 更低的高点  
    - LL (Lower Low): 更低的低点
    
    Returns:
        {
            "higher_highs": int,   # HH数量
            "higher_lows": int,    # HL数量
            "lower_highs": int,    # LH数量
            "lower_lows": int,     # LL数量
            "sequence_bias": str,  # BULLISH/BEARISH/NEUTRAL
        }
    """
    result = {
        "higher_highs": 0,
        "higher_lows": 0,
        "lower_highs": 0,
        "lower_lows": 0,
        "sequence_bias": "NEUTRAL",
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < lookback:
        return result
    
    try:
        bars = ohlcv_bars[-lookback:]
        highs = [b.get("high", 0) for b in bars]
        lows = [b.get("low", 0) for b in bars]
        
        # 找局部高点和低点 (简化: 每5根取一个)
        step = 5
        local_highs = []
        local_lows = []
        
        for i in range(0, len(bars) - step + 1, step):
            chunk = bars[i:i+step]
            chunk_highs = [b.get("high", 0) for b in chunk]
            chunk_lows = [b.get("low", 0) for b in chunk]
            local_highs.append(max(chunk_highs))
            local_lows.append(min(chunk_lows))
        
        # 计算HH/LH
        for i in range(1, len(local_highs)):
            if local_highs[i] > local_highs[i-1]:
                result["higher_highs"] += 1
            elif local_highs[i] < local_highs[i-1]:
                result["lower_highs"] += 1
        
        # 计算HL/LL
        for i in range(1, len(local_lows)):
            if local_lows[i] > local_lows[i-1]:
                result["higher_lows"] += 1
            elif local_lows[i] < local_lows[i-1]:
                result["lower_lows"] += 1
        
        # 综合判断
        bull_score = result["higher_highs"] + result["higher_lows"]
        bear_score = result["lower_highs"] + result["lower_lows"]
        
        if bull_score > bear_score + 1:
            result["sequence_bias"] = "BULLISH"
        elif bear_score > bull_score + 1:
            result["sequence_bias"] = "BEARISH"
        else:
            result["sequence_bias"] = "NEUTRAL"
    
    except Exception as e:
        pass
    
    return result


def compute_unified_visual_material(ohlcv_bars: list, state: dict = None) -> dict:
    """
    v2.850: 统一视觉素材计算
    
    为AI(LLM)和人类视野(Vision)提供统一的预计算素材，
    确保两者基于相同的数据做判断。
    
    Args:
        ohlcv_bars: K线数据列表
        state: 状态字典 (用于AI历史反馈)
    
    Returns:
        {
            "trend": {...},          # 趋势视觉
            "candle": {...},         # K线形态
            "volume_price": {...},   # 量价关系
            "sequence": {...},       # HH/HL序列
            "position": {...},       # 位置信息
            "ai_history": {...},     # AI历史反馈
        }
    """
    result = {
        "trend": {},
        "candle": {},
        "volume_price": {},
        "sequence": {},
        "position": {},
        "ai_history": {},
        "ready": False,
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 20:
        return result
    
    try:
        # 1. 趋势计算 (复用现有函数)
        from typing import List
        closes = [b.get("close", 0) for b in ohlcv_bars]
        
        # 斜率计算
        def calc_slope(data: list) -> float:
            n = len(data)
            if n < 3:
                return 0.0
            x_mean = (n - 1) / 2.0
            y_mean = sum(data) / n
            num = sum((i - x_mean) * (y - y_mean) for i, y in enumerate(data))
            den = sum((i - x_mean) ** 2 for i in range(n))
            if den == 0 or y_mean == 0:
                return 0.0
            return (num / den) / y_mean
        
        slope_5 = calc_slope(closes[-5:]) if len(closes) >= 5 else 0
        slope_10 = calc_slope(closes[-10:]) if len(closes) >= 10 else 0
        slope_20 = calc_slope(closes[-20:]) if len(closes) >= 20 else 0
        
        # 趋势方向
        if slope_10 > 0.002:
            if slope_5 > 0.003:
                trend_visual = "STRONG_UP"
            else:
                trend_visual = "UP"
        elif slope_10 < -0.002:
            if slope_5 < -0.003:
                trend_visual = "STRONG_DOWN"
            else:
                trend_visual = "DOWN"
        else:
            trend_visual = "SIDE"
        
        # 趋势强度
        trend_strength = min(abs(slope_10) / 0.005, 1.0)
        
        result["trend"] = {
            "slope_5": round(slope_5 * 100, 3),
            "slope_10": round(slope_10 * 100, 3),
            "slope_20": round(slope_20 * 100, 3),
            "trend_visual": trend_visual,
            "trend_strength": round(trend_strength, 2),
            "slope_alignment": (slope_5 * slope_10 > 0 and slope_10 * slope_20 > 0),
        }
        
        # 2. K线形态 (v2.940: 增强版)
        result["candle"] = detect_candle_patterns_v2940(ohlcv_bars)
        
        # 3. 量价关系 (使用v2.850版本)
        result["volume_price"] = detect_volume_price_divergence_v2850(ohlcv_bars)
        
        # 4. HH/HL序列
        result["sequence"] = detect_hh_hl_sequence(ohlcv_bars)
        
        # 5. 位置信息
        highs = [b.get("high", 0) for b in ohlcv_bars]
        lows = [b.get("low", 0) for b in ohlcv_bars]
        last_close = closes[-1]
        high_120 = max(highs) if highs else last_close
        low_120 = min(lows) if lows else last_close
        
        pos_ratio = (last_close - low_120) / max(high_120 - low_120, 0.0001)
        
        result["position"] = {
            "pos_ratio": round(pos_ratio, 3),
            "zone": "HIGH" if pos_ratio > 0.7 else ("LOW" if pos_ratio < 0.3 else "MID"),
            "near_resistance": pos_ratio > 0.85,
            "near_support": pos_ratio < 0.15,
            "high_120": high_120,
            "low_120": low_120,
        }
        
        # 6. AI历史反馈
        if state:
            ai_decisions = state.get("ai_decision_history", [])
            
            # 计算最近准确率
            recent = ai_decisions[-10:] if ai_decisions else []
            wins = sum(1 for d in recent if d.get("result") == "WIN")
            total = len([d for d in recent if d.get("result") in ["WIN", "LOSS"]])
            
            recent_accuracy = wins / total if total > 0 else 0.5
            
            # 置信度校准因子
            if recent_accuracy < 0.35:
                confidence_factor = 0.7
            elif recent_accuracy < 0.45:
                confidence_factor = 0.85
            elif recent_accuracy > 0.6:
                confidence_factor = 1.1
            else:
                confidence_factor = 1.0
            
            # 上次错误分析
            last_mistake = None
            for d in reversed(ai_decisions[-5:]):
                if d.get("result") == "LOSS":
                    last_mistake = d.get("mistake_type", "unknown")
                    break
            
            result["ai_history"] = {
                "last_3_decisions": ai_decisions[-3:] if ai_decisions else [],
                "recent_accuracy": round(recent_accuracy, 2),
                "confidence_factor": confidence_factor,
                "last_mistake": last_mistake,
                "total_decisions": len(ai_decisions),
            }
        else:
            result["ai_history"] = {
                "last_3_decisions": [],
                "recent_accuracy": 0.5,
                "confidence_factor": 1.0,
                "last_mistake": None,
                "total_decisions": 0,
            }
        
        result["ready"] = True
    
    except Exception as e:
        result["error"] = str(e)
    
    return result


def compute_l1_ai_vision_fusion(
    llm_action: str,
    llm_confidence: float,
    vision_result: dict,
    visual_material: dict,
) -> dict:
    """
    [DEPRECATED v3.370] AI + Vision 融合 (各50%权重)

    ⚠️ 此函数已废弃，仅作为回退模式使用
    ⚠️ 新架构使用 compute_l1_five_module_v3300() 替代
    ⚠️ 当K线数据不足时才会调用此函数

    v2.850原始功能: 基于统一视觉素材，将LLM判断和Vision判断融合

    Args:
        llm_action: LLM原始动作 (BUY/SELL/HOLD)
        llm_confidence: LLM置信度 (0-1)
        vision_result: L1趋势视觉结果
        visual_material: 统一视觉素材

    Returns:
        {
            "fused_score": float,    # 融合评分 -1~+1
            "fused_action": str,     # BUY/SELL/HOLD
            "fused_confidence": float,
            "agreement": str,        # AGREE/PARTIAL/CONFLICT
            "llm_contrib": float,
            "vision_contrib": float,
            "adjustments": list,     # 调整说明
        }
    """
    # v3.370: 废弃警告
    print("[DEPRECATED] compute_l1_ai_vision_fusion() 已废弃，请使用 compute_l1_five_module_v3300()")
    result = {
        "fused_score": 0.0,
        "fused_action": "HOLD",
        "fused_confidence": 0.5,
        "agreement": "PARTIAL",
        "llm_contrib": 0.0,
        "vision_contrib": 0.0,
        "adjustments": [],
    }
    
    # LLM评分转换
    if llm_action == "BUY":
        llm_score = llm_confidence
    elif llm_action == "SELL":
        llm_score = -llm_confidence
    else:
        llm_score = 0.0
    
    # Vision评分
    vision_score = vision_result.get("score", 0.0) if vision_result else 0.0
    vision_bias = vision_result.get("l1_bias", "HOLD") if vision_result else "HOLD"  # v3.340: 统一格式
    vision_conf = vision_result.get("confidence", 0.5) if vision_result else 0.5
    
    # 基础融合 (各50%)
    base_fused = llm_score * 0.5 + vision_score * 0.5
    
    # ========== 调整因子 ==========
    adjustments = []
    adjustment_factor = 1.0
    
    # 1. 一致性奖惩
    llm_dir = 1 if llm_action == "BUY" else (-1 if llm_action == "SELL" else 0)
    vision_dir = 1 if vision_bias in ["STRONG_BUY", "BUY"] else (-1 if vision_bias in ["STRONG_SELL", "SELL"] else 0)  # v3.340: 统一格式
    
    if llm_dir == vision_dir and llm_dir != 0:
        adjustment_factor *= 1.15
        result["agreement"] = "AGREE"
        adjustments.append("AI+Vision一致 +15%")
    elif llm_dir == -vision_dir and llm_dir != 0:
        adjustment_factor *= 0.7
        result["agreement"] = "CONFLICT"
        adjustments.append("AI+Vision冲突 -30%")
    else:
        result["agreement"] = "PARTIAL"
    
    # 2. 量价背离调整
    if visual_material.get("ready"):
        vol_price = visual_material.get("volume_price", {})
        divergence = vol_price.get("divergence", "NONE")
        
        if divergence == "BEAR_DIV" and base_fused > 0:
            adjustment_factor *= 0.8
            adjustments.append("看跌背离 -20%")
        elif divergence == "BULL_DIV" and base_fused < 0:
            adjustment_factor *= 0.8
            adjustments.append("看涨背离 -20%")
        
        # 天量警告
        if vol_price.get("climax_warning"):
            adjustment_factor *= 0.85
            adjustments.append("天量警告 -15%")
    
    # 3. HH/HL序列确认
    if visual_material.get("ready"):
        sequence = visual_material.get("sequence", {})
        seq_bias = sequence.get("sequence_bias", "NEUTRAL")
        
        if seq_bias == "BULLISH" and base_fused > 0:
            adjustment_factor *= 1.1
            adjustments.append("HH/HL序列确认 +10%")
        elif seq_bias == "BEARISH" and base_fused < 0:
            adjustment_factor *= 1.1
            adjustments.append("LH/LL序列确认 +10%")
        elif seq_bias == "BULLISH" and base_fused < 0:
            adjustment_factor *= 0.9
            adjustments.append("HH/HL与方向矛盾 -10%")
        elif seq_bias == "BEARISH" and base_fused > 0:
            adjustment_factor *= 0.9
            adjustments.append("LH/LL与方向矛盾 -10%")
    
    # 4. AI历史反馈调整
    if visual_material.get("ready"):
        ai_history = visual_material.get("ai_history", {})
        conf_factor = ai_history.get("confidence_factor", 1.0)
        
        # 只调整LLM部分的贡献
        llm_adjusted = llm_score * conf_factor
        base_fused = llm_adjusted * 0.5 + vision_score * 0.5
        
        if conf_factor < 1.0:
            adjustments.append(f"AI校准 x{conf_factor:.2f}")
    
    # 应用调整
    final_score = base_fused * adjustment_factor
    final_score = max(-1.0, min(1.0, final_score))  # 限制范围
    
    result["fused_score"] = round(final_score, 4)
    result["llm_contrib"] = round(llm_score * 0.5, 4)
    result["vision_contrib"] = round(vision_score * 0.5, 4)
    result["adjustments"] = adjustments
    
    # 确定动作和置信度
    if final_score >= 0.15:
        result["fused_action"] = "BUY"
    elif final_score <= -0.15:
        result["fused_action"] = "SELL"
    else:
        result["fused_action"] = "HOLD"
    
    result["fused_confidence"] = round(min(abs(final_score) / 0.6, 1.0), 3)
    
    return result


