# ============================================================================
# v2.905: Phase 4 - 事后验证系统 (Three-Way Validator)
# ============================================================================

THREE_WAY_VALIDATION_FILE = "state/three_way_validation.json"
VALIDATION_BARS_AHEAD = 3  # 3根K线后验证
VALIDATION_BUY_THRESHOLD = 0.005   # BUY正确阈值: +0.5%
VALIDATION_SELL_THRESHOLD = -0.005  # SELL正确阈值: -0.5%
VALIDATION_HOLD_THRESHOLD = 0.01   # HOLD正确阈值: |涨跌|<1%
MAX_VALIDATION_RECORDS = 100  # 每个symbol最多保留100条记录

class ThreeWayValidator:
    """
    v2.905: 三方协商事后验证器
    
    功能:
        1. 记录每次决策的三方信号和价格
        2. 3根K线后自动验证结果
        3. 追踪AI/Human/Tech各自准确率
    """
    
    def __init__(self, file_path: str = THREE_WAY_VALIDATION_FILE):
        self.file_path = file_path
        self.data = self._load()
    
    def _load(self) -> dict:
        """加载验证数据"""
        import os
        if not os.path.exists(self.file_path):
            return {"records": {}, "stats": {}}
        try:
            with open(self.file_path, "r") as f:
                return json.load(f)
        except Exception as e:
            print(f"[V2905_VALIDATOR] 加载失败: {e}")
            return {"records": {}, "stats": {}}
    
    def _save(self):
        """保存验证数据"""
        import os
        os.makedirs(os.path.dirname(self.file_path) if os.path.dirname(self.file_path) else ".", exist_ok=True)
        try:
            with open(self.file_path, "w") as f:
                json.dump(self.data, f, indent=2)
        except Exception as e:
            print(f"[V2905_VALIDATOR] 保存失败: {e}")
    
    def record_decision(self, symbol: str, price: float, 
                       ai_signal: str, human_signal: str, tech_signal: str,
                       final_signal: str, bar_index: int):
        """
        记录一次决策
        
        Args:
            symbol: 交易对
            price: 决策时价格
            ai_signal: AI信号
            human_signal: Human信号
            tech_signal: Tech信号
            final_signal: 最终信号
            bar_index: K线索引（用于判断何时验证）
        """
        if symbol not in self.data["records"]:
            self.data["records"][symbol] = []
        
        record = {
            "timestamp": int(time.time()),
            "bar_index": bar_index,
            "price": price,
            "ai_signal": ai_signal,
            "human_signal": human_signal,
            "tech_signal": tech_signal,
            "final_signal": final_signal,
            "verified": False,
            "verify_bar_index": bar_index + VALIDATION_BARS_AHEAD,
            "outcome": None,
            "ai_correct": None,
            "human_correct": None,
            "tech_correct": None,
            "final_correct": None,
            "price_change_pct": None,
        }
        
        self.data["records"][symbol].append(record)
        
        # 限制记录数量
        if len(self.data["records"][symbol]) > MAX_VALIDATION_RECORDS:
            self.data["records"][symbol] = self.data["records"][symbol][-MAX_VALIDATION_RECORDS:]
        
        self._save()
        print(f"[V2905_VALIDATOR] {symbol} 记录决策: AI={ai_signal}, Human={human_signal}, Tech={tech_signal}, Final={final_signal} @ {price:.2f}")
    
    def verify_pending(self, symbol: str, current_price: float, current_bar_index: int):
        """
        验证待验证的决策
        
        Args:
            symbol: 交易对
            current_price: 当前价格
            current_bar_index: 当前K线索引
        """
        if symbol not in self.data["records"]:
            return
        
        verified_count = 0
        for record in self.data["records"][symbol]:
            if record["verified"]:
                continue
            
            if current_bar_index >= record["verify_bar_index"]:
                # 计算涨跌幅
                entry_price = record["price"]
                if entry_price > 0:
                    change_pct = (current_price - entry_price) / entry_price
                else:
                    change_pct = 0
                
                record["price_change_pct"] = round(change_pct, 6)
                record["verified"] = True
                record["verify_price"] = current_price
                record["verify_timestamp"] = int(time.time())
                
                # 验证各方信号
                record["ai_correct"] = self._verify_signal(record["ai_signal"], change_pct)
                record["human_correct"] = self._verify_signal(record["human_signal"], change_pct)
                record["tech_correct"] = self._verify_signal(record["tech_signal"], change_pct)
                record["final_correct"] = self._verify_signal(record["final_signal"], change_pct)
                
                # 判断整体结果
                if record["final_correct"]:
                    record["outcome"] = "CORRECT"
                else:
                    record["outcome"] = "WRONG"
                
                verified_count += 1
                print(f"[V2905_VALIDATOR] {symbol} 验证完成: {record['outcome']} | "
                      f"涨跌={change_pct:.2%} | AI={record['ai_correct']} | "
                      f"Human={record['human_correct']} | Tech={record['tech_correct']}")
        
        if verified_count > 0:
            self._update_stats(symbol)
            self._save()
    
    def _verify_signal(self, signal: str, change_pct: float) -> bool:
        """验证单个信号是否正确"""
        signal = str(signal).upper()
        
        # BUY系信号
        if signal in ("STRONG_BUY", "BUY", "BUY"):
            return change_pct > VALIDATION_BUY_THRESHOLD
        
        # SELL系信号
        if signal in ("STRONG_SELL", "SELL", "SELL"):
            return change_pct < VALIDATION_SELL_THRESHOLD
        
        # HOLD信号
        if signal in ("HOLD", "HOLD"):
            return abs(change_pct) < VALIDATION_HOLD_THRESHOLD
        
        # 未知信号视为HOLD
        return abs(change_pct) < VALIDATION_HOLD_THRESHOLD
    
    def _update_stats(self, symbol: str):
        """更新统计数据"""
        if symbol not in self.data["records"]:
            return
        
        verified_records = [r for r in self.data["records"][symbol] if r["verified"]]
        
        if not verified_records:
            return
        
        total = len(verified_records)
        ai_correct = sum(1 for r in verified_records if r.get("ai_correct"))
        human_correct = sum(1 for r in verified_records if r.get("human_correct"))
        tech_correct = sum(1 for r in verified_records if r.get("tech_correct"))
        final_correct = sum(1 for r in verified_records if r.get("final_correct"))
        
        self.data["stats"][symbol] = {
            "total": total,
            "ai_accuracy": round(ai_correct / total, 3) if total > 0 else 0.5,
            "human_accuracy": round(human_correct / total, 3) if total > 0 else 0.5,
            "tech_accuracy": round(tech_correct / total, 3) if total > 0 else 0.5,
            "final_accuracy": round(final_correct / total, 3) if total > 0 else 0.5,
            "ai_correct": ai_correct,
            "human_correct": human_correct,
            "tech_correct": tech_correct,
            "final_correct": final_correct,
            "last_update": int(time.time()),
        }
    
    def get_stats(self, symbol: str) -> dict:
        """获取统计数据"""
        return self.data.get("stats", {}).get(symbol, {
            "total": 0,
            "ai_accuracy": 0.5,
            "human_accuracy": 0.5,
            "tech_accuracy": 0.5,
            "final_accuracy": 0.5,
        })
    
    def get_all_stats(self) -> dict:
        """获取所有symbol的统计数据"""
        return self.data.get("stats", {})


# ============================================================================
# v2.905: Phase 5 - 动态校准系统 (Three-Way Calibrator)
# ============================================================================

THREE_WAY_CALIBRATION_FILE = "state/three_way_calibration.json"

# 准确率 → 校准因子映射
ACCURACY_TO_FACTOR = [
    (0.35, 0.70),   # <35%: 严重降权
    (0.45, 0.85),   # 35-45%: 轻度降权
    (0.55, 1.00),   # 45-55%: 基准
    (0.65, 1.15),   # 55-65%: 轻度增权
    (1.00, 1.30),   # >65%: 显著增权
]

class ThreeWayCalibrator:
    """
    v2.905: 三方协商动态校准器
    
    功能:
        1. 根据历史准确率计算校准因子
        2. 动态调整AI/Human/Tech权重
        3. 权重归一化确保总和为1
    """
    
    def __init__(self, validator: ThreeWayValidator = None, 
                 file_path: str = THREE_WAY_CALIBRATION_FILE):
        self.validator = validator
        self.file_path = file_path
        self.base_weights = {
            "ai": 0.35,
            "human": 0.35,
            "tech": 0.30,
        }
        self.calibration_data = self._load()
    
    def _load(self) -> dict:
        """加载校准数据"""
        import os
        if not os.path.exists(self.file_path):
            return {}
        try:
            with open(self.file_path, "r") as f:
                return json.load(f)
        except Exception as e:
            print(f"[V2905_CALIBRATOR] 加载失败: {e}")
            return {}
    
    def _save(self):
        """保存校准数据"""
        import os
        os.makedirs(os.path.dirname(self.file_path) if os.path.dirname(self.file_path) else ".", exist_ok=True)
        try:
            with open(self.file_path, "w") as f:
                json.dump(self.calibration_data, f, indent=2)
        except Exception as e:
            print(f"[V2905_CALIBRATOR] 保存失败: {e}")
    
    def _accuracy_to_factor(self, accuracy: float) -> float:
        """准确率转校准因子"""
        for threshold, factor in ACCURACY_TO_FACTOR:
            if accuracy < threshold:
                return factor
        return ACCURACY_TO_FACTOR[-1][1]
    
    def calibrate_weights(self, symbol: str) -> dict:
        """
        计算动态校准后的权重
        
        Args:
            symbol: 交易对
            
        Returns:
            {
                "ai": float,
                "human": float,
                "tech": float,
                "factors": {"ai": float, "human": float, "tech": float},
                "accuracies": {"ai": float, "human": float, "tech": float},
                "calibrated": bool,
            }
        """
        result = {
            "ai": self.base_weights["ai"],
            "human": self.base_weights["human"],
            "tech": self.base_weights["tech"],
            "factors": {"ai": 1.0, "human": 1.0, "tech": 1.0},
            "accuracies": {"ai": 0.5, "human": 0.5, "tech": 0.5},
            "calibrated": False,
            "sample_count": 0,
        }
        
        if not self.validator:
            return result
        
        stats = self.validator.get_stats(symbol)
        sample_count = stats.get("total", 0)
        result["sample_count"] = sample_count
        
        # 需要至少10个样本才开始校准
        if sample_count < 10:
            return result
        
        # 获取准确率
        ai_acc = stats.get("ai_accuracy", 0.5)
        human_acc = stats.get("human_accuracy", 0.5)
        tech_acc = stats.get("tech_accuracy", 0.5)
        
        result["accuracies"] = {
            "ai": ai_acc,
            "human": human_acc,
            "tech": tech_acc,
        }
        
        # 计算校准因子
        ai_factor = self._accuracy_to_factor(ai_acc)
        human_factor = self._accuracy_to_factor(human_acc)
        tech_factor = self._accuracy_to_factor(tech_acc)
        
        result["factors"] = {
            "ai": ai_factor,
            "human": human_factor,
            "tech": tech_factor,
        }
        
        # 计算调整后权重
        ai_adjusted = self.base_weights["ai"] * ai_factor
        human_adjusted = self.base_weights["human"] * human_factor
        tech_adjusted = self.base_weights["tech"] * tech_factor
        
        # 归一化
        total = ai_adjusted + human_adjusted + tech_adjusted
        if total > 0:
            result["ai"] = round(ai_adjusted / total, 4)
            result["human"] = round(human_adjusted / total, 4)
            result["tech"] = round(tech_adjusted / total, 4)
            result["calibrated"] = True
        
        # 保存校准数据
        self.calibration_data[symbol] = {
            "weights": {
                "ai": result["ai"],
                "human": result["human"],
                "tech": result["tech"],
            },
            "factors": result["factors"],
            "accuracies": result["accuracies"],
            "sample_count": sample_count,
            "last_update": int(time.time()),
        }
        self._save()
        
        print(f"[V2905_CALIBRATOR] {symbol} 动态权重: "
              f"AI={result['ai']:.1%}(acc={ai_acc:.0%},f={ai_factor:.2f}) | "
              f"Human={result['human']:.1%}(acc={human_acc:.0%},f={human_factor:.2f}) | "
              f"Tech={result['tech']:.1%}(acc={tech_acc:.0%},f={tech_factor:.2f})")
        
        return result
    
    def get_calibration_info(self, symbol: str) -> dict:
        """获取校准信息（用于监控显示）"""
        return self.calibration_data.get(symbol, {})
    
    def get_all_calibration_info(self) -> dict:
        """获取所有symbol的校准信息"""
        return self.calibration_data


# 全局验证器和校准器实例
_three_way_validator = None
_three_way_calibrator = None

def get_three_way_validator() -> ThreeWayValidator:
    """获取全局验证器实例"""
    global _three_way_validator
    if _three_way_validator is None:
        _three_way_validator = ThreeWayValidator()
    return _three_way_validator

def get_three_way_calibrator() -> ThreeWayCalibrator:
    """获取全局校准器实例"""
    global _three_way_calibrator
    if _three_way_calibrator is None:
        _three_way_calibrator = ThreeWayCalibrator(validator=get_three_way_validator())
    return _three_way_calibrator


# ============================================================================
# v2.930: Phase 6 - L2事后验证系统 (L2 Validator)
# ============================================================================

L2_VALIDATION_FILE = "state/l2_validation.json"
L2_CALIBRATION_FILE = "state/l2_calibration.json"
L2_VALIDATION_BARS_AHEAD = 4  # 4根K线后验证
L2_MIN_SAMPLES = 10  # 最小样本数
L2_MAX_RECORDS = 100  # 每个symbol最多保留100条记录

# L2 exec_bias 验证阈值
L2_VALIDATION_RULES = {
    "STRONG_BUY":  {"direction": "UP",   "threshold": 0.008},  # 涨幅 > 0.8%
    "BUY":      {"direction": "UP",   "threshold": 0.004},  # 涨幅 > 0.4%
    "HOLD":  {"direction": "FLAT", "threshold": 0.010},  # |涨跌| < 1%
    "SELL":     {"direction": "DOWN", "threshold": 0.004},  # 跌幅 > 0.4%
    "STRONG_SELL": {"direction": "DOWN", "threshold": 0.008},  # 跌幅 > 0.8%
}

# PA Tag 验证规则
L2_PA_TAG_VALIDATION = {
    # 看多形态
    "BULL_ENGULF": {"direction": "UP", "threshold": 0.005},
    "PIN_BAR_BULL": {"direction": "UP", "threshold": 0.005},
    "BREAKOUT_UP": {"direction": "UP", "threshold": 0.006},
    "TREND_CONTINUATION_UP": {"direction": "UP", "threshold": 0.004},
    "FAKE_BREAKOUT_DOWN": {"direction": "UP", "threshold": 0.005},
    # 看空形态
    "BEAR_ENGULF": {"direction": "DOWN", "threshold": 0.005},
    "PIN_BAR_BEAR": {"direction": "DOWN", "threshold": 0.005},
    "BREAKOUT_DOWN": {"direction": "DOWN", "threshold": 0.006},
    "TREND_CONTINUATION_DOWN": {"direction": "DOWN", "threshold": 0.004},
    "FAKE_BREAKOUT_UP": {"direction": "DOWN", "threshold": 0.005},
    # 中性
    "NONE": {"direction": "FLAT", "threshold": 0.008},
}

# 2B Tag 验证规则
L2_TAG_2B_VALIDATION = {
    "TWO_B_BOTTOM": {"direction": "UP", "threshold": 0.006},
    "TWO_B_TOP": {"direction": "DOWN", "threshold": 0.006},
    "NONE": {"direction": "FLAT", "threshold": 0.010},
}

# 123 Tag 验证规则
L2_TAG_123_VALIDATION = {
    "ONE_TWO_THREE_LONG": {"direction": "UP", "threshold": 0.008},
    "ONE_TWO_THREE_SHORT": {"direction": "DOWN", "threshold": 0.008},
    "NONE": {"direction": "FLAT", "threshold": 0.010},
}

# Volume State 验证规则
L2_VOLUME_VALIDATION = {
    "CLIMAX": {"direction": "FLAT", "threshold": 0.010},  # 高潮量，方向不定
    "RISING": {"direction": "FLAT", "threshold": 0.008},
    "FALLING": {"direction": "FLAT", "threshold": 0.010},
    "DRY_UP": {"direction": "FLAT", "threshold": 0.010},
    "NORMAL": {"direction": "FLAT", "threshold": 0.010},
}

# SR Position 验证规则
L2_SR_VALIDATION = {
    "NEAR_SUPPORT": {"direction": "UP", "threshold": 0.005},   # 支撑位应该反弹
    "NEAR_RESISTANCE": {"direction": "DOWN", "threshold": 0.005},  # 阻力位应该回落
    "MID_RANGE": {"direction": "FLAT", "threshold": 0.010},
}

# L2子信号基础权重
L2_BASE_WEIGHTS = {
    "pa": 2.0,
    "tag_2b": 1.5,
    "tag_123": 1.5,
    "volume": 1.0,
    "n_swing": 1.0,
    "sr": 1.0,
}

# L2准确率 → 校准因子
L2_ACCURACY_TO_FACTOR = [
    (0.40, 0.60),   # <40%: 严重降权
    (0.50, 0.80),   # 40-50%: 轻度降权
    (0.60, 1.00),   # 50-60%: 基准
    (0.70, 1.15),   # 60-70%: 轻度增权
    (1.00, 1.30),   # >70%: 显著增权
]


class L2Validator:
    """
    v2.930: L2结构分析事后验证器
    
    功能:
        1. 记录每次L2决策的exec_bias和子信号
        2. 4根K线后自动验证结果
        3. 追踪各子信号准确率
    """
    
    def __init__(self, file_path: str = L2_VALIDATION_FILE):
        self.file_path = file_path
        self.data = self._load()
    
    def _load(self) -> dict:
        """加载验证数据"""
        import os
        if not os.path.exists(self.file_path):
            return {"records": {}, "stats": {}}
        try:
            with open(self.file_path, "r") as f:
                return json.load(f)
        except Exception as e:
            print(f"[V2930_L2_VALIDATOR] 加载失败: {e}")
            return {"records": {}, "stats": {}}
    
    def _save(self):
        """保存验证数据"""
        import os
        os.makedirs(os.path.dirname(self.file_path) if os.path.dirname(self.file_path) else ".", exist_ok=True)
        try:
            with open(self.file_path, "w") as f:
                json.dump(self.data, f, indent=2)
        except Exception as e:
            print(f"[V2930_L2_VALIDATOR] 保存失败: {e}")
    
    def record_decision(self, symbol: str, price: float, bar_index: int,
                       exec_bias: str, l2_score: int,
                       pa_tag: str, pa_score: int,
                       tag_2b: str, tag_2b_score: int,
                       tag_123: str, tag_123_score: int,
                       volume_state: str, volume_score: int,
                       n_swing_score: int,
                       sr_position: str, sr_score: int):
        """
        记录一次L2决策
        """
        if symbol not in self.data["records"]:
            self.data["records"][symbol] = []
        
        record = {
            "timestamp": int(time.time()),
            "bar_index": bar_index,
            "price": price,
            # L2总输出
            "exec_bias": exec_bias,
            "l2_score": l2_score,
            # 子信号
            "pa_tag": pa_tag,
            "pa_score": pa_score,
            "tag_2b": tag_2b,
            "tag_2b_score": tag_2b_score,
            "tag_123": tag_123,
            "tag_123_score": tag_123_score,
            "volume_state": volume_state,
            "volume_score": volume_score,
            "n_swing_score": n_swing_score,
            "sr_position": sr_position,
            "sr_score": sr_score,
            # 验证字段
            "verify_bar_index": bar_index + L2_VALIDATION_BARS_AHEAD,
            "verified": False,
            "verify_price": 0,
            "price_change_pct": 0,
            # 验证结果
            "exec_bias_correct": None,
            "pa_correct": None,
            "tag_2b_correct": None,
            "tag_123_correct": None,
            "volume_correct": None,
            "n_swing_correct": None,
            "sr_correct": None,
        }
        
        self.data["records"][symbol].append(record)
        
        # 限制记录数量
        if len(self.data["records"][symbol]) > L2_MAX_RECORDS:
            self.data["records"][symbol] = self.data["records"][symbol][-L2_MAX_RECORDS:]
        
        self._save()
        print(f"[V2930_L2_VALIDATOR] {symbol} 记录L2决策: exec_bias={exec_bias}, score={l2_score}, PA={pa_tag}")
    
    def verify_pending(self, symbol: str, current_price: float, current_bar_index: int):
        """验证待验证的L2决策"""
        if symbol not in self.data["records"]:
            return
        
        verified_count = 0
        for record in self.data["records"][symbol]:
            if record["verified"]:
                continue
            
            if current_bar_index >= record["verify_bar_index"]:
                # 计算涨跌幅
                entry_price = record["price"]
                if entry_price > 0:
                    change_pct = (current_price - entry_price) / entry_price
                else:
                    change_pct = 0
                
                record["price_change_pct"] = round(change_pct, 6)
                record["verified"] = True
                record["verify_price"] = current_price
                
                # 验证exec_bias
                record["exec_bias_correct"] = self._verify_signal(
                    record["exec_bias"], change_pct, L2_VALIDATION_RULES)
                
                # 验证PA
                record["pa_correct"] = self._verify_signal(
                    record["pa_tag"], change_pct, L2_PA_TAG_VALIDATION)
                
                # 验证2B
                record["tag_2b_correct"] = self._verify_signal(
                    record["tag_2b"], change_pct, L2_TAG_2B_VALIDATION)
                
                # 验证123
                record["tag_123_correct"] = self._verify_signal(
                    record["tag_123"], change_pct, L2_TAG_123_VALIDATION)
                
                # 验证Volume (成交量方向不确定，只验证是否为FLAT)
                record["volume_correct"] = self._verify_signal(
                    record["volume_state"], change_pct, L2_VOLUME_VALIDATION)
                
                # 验证N-Swing
                record["n_swing_correct"] = self._verify_n_swing(
                    record["n_swing_score"], change_pct)
                
                # 验证SR
                record["sr_correct"] = self._verify_signal(
                    record["sr_position"], change_pct, L2_SR_VALIDATION)
                
                verified_count += 1
                print(f"[V2930_L2_VALIDATOR] {symbol} 验证完成: exec_bias={record['exec_bias_correct']} | "
                      f"涨跌={change_pct:.2%} | PA={record['pa_correct']} | N-Swing={record['n_swing_correct']}")
        
        if verified_count > 0:
            self._update_stats(symbol)
            self._save()
    
    def _verify_signal(self, signal: str, change_pct: float, rules: dict) -> bool:
        """验证单个信号"""
        rule = rules.get(signal, rules.get("NONE", {"direction": "FLAT", "threshold": 0.010}))
        
        if rule["direction"] == "UP":
            return change_pct > rule["threshold"]
        elif rule["direction"] == "DOWN":
            return change_pct < -rule["threshold"]
        else:  # FLAT
            return abs(change_pct) < rule["threshold"]
    
    def _verify_n_swing(self, n_swing_score: int, change_pct: float) -> bool:
        """验证N-Swing信号"""
        if n_swing_score > 0:  # 看多
            return change_pct > 0.004
        elif n_swing_score < 0:  # 看空
            return change_pct < -0.004
        else:  # 中性
            return abs(change_pct) < 0.010
    
    def _update_stats(self, symbol: str):
        """更新统计数据"""
        if symbol not in self.data["records"]:
            return
        
        verified_records = [r for r in self.data["records"][symbol] if r["verified"]]
        
        if not verified_records:
            return
        
        total = len(verified_records)
        
        # 统计各项准确率
        exec_correct = sum(1 for r in verified_records if r.get("exec_bias_correct"))
        pa_correct = sum(1 for r in verified_records if r.get("pa_correct"))
        tag_2b_correct = sum(1 for r in verified_records if r.get("tag_2b_correct"))
        tag_123_correct = sum(1 for r in verified_records if r.get("tag_123_correct"))
        volume_correct = sum(1 for r in verified_records if r.get("volume_correct"))
        n_swing_correct = sum(1 for r in verified_records if r.get("n_swing_correct"))
        sr_correct = sum(1 for r in verified_records if r.get("sr_correct"))
        
        self.data["stats"][symbol] = {
            "total": total,
            "exec_bias_accuracy": round(exec_correct / total, 3) if total > 0 else 0.5,
            "pa_accuracy": round(pa_correct / total, 3) if total > 0 else 0.5,
            "tag_2b_accuracy": round(tag_2b_correct / total, 3) if total > 0 else 0.5,
            "tag_123_accuracy": round(tag_123_correct / total, 3) if total > 0 else 0.5,
            "volume_accuracy": round(volume_correct / total, 3) if total > 0 else 0.5,
            "n_swing_accuracy": round(n_swing_correct / total, 3) if total > 0 else 0.5,
            "sr_accuracy": round(sr_correct / total, 3) if total > 0 else 0.5,
            "last_update": int(time.time()),
        }
    
    def get_stats(self, symbol: str) -> dict:
        """获取统计数据"""
        return self.data.get("stats", {}).get(symbol, {
            "total": 0,
            "exec_bias_accuracy": 0.5,
            "pa_accuracy": 0.5,
            "tag_2b_accuracy": 0.5,
            "tag_123_accuracy": 0.5,
            "volume_accuracy": 0.5,
            "n_swing_accuracy": 0.5,
            "sr_accuracy": 0.5,
        })


class L2Calibrator:
    """
    v2.930: L2结构分析动态校准器
    
    功能:
        1. 根据历史准确率计算校准因子
        2. 动态调整L2子信号权重
    """
    
    def __init__(self, validator: L2Validator = None, 
                 file_path: str = L2_CALIBRATION_FILE):
        self.validator = validator
        self.file_path = file_path
        self.calibration_data = self._load()
    
    def _load(self) -> dict:
        """加载校准数据"""
        import os
        if not os.path.exists(self.file_path):
            return {}
        try:
            with open(self.file_path, "r") as f:
                return json.load(f)
        except Exception as e:
            print(f"[V2930_L2_CALIBRATOR] 加载失败: {e}")
            return {}
    
    def _save(self):
        """保存校准数据"""
        import os
        os.makedirs(os.path.dirname(self.file_path) if os.path.dirname(self.file_path) else ".", exist_ok=True)
        try:
            with open(self.file_path, "w") as f:
                json.dump(self.calibration_data, f, indent=2)
        except Exception as e:
            print(f"[V2930_L2_CALIBRATOR] 保存失败: {e}")
    
    def _accuracy_to_factor(self, accuracy: float) -> float:
        """准确率转校准因子"""
        for threshold, factor in L2_ACCURACY_TO_FACTOR:
            if accuracy < threshold:
                return factor
        return L2_ACCURACY_TO_FACTOR[-1][1]
    
    def calibrate_weights(self, symbol: str) -> dict:
        """
        计算动态校准后的L2子信号权重
        """
        result = {
            "calibrated": False,
            "sample_count": 0,
            "weights": dict(L2_BASE_WEIGHTS),
            "factors": {},
            "accuracies": {},
            "adjustments": [],
        }
        
        if not self.validator:
            return result
        
        stats = self.validator.get_stats(symbol)
        sample_count = stats.get("total", 0)
        result["sample_count"] = sample_count
        
        # 最小样本保护
        if sample_count < L2_MIN_SAMPLES:
            result["reason"] = f"样本不足({sample_count}<{L2_MIN_SAMPLES})"
            return result
        
        # 获取各子信号准确率
        accuracies = {
            "pa": stats.get("pa_accuracy", 0.5),
            "tag_2b": stats.get("tag_2b_accuracy", 0.5),
            "tag_123": stats.get("tag_123_accuracy", 0.5),
            "volume": stats.get("volume_accuracy", 0.5),
            "n_swing": stats.get("n_swing_accuracy", 0.5),
            "sr": stats.get("sr_accuracy", 0.5),
        }
        result["accuracies"] = accuracies
        
        # 计算校准因子
        factors = {}
        for key, acc in accuracies.items():
            factors[key] = self._accuracy_to_factor(acc)
        result["factors"] = factors
        
        # 计算调整后权重
        weights = {}
        adjustments = []
        for key, base_w in L2_BASE_WEIGHTS.items():
            new_w = base_w * factors[key]
            weights[key] = round(new_w, 2)
            
            # 记录调整
            if factors[key] != 1.0:
                direction = "↑" if factors[key] > 1.0 else "↓"
                adjustments.append(f"{key.upper()}{direction}{factors[key]:.2f}")
        
        result["weights"] = weights
        result["adjustments"] = adjustments
        result["calibrated"] = True
        
        # 保存校准数据
        self.calibration_data[symbol] = {
            "weights": weights,
            "factors": factors,
            "accuracies": accuracies,
            "exec_bias_accuracy": stats.get("exec_bias_accuracy", 0.5),
            "sample_count": sample_count,
            "adjustments": adjustments,
            "last_update": int(time.time()),
        }
        self._save()
        
        print(f"[V2930_L2_CALIBRATOR] {symbol} L2权重校准: {' '.join(adjustments) if adjustments else '无调整'}")
        
        return result
    
    def get_calibration_info(self, symbol: str) -> dict:
        """获取校准信息"""
        return self.calibration_data.get(symbol, {})
    
    def get_all_calibration_info(self) -> dict:
        """获取所有校准信息"""
        return self.calibration_data


# ============================================================================
# v2.930: Phase 7 - P3事后验证系统 (P3 Validator)
# ============================================================================

P3_VALIDATION_FILE = "state/p3_validation.json"
P3_CALIBRATION_FILE = "state/p3_calibration.json"
P3_VALIDATION_BARS_AHEAD = 4  # 4根K线后验证
P3_MIN_SAMPLES_CALIBRATE = 5  # 单组合最小样本数（校准置信度）
P3_MIN_SAMPLES_ACTION = 10    # 单组合最小样本数（动作建议）
P3_MAX_RECORDS = 200  # 每个symbol最多保留200条记录
P3_LOW_ACCURACY_THRESHOLD = 0.40  # 低准确率阈值

# P3动作验证阈值
P3_VALIDATION_RULES = {
    "BUY":  {"direction": "UP",   "threshold": 0.005},  # 涨幅 > 0.5%
    "SELL": {"direction": "DOWN", "threshold": 0.005},  # 跌幅 > 0.5%
    "HOLD": {"direction": "FLAT", "threshold": 0.010},  # |涨跌| < 1%
}


class P3Validator:
    """
    v2.930: P3仲裁矩阵事后验证器
    
    功能:
        1. 记录每次P3仲裁的输入输出
        2. 4根K线后自动验证结果
        3. 追踪25种仲裁组合的准确率
    """
    
    def __init__(self, file_path: str = P3_VALIDATION_FILE):
        self.file_path = file_path
        self.data = self._load()
    
    def _load(self) -> dict:
        """加载验证数据"""
        import os
        if not os.path.exists(self.file_path):
            return {"records": {}, "stats": {}, "matrix_stats": {}}
        try:
            with open(self.file_path, "r") as f:
                return json.load(f)
        except Exception as e:
            print(f"[V2930_P3_VALIDATOR] 加载失败: {e}")
            return {"records": {}, "stats": {}, "matrix_stats": {}}
    
    def _save(self):
        """保存验证数据"""
        import os
        os.makedirs(os.path.dirname(self.file_path) if os.path.dirname(self.file_path) else ".", exist_ok=True)
        try:
            with open(self.file_path, "w") as f:
                json.dump(self.data, f, indent=2)
        except Exception as e:
            print(f"[V2930_P3_VALIDATOR] 保存失败: {e}")
    
    def record_decision(self, symbol: str, price: float, bar_index: int,
                       l1_bias: str, l2_bias: str,
                       matrix_action: str, matrix_confidence: float,
                       agreement: str, l1_wins: bool):
        """
        记录一次P3仲裁决策
        """
        if symbol not in self.data["records"]:
            self.data["records"][symbol] = []
        
        matrix_key = f"{l1_bias}+{l2_bias}"
        
        record = {
            "timestamp": int(time.time()),
            "bar_index": bar_index,
            "price": price,
            # P3输入
            "l1_bias": l1_bias,
            "l2_bias": l2_bias,
            "matrix_key": matrix_key,
            # P3输出
            "matrix_action": matrix_action,
            "matrix_confidence": matrix_confidence,
            "agreement": agreement,
            "l1_wins": l1_wins,
            # 验证字段
            "verify_bar_index": bar_index + P3_VALIDATION_BARS_AHEAD,
            "verified": False,
            "verify_price": 0,
            "price_change_pct": 0,
            # 验证结果
            "action_correct": None,
        }
        
        self.data["records"][symbol].append(record)
        
        # 限制记录数量
        if len(self.data["records"][symbol]) > P3_MAX_RECORDS:
            self.data["records"][symbol] = self.data["records"][symbol][-P3_MAX_RECORDS:]
        
        self._save()
        print(f"[V2930_P3_VALIDATOR] {symbol} 记录P3决策: {matrix_key} → {matrix_action} (conf={matrix_confidence:.2f})")
    
    def verify_pending(self, symbol: str, current_price: float, current_bar_index: int):
        """验证待验证的P3决策"""
        if symbol not in self.data["records"]:
            return
        
        verified_count = 0
        for record in self.data["records"][symbol]:
            if record["verified"]:
                continue
            
            if current_bar_index >= record["verify_bar_index"]:
                # 计算涨跌幅
                entry_price = record["price"]
                if entry_price > 0:
                    change_pct = (current_price - entry_price) / entry_price
                else:
                    change_pct = 0
                
                record["price_change_pct"] = round(change_pct, 6)
                record["verified"] = True
                record["verify_price"] = current_price
                
                # 验证动作是否正确
                record["action_correct"] = self._verify_action(
                    record["matrix_action"], change_pct)
                
                verified_count += 1
                result_str = "✓" if record["action_correct"] else "✗"
                print(f"[V2930_P3_VALIDATOR] {symbol} 验证完成: {record['matrix_key']} → "
                      f"{record['matrix_action']} {result_str} | 涨跌={change_pct:.2%}")
        
        if verified_count > 0:
            self._update_stats(symbol)
            self._save()
    
    def _verify_action(self, action: str, change_pct: float) -> bool:
        """验证动作是否正确"""
        rule = P3_VALIDATION_RULES.get(action, P3_VALIDATION_RULES.get("HOLD"))
        
        if rule["direction"] == "UP":
            return change_pct > rule["threshold"]
        elif rule["direction"] == "DOWN":
            return change_pct < -rule["threshold"]
        else:  # FLAT
            return abs(change_pct) < rule["threshold"]
    
    def _update_stats(self, symbol: str):
        """更新统计数据"""
        if symbol not in self.data["records"]:
            return
        
        verified_records = [r for r in self.data["records"][symbol] if r["verified"]]
        
        if not verified_records:
            return
        
        total = len(verified_records)
        correct = sum(1 for r in verified_records if r.get("action_correct"))
        
        # 总体统计
        self.data["stats"][symbol] = {
            "total": total,
            "correct": correct,
            "accuracy": round(correct / total, 3) if total > 0 else 0.5,
            "last_update": int(time.time()),
        }
        
        # 分组合统计
        if symbol not in self.data["matrix_stats"]:
            self.data["matrix_stats"][symbol] = {}
        
        # 按matrix_key分组
        from collections import defaultdict
        key_records = defaultdict(list)
        for r in verified_records:
            key_records[r["matrix_key"]].append(r)
        
        for matrix_key, records in key_records.items():
            count = len(records)
            key_correct = sum(1 for r in records if r.get("action_correct"))
            accuracy = round(key_correct / count, 3) if count > 0 else 0.5
            
            # 获取原矩阵置信度
            original_conf = records[0].get("matrix_confidence", 0.5) if records else 0.5
            
            self.data["matrix_stats"][symbol][matrix_key] = {
                "count": count,
                "correct": key_correct,
                "accuracy": accuracy,
                "original_confidence": original_conf,
                "action": records[0].get("matrix_action", "HOLD") if records else "HOLD",
            }
    
    def get_stats(self, symbol: str) -> dict:
        """获取统计数据"""
        return self.data.get("stats", {}).get(symbol, {
            "total": 0,
            "correct": 0,
            "accuracy": 0.5,
        })
    
    def get_matrix_stats(self, symbol: str) -> dict:
        """获取矩阵组合统计"""
        return self.data.get("matrix_stats", {}).get(symbol, {})


class P3Calibrator:
    """
    v2.930: P3仲裁矩阵动态校准器
    
    功能:
        1. 根据历史准确率校准置信度
        2. 低准确率组合给出动作建议
    """
    
    def __init__(self, validator: P3Validator = None,
                 file_path: str = P3_CALIBRATION_FILE):
        self.validator = validator
        self.file_path = file_path
        self.calibration_data = self._load()
    
    def _load(self) -> dict:
        """加载校准数据"""
        import os
        if not os.path.exists(self.file_path):
            return {}
        try:
            with open(self.file_path, "r") as f:
                return json.load(f)
        except Exception as e:
            print(f"[V2930_P3_CALIBRATOR] 加载失败: {e}")
            return {}
    
    def _save(self):
        """保存校准数据"""
        import os
        os.makedirs(os.path.dirname(self.file_path) if os.path.dirname(self.file_path) else ".", exist_ok=True)
        try:
            with open(self.file_path, "w") as f:
                json.dump(self.calibration_data, f, indent=2)
        except Exception as e:
            print(f"[V2930_P3_CALIBRATOR] 保存失败: {e}")
    
    def calibrate_matrix(self, symbol: str) -> dict:
        """
        校准整个仲裁矩阵
        
        Returns:
            {
                "calibrated": bool,
                "total_accuracy": float,
                "confidence_adjustments": {...},  # 置信度调整
                "action_suggestions": {...},      # 动作建议
            }
        """
        result = {
            "calibrated": False,
            "sample_count": 0,
            "total_accuracy": 0.5,
            "confidence_adjustments": {},
            "action_suggestions": [],
        }
        
        if not self.validator:
            return result
        
        stats = self.validator.get_stats(symbol)
        matrix_stats = self.validator.get_matrix_stats(symbol)
        
        sample_count = stats.get("total", 0)
        result["sample_count"] = sample_count
        result["total_accuracy"] = stats.get("accuracy", 0.5)
        
        if sample_count < P3_MIN_SAMPLES_CALIBRATE:
            result["reason"] = f"样本不足({sample_count}<{P3_MIN_SAMPLES_CALIBRATE})"
            return result
        
        confidence_adjustments = {}
        action_suggestions = []
        
        for matrix_key, stat in matrix_stats.items():
            count = stat.get("count", 0)
            accuracy = stat.get("accuracy", 0.5)
            original_conf = stat.get("original_confidence", 0.5)
            action = stat.get("action", "HOLD")
            
            # 置信度校准：需要至少5个样本
            if count >= P3_MIN_SAMPLES_CALIBRATE:
                # 置信度 = 70%历史准确率 + 30%原置信度
                calibrated_conf = round(accuracy * 0.7 + original_conf * 0.3, 3)
                
                if abs(calibrated_conf - original_conf) > 0.05:
                    confidence_adjustments[matrix_key] = {
                        "old": original_conf,
                        "new": calibrated_conf,
                        "accuracy": accuracy,
                        "count": count,
                    }
            
            # 动作建议：需要至少10个样本且准确率<40%
            if count >= P3_MIN_SAMPLES_ACTION and accuracy < P3_LOW_ACCURACY_THRESHOLD:
                action_suggestions.append({
                    "matrix_key": matrix_key,
                    "current_action": action,
                    "accuracy": accuracy,
                    "count": count,
                    "suggestion": "建议改为HOLD",
                })
        
        result["confidence_adjustments"] = confidence_adjustments
        result["action_suggestions"] = action_suggestions
        result["calibrated"] = True
        
        # 保存校准数据
        self.calibration_data[symbol] = {
            "total_accuracy": result["total_accuracy"],
            "sample_count": sample_count,
            "confidence_adjustments": confidence_adjustments,
            "action_suggestions": action_suggestions,
            "last_update": int(time.time()),
        }
        self._save()
        
        # 打印警告
        if action_suggestions:
            for sug in action_suggestions:
                print(f"[V2930_P3_CALIBRATOR] ⚠️ {symbol}: {sug['matrix_key']} 准确率仅{sug['accuracy']:.0%}，{sug['suggestion']}")
        
        return result
    
    def get_calibrated_confidence(self, symbol: str, l1_bias: str, l2_bias: str,
                                   original_confidence: float) -> float:
        """获取校准后的置信度"""
        matrix_key = f"{l1_bias}+{l2_bias}"
        
        cal_info = self.calibration_data.get(symbol, {})
        adjustments = cal_info.get("confidence_adjustments", {})
        
        if matrix_key in adjustments:
            return adjustments[matrix_key].get("new", original_confidence)
        
        return original_confidence
    
    def should_change_action(self, symbol: str, l1_bias: str, l2_bias: str) -> dict:
        """检查是否需要改变动作"""
        matrix_key = f"{l1_bias}+{l2_bias}"
        
        cal_info = self.calibration_data.get(symbol, {})
        suggestions = cal_info.get("action_suggestions", [])
        
        for sug in suggestions:
            if sug["matrix_key"] == matrix_key:
                return {
                    "should_change": True,
                    "original_action": sug["current_action"],
                    "suggested_action": "HOLD",
                    "reason": f"准确率{sug['accuracy']:.0%}过低",
                }
        
        return {"should_change": False}
    
    def get_calibration_info(self, symbol: str) -> dict:
        """获取校准信息"""
        return self.calibration_data.get(symbol, {})
    
    def get_all_calibration_info(self) -> dict:
        """获取所有校准信息"""
        return self.calibration_data


