def signal_to_value_v2900(signal: str) -> int:
    """v2.900: 5级信号转数值"""
    return SIGNAL_VALUES_V2900.get(signal, 0)


def value_to_signal_v2900(value: float) -> str:
    """v2.900: 数值转5级信号"""
    if value >= 1.5:
        return "STRONG_BUY"
    elif value >= 0.5:
        return "BUY"
    elif value <= -1.5:
        return "STRONG_SELL"
    elif value <= -0.5:
        return "SELL"
    else:
        return "HOLD"


def is_buy_side_v2900(signal: str) -> bool:
    """v2.900: 是否为买方信号"""
    return signal in ("STRONG_BUY", "BUY")


def is_sell_side_v2900(signal: str) -> bool:
    """v2.900: 是否为卖方信号"""
    return signal in ("STRONG_SELL", "SELL")


def detect_direction_conflict_v2900(signals: list) -> bool:
    """
    v2.900: 检测方向冲突

    BUY系(STRONG_BUY/BUY) vs SELL系(STRONG_SELL/SELL) = 冲突
    """
    buy_side = [s for s in signals if is_buy_side_v2900(s)]
    sell_side = [s for s in signals if is_sell_side_v2900(s)]
    return len(buy_side) > 0 and len(sell_side) > 0


# v2.999 P2: 增强版DeepSeek触发检测
# v3.260: 增加道氏理论分歧触发
def should_trigger_deepseek_arbiter_v2999(
    signals: list,
    confidences: list,
    dow_trend: str = None,  # v3.260: 道氏理论趋势判断
) -> dict:
    """
    v2.999 P2: 增强版DeepSeek仲裁触发检测
    v3.260: 增加道氏理论分歧触发

    触发条件:
        1. 方向冲突: BUY vs SELL
        2. 置信度分歧: 最高与最低置信度差距>0.4
        3. 高置信度HOLD: HOLD信号置信度>0.7且其他方有明确方向
        4. v3.260道氏分歧: 道氏理论确认趋势，但其他模块HOLD

    Args:
        signals: 三方信号列表
        confidences: 三方置信度列表
        dow_trend: 道氏理论趋势判断 ("up"/"down"/"side"/None)

    Returns:
        {
            "should_trigger": bool,
            "trigger_reason": str,
            "priority": int,  # 1-3, 1最高
        }
    """
    result = {
        "should_trigger": False,
        "trigger_reason": "",
        "priority": 3,
    }

    # 条件1: 方向冲突 (最高优先级)
    if detect_direction_conflict_v2900(signals):
        result["should_trigger"] = True
        result["trigger_reason"] = "DIRECTION_CONFLICT"
        result["priority"] = 1
        return result

    # 条件2: 置信度分歧
    conf_max = max(confidences) if confidences else 0.5
    conf_min = min(confidences) if confidences else 0.5
    conf_spread = conf_max - conf_min

    if conf_spread > 0.4:
        result["should_trigger"] = True
        result["trigger_reason"] = f"CONFIDENCE_DIVERGENCE:{conf_spread:.2f}"
        result["priority"] = 2
        print(f"[v2.999] DeepSeek触发: 置信度分歧 (spread={conf_spread:.2f})")
        return result

    # 条件3: 高置信度HOLD与其他方向冲突
    hold_indices = [i for i, s in enumerate(signals) if s == "HOLD"]
    non_hold_indices = [i for i, s in enumerate(signals) if s != "HOLD"]

    if hold_indices and non_hold_indices:
        # 检查是否有高置信度HOLD
        high_conf_hold = any(confidences[i] >= 0.7 for i in hold_indices)
        # 检查非HOLD方是否有明确方向
        non_hold_has_direction = any(
            signals[i] in ["BUY", "STRONG_BUY", "SELL", "STRONG_SELL"]
            for i in non_hold_indices
        )

        if high_conf_hold and non_hold_has_direction:
            result["should_trigger"] = True
            result["trigger_reason"] = "HIGH_CONF_HOLD_CONFLICT"
            result["priority"] = 2
            print(f"[v2.999] DeepSeek触发: 高置信度HOLD与其他方向冲突")
            return result

    # ═══════════════════════════════════════════════════════════════════════
    # 条件4: v3.260 道氏理论分歧触发
    # 当道氏理论确认趋势(up/down)，但有模块判断HOLD时，触发仲裁
    # 道氏理论是最可靠的趋势判断，不应被HOLD稀释
    # ═══════════════════════════════════════════════════════════════════════
    if dow_trend and dow_trend in ("up", "down"):
        # 检查是否有HOLD信号
        has_hold = "HOLD" in signals
        if has_hold:
            # 道氏理论确认趋势，但有模块观望 → 触发仲裁
            result["should_trigger"] = True
            result["trigger_reason"] = f"DOW_TREND_DIVERGENCE:{dow_trend.upper()}"
            result["priority"] = 2
            print(f"[v3.260] DeepSeek触发: 道氏理论={dow_trend.upper()}，但有模块HOLD，需仲裁")
            return result

    return result


def determine_consensus_type_v2900(signals: list) -> str:
    """
    v2.900: 判断共识类型

    Returns:
        THREE_AGREE: 三方完全一致
        TWO_AGREE: 两方一致
        THREE_SPLIT: 三方分裂
        CONFLICT: 方向冲突
    """
    if detect_direction_conflict_v2900(signals):
        return "CONFLICT"

    unique_signals = set(signals)
    if len(unique_signals) == 1:
        return "THREE_AGREE"
    elif len(unique_signals) == 2:
        return "TWO_AGREE"
    else:
        return "THREE_SPLIT"


# v2.999 P1-3: 增强版共识判定（含置信度差异）
def determine_consensus_type_enhanced_v2999(
    signals: list,
    confidences: list,
) -> dict:
    """
    v2.999 P1-3: 增强版共识判定，考虑置信度差异

    Args:
        signals: 三方信号列表 [ai_signal, human_signal, tech_signal]
        confidences: 三方置信度列表 [ai_conf, human_conf, tech_conf]

    Returns:
        {
            "consensus_type": str,      # 基础共识类型
            "enhanced_type": str,       # 增强共识类型
            "confidence_spread": float, # 置信度差距 (max - min)
            "avg_confidence": float,    # 平均置信度
            "quality": str,             # HIGH/MEDIUM/LOW
            "adjustment": float,        # 建议的置信度调整
        }
    """
    # 基础共识判定
    base_type = determine_consensus_type_v2900(signals)

    # 计算置信度统计
    conf_max = max(confidences) if confidences else 0.5
    conf_min = min(confidences) if confidences else 0.5
    conf_avg = sum(confidences) / len(confidences) if confidences else 0.5
    conf_spread = conf_max - conf_min

    result = {
        "consensus_type": base_type,
        "enhanced_type": base_type,
        "confidence_spread": conf_spread,
        "avg_confidence": conf_avg,
        "quality": "MEDIUM",
        "adjustment": 0.0,
    }

    # 根据置信度差异增强共识类型
    if base_type == "THREE_AGREE":
        if conf_spread < 0.15 and conf_avg >= 0.7:
            # 三方一致且置信度都高且接近
            result["enhanced_type"] = "THREE_AGREE_STRONG"
            result["quality"] = "HIGH"
            result["adjustment"] = 0.1
        elif conf_spread > 0.3:
            # 三方一致但置信度差异大
            result["enhanced_type"] = "THREE_AGREE_DIVERGENT"
            result["quality"] = "MEDIUM"
            result["adjustment"] = -0.05
        elif conf_avg < 0.5:
            # 三方一致但整体置信度低
            result["enhanced_type"] = "THREE_AGREE_WEAK"
            result["quality"] = "LOW"
            result["adjustment"] = -0.1

    elif base_type == "TWO_AGREE":
        # 找出多数方的置信度
        from collections import Counter
        signal_counts = Counter(signals)
        majority_signal = signal_counts.most_common(1)[0][0]
        majority_confs = [c for s, c in zip(signals, confidences) if s == majority_signal]
        minority_conf = [c for s, c in zip(signals, confidences) if s != majority_signal][0] if len(signals) == 3 else 0.5

        majority_avg = sum(majority_confs) / len(majority_confs) if majority_confs else 0.5

        if majority_avg >= 0.7 and minority_conf < 0.4:
            # 多数方高置信度，少数方低置信度
            result["enhanced_type"] = "TWO_AGREE_STRONG"
            result["quality"] = "HIGH"
            result["adjustment"] = 0.08
        elif majority_avg < 0.5:
            # 多数方置信度低
            result["enhanced_type"] = "TWO_AGREE_WEAK"
            result["quality"] = "LOW"
            result["adjustment"] = -0.08
        elif minority_conf > 0.7:
            # 少数方置信度高（值得注意）
            result["enhanced_type"] = "TWO_AGREE_CONTESTED"
            result["quality"] = "MEDIUM"
            result["adjustment"] = -0.03

    elif base_type == "THREE_SPLIT":
        if conf_avg < 0.5:
            result["enhanced_type"] = "THREE_SPLIT_UNCERTAIN"
            result["quality"] = "LOW"
            result["adjustment"] = -0.1

    elif base_type == "CONFLICT":
        if conf_spread > 0.4:
            # 冲突时置信度差异大，可能有一方更可信
            result["enhanced_type"] = "CONFLICT_ASYMMETRIC"
            result["quality"] = "LOW"
        else:
            result["enhanced_type"] = "CONFLICT_SYMMETRIC"
            result["quality"] = "LOW"
            result["adjustment"] = -0.15

    if result["enhanced_type"] != base_type:
        print(f"[v2.999] 增强共识: {base_type} → {result['enhanced_type']} "
              f"(spread={conf_spread:.2f}, avg={conf_avg:.2f}, quality={result['quality']})")

    return result


# v2.999 P1-1: LLM理由语义分析
def analyze_llm_reason_semantics_v2999(reason_text: str) -> dict:
    """
    v2.999 P1-1: 从LLM reason文本提取语义信号

    通过关键词匹配分析LLM理由中的多空情绪和置信度指示

    Args:
        reason_text: LLM返回的reason文本

    Returns:
        {
            "bullish_score": int,     # 多头关键词得分
            "bearish_score": int,     # 空头关键词得分
            "confidence_hint": float, # 置信度提示 (-0.2 ~ +0.2)
            "sentiment": str,         # BULLISH/BEARISH/NEUTRAL
            "keywords_found": list,   # 匹配到的关键词
        }
    """
    result = {
        "bullish_score": 0,
        "bearish_score": 0,
        "confidence_hint": 0.0,
        "sentiment": "NEUTRAL",
        "keywords_found": [],
    }

    if not reason_text:
        return result

    text = reason_text.lower()

    # 多头关键词 (中英文)
    bullish_keywords = {
        # 强多头 (+2)
        "strong_bull": ["突破", "强势", "爆发", "暴涨", "飙升", "breakout", "strong buy",
                        "强力买入", "大涨", "起飞", "底部确认"],
        # 普通多头 (+1)
        "bull": ["看涨", "上涨", "买入", "多头", "反弹", "回升", "向上",
                 "buy", "bullish", "uptrend", "底部", "支撑", "企稳", "回暖"],
    }

    # 空头关键词
    bearish_keywords = {
        # 强空头 (+2)
        "strong_bear": ["崩盘", "暴跌", "跳水", "breakdown", "strong sell",
                        "强力卖出", "大跌", "崩溃", "顶部确认"],
        # 普通空头 (+1)
        "bear": ["看跌", "下跌", "卖出", "空头", "回调", "下探", "向下",
                 "sell", "bearish", "downtrend", "顶部", "阻力", "承压", "疲软"],
    }

    # 置信度提示词
    high_confidence_words = ["确定", "明确", "强烈", "肯定", "显著", "definitely", "certainly", "strong"]
    low_confidence_words = ["可能", "也许", "不确定", "观望", "谨慎", "maybe", "perhaps", "uncertain", "careful"]

    # 计算多头得分
    for keyword in bullish_keywords["strong_bull"]:
        if keyword in text:
            result["bullish_score"] += 2
            result["keywords_found"].append(f"+2:{keyword}")

    for keyword in bullish_keywords["bull"]:
        if keyword in text:
            result["bullish_score"] += 1
            result["keywords_found"].append(f"+1:{keyword}")

    # 计算空头得分
    for keyword in bearish_keywords["strong_bear"]:
        if keyword in text:
            result["bearish_score"] += 2
            result["keywords_found"].append(f"-2:{keyword}")

    for keyword in bearish_keywords["bear"]:
        if keyword in text:
            result["bearish_score"] += 1
            result["keywords_found"].append(f"-1:{keyword}")

    # 计算置信度提示
    for word in high_confidence_words:
        if word in text:
            result["confidence_hint"] += 0.05
    for word in low_confidence_words:
        if word in text:
            result["confidence_hint"] -= 0.05

    # 限制范围
    result["confidence_hint"] = max(-0.2, min(0.2, result["confidence_hint"]))

    # 确定情绪
    bull_score = result["bullish_score"]
    bear_score = result["bearish_score"]
    if bull_score > bear_score + 1:
        result["sentiment"] = "BULLISH"
    elif bear_score > bull_score + 1:
        result["sentiment"] = "BEARISH"
    else:
        result["sentiment"] = "NEUTRAL"

    if result["keywords_found"]:
        print(f"[v2.999] LLM理由语义: {result['sentiment']} "
              f"(bull={bull_score}, bear={bear_score}, conf_hint={result['confidence_hint']:+.2f})")

    return result


def compute_ai_signals_v2900(llm_result: dict, reason_bullets: list = None) -> dict:
    """
    v2.900: 从LLM结果提取AI视角5个信号
    
    信号来源:
        1. Trend120: 120根K线趋势 (UP/DOWN/SIDE)
        2. SwingFeel: Swing感觉 (PUSHING_UP/PUSHING_DOWN/CONSOLIDATING)
        3. CandleNow: 当前K线 (STRONG_BULL/BULL/DOJI/BEAR/STRONG_BEAR)
        4. Instinct: 直觉 (BUY/SELL/HOLD)
        5. AISignal: 最终AI信号 (5级)
    
    Returns:
        {
            "trend120": str,
            "swing_feel": str,
            "candle_now": str,
            "instinct": str,
            "ai_signal": str,  # 5级信号
            "confidence": float,
            "reason": str,
        }
    """
    result = {
        "x4_regime": "UNKNOWN",      # v3.302: 大周期趋势/震荡 (LLM判断)
        "current_regime": "UNKNOWN", # v3.302: 当前周期趋势/震荡 (LLM判断)
        "trend120": "UNKNOWN",
        "swing_feel": "UNKNOWN",
        "candle_now": "UNKNOWN",
        "instinct": "HOLD",
        "ai_signal": "HOLD",
        "confidence": 0.5,
        "reason": "",
    }

    # 从reason_bullets解析REAL_FIRST_REACTION
    found_reaction = False
    # v3.320: 调试输出 (改用log_to_server确保写入server.log)
    reason_text = llm_result.get('reason', '') if isinstance(llm_result, dict) else ''
    has_rfr_in_reason = "REAL_FIRST_REACTION" in str(reason_text)
    log_to_server(f"[v3.320] AI解析: bullets={len(reason_bullets) if reason_bullets else 0}, reason含RFR={has_rfr_in_reason}, llm_result.keys={list(llm_result.keys()) if isinstance(llm_result, dict) else 'N/A'}")
    if reason_bullets:
        for bullet in reason_bullets:
            if "REAL_FIRST_REACTION" in str(bullet):
                parsed = parse_real_first_reaction_v2900(str(bullet))
                result["x4_regime"] = parsed.get("x4_regime", "UNKNOWN")
                result["current_regime"] = parsed.get("current_regime", "UNKNOWN")
                result["trend120"] = parsed.get("trend120", "UNKNOWN")
                result["swing_feel"] = parsed.get("swing_feel", "UNKNOWN")
                result["candle_now"] = parsed.get("candle_now", "UNKNOWN")
                result["instinct"] = parsed.get("instinct", "HOLD")
                result["reason"] = parsed.get("why", "")
                found_reaction = True
                log_to_server(f"[v3.340] 从reason_bullets解析: x4_regime={result['x4_regime']}")
                break

    # v3.301: 如果reason_bullets没找到，也检查reason字段
    # v3.320修复: reason可能在顶层或嵌套在decision里
    if not found_reaction:
        reason_text_raw = llm_result.get("reason", "")
        # v3.320: 如果顶层没有，检查嵌套的decision.reason
        if not reason_text_raw and isinstance(llm_result.get("decision"), dict):
            reason_text_raw = llm_result["decision"].get("reason", "")
        # v3.320: 调试输出
        if "REAL_FIRST_REACTION" in str(reason_text_raw):
            parsed = parse_real_first_reaction_v2900(str(reason_text_raw))
            result["x4_regime"] = parsed.get("x4_regime", "UNKNOWN")
            result["current_regime"] = parsed.get("current_regime", "UNKNOWN")
            result["trend120"] = parsed.get("trend120", "UNKNOWN")
            result["swing_feel"] = parsed.get("swing_feel", "UNKNOWN")
            result["candle_now"] = parsed.get("candle_now", "UNKNOWN")
            result["instinct"] = parsed.get("instinct", "HOLD")
            result["reason"] = parsed.get("why", "")
            found_reaction = True
            log_to_server(f"[v3.340] AI信号解析: x4_regime={result['x4_regime']}, current_regime={result['current_regime']}")
        else:
            pass  # fallback: 使用llm_result["action"]直接提取，无需告警

    # 从LLM结果获取置信度
    result["confidence"] = float(llm_result.get("confidence", 0.5))

    # v2.999 P1-1: 分析LLM理由语义
    reason_text = result.get("reason", "") or llm_result.get("reason", "")
    semantic_analysis = analyze_llm_reason_semantics_v2999(reason_text)
    result["reason_semantics"] = semantic_analysis

    # 获取原始动作
    raw_action = llm_result.get("action", "HOLD")
    if raw_action == "BUY":
        result["instinct"] = "BUY"
    elif raw_action == "SELL":
        result["instinct"] = "SELL"
    else:
        # v2.996/v2.999新增：当action=HOLD时，从factors+语义推断倾向性
        bullish_factors = 0
        bearish_factors = 0

        # trend120因素
        if result["trend120"] == "UP":
            bullish_factors += 2
        elif result["trend120"] == "DOWN":
            bearish_factors += 2

        # swing_feel因素
        if result["swing_feel"] == "PUSHING_UP":
            bullish_factors += 1
        elif result["swing_feel"] == "PUSHING_DOWN":
            bearish_factors += 1

        # candle_now因素
        if result["candle_now"] in ("STRONG_BULL", "BULL", "ENGULF_BULL", "BREAKOUT_BAR"):
            bullish_factors += 1
        elif result["candle_now"] in ("STRONG_BEAR", "BEAR", "ENGULF_BEAR", "BREAKDOWN_BAR"):
            bearish_factors += 1

        # v2.999 P1-1: 语义分析因素
        bullish_factors += semantic_analysis["bullish_score"]
        bearish_factors += semantic_analysis["bearish_score"]

        # 根据因素差异决定倾向
        if bullish_factors > bearish_factors + 1:
            result["instinct"] = "BUY"  # 偏多
            print(f"[v2.999] AI instinct推断: HOLD→BUY (bullish={bullish_factors}, bearish={bearish_factors}, semantic={semantic_analysis['sentiment']})")
        elif bearish_factors > bullish_factors + 1:
            result["instinct"] = "SELL"  # 偏空
            print(f"[v2.999] AI instinct推断: HOLD→SELL (bullish={bullish_factors}, bearish={bearish_factors}, semantic={semantic_analysis['sentiment']})")
        # 否则保持HOLD

    # v2.999 P1-1: 语义置信度调整
    if semantic_analysis["confidence_hint"] != 0:
        result["confidence"] = max(0.1, min(0.95, result["confidence"] + semantic_analysis["confidence_hint"]))
        print(f"[v2.999] 置信度语义调整: {semantic_analysis['confidence_hint']:+.2f} → {result['confidence']:.2f}")

    # 计算AI 5级信号
    result["ai_signal"] = determine_ai_signal_level_v2900(result)

    return result


def parse_real_first_reaction_v2900(text: str) -> dict:
    """
    v2.900: 解析REAL_FIRST_REACTION字符串
    
    v3.302格式: REAL_FIRST_REACTION: X4Regime=TREND_UP, CurrentRegime=RANGING, CandleNow=DOJI, Instinct=HOLD, Why=xxx
    兼容旧格式: Trend120=UP, SwingFeel=PUSHING_UP, ...
    """
    result = {
        "x4_regime": "UNKNOWN",      # v3.302: 大周期趋势/震荡
        "current_regime": "UNKNOWN", # v3.302: 当前周期趋势/震荡
        "trend120": "UNKNOWN",       # 兼容旧格式
        "swing_feel": "UNKNOWN",
        "candle_now": "UNKNOWN",
        "instinct": "HOLD",
        "why": "",
    }

    if not text or "REAL_FIRST_REACTION" not in text:
        return result

    try:
        # 移除前缀
        content = text.replace("REAL_FIRST_REACTION:", "").strip()

        # 解析键值对
        for part in content.split(","):
            part = part.strip()
            if "=" in part:
                key, value = part.split("=", 1)
                key = key.strip().lower()
                value = value.strip()

                # v3.302: 新格式
                if key == "x4regime":
                    result["x4_regime"] = value.upper()
                elif key == "currentregime":
                    result["current_regime"] = value.upper()
                # 兼容旧格式
                elif key == "trend120":
                    result["trend120"] = value.upper()
                    # v3.320: 旧格式Trend120映射到x4_regime
                    trend_val = value.upper()
                    if trend_val in ("UP", "UPTREND"):
                        result["x4_regime"] = "TREND_UP"
                    elif trend_val in ("DOWN", "DOWNTREND"):
                        result["x4_regime"] = "TREND_DOWN"
                    elif trend_val in ("RANGE", "RANGING", "SIDE", "SIDEWAYS"):
                        result["x4_regime"] = "RANGING"
                elif key == "swingfeel":
                    result["swing_feel"] = value.upper()
                elif key == "candlenow":
                    result["candle_now"] = value.upper()
                elif key == "instinct":
                    result["instinct"] = value.upper()
                elif key == "why":
                    result["why"] = value
    except Exception as e:
        print(f"[v3.302] parse_real_first_reaction error: {e}")

    return result


def determine_ai_signal_level_v2900(signals: dict) -> str:
    """
    v2.998: 根据AI信号确定5级信号（LLM置信度加权版）

    v2.998改进：LLM置信度直接影响信号强度
    - 置信度>=0.8: 信号可升级为STRONG
    - 置信度>=0.6: 正常信号
    - 置信度<0.6: 信号降级或变为HOLD

    v2.996改进：当instinct=HOLD时，分析因素输出WEAK_BUY/WEAK_SELL
    """
    instinct = signals.get("instinct", "HOLD")
    llm_confidence = signals.get("confidence", 0.5)

    # v2.998: LLM置信度直接影响信号强度
    # 高置信度(>=0.8)给额外加分
    # 低置信度(<0.5)会降级信号
    confidence_bonus = 0
    if llm_confidence >= 0.8:
        confidence_bonus = 2  # 高置信度额外加2分
    elif llm_confidence >= 0.7:
        confidence_bonus = 1  # 较高置信度额外加1分
    elif llm_confidence < 0.5:
        confidence_bonus = -1  # 低置信度扣1分

    if instinct == "BUY":
        # 检查强买因素
        strong_factors = confidence_bonus  # v2.998: 从LLM置信度开始计分
        if signals.get("trend120") == "UP":
            strong_factors += 1
        if signals.get("swing_feel") == "PUSHING_UP":
            strong_factors += 1
        if signals.get("candle_now") in ("STRONG_BULL", "ENGULF_BULL", "BREAKOUT_BAR", "ENGULF"):
            strong_factors += 1

        # v3.340: 低置信度(<0.5)降级为BUY (原WEAK_BUY)
        if llm_confidence < 0.5:
            print(f"[v3.340] AI信号降级: STRONG_BUY→BUY (LLM conf={llm_confidence:.0%})")
            return "BUY"

        if strong_factors >= 3:
            print(f"[v2.998] AI信号: STRONG_BUY (factors={strong_factors}, LLM conf={llm_confidence:.0%})")
            return "STRONG_BUY"
        return "BUY"

    elif instinct == "SELL":
        # 检查强卖因素
        strong_factors = confidence_bonus  # v2.998: 从LLM置信度开始计分
        if signals.get("trend120") == "DOWN":
            strong_factors += 1
        if signals.get("swing_feel") == "PUSHING_DOWN":
            strong_factors += 1
        if signals.get("candle_now") in ("STRONG_BEAR", "ENGULF_BEAR", "BREAKDOWN_BAR"):
            strong_factors += 1

        # v3.340: 低置信度(<0.5)降级为SELL (原WEAK_SELL)
        if llm_confidence < 0.5:
            print(f"[v3.340] AI信号降级: STRONG_SELL→SELL (LLM conf={llm_confidence:.0%})")
            return "SELL"

        if strong_factors >= 3:
            print(f"[v2.998] AI信号: STRONG_SELL (factors={strong_factors}, LLM conf={llm_confidence:.0%})")
            return "STRONG_SELL"
        return "SELL"

    # v2.996新增：instinct=HOLD时，分析倾向性
    else:
        bullish_factors = 0
        bearish_factors = 0

        if signals.get("trend120") == "UP":
            bullish_factors += 1
        elif signals.get("trend120") == "DOWN":
            bearish_factors += 1

        if signals.get("swing_feel") == "PUSHING_UP":
            bullish_factors += 1
        elif signals.get("swing_feel") == "PUSHING_DOWN":
            bearish_factors += 1

        if signals.get("candle_now") in ("STRONG_BULL", "BULL", "ENGULF_BULL"):
            bullish_factors += 1
        elif signals.get("candle_now") in ("STRONG_BEAR", "BEAR", "ENGULF_BEAR"):
            bearish_factors += 1

        # v3.340: LLM置信度影响HOLD的判定 (统一格式)
        # 如果LLM置信度很高(>=0.7)但给了HOLD，可能是真的没有明确方向
        # 如果置信度低(<0.5)，更应该保持HOLD
        if llm_confidence >= 0.7:
            # 高置信度HOLD，但有明显因素倾向时输出BUY/SELL (原WEAK_BUY/WEAK_SELL)
            if bullish_factors >= 2 and bullish_factors > bearish_factors:
                return "BUY"
            elif bearish_factors >= 2 and bearish_factors > bullish_factors:
                return "SELL"
        elif llm_confidence < 0.5:
            # 低置信度，直接HOLD
            return "HOLD"

        # 偏向判断：需要至少2个因素差异
        if bullish_factors >= 2 and bullish_factors > bearish_factors:
            return "BUY"  # v3.340: WEAK_BUY → BUY
        elif bearish_factors >= 2 and bearish_factors > bullish_factors:
            return "SELL"  # v3.340: WEAK_SELL → SELL

        return "HOLD"


def compute_human_signals_v2900(ohlcv_bars: list, pos_ratio: float = 0.5,
                                 trend_x4: str = None, trend_x8: str = None,
                                 symbol: str = None,
                                 dow_trend_details: dict = None) -> dict:  # v3.270: 道氏理论判断
    """
    v2.993: 计算Human视觉视角5个信号 (增强版 + 双轨模式)

    v3.270改进: 道氏理论替代visual_slope
    - 如果有道氏理论结果，使用道氏理论的趋势判断
    - 道氏理论: HH+HL=UP, LH+LL=DOWN, 其他=SIDE

    v2.993改进: L1 Regime Enhancement
    - 多周期斜率融合 (10/20/30/60周期)
    - 趋势结构确认 (HH/HL/LL/LH)
    - 一致性检测增强信号

    v2.960改进: 规则+CNN双轨融合
    - Part1: 大趋势判断 (visual_slope等) 100%保留，用于趋势投票
    - Part2: 信号计算使用规则+CNN双轨融合
    - Part3: 校准器追踪各自准确率，动态调整权重

    信号定义:
        1. VisualSlope: 视觉斜率 (STEEP_UP/UP/FLAT/DOWN/STEEP_DOWN) - 保留用于趋势投票
        2. RecentImpact: 最近K线冲击 (STRONG_BULL/REVERSAL_BULL/MIXED/REVERSAL_BEAR/STRONG_BEAR)
        3. VolumeFeel: 量能感觉 (CLIMAX/EXPANDING/NORMAL/SHRINKING)
        4. PositionFeel: 位置感觉 (LOW/MID/HIGH)
        5. HumanSignal: 最终Human信号 (5级) - 双轨融合结果

    Args:
        ohlcv_bars: K线数据
        pos_ratio: 位置比率
        trend_x4: 4倍周期趋势 (up/down/side)
        trend_x8: 8倍周期趋势 (up/down/side)
        symbol: 品种代码 (v2.960新增，用于校准)

    Returns:
        {
            "visual_slope": str,      # Part1: 大趋势判断 (保留)
            "recent_impact": str,
            "volume_feel": str,
            "position_feel": str,
            "human_signal": str,      # Part2: 融合信号
            "confidence": float,
            "reason": str,
            "big_small_pattern": str,
            "model_used": bool,
            "probabilities": dict,
            # v2.960新增
            "rule_signal": str,       # 规则信号
            "cnn_signal": str,        # CNN信号
            "rule_weight": float,     # 规则权重
            "cnn_weight": float,      # CNN权重
            "dual_track_mode": bool,  # 是否双轨模式
            # v2.993新增
            "enhancement_used": bool,  # 是否使用增强版
            "multi_slope": dict,       # 多周期斜率详情
            "structure": dict,         # 趋势结构分析
            "regime_vote": str,        # TRENDING / RANGING
            "regime_direction": str,   # UP / DOWN / SIDE
            "regime_confidence": float,
        }
    """
    # ========== v2.993: 尝试使用增强版 ==========
    if USE_L1_ENHANCEMENT and L1_ENHANCEMENT_LOADED:
        try:
            enhanced = compute_human_signals_enhanced(
                ohlcv_bars=ohlcv_bars,
                pos_ratio=pos_ratio,
                trend_x4=trend_x4,
                symbol=symbol,
            )
            # 添加兼容字段
            enhanced["trend_x4"] = trend_x4
            enhanced["trend_x8"] = trend_x8
            enhanced["big_small_pattern"] = enhanced.get("big_small_pattern", "NONE")
            enhanced["model_used"] = False  # 增强版不使用CNN
            enhanced["probabilities"] = {}
            enhanced["rule_signal"] = enhanced.get("human_signal", "HOLD")
            enhanced["rule_confidence"] = enhanced.get("confidence", 0.5)
            enhanced["cnn_signal"] = "HOLD"
            enhanced["cnn_confidence"] = 0.5
            enhanced["rule_weight"] = 1.0
            enhanced["cnn_weight"] = 0.0
            enhanced["dual_track_mode"] = False

            # 日志
            print(f"[v2.993] Human增强: slope={enhanced.get('visual_slope')}, "
                  f"regime={enhanced.get('regime_vote')}/{enhanced.get('regime_direction')}, "
                  f"conf={enhanced.get('regime_confidence', 0):.0%}, "
                  f"consistency={enhanced.get('multi_slope', {}).get('consistency', 0):.0%}")

            return enhanced
        except Exception as e:
            # v2.994: 增强异常日志，便于调试
            import traceback
            print(f"[v2.994] Human增强异常，回退原版+CNN: {e}")
            print(f"[v2.994] 异常详情:")
            print(f"  - ohlcv_bars: {len(ohlcv_bars) if ohlcv_bars else 0}根")
            print(f"  - pos_ratio: {pos_ratio}")
            print(f"  - trend_x4: {trend_x4}")
            print(f"  - symbol: {symbol}")
            if ohlcv_bars and len(ohlcv_bars) > 0:
                last_bar = ohlcv_bars[-1]
                print(f"  - 最后一根K线: O={last_bar.get('open', 'N/A')}, H={last_bar.get('high', 'N/A')}, L={last_bar.get('low', 'N/A')}, C={last_bar.get('close', 'N/A')}")
            traceback.print_exc()
    # ========== v2.993 END ==========

    result = {
        "visual_slope": "FLAT",
        "recent_impact": "MIXED",
        "volume_feel": "NORMAL",
        "position_feel": "MID",
        "human_signal": "HOLD",
        "confidence": 0.5,
        "reason": "",
        "big_small_pattern": "NONE",
        "trend_x4": trend_x4,
        "trend_x8": trend_x8,
        "model_used": False,
        "probabilities": {},
        # v2.960新增
        "rule_signal": "HOLD",
        "rule_confidence": 0.5,
        "cnn_signal": "HOLD",
        "cnn_confidence": 0.5,
        "rule_weight": HUMAN_DEFAULT_RULE_WEIGHT,
        "cnn_weight": HUMAN_DEFAULT_CNN_WEIGHT,
        "dual_track_mode": False,
        # v2.993新增
        "enhancement_used": False,
        "multi_slope": {},
        "structure": {},
        "regime_vote": "RANGING",
        "regime_direction": "SIDE",
        "regime_confidence": 0.5,
    }

    if not ohlcv_bars or len(ohlcv_bars) < 5:
        return result

    # ========== Part 1: 大趋势判断 (100%保留，用于趋势投票) ==========
    # 这些特征必须计算，因为get_human_regime_vote()依赖visual_slope

    # v3.270: 优先使用道氏理论判断趋势，回退到传统visual_slope
    if dow_trend_details and dow_trend_details.get("trend_mid"):
        # 道氏理论结果: up/down/side
        dow_trend_mid = dow_trend_details.get("trend_mid", "side")
        dow_trend_x4 = dow_trend_details.get("trend_x4", "side")
        dow_trend_x8 = dow_trend_details.get("trend_x8", "side")
        dow_consensus = dow_trend_details.get("consensus", "side")

        # 转换道氏理论趋势为visual_slope格式
        # 如果多周期一致，使用STEEP_UP/STEEP_DOWN强化信号
        if dow_trend_mid == "up":
            if dow_trend_x4 == "up" and dow_trend_x8 == "up":
                slope_category = "STEEP_UP"  # 三周期一致上涨
            else:
                slope_category = "UP"
        elif dow_trend_mid == "down":
            if dow_trend_x4 == "down" and dow_trend_x8 == "down":
                slope_category = "STEEP_DOWN"  # 三周期一致下跌
            else:
                slope_category = "DOWN"
        else:
            slope_category = "FLAT"  # side → FLAT

        result["visual_slope"] = slope_category
        result["dow_theory_used"] = True  # v3.270: 标记使用道氏理论
        result["dow_trend_mid"] = dow_trend_mid
        result["dow_consensus"] = dow_consensus
        log_to_server(f"[v3.270 DOW→Human] 道氏理论趋势: mid={dow_trend_mid}, x4={dow_trend_x4}, x8={dow_trend_x8} → visual_slope={slope_category}")
    else:
        # 回退: 使用传统visual_slope计算
        slope_value, slope_category = compute_visual_slope_v2900(ohlcv_bars)
        result["visual_slope"] = slope_category
        result["dow_theory_used"] = False
        log_to_server(f"[v3.270] Human使用传统visual_slope: {slope_category} (无道氏理论数据)")
    
    # 2. 评估最近K线冲击
    result["recent_impact"] = assess_recent_candles_v2900(ohlcv_bars[-5:])
    
    # 3. 评估量能感受
    result["volume_feel"] = assess_volume_visually_v2900(ohlcv_bars)
    
    # 4. 位置感受
    if pos_ratio < 0.25:
        result["position_feel"] = "LOW"
    elif pos_ratio > 0.75:
        result["position_feel"] = "HIGH"
    else:
        result["position_feel"] = "MID"

    # ========== v3.010: Human Knowledge Rules ==========
    knowledge_rules_result = None
    if USE_HUMAN_KNOWLEDGE_RULES and HUMAN_KNOWLEDGE_RULES_LOADED:
        try:
            # 计算当前K线索引 (简化版，实际应该从外部传入)
            bar_index = len(ohlcv_bars)

            knowledge_rules_result = analyze_human_knowledge_rules(
                ohlcv_bars=ohlcv_bars,
                symbol=symbol,
                bar_index=bar_index
            )

            # 添加到result供下游使用
            result["knowledge_rules"] = knowledge_rules_result
            result["knowledge_signals"] = knowledge_rules_result.get("signals", [])
            result["knowledge_warnings"] = knowledge_rules_result.get("warnings", [])

            # 日志输出
            if knowledge_rules_result.get("signals"):
                print(f"[v3.010] Human知识点触发: {knowledge_rules_result['signals']}")
            if knowledge_rules_result.get("warnings"):
                for warn in knowledge_rules_result["warnings"]:
                    print(f"[v3.010] ⚠️ {warn}")

        except Exception as e:
            print(f"[v3.010] Human Knowledge Rules异常: {e}")
            knowledge_rules_result = None

    # ========== Part 2: 信号计算 (双轨融合) ==========

    # 2a. 规则计算 (现有v2.920逻辑 + v3.010知识点调整)
    rule_signal, rule_confidence = determine_human_signal_level_v2900(
        result,
        knowledge_adjustment=knowledge_rules_result
    )
    result["rule_signal"] = rule_signal
    result["rule_confidence"] = rule_confidence
    
    # 2b. CNN计算
    cnn_result = {"signal": "HOLD", "confidence": 0.5, "probabilities": {"UP": 0.33, "SIDE": 0.34, "DOWN": 0.33}, "model_used": False}
    
    if USE_CNN_HUMAN and CNN_HUMAN_LOADED and CNN_HUMAN_MODEL is not None:
        try:
            cnn_result = cnn_predict(ohlcv_bars)
        except Exception as e:
            print(f"[v2.960] CNN预测失败: {e}")
    
    result["cnn_signal"] = cnn_result.get("signal", "HOLD")
    result["cnn_confidence"] = cnn_result.get("confidence", 0.5)
    result["probabilities"] = cnn_result.get("probabilities", {})
    result["model_used"] = cnn_result.get("model_used", False)
    
    # 2c. 获取校准权重
    calibrator = get_human_calibrator()
    weights = calibrator.get_weights(symbol) if symbol else {
        "rule_weight": HUMAN_DEFAULT_RULE_WEIGHT,
        "cnn_weight": HUMAN_DEFAULT_CNN_WEIGHT,
    }
    
    result["rule_weight"] = weights["rule_weight"]
    result["cnn_weight"] = weights["cnn_weight"]
    
    # 2d. 融合决策
    # v3.651: 记录晚期融合得分和视角分歧度
    result["late_fusion_score"] = weights.get("late_fusion_score")
    result["view_divergence"] = weights.get("view_divergence", 0)
    result["active_views"] = weights.get("active_views", 0)

    if result["model_used"]:
        # v3.620 Step 5a: CNN准确率 > 融合准确率 → 跳过融合，直接用CNN
        _cnn_acc = weights.get("cnn_accuracy")
        _fused_acc = weights.get("fused_accuracy")
        if (weights.get("calibrated") and
            _cnn_acc is not None and _fused_acc is not None and
            _cnn_acc > _fused_acc):
            # CNN直接覆盖 (谁准用谁)
            result["human_signal"] = cnn_result["signal"]
            result["confidence"] = cnn_result["confidence"]
            result["dual_track_mode"] = True
            result["fused_probs"] = cnn_result.get("probabilities", {})
            result["cnn_override"] = True
            result["reason"] = (f"CNN覆盖: CNN准确率({_cnn_acc:.0%}) > 融合({_fused_acc:.0%}) "
                               f"→ 直接用CNN={cnn_result['signal']}")
            print(f"[v3.620] CNN覆盖融合: CNN({_cnn_acc:.0%}) > 融合({_fused_acc:.0%}) "
                  f"→ {cnn_result['signal']} (跳过规则={rule_signal})")
        else:
            # 正常双轨融合
            fused = weighted_fusion_human(
                {"signal": rule_signal, "confidence": rule_confidence},
                cnn_result,
                weights["rule_weight"],
                weights["cnn_weight"]
            )
            result["human_signal"] = fused["signal"]
            result["confidence"] = fused["confidence"]
            result["dual_track_mode"] = True
            result["fused_probs"] = fused.get("fused_probs", {})
            result["cnn_override"] = False

            result["reason"] = (f"双轨融合: 规则={rule_signal}({rule_confidence:.0%})×{weights['rule_weight']:.0%} + "
                               f"CNN={cnn_result['signal']}({cnn_result['confidence']:.0%})×{weights['cnn_weight']:.0%} "
                               f"→ {result['human_signal']}")

            print(f"[v2.960] Human双轨: 规则={rule_signal} CNN={cnn_result['signal']} "
                  f"权重={weights['rule_weight']:.0%}/{weights['cnn_weight']:.0%} → {result['human_signal']}")
    else:
        # CNN不可用，100%规则
        result["human_signal"] = rule_signal
        result["confidence"] = rule_confidence
        result["dual_track_mode"] = False
        result["cnn_override"] = False
        result["reason"] = f"{result['visual_slope']}+{result['recent_impact']}+{result['volume_feel']}+{result['position_feel']}"
    
    return result


def compute_visual_slope_v2900(ohlcv_bars: list, period: int = 30) -> tuple:
    """
    v2.900: 计算视觉斜率
    
    Returns:
        (slope_value, category)
    """
    bars = ohlcv_bars[-period:] if len(ohlcv_bars) >= period else ohlcv_bars
    n = len(bars)
    
    if n < 5:
        return 0.0, "FLAT"
    
    closes = [float(bar.get("close", bar.get("c", 0))) for bar in bars]
    
    # 线性回归计算斜率
    x_mean = (n - 1) / 2
    y_mean = sum(closes) / n
    
    numerator = sum((i - x_mean) * (closes[i] - y_mean) for i in range(n))
    denominator = sum((i - x_mean) ** 2 for i in range(n))
    
    if denominator == 0:
        return 0.0, "FLAT"
    
    slope = numerator / denominator
    avg_price = y_mean if y_mean > 0 else 1
    normalized_slope = (slope / avg_price) * 100
    
    # 分类 (v2.985: 优化阈值，更容易识别趋势)
    if normalized_slope > 0.15:      # was 0.3
        category = "STEEP_UP"
    elif normalized_slope > 0.05:    # was 0.1
        category = "UP"
    elif normalized_slope < -0.15:   # was -0.3
        category = "STEEP_DOWN"
    elif normalized_slope < -0.05:   # was -0.1
        category = "DOWN"
    else:
        category = "FLAT"
    
    return normalized_slope, category


def assess_recent_candles_v2900(recent_bars: list) -> str:
    """
    v2.900: 评估最近几根K线的视觉冲击
    """
    if not recent_bars or len(recent_bars) < 3:
        return "MIXED"
    
    bull_count = 0
    bear_count = 0
    strong_bull = False
    strong_bear = False
    body_ratio = 0.5
    
    for bar in recent_bars:
        o = float(bar.get("open", bar.get("o", 0)))
        h = float(bar.get("high", bar.get("h", 0)))
        l = float(bar.get("low", bar.get("l", 0)))
        c = float(bar.get("close", bar.get("c", 0)))
        
        if o == 0:
            continue
        
        body = abs(c - o)
        range_hl = h - l if h > l else 0.001
        body_ratio = body / range_hl if range_hl > 0 else 0
        
        if c > o:
            bull_count += 1
            if body_ratio > 0.7 and (c - o) / o > 0.01:
                strong_bull = True
        elif c < o:
            bear_count += 1
            if body_ratio > 0.7 and (o - c) / o > 0.01:
                strong_bear = True
    
    # 判断冲击类型
    if strong_bull and bull_count >= 3:
        return "STRONG_BULL"
    elif strong_bear and bear_count >= 3:
        return "STRONG_BEAR"
    elif bull_count >= 4:
        return "REVERSAL_BULL" if bear_count >= 1 else "BREAKOUT"
    elif bear_count >= 4:
        return "REVERSAL_BEAR" if bull_count >= 1 else "BREAKDOWN"
    elif abs(bull_count - bear_count) <= 1:
        return "DOJI" if body_ratio < 0.3 else "MIXED"
    else:
        return "MIXED"


def assess_volume_visually_v2900(ohlcv_bars: list) -> str:
    """
    v2.900: 视觉评估量能
    """
    if len(ohlcv_bars) < 10:
        return "NORMAL"
    
    recent_bars = ohlcv_bars[-5:]
    older_bars = ohlcv_bars[-30:-5] if len(ohlcv_bars) >= 30 else ohlcv_bars[:-5]
    
    recent_vol = sum(float(bar.get("volume", bar.get("v", 0))) for bar in recent_bars) / len(recent_bars)
    older_vol = sum(float(bar.get("volume", bar.get("v", 0))) for bar in older_bars) / len(older_bars) if older_bars else 1
    
    if older_vol == 0:
        older_vol = 1
    
    ratio = recent_vol / older_vol
    
    if ratio > 3.0:
        return "CLIMAX"
    elif ratio > 1.5:
        return "EXPANDING"
    elif ratio < 0.7:
        return "SHRINKING"
    else:
        return "NORMAL"


def determine_human_signal_level_v2900(signals: dict, knowledge_adjustment: dict = None) -> tuple:
    """
    v2.900/v2.920/v3.010: 根据Human信号确定5级信号和置信度

    v2.920: 新增顺大逆小加分逻辑
    v3.010: 新增Human知识点规则调整

    Args:
        signals: Human信号字典
        knowledge_adjustment: v3.010知识点规则调整 (可选)
            - bull_adjustment: 多头因素调整
            - bear_adjustment: 空头因素调整

    Returns:
        (signal, confidence)
    """
    bull_factors = 0
    bear_factors = 0

    # v3.010: 应用Human知识点规则调整
    if knowledge_adjustment:
        bull_adj = knowledge_adjustment.get("bull_adjustment", 0)
        bear_adj = knowledge_adjustment.get("bear_adjustment", 0)
        bull_factors += bull_adj
        bear_factors += bear_adj
        if bull_adj != 0 or bear_adj != 0:
            print(f"[v3.010] 知识点调整: bull+{bull_adj}, bear+{bear_adj}")

    # v2.920: 顺大逆小检测
    # v2.979: 只用x4判断大周期（120根K线足够）
    trend_x4 = signals.get("trend_x4", "").lower() if signals.get("trend_x4") else ""
    visual_slope = signals.get("visual_slope", "FLAT")
    
    big_trend_up = (trend_x4 == "up")
    big_trend_down = (trend_x4 == "down")
    
    # 大涨 + 小周期回调/横盘 = 买入机会 (顺大逆小)
    if big_trend_up and visual_slope in ("DOWN", "FLAT", "STEEP_DOWN"):
        bull_factors += 3
        signals["big_small_pattern"] = "BIG_UP_SMALL_PULLBACK"
    # 大跌 + 小周期反弹/横盘 = 卖出机会 (顺大逆小)
    elif big_trend_down and visual_slope in ("UP", "FLAT", "STEEP_UP"):
        bear_factors += 3
        signals["big_small_pattern"] = "BIG_DOWN_SMALL_BOUNCE"
    
    # 斜率
    if signals["visual_slope"] == "STEEP_UP":
        bull_factors += 2
    elif signals["visual_slope"] == "UP":
        bull_factors += 1
    elif signals["visual_slope"] == "STEEP_DOWN":
        bear_factors += 2
    elif signals["visual_slope"] == "DOWN":
        bear_factors += 1
    
    # 最近冲击
    if signals["recent_impact"] in ("STRONG_BULL", "BREAKOUT"):
        bull_factors += 2
    elif signals["recent_impact"] == "REVERSAL_BULL":
        bull_factors += 1
    elif signals["recent_impact"] in ("STRONG_BEAR", "BREAKDOWN"):
        bear_factors += 2
    elif signals["recent_impact"] == "REVERSAL_BEAR":
        bear_factors += 1
    
    # 量能
    if signals["volume_feel"] in ("CLIMAX", "EXPANDING"):
        if bull_factors > bear_factors:
            bull_factors += 1
        elif bear_factors > bull_factors:
            bear_factors += 1
    
    # 位置
    if signals["position_feel"] == "LOW":
        bull_factors += 1
    elif signals["position_feel"] == "HIGH":
        bear_factors += 1
    
    # 计算净因素
    net_factor = bull_factors - bear_factors
    total_factor = bull_factors + bear_factors
    confidence = min(0.9, 0.4 + total_factor * 0.1)
    
    if net_factor >= 4:
        return "STRONG_BUY", confidence
    elif net_factor >= 2:
        return "BUY", confidence
    elif net_factor <= -4:
        return "STRONG_SELL", confidence
    elif net_factor <= -2:
        return "SELL", confidence
    else:
        return "HOLD", 0.5


def compute_tech_signals_v2900(ohlcv_bars: list, tv_data: dict = None,
                                trend_x4: str = None, trend_x8: str = None) -> dict:
    """
    v2.900/v2.920: 计算Tech视角5个信号
    
    v2.920新增: 顺大逆小检测
    - 大趋势UP + 小周期指标弱 → 放宽买入条件
    - 大趋势DOWN + 小周期指标弱 → 放宽卖出条件
    
    信号定义:
        1. ADX_Strength: ADX强度 (STRONG/MEDIUM/WEAK)
        2. Choppiness: 震荡度 (TRENDING/MIXED/CHOPPY)
        3. DI_Direction: DI方向 (BULLISH/NEUTRAL/BEARISH)
        4. TechRegime: 技术regime (UPTREND/DOWNTREND/RANGE/UNCLEAR)
        5. TechSignal: 最终Tech信号 (5级)
    
    Args:
        ohlcv_bars: K线数据
        tv_data: TradingView推送数据
        trend_x4: 4倍周期趋势 (up/down/side)
        trend_x8: 8倍周期趋势 (up/down/side)
    
    Returns:
        {
            "adx_strength": str,
            "choppiness": str,
            "di_direction": str,
            "tech_regime": str,
            "tech_signal": str,  # 5级信号
            "confidence": float,
            "reason": str,
            "raw": {adx, chop, plus_di, minus_di},
            "big_small_pattern": str,  # v2.920: 顺大逆小模式
        }
    """
    result = {
        "adx_strength": "WEAK",
        "choppiness": "MIXED",
        "di_direction": "NEUTRAL",
        "tech_regime": "UNCLEAR",
        "tech_signal": "HOLD",
        "confidence": 0.5,
        "reason": "",
        "raw": {
            "adx": 0.0,
            "chop": 50.0,
            "plus_di": 0.0,
            "minus_di": 0.0,
        },
        "big_small_pattern": "NONE",  # v2.920
        "trend_x4": trend_x4,  # v2.920
        "trend_x8": trend_x8,  # v2.920
    }
    
    # 优先使用TV推送的数据
    if tv_data:
        tv_regime = tv_data.get("regime", "")
        if tv_regime:
            result["tech_regime"] = map_tv_regime_v2900(tv_regime)
        if "adx" in tv_data:
            result["raw"]["adx"] = float(tv_data.get("adx", 0))
        if "plus_di" in tv_data:
            result["raw"]["plus_di"] = float(tv_data.get("plus_di", 0))
        if "minus_di" in tv_data:
            result["raw"]["minus_di"] = float(tv_data.get("minus_di", 0))
        if "choppiness" in tv_data:
            result["raw"]["chop"] = float(tv_data.get("choppiness", 50))
    
    # 如果没有TV数据或数据不完整，本地计算
    # v3.390: 使用x4周期K线计算ADX/Chop，与AI判断(x4周期)保持一致
    if len(ohlcv_bars) >= 20:  # 需要足够K线聚合
        # 先聚合成x4周期
        x4_bars = []
        for i in range(0, len(ohlcv_bars) - 3, 4):
            chunk = ohlcv_bars[i:i+4]
            if len(chunk) == 4:
                x4_bar = {
                    "open": chunk[0].get("open", chunk[0].get("o", 0)),
                    "high": max(float(b.get("high", b.get("h", 0)) or 0) for b in chunk),
                    "low": min(float(b.get("low", b.get("l", 0)) or 0) for b in chunk if float(b.get("low", b.get("l", 0)) or 0) > 0),
                    "close": chunk[-1].get("close", chunk[-1].get("c", 0)),
                    "volume": sum(float(b.get("volume", b.get("v", 0)) or 0) for b in chunk),
                }
                x4_bars.append(x4_bar)

        # 用x4周期K线计算指标
        if len(x4_bars) >= 14:
            if result["raw"]["chop"] == 50.0:
                result["raw"]["chop"] = calculate_choppiness_index_v2900(x4_bars, period=14)
            if result["raw"]["adx"] == 0:
                adx, plus_di, minus_di = calculate_adx_v2900(x4_bars, period=14)
                result["raw"]["adx"] = adx
                result["raw"]["plus_di"] = plus_di
                result["raw"]["minus_di"] = minus_di
            result["x4_bars_used"] = len(x4_bars)
    elif len(ohlcv_bars) >= 14:
        # 回退：K线不足时用当前周期
        if result["raw"]["chop"] == 50.0:
            result["raw"]["chop"] = calculate_choppiness_index_v2900(ohlcv_bars, period=14)
        if result["raw"]["adx"] == 0:
            adx, plus_di, minus_di = calculate_adx_v2900(ohlcv_bars, period=14)
            result["raw"]["adx"] = adx
            result["raw"]["plus_di"] = plus_di
            result["raw"]["minus_di"] = minus_di
        result["x4_bars_used"] = 0
    
    adx = result["raw"]["adx"]
    chop = result["raw"]["chop"]
    plus_di = result["raw"]["plus_di"]
    minus_di = result["raw"]["minus_di"]
    
    # ADX强度分类
    if adx > 30:
        result["adx_strength"] = "STRONG"
    elif adx > 20:
        result["adx_strength"] = "MEDIUM"
    else:
        result["adx_strength"] = "WEAK"
    
    # Choppiness分类
    if chop < 38.2:
        result["choppiness"] = "TRENDING"
    elif chop > 61.8:
        result["choppiness"] = "CHOPPY"
    else:
        result["choppiness"] = "MIXED"
    
    # DI方向
    di_diff = plus_di - minus_di
    if di_diff > 5:
        result["di_direction"] = "BULLISH"
    elif di_diff < -5:
        result["di_direction"] = "BEARISH"
    else:
        result["di_direction"] = "NEUTRAL"
    
    # 推断Tech Regime
    if result["tech_regime"] == "UNCLEAR":
        result["tech_regime"] = derive_tech_regime_v2900(result)
    
    # 计算Tech 5级信号
    result["tech_signal"], result["confidence"] = determine_tech_signal_level_v2900(result)
    result["reason"] = f"ADX={adx:.0f},{result['choppiness']},DI_diff={di_diff:.0f}"
    
    return result


# ============================================================================
# v2.940: XGBoost Tech 模块
# ============================================================================
# 
# 用XGBoost替换机械规则，提升Tech准确率
# 目标: 6-44% → 55-65%
#
# ============================================================================

class XGBoostTechModel:
    """
    v2.940: XGBoost技术分析模型
    
    特征工程 (15-20个指标):
        - ADX, +DI, -DI
        - RSI(14), RSI(7)
        - MACD, MACD_Signal, MACD_Hist
        - Choppiness Index
        - 布林带位置 (上轨距离%, 下轨距离%)
        - EMA交叉状态 (9/21, 21/55)
        - 成交量比率 (当前/平均)
        - ATR百分比
        - 价格动量 (5根, 10根, 20根)
        - 大周期趋势 (x4, x8)
    
    输出:
        - 5级信号: STRONG_BUY, BUY, HOLD, SELL, STRONG_SELL
        - 各类概率分布
        - 置信度
    """
    
    def __init__(self):
        self.model = None
        self.is_trained = False
        self.feature_names = [
            "adx", "plus_di", "minus_di", "di_diff",
            "rsi_14", "rsi_7",
            "macd", "macd_signal", "macd_hist",
            "choppiness",
            "bb_upper_dist", "bb_lower_dist", "bb_position",
            "ema_9_21_cross", "ema_21_55_cross",
            "volume_ratio",
            "atr_pct",
            "momentum_5", "momentum_10", "momentum_20",
            "trend_x4_up", "trend_x4_down",
            "trend_x8_up", "trend_x8_down",
        ]
        self.label_map = {
            0: "STRONG_SELL",
            1: "SELL",
            2: "HOLD",
            3: "BUY",
            4: "STRONG_BUY",
        }
        self.reverse_label_map = {v: k for k, v in self.label_map.items()}
        self._load_model()
    
    def _load_model(self):
        """加载已训练的模型"""
        if not XGBOOST_AVAILABLE:
            print("[XGBoost] ⚠️ xgboost库不可用")
            return
        
        try:
            if os.path.exists(XGBOOST_MODEL_PATH):
                self.model = xgb.Booster()
                self.model.load_model(XGBOOST_MODEL_PATH)
                self.is_trained = True
                print(f"[XGBoost] ✅ 模型已加载: {XGBOOST_MODEL_PATH}")
            else:
                print(f"[XGBoost] ⚠️ 模型文件不存在: {XGBOOST_MODEL_PATH}")
                print("[XGBoost] 将使用规则模式，可调用 train_model() 训练")
        except Exception as e:
            print(f"[XGBoost] ❌ 模型加载失败: {e}")
    
    def extract_features(self, ohlcv_bars: list, tv_data: dict = None,
                        trend_x4: str = None, trend_x8: str = None) -> list:
        """
        从K线数据提取特征向量
        
        Args:
            ohlcv_bars: K线数据
            tv_data: TradingView推送数据
            trend_x4: 4倍周期趋势
            trend_x8: 8倍周期趋势
        
        Returns:
            特征向量 (24维)
        """
        import numpy as np
        
        features = [0.0] * len(self.feature_names)
        
        if not ohlcv_bars or len(ohlcv_bars) < 30:
            return features
        
        try:
            closes = [float(b.get("close", b.get("c", 0))) for b in ohlcv_bars]
            highs = [float(b.get("high", b.get("h", 0))) for b in ohlcv_bars]
            lows = [float(b.get("low", b.get("l", 0))) for b in ohlcv_bars]
            volumes = [float(b.get("volume", b.get("v", 0))) for b in ohlcv_bars]
            
            # 1. ADX, +DI, -DI
            adx, plus_di, minus_di = calculate_adx_v2900(ohlcv_bars, period=14)
            features[0] = adx / 100.0  # 归一化
            features[1] = plus_di / 100.0
            features[2] = minus_di / 100.0
            features[3] = (plus_di - minus_di) / 100.0  # DI差
            
            # 2. RSI
            features[4] = self._calculate_rsi(closes, 14) / 100.0
            features[5] = self._calculate_rsi(closes, 7) / 100.0
            
            # 3. MACD
            macd, signal, hist = self._calculate_macd(closes)
            features[6] = np.clip(macd / closes[-1] * 100, -5, 5) / 5  # 归一化到[-1,1]
            features[7] = np.clip(signal / closes[-1] * 100, -5, 5) / 5
            features[8] = np.clip(hist / closes[-1] * 100, -5, 5) / 5
            
            # 4. Choppiness
            chop = calculate_choppiness_index_v2900(ohlcv_bars, 14)
            features[9] = chop / 100.0
            
            # 5. 布林带位置
            bb_upper, bb_middle, bb_lower = self._calculate_bollinger(closes)
            current_price = closes[-1]
            bb_range = bb_upper - bb_lower if bb_upper > bb_lower else 1
            features[10] = (bb_upper - current_price) / bb_range  # 上轨距离
            features[11] = (current_price - bb_lower) / bb_range  # 下轨距离
            features[12] = (current_price - bb_lower) / bb_range  # 位置 0=底 1=顶
            
            # 6. EMA交叉
            ema_9 = self._calculate_ema(closes, 9)
            ema_21 = self._calculate_ema(closes, 21)
            ema_55 = self._calculate_ema(closes, 55) if len(closes) >= 55 else ema_21
            features[13] = 1.0 if ema_9 > ema_21 else -1.0  # 9/21交叉
            features[14] = 1.0 if ema_21 > ema_55 else -1.0  # 21/55交叉
            
            # 7. 成交量比率
            avg_vol = np.mean(volumes[-20:]) if len(volumes) >= 20 else np.mean(volumes)
            current_vol = volumes[-1] if volumes else 0
            features[15] = min(current_vol / avg_vol, 5.0) / 5.0 if avg_vol > 0 else 0.5
            
            # 8. ATR百分比
            atr = self._calculate_atr(ohlcv_bars, 14)
            features[16] = min(atr / closes[-1] * 100, 10) / 10  # ATR%
            
            # 9. 价格动量
            features[17] = np.clip((closes[-1] / closes[-5] - 1) * 100, -10, 10) / 10 if len(closes) >= 5 else 0
            features[18] = np.clip((closes[-1] / closes[-10] - 1) * 100, -20, 20) / 20 if len(closes) >= 10 else 0
            features[19] = np.clip((closes[-1] / closes[-20] - 1) * 100, -30, 30) / 30 if len(closes) >= 20 else 0
            
            # 10. 大周期趋势
            trend_x4 = (trend_x4 or "").lower()
            trend_x8 = (trend_x8 or "").lower()
            features[20] = 1.0 if trend_x4 == "up" else 0.0
            features[21] = 1.0 if trend_x4 == "down" else 0.0
            features[22] = 1.0 if trend_x8 == "up" else 0.0
            features[23] = 1.0 if trend_x8 == "down" else 0.0
            
        except Exception as e:
            print(f"[XGBoost] ⚠️ 特征提取错误: {e}")
        
        return features
    
    def predict(self, ohlcv_bars: list, tv_data: dict = None,
               trend_x4: str = None, trend_x8: str = None) -> dict:
        """
        预测Tech信号
        
        Returns:
            {
                "tech_signal": str,
                "confidence": float,
                "probabilities": {STRONG_BUY: float, ...},
                "feature_importance": dict,
                "model_used": bool,
            }
        """
        import numpy as np
        
        result = {
            "tech_signal": "HOLD",
            "confidence": 0.5,
            "probabilities": {
                "STRONG_BUY": 0.0,
                "BUY": 0.0,
                "HOLD": 1.0,
                "SELL": 0.0,
                "STRONG_SELL": 0.0,
            },
            "feature_importance": {},
            "model_used": False,
            "reason": "",
        }
        
        if not self.is_trained or not XGBOOST_AVAILABLE:
            result["reason"] = "模型未训练或XGBoost不可用"
            return result
        
        try:
            # 提取特征
            features = self.extract_features(ohlcv_bars, tv_data, trend_x4, trend_x8)
            
            # 构建DMatrix
            dmatrix = xgb.DMatrix(np.array([features]), feature_names=self.feature_names)
            
            # 预测概率
            probs = self.model.predict(dmatrix)[0]
            
            # 如果是多分类，probs是概率数组
            if hasattr(probs, '__len__') and len(probs) == 5:
                prob_dict = {
                    "STRONG_SELL": float(probs[0]),
                    "SELL": float(probs[1]),
                    "HOLD": float(probs[2]),
                    "BUY": float(probs[3]),
                    "STRONG_BUY": float(probs[4]),
                }
            else:
                # 二分类或回归模式，简化处理
                # v3.391: 修复numpy.ndarray doesn't define __round__错误
                # 使用np.round()替代round()，并确保转换为标量
                pred_value = float(probs) if np.isscalar(probs) else float(probs.item()) if probs.size == 1 else float(probs[0])
                pred_class = int(np.round(pred_value))
                prob_dict = {k: 0.0 for k in self.label_map.values()}
                if pred_class in self.label_map:
                    prob_dict[self.label_map[pred_class]] = 1.0
                else:
                    prob_dict["HOLD"] = 1.0
            
            result["probabilities"] = prob_dict
            
            # 选择最高概率的信号
            best_signal = max(prob_dict.keys(), key=lambda k: prob_dict[k])
            result["tech_signal"] = best_signal
            result["confidence"] = prob_dict[best_signal]
            result["model_used"] = True
            result["reason"] = f"XGBoost: {best_signal}({prob_dict[best_signal]:.1%})"
            
        except Exception as e:
            result["reason"] = f"预测错误: {e}"
            print(f"[XGBoost] ❌ 预测失败: {e}")
        
        return result
    
    def train_model(self, training_data: list, labels: list,
                   validation_split: float = 0.2):
        """
        训练XGBoost模型
        
        Args:
            training_data: 特征数据列表 [[f1,f2,...], ...]
            labels: 标签列表 [0,1,2,3,4, ...]
            validation_split: 验证集比例
        
        Returns:
            训练结果统计
        """
        import numpy as np
        
        if not XGBOOST_AVAILABLE:
            return {"error": "XGBoost不可用"}
        
        try:
            # 划分训练/验证集
            n_samples = len(training_data)
            n_val = int(n_samples * validation_split)
            indices = np.random.permutation(n_samples)
            
            train_idx = indices[n_val:]
            val_idx = indices[:n_val]
            
            X_train = np.array([training_data[i] for i in train_idx])
            y_train = np.array([labels[i] for i in train_idx])
            X_val = np.array([training_data[i] for i in val_idx])
            y_val = np.array([labels[i] for i in val_idx])
            
            dtrain = xgb.DMatrix(X_train, label=y_train, feature_names=self.feature_names)
            dval = xgb.DMatrix(X_val, label=y_val, feature_names=self.feature_names)
            
            # 训练参数
            params = {
                "objective": "multi:softprob",
                "num_class": 5,
                "max_depth": 6,
                "eta": 0.1,
                "subsample": 0.8,
                "colsample_bytree": 0.8,
                "eval_metric": "mlogloss",
                "seed": 42,
            }
            
            # 训练
            evallist = [(dtrain, "train"), (dval, "eval")]
            self.model = xgb.train(
                params,
                dtrain,
                num_boost_round=200,
                evals=evallist,
                early_stopping_rounds=20,
                verbose_eval=False,
            )
            
            # 保存模型
            os.makedirs(os.path.dirname(XGBOOST_MODEL_PATH), exist_ok=True)
            self.model.save_model(XGBOOST_MODEL_PATH)
            self.is_trained = True
            
            # 计算验证集准确率
            preds = self.model.predict(dval)
            pred_labels = np.argmax(preds, axis=1)
            accuracy = np.mean(pred_labels == y_val)
            
            stats = {
                "train_samples": len(X_train),
                "val_samples": len(X_val),
                "val_accuracy": float(accuracy),
                "model_path": XGBOOST_MODEL_PATH,
            }
            
            # 保存统计
            os.makedirs(os.path.dirname(XGBOOST_STATS_PATH), exist_ok=True)
            with open(XGBOOST_STATS_PATH, "w") as f:
                json.dump(stats, f, indent=2)
            
            print(f"[XGBoost] ✅ 模型训练完成: 准确率={accuracy:.1%}")
            return stats
            
        except Exception as e:
            print(f"[XGBoost] ❌ 训练失败: {e}")
            return {"error": str(e)}
    
    # ========== 辅助计算函数 ==========
    
    def _calculate_rsi(self, closes: list, period: int = 14) -> float:
        """计算RSI"""
        if len(closes) < period + 1:
            return 50.0
        
        deltas = [closes[i] - closes[i-1] for i in range(1, len(closes))]
        gains = [d if d > 0 else 0 for d in deltas[-period:]]
        losses = [-d if d < 0 else 0 for d in deltas[-period:]]
        
        avg_gain = sum(gains) / period
        avg_loss = sum(losses) / period
        
        if avg_loss == 0:
            return 100.0
        
        rs = avg_gain / avg_loss
        return 100 - (100 / (1 + rs))
    
    def _calculate_macd(self, closes: list, fast: int = 12, slow: int = 26, signal: int = 9):
        """计算MACD"""
        if len(closes) < slow + signal:
            return 0.0, 0.0, 0.0
        
        ema_fast = self._calculate_ema(closes, fast)
        ema_slow = self._calculate_ema(closes, slow)
        macd_line = ema_fast - ema_slow
        
        # 简化：使用最后一个值
        signal_line = macd_line * 0.9  # 简化计算
        histogram = macd_line - signal_line
        
        return macd_line, signal_line, histogram
    
    def _calculate_ema(self, data: list, period: int) -> float:
        """计算EMA"""
        if len(data) < period:
            return data[-1] if data else 0.0
        
        multiplier = 2 / (period + 1)
        ema = sum(data[:period]) / period
        
        for price in data[period:]:
            ema = (price - ema) * multiplier + ema
        
        return ema
    
    def _calculate_bollinger(self, closes: list, period: int = 20, std_dev: float = 2.0):
        """计算布林带"""
        import numpy as np
        
        if len(closes) < period:
            return closes[-1], closes[-1], closes[-1]
        
        recent = closes[-period:]
        middle = np.mean(recent)
        std = np.std(recent)
        
        upper = middle + std_dev * std
        lower = middle - std_dev * std
        
        return upper, middle, lower
    
    def _calculate_atr(self, ohlcv_bars: list, period: int = 14) -> float:
        """计算ATR"""
        if len(ohlcv_bars) < period + 1:
            return 0.0
        
        tr_list = []
        for i in range(1, len(ohlcv_bars)):
            h = float(ohlcv_bars[i].get("high", 0))
            l = float(ohlcv_bars[i].get("low", 0))
            pc = float(ohlcv_bars[i-1].get("close", 0))
            tr = max(h - l, abs(h - pc), abs(l - pc))
            tr_list.append(tr)
        
        return sum(tr_list[-period:]) / period if tr_list else 0.0


# 全局XGBoost模型实例
_xgboost_tech_model = None

def get_xgboost_tech_model() -> XGBoostTechModel:
    """获取全局XGBoost模型实例"""
    global _xgboost_tech_model
    if _xgboost_tech_model is None:
        _xgboost_tech_model = XGBoostTechModel()
    return _xgboost_tech_model


def compute_tech_signals_v2940(ohlcv_bars: list, tv_data: dict = None,
                                trend_x4: str = None, trend_x8: str = None) -> dict:
    """
    v2.940: 计算Tech视角信号 (XGBoost + 规则混合)
    
    如果USE_XGBOOST_TECH=True且模型可用，使用XGBoost预测
    否则回退到规则模式 (compute_tech_signals_v2900)
    
    Args:
        ohlcv_bars: K线数据
        tv_data: TradingView推送数据
        trend_x4: 4倍周期趋势
        trend_x8: 8倍周期趋势
    
    Returns:
        与v2900相同格式，新增xgboost_result字段
    """
    # 先用规则计算作为基础
    result = compute_tech_signals_v2900(ohlcv_bars, tv_data, trend_x4, trend_x8)
    result["xgboost_result"] = None
    result["model_used"] = False
    
    # 尝试使用XGBoost
    if USE_XGBOOST_TECH and XGBOOST_AVAILABLE:
        try:
            xgb_model = get_xgboost_tech_model()
            if xgb_model.is_trained:
                xgb_result = xgb_model.predict(ohlcv_bars, tv_data, trend_x4, trend_x8)
                result["xgboost_result"] = xgb_result
                
                if xgb_result["model_used"]:
                    # 使用XGBoost结果
                    result["tech_signal"] = xgb_result["tech_signal"]
                    result["confidence"] = xgb_result["confidence"]
                    result["model_used"] = True
                    result["reason"] = xgb_result["reason"]
                    print(f"[v2.940 Tech] 🤖 XGBoost: {result['tech_signal']} ({result['confidence']:.0%})")
        except Exception as e:
            print(f"[v2.940 Tech] ⚠️ XGBoost失败，使用规则: {e}")
    
    if not result["model_used"]:
        print(f"[v2.940 Tech] 📊 规则模式: {result['tech_signal']} ({result['confidence']:.0%})")
    
    return result


