def detect_three_white_soldiers(ohlcv_bars: list) -> dict:
    """
    v2.940: 检测三白兵形态
    
    三白兵条件:
    1. 连续3根阳线
    2. 每根收盘价高于前一根
    3. 每根开盘价在前一根实体内
    4. 实体较大(>50%总长)
    5. 最好放量
    
    Returns:
        {
            "detected": bool,
            "confidence": float,
            "volume_confirm": bool,
            "reason": str,
        }
    """
    result = {
        "detected": False,
        "confidence": 0.0,
        "volume_confirm": False,
        "reason": "",
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 4:
        return result
    
    try:
        bars = ohlcv_bars[-4:]  # 包含前一根用于比较
        b1, b2, b3 = bars[-3], bars[-2], bars[-1]
        
        # 检查3根都是阳线
        is_bull_1 = b1["close"] > b1["open"]
        is_bull_2 = b2["close"] > b2["open"]
        is_bull_3 = b3["close"] > b3["open"]
        
        if not (is_bull_1 and is_bull_2 and is_bull_3):
            return result
        
        # 检查收盘价递增
        close_ascending = b1["close"] < b2["close"] < b3["close"]
        if not close_ascending:
            return result
        
        # 检查开盘价在前一根实体内
        open_in_body_2 = b1["open"] <= b2["open"] <= b1["close"]
        open_in_body_3 = b2["open"] <= b3["open"] <= b2["close"]
        
        # 检查实体比例
        def body_ratio(bar):
            total = bar["high"] - bar["low"]
            body = abs(bar["close"] - bar["open"])
            return body / total if total > 0 else 0
        
        ratio_1 = body_ratio(b1)
        ratio_2 = body_ratio(b2)
        ratio_3 = body_ratio(b3)
        
        strong_bodies = ratio_1 > 0.5 and ratio_2 > 0.5 and ratio_3 > 0.5
        
        # 成交量检查
        volumes = [b.get("volume", 0) for b in bars]
        avg_vol = sum(volumes[:-3]) / max(1, len(volumes) - 3) if len(volumes) > 3 else volumes[-1]
        vol_confirm = volumes[-1] > avg_vol * 1.2
        
        # 综合判断
        if close_ascending and (open_in_body_2 or open_in_body_3) and strong_bodies:
            confidence = 0.6
            if open_in_body_2 and open_in_body_3:
                confidence += 0.1
            if vol_confirm:
                confidence += 0.15
            if ratio_1 > 0.6 and ratio_2 > 0.6 and ratio_3 > 0.6:
                confidence += 0.1
            
            result["detected"] = True
            result["confidence"] = min(confidence, 0.95)
            result["volume_confirm"] = vol_confirm
            result["reason"] = f"三白兵: 连续3阳递增, 实体比={ratio_3:.0%}"
        
    except Exception as e:
        result["reason"] = f"检测错误: {e}"
    
    return result


