def calculate_obv_v2940(ohlcv_bars: list) -> dict:
    """
    v2.940: 计算OBV能量潮
    
    OBV计算:
    - 收盘价上涨: OBV += volume
    - 收盘价下跌: OBV -= volume
    - 收盘价不变: OBV不变
    
    Returns:
        {
            "obv": float,           # 当前OBV值
            "obv_ema": float,       # OBV的EMA
            "obv_trend": str,       # UP/DOWN/FLAT
            "obv_divergence": str,  # BULL_DIV/BEAR_DIV/NONE
            "detail": dict,
        }
    """
    result = {
        "obv": 0.0,
        "obv_ema": 0.0,
        "obv_trend": "FLAT",
        "obv_divergence": "NONE",
        "detail": {},
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return result
    
    try:
        closes = [float(b.get("close", 0)) for b in ohlcv_bars]
        volumes = [float(b.get("volume", 0)) for b in ohlcv_bars]
        
        # 计算OBV序列
        obv_list = [0.0]
        for i in range(1, len(closes)):
            if closes[i] > closes[i-1]:
                obv_list.append(obv_list[-1] + volumes[i])
            elif closes[i] < closes[i-1]:
                obv_list.append(obv_list[-1] - volumes[i])
            else:
                obv_list.append(obv_list[-1])
        
        result["obv"] = obv_list[-1]
        
        # 计算OBV的EMA(10)
        ema_period = 10
        if len(obv_list) >= ema_period:
            multiplier = 2 / (ema_period + 1)
            ema = sum(obv_list[:ema_period]) / ema_period
            for val in obv_list[ema_period:]:
                ema = (val - ema) * multiplier + ema
            result["obv_ema"] = ema
        else:
            result["obv_ema"] = result["obv"]
        
        # 判断OBV趋势
        obv_recent = obv_list[-5:]
        if len(obv_recent) >= 3:
            obv_change = obv_recent[-1] - obv_recent[0]
            avg_vol = sum(volumes[-20:]) / 20 if len(volumes) >= 20 else sum(volumes) / len(volumes)
            
            if obv_change > avg_vol * 0.5:
                result["obv_trend"] = "UP"
            elif obv_change < -avg_vol * 0.5:
                result["obv_trend"] = "DOWN"
            else:
                result["obv_trend"] = "FLAT"
        
        # 检测OBV背离
        price_recent = closes[-10:]
        obv_recent = obv_list[-10:]
        
        if len(price_recent) >= 10:
            # 价格创新高但OBV没有 = 看跌背离
            price_new_high = max(price_recent[-3:]) >= max(price_recent[:-3])
            obv_new_high = max(obv_recent[-3:]) >= max(obv_recent[:-3])
            
            # 价格创新低但OBV没有 = 看涨背离
            price_new_low = min(price_recent[-3:]) <= min(price_recent[:-3])
            obv_new_low = min(obv_recent[-3:]) <= min(obv_recent[:-3])
            
            if price_new_high and not obv_new_high:
                result["obv_divergence"] = "BEAR_DIV"
            elif price_new_low and not obv_new_low:
                result["obv_divergence"] = "BULL_DIV"
        
        result["detail"] = {
            "obv_list_last5": obv_list[-5:],
            "price_last5": closes[-5:],
        }
        
    except Exception as e:
        result["detail"]["error"] = str(e)
    
    return result


def analyze_2b_enhanced_v2940(ohlcv_bars: list, atr_period: int = 14) -> dict:
    """
    v2.940: 增强2B形态检测
    
    改进:
    1. 动态阈值: 基于ATR自适应
    2. 放量确认: 破位需成交量配合
    3. 回抽确认: 反向K线收盘
    
    Returns:
        {
            "pattern": str,       # TWO_B_TOP / TWO_B_BOTTOM / NONE
            "confidence": float,
            "volume_confirm": bool,
            "atr_threshold": float,
            "reason": str,
        }
    """
    result = {
        "pattern": "NONE",
        "confidence": 0.0,
        "volume_confirm": False,
        "atr_threshold": 0.0,
        "reason": "",
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 20:
        return result
    
    try:
        closes = [float(b.get("close", 0)) for b in ohlcv_bars]
        highs = [float(b.get("high", 0)) for b in ohlcv_bars]
        lows = [float(b.get("low", 0)) for b in ohlcv_bars]
        volumes = [float(b.get("volume", 0)) for b in ohlcv_bars]
        
        # 计算ATR
        tr_list = []
        for i in range(1, len(ohlcv_bars)):
            h = highs[i]
            l = lows[i]
            pc = closes[i-1]
            tr = max(h - l, abs(h - pc), abs(l - pc))
            tr_list.append(tr)
        
        atr = sum(tr_list[-atr_period:]) / atr_period if len(tr_list) >= atr_period else 0
        current_price = closes[-1]
        
        # 动态阈值 = ATR * 0.3 (约0.3-0.5%)
        threshold_pct = (atr / current_price) * 0.3 if current_price > 0 else 0.003
        threshold_pct = max(0.002, min(threshold_pct, 0.008))  # 限制在0.2%-0.8%
        result["atr_threshold"] = threshold_pct
        
        # 找近期高点和低点
        lookback = 15
        recent_high = max(highs[-lookback:-1])
        recent_low = min(lows[-lookback:-1])
        
        last_bar = ohlcv_bars[-1]
        prev_bar = ohlcv_bars[-2]
        
        # 成交量检查
        avg_vol = sum(volumes[-20:]) / 20 if len(volumes) >= 20 else sum(volumes) / len(volumes)
        vol_confirm = volumes[-1] > avg_vol * 1.3
        
        # 2B顶部: 突破高点后回落收阴
        if highs[-2] > recent_high:  # 前一根突破
            breakout_pct = (highs[-2] - recent_high) / recent_high
            if breakout_pct < threshold_pct * 2:  # 假突破
                if last_bar["close"] < last_bar["open"]:  # 回抽阴线
                    if last_bar["close"] < recent_high:  # 收盘回到高点下方
                        confidence = 0.55
                        if vol_confirm:
                            confidence += 0.15
                        if breakout_pct < threshold_pct:
                            confidence += 0.1
                        
                        result["pattern"] = "TWO_B_TOP"
                        result["confidence"] = min(confidence, 0.85)
                        result["volume_confirm"] = vol_confirm
                        result["reason"] = f"2B顶: 假突破{breakout_pct:.2%}后回落"
                        return result
        
        # 2B底部: 跌破低点后反弹收阳
        if lows[-2] < recent_low:  # 前一根跌破
            breakdown_pct = (recent_low - lows[-2]) / recent_low
            if breakdown_pct < threshold_pct * 2:  # 假跌破
                if last_bar["close"] > last_bar["open"]:  # 回抽阳线
                    if last_bar["close"] > recent_low:  # 收盘回到低点上方
                        confidence = 0.55
                        if vol_confirm:
                            confidence += 0.15
                        if breakdown_pct < threshold_pct:
                            confidence += 0.1
                        
                        result["pattern"] = "TWO_B_BOTTOM"
                        result["confidence"] = min(confidence, 0.85)
                        result["volume_confirm"] = vol_confirm
                        result["reason"] = f"2B底: 假跌破{breakdown_pct:.2%}后反弹"
                        return result
        
    except Exception as e:
        result["reason"] = f"检测错误: {e}"
    
    return result


def find_swing_points_v2940(ohlcv_bars: list, left_bars: int = 3, right_bars: int = 3) -> dict:
    """
    v2.940: 真实Swing点识别
    
    Swing High: 左右N根都比它低
    Swing Low: 左右N根都比它高
    
    Args:
        ohlcv_bars: K线数据
        left_bars: 左侧确认K线数
        right_bars: 右侧确认K线数
    
    Returns:
        {
            "swing_highs": [(index, price), ...],
            "swing_lows": [(index, price), ...],
            "last_swing_high": float,
            "last_swing_low": float,
            "swing_trend": str,  # HH_HL / LH_LL / MIXED
        }
    """
    result = {
        "swing_highs": [],
        "swing_lows": [],
        "last_swing_high": 0.0,
        "last_swing_low": 0.0,
        "swing_trend": "MIXED",
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < left_bars + right_bars + 1:
        return result
    
    try:
        highs = [float(b.get("high", 0)) for b in ohlcv_bars]
        lows = [float(b.get("low", 0)) for b in ohlcv_bars]
        
        swing_highs = []
        swing_lows = []
        
        # 找所有swing点 (不包括最后right_bars根)
        for i in range(left_bars, len(highs) - right_bars):
            # Swing High
            is_swing_high = True
            for j in range(1, left_bars + 1):
                if highs[i - j] >= highs[i]:
                    is_swing_high = False
                    break
            if is_swing_high:
                for j in range(1, right_bars + 1):
                    if highs[i + j] >= highs[i]:
                        is_swing_high = False
                        break
            if is_swing_high:
                swing_highs.append((i, highs[i]))
            
            # Swing Low
            is_swing_low = True
            for j in range(1, left_bars + 1):
                if lows[i - j] <= lows[i]:
                    is_swing_low = False
                    break
            if is_swing_low:
                for j in range(1, right_bars + 1):
                    if lows[i + j] <= lows[i]:
                        is_swing_low = False
                        break
            if is_swing_low:
                swing_lows.append((i, lows[i]))
        
        result["swing_highs"] = swing_highs[-5:]  # 保留最近5个
        result["swing_lows"] = swing_lows[-5:]
        
        if swing_highs:
            result["last_swing_high"] = swing_highs[-1][1]
        if swing_lows:
            result["last_swing_low"] = swing_lows[-1][1]
        
        # 判断swing趋势
        if len(swing_highs) >= 2 and len(swing_lows) >= 2:
            hh = swing_highs[-1][1] > swing_highs[-2][1]  # Higher High
            hl = swing_lows[-1][1] > swing_lows[-2][1]   # Higher Low
            lh = swing_highs[-1][1] < swing_highs[-2][1]  # Lower High
            ll = swing_lows[-1][1] < swing_lows[-2][1]   # Lower Low
            
            if hh and hl:
                result["swing_trend"] = "HH_HL"  # 上升趋势
            elif lh and ll:
                result["swing_trend"] = "LH_LL"  # 下降趋势
            else:
                result["swing_trend"] = "MIXED"
        
    except Exception as e:
        pass
    
    return result


def detect_candle_patterns_v2940(ohlcv_bars: list) -> dict:
    """
    v2.940: 增强K线形态检测
    
    在原有基础上新增:
    - THREE_WHITE_SOLDIERS
    - THREE_BLACK_CROWS
    - 增强的早晨/黄昏之星
    
    Returns:
        原有字段 + {
            "pattern_3bar_enhanced": str,
            "three_soldiers": dict,
            "three_crows": dict,
        }
    """
    # 先调用原有检测
    result = detect_candle_patterns(ohlcv_bars)
    
    # 新增字段
    result["pattern_3bar_enhanced"] = result.get("pattern_3bar", "NONE")
    result["three_soldiers"] = {"detected": False}
    result["three_crows"] = {"detected": False}
    
    if not USE_ENHANCED_L2:
        return result
    
    # 检测三白兵
    soldiers = detect_three_white_soldiers(ohlcv_bars)
    result["three_soldiers"] = soldiers
    if soldiers["detected"]:
        result["pattern_3bar_enhanced"] = "THREE_WHITE_SOLDIERS"
    
    # 检测三只乌鸦
    crows = detect_three_black_crows(ohlcv_bars)
    result["three_crows"] = crows
    if crows["detected"] and not soldiers["detected"]:
        result["pattern_3bar_enhanced"] = "THREE_BLACK_CROWS"
    
    return result


