def map_tv_regime_v2900(tv_regime: str) -> str:
    """v2.900: 映射TV推送的regime"""
    tv_regime = tv_regime.upper()
    if tv_regime in ("UPTREND", "UP", "BULL", "BULLISH", "UPTREND_RIDE"):
        return "UPTREND"
    elif tv_regime in ("DOWNTREND", "DOWN", "BEAR", "BEARISH", "DOWNTREND_RIDE"):
        return "DOWNTREND"
    elif tv_regime in ("RANGE", "RANGING", "SIDEWAYS", "CHOP", "CHOPPY"):
        return "RANGE"
    else:
        return "UNCLEAR"


def derive_tech_regime_v2900(signals: dict) -> str:
    """v2.900: 从技术指标推断Regime"""
    if signals["choppiness"] == "CHOPPY" and signals["adx_strength"] == "WEAK":
        return "RANGE"
    elif signals["choppiness"] == "TRENDING" and signals["adx_strength"] in ("STRONG", "MEDIUM"):
        if signals["di_direction"] == "BULLISH":
            return "UPTREND"
        elif signals["di_direction"] == "BEARISH":
            return "DOWNTREND"
    return "UNCLEAR"


def calculate_choppiness_index_v2900(ohlcv_bars: list, period: int = 14) -> float:
    """
    v2.900: 计算Choppiness Index
    
    公式: 100 * LOG10(SUM(ATR, period) / (Highest High - Lowest Low)) / LOG10(period)
    
    解读:
        < 38.2: 强趋势
        > 61.8: 震荡
        38.2-61.8: 过渡
    """
    import math
    
    if len(ohlcv_bars) < period + 1:
        return 50.0
    
    bars = ohlcv_bars[-(period + 1):]
    atr_sum = 0
    highest = float('-inf')
    lowest = float('inf')
    
    for i in range(1, len(bars)):
        h = float(bars[i].get("high", bars[i].get("h", 0)))
        l = float(bars[i].get("low", bars[i].get("l", 0)))
        prev_c = float(bars[i-1].get("close", bars[i-1].get("c", 0)))
        
        tr = max(h - l, abs(h - prev_c), abs(l - prev_c))
        atr_sum += tr
        highest = max(highest, h)
        lowest = min(lowest, l)
    
    range_hl = highest - lowest
    if range_hl <= 0 or atr_sum <= 0:
        return 50.0
    
    try:
        chop = 100 * math.log10(atr_sum / range_hl) / math.log10(period)
        return max(0, min(100, chop))
    except Exception as e:
        print(f"[CHOPPINESS] 计算异常: {e}")
        return 50.0


def calculate_adx_v2900(ohlcv_bars: list, period: int = 14) -> tuple:
    """
    v2.900: 计算ADX, +DI, -DI
    
    Returns:
        (adx, plus_di, minus_di)
    """
    if len(ohlcv_bars) < period * 2:
        return 0.0, 0.0, 0.0
    
    bars = ohlcv_bars[-(period * 2):]
    plus_dm_list = []
    minus_dm_list = []
    tr_list = []
    
    for i in range(1, len(bars)):
        h = float(bars[i].get("high", bars[i].get("h", 0)))
        l = float(bars[i].get("low", bars[i].get("l", 0)))
        prev_h = float(bars[i-1].get("high", bars[i-1].get("h", 0)))
        prev_l = float(bars[i-1].get("low", bars[i-1].get("l", 0)))
        prev_c = float(bars[i-1].get("close", bars[i-1].get("c", 0)))
        
        plus_dm = max(0, h - prev_h)
        minus_dm = max(0, prev_l - l)
        
        if plus_dm > minus_dm:
            minus_dm = 0
        elif minus_dm > plus_dm:
            plus_dm = 0
        else:
            plus_dm = minus_dm = 0
        
        tr = max(h - l, abs(h - prev_c), abs(l - prev_c))
        
        plus_dm_list.append(plus_dm)
        minus_dm_list.append(minus_dm)
        tr_list.append(tr)
    
    if len(tr_list) < period:
        return 0.0, 0.0, 0.0
    
    def wilder_smooth(data: list, period: int) -> float:
        if len(data) < period:
            return 0.0
        smoothed = sum(data[:period])
        for i in range(period, len(data)):
            smoothed = smoothed - smoothed / period + data[i]
        return smoothed / period
    
    atr = wilder_smooth(tr_list, period)
    smoothed_plus_dm = wilder_smooth(plus_dm_list, period)
    smoothed_minus_dm = wilder_smooth(minus_dm_list, period)
    
    if atr == 0:
        return 0.0, 0.0, 0.0
    
    plus_di = 100 * smoothed_plus_dm / atr
    minus_di = 100 * smoothed_minus_dm / atr
    
    di_sum = plus_di + minus_di
    if di_sum == 0:
        return 0.0, plus_di, minus_di
    
    dx = 100 * abs(plus_di - minus_di) / di_sum
    adx = dx  # 简化版，实际应该是DX的平滑值
    
    return adx, plus_di, minus_di


def determine_tech_signal_level_v2900(signals: dict) -> tuple:
    """
    v2.900/v2.920: 根据Tech信号确定5级信号和置信度
    
    v2.920: 新增顺大逆小逻辑
    - 大趋势UP时，放宽买入条件
    - 大趋势DOWN时，放宽卖出条件
    
    Returns:
        (signal, confidence)
    """
    di_diff = signals["raw"]["plus_di"] - signals["raw"]["minus_di"]
    adx = signals["raw"]["adx"]
    chop = signals["raw"]["chop"]
    
    # v2.920: 顺大逆小检测
    # v2.979: 只用x4判断大周期
    trend_x4 = signals.get("trend_x4", "").lower() if signals.get("trend_x4") else ""
    
    big_trend_up = (trend_x4 == "up")
    big_trend_down = (trend_x4 == "down")
    
    # v2.920: 顺大逆小 - 大趋势UP + 小周期回调(指标弱化)
    if big_trend_up:
        signals["big_small_pattern"] = "BIG_UP_TREND"
        # 大趋势向上时，只要DI不是强烈看空就给买入信号
        if di_diff > -5:  # 放宽条件：原本需要 >5
            if adx > 25 or chop < 50:  # 有一定趋势性
                return "STRONG_BUY", 0.80
            return "BUY", 0.70
        elif di_diff > -15:  # 即使DI偏空，大趋势向上也给温和买入
            return "BUY", 0.60
    
    # v2.920: 顺大逆小 - 大趋势DOWN + 小周期反弹(指标弱化)
    if big_trend_down:
        signals["big_small_pattern"] = "BIG_DOWN_TREND"
        # 大趋势向下时，只要DI不是强烈看多就给卖出信号
        if di_diff < 5:  # 放宽条件：原本需要 <-5
            if adx > 25 or chop < 50:
                return "STRONG_SELL", 0.80
            return "SELL", 0.70
        elif di_diff < 15:  # 即使DI偏多，大趋势向下也给温和卖出
            return "SELL", 0.60
    
    # v2.994: 放宽chop阈值从35到50，解决信号与方向矛盾问题
    # 原有逻辑: 强趋势 + 强ADX + 明确方向
    if adx > 30 and chop < 50 and di_diff > 10:
        return "STRONG_BUY", 0.85
    if adx > 30 and chop < 50 and di_diff < -10:
        return "STRONG_SELL", 0.85

    # 中等趋势
    if adx > 20 and di_diff > 5:
        return "BUY", 0.70
    if adx > 20 and di_diff < -5:
        return "SELL", 0.70

    # 默认HOLD
    return "HOLD", 0.50


# ============================================================
# v3.160: 威科夫量价分析检测器模块
# ============================================================
# 基于NotebookLM威科夫笔记本库提炼的核心规则
# ============================================================

def detect_wyckoff_volume_divergence(ohlcv_bars: list, lookback: int = 5) -> dict:
    """
    v3.160: 检测威科夫量价背离 (威科夫规则1 - Effort vs Result)

    注意: 重命名避免与P0增强函数 detect_volume_price_divergence 冲突

    量化标准: 成交量显著放大(>2倍均量)但K线实体异常小(<30%振幅)

    Returns:
        {
            "divergence_type": "BEARISH" | "BULLISH" | "NONE",
            "strength": float,  # 0-1
            "description": str,
        }
    """
    if not ohlcv_bars or len(ohlcv_bars) < lookback + 1:
        return {"divergence_type": "NONE", "strength": 0, "description": "数据不足"}

    recent = ohlcv_bars[-1]
    volume = float(recent.get("volume", recent.get("v", 0)))
    close = float(recent.get("close", recent.get("c", 0)))
    open_p = float(recent.get("open", recent.get("o", 0)))
    high = float(recent.get("high", recent.get("h", 0)))
    low = float(recent.get("low", recent.get("l", 0)))

    # 计算均量
    volumes = [float(b.get("volume", b.get("v", 0))) for b in ohlcv_bars[-lookback-1:-1]]
    avg_volume = sum(volumes) / len(volumes) if volumes else 1

    # 计算K线形态
    body = abs(close - open_p)
    range_hl = high - low
    body_ratio = body / range_hl if range_hl > 0 else 0

    # 判断趋势方向
    closes = [float(b.get("close", b.get("c", 0))) for b in ohlcv_bars[-lookback:]]
    trend_up = closes[-1] > closes[0]

    # 量价背离判断: 量能放大2倍 + 实体占比<30%
    volume_surge = volume > avg_volume * 2.0
    small_body = body_ratio < 0.3

    if volume_surge and small_body:
        strength = min(1.0, (volume / avg_volume - 1) * 0.5)
        if trend_up:
            return {
                "divergence_type": "BEARISH",
                "strength": strength,
                "description": "上涨放量滞涨(派发征兆)",
            }
        else:
            return {
                "divergence_type": "BULLISH",
                "strength": strength,
                "description": "下跌放量企稳(吸筹征兆)",
            }

    return {"divergence_type": "NONE", "strength": 0, "description": "无明显背离"}


def detect_intention_bar(ohlcv_bars: list) -> dict:
    """
    v3.160: 检测意图K线 (威科夫规则5)

    意图K线: 实体>66%振幅, 收盘在末端1/3
    犹豫K线: 实体<33% 或 长影线

    Returns:
        {
            "bar_type": "INTENTION_BULL" | "INTENTION_BEAR" | "HESITATION" | "NEUTRAL",
            "body_ratio": float,
            "confidence_boost": float,  # 对regime判断的置信度加成
        }
    """
    if not ohlcv_bars:
        return {"bar_type": "NEUTRAL", "body_ratio": 0, "confidence_boost": 0}

    bar = ohlcv_bars[-1]
    close = float(bar.get("close", bar.get("c", 0)))
    open_p = float(bar.get("open", bar.get("o", 0)))
    high = float(bar.get("high", bar.get("h", 0)))
    low = float(bar.get("low", bar.get("l", 0)))

    body = abs(close - open_p)
    range_hl = high - low
    body_ratio = body / range_hl if range_hl > 0 else 0

    upper_wick = high - max(close, open_p)
    lower_wick = min(close, open_p) - low

    # 意图K线: 实体>66%, 收盘在末端1/3
    if body_ratio > 0.66:
        if close > open_p:  # 阳线
            if close > high - range_hl * 0.33:
                return {
                    "bar_type": "INTENTION_BULL",
                    "body_ratio": body_ratio,
                    "confidence_boost": 0.08,
                }
        else:  # 阴线
            if close < low + range_hl * 0.33:
                return {
                    "bar_type": "INTENTION_BEAR",
                    "body_ratio": body_ratio,
                    "confidence_boost": 0.08,
                }

    # 犹豫K线: 实体<33% 或 长影线
    if body_ratio < 0.33 or (body > 0 and (upper_wick > body * 1.5 or lower_wick > body * 1.5)):
        return {
            "bar_type": "HESITATION",
            "body_ratio": body_ratio,
            "confidence_boost": -0.05,
        }

    return {"bar_type": "NEUTRAL", "body_ratio": body_ratio, "confidence_boost": 0}


def detect_spring_shakeout(ohlcv_bars: list, support_level: float = None) -> dict:
    """
    v3.160: 检测震仓/弹簧效应 (威科夫规则4)

    条件: 跌破支撑 → 3根K线内收回 → 放量确认

    Returns:
        {
            "spring_detected": bool,
            "recovery_bars": int,
            "signal": "BULLISH_REVERSAL" | "NONE",
            "confidence": float,
        }
    """
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return {"spring_detected": False, "recovery_bars": 0, "signal": "NONE", "confidence": 0}

    # 自动计算支撑位(如未提供): 取前20根最低点
    if support_level is None:
        lows = [float(b.get("low", b.get("l", 0))) for b in ohlcv_bars[-20:-3]]
        support_level = min(lows) if lows else 0

    if support_level <= 0:
        return {"spring_detected": False, "recovery_bars": 0, "signal": "NONE", "confidence": 0}

    # 计算均量
    volumes = [float(b.get("volume", b.get("v", 0))) for b in ohlcv_bars[-10:-5]]
    avg_vol = sum(volumes) / len(volumes) if volumes else 1

    # 检查最近5根K线是否有Spring形态
    for i in range(-5, -1):
        try:
            bar = ohlcv_bars[i]
            low = float(bar.get("low", bar.get("l", 0)))

            # 条件1: 跌破支撑(允许0.5%容差)
            if low < support_level * 0.995:
                # 检查后续K线是否收回
                recovery_bars = 0
                for j in range(i + 1, 0):
                    next_bar = ohlcv_bars[j]
                    next_close = float(next_bar.get("close", next_bar.get("c", 0)))
                    if next_close > support_level:
                        recovery_bars = j - i
                        break

                if 0 < recovery_bars <= 3:
                    # 检查恢复时的成交量
                    recovery_idx = i + recovery_bars
                    if recovery_idx < 0:
                        recovery_vol = float(ohlcv_bars[recovery_idx].get("volume", ohlcv_bars[recovery_idx].get("v", 0)))
                        volume_surge = recovery_vol > avg_vol * 1.3

                        if volume_surge:
                            return {
                                "spring_detected": True,
                                "recovery_bars": recovery_bars,
                                "signal": "BULLISH_REVERSAL",
                                "confidence": 0.75,
                            }
        except (IndexError, KeyError):
            continue

    return {"spring_detected": False, "recovery_bars": 0, "signal": "NONE", "confidence": 0}


def detect_upthrust(ohlcv_bars: list, resistance_level: float = None) -> dict:
    """
    v3.270: 检测上冲回落/UTAD (威科夫规则 - Spring的反面)

    条件: 突破阻力 → 3根K线内跌回 → 放量确认

    Returns:
        {
            "upthrust_detected": bool,
            "fallback_bars": int,
            "signal": "BEARISH_REVERSAL" | "NONE",
            "confidence": float,
        }
    """
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return {"upthrust_detected": False, "fallback_bars": 0, "signal": "NONE", "confidence": 0}

    # 自动计算阻力位(如未提供): 取前20根最高点
    if resistance_level is None:
        highs = [float(b.get("high", b.get("h", 0))) for b in ohlcv_bars[-20:-3]]
        resistance_level = max(highs) if highs else 0

    if resistance_level <= 0:
        return {"upthrust_detected": False, "fallback_bars": 0, "signal": "NONE", "confidence": 0}

    # 计算均量
    volumes = [float(b.get("volume", b.get("v", 0))) for b in ohlcv_bars[-10:-5]]
    avg_vol = sum(volumes) / len(volumes) if volumes else 1

    # 检查最近5根K线是否有Upthrust形态
    for i in range(-5, -1):
        try:
            bar = ohlcv_bars[i]
            high = float(bar.get("high", bar.get("h", 0)))

            # 条件1: 突破阻力(允许0.5%容差)
            if high > resistance_level * 1.005:
                # 检查后续K线是否跌回
                fallback_bars = 0
                for j in range(i + 1, 0):
                    next_bar = ohlcv_bars[j]
                    next_close = float(next_bar.get("close", next_bar.get("c", 0)))
                    if next_close < resistance_level:
                        fallback_bars = j - i
                        break

                if 0 < fallback_bars <= 3:
                    # 检查回落时的成交量
                    fallback_idx = i + fallback_bars
                    if fallback_idx < 0:
                        fallback_vol = float(ohlcv_bars[fallback_idx].get("volume", ohlcv_bars[fallback_idx].get("v", 0)))
                        volume_surge = fallback_vol > avg_vol * 1.3

                        if volume_surge:
                            return {
                                "upthrust_detected": True,
                                "fallback_bars": fallback_bars,
                                "signal": "BEARISH_REVERSAL",
                                "confidence": 0.75,
                            }
        except (IndexError, KeyError):
            continue

    return {"upthrust_detected": False, "fallback_bars": 0, "signal": "NONE", "confidence": 0}


def detect_sos_sow(ohlcv_bars: list) -> dict:
    """
    v3.270: 检测强弱信号 SOS/SOW (Sign of Strength / Sign of Weakness)

    SOS (强势信号): 放量长阳，实体>70%，突破近期高点
    SOW (弱势信号): 放量长阴，实体>70%，跌破近期低点

    Returns:
        {
            "signal_type": "SOS" | "SOW" | "NONE",
            "body_ratio": float,
            "volume_ratio": float,
            "breakout": bool,
            "confidence": float,
        }
    """
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return {"signal_type": "NONE", "body_ratio": 0, "volume_ratio": 0, "breakout": False, "confidence": 0}

    recent = ohlcv_bars[-1]
    close = float(recent.get("close", recent.get("c", 0)))
    open_p = float(recent.get("open", recent.get("o", 0)))
    high = float(recent.get("high", recent.get("h", 0)))
    low = float(recent.get("low", recent.get("l", 0)))
    volume = float(recent.get("volume", recent.get("v", 0)))

    # 计算实体占比
    range_hl = high - low
    body = abs(close - open_p)
    body_ratio = body / range_hl if range_hl > 0 else 0

    # 计算均量
    volumes = [float(b.get("volume", b.get("v", 0))) for b in ohlcv_bars[-11:-1]]
    avg_vol = sum(volumes) / len(volumes) if volumes else 1
    volume_ratio = volume / avg_vol if avg_vol > 0 else 1

    # 计算近期高低点
    highs = [float(b.get("high", b.get("h", 0))) for b in ohlcv_bars[-11:-1]]
    lows = [float(b.get("low", b.get("l", 0))) for b in ohlcv_bars[-11:-1]]
    recent_high = max(highs) if highs else high
    recent_low = min(lows) if lows else low

    # SOS判断: 放量长阳 + 突破近期高点
    is_bullish = close > open_p
    is_bearish = close < open_p

    if is_bullish and body_ratio >= 0.70 and volume_ratio >= 1.5:
        breakout = high > recent_high
        if breakout:
            conf = min(1.0, 0.60 + (body_ratio - 0.70) * 0.5 + (volume_ratio - 1.5) * 0.1)
            return {
                "signal_type": "SOS",
                "body_ratio": body_ratio,
                "volume_ratio": volume_ratio,
                "breakout": True,
                "confidence": conf,
            }

    # SOW判断: 放量长阴 + 跌破近期低点
    if is_bearish and body_ratio >= 0.70 and volume_ratio >= 1.5:
        breakdown = low < recent_low
        if breakdown:
            conf = min(1.0, 0.60 + (body_ratio - 0.70) * 0.5 + (volume_ratio - 1.5) * 0.1)
            return {
                "signal_type": "SOW",
                "body_ratio": body_ratio,
                "volume_ratio": volume_ratio,
                "breakout": True,
                "confidence": conf,
            }

    return {"signal_type": "NONE", "body_ratio": body_ratio, "volume_ratio": volume_ratio, "breakout": False, "confidence": 0}


def detect_stopping_action(ohlcv_bars: list) -> dict:
    """
    v3.160: 检测止跌/停止行为 (威科夫规则9)

    买入高潮: 支撑位天量但不创新低(底部信号)
    卖出高潮: 阻力位天量但不创新高(顶部信号)

    Returns:
        {
            "stopping_action": "BUYING_CLIMAX" | "SELLING_CLIMAX" | "NONE",
            "climax_volume": bool,
            "signal_strength": float,
        }
    """
    if not ohlcv_bars or len(ohlcv_bars) < 20:
        return {"stopping_action": "NONE", "climax_volume": False, "signal_strength": 0}

    recent = ohlcv_bars[-1]
    volume = float(recent.get("volume", recent.get("v", 0)))
    close = float(recent.get("close", recent.get("c", 0)))
    open_p = float(recent.get("open", recent.get("o", 0)))
    high = float(recent.get("high", recent.get("h", 0)))
    low = float(recent.get("low", recent.get("l", 0)))

    # 计算20日均量
    volumes = [float(b.get("volume", b.get("v", 0))) for b in ohlcv_bars[-21:-1]]
    avg_volume_20 = sum(volumes) / len(volumes) if volumes else 1

    # 计算最低点/最高点
    lows = [float(b.get("low", b.get("l", 0))) for b in ohlcv_bars[-20:-1]]
    lowest_low = min(lows) if lows else low

    highs = [float(b.get("high", b.get("h", 0))) for b in ohlcv_bars[-20:-1]]
    highest_high = max(highs) if highs else high

    # 天量判断: >2.5倍均量
    climax_volume = volume > avg_volume_20 * 2.5

    # K线形态
    body = abs(close - open_p)
    range_hl = high - low
    body_ratio = body / range_hl if range_hl > 0 else 0
    lower_wick = min(close, open_p) - low if range_hl > 0 else 0
    upper_wick = high - max(close, open_p) if range_hl > 0 else 0

    # 买入高潮(底部): 天量 + 接近支撑 + (不破新低 或 长下影)
    if climax_volume and low <= lowest_low * 1.02:
        no_new_low = low >= lowest_low
        long_lower_wick = body > 0 and lower_wick > body * 2 and body_ratio < 0.4

        if no_new_low or long_lower_wick:
            return {
                "stopping_action": "BUYING_CLIMAX",
                "climax_volume": True,
                "signal_strength": min(1.0, volume / avg_volume_20 / 2.5),
            }

    # 卖出高潮(顶部): 天量 + 接近阻力 + (不破新高 或 长上影)
    if climax_volume and high >= highest_high * 0.98:
        no_new_high = high <= highest_high
        long_upper_wick = body > 0 and upper_wick > body * 2 and body_ratio < 0.4

        if no_new_high or long_upper_wick:
            return {
                "stopping_action": "SELLING_CLIMAX",
                "climax_volume": True,
                "signal_strength": min(1.0, volume / avg_volume_20 / 2.5),
            }

    return {"stopping_action": "NONE", "climax_volume": False, "signal_strength": 0}


def compute_wyckoff_analysis(ohlcv_bars: list, symbol: str = None) -> dict:
    """
    v3.270: 威科夫综合分析 (整合6个检测器)
    v3.550: 新增第7个检测器 - 累积/分配量能特征

    v3.270新增:
    - upthrust: 上冲回落检测 (Spring反面)
    - sos_sow: 强弱信号检测 (SOS/SOW)

    v3.550新增:
    - accum_dist: 累积/分配量能特征检测 (鲁本威科夫7.12)

    Returns:
        {
            "divergence": dict,      # 量价背离
            "intention": dict,       # 意图K线
            "spring": dict,          # 震仓检测
            "upthrust": dict,        # v3.270: 上冲回落
            "sos_sow": dict,         # v3.270: 强弱信号
            "stopping": dict,        # 停止行为
            "accum_dist": dict,      # v3.550: 累积/分配量能
            "wyckoff_signal": str,   # 综合信号
            "wyckoff_confidence": float,
            "wyckoff_warning": str,
        }
    """
    result = {
        "divergence": {"divergence_type": "NONE", "strength": 0, "description": ""},
        "intention": {"bar_type": "NEUTRAL", "body_ratio": 0, "confidence_boost": 0},
        "spring": {"spring_detected": False, "signal": "NONE", "confidence": 0},
        "upthrust": {"upthrust_detected": False, "signal": "NONE", "confidence": 0},
        "sos_sow": {"signal_type": "NONE", "body_ratio": 0, "volume_ratio": 0, "confidence": 0},
        "stopping": {"stopping_action": "NONE", "climax_volume": False, "signal_strength": 0},
        # v3.550: 累积/分配量能特征
        "accum_dist": {"volume_trend": "STABLE", "accumulation_probability": 0.0, "distribution_probability": 0.0},
        "wyckoff_signal": None,
        "wyckoff_confidence": 0,
        "wyckoff_warning": None,
    }

    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return result

    # 1. 量价背离检测 (使用威科夫版本)
    result["divergence"] = detect_wyckoff_volume_divergence(ohlcv_bars)

    # 2. 意图K线检测
    result["intention"] = detect_intention_bar(ohlcv_bars)

    # 3. 震仓检测 (Spring - 买入信号)
    result["spring"] = detect_spring_shakeout(ohlcv_bars)

    # 4. v3.270: 上冲回落检测 (Upthrust - 卖出信号)
    result["upthrust"] = detect_upthrust(ohlcv_bars)

    # 5. v3.270: 强弱信号检测 (SOS/SOW - 确认信号)
    result["sos_sow"] = detect_sos_sow(ohlcv_bars)

    # 6. 停止行为检测
    result["stopping"] = detect_stopping_action(ohlcv_bars)

    # 7. v3.550: 累积/分配量能特征检测
    volumes = [float(bar.get('volume', bar.get('v', 0))) for bar in ohlcv_bars]
    closes = [float(bar.get('close', bar.get('c', 0))) for bar in ohlcv_bars]
    result["accum_dist"] = detect_accumulation_distribution_volume_v3550(volumes, closes, lookback=20)

    # 综合信号判断 (v3.270优先级: Spring > Upthrust > SOS/SOW > Stopping > Divergence)
    if result["spring"]["spring_detected"]:
        result["wyckoff_signal"] = "SPRING_BUY"
        result["wyckoff_confidence"] = result["spring"]["confidence"]
    elif result["upthrust"]["upthrust_detected"]:
        # v3.270: Upthrust = 卖出信号
        result["wyckoff_signal"] = "UPTHRUST_SELL"
        result["wyckoff_confidence"] = result["upthrust"]["confidence"]
    elif result["sos_sow"]["signal_type"] == "SOS":
        # v3.270: SOS = 强势确认 (买入方向增强)
        result["wyckoff_signal"] = "SOS_CONFIRM_BUY"
        result["wyckoff_confidence"] = result["sos_sow"]["confidence"]
    elif result["sos_sow"]["signal_type"] == "SOW":
        # v3.270: SOW = 弱势确认 (卖出方向增强)
        result["wyckoff_signal"] = "SOW_CONFIRM_SELL"
        result["wyckoff_confidence"] = result["sos_sow"]["confidence"]
    elif result["stopping"]["stopping_action"] == "BUYING_CLIMAX":
        result["wyckoff_signal"] = "STOPPING_BUY"
        result["wyckoff_confidence"] = result["stopping"]["signal_strength"]
    elif result["stopping"]["stopping_action"] == "SELLING_CLIMAX":
        result["wyckoff_signal"] = "STOPPING_SELL"
        result["wyckoff_confidence"] = result["stopping"]["signal_strength"]

    # 背离警告 (努力与结果原则)
    if result["divergence"]["divergence_type"] != "NONE":
        result["wyckoff_warning"] = result["divergence"]["description"]

    # 日志输出
    if result["wyckoff_signal"] or result["wyckoff_warning"]:
        print(f"[v3.270] 威科夫分析 {symbol}: signal={result['wyckoff_signal']}, "
              f"conf={result['wyckoff_confidence']:.2f}, "
              f"warning={result['wyckoff_warning']}, "
              f"intention={result['intention']['bar_type']}")

    return result


