# ============================================================================
# ============================================================================
# v2.800: L1 Trend Vision - 让AI学会"一眼看图"
# ============================================================================
# ============================================================================
#
# 核心理念：人类看K线能一眼判断趋势方向和强度，AI也应该具备这个能力
#
# 模块组成:
#   1. compute_trend_slope() - 趋势斜率计算
#   2. identify_trend_stage() - 趋势阶段识别
#   3. analyze_volume_trend() - 量价趋势分析
#   4. get_l1_trend_vision() - 综合趋势评分
#
# 输出5档信号: STRONG_BUY / BUY / HOLD / SELL / STRONG_SELL  (v3.340统一格式)
#
# ============================================================================

import numpy as np
from typing import Tuple

def compute_trend_slope(ohlcv_bars: list) -> dict:
    """
    v2.800: 计算多周期趋势斜率
    
    方法: 线性回归拟合收盘价，计算斜率百分比
    
    Args:
        ohlcv_bars: K线数据列表
    
    Returns:
        {
            "slope_5": float,       # 5根斜率 (%)，短期
            "slope_10": float,      # 10根斜率 (%)，中期
            "slope_20": float,      # 20根斜率 (%)，长期
            "slope_trend": str,     # 综合方向: STRONG_UP/UP/SIDE/DOWN/STRONG_DOWN
            "slope_strength": float, # 强度 0-1
            "slope_alignment": bool, # 多周期是否同向
            "detail": dict,         # 详细信息
        }
    """
    result = {
        "slope_5": 0.0,
        "slope_10": 0.0,
        "slope_20": 0.0,
        "slope_trend": "SIDE",
        "slope_strength": 0.0,
        "slope_alignment": False,
        "detail": {},
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 5:
        return result
    
    closes = [bar["close"] for bar in ohlcv_bars]
    
    def calc_slope_pct(prices: list) -> float:
        """计算斜率百分比（使用线性回归）"""
        if len(prices) < 2:
            return 0.0
        n = len(prices)
        x = list(range(n))
        x_mean = sum(x) / n
        y_mean = sum(prices) / n
        
        numerator = sum((x[i] - x_mean) * (prices[i] - y_mean) for i in range(n))
        denominator = sum((x[i] - x_mean) ** 2 for i in range(n))
        
        if denominator == 0 or y_mean == 0:
            return 0.0
        
        slope = numerator / denominator
        # 转换为每根K线的百分比变化
        slope_pct = (slope / y_mean) * 100
        return slope_pct
    
    # 计算不同周期的斜率
    slope_5 = calc_slope_pct(closes[-5:]) if len(closes) >= 5 else 0.0
    slope_10 = calc_slope_pct(closes[-10:]) if len(closes) >= 10 else slope_5
    slope_20 = calc_slope_pct(closes[-20:]) if len(closes) >= 20 else slope_10
    
    result["slope_5"] = round(slope_5, 3)
    result["slope_10"] = round(slope_10, 3)
    result["slope_20"] = round(slope_20, 3)
    
    # 判断斜率方向
    def get_slope_direction(slope: float) -> str:
        if slope >= 1.5:
            return "STRONG_UP"
        elif slope >= 0.5:
            return "UP"
        elif slope <= -1.5:
            return "STRONG_DOWN"
        elif slope <= -0.5:
            return "DOWN"
        else:
            return "SIDE"
    
    dir_5 = get_slope_direction(slope_5)
    dir_10 = get_slope_direction(slope_10)
    
    # 综合方向：以短期为主，长期为辅
    if dir_5 in ["STRONG_UP", "UP"] and dir_10 in ["STRONG_UP", "UP", "SIDE"]:
        if slope_5 >= 1.5 and slope_10 >= 0.5:
            result["slope_trend"] = "STRONG_UP"
        else:
            result["slope_trend"] = "UP"
    elif dir_5 in ["STRONG_DOWN", "DOWN"] and dir_10 in ["STRONG_DOWN", "DOWN", "SIDE"]:
        if slope_5 <= -1.5 and slope_10 <= -0.5:
            result["slope_trend"] = "STRONG_DOWN"
        else:
            result["slope_trend"] = "DOWN"
    else:
        result["slope_trend"] = "SIDE"
    
    # 计算斜率强度 (0-1)
    max_slope = max(abs(slope_5), abs(slope_10))
    result["slope_strength"] = min(max_slope / 3.0, 1.0)  # 3%斜率为满分
    
    # 检查多周期是否同向
    signs = [slope_5 > 0.3, slope_10 > 0.3, slope_20 > 0.3]
    neg_signs = [slope_5 < -0.3, slope_10 < -0.3, slope_20 < -0.3]
    result["slope_alignment"] = all(signs) or all(neg_signs)
    
    result["detail"] = {
        "dir_5": dir_5,
        "dir_10": dir_10,
        "closes_5": closes[-5:] if len(closes) >= 5 else closes,
    }
    
    return result


def identify_trend_stage(ohlcv_bars: list, slope_info: dict) -> dict:
    """
    v2.800: 识别趋势所处阶段
    
    Args:
        ohlcv_bars: K线数据
        slope_info: 来自compute_trend_slope的结果
    
    Returns:
        {
            "stage": str,           # TREND_START/TREND_MIDDLE/TREND_LATE/TREND_EXHAUST/CONSOLIDATION
            "run_percent": float,   # 已涨/跌幅度%
            "momentum": str,        # ACCELERATING/STEADY/DECELERATING
            "chase_ok": bool,       # 是否可追
            "stage_score": float,   # 阶段评分 (有利=正, 不利=负)
        }
    """
    result = {
        "stage": "CONSOLIDATION",
        "run_percent": 0.0,
        "momentum": "STEADY",
        "chase_ok": False,
        "stage_score": 0.0,
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return result
    
    closes = [bar["close"] for bar in ohlcv_bars]
    highs = [bar["high"] for bar in ohlcv_bars]
    lows = [bar["low"] for bar in ohlcv_bars]
    
    # 计算从近期低点/高点的涨跌幅
    recent_20 = closes[-20:] if len(closes) >= 20 else closes
    recent_low = min(recent_20)
    recent_high = max(recent_20)
    current = closes[-1]
    
    # 计算运行幅度 (v3.003: 添加除零保护)
    run_from_low = 0
    run_from_high = 0
    if recent_high > recent_low and recent_low > 0 and recent_high > 0:
        if current > recent_low:
            run_from_low = (current - recent_low) / max(recent_low, 1e-9) * 100
        if current < recent_high:
            run_from_high = (recent_high - current) / max(recent_high, 1e-9) * 100
    
    slope_trend = slope_info.get("slope_trend", "SIDE")
    slope_5 = slope_info.get("slope_5", 0)
    slope_10 = slope_info.get("slope_10", 0)
    
    # 判断动量变化（斜率加速/减速）
    if abs(slope_5) > abs(slope_10) * 1.3:
        momentum = "ACCELERATING"
    elif abs(slope_5) < abs(slope_10) * 0.7:
        momentum = "DECELERATING"
    else:
        momentum = "STEADY"
    
    result["momentum"] = momentum
    
    # 判断趋势阶段
    if slope_trend in ["STRONG_UP", "UP"]:
        result["run_percent"] = run_from_low
        
        if run_from_low < 8:
            result["stage"] = "TREND_START"
            result["chase_ok"] = True
            result["stage_score"] = 0.8
        elif run_from_low < 18:
            result["stage"] = "TREND_MIDDLE"
            result["chase_ok"] = momentum != "DECELERATING"
            result["stage_score"] = 0.5 if momentum != "DECELERATING" else 0.2
        elif run_from_low < 30:
            result["stage"] = "TREND_LATE"
            result["chase_ok"] = False
            result["stage_score"] = -0.2
        else:
            result["stage"] = "TREND_EXHAUST"
            result["chase_ok"] = False
            result["stage_score"] = -0.5
        
        # 动量衰减降级
        if momentum == "DECELERATING" and result["stage"] != "TREND_START":
            result["stage_score"] -= 0.3
            
    elif slope_trend in ["STRONG_DOWN", "DOWN"]:
        result["run_percent"] = run_from_high
        
        if run_from_high < 8:
            result["stage"] = "TREND_START"
            result["chase_ok"] = True  # 可以做空/卖出
            result["stage_score"] = -0.8  # 负分表示看跌
        elif run_from_high < 18:
            result["stage"] = "TREND_MIDDLE"
            result["chase_ok"] = momentum != "DECELERATING"
            result["stage_score"] = -0.5 if momentum != "DECELERATING" else -0.2
        elif run_from_high < 30:
            result["stage"] = "TREND_LATE"
            result["chase_ok"] = False
            result["stage_score"] = 0.2  # 跌多了反而有支撑
        else:
            result["stage"] = "TREND_EXHAUST"
            result["chase_ok"] = False
            result["stage_score"] = 0.5  # 超跌反弹机会
            
    else:  # SIDE
        result["stage"] = "CONSOLIDATION"
        result["run_percent"] = 0
        result["chase_ok"] = False
        result["stage_score"] = 0.0
    
    return result


def analyze_volume_trend(ohlcv_bars: list, slope_info: dict) -> dict:
    """
    v2.800: 分析量价配合关系
    
    Args:
        ohlcv_bars: K线数据
        slope_info: 来自compute_trend_slope的结果
    
    Returns:
        {
            "volume_trend": str,        # INCREASING/DECREASING/STABLE
            "price_volume_match": bool, # 量价配合
            "divergence": str or None,  # BULLISH_DIV/BEARISH_DIV/None
            "climax_detected": bool,    # 放量顶/底
            "health_score": float,      # 趋势健康度 0-1
        }
    """
    result = {
        "volume_trend": "STABLE",
        "price_volume_match": True,
        "divergence": None,
        "climax_detected": False,
        "health_score": 0.5,
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return result
    
    # 提取成交量
    volumes = [bar.get("volume", 0) for bar in ohlcv_bars]
    closes = [bar["close"] for bar in ohlcv_bars]
    
    # 过滤0成交量
    valid_volumes = [v for v in volumes if v > 0]
    if len(valid_volumes) < 5:
        return result
    
    # 计算成交量趋势（最近5根 vs 前10根平均）
    recent_vol = volumes[-5:]
    older_vol = volumes[-15:-5] if len(volumes) >= 15 else volumes[:-5]
    
    recent_avg = sum(v for v in recent_vol if v > 0) / max(len([v for v in recent_vol if v > 0]), 1)
    older_avg = sum(v for v in older_vol if v > 0) / max(len([v for v in older_vol if v > 0]), 1)
    
    if older_avg > 0:
        vol_change = (recent_avg - older_avg) / older_avg
    else:
        vol_change = 0
    
    # 判断成交量趋势
    if vol_change > 0.3:
        result["volume_trend"] = "INCREASING"
    elif vol_change < -0.3:
        result["volume_trend"] = "DECREASING"
    else:
        result["volume_trend"] = "STABLE"
    
    # 判断量价配合
    slope_trend = slope_info.get("slope_trend", "SIDE")
    
    # 健康的量价关系
    # 涨+量增 = 健康 (0.9)
    # 涨+量减 = 不健康 (0.4)
    # 跌+量增 = 恐慌 (0.3)
    # 跌+量减 = 衰竭 (0.6)
    
    if slope_trend in ["STRONG_UP", "UP"]:
        if result["volume_trend"] == "INCREASING":
            result["price_volume_match"] = True
            result["health_score"] = 0.9
        elif result["volume_trend"] == "DECREASING":
            result["price_volume_match"] = False
            result["health_score"] = 0.4
            result["divergence"] = "BEARISH_DIV"  # 量价背离
        else:
            result["price_volume_match"] = True
            result["health_score"] = 0.7
            
    elif slope_trend in ["STRONG_DOWN", "DOWN"]:
        if result["volume_trend"] == "INCREASING":
            result["price_volume_match"] = True  # 下跌放量是"正常"的恐慌
            result["health_score"] = 0.3
        elif result["volume_trend"] == "DECREASING":
            result["price_volume_match"] = False
            result["health_score"] = 0.6
            result["divergence"] = "BULLISH_DIV"  # 下跌缩量，可能见底
        else:
            result["price_volume_match"] = True
            result["health_score"] = 0.4
    else:
        result["health_score"] = 0.5
    
    # 检测放量顶/底 (最后一根成交量是否异常大)
    if len(valid_volumes) >= 10:
        avg_vol = sum(valid_volumes[-10:]) / 10
        last_vol = volumes[-1] if volumes[-1] > 0 else 0
        
        if last_vol > avg_vol * 2.5:
            result["climax_detected"] = True
            # 放量可能是顶或底
            if slope_trend in ["STRONG_UP", "UP"]:
                result["health_score"] -= 0.2  # 涨势中放量可能见顶
            elif slope_trend in ["STRONG_DOWN", "DOWN"]:
                result["health_score"] += 0.2  # 跌势中放量可能见底
    
    return result


def get_l1_trend_vision(ohlcv_bars: list, pos_ratio: float = 0.5, 
                        swing_support: float = 0.0, swing_resistance: float = 0.0) -> dict:
    """
    v2.865: L1层趋势视觉综合判断 - AI的"一眼看图"能力
    
    整合K线形态检测，新权重分配:
    - K线形态: 35% (V底/V顶/锤子/吞没/震荡顶底)
    - 斜率趋势: 25% (5根/10根斜率)
    - 量价配合: 20% (背离/天量)
    - 趋势阶段: 20% (初期/中段/末期)
    
    Args:
        ohlcv_bars: K线数据
        pos_ratio: 价格在区间中的位置 (0=底部, 1=顶部)
        swing_support: swing支撑位
        swing_resistance: swing阻力位
    
    Returns:
        {
            "l1_bias": str,         # v3.340: STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL
            "confidence": float,    # 0-1
            "action_bias": str,     # BUY/SELL/HOLD
            "score": float,         # -1 到 +1
            "candle": dict,         # K线形态信息
            "slope": dict,          # 斜率信息
            "stage": dict,          # 阶段信息
            "volume": dict,         # 量价信息
            "reasons": list,
        }
    """
    result = {
        "l1_bias": "HOLD",
        "confidence": 0.5,
        "action_bias": "HOLD",
        "score": 0.0,
        "candle": {},
        "slope": {},
        "stage": {},
        "volume": {},
        "reasons": [],
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        result["reasons"].append("K线数据不足")
        return result
    
    score = 0.0
    reasons = []
    
    # ========== 1. K线形态检测 (权重: 35%) ==========
    candle_info = _detect_candle_pattern_for_vision(ohlcv_bars, pos_ratio, swing_support, swing_resistance)
    result["candle"] = candle_info
    
    candle_score = candle_info.get("score", 0.0)  # -1 到 +1
    score += candle_score * 0.35
    
    candle_signal = candle_info.get("signal", "NONE")
    if candle_signal != "NONE":
        reasons.append(f"K线:{candle_signal}({candle_info.get('pattern', '')})")
    
    # ========== 2. 斜率趋势 (权重: 25%) ==========
    slope_info = compute_trend_slope(ohlcv_bars)
    result["slope"] = slope_info
    
    slope_trend = slope_info.get("slope_trend", "SIDE")
    slope_alignment = slope_info.get("slope_alignment", False)
    
    slope_score = 0.0
    if slope_trend == "STRONG_UP":
        slope_score = 1.0
        reasons.append(f"斜率强涨(+{slope_info.get('slope_5', 0):.1f}%)")
    elif slope_trend == "UP":
        slope_score = 0.5
        reasons.append(f"斜率温涨")
    elif slope_trend == "STRONG_DOWN":
        slope_score = -1.0
        reasons.append(f"斜率强跌({slope_info.get('slope_5', 0):.1f}%)")
    elif slope_trend == "DOWN":
        slope_score = -0.5
        reasons.append(f"斜率温跌")
    else:
        reasons.append("斜率横盘")
    
    # 斜率同向加成
    if slope_alignment and slope_score != 0:
        slope_score *= 1.2
        reasons.append("多周期同向")
    
    score += slope_score * 0.25
    
    # ========== 3. 量价配合 (权重: 20%) ==========
    volume_info = analyze_volume_trend(ohlcv_bars, slope_info)
    result["volume"] = volume_info
    
    health_score = volume_info.get("health_score", 0.5)
    divergence = volume_info.get("divergence")
    climax = volume_info.get("climax_detected", False)
    
    # 健康度映射到 -1 ~ +1
    volume_score = (health_score - 0.5) * 2
    
    if divergence == "BULLISH_DIV":
        volume_score += 0.3
        reasons.append("底背离")
    elif divergence == "BEARISH_DIV":
        volume_score -= 0.3
        reasons.append("顶背离")
    
    if climax:
        reasons.append("放量异常")
    
    if volume_info.get("price_volume_match"):
        reasons.append("量价配合")
    
    score += volume_score * 0.20
    
    # ========== 4. 趋势阶段 (权重: 20%) ==========
    stage_info = identify_trend_stage(ohlcv_bars, slope_info)
    result["stage"] = stage_info
    
    stage = stage_info.get("stage", "CONSOLIDATION")
    stage_score = stage_info.get("stage_score", 0)
    run_pct = stage_info.get("run_percent", 0)
    
    if stage == "TREND_START":
        reasons.append(f"趋势初期({run_pct:.0f}%)")
    elif stage == "TREND_MIDDLE":
        reasons.append(f"趋势中段")
    elif stage == "TREND_LATE":
        reasons.append(f"趋势末期")
    elif stage == "TREND_EXHAUST":
        reasons.append(f"趋势衰竭")
    else:
        reasons.append("盘整")
    
    score += stage_score * 0.20
    
    # ========== 确定L1_bias ==========
    # 限制score在-1到+1之间
    score = max(-1.0, min(1.0, score))
    result["score"] = round(score, 3)
    result["reasons"] = reasons
    
    # v3.340: 评分到5档映射 (统一格式: STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL)
    if score >= 0.4:
        result["l1_bias"] = "STRONG_BUY"
        result["action_bias"] = "BUY"
        result["confidence"] = min(0.5 + score * 0.4, 0.90)
    elif score >= 0.15:
        result["l1_bias"] = "BUY"  # v3.340: WEAK_BUY → BUY
        result["action_bias"] = "BUY"
        result["confidence"] = 0.5 + score * 0.3
    elif score <= -0.4:
        result["l1_bias"] = "STRONG_SELL"
        result["action_bias"] = "SELL"
        result["confidence"] = min(0.5 + abs(score) * 0.4, 0.90)
    elif score <= -0.15:
        result["l1_bias"] = "SELL"  # v3.340: WEAK_SELL → SELL
        result["action_bias"] = "SELL"
        result["confidence"] = 0.5 + abs(score) * 0.3
    else:
        result["l1_bias"] = "HOLD"  # v3.340: NEUTRAL → HOLD
        result["action_bias"] = "HOLD"
        result["confidence"] = 0.5
    
    return result


def _detect_candle_pattern_for_vision(ohlcv_bars: list, pos_ratio: float,
                                       swing_support: float, swing_resistance: float) -> dict:
    """
    v2.865: Vision内部的K线形态检测
    
    返回:
        {
            "signal": str,      # V_BOTTOM/V_TOP/RANGE_LOW/RANGE_HIGH/HAMMER/ENGULF/NONE
            "pattern": str,     # 具体K线形态
            "score": float,     # -1 到 +1
            "confidence": float,
            "reason": str,
        }
    """
    result = {
        "signal": "NONE",
        "pattern": "NONE",
        "score": 0.0,
        "confidence": 0.0,
        "reason": "",
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 5:
        return result
    
    # 计算平均成交量
    volumes = [bar.get("volume", 0) for bar in ohlcv_bars[-20:] if bar.get("volume", 0) > 0]
    avg_volume = sum(volumes) / len(volumes) if volumes else 1
    
    last_bar = ohlcv_bars[-1]
    prev_bar = ohlcv_bars[-2] if len(ohlcv_bars) >= 2 else None
    
    last_open = last_bar.get("open", 0)
    last_high = last_bar.get("high", 0)
    last_low = last_bar.get("low", 0)
    last_close = last_bar.get("close", 0)
    last_volume = last_bar.get("volume", 0)
    
    body = abs(last_close - last_open)
    upper_shadow = last_high - max(last_open, last_close)
    lower_shadow = min(last_open, last_close) - last_low
    bar_range = last_high - last_low if last_high > last_low else 0.0001
    
    volume_ratio = last_volume / avg_volume if avg_volume > 0 else 1.0
    is_bullish = last_close > last_open
    is_bearish = last_close < last_open
    
    # ========== 检测锤子线/上吊线 ==========
    is_hammer = (lower_shadow > body * 2 and upper_shadow < body * 0.5 and bar_range > 0)
    is_hanging_man = (upper_shadow > body * 2 and lower_shadow < body * 0.5 and bar_range > 0)
    
    # ========== 检测吞没形态 ==========
    is_bullish_engulf = False
    is_bearish_engulf = False
    if prev_bar:
        prev_open = prev_bar.get("open", 0)
        prev_close = prev_bar.get("close", 0)
        prev_body = abs(prev_close - prev_open)
        
        if is_bullish and prev_close < prev_open:  # 当前阳线，前一根阴线
            if last_close > prev_open and last_open < prev_close:
                is_bullish_engulf = True
        elif is_bearish and prev_close > prev_open:  # 当前阴线，前一根阳线
            if last_close < prev_open and last_open > prev_close:
                is_bearish_engulf = True
    
    # ========== 检测连续下跌/上涨 ==========
    consecutive_down = 0
    consecutive_up = 0
    for i in range(2, min(6, len(ohlcv_bars))):
        bar = ohlcv_bars[-i]
        if bar.get("close", 0) < bar.get("open", 0):
            consecutive_down += 1
        else:
            break
    for i in range(2, min(6, len(ohlcv_bars))):
        bar = ohlcv_bars[-i]
        if bar.get("close", 0) > bar.get("open", 0):
            consecutive_up += 1
        else:
            break
    
    # ========== 综合判断 ==========
    
    # V底信号: 连跌+锤子/吞没+低位+放量
    if pos_ratio <= 0.35 and (is_hammer or is_bullish_engulf) and consecutive_down >= 2:
        pattern = "HAMMER" if is_hammer else "BULL_ENGULF"
        conf = 0.6
        if volume_ratio > 1.3:
            conf += 0.1
        if consecutive_down >= 3:
            conf += 0.1
        if pos_ratio <= 0.20:
            conf += 0.1
        
        result["signal"] = "V_BOTTOM"
        result["pattern"] = pattern
        result["score"] = min(conf, 0.9)
        result["confidence"] = conf
        result["reason"] = f"连跌{consecutive_down}根+{pattern}+低位{pos_ratio:.0%}"
        return result
    
    # V顶信号: 连涨+上吊/吞没+高位+放量
    if pos_ratio >= 0.65 and (is_hanging_man or is_bearish_engulf) and consecutive_up >= 2:
        pattern = "HANGING_MAN" if is_hanging_man else "BEAR_ENGULF"
        conf = 0.6
        if volume_ratio > 1.3:
            conf += 0.1
        if consecutive_up >= 3:
            conf += 0.1
        if pos_ratio >= 0.80:
            conf += 0.1
        
        result["signal"] = "V_TOP"
        result["pattern"] = pattern
        result["score"] = -min(conf, 0.9)
        result["confidence"] = conf
        result["reason"] = f"连涨{consecutive_up}根+{pattern}+高位{pos_ratio:.0%}"
        return result
    
    # 区间底部反弹信号
    if pos_ratio <= 0.25 and is_bullish and (is_hammer or body > bar_range * 0.6):
        pattern = "HAMMER" if is_hammer else "BULL_BAR"
        conf = 0.5
        if volume_ratio > 1.2:
            conf += 0.1
        
        result["signal"] = "RANGE_LOW"
        result["pattern"] = pattern
        result["score"] = conf
        result["confidence"] = conf
        result["reason"] = f"区间底部{pos_ratio:.0%}+{pattern}"
        return result
    
    # 区间顶部受阻信号
    if pos_ratio >= 0.75 and is_bearish and (is_hanging_man or body > bar_range * 0.6):
        pattern = "HANGING_MAN" if is_hanging_man else "BEAR_BAR"
        conf = 0.5
        if volume_ratio > 1.2:
            conf += 0.1
        
        result["signal"] = "RANGE_HIGH"
        result["pattern"] = pattern
        result["score"] = -conf
        result["confidence"] = conf
        result["reason"] = f"区间顶部{pos_ratio:.0%}+{pattern}"
        return result
    
    # 单根锤子线（位置中性）
    if is_hammer and is_bullish:
        result["signal"] = "HAMMER"
        result["pattern"] = "HAMMER"
        result["score"] = 0.3
        result["confidence"] = 0.4
        result["reason"] = "单根锤子线"
        return result
    
    # 单根上吊线（位置中性）
    if is_hanging_man and is_bearish:
        result["signal"] = "HANGING"
        result["pattern"] = "HANGING_MAN"
        result["score"] = -0.3
        result["confidence"] = 0.4
        result["reason"] = "单根上吊线"
        return result
    
    return result


def l1_l2_negotiate(l1_bias: str, l2_bias: str, l1_confidence: float = 0.5) -> dict:
    """
    v2.800: L1-L2 协商矩阵
    
    25种组合的决策逻辑
    
    Args:
        l1_bias: L1趋势视觉信号 (STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL)  # v3.340: 统一格式
        l2_bias: L2执行层信号 (STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL)
        l1_confidence: L1置信度
    
    Returns:
        {
            "final_action": str,    # BUY/SELL/HOLD
            "confidence": float,    # 最终置信度
            "agreement": str,       # 协商结果类型
            "l1_wins": bool,        # L1是否胜出
            "reason": str,          # 协商理由
        }
    """
    
    # L1-L2 决策矩阵
    # 格式: (final_action, agreement_type, l1_wins)
    MATRIX = {
        # L1=STRONG_BUY
        ("STRONG_BUY", "STRONG_BUY"): ("BUY", "DOUBLE_CONFIRM_BUY", False, 0.95),
        ("STRONG_BUY", "BUY"):     ("BUY", "L1_STRONG_L2_OK", False, 0.85),
        ("STRONG_BUY", "HOLD"): ("BUY", "L1_STRONG_OVERRIDE", True, 0.75),
        ("STRONG_BUY", "SELL"):    ("BUY", "L1_STRONG_OVERRIDE", True, 0.65),
        ("STRONG_BUY", "STRONG_SELL"):("HOLD", "L1_L2_CONFLICT", False, 0.5),
        
        # L1=BUY (v3.340: WEAK_BUY → BUY)
        ("BUY", "STRONG_BUY"):   ("BUY", "L2_CONFIRM_BUY", False, 0.85),
        ("BUY", "BUY"):          ("BUY", "L1_L2_AGREE_BUY", False, 0.7),
        ("BUY", "HOLD"):         ("HOLD", "L1_NO_OVERRIDE", False, 0.5),
        ("BUY", "SELL"):         ("HOLD", "L2_VETO_L1", False, 0.5),
        ("BUY", "STRONG_SELL"):  ("HOLD", "L2_VETO_L1", False, 0.5),
        
        # L1=HOLD (v3.340: NEUTRAL → HOLD)
        ("HOLD", "STRONG_BUY"):    ("BUY", "L2_LEAD_BUY", False, 0.7),
        ("HOLD", "BUY"):           ("HOLD", "L1_HOLD", False, 0.5),
        ("HOLD", "HOLD"):          ("HOLD", "L1_HOLD", False, 0.5),
        ("HOLD", "SELL"):          ("HOLD", "L1_HOLD", False, 0.5),
        ("HOLD", "STRONG_SELL"):   ("SELL", "L2_LEAD_SELL", False, 0.7),
        
        # L1=SELL (v3.340: WEAK_SELL → SELL)
        ("SELL", "STRONG_BUY"):  ("HOLD", "L2_VETO_L1", False, 0.5),
        ("SELL", "BUY"):         ("HOLD", "L2_VETO_L1", False, 0.5),
        ("SELL", "HOLD"):        ("HOLD", "L1_NO_OVERRIDE", False, 0.5),
        ("SELL", "SELL"):        ("SELL", "L1_L2_AGREE_SELL", False, 0.7),
        ("SELL", "STRONG_SELL"): ("SELL", "L2_CONFIRM_SELL", False, 0.85),
        
        # L1=STRONG_SELL
        ("STRONG_SELL", "STRONG_BUY"):("HOLD", "L1_L2_CONFLICT", False, 0.5),
        ("STRONG_SELL", "BUY"):    ("SELL", "L1_STRONG_OVERRIDE", True, 0.65),
        ("STRONG_SELL", "HOLD"):("SELL", "L1_STRONG_OVERRIDE", True, 0.75),
        ("STRONG_SELL", "SELL"):   ("SELL", "L1_STRONG_L2_OK", False, 0.85),
        ("STRONG_SELL", "STRONG_SELL"):("SELL", "DOUBLE_CONFIRM_SELL", False, 0.95),
    }
    
    key = (l1_bias, l2_bias)
    if key in MATRIX:
        action, agreement, l1_wins, conf = MATRIX[key]
        # 调整置信度（结合L1原始置信度）
        final_conf = (conf + l1_confidence) / 2 if l1_wins else conf
        
        return {
            "final_action": action,
            "confidence": round(final_conf, 3),
            "agreement": agreement,
            "l1_wins": l1_wins,
            "reason": f"L1={l1_bias} + L2={l2_bias} → {agreement}",
        }
    
    # 默认情况
    return {
        "final_action": "HOLD",
        "confidence": 0.5,
        "agreement": "UNKNOWN",
        "l1_wins": False,
        "reason": f"未知组合: L1={l1_bias}, L2={l2_bias}",
    }


# ============================================================================
# v2.900: L1 统一信号 - 三方协商架构
# ============================================================================
# 
# v2.900 重大架构升级:
#   - v2.850: AI(50%) + Vision(50%) → Grid门控
#   - v2.900: AI(35%) + Human(35%) + Tech(30%) 三方协商 → Grid门控
#
# ============================================================================

def compute_l1_unified_signal(
    llm_action: str,
    llm_confidence: float,
    grid_action: str,
    grid_confidence: float,
    trend_vision: dict,
    market_regime: str = "RANGE",
    visual_material: dict = None,  # v2.850: 统一视觉素材
    # v2.900: 新增参数
    ohlcv_bars: list = None,       # v2.900: K线数据用于三方协商
    pos_ratio: float = 0.5,        # v2.900: 位置比例
    llm_result: dict = None,       # v2.900: 完整LLM结果
    tv_data: dict = None,          # v2.900: TV推送数据
    reason_bullets: list = None,   # v2.900: LLM reason_bullets
    use_three_way: bool = True,    # v2.900: 是否使用三方协商
    symbol: str = None,            # v2.905: symbol用于动态校准
    trend_x4: str = None,          # v2.920: 4倍周期趋势
    trend_x8: str = None,          # v2.920: 8倍周期趋势
    dow_trend_details: dict = None,  # v3.260: 道氏理论判断详情
) -> dict:
    """
    v2.900/v2.905/v2.920: L1统一信号 - 三方协商架构
    
    架构变更:
    - v2.820: LLM(35%) + Grid(30%) + Vision(35%) 三者加权
    - v2.850: AI+Vision(各50%)先融合 → Grid作为硬规则门控
    - v2.900: AI(35%) + Human(35%) + Tech(30%) 三方协商 → Grid门控
    - v2.905: 动态权重校准 (根据历史准确率调整)
    - v2.920: 顺大逆小增强 (Human/Tech使用多周期趋势)
    
    v2.920新增:
    - trend_x4/trend_x8传递给Human和Tech
    - 顺大逆小检测: 大趋势+小回调 = 入场机会
    
    Args:
        llm_action: LLM原始动作 (BUY/SELL/HOLD)
        llm_confidence: LLM置信度 (0-1)
        grid_action: Grid规则动作 (BUY/SELL/HOLD/NO_TRADE 或 None)
        grid_confidence: Grid置信度 (0-1)
        trend_vision: L1趋势视觉结果 {l1_bias, confidence, score, ...}
        market_regime: 市场regime
        visual_material: v2.850统一视觉素材
        ohlcv_bars: v2.900 K线数据
        pos_ratio: v2.900 位置比例
        llm_result: v2.900 完整LLM结果
        tv_data: v2.900 TV推送数据
        reason_bullets: v2.900 LLM reason_bullets
        use_three_way: v2.900 是否使用三方协商 (默认True)
        symbol: v2.905 交易对 (用于动态校准)
        trend_x4: v2.920 4倍周期趋势 (up/down/side)
        trend_x8: v2.920 8倍周期趋势 (up/down/side)
    
    Returns:
        {
            "signal": str,           # STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL
            "action": str,           # BUY/HOLD/SELL
            "confidence": float,
            "final_score": float,
            "agreement_level": str,  # v2.900: THREE_AGREE/TWO_AGREE/THREE_SPLIT/CONFLICT
            "components": dict,
            "reasoning": str,
            "grid_gate": dict,
            "three_way": dict,       # v2.900: 三方协商详情
            "dynamic_weights": dict, # v2.905: 动态权重信息
        }
    """
    
    # ========== v2.900: 三方协商架构 ==========
    if use_three_way and ohlcv_bars and len(ohlcv_bars) >= 5:
        # 构建LLM结果
        if llm_result is None:
            llm_result = {
                "action": llm_action,
                "confidence": llm_confidence,
            }
        
        # 从decision获取reason_bullets
        if reason_bullets is None and isinstance(llm_result, dict):
            reason_bullets = llm_result.get("reason_bullets", [])
        
        # 调用v2.900三方协商 (v2.905: 传递symbol用于动态校准) (v2.920: 传入trend_x4/x8) (v3.260: 道氏理论)
        three_way_result = compute_l1_three_way_signal_v2900(
            llm_result=llm_result,
            ohlcv_bars=ohlcv_bars,
            pos_ratio=pos_ratio,
            grid_action=grid_action,
            grid_confidence=grid_confidence,
            tv_data=tv_data,
            reason_bullets=reason_bullets,
            symbol=symbol,  # v2.905
            trend_x4=trend_x4,  # v2.920
            trend_x8=trend_x8,  # v2.920
            dow_trend_details=dow_trend_details,  # v3.260
        )
        
        # 转换为兼容格式
        return {
            "signal": three_way_result["signal"],
            "action": three_way_result["action"],
            "confidence": three_way_result["confidence"],
            "final_score": three_way_result["final_score"],
            "agreement_level": three_way_result["agreement_level"],
            "agreement_detail": three_way_result["three_way"]["consensus_type"],
            "components": three_way_result["components"],
            "reasoning": three_way_result["reasoning"],
            "market_regime": three_way_result.get("market_regime", {}),  # v2.960修复: 使用三方协商的市场状态字典
            "grid_gate": three_way_result["grid_gate"],
            "three_way": three_way_result["three_way"],
            "dynamic_weights": three_way_result.get("dynamic_weights"),  # v2.905
            # v2.900: 向下兼容字段
            "ai_vision_fusion": {
                "fused_score": three_way_result["final_score"],
                "fused_action": three_way_result["action"],
                "agreement": three_way_result["three_way"]["consensus_type"],
                "adjustments": [],
            },
            "v3300_five_module": three_way_result.get("v3300_five_module"),  # v3.300: L1五模块框架
        }
    
    # ========== 回退: v2.850 AI+Vision融合 ==========
    # 当没有足够的OHLCV数据或禁用三方协商时使用
    
    # v3.320: 即使在回退模式，也解析AI信号以获取ai_x4_regime
    fallback_ai_signals = {}
    if llm_result is None:
        llm_result = {"action": llm_action, "confidence": llm_confidence}
    if reason_bullets is None and isinstance(llm_result, dict):
        reason_bullets = llm_result.get("reason_bullets", [])
    try:
        fallback_ai_signals = compute_ai_signals_v2900(llm_result, reason_bullets)
        log_to_server(f"[v3.320] 回退模式AI解析: x4_regime={fallback_ai_signals.get('x4_regime', 'UNKNOWN')}")
    except Exception as e:
        log_to_server(f"[v3.320] 回退模式AI解析失败: {e}")
        fallback_ai_signals = {"x4_regime": "UNKNOWN", "current_regime": "UNKNOWN"}

    # 调用v2.850的融合函数
    if visual_material and visual_material.get("ready"):
        fusion = compute_l1_ai_vision_fusion(
            llm_action=llm_action,
            llm_confidence=llm_confidence,
            vision_result=trend_vision,
            visual_material=visual_material,
        )
    else:
        # 没有统一素材时，使用简化融合
        fusion = _simple_ai_vision_fusion(llm_action, llm_confidence, trend_vision)
    
    ai_vision_score = fusion["fused_score"]
    ai_vision_action = fusion["fused_action"]
    ai_vision_conf = fusion["fused_confidence"]
    ai_vision_agreement = fusion["agreement"]
    
    # Grid 硬规则门控
    grid_gate = {
        "applied": False,
        "rule": grid_action,
        "effect": "NONE",
        "reason": "",
    }
    
    final_score = ai_vision_score
    final_action = ai_vision_action
    
    # Grid门控逻辑
    if grid_action:
        # Grid=NO_TRADE: 强制HOLD
        if grid_action == "NO_TRADE" or grid_confidence >= 0.9 and grid_action == "HOLD":
            final_action = "HOLD"
            final_score = 0.0
            grid_gate["applied"] = True
            grid_gate["effect"] = "HOLD"
            grid_gate["reason"] = "Grid禁止交易"
        
        # Grid强买 vs AI+Vision偏空 → 冲突降级
        elif grid_action == "BUY" and ai_vision_score < -0.2:
            final_action = "HOLD"
            final_score *= 0.5
            grid_gate["applied"] = True
            grid_gate["effect"] = "CONFLICT_HOLD"
            grid_gate["reason"] = "Grid看多但AI+Vision看空"
        
        # Grid强卖 vs AI+Vision偏多 → 冲突降级
        elif grid_action == "SELL" and ai_vision_score > 0.2:
            final_action = "HOLD"
            final_score *= 0.5
            grid_gate["applied"] = True
            grid_gate["effect"] = "CONFLICT_HOLD"
            grid_gate["reason"] = "Grid看空但AI+Vision看多"
        
        # Grid与AI+Vision同向 → 确认加强
        elif grid_action == "BUY" and ai_vision_score > 0:
            final_score *= 1.15
            grid_gate["applied"] = True
            grid_gate["effect"] = "CONFIRM_BUY"
            grid_gate["reason"] = "Grid确认做多"
        
        elif grid_action == "SELL" and ai_vision_score < 0:
            final_score *= 1.15
            grid_gate["applied"] = True
            grid_gate["effect"] = "CONFIRM_SELL"
            grid_gate["reason"] = "Grid确认做空"
        
        # Grid中性，不干预
        else:
            grid_gate["effect"] = "NEUTRAL"
            grid_gate["reason"] = "Grid不干预"
    
    # 限制分数范围
    final_score = max(-1.0, min(1.0, final_score))
    
    # 映射到5档信号
    if ai_vision_agreement == "AGREE":
        STRONG_THRESHOLD = 0.45
        WEAK_THRESHOLD = 0.20
    elif ai_vision_agreement == "CONFLICT":
        STRONG_THRESHOLD = 0.60
        WEAK_THRESHOLD = 0.35
    else:  # PARTIAL
        STRONG_THRESHOLD = 0.50
        WEAK_THRESHOLD = 0.25
    
    if final_score >= STRONG_THRESHOLD:
        signal = "STRONG_BUY"
        action = "BUY"
    elif final_score >= WEAK_THRESHOLD:
        signal = "BUY"
        action = "BUY"
    elif final_score <= -STRONG_THRESHOLD:
        signal = "STRONG_SELL"
        action = "SELL"
    elif final_score <= -WEAK_THRESHOLD:
        signal = "SELL"
        action = "SELL"
    else:
        signal = "HOLD"
        action = "HOLD"
    
    # Grid门控覆盖
    if grid_gate["effect"] == "HOLD":
        signal = "HOLD"
        action = "HOLD"
    elif grid_gate["effect"] == "CONFLICT_HOLD":
        signal = "HOLD"
        action = "HOLD"
    
    confidence = min(abs(final_score) / 0.7, 1.0)
    
    # 生成理由
    reason_parts = []
    reason_parts.append(f"AI+Vision={ai_vision_action}({ai_vision_conf:.2f})")
    
    if fusion.get("adjustments"):
        for adj in fusion["adjustments"][:2]:
            reason_parts.append(adj)
    
    if grid_gate["applied"]:
        reason_parts.append(f"Grid:{grid_gate['reason']}")
    
    if ai_vision_agreement == "AGREE":
        reason_parts.append("✓AI+Vision一致")
    elif ai_vision_agreement == "CONFLICT":
        reason_parts.append("⚠AI+Vision冲突")
    
    reasoning = " | ".join(reason_parts) if reason_parts else "无明确信号"
    
    # 提取Vision信息
    l1_bias = trend_vision.get("l1_bias", "HOLD") if trend_vision else "HOLD"  # v3.340: 统一格式
    l1_conf = trend_vision.get("confidence", 0.5) if trend_vision else 0.5
    l1_score_raw = trend_vision.get("score", 0.0) if trend_vision else 0.0
    
    return {
        "signal": signal,
        "action": action,
        "confidence": round(confidence, 3),
        "final_score": round(final_score, 4),
        "agreement_level": ai_vision_agreement.upper() if ai_vision_agreement else "PARTIAL",
        "agreement_detail": ai_vision_agreement,
        "components": {
            "llm": {
                "action": llm_action,
                "confidence": llm_confidence,
                "score": round(fusion["llm_contrib"] * 2, 3),
                "weight": 0.50,
                "weighted": round(fusion["llm_contrib"], 4),
            },
            "grid": {
                "action": grid_action,
                "confidence": grid_confidence,
                "score": 0.0,
                "weight": 0.0,
                "weighted": 0.0,
                "gate_effect": grid_gate["effect"],
            },
            "vision": {
                "bias": l1_bias,
                "confidence": l1_conf,
                "raw_score": round(l1_score_raw, 3),
                "score": round(fusion["vision_contrib"] * 2, 3),
                "weight": 0.50,
                "weighted": round(fusion["vision_contrib"], 4),
            },
        },
        "reasoning": reasoning,
        "market_regime": market_regime,
        "grid_gate": grid_gate,
        "ai_vision_fusion": {
            "fused_score": fusion["fused_score"],
            "fused_action": fusion["fused_action"],
            "agreement": fusion["agreement"],
            "adjustments": fusion.get("adjustments", []),
        },
        "three_way": None,  # v2.900: 回退模式无三方协商
        # v3.320: 回退模式也提供五模块数据用于监控显示
        "v3300_five_module": {
            "signal": signal,
            "confidence": confidence,
            "reason": "回退模式(OHLCV数据不足)",
            "ai_module": {
                "big_trend": "SIDE",  # 回退模式默认震荡
                "consensus": "FALLBACK",
                "confidence": 0.5,
                "detail": {
                    "ai_x4_regime": fallback_ai_signals.get("x4_regime", "UNKNOWN"),
                    "current_regime": fallback_ai_signals.get("current_regime", "UNKNOWN"),
                    "tech_regime": "UNKNOWN",
                    "adx": 0,
                    "choppiness": 50,
                },
            },
            "human_module": {"phase": "UNKNOWN", "detail": {}},
            "tech_module": {"strength": "UNKNOWN", "detail": {"adx": 0, "choppiness": 50}},
            "grid_module": {"position": "UNKNOWN", "detail": {}},
        },
    }


def _simple_ai_vision_fusion(llm_action: str, llm_confidence: float, vision_result: dict) -> dict:
    """
    [DEPRECATED v3.370] 简化版AI+Vision融合 (无统一素材时使用)

    ⚠️ 此函数已废弃，仅作为回退模式使用
    ⚠️ 新架构使用 compute_l1_five_module_v3300() 替代
    ⚠️ 当K线数据不足且无统一素材时才会调用此函数
    """
    # v3.370: 废弃警告
    print("[DEPRECATED] _simple_ai_vision_fusion() 已废弃，请使用 compute_l1_five_module_v3300()")

    # LLM评分
    if llm_action == "BUY":
        llm_score = llm_confidence
    elif llm_action == "SELL":
        llm_score = -llm_confidence
    else:
        llm_score = 0.0
    
    # Vision评分
    vision_score = vision_result.get("score", 0.0) if vision_result else 0.0
    vision_bias = vision_result.get("l1_bias", "HOLD") if vision_result else "HOLD"  # v3.340: 统一格式
    
    # 基础融合
    fused_score = llm_score * 0.5 + vision_score * 0.5
    
    # 一致性检测
    llm_dir = 1 if llm_action == "BUY" else (-1 if llm_action == "SELL" else 0)
    vision_dir = 1 if vision_bias in ["STRONG_BUY", "BUY"] else (-1 if vision_bias in ["STRONG_SELL", "SELL"] else 0)  # v3.340: 统一格式
    
    if llm_dir == vision_dir and llm_dir != 0:
        agreement = "AGREE"
        fused_score *= 1.1
    elif llm_dir == -vision_dir and llm_dir != 0:
        agreement = "CONFLICT"
        fused_score *= 0.7
    else:
        agreement = "PARTIAL"
    
    # 确定动作
    if fused_score >= 0.15:
        fused_action = "BUY"
    elif fused_score <= -0.15:
        fused_action = "SELL"
    else:
        fused_action = "HOLD"
    
    return {
        "fused_score": round(fused_score, 4),
        "fused_action": fused_action,
        "fused_confidence": round(min(abs(fused_score) / 0.6, 1.0), 3),
        "agreement": agreement,
        "llm_contrib": round(llm_score * 0.5, 4),
        "vision_contrib": round(vision_score * 0.5, 4),
        "adjustments": [],
    }


# ============================================================================
# v2.800: L1 Trend Vision 模块结束
# ============================================================================


# ============================================================================
# v2.750: K线强信号检测模块 (Candle Strong Signal Detection)
# ============================================================================
# 
# 核心理念：K线是价格行为的第一手信号，应优先于滞后指标
#
# 信号类型:
#   1. V型反转（V_BOTTOM/V_TOP）- 最强信号
#   2. 震荡顶底（RANGE_LOW_BOUNCE/RANGE_HIGH_REJECT）
#   3. 趋势突破（TREND_BREAKOUT/TREND_BREAKDOWN）
#   4. 连续动量（MOMENTUM_UP/MOMENTUM_DOWN）
#
# ============================================================================

def detect_candle_strong_signal(
    ohlcv_bars: list,
    market_regime: str = "RANGE",
    swing_support: float = 0.0,
    swing_resistance: float = 0.0,
    pos_ratio: float = 0.5,
) -> dict:
    """
    v2.750: K线强信号检测主函数
    
    检测优先级:
        1. V型反转（最高优先级）
        2. 震荡顶底
        3. 趋势突破
        4. 连续动量
    
    Args:
        ohlcv_bars: K线数据
        market_regime: 市场regime (RANGE/UPTREND_RIDE/DOWNTREND_RIDE)
        swing_support: swing支撑位
        swing_resistance: swing阻力位
        pos_ratio: 价格在区间中的位置 (0=底部, 1=顶部)
    
    Returns:
        {
            "signal": "V_BOTTOM" | "V_TOP" | "RANGE_LOW" | "RANGE_HIGH" | 
                      "TREND_BREAKOUT" | "TREND_BREAKDOWN" | "MOMENTUM_UP" | 
                      "MOMENTUM_DOWN" | "NONE",
            "action": "BUY" | "SELL" | "HOLD",
            "confidence": 0.0 - 1.0,
            "reason": str,
            "candle_pattern": str,  # 识别到的K线形态
            "volume_confirm": bool,  # 成交量确认
            "detail": dict,  # 详细信息
        }
    """
    result = {
        "signal": "NONE",
        "action": "HOLD",
        "confidence": 0.0,
        "reason": "",
        "candle_pattern": "NONE",
        "volume_confirm": False,
        "detail": {},
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 8:
        result["reason"] = "数据不足"
        return result
    
    # 计算平均成交量
    volumes = [bar.get("volume", 0) for bar in ohlcv_bars[-20:] if bar.get("volume", 0) > 0]
    avg_volume = sum(volumes) / len(volumes) if volumes else 0
    last_volume = ohlcv_bars[-1].get("volume", 0)
    volume_ratio = last_volume / avg_volume if avg_volume > 0 else 1.0
    
    # 优先级1：检测V型反转
    v_result = detect_v_reversal(ohlcv_bars, avg_volume)
    if v_result["detected"]:
        result["signal"] = v_result["type"]
        result["action"] = "BUY" if v_result["type"] == "V_BOTTOM" else "SELL"
        result["confidence"] = v_result["confidence"]
        result["reason"] = v_result["reason"]
        result["candle_pattern"] = v_result["pattern"]
        result["volume_confirm"] = v_result["volume_confirm"]
        result["detail"] = v_result
        print(f"[v2.750 K线信号] ⚡ {result['signal']}: {result['reason']} (置信度:{result['confidence']:.2f})")
        return result
    
    # 优先级2：检测震荡顶底
    if market_regime == "RANGE" or abs(pos_ratio - 0.5) > 0.3:
        range_result = detect_range_bounce(
            ohlcv_bars, 
            pos_ratio=pos_ratio,
            swing_support=swing_support,
            swing_resistance=swing_resistance,
            avg_volume=avg_volume
        )
        if range_result["detected"]:
            result["signal"] = range_result["type"]
            result["action"] = "BUY" if "LOW" in range_result["type"] else "SELL"
            result["confidence"] = range_result["confidence"]
            result["reason"] = range_result["reason"]
            result["candle_pattern"] = range_result["pattern"]
            result["volume_confirm"] = range_result["volume_confirm"]
            result["detail"] = range_result
            print(f"[v2.750 K线信号] 📊 {result['signal']}: {result['reason']} (置信度:{result['confidence']:.2f})")
            return result
    
    # 优先级3：检测趋势突破
    breakout_result = detect_trend_breakout(
        ohlcv_bars,
        swing_support=swing_support,
        swing_resistance=swing_resistance,
        avg_volume=avg_volume
    )
    if breakout_result["detected"]:
        result["signal"] = breakout_result["type"]
        result["action"] = "BUY" if "BREAKOUT" in breakout_result["type"] else "SELL"
        result["confidence"] = breakout_result["confidence"]
        result["reason"] = breakout_result["reason"]
        result["candle_pattern"] = breakout_result["pattern"]
        result["volume_confirm"] = breakout_result["volume_confirm"]
        result["detail"] = breakout_result
        print(f"[v2.750 K线信号] 🚀 {result['signal']}: {result['reason']} (置信度:{result['confidence']:.2f})")
        return result
    
    # 优先级4：检测连续动量
    momentum_result = detect_continuous_momentum(ohlcv_bars, avg_volume)
    if momentum_result["detected"]:
        result["signal"] = momentum_result["type"]
        result["action"] = "BUY" if "UP" in momentum_result["type"] else "SELL"
        result["confidence"] = momentum_result["confidence"]
        result["reason"] = momentum_result["reason"]
        result["candle_pattern"] = momentum_result["pattern"]
        result["volume_confirm"] = momentum_result["volume_confirm"]
        result["detail"] = momentum_result
        print(f"[v2.750 K线信号] 📈 {result['signal']}: {result['reason']} (置信度:{result['confidence']:.2f})")
        return result
    
    result["reason"] = "无K线强信号"
    return result


def detect_v_reversal(ohlcv_bars: list, avg_volume: float) -> dict:
    """
    v2.750: V型反转检测
    
    V型底部条件:
        1. 前期连续下跌（3根以上阴线或高低点持续下降）
        2. 关键反转K线（锤子线/吞没阳线/长下影线）
        3. 放量确认（成交量 > 1.3倍平均）
        4. 突破确认（收盘价突破前一根高点）
    
    V型顶部条件（反向）
    """
    result = {
        "detected": False,
        "type": "NONE",
        "confidence": 0.0,
        "reason": "",
        "pattern": "NONE",
        "volume_confirm": False,
        "consecutive_bars": 0,
    }
    
    if len(ohlcv_bars) < 6:
        return result
    
    last = ohlcv_bars[-1]
    prev = ohlcv_bars[-2]
    last_volume = last.get("volume", 0)
    volume_ratio = last_volume / avg_volume if avg_volume > 0 else 1.0
    
    # ========== V型底部检测 ==========
    
    # 检查前期下跌（看最近5根K线）
    down_bars = 0
    lower_lows = 0
    for i in range(-5, -1):
        bar = ohlcv_bars[i]
        prev_bar = ohlcv_bars[i-1]
        if bar["close"] < bar["open"]:  # 阴线
            down_bars += 1
        if bar["low"] < prev_bar["low"]:  # 低点下降
            lower_lows += 1
    
    is_downtrend = down_bars >= 3 or lower_lows >= 3
    
    if is_downtrend:
        # 检查反转K线形态
        last_body = last["close"] - last["open"]
        last_range = last["high"] - last["low"]
        lower_shadow = min(last["open"], last["close"]) - last["low"]
        upper_shadow = last["high"] - max(last["open"], last["close"])
        
        is_bullish = last["close"] > last["open"]
        is_hammer = (lower_shadow > abs(last_body) * 1.5 and 
                     upper_shadow < abs(last_body) * 0.5 and
                     last_range > 0)
        is_engulf = (is_bullish and 
                     last["close"] > prev["open"] and 
                     last["open"] < prev["close"])
        is_strong_bull = (is_bullish and 
                          abs(last_body) > last_range * 0.6)
        
        # 检查是否突破前一根高点
        breaks_prev_high = last["close"] > prev["high"]
        
        # 成交量确认
        volume_confirm = volume_ratio >= 1.3
        
        pattern = "NONE"
        if is_hammer:
            pattern = "HAMMER"
        elif is_engulf:
            pattern = "ENGULF_BULL"
        elif is_strong_bull:
            pattern = "STRONG_BULL"
        
        if pattern != "NONE" and (breaks_prev_high or volume_confirm):
            confidence = 0.5
            if volume_confirm:
                confidence += 0.15
            if breaks_prev_high:
                confidence += 0.15
            if down_bars >= 4:
                confidence += 0.1
            if is_engulf:
                confidence += 0.1
            
            result["detected"] = True
            result["type"] = "V_BOTTOM"
            result["confidence"] = min(confidence, 0.95)
            result["reason"] = f"连跌{down_bars}根后{pattern}反转"
            result["pattern"] = pattern
            result["volume_confirm"] = volume_confirm
            result["consecutive_bars"] = down_bars
            return result
    
    # ========== V型顶部检测 ==========
    
    # 检查前期上涨
    up_bars = 0
    higher_highs = 0
    for i in range(-5, -1):
        bar = ohlcv_bars[i]
        prev_bar = ohlcv_bars[i-1]
        if bar["close"] > bar["open"]:  # 阳线
            up_bars += 1
        if bar["high"] > prev_bar["high"]:  # 高点上升
            higher_highs += 1
    
    is_uptrend = up_bars >= 3 or higher_highs >= 3
    
    if is_uptrend:
        # 检查反转K线形态
        last_body = last["close"] - last["open"]
        last_range = last["high"] - last["low"]
        lower_shadow = min(last["open"], last["close"]) - last["low"]
        upper_shadow = last["high"] - max(last["open"], last["close"])
        
        is_bearish = last["close"] < last["open"]
        is_shooting_star = (upper_shadow > abs(last_body) * 1.5 and 
                            lower_shadow < abs(last_body) * 0.5 and
                            last_range > 0)
        is_engulf = (is_bearish and 
                     last["close"] < prev["open"] and 
                     last["open"] > prev["close"])
        is_strong_bear = (is_bearish and 
                          abs(last_body) > last_range * 0.6)
        
        # 检查是否跌破前一根低点
        breaks_prev_low = last["close"] < prev["low"]
        
        # 成交量确认
        volume_confirm = volume_ratio >= 1.3
        
        pattern = "NONE"
        if is_shooting_star:
            pattern = "SHOOTING_STAR"
        elif is_engulf:
            pattern = "ENGULF_BEAR"
        elif is_strong_bear:
            pattern = "STRONG_BEAR"
        
        if pattern != "NONE" and (breaks_prev_low or volume_confirm):
            confidence = 0.5
            if volume_confirm:
                confidence += 0.15
            if breaks_prev_low:
                confidence += 0.15
            if up_bars >= 4:
                confidence += 0.1
            if is_engulf:
                confidence += 0.1
            
            result["detected"] = True
            result["type"] = "V_TOP"
            result["confidence"] = min(confidence, 0.95)
            result["reason"] = f"连涨{up_bars}根后{pattern}反转"
            result["pattern"] = pattern
            result["volume_confirm"] = volume_confirm
            result["consecutive_bars"] = up_bars
            return result
    
    return result


def detect_range_bounce(
    ohlcv_bars: list, 
    pos_ratio: float,
    swing_support: float,
    swing_resistance: float,
    avg_volume: float
) -> dict:
    """
    v2.750: 震荡顶底检测
    
    底部反弹条件:
        1. pos_ratio < 0.25（在区间下沿25%以内）
        2. 出现看涨K线形态
        3. 可选：放量确认
    
    顶部回落条件（反向）
    """
    result = {
        "detected": False,
        "type": "NONE",
        "confidence": 0.0,
        "reason": "",
        "pattern": "NONE",
        "volume_confirm": False,
    }
    
    if len(ohlcv_bars) < 3:
        return result
    
    last = ohlcv_bars[-1]
    prev = ohlcv_bars[-2]
    last_volume = last.get("volume", 0)
    volume_ratio = last_volume / avg_volume if avg_volume > 0 else 1.0
    volume_confirm = volume_ratio >= 1.2
    
    last_body = last["close"] - last["open"]
    last_range = last["high"] - last["low"]
    is_bullish = last["close"] > last["open"]
    is_bearish = last["close"] < last["open"]
    
    # ========== 底部反弹检测 ==========
    if pos_ratio < 0.25:
        # 检查看涨形态
        lower_shadow = min(last["open"], last["close"]) - last["low"]
        is_hammer = (lower_shadow > abs(last_body) * 1.2 and last_range > 0)
        is_bullish_strong = (is_bullish and abs(last_body) > last_range * 0.5)
        is_engulf = (is_bullish and 
                     prev["close"] < prev["open"] and  # 前一根阴线
                     last["close"] > prev["open"])
        
        # 检查是否接近支撑位
        near_support = (swing_support > 0 and 
                        last["low"] <= swing_support * 1.02)
        
        pattern = "NONE"
        if is_hammer:
            pattern = "HAMMER"
        elif is_engulf:
            pattern = "ENGULF_BULL"
        elif is_bullish_strong:
            pattern = "STRONG_BULL"
        
        if pattern != "NONE":
            confidence = 0.45
            if volume_confirm:
                confidence += 0.15
            if near_support:
                confidence += 0.15
            if pos_ratio < 0.15:
                confidence += 0.1
            if is_engulf:
                confidence += 0.1
            
            result["detected"] = True
            result["type"] = "RANGE_LOW_BOUNCE"
            result["confidence"] = min(confidence, 0.9)
            result["reason"] = f"区间底部{int(pos_ratio*100)}%+{pattern}"
            result["pattern"] = pattern
            result["volume_confirm"] = volume_confirm
            return result
    
    # ========== 顶部回落检测 ==========
    if pos_ratio > 0.75:
        # 检查看跌形态
        upper_shadow = last["high"] - max(last["open"], last["close"])
        is_shooting = (upper_shadow > abs(last_body) * 1.2 and last_range > 0)
        is_bearish_strong = (is_bearish and abs(last_body) > last_range * 0.5)
        is_engulf = (is_bearish and 
                     prev["close"] > prev["open"] and  # 前一根阳线
                     last["close"] < prev["open"])
        
        # 检查是否接近阻力位
        near_resistance = (swing_resistance > 0 and 
                           last["high"] >= swing_resistance * 0.98)
        
        pattern = "NONE"
        if is_shooting:
            pattern = "SHOOTING_STAR"
        elif is_engulf:
            pattern = "ENGULF_BEAR"
        elif is_bearish_strong:
            pattern = "STRONG_BEAR"
        
        if pattern != "NONE":
            confidence = 0.45
            if volume_confirm:
                confidence += 0.15
            if near_resistance:
                confidence += 0.15
            if pos_ratio > 0.85:
                confidence += 0.1
            if is_engulf:
                confidence += 0.1
            
            result["detected"] = True
            result["type"] = "RANGE_HIGH_REJECT"
            result["confidence"] = min(confidence, 0.9)
            result["reason"] = f"区间顶部{int(pos_ratio*100)}%+{pattern}"
            result["pattern"] = pattern
            result["volume_confirm"] = volume_confirm
            return result
    
    return result


def detect_trend_breakout(
    ohlcv_bars: list,
    swing_support: float,
    swing_resistance: float,
    avg_volume: float
) -> dict:
    """
    v2.750: 趋势突破检测
    
    向上突破条件:
        1. 收盘价突破swing阻力位
        2. 放量确认（成交量 > 1.3倍平均）
        3. K线实体强势（实体 > 60%振幅）
    
    向下突破条件（反向）
    """
    result = {
        "detected": False,
        "type": "NONE",
        "confidence": 0.0,
        "reason": "",
        "pattern": "NONE",
        "volume_confirm": False,
    }
    
    if len(ohlcv_bars) < 3 or swing_resistance <= 0 or swing_support <= 0:
        return result
    
    last = ohlcv_bars[-1]
    prev = ohlcv_bars[-2]
    last_volume = last.get("volume", 0)
    volume_ratio = last_volume / avg_volume if avg_volume > 0 else 1.0
    volume_confirm = volume_ratio >= 1.3
    
    last_body = abs(last["close"] - last["open"])
    last_range = last["high"] - last["low"]
    body_ratio = last_body / last_range if last_range > 0 else 0
    
    is_bullish = last["close"] > last["open"]
    is_bearish = last["close"] < last["open"]
    
    # ========== 向上突破 ==========
    if last["close"] > swing_resistance and prev["close"] <= swing_resistance:
        if is_bullish and body_ratio > 0.5:
            confidence = 0.5
            if volume_confirm:
                confidence += 0.2
            if body_ratio > 0.7:
                confidence += 0.1
            
            breakout_pct = (last["close"] - swing_resistance) / swing_resistance * 100
            
            result["detected"] = True
            result["type"] = "TREND_BREAKOUT"
            result["confidence"] = min(confidence, 0.9)
            result["reason"] = f"突破阻力{swing_resistance:.2f}+{breakout_pct:.1f}%"
            result["pattern"] = "BREAKOUT_BAR"
            result["volume_confirm"] = volume_confirm
            return result
    
    # ========== 向下突破 ==========
    if last["close"] < swing_support and prev["close"] >= swing_support:
        if is_bearish and body_ratio > 0.5:
            confidence = 0.5
            if volume_confirm:
                confidence += 0.2
            if body_ratio > 0.7:
                confidence += 0.1
            
            breakdown_pct = (swing_support - last["close"]) / swing_support * 100
            
            result["detected"] = True
            result["type"] = "TREND_BREAKDOWN"
            result["confidence"] = min(confidence, 0.9)
            result["reason"] = f"跌破支撑{swing_support:.2f}-{breakdown_pct:.1f}%"
            result["pattern"] = "BREAKDOWN_BAR"
            result["volume_confirm"] = volume_confirm
            return result
    
    return result


def detect_continuous_momentum(ohlcv_bars: list, avg_volume: float) -> dict:
    """
    v2.750: 连续动量检测
    
    强势上涨条件:
        1. 连续3根以上阳线
        2. 低点逐步抬升
        3. 收盘价突破前一根高点
    
    强势下跌条件（反向）
    """
    result = {
        "detected": False,
        "type": "NONE",
        "confidence": 0.0,
        "reason": "",
        "pattern": "NONE",
        "volume_confirm": False,
    }
    
    if len(ohlcv_bars) < 5:
        return result
    
    recent_5 = ohlcv_bars[-5:]
    last_volume = recent_5[-1].get("volume", 0)
    volume_ratio = last_volume / avg_volume if avg_volume > 0 else 1.0
    volume_confirm = volume_ratio >= 1.2
    
    # ========== 强势上涨动量 ==========
    bullish_bars = 0
    higher_lows = 0
    higher_closes = 0
    
    for i in range(1, len(recent_5)):
        bar = recent_5[i]
        prev_bar = recent_5[i-1]
        
        if bar["close"] > bar["open"]:
            bullish_bars += 1
        if bar["low"] > prev_bar["low"]:
            higher_lows += 1
        if bar["close"] > prev_bar["close"]:
            higher_closes += 1
    
    # 检查最后一根是否突破前一根高点
    breaks_prev_high = recent_5[-1]["close"] > recent_5[-2]["high"]
    
    if bullish_bars >= 3 and higher_lows >= 2 and breaks_prev_high:
        confidence = 0.45
        if bullish_bars >= 4:
            confidence += 0.1
        if higher_lows >= 3:
            confidence += 0.1
        if volume_confirm:
            confidence += 0.15
        
        result["detected"] = True
        result["type"] = "MOMENTUM_UP"
        result["confidence"] = min(confidence, 0.85)
        result["reason"] = f"连续{bullish_bars}阳+低点抬升"
        result["pattern"] = "MOMENTUM_BULL"
        result["volume_confirm"] = volume_confirm
        return result
    
    # ========== 强势下跌动量 ==========
    bearish_bars = 0
    lower_highs = 0
    lower_closes = 0
    
    for i in range(1, len(recent_5)):
        bar = recent_5[i]
        prev_bar = recent_5[i-1]
        
        if bar["close"] < bar["open"]:
            bearish_bars += 1
        if bar["high"] < prev_bar["high"]:
            lower_highs += 1
        if bar["close"] < prev_bar["close"]:
            lower_closes += 1
    
    # 检查最后一根是否跌破前一根低点
    breaks_prev_low = recent_5[-1]["close"] < recent_5[-2]["low"]
    
    if bearish_bars >= 3 and lower_highs >= 2 and breaks_prev_low:
        confidence = 0.45
        if bearish_bars >= 4:
            confidence += 0.1
        if lower_highs >= 3:
            confidence += 0.1
        if volume_confirm:
            confidence += 0.15
        
        result["detected"] = True
        result["type"] = "MOMENTUM_DOWN"
        result["confidence"] = min(confidence, 0.85)
        result["reason"] = f"连续{bearish_bars}阴+高点下降"
        result["pattern"] = "MOMENTUM_BEAR"
        result["volume_confirm"] = volume_confirm
        return result
    
    return result


# ============================================================================
# v2.750: K线强信号检测模块结束
# ============================================================================


def detect_pa_tag_enhanced(ohlcv_bars, candle_feat, swing_points,
                          donchian_support, donchian_resistance):
    """
    v3.400 增强PA识别 - 新增形态质量评分

    覆盖：
    - BULL_ENGULF / BEAR_ENGULF (带质量等级)
    - PIN_BAR_BULL / PIN_BAR_BEAR (带质量等级)
    - BREAKOUT_UP / BREAKOUT_DOWN / FAKE_BREAKOUT_UP / FAKE_BREAKOUT_DOWN
    - TREND_CONTINUATION_UP / TREND_CONTINUATION_DOWN
    - NONE

    Returns:
        tuple: (pa_tag, quality_score, quality_details)
        - pa_tag: 形态标签
        - quality_score: 质量分 1-3 (1=变形, 2=标准, 3=完美)
        - quality_details: 质量判断详情字典
    """
    if not ohlcv_bars or len(ohlcv_bars) < 2:
        return "NONE", 0, {}

    last = ohlcv_bars[-1]
    prev = ohlcv_bars[-2]

    # 计算K线基础数据
    last_body = abs(last["close"] - last["open"])
    last_range = last["high"] - last["low"]
    last_upper_shadow = last["high"] - max(last["open"], last["close"])
    last_lower_shadow = min(last["open"], last["close"]) - last["low"]

    prev_body = abs(prev["close"] - prev["open"])
    prev_range = prev["high"] - prev["low"]

    # 获取成交量
    last_vol = last.get("volume", 0)
    prev_vol = prev.get("volume", 0)
    vol_ratio = last_vol / prev_vol if prev_vol > 0 else 1.0

    # ═══════════════════════════════════════════════════════════════════════
    # 1. Pin Bar 质量评分 (D1改进)
    # ═══════════════════════════════════════════════════════════════════════
    if candle_feat.get("is_pin_bar_bull"):
        # 计算Pin Bar质量
        quality_score = 1  # 默认变形
        quality_details = {"type": "PIN_BAR_BULL"}

        if last_range > 0:
            body_ratio = last_body / last_range
            lower_shadow_ratio = last_lower_shadow / last_range
            upper_shadow_ratio = last_upper_shadow / last_range

            quality_details["body_ratio"] = round(body_ratio, 3)
            quality_details["lower_shadow_ratio"] = round(lower_shadow_ratio, 3)
            quality_details["vol_ratio"] = round(vol_ratio, 2)

            # 完美Pin Bar: 实体<20%, 下影线>60%, 上影线<10%
            if body_ratio < 0.2 and lower_shadow_ratio > 0.6 and upper_shadow_ratio < 0.1:
                quality_score = 3
                quality_details["quality"] = "PERFECT"
            # 标准Pin Bar: 实体<30%, 下影线>50%
            elif body_ratio < 0.3 and lower_shadow_ratio > 0.5:
                quality_score = 2
                quality_details["quality"] = "STANDARD"
            else:
                quality_details["quality"] = "DEFORMED"

            # 放量加分
            if vol_ratio > 1.5:
                quality_score = min(quality_score + 1, 3)
                quality_details["vol_bonus"] = True

        return "PIN_BAR_BULL", quality_score, quality_details

    if candle_feat.get("is_pin_bar_bear"):
        quality_score = 1
        quality_details = {"type": "PIN_BAR_BEAR"}

        if last_range > 0:
            body_ratio = last_body / last_range
            upper_shadow_ratio = last_upper_shadow / last_range
            lower_shadow_ratio = last_lower_shadow / last_range

            quality_details["body_ratio"] = round(body_ratio, 3)
            quality_details["upper_shadow_ratio"] = round(upper_shadow_ratio, 3)
            quality_details["vol_ratio"] = round(vol_ratio, 2)

            # 完美Pin Bar空头: 实体<20%, 上影线>60%, 下影线<10%
            if body_ratio < 0.2 and upper_shadow_ratio > 0.6 and lower_shadow_ratio < 0.1:
                quality_score = 3
                quality_details["quality"] = "PERFECT"
            elif body_ratio < 0.3 and upper_shadow_ratio > 0.5:
                quality_score = 2
                quality_details["quality"] = "STANDARD"
            else:
                quality_details["quality"] = "DEFORMED"

            if vol_ratio > 1.5:
                quality_score = min(quality_score + 1, 3)
                quality_details["vol_bonus"] = True

        return "PIN_BAR_BEAR", quality_score, quality_details

    # ═══════════════════════════════════════════════════════════════════════
    # 2. Engulfing 力度评分 (D2改进)
    # ═══════════════════════════════════════════════════════════════════════
    last_body_top = max(last["open"], last["close"])
    last_body_bottom = min(last["open"], last["close"])
    prev_body_top = max(prev["open"], prev["close"])
    prev_body_bottom = min(prev["open"], prev["close"])

    # 多头吞没
    if (last["close"] > last["open"] and  # 阳线
        prev["close"] < prev["open"] and  # 前阴线
        last_body_bottom < prev_body_bottom and
        last_body_top > prev_body_top):

        quality_score = 1
        quality_details = {"type": "BULL_ENGULF"}

        # 计算吞没倍数
        if prev_body > 0:
            engulf_ratio = last_body / prev_body
            quality_details["engulf_ratio"] = round(engulf_ratio, 2)
            quality_details["vol_ratio"] = round(vol_ratio, 2)

            # 质量评分: 吞没倍数
            if engulf_ratio >= 2.0:
                quality_score = 3
                quality_details["quality"] = "STRONG"
            elif engulf_ratio >= 1.5:
                quality_score = 2
                quality_details["quality"] = "STANDARD"
            else:
                quality_details["quality"] = "WEAK"

            # 放量加分
            if vol_ratio > 1.5:
                quality_score = min(quality_score + 1, 3)
                quality_details["vol_bonus"] = True

        return "BULL_ENGULF", quality_score, quality_details

    # 空头吞没
    if (last["close"] < last["open"] and  # 阴线
        prev["close"] > prev["open"] and  # 前阳线
        last_body_top > prev_body_top and
        last_body_bottom < prev_body_bottom):

        quality_score = 1
        quality_details = {"type": "BEAR_ENGULF"}

        if prev_body > 0:
            engulf_ratio = last_body / prev_body
            quality_details["engulf_ratio"] = round(engulf_ratio, 2)
            quality_details["vol_ratio"] = round(vol_ratio, 2)

            if engulf_ratio >= 2.0:
                quality_score = 3
                quality_details["quality"] = "STRONG"
            elif engulf_ratio >= 1.5:
                quality_score = 2
                quality_details["quality"] = "STANDARD"
            else:
                quality_details["quality"] = "WEAK"

            if vol_ratio > 1.5:
                quality_score = min(quality_score + 1, 3)
                quality_details["vol_bonus"] = True

        return "BEAR_ENGULF", quality_score, quality_details

    # ═══════════════════════════════════════════════════════════════════════
    # 3. Breakout/Breakdown (D4改进: 假突破质量判断)
    # ═══════════════════════════════════════════════════════════════════════
    last_swing_high = swing_points.get("last_swing_high")
    last_swing_low = swing_points.get("last_swing_low")

    # 真突破：高点突破且收盘站稳
    if last_swing_high and last["high"] > last_swing_high[1]:
        swing_price = last_swing_high[1]
        if last["close"] > swing_price:
            # 真突破质量: 看收盘站稳幅度
            breakout_strength = (last["close"] - swing_price) / swing_price if swing_price > 0 else 0
            quality_score = 3 if breakout_strength > 0.01 else 2 if breakout_strength > 0.005 else 1
            return "BREAKOUT_UP", quality_score, {
                "type": "BREAKOUT_UP",
                "breakout_strength": round(breakout_strength * 100, 2),
                "vol_ratio": round(vol_ratio, 2)
            }
        else:
            # 假突破质量判断
            # 突破幅度
            breakout_extent = (last["high"] - swing_price) / swing_price if swing_price > 0 else 0
            # 回落幅度
            pullback_extent = (last["high"] - last["close"]) / last["high"] if last["high"] > 0 else 0

            quality_score = 1
            quality_details = {
                "type": "FAKE_BREAKOUT_UP",
                "breakout_extent_pct": round(breakout_extent * 100, 2),
                "pullback_extent_pct": round(pullback_extent * 100, 2),
                "vol_ratio": round(vol_ratio, 2)
            }

            # 假突破质量: 突破越多回落越彻底越好
            if breakout_extent > 0.005 and pullback_extent > 0.01 and vol_ratio > 1.3:
                quality_score = 3
                quality_details["quality"] = "STRONG"
            elif breakout_extent > 0.003 and pullback_extent > 0.005:
                quality_score = 2
                quality_details["quality"] = "STANDARD"
            else:
                quality_details["quality"] = "WEAK"

            return "FAKE_BREAKOUT_UP", quality_score, quality_details

    # 真跌破：低点跌破且收盘确认
    if last_swing_low and last["low"] < last_swing_low[1]:
        swing_price = last_swing_low[1]
        if last["close"] < swing_price:
            breakdown_strength = (swing_price - last["close"]) / swing_price if swing_price > 0 else 0
            quality_score = 3 if breakdown_strength > 0.01 else 2 if breakdown_strength > 0.005 else 1
            return "BREAKOUT_DOWN", quality_score, {
                "type": "BREAKOUT_DOWN",
                "breakdown_strength": round(breakdown_strength * 100, 2),
                "vol_ratio": round(vol_ratio, 2)
            }
        else:
            # 假跌破质量判断
            breakdown_extent = (swing_price - last["low"]) / swing_price if swing_price > 0 else 0
            bounce_extent = (last["close"] - last["low"]) / last["low"] if last["low"] > 0 else 0

            quality_score = 1
            quality_details = {
                "type": "FAKE_BREAKOUT_DOWN",
                "breakdown_extent_pct": round(breakdown_extent * 100, 2),
                "bounce_extent_pct": round(bounce_extent * 100, 2),
                "vol_ratio": round(vol_ratio, 2)
            }

            if breakdown_extent > 0.005 and bounce_extent > 0.01 and vol_ratio > 1.3:
                quality_score = 3
                quality_details["quality"] = "STRONG"
            elif breakdown_extent > 0.003 and bounce_extent > 0.005:
                quality_score = 2
                quality_details["quality"] = "STANDARD"
            else:
                quality_details["quality"] = "WEAK"

            return "FAKE_BREAKOUT_DOWN", quality_score, quality_details

    # 4. Trend Continuation (需要多根K线确认)
    if len(ohlcv_bars) >= 5:
        last_5 = ohlcv_bars[-5:]
        ups = sum(1 for bar in last_5 if bar["close"] > bar["open"])
        downs = sum(1 for bar in last_5 if bar["close"] < bar["open"])

        if ups >= 4 and candle_feat.get("is_bullish") and candle_feat.get("is_long_body"):
            return "TREND_CONTINUATION_UP", 2, {"type": "TREND_CONTINUATION_UP", "consecutive_up": ups}
        if downs >= 4 and candle_feat.get("is_bearish") and candle_feat.get("is_long_body"):
            return "TREND_CONTINUATION_DOWN", 2, {"type": "TREND_CONTINUATION_DOWN", "consecutive_down": downs}

    return "NONE", 0, {}


def detect_two_b_tag_enhanced(ohlcv_bars, swing_points, volume_state):
    """
    v3.400 增强2B检测 - 新增速度验证 (D3改进)

    规则：
    - TWO_B_BOTTOM: 跌破swing_low后快速收回 + 量能配合
    - TWO_B_TOP: 突破swing_high后快速回落 + 量能配合

    v3.400新增:
    - 速度验证: 区分急速2B(1-2根K线内回落) vs 普通2B(3-4根) vs 慢速2B(5根+)
    - 返回元组: (tag, speed_score, speed_details)
    """
    if not ohlcv_bars or len(ohlcv_bars) < 3:
        return "NONE", 0, {}

    last = ohlcv_bars[-1]
    prev = ohlcv_bars[-2]

    last_swing_low = swing_points.get("last_swing_low")
    last_swing_high = swing_points.get("last_swing_high")

    # ═══════════════════════════════════════════════════════════════════════
    # 2B Bottom: 跌破支撑后快速收回
    # ═══════════════════════════════════════════════════════════════════════
    if last_swing_low:
        swing_low_price = last_swing_low[1]
        swing_low_idx = last_swing_low[0]  # 摆点索引

        # 检查最近几根K线是否有跌破
        bars_since_break = 0
        break_found = False
        break_low = None

        # 从最近开始往前找跌破点
        for i in range(len(ohlcv_bars) - 1, max(len(ohlcv_bars) - 6, -1), -1):
            bar = ohlcv_bars[i]
            if bar["low"] < swing_low_price:
                break_found = True
                bars_since_break = len(ohlcv_bars) - 1 - i
                break_low = bar["low"]
                break

        # 当前收盘站稳支撑上方
        if break_found and last["close"] > swing_low_price:
            if volume_state in ("RISING", "CLIMAX", "NORMAL"):
                # D3改进: 速度评分
                speed_score = 1  # 默认慢速
                speed_details = {
                    "type": "TWO_B_BOTTOM",
                    "bars_to_recover": bars_since_break,
                    "break_low": break_low,
                    "swing_low": swing_low_price,
                    "volume_state": volume_state
                }

                # 急速2B: 当前或上一根K线内回收 (bars_since_break=0或1)
                if bars_since_break <= 1:
                    speed_score = 3
                    speed_details["speed"] = "FAST"
                # 普通2B: 2根K线内回收 (bars_since_break=2)
                elif bars_since_break <= 2:
                    speed_score = 2
                    speed_details["speed"] = "NORMAL"
                # 慢速2B: 3根以上K线回收 (bars_since_break>=3)
                else:
                    speed_score = 1
                    speed_details["speed"] = "SLOW"

                # 放量加分
                if volume_state in ("RISING", "CLIMAX"):
                    speed_score = min(speed_score + 1, 3)
                    speed_details["vol_bonus"] = True

                return "TWO_B_BOTTOM", speed_score, speed_details

    # ═══════════════════════════════════════════════════════════════════════
    # 2B Top: 突破阻力后快速回落
    # ═══════════════════════════════════════════════════════════════════════
    if last_swing_high:
        swing_high_price = last_swing_high[1]

        # 检查最近几根K线是否有突破
        bars_since_break = 0
        break_found = False
        break_high = None

        for i in range(len(ohlcv_bars) - 1, max(len(ohlcv_bars) - 6, -1), -1):
            bar = ohlcv_bars[i]
            if bar["high"] > swing_high_price:
                break_found = True
                bars_since_break = len(ohlcv_bars) - 1 - i
                break_high = bar["high"]
                break

        # 当前收盘跌破阻力
        if break_found and last["close"] < swing_high_price:
            if volume_state in ("RISING", "CLIMAX", "NORMAL"):
                speed_score = 1
                speed_details = {
                    "type": "TWO_B_TOP",
                    "bars_to_recover": bars_since_break,
                    "break_high": break_high,
                    "swing_high": swing_high_price,
                    "volume_state": volume_state
                }

                if bars_since_break <= 1:
                    speed_score = 3
                    speed_details["speed"] = "FAST"
                elif bars_since_break <= 2:
                    speed_score = 2
                    speed_details["speed"] = "NORMAL"
                else:
                    speed_score = 1
                    speed_details["speed"] = "SLOW"

                if volume_state in ("RISING", "CLIMAX"):
                    speed_score = min(speed_score + 1, 3)
                    speed_details["vol_bonus"] = True

                return "TWO_B_TOP", speed_score, speed_details

    return "NONE", 0, {}


def detect_one_two_three_tag_enhanced(ohlcv_bars, swing_points):
    """
    增强1-2-3检测
    
    规则：
    - ONE_TWO_THREE_LONG: 1=回调低点，2=反弹高点，3=次级回调不破1，突破2
    - ONE_TWO_THREE_SHORT: 1=反弹高点，2=回调低点，3=次级反弹不破1，跌破2
    """
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        return "NONE"
    
    swing_lows = swing_points.get("swing_lows", [])
    swing_highs = swing_points.get("swing_highs", [])
    
    if len(swing_lows) < 2 or len(swing_highs) < 2:
        return "NONE"
    
    last = ohlcv_bars[-1]
    
    # 多头1-2-3: 最近3个swing_low，最后一个>第一个（higher low），且当前突破swing_high
    if len(swing_lows) >= 3:
        point_1 = swing_lows[-3][1]  # 第一个低点
        point_3 = swing_lows[-1][1]  # 第三个低点
        if point_3 > point_1:  # higher low
            if swing_highs:
                point_2 = swing_highs[-1][1]  # 中间高点
                if last["close"] > point_2:  # 突破point 2
                    return "ONE_TWO_THREE_LONG"
    
    # 空头1-2-3: 最近3个swing_high，最后一个<第一个（lower high），且当前跌破swing_low
    if len(swing_highs) >= 3:
        point_1 = swing_highs[-3][1]  # 第一个高点
        point_3 = swing_highs[-1][1]  # 第三个高点
        if point_3 < point_1:  # lower high
            if swing_lows:
                point_2 = swing_lows[-1][1]  # 中间低点
                if last["close"] < point_2:  # 跌破point 2
                    return "ONE_TWO_THREE_SHORT"
    
    return "NONE"


