# v3.410 量价理论增强模块
# 来源: 50集量价理论知识卡片
# ============================================================

def detect_volume_price_divergence(closes: list, volumes: list, lookback: int = 5) -> dict:
    """
    v3.410 P0-1: 量价背离预警系统
    来源: 第16集量缩价涨、第17集量增价跌、第30集分时量价背离

    核心观点:
    - 价升量缩 = 做多动能衰竭，预示调整或见顶
    - 价跌量增 = 市场分歧，需结合位置判断

    返回:
        {
            "divergence_type": "BEARISH_DIVERGENCE" / "BULLISH_DIVERGENCE" / "NONE",
            "severity": 1-3 (严重程度),
            "description": str
        }
    """
    if len(closes) < lookback + 1 or len(volumes) < lookback + 1:
        return {"divergence_type": "NONE", "severity": 0, "description": "数据不足"}

    # 计算价格变化和成交量变化
    price_change = (closes[-1] - closes[-lookback]) / closes[-lookback] if closes[-lookback] > 0 else 0
    vol_change = (volumes[-1] - volumes[-lookback]) / volumes[-lookback] if volumes[-lookback] > 0 else 0

    # 计算均量作为参考
    vol_ma = sum(volumes[-20:]) / min(len(volumes), 20) if len(volumes) >= 5 else volumes[-1]
    current_vol_ratio = volumes[-1] / vol_ma if vol_ma > 0 else 1.0

    divergence_type = "NONE"
    severity = 0
    description = ""

    # 价升量缩背离 (看跌背离)
    if price_change > 0.005:  # 价格上涨0.5%以上
        if vol_change < -0.3:  # 成交量下降30%以上
            divergence_type = "BEARISH_DIVERGENCE"
            if vol_change < -0.5:
                severity = 3
                description = "强烈看跌背离: 价格上涨但成交量大幅萎缩"
            elif vol_change < -0.4:
                severity = 2
                description = "中度看跌背离: 价格上涨但成交量明显萎缩"
            else:
                severity = 1
                description = "轻度看跌背离: 价格上涨但成交量萎缩"

    # 价跌量增背离 (潜在底部或出货)
    elif price_change < -0.005:  # 价格下跌0.5%以上
        if vol_change > 0.3:  # 成交量上升30%以上
            divergence_type = "BULLISH_DIVERGENCE"  # 可能是抛压释放
            if vol_change > 0.5 and current_vol_ratio > 1.5:
                severity = 3
                description = "放量下跌: 可能是恐慌抛售或主力出货"
            elif vol_change > 0.4:
                severity = 2
                description = "中度放量下跌: 市场分歧加大"
            else:
                severity = 1
                description = "轻度放量下跌: 存在分歧"

    return {
        "divergence_type": divergence_type,
        "severity": severity,
        "description": description,
        "price_change_pct": round(price_change * 100, 2),
        "vol_change_pct": round(vol_change * 100, 2)
    }


def calculate_position_context_weight(current_price: float, high_52w: float, low_52w: float) -> dict:
    """
    v3.410 P0-2: 位置决定含义原则
    来源: 第14集量增价涨、第17集量增价跌

    核心观点: 同样的量价信号在底部/中部/高位含义完全不同

    返回:
        {
            "position_pct": 0-1 (0=52周低点, 1=52周高点),
            "zone": "LOW" / "MID" / "HIGH",
            "bullish_weight": 0.5-1.5 (看多信号权重调整),
            "bearish_weight": 0.5-1.5 (看空信号权重调整)
        }
    """
    if high_52w <= low_52w or high_52w <= 0:
        return {
            "position_pct": 0.5,
            "zone": "MID",
            "bullish_weight": 1.0,
            "bearish_weight": 1.0
        }

    position_pct = (current_price - low_52w) / (high_52w - low_52w)
    position_pct = max(0, min(1, position_pct))  # 限制在0-1范围

    # 确定区域
    if position_pct < 0.25:
        zone = "LOW"
        bullish_weight = 1.3  # 低位看多信号增强
        bearish_weight = 0.7  # 低位看空信号减弱
    elif position_pct > 0.75:
        zone = "HIGH"
        bullish_weight = 0.7  # 高位看多信号减弱
        bearish_weight = 1.3  # 高位看空信号增强
    else:
        zone = "MID"
        bullish_weight = 1.0
        bearish_weight = 1.0

    return {
        "position_pct": round(position_pct, 3),
        "zone": zone,
        "bullish_weight": bullish_weight,
        "bearish_weight": bearish_weight
    }


def calculate_breakout_volume_quality(volumes: list, is_breakout: bool, ma_period: int = 20) -> dict:
    """
    v3.410 P1-1: 放量突破有效性验证
    来源: 第14集量增价涨

    核心观点: 突破时要持续放量，缩量突破=假突破风险高

    返回:
        {
            "quality": "HIGH" / "MEDIUM" / "LOW",
            "vol_ratio": float (当前量/均量),
            "is_valid_breakout": bool,
            "description": str
        }
    """
    if not volumes or len(volumes) < ma_period:
        return {
            "quality": "MEDIUM",
            "vol_ratio": 1.0,
            "is_valid_breakout": is_breakout,
            "description": "数据不足"
        }

    vol_ma = sum(volumes[-ma_period:]) / ma_period
    current_vol = volumes[-1]
    vol_ratio = current_vol / vol_ma if vol_ma > 0 else 1.0

    if not is_breakout:
        return {
            "quality": "N/A",
            "vol_ratio": round(vol_ratio, 2),
            "is_valid_breakout": False,
            "description": "无突破"
        }

    # 判断突破质量
    if vol_ratio >= 1.5:
        quality = "HIGH"
        is_valid = True
        description = f"放量突破(量比{vol_ratio:.1f}): 突破有效性高"
    elif vol_ratio >= 1.0:
        quality = "MEDIUM"
        is_valid = True
        description = f"温和放量突破(量比{vol_ratio:.1f}): 需观察后续量能"
    else:
        quality = "LOW"
        is_valid = False
        description = f"缩量突破(量比{vol_ratio:.1f}): 警惕假突破"

    return {
        "quality": quality,
        "vol_ratio": round(vol_ratio, 2),
        "is_valid_breakout": is_valid,
        "description": description
    }


def detect_extreme_volume(volumes: list, lookback_days: int = 60) -> dict:
    """
    v3.410 P1-2: 天量/地量极端信号
    来源: 第10集天量、第12集地量

    核心观点:
    - 天量 = 创历史新高成交量，重大分歧信号
    - 地量频繁出现 = 底部区域信号

    返回:
        {
            "signal": "EXTREME_HIGH" / "EXTREME_LOW" / "NEAR_LOW" / "NONE",
            "vol_percentile": float (0-100),
            "description": str
        }
    """
    if not volumes or len(volumes) < lookback_days:
        return {"signal": "NONE", "vol_percentile": 50, "description": "数据不足"}

    recent_volumes = volumes[-lookback_days:]
    current_vol = volumes[-1]
    max_vol = max(recent_volumes)
    min_vol = min(recent_volumes)

    # 计算百分位
    sorted_vols = sorted(recent_volumes)
    percentile = sum(1 for v in sorted_vols if v <= current_vol) / len(sorted_vols) * 100

    signal = "NONE"
    description = ""

    # 天量检测: 超过近期最大量的95%
    if current_vol >= max_vol * 0.95:
        signal = "EXTREME_HIGH"
        description = f"天量信号: 成交量达到{lookback_days}日最高水平，重大分歧"

    # 地量检测: 低于近期最小量的110%
    elif current_vol <= min_vol * 1.1:
        signal = "EXTREME_LOW"
        description = f"地量信号: 成交量接近{lookback_days}日最低水平，交投冷清"

    # 接近地量
    elif percentile < 10:
        signal = "NEAR_LOW"
        description = f"接近地量: 成交量处于{lookback_days}日内10%分位"

    return {
        "signal": signal,
        "vol_percentile": round(percentile, 1),
        "description": description,
        "current_vol": current_vol,
        "max_vol": max_vol,
        "min_vol": min_vol
    }


def calculate_xingshen_score(ohlcv_bars: list, lookback: int = 10) -> dict:
    """
    v3.410 P2-1: 行神分析法 (K线+量能有序性)
    来源: 第3集形神分析法、第41集主力出货

    核心观点:
    - 行神兼备 = K线整齐+量能有序 → 健康趋势
    - 行神聚散 = K线混乱+量能失衡 → 出货/反转信号

    返回:
        {
            "xingshen_score": 0-1 (越高越健康),
            "xing_score": 0-1 (K线有序性),
            "shen_score": 0-1 (量能有序性),
            "status": "HEALTHY" / "WARNING" / "DANGER",
            "description": str
        }
    """
    if not ohlcv_bars or len(ohlcv_bars) < lookback:
        return {
            "xingshen_score": 0.5,
            "xing_score": 0.5,
            "shen_score": 0.5,
            "status": "UNKNOWN",
            "description": "数据不足"
        }

    recent_bars = ohlcv_bars[-lookback:]

    # 计算收益率序列
    returns = []
    for i in range(1, len(recent_bars)):
        prev_close = recent_bars[i-1].get("close", 0)
        curr_close = recent_bars[i].get("close", 0)
        if prev_close > 0:
            returns.append((curr_close - prev_close) / prev_close)

    # 计算成交量变化序列
    vol_changes = []
    for i in range(1, len(recent_bars)):
        prev_vol = recent_bars[i-1].get("volume", 0)
        curr_vol = recent_bars[i].get("volume", 0)
        if prev_vol > 0:
            vol_changes.append((curr_vol - prev_vol) / prev_vol)

    if not returns or not vol_changes:
        return {
            "xingshen_score": 0.5,
            "xing_score": 0.5,
            "shen_score": 0.5,
            "status": "UNKNOWN",
            "description": "计算数据不足"
        }

    # 计算标准差
    import statistics
    returns_std = statistics.stdev(returns) if len(returns) > 1 else 0
    vol_std = statistics.stdev(vol_changes) if len(vol_changes) > 1 else 0

    # 行(形)分: K线有序性 (标准差越小越有序)
    # 正常波动率约0.02-0.03，超过0.05视为混乱
    xing_score = max(0, 1 - returns_std / 0.05)
    xing_score = min(1, xing_score)

    # 神分: 量能有序性 (成交量变化标准差越小越有序)
    # 正常量能变化约0.3-0.5，超过1.0视为失衡
    shen_score = max(0, 1 - vol_std / 1.0)
    shen_score = min(1, shen_score)

    # 综合分
    xingshen_score = (xing_score + shen_score) / 2

    # 判断状态
    if xingshen_score >= 0.6:
        status = "HEALTHY"
        description = "行神兼备: K线有序、量能稳定，趋势健康"
    elif xingshen_score >= 0.4:
        status = "WARNING"
        description = "行神欠佳: 波动加大，需注意风险"
    else:
        status = "DANGER"
        description = "行神聚散: K线混乱、量能失衡，警惕反转或出货"

    return {
        "xingshen_score": round(xingshen_score, 2),
        "xing_score": round(xing_score, 2),
        "shen_score": round(shen_score, 2),
        "status": status,
        "description": description,
        "returns_std": round(returns_std, 4),
        "vol_std": round(vol_std, 4)
    }


def calculate_volume_trend_confirmation(trend: str, volumes: list, ma_period: int = 20) -> dict:
    """
    v3.410 P2-2: 量价配合验证趋势
    来源: 第2集成交量五大作用、第14集量增价涨

    核心观点: 成交量强化趋势可靠性
    - 上涨趋势+放量 = 趋势可靠
    - 上涨趋势+缩量 = 趋势存疑

    返回:
        {
            "confirmation": "STRONG" / "WEAK" / "DIVERGENT",
            "trend_confidence_adj": 0.8-1.2 (趋势置信度调整系数),
            "vol_trend": "RISING" / "FALLING" / "FLAT",
            "description": str
        }
    """
    if not volumes or len(volumes) < ma_period:
        return {
            "confirmation": "UNKNOWN",
            "trend_confidence_adj": 1.0,
            "vol_trend": "FLAT",
            "description": "数据不足"
        }

    vol_ma = sum(volumes[-ma_period:]) / ma_period
    recent_vol_ma = sum(volumes[-5:]) / 5 if len(volumes) >= 5 else volumes[-1]
    vol_ratio = recent_vol_ma / vol_ma if vol_ma > 0 else 1.0

    # 判断成交量趋势
    if vol_ratio > 1.2:
        vol_trend = "RISING"
    elif vol_ratio < 0.8:
        vol_trend = "FALLING"
    else:
        vol_trend = "FLAT"

    # 验证量价配合
    confirmation = "WEAK"
    trend_confidence_adj = 1.0
    description = ""

    if trend.lower() in ("up", "bullish"):
        if vol_trend == "RISING":
            confirmation = "STRONG"
            trend_confidence_adj = 1.15
            description = "上涨趋势+放量: 量价配合，趋势可靠"
        elif vol_trend == "FALLING":
            confirmation = "DIVERGENT"
            trend_confidence_adj = 0.85
            description = "上涨趋势+缩量: 量价背离，趋势存疑"
        else:
            confirmation = "WEAK"
            trend_confidence_adj = 1.0
            description = "上涨趋势+量能平稳: 需观察"

    elif trend.lower() in ("down", "bearish"):
        if vol_trend == "RISING":
            confirmation = "STRONG"
            trend_confidence_adj = 1.15
            description = "下跌趋势+放量: 空头强势，趋势可靠"
        elif vol_trend == "FALLING":
            confirmation = "DIVERGENT"
            trend_confidence_adj = 0.85
            description = "下跌趋势+缩量: 抛压减少，可能见底"
        else:
            confirmation = "WEAK"
            trend_confidence_adj = 1.0
            description = "下跌趋势+量能平稳: 需观察"

    return {
        "confirmation": confirmation,
        "trend_confidence_adj": trend_confidence_adj,
        "vol_trend": vol_trend,
        "vol_ratio": round(vol_ratio, 2),
        "description": description
    }


def compute_volume_state_enhanced(volumes):
    """
    增强成交量状态：使用robust统计
    
    返回：CLIMAX / RISING / FALLING / DRY_UP / NORMAL
    """
    if not volumes or len(volumes) < 20:
        return "NORMAL"
    
    # 使用中位数和MAD (Median Absolute Deviation)
    import statistics
    median_vol = statistics.median(volumes)
    mad = statistics.median([abs(v - median_vol) for v in volumes])
    
    if mad == 0:
        return "NORMAL"
    
    last_vol = volumes[-1]
    z_score = (last_vol - median_vol) / (mad * 1.4826)  # MAD->std转换系数
    
    if z_score > 3.0:
        return "CLIMAX"
    elif z_score > 1.5:
        return "RISING"
    elif z_score < -2.0:
        return "DRY_UP"
    elif z_score < -1.0:
        return "FALLING"
    else:
        return "NORMAL"


# ═══════════════════════════════════════════════════════════════════════════════
# v3.487 P0-2: 短期回调企稳检测 (见底仍SELL问题)
# ═══════════════════════════════════════════════════════════════════════════════

def detect_pullback_stabilization_v3487(ohlcv_bars: list, lookback: int = 10, threshold: float = 0.05) -> dict:
    """
    v3.487: 检测短期回调后的企稳信号

    核心逻辑:
    - 计算从近lookback根K线高点的回调幅度
    - 回调>threshold(5%) + 企稳K线(锤子/十字星/长下影) → 暂停SELL

    参数:
        ohlcv_bars: OHLCV数据列表
        lookback: 回溯K线数
        threshold: 回调幅度阈值

    返回: {"is_stabilizing": bool, "pullback_pct": float, "stabilization_pattern": str, "reason": str}
    """
    if not ohlcv_bars or len(ohlcv_bars) < 3:
        return {"is_stabilizing": False, "pullback_pct": 0.0, "stabilization_pattern": "NONE", "reason": "INSUFFICIENT_DATA"}

    # 获取回溯期间的高点
    bars_to_check = ohlcv_bars[-lookback:] if len(ohlcv_bars) >= lookback else ohlcv_bars
    recent_high = max(bar.get("high", 0) for bar in bars_to_check)
    current_close = ohlcv_bars[-1].get("close", 0)

    if recent_high <= 0 or current_close <= 0:
        return {"is_stabilizing": False, "pullback_pct": 0.0, "stabilization_pattern": "NONE", "reason": "INVALID_DATA"}

    # 计算回调幅度
    pullback_pct = (recent_high - current_close) / recent_high

    # 如果回调不足阈值，不需要检测企稳
    if pullback_pct < threshold:
        return {"is_stabilizing": False, "pullback_pct": pullback_pct, "stabilization_pattern": "NONE", "reason": "PULLBACK_TOO_SMALL"}

    # 检测最后一根K线是否是企稳形态
    last_bar = ohlcv_bars[-1]
    open_p = last_bar.get("open", 0)
    high_p = last_bar.get("high", 0)
    low_p = last_bar.get("low", 0)
    close_p = last_bar.get("close", 0)

    body = abs(close_p - open_p)
    full_range = high_p - low_p if high_p > low_p else 0.0001
    lower_shadow = min(open_p, close_p) - low_p
    upper_shadow = high_p - max(open_p, close_p)

    stabilization_pattern = "NONE"

    # 锤子线: 下影线>=2倍实体, 上影线<实体
    if lower_shadow >= 2 * body and upper_shadow < body:
        stabilization_pattern = "HAMMER"
    # 十字星: 实体<全幅的15%
    elif body < 0.15 * full_range:
        stabilization_pattern = "DOJI"
    # 长下影线: 下影线>50%全幅
    elif lower_shadow > 0.5 * full_range:
        stabilization_pattern = "LONG_LOWER_SHADOW"

    is_stabilizing = stabilization_pattern != "NONE"

    return {
        "is_stabilizing": is_stabilizing,
        "pullback_pct": pullback_pct,
        "stabilization_pattern": stabilization_pattern,
        "reason": f"PULLBACK_{pullback_pct*100:.1f}%_{stabilization_pattern}" if is_stabilizing else "NO_STABILIZATION"
    }


# ═══════════════════════════════════════════════════════════════════════════════
# v3.487 P1-4: 底部反转保护 (RSI/K线保护)
# ═══════════════════════════════════════════════════════════════════════════════

def check_bottom_reversal_protection_v3487(rsi14: float, ohlcv_bars: list) -> dict:
    """
    v3.487: 检测底部反转保护条件

    满足任一条件阻止SELL:
    - RSI < 30 (超卖)
    - 看涨吞没K线
    - 锤子线

    返回: {"should_protect": bool, "reason": str}
    """
    reasons = []

    # 条件1: RSI超卖
    if rsi14 is not None and rsi14 < 30:
        reasons.append(f"RSI_OVERSOLD_{rsi14:.1f}")

    # 条件2&3: K线形态
    if ohlcv_bars and len(ohlcv_bars) >= 2:
        curr = ohlcv_bars[-1]
        prev = ohlcv_bars[-2]

        c_open = curr.get("open", 0)
        c_close = curr.get("close", 0)
        c_high = curr.get("high", 0)
        c_low = curr.get("low", 0)
        p_open = prev.get("open", 0)
        p_close = prev.get("close", 0)

        # 看涨吞没: 前阴后阳, 当前收盘>前开盘, 当前开盘<前收盘
        if p_close < p_open and c_close > c_open:  # 前阴后阳
            if c_close > p_open and c_open < p_close:  # 吞没
                reasons.append("BULL_ENGULFING")

        # 锤子线检测
        body = abs(c_close - c_open)
        full_range = c_high - c_low if c_high > c_low else 0.0001
        lower_shadow = min(c_open, c_close) - c_low
        upper_shadow = c_high - max(c_open, c_close)

        if lower_shadow >= 2 * body and upper_shadow < body:
            reasons.append("HAMMER")

    should_protect = len(reasons) > 0
    return {
        "should_protect": should_protect,
        "reason": "+".join(reasons) if reasons else "NONE"
    }


def compute_exec_bias_with_scoring(pa_tag, two_b_tag, one_two_three_tag,
                                   volume_state, dist_to_support_pct,
                                   dist_to_resistance_pct, trend_mid,
                                   trend_x4, trend_x8,
                                   market_regime=None,
                                   pa_quality_score=2,  # v3.400: PA质量分(1-3)
                                   two_b_speed_score=2,  # v3.400: 2B速度分(1-3)
                                   # v3.410 量价理论新增参数
                                   ohlcv_bars=None,      # v3.410: OHLCV数据用于行神分析
                                   closes=None,          # v3.410: 收盘价序列用于背离检测
                                   volumes=None,         # v3.410: 成交量序列
                                   high_52w=None,        # v3.410: 52周高点用于位置判断
                                   low_52w=None,         # v3.410: 52周低点用于位置判断
                                   tv_donchian=None,     # v3.480: TV推送的Donchian数据
                                   wyckoff_phase=None,   # v3.485: Wyckoff阶段 (MARKUP/MARKDOWN/ACCUMULATION/DISTRIBUTION/RANGING)
                                   l2_strategy=None,     # v3.485: L2策略 (TREND_PULLBACK/RANGE_REVERSAL)
                                   symbol=None,          # v3.499: 品种代码 (唐纳奇通道反馈)
                                   current_trend=None):  # v3.499: L1当前周期趋势 (UP/DOWN/SIDE) 用于矛盾检测
    """
    v3.500 L2 exec_bias打分模型 - 5大类评分

    v3.500更新:
    - 移除唐纳奇通道分(与位置分重复计算pos_in_channel)
    - 总分范围: -16 ~ +16 (形态±6+位置±4+量能±2+Wyckoff±2+每日偏向±2)
    - STRONG阈值±8 (50%触发率)

    ═══════════════════════════════════════════════════════════════
    5大类评分体系 (v3.500):
    ═══════════════════════════════════════════════════════════════

    【形态分】(±6) - PA形态 + 2B + 123 + K线形态
        基础形态分范围: -4 ~ +4
        Donchian位置验证乘数: 0.5x ~ 1.5x
        最终形态分: -6 ~ +6

        乘数规则 (以多头形态为例):
        - pos_in_channel < 20%: 1.5x (低位多头形态=高价值)
        - pos_in_channel < 40%: 1.0x (中低位=正常)
        - pos_in_channel < 60%: 0.7x (中间=打折)
        - pos_in_channel >= 60%: 0.5x (高位追多=大打折)

    【位置分】(±4) - TV Donchian pos_in_channel直接映射
        0-10%:   +4 (极度超卖)
        10-20%:  +3 (超卖)
        20-30%:  +2 (偏低)
        30-40%:  +1 (略低)
        40-60%:  0  (中性)
        60-70%:  -1 (略高)
        70-80%:  -2 (偏高)
        80-90%:  -3 (超买)
        90-100%: -4 (极度超买)

    【量能分】(±2) - 量价配合验证
        多头形态+放量: +2 (量价齐升)
        空头形态+放量: -2 (放量下跌)
        形态与量能不配合: ±1惩罚
        无明显信号: 0

    【Wyckoff策略分】(±2) - v3.485新增
        形态与Wyckoff阶段一致: +2 (如MARKUP期Hammer)
        形态与Wyckoff阶段冲突: -2 (如MARKUP期Bear Engulfing)
        中性: 0

    ═══════════════════════════════════════════════════════════════
    总分映射 (v3.499调整 - 移除RSI后):
    >= 8: STRONG_BUY  (原7, 移除RSI±1后提高)
    >= 4: BUY
    <= -8: STRONG_SELL (原-7, 移除RSI±1后提高)
    <= -4: SELL
    其他: HOLD
    ═══════════════════════════════════════════════════════════════
    """
    
    # ═══════════════════════════════════════════════════════════════════════
    # v3.480: 3大类评分体系
    # ═══════════════════════════════════════════════════════════════════════

    # --- 获取TV Donchian pos_in_channel ---
    pos_in_channel = None
    if tv_donchian and isinstance(tv_donchian, dict):
        pos_in_channel = tv_donchian.get("pos_in_channel")
        if pos_in_channel is not None:
            pos_in_channel = float(pos_in_channel)

    # 如果没有TV数据，使用dist_to_support_pct作为备用
    if pos_in_channel is None:
        pos_in_channel = dist_to_support_pct if dist_to_support_pct is not None else 0.5

    print(f"[v3.480] Donchian pos_in_channel: {pos_in_channel*100:.1f}%")

    # ═══════════════════════════════════════════════════════════════════════
    # v3.501: 检测市场模式 (突破/震荡) 并更新突破状态
    # ═══════════════════════════════════════════════════════════════════════
    market_mode = "RANGING"
    breakout_direction = None
    breakout_score = 0
    breakout_reason = "震荡模式"
    ranging_score = 0
    ranging_reason = ""
    trend_bonus = 0  # v3.501: 趋势强化加分
    force_ranging = False  # v3.501: 强制震荡模式

    # 获取当前收盘价和唐纳奇通道上下轨
    current_close = None
    donchian_upper = None
    donchian_lower = None

    if tv_donchian and isinstance(tv_donchian, dict):
        donchian_upper = tv_donchian.get("upper")
        donchian_lower = tv_donchian.get("lower")
        # 尝试从ohlcv_bars获取当前收盘价
        if ohlcv_bars and len(ohlcv_bars) >= 1:
            last_bar = ohlcv_bars[-1]
            if isinstance(last_bar, dict):
                current_close = last_bar.get("close") or last_bar.get("c")
            elif isinstance(last_bar, (list, tuple)) and len(last_bar) >= 5:
                current_close = last_bar[4]  # OHLCV格式

    # 如果有完整数据，检测突破/震荡模式
    if symbol and current_close is not None and donchian_upper is not None and donchian_lower is not None:
        # 更新突破状态
        breakout_result = update_symbol_breakout_state(symbol, current_close, donchian_upper, donchian_lower)
        market_mode = breakout_result["mode"]
        breakout_direction = breakout_result["direction"]
        force_ranging = breakout_result.get("force_ranging", False)
        trend_bonus = breakout_result.get("trend_bonus", 0)

        # v3.501: 如果强制震荡模式（上次突破失败），覆盖市场模式
        if force_ranging:
            market_mode = "RANGING"
            breakout_score = 0
            breakout_reason = "强制震荡(上次突破失败)"
            ranging_score, ranging_reason = get_ranging_mode_score(pos_in_channel)
            print(f"[v3.501] 强制震荡模式: pos={pos_in_channel:.0%} → {ranging_score:+d}分 ({ranging_reason})")
        elif market_mode == "BREAKOUT":
            # 突破模式: 使用突破评分
            breakout_score, breakout_reason = get_breakout_mode_score(symbol)
            print(f"[v3.501] 突破模式: {breakout_direction} → {breakout_score:+d}分 ({breakout_reason})")
        else:
            # 震荡模式: 使用低买高卖评分
            ranging_score, ranging_reason = get_ranging_mode_score(pos_in_channel)
            print(f"[v3.501] 震荡模式: pos={pos_in_channel:.0%} → {ranging_score:+d}分 ({ranging_reason})")

        # v3.501: 趋势强化加分
        if trend_bonus != 0:
            print(f"[v3.501] 趋势强化加分: {trend_bonus:+d}")
    else:
        print(f"[v3.501] 数据不完整，跳过突破检测: close={current_close}, upper={donchian_upper}, lower={donchian_lower}")

    # ═══════════════════════════════════════════════════════════════════════
    # 【类别1】形态分 (±6) - PA + 2B + 123 + K线形态 + Donchian位置乘数
    # ═══════════════════════════════════════════════════════════════════════

    # --- 1.1 基础PA形态分 ---
    base_pa_score = 0
    if pa_tag in ("BULL_ENGULF", "PIN_BAR_BULL", "BREAKOUT_UP", "TREND_CONTINUATION_UP"):
        base_pa_score = 2
    elif pa_tag in ("BEAR_ENGULF", "PIN_BAR_BEAR", "BREAKOUT_DOWN", "TREND_CONTINUATION_DOWN"):
        base_pa_score = -2
    elif pa_tag == "FAKE_BREAKOUT_UP":
        base_pa_score = -3  # 假突破向上失败=强空
    elif pa_tag == "FAKE_BREAKOUT_DOWN":
        base_pa_score = 3   # 假跌破=强多

    # PA质量乘数 (1=0.5, 2=1.0, 3=1.5)
    pa_quality_multiplier = {1: 0.5, 2: 1.0, 3: 1.5}.get(pa_quality_score, 1.0)
    pa_score = int(round(base_pa_score * pa_quality_multiplier))

    # --- 1.2 2B形态分 ---
    base_two_b_score = 0
    if two_b_tag == "TWO_B_BOTTOM":
        base_two_b_score = 1
    elif two_b_tag == "TWO_B_TOP":
        base_two_b_score = -1

    two_b_speed_multiplier = {1: 0.5, 2: 1.0, 3: 1.5}.get(two_b_speed_score, 1.0)
    two_b_score = int(round(base_two_b_score * two_b_speed_multiplier))

    # --- 1.3 123形态分 ---
    one23_score = 0
    if one_two_three_tag == "ONE_TWO_THREE_LONG":
        one23_score = 1
    elif one_two_three_tag == "ONE_TWO_THREE_SHORT":
        one23_score = -1

    # --- 1.4 K线形态分 ---
    candle_shape_score = 0.0
    candle_shape_name = "UNKNOWN"
    if ohlcv_bars and len(ohlcv_bars) >= 1:
        candle_shape_score, candle_shape_name = compute_candle_shape_score(ohlcv_bars[-1])

    # --- 1.5 合并基础形态分 (范围: -4 ~ +4) ---
    base_pattern_score = pa_score + two_b_score + one23_score + int(round(candle_shape_score))
    base_pattern_score = max(min(base_pattern_score, 4), -4)

    # --- 1.6 Donchian位置验证乘数 ---
    # 核心逻辑: 形态需要在合适位置才有价值
    # 多头形态: 低位=高价值(1.5x), 高位追多=打折(0.5x)
    # 空头形态: 高位=高价值(1.5x), 低位杀跌=打折(0.5x)

    if base_pattern_score > 0:  # 多头形态
        if pos_in_channel < 0.20:
            donchian_multiplier = 1.5  # 低位多头=高价值
        elif pos_in_channel < 0.40:
            donchian_multiplier = 1.0  # 中低位=正常
        elif pos_in_channel < 0.60:
            donchian_multiplier = 0.7  # 中间=打折
        else:
            donchian_multiplier = 0.5  # 高位追多=大打折
    elif base_pattern_score < 0:  # 空头形态
        if pos_in_channel > 0.80:
            donchian_multiplier = 1.5  # 高位空头=高价值
        elif pos_in_channel > 0.60:
            donchian_multiplier = 1.0  # 中高位=正常
        elif pos_in_channel > 0.40:
            donchian_multiplier = 0.7  # 中间=打折
        else:
            donchian_multiplier = 0.5  # 低位杀跌=大打折
    else:
        donchian_multiplier = 1.0  # 无形态

    # 计算最终形态分 (±6)
    pattern_score = int(round(base_pattern_score * donchian_multiplier))
    pattern_score = max(min(pattern_score, 6), -6)

    print(f"[v3.480] 形态分: base={base_pattern_score} x donchian_mult={donchian_multiplier:.1f} = {pattern_score}")
    if pa_tag != "NONE":
        log_to_server(f"[v3.480] PA: {pa_tag}, 2B: {two_b_tag}, 123: {one_two_three_tag}, K线: {candle_shape_name}")

    # ═══════════════════════════════════════════════════════════════════════
    # 【类别2】位置分 (±4) - TV Donchian pos_in_channel直接映射
    # ═══════════════════════════════════════════════════════════════════════

    if pos_in_channel < 0.10:
        position_score = 4   # 极度超卖
    elif pos_in_channel < 0.20:
        position_score = 3   # 超卖
    elif pos_in_channel < 0.30:
        position_score = 2   # 偏低
    elif pos_in_channel < 0.40:
        position_score = 1   # 略低
    elif pos_in_channel < 0.60:
        position_score = 0   # 中性
    elif pos_in_channel < 0.70:
        position_score = -1  # 略高
    elif pos_in_channel < 0.80:
        position_score = -2  # 偏高
    elif pos_in_channel < 0.90:
        position_score = -3  # 超买
    else:
        position_score = -4  # 极度超买

    print(f"[v3.480] 位置分: pos={pos_in_channel*100:.1f}% → score={position_score}")

    # ═══════════════════════════════════════════════════════════════════════
    # 【类别3】量能分 (±2) - 量价配合验证
    # ═══════════════════════════════════════════════════════════════════════

    volume_score = 0
    volume_detail = "无信号"

    is_bullish = base_pattern_score > 0
    is_bearish = base_pattern_score < 0
    is_volume_up = volume_state in ("RISING", "CLIMAX")
    is_volume_down = volume_state in ("DRY_UP", "FALLING")

    if is_bullish and is_volume_up:
        volume_score = 2  # 量价齐升
        volume_detail = "量价齐升"
    elif is_bearish and is_volume_up:
        volume_score = -2  # 放量下跌
        volume_detail = "放量下跌"
    elif is_bullish and is_volume_down:
        volume_score = -1  # 多头形态但缩量=惩罚
        volume_detail = "多头缩量惩罚"
    elif is_bearish and is_volume_down:
        volume_score = 1   # 空头形态但缩量=减弱
        volume_detail = "空头缩量减弱"

    print(f"[v3.480] 量能分: vol_state={volume_state}, pattern={'多头' if is_bullish else ('空头' if is_bearish else '无')} → {volume_score} ({volume_detail})")

    # ===== v3.550: 量能分增强 - 累积/分配量能特征 =====
    v3550_volume_adj = 0
    if ohlcv_bars and len(ohlcv_bars) >= 20:
        try:
            v3550_volumes = [float(bar.get('volume', bar.get('v', 0))) for bar in ohlcv_bars]
            v3550_closes = [float(bar.get('close', bar.get('c', 0))) for bar in ohlcv_bars]
            accum_dist = detect_accumulation_distribution_volume_v3550(v3550_volumes, v3550_closes, lookback=20)

            # 累积阶段(量减少)+多头形态 → 量能分+1奖励
            if accum_dist["volume_trend"] == "DECREASING" and is_bullish:
                if accum_dist["accumulation_probability"] >= 0.5:
                    v3550_volume_adj = 1
                    volume_detail += "+累积确认"
                    print(f"[v3.550] 累积量能匹配: accum_prob={accum_dist['accumulation_probability']:.2f} → 量能分+1")

            # 分配阶段(量异常)+空头形态 → 量能分-1惩罚
            elif accum_dist["volume_trend"] == "INCREASING" and is_bearish:
                if accum_dist["distribution_probability"] >= 0.5:
                    v3550_volume_adj = -1
                    volume_detail += "+分配确认"
                    print(f"[v3.550] 分配量能匹配: dist_prob={accum_dist['distribution_probability']:.2f} → 量能分-1")

            # 应用调整但保持在±2范围内
            volume_score = max(-2, min(2, volume_score + v3550_volume_adj))
        except Exception as e:
            print(f"[v3.550] 量能增强异常: {e}")
    # ===== v3.550 END =====

    # ═══════════════════════════════════════════════════════════════════════
    # v3.485: 【类别4】Wyckoff策略分 (±2)
    # ═══════════════════════════════════════════════════════════════════════
    wyckoff_score = 0
    wyckoff_score_reason = "NONE"

    if wyckoff_phase:
        wyckoff_score, wyckoff_score_reason = compute_wyckoff_strategy_score(
            wyckoff_phase=wyckoff_phase,
            pa_tag=pa_tag,
            two_b_tag=two_b_tag,
            one_two_three_tag=one_two_three_tag,
            pos_in_channel=pos_in_channel
        )
        print(f"[v3.485] Wyckoff策略分: phase={wyckoff_phase}, l2_strategy={l2_strategy} → {wyckoff_score:+d} ({wyckoff_score_reason})")

        # ===== v3.550: Wyckoff分增强 - VPOC迁移验证 =====
        if ohlcv_bars and len(ohlcv_bars) >= 60:
            try:
                vpoc_migration = compute_vpoc_migration_v3550(ohlcv_bars, period_size=20, min_periods=3)

                # VPOC迁移与Wyckoff阶段一致 → Wyckoff分奖励
                vpoc_matches_phase = False
                if vpoc_migration["migration_direction"] == "UP" and wyckoff_phase in ("MARKUP", "ACCUMULATION"):
                    vpoc_matches_phase = True
                elif vpoc_migration["migration_direction"] == "DOWN" and wyckoff_phase in ("MARKDOWN", "DISTRIBUTION"):
                    vpoc_matches_phase = True

                if vpoc_matches_phase and vpoc_migration["migration_strength"] >= 0.6:
                    v3550_wyckoff_adj = 1 if wyckoff_score >= 0 else -1
                    wyckoff_score = max(-2, min(2, wyckoff_score + v3550_wyckoff_adj))
                    wyckoff_score_reason += f"+VPOC_{vpoc_migration['migration_direction']}"
                    print(f"[v3.550] VPOC迁移一致: {vpoc_migration['migration_direction']}={wyckoff_phase} → Wyckoff分调整")
            except Exception as e:
                print(f"[v3.550] VPOC增强异常: {e}")
        # ===== v3.550 END =====
    else:
        print(f"[v3.485] Wyckoff策略分: phase=未知 → 0 (跳过)")

    # ═══════════════════════════════════════════════════════════════════════
    # v3.499: 【类别5】唐纳奇通道策略分 (±3) - L2位置确认反馈
    # ═══════════════════════════════════════════════════════════════════════
    donchian_score = 0
    donchian_reason = "NONE"
    donchian_feedback = None
    instability_penalty = 0  # v3.499: 趋势不稳定惩罚

    if symbol and pos_in_channel is not None:
        # 先更新唐纳奇状态缓存
        update_donchian_state(symbol, pos_in_channel, verbose=False)

        # 获取唐纳奇策略评分
        l1_trend = trend_x4 if trend_x4 in ("UP", "DOWN", "SIDE") else "SIDE"
        donchian_result = apply_donchian_strategy(symbol, l1_trend, pos_in_channel)
        donchian_score = donchian_result["score"]
        donchian_reason = donchian_result["reason"]
        donchian_feedback = donchian_result.get("donchian_feedback")

        print(f"[v3.499] 唐纳奇通道分: L1={l1_trend}, pos={pos_in_channel:.0%} → {donchian_score:+d} ({donchian_reason})")

        # v3.499: L1趋势不稳定检测 → 额外惩罚分
        # L1判断有趋势，但L2观察到价格位置与趋势不符 → 趋势不稳定
        if current_trend and donchian_feedback:
            high_count = donchian_feedback.get("high_count", 0)
            low_count = donchian_feedback.get("low_count", 0)

            # current_trend=UP 但连续低位 → 趋势不稳定(可能假突破/回调中)
            if current_trend == "UP" and low_count >= 3:
                instability_penalty = -2
                print(f"[v3.499] ⚠️ 趋势不稳定: 当前=UP但连续{low_count}根低位 → {instability_penalty:+d}分")

            # current_trend=DOWN 但连续高位 → 趋势不稳定(可能假跌破/反弹中)
            elif current_trend == "DOWN" and high_count >= 3:
                instability_penalty = +2
                print(f"[v3.499] ⚠️ 趋势不稳定: 当前=DOWN但连续{high_count}根高位 → {instability_penalty:+d}分")

            donchian_score += instability_penalty
    else:
        print(f"[v3.499] 唐纳奇通道分: symbol={symbol}, pos={pos_in_channel} → 0 (跳过)")

    # ═══════════════════════════════════════════════════════════════════════
    # v3.520: 5大类总分计算 (合并唐纳奇综合分 + Vegas隧道)
    # 形态±6 + 唐纳奇综合±8 + 量能±2 + Wyckoff±2 + 每日偏向±2 + Vegas隧道±2 = ±22
    # ═══════════════════════════════════════════════════════════════════════

    # v3.520: 合并唐纳奇综合分 (位置±4 + 突破/震荡±3 + 趋势强化±1 = ±8)
    mode_score = breakout_score + ranging_score
    mode_reason = breakout_reason if breakout_score != 0 else ranging_reason
    donchian_combined_score = position_score + mode_score + trend_bonus
    donchian_combined_detail = f"位置{position_score:+d}+模式{mode_score:+d}+验证{trend_bonus:+d}"

    # v3.520: Vegas隧道评分 (±2)
    vegas_score = 0
    vegas_reason = "N/A"
    if symbol and ohlcv_bars and len(ohlcv_bars) >= 30:
        try:
            # 获取预计算缓存
            timeframe = 15  # 默认15分钟
            precomp = get_precomputed_cache(symbol, timeframe)
            ema_144 = precomp.ema_144
            ema_169 = precomp.ema_169
            last_close = ohlcv_bars[-1].get("close", 0) if ohlcv_bars else 0

            if ema_144 > 0 and ema_169 > 0 and last_close > 0:
                above_tunnel = last_close > ema_169
                in_tunnel = ema_144 < last_close <= ema_169
                below_tunnel = last_close <= ema_144

                # 根据初步信号方向计算Vegas分
                preliminary_signal = "BUY" if (pattern_score + donchian_combined_score) >= 4 else ("SELL" if (pattern_score + donchian_combined_score) <= -4 else "HOLD")

                if preliminary_signal in ("BUY", "STRONG_BUY"):
                    if above_tunnel:
                        vegas_score = +2
                        vegas_reason = "隧道上方买入(强势)"
                    elif in_tunnel:
                        vegas_score = +1
                        vegas_reason = "隧道内买入(中性)"
                    else:
                        vegas_score = -1
                        vegas_reason = "隧道下方买入(逆势)"
                elif preliminary_signal in ("SELL", "STRONG_SELL"):
                    if below_tunnel:
                        vegas_score = +2
                        vegas_reason = "隧道下方卖出(强势)"
                    elif in_tunnel:
                        vegas_score = +1
                        vegas_reason = "隧道内卖出(中性)"
                    else:
                        vegas_score = -1
                        vegas_reason = "隧道上方卖出(逆势)"
                else:
                    vegas_score = 0
                    vegas_reason = f"HOLD无Vegas调整(EMA144={ema_144:.2f},EMA169={ema_169:.2f})"
        except Exception as e:
            vegas_reason = f"Vegas计算异常: {e}"

    # v3.520: 根据基础分数判断初步信号方向，用于计算每日偏向分
    base_score_for_bias = pattern_score + donchian_combined_score + volume_score + wyckoff_score
    if base_score_for_bias >= 6:
        preliminary_direction = "BUY"
    elif base_score_for_bias <= -6:
        preliminary_direction = "SELL"
    else:
        preliminary_direction = "HOLD"

    # v3.499: 获取每日偏向评分调整 (只对今天手动设置的偏向生效)
    daily_bias_score, daily_bias_reason = get_daily_bias_l2_score(symbol, preliminary_direction)

    # v3.520: 5大类总分 (形态±6 + 唐纳奇综合±8 + 量能±2 + Wyckoff±2 + 每日偏向±2 + Vegas±2 = ±22)
    score_total = pattern_score + donchian_combined_score + volume_score + wyckoff_score + daily_bias_score + vegas_score

    print(f"[v3.520] ══════════════════════════════════════════════════")
    print(f"[v3.520] 5大类评分汇总 (v3.520合并唐纳奇+Vegas隧道):")
    print(f"[v3.520]   形态分: {pattern_score:+d} (±6)")
    print(f"[v3.520]   唐纳奇综合分: {donchian_combined_score:+d} (±8) [{donchian_combined_detail}]")
    print(f"[v3.520]   量能分: {volume_score:+d} (±2)")
    print(f"[v3.520]   Wyckoff策略分: {wyckoff_score:+d} (±2) [{wyckoff_phase or 'N/A'}]")
    print(f"[v3.520]   每日偏向分: {daily_bias_score:+d} (±2) [{daily_bias_reason}]")
    print(f"[v3.520]   Vegas隧道分: {vegas_score:+d} (±2) [{vegas_reason}]")
    print(f"[v3.520]   ─────────────────")
    print(f"[v3.600fix]   总分: {score_total:+d} (范围: -22 ~ +22, STRONG±8/BUY±4)")
    print(f"[v3.520] ══════════════════════════════════════════════════")

    # 保留兼容性变量
    regime_score = 0
    regime_adjustment_reason = "v3.520_simplified"
    trend_score = 0
    volume_penalty = 0
    v3410_score = 0
    v3410_details = {}
    # v3.480: 保留xingshen计算用于参考，但不加入总分
    if ohlcv_bars and len(ohlcv_bars) >= 10:
        try:
            xingshen_result = calculate_xingshen_score(ohlcv_bars, lookback=10)
            v3410_details["xingshen"] = xingshen_result
        except Exception:
            pass  # 忽略错误

    weighted_adjustment = 0  # 兼容性保留

    # v3.600fix-A: 统一L2阈值 (总分±22)
    # STRONG≥8/BUY≥4/HOLD[-3,+3]/SELL≤-4/STRONG_SELL≤-8
    # 与外层 compute_l2_macro_exec_bias_enhanced() 阈值一致
    if score_total >= 8:
        exec_bias = "STRONG_BUY"
    elif score_total >= 4:
        exec_bias = "BUY"
    elif score_total <= -8:
        exec_bias = "STRONG_SELL"
    elif score_total <= -4:
        exec_bias = "SELL"
    else:
        exec_bias = "HOLD"
    
    
    # ===== v2.120: SR 全局位置硬性保护（混合分级方案） =====
    
    dist_to_resist_pct = dist_to_resistance_pct
    dist_to_supp_pct = dist_to_support_pct
    
    veto_applied = False
    veto_reason = None
    original_exec_bias = exec_bias
    
    # === 高位保护规则 ===
    
    # Level 1: 极端高位（< 3%）→ 强制 SELL
    if dist_to_resist_pct < 0.03:
        if exec_bias in ["STRONG_BUY", "BUY"]:
            print(f"[SR_FORCE_SELL] 极高位({dist_to_resist_pct:.2%})，强制改为卖出: {exec_bias} → SELL")
            exec_bias = "SELL"
            veto_applied = True
            veto_reason = "EXTREME_HIGH_FORCE_SELL"
    
    # Level 2: 高位（3% ~ 5%）→ 禁止 BUY
    elif dist_to_resist_pct < 0.05:
        if exec_bias in ["STRONG_BUY", "BUY"]:
            print(f"[SR_VETO_BUY] 高位({dist_to_resist_pct:.2%})，禁止买入: {exec_bias} → HOLD")
            exec_bias = "HOLD"
            veto_applied = True
            veto_reason = "HIGH_RESIST_VETO_BUY"
    
    # Level 3: 接近高位（5% ~ 10%）→ 降级 BUY
    elif dist_to_resist_pct < 0.10:
        if exec_bias == "STRONG_BUY":
            print(f"[SR_DOWNGRADE] 接近阻力({dist_to_resist_pct:.2%})，降级: STRONG_BUY → BUY")
            exec_bias = "BUY"
            veto_applied = True
            veto_reason = "NEAR_RESIST_DOWNGRADE_BUY"
    
    # === 低位保护规则 ===
    
    # Level 1: 极端低位（< 3%）→ 强制 BUY
    if dist_to_supp_pct < 0.03 and not veto_applied:
        if exec_bias in ["STRONG_SELL", "SELL"]:
            print(f"[SR_FORCE_BUY] 极低位({dist_to_supp_pct:.2%})，强制改为买入: {exec_bias} → BUY")
            exec_bias = "BUY"
            veto_applied = True
            veto_reason = "EXTREME_LOW_FORCE_BUY"
    
    # Level 2: 低位（3% ~ 5%）→ 禁止 SELL
    elif dist_to_supp_pct < 0.05 and not veto_applied:
        if exec_bias in ["STRONG_SELL", "SELL"]:
            print(f"[SR_VETO_SELL] 低位({dist_to_supp_pct:.2%})，禁止卖出: {exec_bias} → HOLD")
            exec_bias = "HOLD"
            veto_applied = True
            veto_reason = "LOW_SUPPORT_VETO_SELL"
    
    # Level 3: 接近低位（5% ~ 10%）→ 降级 SELL
    elif dist_to_supp_pct < 0.10 and not veto_applied:
        if exec_bias == "STRONG_SELL":
            print(f"[SR_DOWNGRADE] 接近支撑({dist_to_supp_pct:.2%})，降级: STRONG_SELL → SELL")
            exec_bias = "SELL"
            veto_applied = True
            veto_reason = "NEAR_SUPPORT_DOWNGRADE_SELL"

    # ═══════════════════════════════════════════════════════════════════════
    # v3.487 P0-2 + P1-4: 回调企稳检测 + 底部反转保护
    # ═══════════════════════════════════════════════════════════════════════
    v3487_stabilization = {"is_stabilizing": False, "reason": "NOT_CHECKED"}
    v3487_bottom_protect = {"should_protect": False, "reason": "NOT_CHECKED"}

    if exec_bias in ["SELL", "STRONG_SELL"] and not veto_applied:
        # P0-2: 检测回调企稳
        v3487_stabilization = detect_pullback_stabilization_v3487(ohlcv_bars, lookback=10, threshold=0.05)
        if v3487_stabilization["is_stabilizing"]:
            print(f"[v3.487] 回调企稳检测: 回调{v3487_stabilization['pullback_pct']*100:.1f}% + {v3487_stabilization['stabilization_pattern']} → SELL暂停")
            exec_bias = "HOLD"
            veto_applied = True
            veto_reason = f"V3487_STABILIZATION_{v3487_stabilization['stabilization_pattern']}"

        # P1-4: 底部反转保护 (只有在企稳检测未触发时才检查)
        if not veto_applied and exec_bias in ["SELL", "STRONG_SELL"]:
            # 需要计算RSI用于保护检测
            _closes_for_rsi = [b.get("close", 0) for b in ohlcv_bars] if ohlcv_bars else []
            _rsi14_for_protect = calc_rsi(_closes_for_rsi, period=14) if len(_closes_for_rsi) >= 14 else None
            v3487_bottom_protect = check_bottom_reversal_protection_v3487(_rsi14_for_protect, ohlcv_bars)
            if v3487_bottom_protect["should_protect"]:
                print(f"[v3.487] 底部反转保护: {v3487_bottom_protect['reason']} → SELL暂停")
                exec_bias = "HOLD"
                veto_applied = True
                veto_reason = f"V3487_BOTTOM_PROTECT_{v3487_bottom_protect['reason']}"

    # v3.370: 记录降级信息到返回值
    if veto_applied:
        # 对于强制反向，score_total 设为 0
        if veto_reason and ("FORCE" in veto_reason):
            score_total = 0

        # v3.370: 生成降级描述
        downgrade_desc = f"{original_exec_bias}→{exec_bias}"
        if "DOWNGRADE" in veto_reason:
            downgrade_desc += f" (SR位置降级)"
        elif "VETO" in veto_reason:
            downgrade_desc += f" (SR位置否决)"
        elif "FORCE" in veto_reason:
            downgrade_desc += f" (SR强制反向)"

        return {
            "exec_bias": exec_bias,
            "score_total": score_total,
            # v3.520: 5大类评分
            "score_pattern": pattern_score,      # 形态分 (±6)
            "score_donchian_combined": donchian_combined_score,  # v3.520: 唐纳奇综合分 (±8)
            "donchian_combined_detail": donchian_combined_detail,  # v3.520: 唐纳奇综合分细节
            "score_volume": volume_score,        # 量能分 (±2)
            "score_wyckoff": wyckoff_score,      # Wyckoff策略分 (±2)
            "score_daily_bias": daily_bias_score,  # 每日偏向分 (±2)
            "score_vegas": vegas_score,          # v3.520: Vegas隧道分 (±2)
            "vegas_reason": vegas_reason,        # v3.520: Vegas评分原因
            "daily_bias_reason": daily_bias_reason,
            # 兼容性保留 (旧字段)
            "score_position": position_score,    # 位置分 (±4) - 已合并到唐纳奇综合分
            "score_donchian": donchian_score,    # 旧唐纳奇通道分
            "donchian_reason": donchian_reason,
            "trend_instability": instability_penalty,
            "wyckoff_phase": wyckoff_phase,
            "wyckoff_score_reason": wyckoff_score_reason,
            "l2_strategy": l2_strategy,
            # 形态分细分 (用于调试)
            "score_pa": pa_score,
            "score_2b": two_b_score,
            "score_123": one23_score,
            "score_candle_shape": candle_shape_score,
            "candle_shape_name": candle_shape_name,
            "base_pattern_score": base_pattern_score,
            "donchian_multiplier": donchian_multiplier,
            "pos_in_channel": pos_in_channel,
            "volume_detail": volume_detail,
            # 兼容性保留
            "score_trend": trend_score,
            "score_regime": regime_score,
            "regime_adjustment_reason": regime_adjustment_reason,
            "veto_reason": veto_reason,
            "veto_applied": True,
            "original_exec_bias": original_exec_bias,
            "downgrade_desc": downgrade_desc,
            "score_v3410": v3410_score,
            "v3410_details": v3410_details,
            "score_volume_penalty": volume_penalty,
            "score_weighted": weighted_adjustment,
            # v3.520: 突破/震荡模式分 + 趋势强化分 (已合并到唐纳奇综合分)
            "score_mode": mode_score,
            "mode_reason": mode_reason,
            "trend_bonus": trend_bonus,
        }

    # ===== SR 全局保护结束 =====

    # v3.520: 正常返回 - 5大类评分结构
    return {
        "exec_bias": exec_bias,
        "score_total": score_total,
        # v3.520: 5大类评分
        "score_pattern": pattern_score,      # 形态分 (±6)
        "score_donchian_combined": donchian_combined_score,  # v3.520: 唐纳奇综合分 (±8)
        "donchian_combined_detail": donchian_combined_detail,  # v3.520: 唐纳奇综合分细节
        "score_volume": volume_score,        # 量能分 (±2)
        "score_wyckoff": wyckoff_score,      # Wyckoff策略分 (±2)
        "score_daily_bias": daily_bias_score,  # 每日偏向分 (±2)
        "score_vegas": vegas_score,          # v3.520: Vegas隧道分 (±2)
        "vegas_reason": vegas_reason,        # v3.520: Vegas评分原因
        "daily_bias_reason": daily_bias_reason,
        # 兼容性保留 (旧字段)
        "score_position": position_score,    # 位置分 (±4) - 已合并到唐纳奇综合分
        "score_donchian": donchian_score,    # 旧唐纳奇通道分
        "donchian_reason": donchian_reason,
        "trend_instability": instability_penalty,
        "wyckoff_phase": wyckoff_phase,
        "wyckoff_score_reason": wyckoff_score_reason,
        "l2_strategy": l2_strategy,
        # 形态分细分 (用于调试)
        "score_pa": pa_score,
        "score_2b": two_b_score,
        "score_123": one23_score,
        "score_candle_shape": candle_shape_score,
        "candle_shape_name": candle_shape_name,
        "base_pattern_score": base_pattern_score,
        "donchian_multiplier": donchian_multiplier,
        "pos_in_channel": pos_in_channel,
        "volume_detail": volume_detail,
        # 兼容性保留
        "score_trend": trend_score,
        "score_regime": regime_score,
        "regime_adjustment_reason": regime_adjustment_reason,
        "veto_applied": False,
        "original_exec_bias": exec_bias,
        "downgrade_desc": None,
        "score_v3410": v3410_score,
        "v3410_details": v3410_details,
        "score_volume_penalty": volume_penalty,
        "score_weighted": weighted_adjustment,
        # v3.520: 突破/震荡模式分 + 趋势强化分 (已合并到唐纳奇综合分)
        "score_mode": mode_score,
        "mode_reason": mode_reason,
        "trend_bonus": trend_bonus,
    }


# =========================================
# v2.390: L1 内部 LLM-Grid 互相尊重协商机制
# =========================================

def detect_llm_grid_conflict(
    llm_action: str,
    grid_action: str,
    llm_confidence: float,
    grid_confidence: float,
) -> dict:
    """
    检测 LLM 和 Grid 的冲突程度
    
    类似 L2 10m 修正的冲突检测逻辑
    
    Args:
        llm_action: LLM 原始建议 (BUY/SELL/HOLD)
        grid_action: Grid 规则建议 (BUY/SELL/HOLD)
        llm_confidence: LLM 置信度 (0.0-1.0)
        grid_confidence: Grid 置信度 (0.0-1.0)
    
    Returns:
        {
            "level": "NONE/LOW/MEDIUM/HIGH",
            "type": "AGREE/PARTIAL/OPPOSITE",
            "description": str
        }
    """
    
    # 完全一致
    if llm_action == grid_action:
        return {
            "level": "NONE",
            "type": "AGREE",
            "description": f"LLM和Grid完全一致: {llm_action}"
        }
    
    # 方向完全相反 (BUY vs SELL)
    if (llm_action == "BUY" and grid_action == "SELL") or \
       (llm_action == "SELL" and grid_action == "BUY"):
        return {
            "level": "HIGH",
            "type": "OPPOSITE",
            "description": f"方向完全相反: LLM={llm_action} vs Grid={grid_action}"
        }
    
    # 部分冲突 (一方 HOLD)
    if llm_action == "HOLD" or grid_action == "HOLD":
        # 判断冲突等级
        conf_diff = abs(llm_confidence - grid_confidence)
        
        if conf_diff >= 0.20:
            # 置信度差距大
            return {
                "level": "LOW",
                "type": "PARTIAL",
                "description": f"一方保守，置信度差距大({conf_diff:.2f})"
            }
        else:
            # 置信度接近
            return {
                "level": "MEDIUM",
                "type": "PARTIAL",
                "description": f"一方保守，置信度接近({conf_diff:.2f})"
            }
    
    # 不应该到这里
    return {
        "level": "UNKNOWN",
        "type": "UNKNOWN",
        "description": "未知冲突类型"
    }


def merge_llm_with_grid(
    llm_raw_action: str,
    llm_confidence: float,
    llm_reason: str,
    grid_action: str,
    grid_key: tuple,
    grid_confidence: float,
    pa_edge_tag: str,
    phase_code: str,
) -> dict:
    """
    L1 内部 LLM-Grid 互相尊重协商决策
    
    完全参考 L2 10m 修正逻辑 (apply_corrections_to_l2):
      1. 冲突检测
      2. 置信度比较  
      3. 协商决策
      4. 降级机制
      5. 日志记录
    
    类比关系:
      LLM = L2 主周期 (战略层)
      Grid = L2 小周期 (战术层)
    
    Args:
        llm_raw_action: LLM 原始建议 (BUY/SELL/HOLD)
        llm_confidence: LLM 置信度 (0.0-1.0)
        llm_reason: LLM 决策理由
        grid_action: Grid 规则建议 (BUY/SELL/HOLD 或 None)
        grid_key: Grid 查询键 (6维tuple)
        grid_confidence: Grid 规则置信度 (0.0-1.0)
        pa_edge_tag: PA优势标签 (BUY/SELL/NONE)
        phase_code: Wyckoff 阶段代码
    
    Returns:
        {
            "final_action": "BUY/SELL/HOLD",
            "confidence": float,
            "modified": bool,  # 类似 L2 的 modified
            "decision_path": str,
            "agreement_type": str,
            "llm_used": bool,
            "grid_used": bool,
            "reason": str,
            "base_action": str,
            "grid_action": str or None,
            "conflict_info": dict,
        }
    """
    
    # ========================================
    # STEP 1: 特殊情况处理 (最高优先级)
    # ========================================
    
    # 1.1: 无 PA Edge (类似 L2 数据不足)
    # v3.241 G1: 放松pa_edge检测，不再强制降级置信度
    if pa_edge_tag == "NONE":
        print(f"[v3.241 G1] 无PA优势，完全信任LLM战略: {llm_raw_action} (conf={llm_confidence:.2f}，不降级)")
        return {
            "final_action": llm_raw_action,
            "confidence": llm_confidence,  # v3.241 G1: 不再降级，保持原置信度
            "modified": False,
            "decision_path": "NO_PA_EDGE_TRUST_LLM",
            "agreement_type": "NO_PA_EDGE",
            "llm_used": True,
            "grid_used": False,
            "reason": "无PA优势，完全信任LLM战略判断(v3.241)",
            "base_action": llm_raw_action,
            "grid_action": None,
            "conflict_info": {"level": "NONE", "type": "NO_PA_EDGE"},
        }
    
    # 1.2: Grid 无匹配规则 (类似 L2 小周期数据不足)
    if grid_action is None:
        print(f"[L1_MERGE] Grid无匹配，信任LLM: {llm_raw_action} (conf={llm_confidence:.2f})")
        return {
            "final_action": llm_raw_action,
            "confidence": llm_confidence,
            "modified": False,
            "decision_path": "GRID_NO_MATCH_TRUST_LLM",
            "agreement_type": "GRID_NO_MATCH",
            "llm_used": True,
            "grid_used": False,
            "reason": f"Grid无匹配规则，信任LLM",
            "base_action": llm_raw_action,
            "grid_action": None,
            "conflict_info": {"level": "NONE", "type": "GRID_NO_MATCH"},
        }
    
    # ========================================
    # STEP 2: 冲突检测 (类似 L2 has_conflict)
    # ========================================
    
    conflict_info = detect_llm_grid_conflict(
        llm_action=llm_raw_action,
        grid_action=grid_action,
        llm_confidence=llm_confidence,
        grid_confidence=grid_confidence,
    )
    
    conflict_level = conflict_info.get("level")
    conflict_type = conflict_info.get("type")
    
    # ========================================
    # STEP 3: 无冲突 - 一致强化 (类似 L2 无修正)
    # ========================================
    
    if conflict_level == "NONE":
        enhanced_conf = min(1.0, llm_confidence + 0.15)
        print(f"[L1_MERGE] ✓ LLM与Grid完全一致: {llm_raw_action} "
              f"(conf: {llm_confidence:.2f}→{enhanced_conf:.2f})")
        return {
            "final_action": llm_raw_action,
            "confidence": enhanced_conf,
            "modified": False,
            "decision_path": "LLM_GRID_FULL_AGREEMENT",
            "agreement_type": "FULL_AGREEMENT",
            "llm_used": True,
            "grid_used": True,
            "reason": "LLM和Grid完全一致，强化信号",
            "base_action": llm_raw_action,
            "grid_action": grid_action,
            "conflict_info": conflict_info,
        }
    
    # ========================================
    # STEP 4: 高置信度覆盖 (类似 L2 强修正)
    # ========================================
    
    # 4.1: LLM 极高置信度 (≥0.90)
    if llm_confidence >= 0.90:
        print(f"[L1_MERGE] ⚡ LLM极高置信度({llm_confidence:.2f})强制通过: "
              f"{llm_raw_action} (覆盖Grid={grid_action})")
        return {
            "final_action": llm_raw_action,
            "confidence": llm_confidence,
            "modified": True,
            "decision_path": "LLM_VERY_HIGH_CONFIDENCE_FORCE",
            "agreement_type": "LLM_FORCE_OVERRIDE",
            "llm_used": True,
            "grid_used": False,
            "reason": f"LLM极高置信度({llm_confidence:.2f})，强制通过",
            "base_action": llm_raw_action,
            "grid_action": grid_action,
            "conflict_info": conflict_info,
        }
    
    # 4.2: Grid 极高置信度 (≥0.90)
    if grid_confidence >= 0.90:
        print(f"[L1_MERGE] 🎯 Grid极高置信度({grid_confidence:.2f})强制通过: "
              f"{grid_action} (覆盖LLM={llm_raw_action})")
        return {
            "final_action": grid_action,
            "confidence": grid_confidence,
            "modified": True,
            "decision_path": "GRID_VERY_HIGH_CONFIDENCE_FORCE",
            "agreement_type": "GRID_FORCE_OVERRIDE",
            "llm_used": False,
            "grid_used": True,
            "reason": f"Grid极高置信度({grid_confidence:.2f})，强制通过",
            "base_action": llm_raw_action,
            "grid_action": grid_action,
            "conflict_info": conflict_info,
        }
    
    # 4.3: LLM 高置信度 (0.85-0.89)
    if llm_confidence >= 0.85 and llm_confidence < 0.90:
        if conflict_level in ["LOW", "MEDIUM"]:
            print(f"[L1_MERGE] 💡 LLM高置信度({llm_confidence:.2f})覆盖Grid: {llm_raw_action}")
            return {
                "final_action": llm_raw_action,
                "confidence": llm_confidence * 0.95,  # 轻微降级
                "modified": True,
                "decision_path": "LLM_HIGH_CONFIDENCE_OVERRIDE",
                "agreement_type": "LLM_OVERRIDE",
                "llm_used": True,
                "grid_used": False,
                "reason": f"LLM高置信度({llm_confidence:.2f}), 冲突等级{conflict_level}",
                "base_action": llm_raw_action,
                "grid_action": grid_action,
                "conflict_info": conflict_info,
            }
    
    # 4.4: Grid 高置信度 (0.85-0.89)
    if grid_confidence >= 0.85 and grid_confidence < 0.90:
        if conflict_level in ["LOW", "MEDIUM"]:
            print(f"[L1_MERGE] 📋 Grid高置信度({grid_confidence:.2f})覆盖LLM: {grid_action}")
            return {
                "final_action": grid_action,
                "confidence": grid_confidence * 0.95,  # 轻微降级
                "modified": True,
                "decision_path": "GRID_HIGH_CONFIDENCE_OVERRIDE",
                "agreement_type": "GRID_OVERRIDE",
                "llm_used": False,
                "grid_used": True,
                "reason": f"Grid高置信度({grid_confidence:.2f}), 冲突等级{conflict_level}",
                "base_action": llm_raw_action,
                "grid_action": grid_action,
                "conflict_info": conflict_info,
            }
    
    # ========================================
    # STEP 5: 严重冲突 - 智能处理 (v2.540 优化)
    # ========================================
    
    if conflict_type == "OPPOSITE":
        # v2.540 优化: 检查置信度差异
        conf_diff = abs(llm_confidence - grid_confidence)
        
        # 5.1: LLM 极高置信度且远超 Grid
        if llm_confidence >= 0.90 and conf_diff > 0.20:
            print(f"[L1_MERGE] ⚡ OPPOSITE 冲突但 LLM 极高置信度({llm_confidence:.2f})强制通过: {llm_raw_action}")
            return {
                "final_action": llm_raw_action,
                "confidence": llm_confidence * 0.8,  # 降级但保留
                "modified": True,
                "decision_path": "OPPOSITE_BUT_LLM_VERY_HIGH",
                "agreement_type": "LLM_OVERRIDE_OPPOSITE",
                "llm_used": True,
                "grid_used": False,
                "reason": f"OPPOSITE 冲突但 LLM 极高置信度({llm_confidence:.2f}) >> Grid({grid_confidence:.2f})",
                "base_action": llm_raw_action,
                "grid_action": grid_action,
                "conflict_info": conflict_info,
            }
        
        # 5.2: Grid 极高置信度且远超 LLM
        elif grid_confidence >= 0.90 and conf_diff > 0.20:
            print(f"[L1_MERGE] 🎯 OPPOSITE 冲突但 Grid 极高置信度({grid_confidence:.2f})强制通过: {grid_action}")
            return {
                "final_action": grid_action,
                "confidence": grid_confidence * 0.8,
                "modified": True,
                "decision_path": "OPPOSITE_BUT_GRID_VERY_HIGH",
                "agreement_type": "GRID_OVERRIDE_OPPOSITE",
                "llm_used": False,
                "grid_used": True,
                "reason": f"OPPOSITE 冲突但 Grid 极高置信度({grid_confidence:.2f}) >> LLM({llm_confidence:.2f})",
                "base_action": llm_raw_action,
                "grid_action": grid_action,
                "conflict_info": conflict_info,
            }
        
        # 5.3: 置信度相近或都不够高，保守 HOLD
        else:
            print(f"[L1_MERGE] ⚠️ OPPOSITE 冲突且置信度相近: LLM={llm_raw_action}({llm_confidence:.2f}) vs Grid={grid_action}({grid_confidence:.2f}) → HOLD")
            return {
                "final_action": "HOLD",
                "confidence": 0.0,
                "modified": True,
                "decision_path": "OPPOSITE_CONFLICT_HOLD",
                "agreement_type": "OPPOSITE_CONFLICT",
                "llm_used": False,
                "grid_used": False,
                "reason": f"OPPOSITE 冲突且置信度相近 (diff={conf_diff:.2f}), 保守观望",
                "base_action": llm_raw_action,
                "grid_action": grid_action,
                "conflict_info": conflict_info,
            }
    
    # ========================================
    # STEP 6: 部分冲突 - 协商处理 (类似 L2 降级)
    # ========================================
    
    if conflict_type == "PARTIAL":
        # 一方 HOLD，一方 BUY/SELL
        
        # 6.1: LLM 保守 (HOLD)
        if llm_raw_action == "HOLD":
            if grid_confidence > llm_confidence + 0.15:
                # Grid 明显更确定
                print(f"[L1_MERGE] Grid更明确({grid_confidence:.2f} > {llm_confidence:.2f}+0.15): {grid_action}")
                return {
                    "final_action": grid_action,
                    "confidence": grid_confidence * 0.75,  # 降级
                    "modified": True,
                    "decision_path": "GRID_MORE_DECISIVE_OVERRIDE_HOLD",
                    "agreement_type": "GRID_MORE_DECISIVE",
                    "llm_used": False,
                    "grid_used": True,
                    "reason": "LLM保守但Grid更明确，采用Grid但降低置信度",
                    "base_action": llm_raw_action,
                    "grid_action": grid_action,
                    "conflict_info": conflict_info,
                }
            else:
                # 置信度接近，尊重 LLM 保守
                print(f"[L1_MERGE] 尊重LLM保守: HOLD")
                return {
                    "final_action": "HOLD",
                    "confidence": llm_confidence,
                    "modified": False,
                    "decision_path": "RESPECT_LLM_CONSERVATIVE",
                    "agreement_type": "LLM_CONSERVATIVE",
                    "llm_used": True,
                    "grid_used": False,
                    "reason": "LLM建议保守，Grid置信度不足以推翻",
                    "base_action": llm_raw_action,
                    "grid_action": grid_action,
                    "conflict_info": conflict_info,
                }
        
        # 6.2: Grid 保守 (HOLD)
        if grid_action == "HOLD":
            if llm_confidence > grid_confidence + 0.15:
                # LLM 明显更确定
                print(f"[L1_MERGE] LLM更明确({llm_confidence:.2f} > {grid_confidence:.2f}+0.15): {llm_raw_action}")
                return {
                    "final_action": llm_raw_action,
                    "confidence": llm_confidence * 0.75,  # 降级
                    "modified": True,
                    "decision_path": "LLM_MORE_DECISIVE_OVERRIDE_HOLD",
                    "agreement_type": "LLM_MORE_DECISIVE",
                    "llm_used": True,
                    "grid_used": False,
                    "reason": "Grid保守但LLM更明确，采用LLM但降低置信度",
                    "base_action": llm_raw_action,
                    "grid_action": grid_action,
                    "conflict_info": conflict_info,
                }
            else:
                # 置信度接近，尊重 Grid 保守
                print(f"[L1_MERGE] 尊重Grid保守: HOLD")
                return {
                    "final_action": "HOLD",
                    "confidence": grid_confidence,
                    "modified": False,
                    "decision_path": "RESPECT_GRID_CONSERVATIVE",
                    "agreement_type": "GRID_CONSERVATIVE",
                    "llm_used": False,
                    "grid_used": True,
                    "reason": "Grid建议保守，LLM置信度不足以推翻",
                    "base_action": llm_raw_action,
                    "grid_action": grid_action,
                    "conflict_info": conflict_info,
                }
    
    # ========================================
    # STEP 7: 默认处理 - 置信度比较 (类似 L2 最终决策)
    # ========================================
    
    if grid_confidence >= llm_confidence:
        final_action = grid_action
        final_conf = grid_confidence * 0.7  # 降级
        used_grid = True
        used_llm = False
        reason = f"Grid置信度更高({grid_confidence:.2f} vs {llm_confidence:.2f}), 但降级"
    else:
        final_action = llm_raw_action
        final_conf = llm_confidence * 0.7  # 降级
        used_grid = False
        used_llm = True
        reason = f"LLM置信度更高({llm_confidence:.2f} vs {grid_confidence:.2f}), 但降级"
    
    print(f"[L1_MERGE] 默认: {final_action} ({reason})")
    return {
        "final_action": final_action,
        "confidence": final_conf,
        "modified": True,
        "decision_path": "DEFAULT_HIGHER_CONFIDENCE",
        "agreement_type": "TIE_BREAK",
        "llm_used": used_llm,
        "grid_used": used_grid,
        "reason": reason,
        "base_action": llm_raw_action,
        "grid_action": grid_action,
        "conflict_info": conflict_info,
    }




# =========================================
# v2.395: L1-L2 互相尊重协商辅助函数
# =========================================

def analyze_l2_veto_strength(
    l2_exec_bias: str,
    l2_score: int = 0,
    l2_reasons: list = None,
) -> str:
    """
    分析 L2 否决强度
    
    Args:
        l2_exec_bias: L2 执行偏好
        l2_score: L2 评分
        l2_reasons: L2 原因列表
    
    Returns:
        "NONE" / "LOW" / "MEDIUM" / "HIGH" / "CRITICAL"
    """
    if l2_exec_bias != "HOLD":
        return "NONE"
    
    l2_reasons = l2_reasons or []
    config = L1_L2_MUTUAL_RESPECT_CONFIG
    
    # 转换为字符串方便搜索
    reasons_str = " ".join([str(r) for r in l2_reasons])
    
    # 检查 CRITICAL 关键词
    for keyword in config["critical_keywords"]:
        if keyword.lower() in reasons_str.lower():
            return "CRITICAL"
    
    # 检查 HIGH 关键词
    for keyword in config["high_keywords"]:
        if keyword.lower() in reasons_str.lower():
            return "HIGH"
    
    # 检查 MEDIUM 关键词
    for keyword in config["medium_keywords"]:
        if keyword.lower() in reasons_str.lower():
            return "MEDIUM"
    
    # 基于分数判断
    if l2_score <= config["critical_score_threshold"]:
        return "HIGH"
    elif l2_score <= config["high_score_threshold"]:
        return "MEDIUM"
    else:
        return "LOW"


def merge_l2_with_l1_action(l1_action, l2_exec_bias, position_units, 
                            open_buys, open_sells, n_swing_override=False,
                            # ===== v2.395 新增参数 =====
                            l1_confidence=0.0, l1_merge_info=None,
                            l2_score=0, l2_reasons=None,
                            # ===== v2.748 新增参数 =====
                            market_regime="RANGE",
                            # ===== v2.978 新增参数 =====
                            l1_market_regime_dict=None):  # [v2.978] L1市场状态字典（含顺大逆小）
    """
    L2→最终动作合并规则 (v2.395: 增加 L1-L2 互相尊重协商)
    
    v2.395 新增参数:
        l1_confidence: L1 最终置信度 (来自 L1 协商结果)
        l1_merge_info: L1 内部协商详情 (LLM-Grid)
        l2_score: L2 评分 (用于判断否决强度)
        l2_reasons: L2 否决原因列表
    
    v2.748 新增参数:
        market_regime: 市场趋势regime (UPTREND_RIDE/DOWNTREND_RIDE/RANGE)
                       当L1=HOLD但L2=STRONG且趋势明确时，允许执行
    
    v2.978 新增参数:
        l1_market_regime_dict: L1市场状态字典，含big_small_pattern
                               当顺大逆小时，阻止L2触发交易
    """
    
    # ========== [PATCHED] N-swing强信号豁免逻辑 ==========
    # 最高优先级：N-swing强信号无条件通过L2 veto
    if n_swing_override and l2_exec_bias in ("STRONG_BUY", "STRONG_SELL"):
        if l1_action == "BUY" and l2_exec_bias == "STRONG_BUY":
            print(f"[N-SWING EXEMPT] 强买信号豁免L2 veto: {l1_action} + {l2_exec_bias} → BUY")
            return {
                "final_action": "BUY",
                "is_entry": True,
                "is_exit": False,
                "l2_block_reason": None,
                "exit_override_reason": None,
                "l2_veto_applied": False,
                "veto_reason": None,
                "n_swing_forced": True,  # [PATCHED] 新增标记
            }
        elif l1_action == "SELL" and l2_exec_bias == "STRONG_SELL":
            print(f"[N-SWING EXEMPT] 强卖信号豁免L2 veto: {l1_action} + {l2_exec_bias} → SELL")
            return {
                "final_action": "SELL",
                "is_entry": True,
                "is_exit": False,
                "l2_block_reason": None,
                "exit_override_reason": None,
                "l2_veto_applied": False,
                "veto_reason": None,
                "n_swing_forced": True,  # [PATCHED] 新增标记
            }
        # 如果L1是HOLD但N-swing是强信号，也可以考虑覆盖
        # 但这里保持保守，只在L1方向与N-swing一致时豁免
    # ========== [PATCHED] N-swing豁免逻辑结束 ==========
    
    # ========== [v2.978] 顺大逆小检查 — GCC-0049: 已取消拦截 ==========
    # 原逻辑: 大跌+小反弹阻止BUY, 大涨+小回调阻止SELL
    # GCC-0049: 取消x4顺大逆小门禁, 靠FilterChain+其他门禁过滤
    if l1_market_regime_dict:
        big_small_pattern = l1_market_regime_dict.get("big_small_pattern", "NONE")
        if big_small_pattern not in ("NONE", None, ""):
            log_to_server(f"[GCC-0049][观察] 顺大逆小={big_small_pattern} L2={l2_exec_bias} (不拦截)")
    # ========== [v2.978] 顺大逆小检查结束 ==========
    
    # ========== [v2.748] L1=HOLD + L2=STRONG + 趋势明确 → 执行 ==========
    # 注意：此函数只在 exec_bias == HOLD and has_l2_conflict 时被调用
    # 所以当L2=STRONG_BUY/STRONG_SELL时，此段代码不会被触发
    # v2.749已在统一决策引擎(final_decision_engine)中正确处理此逻辑
    # 保留此代码作为备用/兼容层
    # ========================================================================
    if l1_action == "HOLD" and l2_exec_bias in ("STRONG_BUY", "STRONG_SELL"):
        # 检查趋势是否与L2方向一致
        trend_confirms_buy = (market_regime == "UPTREND_RIDE" and l2_exec_bias == "STRONG_BUY")
        trend_confirms_sell = (market_regime == "DOWNTREND_RIDE" and l2_exec_bias == "STRONG_SELL")
        
        if trend_confirms_buy:
            print(f"[v2.748] ⚡ L1=HOLD但L2=STRONG_BUY+趋势上涨 → 执行BUY")
            print(f"         market_regime={market_regime}, l2_exec_bias={l2_exec_bias}")
            return {
                "final_action": "BUY",
                "is_entry": True,
                "is_exit": False,
                "l2_block_reason": None,
                "exit_override_reason": None,
                "l2_veto_applied": False,
                "veto_reason": None,
                "l1_l2_agreement": "L2_STRONG_TREND_OVERRIDE",
                "trend_override": True,
            }
        
        if trend_confirms_sell:
            print(f"[v2.748] ⚡ L1=HOLD但L2=STRONG_SELL+趋势下跌 → 执行SELL")
            print(f"         market_regime={market_regime}, l2_exec_bias={l2_exec_bias}")
            return {
                "final_action": "SELL",
                "is_entry": False,
                "is_exit": True,
                "l2_block_reason": None,
                "exit_override_reason": None,
                "l2_veto_applied": False,
                "veto_reason": None,
                "l1_l2_agreement": "L2_STRONG_TREND_OVERRIDE",
                "trend_override": True,
            }
        
        # 趋势不明确(RANGE)或方向不一致，保持HOLD
        print(f"[v2.748] L1=HOLD, L2={l2_exec_bias}, regime={market_regime} → 趋势不明确或不一致，保持HOLD")
    # ========== [v2.748] 结束 ==========
    
    if l1_action == "HOLD":
        return {
            "final_action": "HOLD",
            "is_entry": False,
            "is_exit": False,
            "l2_block_reason": None,
            "exit_override_reason": None,
            "l2_veto_applied": False,
            "veto_reason": None,
        }
    
    is_exit_sell = (position_units > 0 or len(open_buys) > 0)
    is_exit_buy = (position_units < 0 or len(open_sells) > 0)
    
    if l1_action == "BUY":
        is_entry = not is_exit_buy
        
        if is_entry:
            # ========== L2 同意 ==========
            if l2_exec_bias in ("BUY", "STRONG_BUY"):
                return {
                    "final_action": "BUY",
                    "is_entry": True,
                    "is_exit": False,
                    "l2_block_reason": None,
                    "exit_override_reason": None,
                    "l2_veto_applied": False,
                    "veto_reason": None,
                    "l1_l2_agreement": "FULL_AGREE",
                }
            
            # ========== L2 不同意 - v2.395 协商逻辑 ==========
            else:
                # 如果未启用互相尊重，走原逻辑 (完全否决)
                if not L1_L2_MUTUAL_RESPECT_CONFIG.get("enabled", True):
                    veto_reason = None
                    if l2_exec_bias == "HOLD":
                        veto_reason = "L2_HOLD_VETO:entry_blocked"
                    else:
                        veto_reason = "L2_VETO:bias=" + str(l2_exec_bias)
                    
                    return {
                        "final_action": "HOLD",
                        "is_entry": True,
                        "is_exit": False,
                        "l2_block_reason": "L2_BLOCK_ENTRY:" + str(l2_exec_bias),
                        "exit_override_reason": None,
                        "l2_veto_applied": True,
                        "veto_reason": veto_reason,
                    }
                
                # ========== v2.395: 互相尊重协商 ==========
                
                # 分析 L2 否决强度
                l2_veto_strength = analyze_l2_veto_strength(
                    l2_exec_bias=l2_exec_bias,
                    l2_score=l2_score,
                    l2_reasons=l2_reasons or [],
                )
                
                config = L1_L2_MUTUAL_RESPECT_CONFIG
                
                # ===== 规则 1: L1 极高置信度 (≥0.90) =====
                if l1_confidence >= config["l1_very_high_threshold"]:
                    # 除非 L2 CRITICAL，否则强制通过
                    if l2_veto_strength == "CRITICAL":
                        print(f"[L1-L2] ⚠️ L2 CRITICAL 否决，即使 L1 极高置信度({l1_confidence:.2f})也无法通过")
                        return {
                            "final_action": "HOLD",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": "L2_CRITICAL_VETO",
                            "exit_override_reason": None,
                            "l2_veto_applied": True,
                            "veto_reason": f"L2_CRITICAL_VETO:L1_conf={l1_confidence:.2f}",
                            "l1_l2_agreement": "L2_CRITICAL_VETO",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                        }
                    else:
                        print(f"[L1-L2] ⚡ L1 极高置信度({l1_confidence:.2f})强制通过BUY (覆盖L2 {l2_veto_strength})")
                        return {
                            "final_action": "BUY",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": None,
                            "exit_override_reason": None,
                            "l2_veto_applied": False,
                            "veto_reason": None,
                            "l1_l2_agreement": "L1_FORCE_OVERRIDE",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                            "override_reason": f"L1_VERY_HIGH_CONFIDENCE:{l1_confidence:.2f}",
                        }
                
                # ===== 规则 2: L1 高置信度 (0.85-0.89) =====
                if l1_confidence >= config["l1_high_threshold"]:
                    # 只能覆盖 LOW/MEDIUM
                    if l2_veto_strength in ("LOW", "MEDIUM"):
                        print(f"[L1-L2] 💡 L1 高置信度({l1_confidence:.2f})覆盖L2 {l2_veto_strength}, BUY通过")
                        return {
                            "final_action": "BUY",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": None,
                            "exit_override_reason": None,
                            "l2_veto_applied": False,
                            "veto_reason": None,
                            "l1_l2_agreement": "L1_HIGH_CONF_OVERRIDE",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                            "override_reason": f"L1_HIGH_CONFIDENCE:{l1_confidence:.2f} > L2_{l2_veto_strength}",
                        }
                    else:
                        # HIGH/CRITICAL 无法覆盖
                        print(f"[L1-L2] ⚠️ L2 {l2_veto_strength} 否决，L1 高置信度({l1_confidence:.2f})无法覆盖")
                        return {
                            "final_action": "HOLD",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": f"L2_{l2_veto_strength}_VETO",
                            "exit_override_reason": None,
                            "l2_veto_applied": True,
                            "veto_reason": f"L2_{l2_veto_strength}_VETO:L1_conf={l1_confidence:.2f}",
                            "l1_l2_agreement": "L2_STRONG_VETO",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                        }
                
                # ===== 规则 3: L1 中等置信度 (0.75-0.84) =====
                if l1_confidence >= config["l1_medium_threshold"]:
                    # 只能覆盖 LOW
                    if l2_veto_strength == "LOW":
                        print(f"[L1-L2] 📉 L1 中置信度({l1_confidence:.2f})覆盖L2 LOW, BUY通过")
                        return {
                            "final_action": "BUY",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": None,
                            "exit_override_reason": None,
                            "l2_veto_applied": False,
                            "veto_reason": None,
                            "l1_l2_agreement": "L1_MED_CONF_OVERRIDE_LOW",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                            "override_reason": f"L1_MED_CONFIDENCE:{l1_confidence:.2f} > L2_LOW",
                        }
                    else:
                        # MEDIUM/HIGH/CRITICAL 无法覆盖
                        print(f"[L1-L2] 🛡️ L1 中置信度({l1_confidence:.2f})，尊重L2 {l2_veto_strength}")
                        return {
                            "final_action": "HOLD",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": f"L2_{l2_veto_strength}_VETO",
                            "exit_override_reason": None,
                            "l2_veto_applied": True,
                            "veto_reason": f"L2_{l2_veto_strength}_VETO:L1_conf={l1_confidence:.2f}",
                            "l1_l2_agreement": "RESPECT_L2",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                        }
                
                # ===== 规则 4: L1 低置信度 (<0.75) =====
                print(f"[L1-L2] 🛡️ L1 低置信度({l1_confidence:.2f})，完全尊重L2")
                return {
                    "final_action": "HOLD",
                    "is_entry": True,
                    "is_exit": False,
                    "l2_block_reason": "L2_VETO",
                    "exit_override_reason": None,
                    "l2_veto_applied": True,
                    "veto_reason": f"L2_VETO:L1_low_conf={l1_confidence:.2f}",
                    "l1_l2_agreement": "RESPECT_L2_LOW_CONF",
                    "l1_confidence": l1_confidence,
                    "l2_veto_strength": l2_veto_strength,
                }
        else:
            bypass = "exit_bypass_L2" if l2_exec_bias == "HOLD" else "exit_allowed"
            return {
                "final_action": "BUY",
                "is_entry": False,
                "is_exit": True,
                "l2_block_reason": None,
                "exit_override_reason": bypass,
                "l2_veto_applied": False,
                "veto_reason": None,
            }
    
    if l1_action == "SELL":
        is_entry = not is_exit_sell
        
        if is_entry:
            if l2_exec_bias in ("SELL", "STRONG_SELL"):
                return {
                    "final_action": "SELL",
                    "is_entry": True,
                    "is_exit": False,
                    "l2_block_reason": None,
                    "exit_override_reason": None,
                    "l2_veto_applied": False,
                    "veto_reason": None,
                    "l1_l2_agreement": "FULL_AGREE",
                }
            else:
                # ========== L2 不同意 - v2.395 协商逻辑 (与BUY对称) ==========
                
                # 如果未启用互相尊重，走原逻辑
                if not L1_L2_MUTUAL_RESPECT_CONFIG.get("enabled", True):
                    veto_reason = None
                    if l2_exec_bias == "HOLD":
                        veto_reason = "L2_HOLD_VETO:entry_blocked"
                    else:
                        veto_reason = "L2_VETO:bias=" + str(l2_exec_bias)
                    
                    return {
                        "final_action": "HOLD",
                        "is_entry": True,
                        "is_exit": False,
                        "l2_block_reason": "L2_BLOCK_ENTRY:" + str(l2_exec_bias),
                        "exit_override_reason": None,
                        "l2_veto_applied": True,
                        "veto_reason": veto_reason,
                    }
                
                # 分析 L2 否决强度
                l2_veto_strength = analyze_l2_veto_strength(
                    l2_exec_bias=l2_exec_bias,
                    l2_score=l2_score,
                    l2_reasons=l2_reasons or [],
                )
                
                config = L1_L2_MUTUAL_RESPECT_CONFIG
                
                # ===== 规则 1: L1 极高置信度 =====
                if l1_confidence >= config["l1_very_high_threshold"]:
                    if l2_veto_strength == "CRITICAL":
                        print(f"[L1-L2] ⚠️ L2 CRITICAL 否决，即使 L1 极高置信度({l1_confidence:.2f})也无法通过")
                        return {
                            "final_action": "HOLD",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": "L2_CRITICAL_VETO",
                            "exit_override_reason": None,
                            "l2_veto_applied": True,
                            "veto_reason": f"L2_CRITICAL_VETO:L1_conf={l1_confidence:.2f}",
                            "l1_l2_agreement": "L2_CRITICAL_VETO",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                        }
                    else:
                        print(f"[L1-L2] ⚡ L1 极高置信度({l1_confidence:.2f})强制通过SELL (覆盖L2 {l2_veto_strength})")
                        return {
                            "final_action": "SELL",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": None,
                            "exit_override_reason": None,
                            "l2_veto_applied": False,
                            "veto_reason": None,
                            "l1_l2_agreement": "L1_FORCE_OVERRIDE",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                            "override_reason": f"L1_VERY_HIGH_CONFIDENCE:{l1_confidence:.2f}",
                        }
                
                # ===== 规则 2: L1 高置信度 =====
                if l1_confidence >= config["l1_high_threshold"]:
                    if l2_veto_strength in ("LOW", "MEDIUM"):
                        print(f"[L1-L2] 💡 L1 高置信度({l1_confidence:.2f})覆盖L2 {l2_veto_strength}, SELL通过")
                        return {
                            "final_action": "SELL",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": None,
                            "exit_override_reason": None,
                            "l2_veto_applied": False,
                            "veto_reason": None,
                            "l1_l2_agreement": "L1_HIGH_CONF_OVERRIDE",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                            "override_reason": f"L1_HIGH_CONFIDENCE:{l1_confidence:.2f} > L2_{l2_veto_strength}",
                        }
                    else:
                        print(f"[L1-L2] ⚠️ L2 {l2_veto_strength} 否决，L1 高置信度({l1_confidence:.2f})无法覆盖")
                        return {
                            "final_action": "HOLD",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": f"L2_{l2_veto_strength}_VETO",
                            "exit_override_reason": None,
                            "l2_veto_applied": True,
                            "veto_reason": f"L2_{l2_veto_strength}_VETO:L1_conf={l1_confidence:.2f}",
                            "l1_l2_agreement": "L2_STRONG_VETO",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                        }
                
                # ===== 规则 3: L1 中等置信度 =====
                if l1_confidence >= config["l1_medium_threshold"]:
                    if l2_veto_strength == "LOW":
                        print(f"[L1-L2] 📉 L1 中置信度({l1_confidence:.2f})覆盖L2 LOW, SELL通过")
                        return {
                            "final_action": "SELL",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": None,
                            "exit_override_reason": None,
                            "l2_veto_applied": False,
                            "veto_reason": None,
                            "l1_l2_agreement": "L1_MED_CONF_OVERRIDE_LOW",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                            "override_reason": f"L1_MED_CONFIDENCE:{l1_confidence:.2f} > L2_LOW",
                        }
                    else:
                        print(f"[L1-L2] 🛡️ L1 中置信度({l1_confidence:.2f})，尊重L2 {l2_veto_strength}")
                        return {
                            "final_action": "HOLD",
                            "is_entry": True,
                            "is_exit": False,
                            "l2_block_reason": f"L2_{l2_veto_strength}_VETO",
                            "exit_override_reason": None,
                            "l2_veto_applied": True,
                            "veto_reason": f"L2_{l2_veto_strength}_VETO:L1_conf={l1_confidence:.2f}",
                            "l1_l2_agreement": "RESPECT_L2",
                            "l1_confidence": l1_confidence,
                            "l2_veto_strength": l2_veto_strength,
                        }
                
                # ===== 规则 4: L1 低置信度 =====
                print(f"[L1-L2] 🛡️ L1 低置信度({l1_confidence:.2f})，完全尊重L2")
                return {
                    "final_action": "HOLD",
                    "is_entry": True,
                    "is_exit": False,
                    "l2_block_reason": "L2_VETO",
                    "exit_override_reason": None,
                    "l2_veto_applied": True,
                    "veto_reason": f"L2_VETO:L1_low_conf={l1_confidence:.2f}",
                    "l1_l2_agreement": "RESPECT_L2_LOW_CONF",
                    "l1_confidence": l1_confidence,
                    "l2_veto_strength": l2_veto_strength,
                }
        else:
            bypass = "exit_bypass_L2" if l2_exec_bias == "HOLD" else "exit_allowed"
            return {
                "final_action": "SELL",
                "is_entry": False,
                "is_exit": True,
                "l2_block_reason": None,
                "exit_override_reason": bypass,
                "l2_veto_applied": False,
                "veto_reason": None,
            }
    
    return {
        "final_action": "HOLD",
        "is_entry": False,
        "is_exit": False,
        "l2_block_reason": "UNKNOWN",
        "exit_override_reason": None,
        "l2_veto_applied": False,
        "veto_reason": None,
    }

def _append_text_to_log(symbol: str, timeframe: str, text: str) -> None:
    today = datetime.now().strftime("%Y%m%d")
    path = DECISION_LOG_DIR / f"{symbol}_{timeframe}_{today}.log"
    with path.open("a", encoding="utf-8") as f:
        f.write(text)
        if not text.endswith("\n"):
            f.write("\n")
        f.write("\n" + "-" * 60 + "\n")
    print(f"[LOG] written to {path}")


def write_decision_log_v197(*args, **kwargs):
    """v1.981 日志包装函数：在原有 write_decision_log_v197 外再加一层通用 JSONL 日志。

    - 不修改原函数签名，通过 *args/**kwargs 转发；
    - 任何日志失败都不会影响交易主流程；
    - 日志写入 ./decision_logs_v1982/decision_log.jsonl，每行一条 JSON。"""
    def _safe_repr(obj, max_len=800):
        try:
            s = repr(obj)
        except Exception:
            s = "<unrepr {}>".format(type(obj).__name__)
        if len(s) > max_len:
            s = s[:max_len] + "...(truncated)"
        return s

    error = None
    result = None

    # 先调用原始实现，保证行为与旧版本一致
    try:
        result = _write_decision_log_v197_inner(*args, **kwargs)
    except Exception as e:  # noqa: BLE001
        error = e

    # 再做一层“通用字段”的 JSONL 日志，任何失败都不能阻塞主流程
    try:
        import datetime
        import json
        import os
        import traceback

        log_dir = os.path.join(os.getcwd(), "decision_logs_v1982")
        os.makedirs(log_dir, exist_ok=True)
        log_path = os.path.join(log_dir, "decision_log.jsonl")

        # 尝试从 kwargs 里挖掘一点结构化信息（如果有的话）
        decision_dict = None
        for key in ("decision", "decision_dict", "llm_decision", "decision_payload"):
            value = kwargs.get(key)
            if isinstance(value, dict):
                decision_dict = value
                break

        symbol = None
        final_action = None
        wyckoff_phase = None

        if isinstance(decision_dict, dict):
            symbol = decision_dict.get("symbol") or decision_dict.get("base_symbol")
            final_action = decision_dict.get("final_action") or decision_dict.get("recommended_action")
            wyckoff_phase = decision_dict.get("wyckoff_phase_label") or decision_dict.get("wyckoff_phase_code")

        payload = {
            "ts": datetime.datetime.utcnow().isoformat() + "Z",
            "version": "1.99",
            "symbol": symbol,
            "final_action": final_action,
            "wyckoff_phase": wyckoff_phase,
            "error": repr(error) if error else None,
            "args_preview": _safe_repr(args),
            "kwargs_preview": _safe_repr(kwargs),
            "result_preview": _safe_repr(result),
            "traceback": traceback.format_exc() if error else None,
        }

        with open(log_path, "a", encoding="utf-8") as f:
            f.write(json.dumps(payload, ensure_ascii=False) + "\n")
    except Exception:
        # 任何日志异常都不能影响交易主流程
        pass

    # 保持与原始函数兼容：如果原函数抛异常，这里在日志之后再抛出去
    if error is not None:
        raise error

    return result
def _write_decision_log_v197_inner(
    symbol: str,
    timeframe: str,
    trade_mode: str,
    now_ny,
    state: dict,
    decision: dict,
) -> None:
    """
    轻量版 v1.97 决策日志：写入本地 logs/xx.log，保留核心信息 + L2 执行层。
    """
    try:
        lines = []
        version = decision.get("version", globals().get("AIPRO_VERSION", "UNKNOWN"))

        # STEP1 - 基本信息
        lines.append(f"Version: {version}")
        lines.append(f"Time: {now_ny}  Symbol: {symbol}  TF: {timeframe}  Mode: {trade_mode}")
        lines.append("")
        lines.append("STEP1 - Input Snapshot / 输入概览")
        lines.append(
            "STATE: symbol={sym}, position_units={pu}, cycle_id={cid}, "
            "open_buys_cnt={ob}, open_sells_cnt={os}".format(
                sym=symbol,
                pu=state.get("position_units"),
                cid=state.get("cycle_id"),
                ob=len(state.get("open_buys", [])),
                os=len(state.get("open_sells", [])),
            )
        )

        # STEP2 - 决策概要
        lines.append("")
        lines.append("STEP2 - Decision / 决策概要")
        lines.append(f"llm_raw_action: {decision.get('llm_raw_action')}")
        
        # v2.390: L1 协商信息
        l1_merge = decision.get('l1_merge', {})
        if l1_merge:
            lines.append(f"  L1_Merge: {l1_merge.get('decision_path', 'N/A')}")
            lines.append(f"    - Agreement: {l1_merge.get('agreement_type', 'N/A')}")
            lines.append(f"    - LLM used: {l1_merge.get('llm_used', False)}, Grid used: {l1_merge.get('grid_used', False)}")
            lines.append(f"    - L1 confidence: {decision.get('l1_confidence', 0.0):.2f}, modified: {decision.get('l1_modified', False)}")
            conflict = l1_merge.get('conflict_info', {})
            if conflict.get('level') != 'NONE':
                lines.append(f"    - Conflict: {conflict.get('level')} / {conflict.get('type')}")
        
        lines.append(f"ai_action(after Grid): {decision.get('ai_action')}")
        lines.append(f"final_action(after gates+L2): {decision.get('final_action')}")
        lines.append(f"confidence: {decision.get('confidence')}")
        lines.append(
            f"llm_fallback: {decision.get('llm_fallback')}, "
            f"fallback_reasons: {decision.get('fallback_reasons')}"
        )

        # v3.010: P3协商追踪增强 - 显示为什么决策被改变
        l1_vision = decision.get('l1_trend_vision', {})
        l1_bias = l1_vision.get('l1_bias', 'HOLD')
        l1_score = l1_vision.get('score', 0.0)
        exec_bias = decision.get('exec_bias', 'HOLD')
        ai_action = decision.get('ai_action', 'HOLD')
        final_action = decision.get('final_action', 'HOLD')
        l1_action_before_l2 = decision.get('l1_action_before_l2', ai_action)

        # v3.010: 检测更多变更场景
        # 场景1: ai_action与final_action不同
        # 场景2: L2有建议(SELL/BUY)但最终是HOLD (L1否决了L2)
        # 场景3: L1有建议但被L2否决
        has_decision_change = (
            ai_action != final_action or
            (exec_bias in ('SELL', 'BUY') and final_action == 'HOLD') or
            (l1_action_before_l2 != 'HOLD' and final_action == 'HOLD')
        )

        if has_decision_change:
            lines.append(f"  ⚠️ P3协商追踪:")
            lines.append(f"    L1_action={l1_action_before_l2} | L1_bias={l1_bias} (score={l1_score:.2f})")
            lines.append(f"    L2_exec={exec_bias} | final={final_action}")

            # v3.340: 根据L1-L2协商矩阵解释原因 (统一5档格式)
            negotiate_reasons = {
                ("HOLD", "SELL"): "L1=HOLD+L2=SELL → L1否决L2 → HOLD",
                ("HOLD", "BUY"): "L1=HOLD+L2=BUY → L1否决L2 → HOLD",
                ("SELL", "SELL"): "L1=SELL+L2=SELL → 同意SELL",
                ("BUY", "BUY"): "L1=BUY+L2=BUY → 同意BUY",
                ("SELL", "BUY"): "L1=SELL+L2=BUY → 方向冲突→HOLD",
                ("BUY", "SELL"): "L1=BUY+L2=SELL → 方向冲突→HOLD",
                ("STRONG_SELL", "SELL"): "L1=STRONG_SELL+L2=SELL → 确认SELL",
                ("STRONG_BUY", "BUY"): "L1=STRONG_BUY+L2=BUY → 确认BUY",
                ("STRONG_SELL", "STRONG_SELL"): "L1+L2双强卖 → 确认SELL",
                ("STRONG_BUY", "STRONG_BUY"): "L1+L2双强买 → 确认BUY",
                ("SELL", "HOLD"): "L1=SELL+L2=HOLD → L2否决 → HOLD",
                ("BUY", "HOLD"): "L1=BUY+L2=HOLD → L2否决 → HOLD",
            }
            # 尝试多种key组合
            key = (l1_action_before_l2, exec_bias)
            reason = negotiate_reasons.get(key)
            if not reason:
                key = (l1_bias, exec_bias)
                reason = negotiate_reasons.get(key)
            if not reason:
                reason = f"协商: L1={l1_action_before_l2}({l1_bias}) + L2={exec_bias} → {final_action}"
            lines.append(f"    原因: {reason}")
        else:
            lines.append(f"  L1_bias={l1_bias} (score={l1_score:.2f}), L2={exec_bias}, 决策一致={final_action}")

        # STEP3 - Wyckoff & 位置
        lines.append("")
        lines.append("STEP3 - Wyckoff & Position / Wyckoff 与位置")
        lines.append(
            "wyckoff_phase: {code}, label={label}".format(
                code=decision.get("wyckoff_phase_code"),
                label=decision.get("wyckoff_phase_label"),
            )
        )
        lines.append(
            "pos_zone={pz}, pos_ratio={pr:.4f}, near_low_120={nl}, near_high_120={nh}".format(
                pz=decision.get("pos_zone"),
                pr=float(decision.get("pos_ratio", 0.0) or 0.0),
                nl=decision.get("near_low_120"),
                nh=decision.get("near_high_120"),
            )
        )

        # STEP4 - L2 执行层
        lines.append("")
        lines.append("STEP4 - L2 Exec Layer / 执行层")
        lines.append(
            "sr_zone={sr}, exec_bias={eb}, pa_tag={pa}, two_b_tag={tb}, volume_state={vs}".format(
                sr=decision.get("sr_zone"),
                eb=decision.get("exec_bias"),
                pa=decision.get("pa_tag"),
                tb=decision.get("two_b_tag"),
                vs=decision.get("volume_state"),
            )
        )
        lines.append(f"l1_action_before_l2: {decision.get('l1_action_before_l2')}")
        # L2 10m 视角补充日志
        l2_10m = decision.get("l2_10m", {}) or {}
        lines.append(
            "L2_10m: pos_zone_10m={pz}, exec_bias_10m={eb10}, micro_reversal_10m={mr}, volume_state_10m={vs10}".format(
                pz=l2_10m.get("pos_zone_10m"),
                eb10=l2_10m.get("exec_bias_10m"),
                mr=l2_10m.get("micro_reversal_10m"),
                vs10=l2_10m.get("volume_state_10m"),
            )
        )
        lines.append(
            "first_entry_override={fe}, first_exit_override={fx}".format(
                fe=decision.get("first_entry_override_applied"),
                fx=decision.get("first_exit_override_applied"),
            )
        )
        mt_gate = decision.get("micro_timing_gate", {}) or {}
        lines.append(
            "MICRO_TIMING_GATE: pass={p}, combo={c}, reasons={r}".format(
                p=mt_gate.get("pass"),
                c=mt_gate.get("combo_tag"),
                r="|".join(mt_gate.get("reasons", [])) if mt_gate.get("reasons") else "",
            )
        )

        # STEP5 - 交易计数 & 配额
        lines.append("")
        lines.append("STEP5 - Cycle & Counters / Cycle 与计数")
        lines.append(
            "actual_buy_count={ab}, actual_sell_count={as_}, cycle_trades={ct}, cycle_id={cid}".format(
                ab=state.get("actual_buy_count"),
                as_=state.get("actual_sell_count"),
                ct=state.get("cycle_trades"),
                cid=state.get("cycle_id"),
            )
        )
        lines.append(
            "phase_buy_count={pb}, phase_sell_count={ps}, "
            "phase_smart_limit={pl}, phase_smart_trades={pt}".format(
                pb=decision.get("phase_buy_count"),
                ps=decision.get("phase_sell_count"),
                pl=decision.get("phase_smart_limit"),
                pt=decision.get("phase_smart_trades"),
            )
        )

        # STEP6 - 风险模式
        lines.append("")
        lines.append("STEP6 - Risk Mode / 风险模式")
        lines.append(
            "wyckoff_meta_regime={mr}, risk_mode={rm}, "
            "buy_quota_factor={bq}, sell_quota_factor={sq}".format(
                mr=decision.get("wyckoff_meta_regime"),
                rm=decision.get("risk_mode"),
                bq=decision.get("buy_quota_factor"),
                sq=decision.get("sell_quota_factor"),
            )
        )

        # STEP7 - 熊市反弹 & 环境
        lines.append("")
        lines.append("STEP7 - Bear Env / 熊市环境")
        lines.append(
            "bearish_env={be}, bearish_gate={bg}, "
            "bear_rebound_buy_count={brc}".format(
                be=decision.get("bearish_env"),
                bg=decision.get("bearish_gate"),
                brc=decision.get("bear_rebound_buy_count"),
            )
        )
        lines.append(
            "rebound_first_3pct={r1}, rebound_second_5pct={r2}".format(
                r1=decision.get("rebound_first_3pct"),
                r2=decision.get("rebound_second_5pct"),
            )
        )

        # STEP8 - 原则
        lines.append("")
        lines.append("Trading Principles / 交易原则:")
        lines.append(
            "- Principle 1: High area + structure worsening ⇒ "
            "prefer SELL or HOLD; avoid new BUY."
        )
        lines.append(
            "- 原则1：高位且结构变差时，优先减仓或观望，避免新开多单。"
        )
        lines.append(
            "- Principle 2: Low area + structure improving ⇒ "
            "prefer BUY or HOLD; avoid panic SELL."
        )
        lines.append(
            "- 原则2：低位且结构明显好转时，优先考虑分批买入或持有，避免恐慌性卖出。"
        )
        lines.append(
            "- Principle 3: Structure unclear + mid zone ⇒ "
            "default HOLD; do not waste smart trades or quotas."
        )
        lines.append(
            "- 原则3：结构不清晰且位于区间中部时，默认 HOLD，不浪费 smart trade 和买卖次数配额。"
        )

        text = "\n".join(lines)
        _append_text_to_log(symbol, str(timeframe), text)
    except Exception as e:
        print(f"[WARN] write_decision_log_v197 failed: {e}")


