# ============================================================================
# v2.095: 自动检测周期配置
# ============================================================================

_symbol_cycle_config = {}

def get_main_cycle_minutes(symbol: str) -> int:
    """获取symbol的主周期配置，默认30"""
    return _symbol_cycle_config.get(symbol, 30)

def get_window_size_10m(symbol: str) -> int:
    """获取symbol的10m窗口大小"""
    main_cycle = get_main_cycle_minutes(symbol)
    return max(3, main_cycle // 10)

SYMBOL_CONFIG_FILE = "state/symbol_config.json"  # v3.573: 周期配置持久化

def update_symbol_cycle(symbol: str, timeframe):
    """更新symbol的主周期配置"""
    # v2.095: 确保timeframe是整数
    try:
        timeframe = int(timeframe)
    except (ValueError, TypeError) as e:
        print(f"[配置错误] timeframe转换失败: {timeframe} ({e}), 使用默认30")
        timeframe = 30

    old_cycle = _symbol_cycle_config.get(symbol)
    _symbol_cycle_config[symbol] = timeframe

    if old_cycle != timeframe:
        window_size = max(3, timeframe // 10)
        print(f"[配置] {symbol} 主周期: {timeframe}分钟, 窗口: {window_size}根10m K线")

    # v3.573: 持久化到文件供vision_analyzer读取
    _persist_symbol_config()


def _persist_symbol_config():
    """v3.573: 将周期配置持久化到文件"""
    try:
        os.makedirs("state", exist_ok=True)
        config_data = {
            "symbols": _symbol_cycle_config.copy(),
            "last_updated": datetime.now().isoformat(),
        }
        tmp_path = SYMBOL_CONFIG_FILE + f".{os.getpid()}.tmp"
        with open(tmp_path, 'w', encoding='utf-8') as f:
            json.dump(config_data, f, indent=2, ensure_ascii=False)
        os.replace(tmp_path, SYMBOL_CONFIG_FILE)
    except Exception as e:
        print(f"[v3.573] 周期配置保存失败: {e}")

print("[配置] v2.095 - 自动检测主周期模式已启用")

