# ████████████████████████████████████████████████████████████████████████

# =========================================
# 多周期趋势计算
# =========================================
def _linear_regression_slope_pct(series: List[float]) -> float:
    n = len(series)
    if n < 5:
        return 0.0

    x_mean = (n - 1) / 2.0
    y_mean = sum(series) / n

    num = 0.0
    den = 0.0
    for i, y in enumerate(series):
        dx = i - x_mean
        dy = y - y_mean
        num += dx * dy
        den += dx * dx

    if den == 0 or y_mean == 0:
        return 0.0

    slope = num / den
    return slope / y_mean


def _dir_ratio(series: List[float]) -> float:
    n = len(series)
    if n < 2:
        return 0.5
    ups = 0
    total = n - 1
    for i in range(1, n):
        if series[i] > series[i - 1]:
            ups += 1
    return ups / total if total > 0 else 0.5


def _weighted_dir_ratio(series: List[float]) -> float:
    """
    v3.240: 加权方向比率 - 按涨跌幅度加权，而非K线数量

    解决问题：
    - 原_dir_ratio: 1根大阴线(-2%) + 5根小阳线(+0.5%) = dr=0.83 → 错误判断UP
    - 新_weighted_dir_ratio: total_up=0.5, total_down=2.0 → wdr=0.2 → 正确判断DOWN

    Returns:
        float: 0-1, 上涨幅度占总波动的比例
               > 0.55 倾向上涨, < 0.45 倾向下跌
    """
    n = len(series)
    if n < 2:
        return 0.5

    total_up_move = 0.0
    total_down_move = 0.0

    for i in range(1, n):
        change = series[i] - series[i - 1]
        if change > 0:
            total_up_move += change
        else:
            total_down_move += abs(change)

    total_move = total_up_move + total_down_move
    if total_move == 0:
        return 0.5

    return total_up_move / total_move


def _aggregate_series(series: List[float], mult: int) -> List[float]:
    if mult <= 1:
        return series[:]
    out = []
    for i in range(0, len(series), mult):
        chunk = series[i:i + mult]
        if chunk:
            out.append(chunk[-1])
    return out


def compute_trend_v11(series: List[float]) -> Tuple[str, float, float]:
    """原版趋势计算，保留用于对比"""
    n = len(series)
    if n < 10:
        return "unknown", 0.0, 0.5

    slope_pct = _linear_regression_slope_pct(series)
    dr = _dir_ratio(series)

    if slope_pct > 0.001 and dr > 0.55:
        trend = "up"
    elif slope_pct < -0.001 and dr < 0.45:
        trend = "down"
    else:
        trend = "side"

    return trend, slope_pct, dr


# v3.241 H1: 动态slope阈值配置
# v3.250 ZEC优化: 大幅提高ZEC阈值，适应高波动特性
SLOPE_THRESHOLDS = {
    # 大盘币 - 波动较小，阈值收紧
    "BTCUSDC": {"strong": 0.002, "weak": 0.001},
    "ETHUSDC": {"strong": 0.0025, "weak": 0.001},
    # 中等波动币
    "SOLUSDC": {"strong": 0.003, "weak": 0.0015},
    # 小币 - 波动较大，阈值放宽
    # v3.250 ZEC优化: 0.004→0.008 (ZEC日波动常>5%，需要更高阈值)
    "ZECUSDC": {"strong": 0.008, "weak": 0.004},
    "ONDOUSDC": {"strong": 0.005, "weak": 0.0025},
    # 股票 - 中等波动
    "STOCK_DEFAULT": {"strong": 0.003, "weak": 0.0015},
    # 默认值
    "DEFAULT": {"strong": 0.003, "weak": 0.001},
}


def get_slope_threshold(symbol: str = None) -> dict:
    """v3.241 H1: 获取品种特定的slope阈值"""
    if symbol:
        # 直接匹配
        if symbol in SLOPE_THRESHOLDS:
            return SLOPE_THRESHOLDS[symbol]
        # 股票判断 (非USDC结尾)
        if not symbol.endswith("USDC") and not symbol.endswith("USD"):
            return SLOPE_THRESHOLDS["STOCK_DEFAULT"]
    return SLOPE_THRESHOLDS["DEFAULT"]


def compute_trend_v12(series: List[float]) -> Tuple[str, float, float]:
    """
    v3.240: 改进版趋势计算 - 加权方向比率

    改进点：
    1. 斜率足够大(>0.3%)时，直接判断趋势方向（不需要dr确认）
    2. 斜率中等(0.1-0.3%)时，使用加权方向比率判断
    3. 斜率很小(<0.1%)时，判断为SIDE

    Returns:
        Tuple[str, float, float]: (trend, slope_pct, weighted_dr)
    """
    n = len(series)
    if n < 10:
        return "unknown", 0.0, 0.5

    slope_pct = _linear_regression_slope_pct(series)
    dr = _dir_ratio(series)
    weighted_dr = _weighted_dir_ratio(series)

    # v3.240核心改进：双重条件判断
    # 条件1: 斜率足够大时，直接判断（不需要dr确认）
    if slope_pct > 0.003:  # 斜率>0.3%，明显上涨
        trend = "up"
    elif slope_pct < -0.003:  # 斜率<-0.3%，明显下跌
        trend = "down"
    # 条件2: 斜率中等时，使用加权方向比率辅助判断
    elif slope_pct > 0.001 and weighted_dr > 0.52:  # 放宽: 0.55→0.52
        trend = "up"
    elif slope_pct < -0.001 and weighted_dr < 0.48:  # 放宽: 0.45→0.48
        trend = "down"
    else:
        trend = "side"

    # 诊断日志（调试用）
    if trend != "side":
        print(f"[v3.240] compute_trend_v12: slope={slope_pct:.4f}, dr={dr:.3f}, "
              f"weighted_dr={weighted_dr:.3f} → {trend}")

    return trend, slope_pct, weighted_dr


def compute_trend_v13(series: List[float], symbol: str = None) -> Tuple[str, float, float]:
    """
    v3.241 H1: 动态阈值版趋势计算

    改进点：
    1. 根据品种使用不同的slope阈值
    2. 大盘币(BTC/ETH)使用更严格阈值
    3. 小币(ZEC/ONDO)使用更宽松阈值
    4. 股票使用中等阈值

    Args:
        series: 价格序列
        symbol: 交易品种（可选，用于动态阈值）

    Returns:
        Tuple[str, float, float]: (trend, slope_pct, weighted_dr)
    """
    n = len(series)
    if n < 10:
        return "unknown", 0.0, 0.5

    slope_pct = _linear_regression_slope_pct(series)
    dr = _dir_ratio(series)
    weighted_dr = _weighted_dir_ratio(series)

    # v3.241 H1: 获取品种特定阈值
    thresholds = get_slope_threshold(symbol)
    strong_th = thresholds["strong"]
    weak_th = thresholds["weak"]

    # 动态阈值判断
    if slope_pct > strong_th:
        trend = "up"
    elif slope_pct < -strong_th:
        trend = "down"
    elif slope_pct > weak_th and weighted_dr > 0.52:
        trend = "up"
    elif slope_pct < -weak_th and weighted_dr < 0.48:
        trend = "down"
    else:
        trend = "side"

    # 诊断日志
    if trend != "side":
        print(f"[v3.241 H1] compute_trend_v13({symbol}): slope={slope_pct:.4f}, "
              f"threshold={strong_th:.4f}/{weak_th:.4f}, weighted_dr={weighted_dr:.3f} → {trend}")

    return trend, slope_pct, weighted_dr


# =========================================
# v3.250 ZEC专属L1趋势判断
# =========================================
def compute_trend_zec(series: List[float]) -> Tuple[str, float, dict]:
    """
    v3.250: ZEC专属趋势判断算法

    设计理念：
    1. ZEC波动大(日常5-15%)，不适合用slope百分比判断
    2. 使用价格变化幅度+动量判断
    3. 更短回溯期(30根)，更快响应
    4. 更激进的趋势识别

    Returns:
        Tuple[str, float, dict]: (trend, change_pct, details)
    """
    n = len(series)
    if n < 20:
        return "unknown", 0.0, {}

    # 使用最近30根K线（或可用的最大长度）
    lookback = min(30, n)
    recent = series[-lookback:]

    # 计算关键指标
    current = recent[-1]
    start = recent[0]
    high = max(recent)
    low = min(recent)

    # 1. 总体变化幅度
    change_pct = (current - start) / start if start > 0 else 0

    # 2. 位置判断：当前价格在近期范围的位置
    range_width = high - low
    if range_width > 0:
        pos_in_range = (current - low) / range_width
    else:
        pos_in_range = 0.5

    # 3. 动量：最近5根vs前5根
    if len(recent) >= 10:
        recent_5_avg = sum(recent[-5:]) / 5
        prev_5_avg = sum(recent[-10:-5]) / 5
        momentum = (recent_5_avg - prev_5_avg) / prev_5_avg if prev_5_avg > 0 else 0
    else:
        momentum = 0

    # 4. 方向比率
    up_count = sum(1 for i in range(1, len(recent)) if recent[i] > recent[i-1])
    dr = up_count / (len(recent) - 1) if len(recent) > 1 else 0.5

    # ZEC专属判断逻辑（更激进）
    # 阈值：变化>3%且动量一致 或 变化>5%
    trend = "side"
    reason = ""

    if change_pct > 0.05:  # 涨幅>5%，强上涨
        trend = "up"
        reason = f"强涨{change_pct*100:.1f}%"
    elif change_pct < -0.05:  # 跌幅>5%，强下跌
        trend = "down"
        reason = f"强跌{change_pct*100:.1f}%"
    elif change_pct > 0.03 and momentum > 0.01 and dr > 0.55:
        # 涨幅3-5%，动量向上，方向比率偏多
        trend = "up"
        reason = f"涨{change_pct*100:.1f}%+动量{momentum*100:.1f}%"
    elif change_pct < -0.03 and momentum < -0.01 and dr < 0.45:
        # 跌幅3-5%，动量向下，方向比率偏空
        trend = "down"
        reason = f"跌{change_pct*100:.1f}%+动量{momentum*100:.1f}%"
    elif pos_in_range > 0.85 and momentum > 0:
        # 价格在高位且动量向上
        trend = "up"
        reason = f"高位{pos_in_range*100:.0f}%+动量正"
    elif pos_in_range < 0.15 and momentum < 0:
        # 价格在低位且动量向下
        trend = "down"
        reason = f"低位{pos_in_range*100:.0f}%+动量负"
    else:
        reason = f"震荡(变化{change_pct*100:.1f}%,位置{pos_in_range*100:.0f}%)"

    details = {
        "change_pct": round(change_pct * 100, 2),
        "pos_in_range": round(pos_in_range * 100, 1),
        "momentum": round(momentum * 100, 2),
        "dr": round(dr, 3),
        "reason": reason,
    }

    print(f"[v3.250 ZEC] compute_trend_zec: change={change_pct*100:.2f}%, "
          f"pos={pos_in_range*100:.0f}%, momentum={momentum*100:.2f}%, dr={dr:.2f} → {trend} ({reason})")

    return trend, change_pct, details


# =========================================
# v3.280 Swing Point 摆动点识别
# =========================================
def find_swing_points(highs: List[float], lows: List[float], n: int = 2) -> Tuple[List[Tuple[int, float]], List[Tuple[int, float]]]:
    """
    v3.280: 识别摆动高点和摆动低点

    摆动高点(Swing High): 左右各n根的High都比它低
    摆动低点(Swing Low): 左右各n根的Low都比它高

    Args:
        highs: K线高点序列
        lows: K线低点序列
        n: 左右确认K线数量（默认2，即左右各2根）

    Returns:
        Tuple[List[Tuple[int, float]], List[Tuple[int, float]]]:
        (swing_highs, swing_lows) - 每个元素是(索引, 价格)

    示例:
        原始:  10 12 11 11 13 12 14 13 13 15
                   ↑        ↑        ↑
                Swing    Swing    Swing
                 High     High     High
    """
    swing_highs = []  # [(index, price), ...]
    swing_lows = []   # [(index, price), ...]

    if len(highs) < 2 * n + 1 or len(lows) < 2 * n + 1:
        return swing_highs, swing_lows

    for i in range(n, len(highs) - n):
        # 检查是否为摆动高点: 左右各n根的High都比它低
        is_swing_high = True
        for j in range(1, n + 1):
            if highs[i] <= highs[i - j] or highs[i] <= highs[i + j]:
                is_swing_high = False
                break

        if is_swing_high:
            swing_highs.append((i, highs[i]))

        # 检查是否为摆动低点: 左右各n根的Low都比它高
        is_swing_low = True
        for j in range(1, n + 1):
            if lows[i] >= lows[i - j] or lows[i] >= lows[i + j]:
                is_swing_low = False
                break

        if is_swing_low:
            swing_lows.append((i, lows[i]))

    return swing_highs, swing_lows


def compute_trend_dow_swing(highs: List[float], lows: List[float], n_swing: int = 2, min_swings: int = 2) -> Tuple[str, dict]:
    """
    v3.280: 基于摆动点的道氏理论趋势判断

    核心逻辑：
    1. 先用find_swing_points()找出有效的摆动高点和摆动低点
    2. 比较最近的摆动点高低关系
    3. HH+HL = UP趋势，LH+LL = DOWN趋势

    优势：
    - 过滤中间的盘整噪音
    - 更符合道氏理论原意（比较波峰波谷，不是每根K线）
    - 解决"阳线-盘整-阳线"被误判为SIDE的问题

    Args:
        highs: K线高点序列
        lows: K线低点序列
        n_swing: 摆动点确认K线数（默认2，左右各2根）
        min_swings: 最少需要的摆动点数量（默认2个）

    Returns:
        Tuple[str, dict]: (trend, details)
        - trend: "up" / "down" / "side"
        - details: 判断详情
    """
    # 找出摆动点
    swing_highs, swing_lows = find_swing_points(highs, lows, n_swing)

    details = {
        "method": "swing_point",
        "n_swing": n_swing,
        "swing_highs_count": len(swing_highs),
        "swing_lows_count": len(swing_lows),
        "swing_highs": swing_highs[-3:] if swing_highs else [],  # 最近3个
        "swing_lows": swing_lows[-3:] if swing_lows else [],     # 最近3个
    }

    # 需要至少min_swings个摆动高点和摆动低点
    if len(swing_highs) < min_swings or len(swing_lows) < min_swings:
        details["reason"] = f"摆动点不足(需要{min_swings}个，SH={len(swing_highs)},SL={len(swing_lows)})"
        _server_logger.debug(f"[v3.280 DOW-Swing] 摆动点不足: SH={len(swing_highs)}, SL={len(swing_lows)} → side")
        return "side", details

    # 取最近的摆动点进行比较
    last_2_highs = [sh[1] for sh in swing_highs[-2:]]
    last_2_lows = [sl[1] for sl in swing_lows[-2:]]

    # 判断Higher High / Lower High
    higher_high = last_2_highs[1] > last_2_highs[0]
    lower_high = last_2_highs[1] < last_2_highs[0]

    # 判断Higher Low / Lower Low
    higher_low = last_2_lows[1] > last_2_lows[0]
    lower_low = last_2_lows[1] < last_2_lows[0]

    details["last_2_swing_highs"] = last_2_highs
    details["last_2_swing_lows"] = last_2_lows
    details["higher_high"] = higher_high
    details["higher_low"] = higher_low
    details["lower_high"] = lower_high
    details["lower_low"] = lower_low

    # 道氏理论判断
    if higher_high and higher_low:
        trend = "up"
        pattern = "HH+HL"
        details["reason"] = f"摆动点确认上涨: {last_2_highs[0]:.2f}→{last_2_highs[1]:.2f}(HH), {last_2_lows[0]:.2f}→{last_2_lows[1]:.2f}(HL)"
    elif lower_high and lower_low:
        trend = "down"
        pattern = "LH+LL"
        details["reason"] = f"摆动点确认下跌: {last_2_highs[0]:.2f}→{last_2_highs[1]:.2f}(LH), {last_2_lows[0]:.2f}→{last_2_lows[1]:.2f}(LL)"
    else:
        # v3.394: 混合模式时，用最近摆动点方向+动量打破平局
        # 趋势转换期: LH+HL或HH+LL，需要判断当前处于转换的哪个阶段
        hh_str = "HH" if higher_high else ("LH" if lower_high else "EH")
        hl_str = "HL" if higher_low else ("LL" if lower_low else "EL")

        # 获取最近摆动点的索引位置
        last_sh_idx = swing_highs[-1][0] if swing_highs else 0
        last_sl_idx = swing_lows[-1][0] if swing_lows else 0

        # 计算价格动量: 当前价格相对于中点的位置
        mid_price = (highs[-1] + lows[-1]) / 2 if highs and lows else 0
        recent_high = max(highs[-5:]) if len(highs) >= 5 else highs[-1] if highs else 0
        recent_low = min(lows[-5:]) if len(lows) >= 5 else lows[-1] if lows else 0
        price_range = recent_high - recent_low if recent_high > recent_low else 1
        price_position = (mid_price - recent_low) / price_range  # 0=低位, 1=高位

        # 混合模式判断逻辑:
        # LH + HL: 最近高点更低 + 最近低点更高 → 看哪个更近+动量
        # HH + LL: 最近高点更高 + 最近低点更低 → 看哪个更近+动量
        mixed_trend = "side"
        mixed_reason = ""

        if lower_high and higher_low:
            # LH+HL: 典型的趋势转换期
            if last_sh_idx > last_sl_idx:
                # LH更近 → 可能转DOWN
                if price_position < 0.4:
                    mixed_trend = "down"
                    mixed_reason = f"LH更近(idx:{last_sh_idx}>{last_sl_idx})+价格偏低({price_position:.0%})"
                else:
                    mixed_reason = f"LH更近但价格未确认低位({price_position:.0%})"
            else:
                # HL更近 → 可能转UP
                if price_position > 0.6:
                    mixed_trend = "up"
                    mixed_reason = f"HL更近(idx:{last_sl_idx}>{last_sh_idx})+价格偏高({price_position:.0%})"
                else:
                    mixed_reason = f"HL更近但价格未确认高位({price_position:.0%})"
        elif higher_high and lower_low:
            # HH+LL: 宽幅震荡扩大
            if last_sh_idx > last_sl_idx and price_position > 0.6:
                mixed_trend = "up"
                mixed_reason = f"HH更近+价格偏高({price_position:.0%})"
            elif last_sl_idx > last_sh_idx and price_position < 0.4:
                mixed_trend = "down"
                mixed_reason = f"LL更近+价格偏低({price_position:.0%})"
            else:
                mixed_reason = f"HH+LL宽幅震荡,价格中立({price_position:.0%})"

        if mixed_trend != "side":
            trend = mixed_trend
            pattern = f"{hh_str}+{hl_str}→{mixed_trend.upper()}"
            details["reason"] = f"混合模式转换: {mixed_reason}"
            details["transition_detected"] = True
        else:
            trend = "side"
            pattern = "mixed"
            details["reason"] = f"摆动点方向不一致: {hh_str}+{hl_str}, {mixed_reason}" if mixed_reason else f"摆动点方向不一致: {hh_str}+{hl_str}"

        details["last_sh_idx"] = last_sh_idx
        details["last_sl_idx"] = last_sl_idx
        details["price_position"] = price_position

    details["pattern"] = pattern

    _server_logger.debug(f"[v3.394 DOW-Swing] SH={len(swing_highs)}, SL={len(swing_lows)} | "
          f"Highs: {last_2_highs[0]:.2f}→{last_2_highs[1]:.2f}, "
          f"Lows: {last_2_lows[0]:.2f}→{last_2_lows[1]:.2f} → {trend} ({pattern})")

    return trend, details


# =========================================
# v3.395 4根K线快速趋势检测 (道氏理论补充)
# =========================================
def compute_trend_4bar_fast(highs: List[float], lows: List[float], closes: List[float], n_bars: int = 4) -> Tuple[str, dict]:
    """
    v3.395: 4根K线快速趋势检测

    当道氏理论返回side/unknown时，用简单的4根K线结构快速判断趋势转换。
    比道氏理论更快响应(4根 vs 6-10根)，但可能有更多噪音。

    判断逻辑:
    1. 高点方向: 最近高点 vs 4根前高点
    2. 低点方向: 最近低点 vs 4根前低点
    3. 斜率: (close[-1] - close[-n]) / close[-n]

    Args:
        highs: K线高点序列
        lows: K线低点序列
        closes: K线收盘价序列
        n_bars: 判断所需K线数量（默认4根）

    Returns:
        Tuple[str, dict]: (trend, details)
    """
    if len(highs) < n_bars or len(lows) < n_bars or len(closes) < n_bars:
        return "unknown", {"reason": f"数据不足(需要{n_bars}根K线)", "method": "4bar_fast"}

    # 取最近n_bars根
    recent_highs = highs[-n_bars:]
    recent_lows = lows[-n_bars:]
    recent_closes = closes[-n_bars:]

    # 计算方向
    first_high, last_high = recent_highs[0], recent_highs[-1]
    first_low, last_low = recent_lows[0], recent_lows[-1]
    first_close, last_close = recent_closes[0], recent_closes[-1]

    highs_rising = last_high > first_high
    highs_falling = last_high < first_high
    lows_rising = last_low > first_low
    lows_falling = last_low < first_low

    # 斜率 (百分比)
    slope = (last_close - first_close) / first_close if first_close > 0 else 0
    slope_pct = slope * 100

    # 价格范围内的位置
    range_high = max(recent_highs)
    range_low = min(recent_lows)
    price_range = range_high - range_low if range_high > range_low else 1
    price_position = (last_close - range_low) / price_range  # 0=底部, 1=顶部

    details = {
        "method": "4bar_fast",
        "n_bars": n_bars,
        "highs_rising": highs_rising,
        "lows_rising": lows_rising,
        "slope_pct": slope_pct,
        "price_position": price_position,
        "first_high": first_high,
        "last_high": last_high,
        "first_low": first_low,
        "last_low": last_low,
    }

    # 判断逻辑
    trend = "side"
    reason = ""

    # v3.396: 计算高低点变化幅度，用于检测趋势减弱
    high_change_pct = (last_high - first_high) / first_high * 100 if first_high > 0 else 0
    low_change_pct = (last_low - first_low) / first_low * 100 if first_low > 0 else 0
    details["high_change_pct"] = high_change_pct
    details["low_change_pct"] = low_change_pct

    # 情况1: 高低点同向 → 检查幅度确认趋势强度
    if highs_rising and lows_rising:
        # v3.396: 如果涨幅很小(<0.5%)，可能是趋势减弱→震荡
        if high_change_pct < 0.5 and low_change_pct < 0.5 and abs(slope_pct) < 1.0:
            trend = "side"
            reason = f"高↑低↑但幅度微弱(H:{high_change_pct:+.1f}%,L:{low_change_pct:+.1f}%)→震荡"
        else:
            trend = "up"
            reason = f"高点↑低点↑斜率{slope_pct:+.1f}%"
    elif highs_falling and lows_falling:
        # v3.396: 如果跌幅很小(>-0.5%)，可能是趋势减弱→震荡
        if high_change_pct > -0.5 and low_change_pct > -0.5 and abs(slope_pct) < 1.0:
            trend = "side"
            reason = f"高↓低↓但幅度微弱(H:{high_change_pct:+.1f}%,L:{low_change_pct:+.1f}%)→震荡"
        else:
            trend = "down"
            reason = f"高点↓低点↓斜率{slope_pct:+.1f}%"

    # 情况2: 高低点不同向 → 用斜率+位置打破平局
    elif highs_falling and lows_rising:
        # 收敛三角形 - 看斜率和位置
        if slope_pct < -1.0 and price_position < 0.4:
            trend = "down"
            reason = f"收敛+斜率{slope_pct:.1f}%+低位({price_position:.0%})→DOWN"
        elif slope_pct > 1.0 and price_position > 0.6:
            trend = "up"
            reason = f"收敛+斜率{slope_pct:.1f}%+高位({price_position:.0%})→UP"
        else:
            reason = f"收敛震荡(斜率{slope_pct:.1f}%,位置{price_position:.0%})"

    elif highs_rising and lows_falling:
        # 扩散三角形 - 看斜率和位置
        if slope_pct < -1.5 and price_position < 0.35:
            trend = "down"
            reason = f"扩散+斜率{slope_pct:.1f}%+低位({price_position:.0%})→DOWN"
        elif slope_pct > 1.5 and price_position > 0.65:
            trend = "up"
            reason = f"扩散+斜率{slope_pct:.1f}%+高位({price_position:.0%})→UP"
        else:
            reason = f"扩散震荡(斜率{slope_pct:.1f}%,位置{price_position:.0%})"

    else:
        # 其他情况 - 纯靠斜率
        if slope_pct > 2.0:
            trend = "up"
            reason = f"强斜率{slope_pct:.1f}%→UP"
        elif slope_pct < -2.0:
            trend = "down"
            reason = f"强斜率{slope_pct:.1f}%→DOWN"
        else:
            reason = f"震荡(斜率{slope_pct:.1f}%)"

    details["reason"] = reason
    details["pattern"] = f"4bar_{trend}"

    log_to_server(f"[v3.395 4bar-Fast] H:{first_high:.2f}→{last_high:.2f}({'↑' if highs_rising else '↓'}) "
                  f"L:{first_low:.2f}→{last_low:.2f}({'↑' if lows_rising else '↓'}) "
                  f"slope:{slope_pct:+.1f}% pos:{price_position:.0%} → {trend}")

    return trend, details


# =========================================
# v3.260 道氏理论趋势判断 (保留作为备用)
# =========================================
def compute_trend_dow(highs: List[float], lows: List[float], n_bars: int = 4) -> Tuple[str, dict]:
    """
    v3.260: 道氏理论趋势判断

    核心逻辑：
    - UP趋势：连续(n_bars-1)次 HH+HL (Higher High + Higher Low)
    - DOWN趋势：连续(n_bars-1)次 LH+LL (Lower High + Lower Low)
    - SIDE震荡：其他情况（方向不一致）

    Args:
        highs: K线高点序列
        lows: K线低点序列
        n_bars: 判断所需K线数量（默认4根，即3次比较）

    Returns:
        Tuple[str, dict]: (trend, details)
        - trend: "up" / "down" / "side"
        - details: 判断详情
    """
    if len(highs) < n_bars or len(lows) < n_bars:
        return "unknown", {"reason": f"数据不足(需要{n_bars}根K线)"}

    # 取最近n_bars根K线
    recent_highs = highs[-n_bars:]
    recent_lows = lows[-n_bars:]

    # 统计HH/HL和LH/LL次数
    hh_count = 0  # Higher High 次数
    hl_count = 0  # Higher Low 次数
    lh_count = 0  # Lower High 次数
    ll_count = 0  # Lower Low 次数

    comparisons = []
    for i in range(1, n_bars):
        h_prev, h_curr = recent_highs[i-1], recent_highs[i]
        l_prev, l_curr = recent_lows[i-1], recent_lows[i]

        is_hh = h_curr > h_prev
        is_hl = l_curr > l_prev
        is_lh = h_curr < h_prev
        is_ll = l_curr < l_prev

        if is_hh:
            hh_count += 1
        if is_hl:
            hl_count += 1
        if is_lh:
            lh_count += 1
        if is_ll:
            ll_count += 1

        comp = []
        if is_hh:
            comp.append("HH")
        elif is_lh:
            comp.append("LH")
        else:
            comp.append("EH")  # Equal High

        if is_hl:
            comp.append("HL")
        elif is_ll:
            comp.append("LL")
        else:
            comp.append("EL")  # Equal Low

        comparisons.append("+".join(comp))

    required = n_bars - 1  # 需要连续的次数

    # 判断趋势
    if hh_count >= required and hl_count >= required:
        trend = "up"
        reason = f"连续{required}次HH+HL"
    elif lh_count >= required and ll_count >= required:
        trend = "down"
        reason = f"连续{required}次LH+LL"
    else:
        trend = "side"
        reason = f"方向不一致(HH={hh_count},HL={hl_count},LH={lh_count},LL={ll_count})"

    details = {
        "hh_count": hh_count,
        "hl_count": hl_count,
        "lh_count": lh_count,
        "ll_count": ll_count,
        "required": required,
        "comparisons": comparisons,
        "reason": reason,
    }

    print(f"[v3.260 DOW] compute_trend_dow: {' → '.join(comparisons)} → {trend} ({reason})")

    return trend, details


def aggregate_ohlc(bars: List[dict], factor: int) -> Tuple[List[float], List[float]]:
    """
    v3.260: 聚合K线数据为更大周期

    Args:
        bars: OHLCV K线列表 [{open, high, low, close, ...}, ...]
        factor: 聚合因子（4=x4周期，8=x8周期）

    Returns:
        Tuple[List[float], List[float]]: (aggregated_highs, aggregated_lows)
    """
    if not bars or factor < 1:
        return [], []

    aggregated_highs = []
    aggregated_lows = []

    for i in range(0, len(bars) - factor + 1, factor):
        chunk = bars[i:i + factor]
        if chunk:
            chunk_high = max(b.get("high", 0) for b in chunk)
            chunk_low = min(b.get("low", float('inf')) for b in chunk)
            if chunk_low == float('inf'):
                chunk_low = 0
            aggregated_highs.append(chunk_high)
            aggregated_lows.append(chunk_low)

    return aggregated_highs, aggregated_lows


# =========================================
# KEY-001: L1分型输出接口 (N字门控数据源)
# =========================================
def get_fractal_sequence(ohlcv_bars: list, mode: str = "4H", lookback: int = 30) -> List:
    """
    KEY-001: L1分型输出接口 — 将OHLCV转为czsc_lite分型序列。

    Args:
        ohlcv_bars: OHLCV K线列表 [{open, high, low, close, vol, dt/time, ...}, ...]
        mode: '4H' = 当前周期直接跑分型
        lookback: 回看K线数量

    Returns:
        List[Fractal]: 分型序列 (用收盘价作为price)
    """
    if not ohlcv_bars or len(ohlcv_bars) < 6:
        return []

    bars = ohlcv_bars[-lookback:] if len(ohlcv_bars) > lookback else ohlcv_bars

    # 转为czsc_lite RawBar
    raw_bars = []
    for i, b in enumerate(bars):
        dt_val = b.get("dt") or b.get("time") or b.get("datetime")
        if dt_val is None:
            from datetime import datetime, timedelta
            dt_val = datetime(2026, 1, 1) + timedelta(hours=i * 4)
        elif isinstance(dt_val, str):
            from datetime import datetime as dt_cls
            try:
                dt_val = dt_cls.fromisoformat(dt_val.replace("Z", "+00:00"))
            except Exception:
                from datetime import timedelta
                dt_val = dt_cls(2026, 1, 1) + timedelta(hours=i * 4)

        raw_bars.append(RawBar(
            symbol="",
            dt=dt_val,
            freq=Freq.F240,
            open=float(b.get("open", b.get("o", 0))),
            close=float(b.get("close", b.get("c", 0))),
            high=float(b.get("high", b.get("h", 0))),
            low=float(b.get("low", b.get("l", 0))),
            vol=float(b.get("volume", b.get("v", 0))),
        ))

    if len(raw_bars) < 3:
        return []

    # 跑czsc_lite引擎: K线合并→分型检测
    czsc = CZSC(raw_bars)
    fractals = []
    for fx in czsc.fx_list:
        # 关键: 用收盘价而非high/low (遵循prompt约束)
        # 顶分型: 中间K线的close
        # 底分型: 中间K线的close
        mid_bar = fx.elements[1] if len(fx.elements) >= 2 else None
        if mid_bar:
            price = mid_bar.close
        else:
            price = fx.high if fx.mark == "g" else fx.low

        bar_idx = _find_merged_bar_index(czsc.bars_merged, fx.dt)

        fractals.append(Fractal(
            type="TOP" if fx.mark == "g" else "BOTTOM",
            price=price,
            bar_index=bar_idx,
            dt=fx.dt,
            confirmed=True,
        ))

    return fractals


def _aggregate_bars_full(bars: list, factor: int) -> list:
    """
    KEY-001: 完整OHLCV合并 (不同于aggregate_ohlc只返回highs/lows)。
    将每factor根K线合并为1根, 保留完整OHLCV。
    """
    result = []
    for i in range(0, len(bars) - factor + 1, factor):
        chunk = bars[i:i + factor]
        if not chunk:
            continue
        merged = {
            "open": float(chunk[0].get("open", chunk[0].get("o", 0))),
            "close": float(chunk[-1].get("close", chunk[-1].get("c", 0))),
            "high": max(float(b.get("high", b.get("h", 0))) for b in chunk),
            "low": min(float(b.get("low", b.get("l", 0))) for b in chunk),
            "volume": sum(float(b.get("volume", b.get("v", 0))) for b in chunk),
        }
        # 取最后一根的时间
        merged["dt"] = chunk[-1].get("dt") or chunk[-1].get("time") or chunk[-1].get("datetime")
        result.append(merged)
    return result


def _find_merged_bar_index(bars_merged, dt) -> int:
    """找到合并K线中分型对应的索引"""
    for i, bar in enumerate(bars_merged):
        if bar.dt == dt:
            return i
    for i, bar in enumerate(bars_merged):
        if bar.dt >= dt:
            return i
    return len(bars_merged) - 1 if bars_merged else 0


# =========================================
# v1.95 位置网格与辅助（第一层细化）
# =========================================
def classify_pos_zone(pos_ratio: float) -> str:
    """
    v1.95: 把 [0,1] 的 pos_ratio 细分为 5 档：
    EXTREME_LOW, LOW, MID, HIGH, EXTREME_HIGH
    """
    if pos_ratio <= 0.10:
        return "EXTREME_LOW"
    if pos_ratio <= 0.35:
        return "LOW"
    if pos_ratio <= 0.65:
        return "MID"
    if pos_ratio <= 0.90:
        return "HIGH"
    return "EXTREME_HIGH"


def compute_vol_regime(low_120: float, high_120: float) -> str:
    """
    v1.95: 用 120 根区间振幅粗分波动等级：
    - TIGHT   : 区间幅度 < 5%
    - NORMAL  : 5% ~ 15%
    - WIDE    : > 15%
    这里只作为第一层标签，不直接参与 gate。
    """
    if high_120 <= 0:
        return "NORMAL"

    width = max(high_120 - low_120, 0.0)
    pct = width / high_120
    if pct < 0.05:
        return "TIGHT"
    if pct < 0.15:
        return "NORMAL"
    return "WIDE"


def compute_wyckoff_meta_regime(phase_code: str) -> str:
    """
    v1.95: Wyckoff 元状态：RANGE / TREND / UNCLEAR
    仅作为标签输出，不改任何现有逻辑。
    """
    p = (phase_code or "UNCLEAR").upper()
    if p in ["ACCUM_RANGE_A", "ACCUM_RANGE_B", "DISTRIB_RANGE", "REDIST_RANGE"]:
        return "RANGE"
    if p in ["MARKUP_TREND", "MARKDOWN_TREND"]:
        return "TREND"
    return "UNCLEAR"


def compute_risk_mode(phase_code: str, pos_zone: str, vol_regime: str) -> Tuple[str, float, float]:
    """
    v1.95: 在 (Wyckoff 区间 × pos_zone × vol_regime) 上给一个风险标签：
    - risk_mode ∈ {AGGRESSIVE_LONG, AGGRESSIVE_SHORT, NEUTRAL, DEFENSIVE, NO_TRADE}
    - buy_quota_factor / sell_quota_factor 只用于输出，暂不参与任何 gate。
    """
    p = (phase_code or "UNCLEAR").upper()
    z = (pos_zone or "MID").upper()
    v = (vol_regime or "NORMAL").upper()

    risk_mode = "NEUTRAL"
    buy_factor = 1.0
    sell_factor = 1.0

    if p in ["ACCUM_RANGE_A", "ACCUM_RANGE_B"]:
        if z in ["EXTREME_LOW", "LOW"]:
            risk_mode = "AGGRESSIVE_LONG"
            buy_factor, sell_factor = 1.0, 0.5
        elif z == "MID":
            risk_mode = "NEUTRAL"
            buy_factor, sell_factor = 0.8, 0.8
        else:
            risk_mode = "DEFENSIVE"
            buy_factor, sell_factor = 0.5, 0.7

    elif p == "MARKUP_TREND":
        if z in ["EXTREME_LOW", "LOW", "MID"]:
            risk_mode = "AGGRESSIVE_LONG"
            buy_factor, sell_factor = 1.0, 0.5
        elif z == "HIGH":
            risk_mode = "NEUTRAL"
            buy_factor, sell_factor = 0.7, 0.8
        else:
            risk_mode = "DEFENSIVE"
            buy_factor, sell_factor = 0.4, 0.9

    elif p == "DISTRIB_RANGE":
        if z in ["HIGH", "EXTREME_HIGH"]:
            risk_mode = "AGGRESSIVE_SHORT"
            buy_factor, sell_factor = 0.5, 1.0
        elif z == "MID":
            risk_mode = "NEUTRAL"
            buy_factor, sell_factor = 0.7, 0.7
        else:
            risk_mode = "DEFENSIVE"
            buy_factor, sell_factor = 0.6, 0.6

    elif p == "REDIST_RANGE":
        if z in ["HIGH", "EXTREME_HIGH"]:
            risk_mode = "AGGRESSIVE_SHORT"
            buy_factor, sell_factor = 0.5, 1.0
        elif z == "MID":
            risk_mode = "NEUTRAL"
            buy_factor, sell_factor = 0.6, 0.8
        else:
            risk_mode = "DEFENSIVE"
            buy_factor, sell_factor = 0.6, 0.6

    elif p == "MARKDOWN_TREND":
        if z in ["HIGH", "EXTREME_HIGH"]:
            risk_mode = "AGGRESSIVE_SHORT"
            buy_factor, sell_factor = 0.4, 1.0
        elif z == "MID":
            risk_mode = "NEUTRAL"
            buy_factor, sell_factor = 0.7, 0.9
        else:
            risk_mode = "DEFENSIVE"
            buy_factor, sell_factor = 0.7, 0.7

    else:  # UNCLEAR
        if z in ["EXTREME_LOW", "EXTREME_HIGH"]:
            risk_mode = "DEFENSIVE"
            buy_factor, sell_factor = 0.4, 0.4
        else:
            risk_mode = "NO_TRADE"
            buy_factor, sell_factor = 0.0, 0.0

    # 波动特别 WIDE 时，整体再收一档
    if v == "WIDE":
        if risk_mode == "AGGRESSIVE_LONG":
            risk_mode = "NEUTRAL"
            buy_factor *= 0.8
            sell_factor *= 0.8
        elif risk_mode == "AGGRESSIVE_SHORT":
            risk_mode = "NEUTRAL"
            buy_factor *= 0.8
            sell_factor *= 0.8
        elif risk_mode == "NEUTRAL":
            risk_mode = "DEFENSIVE"
            buy_factor *= 0.8
            sell_factor *= 0.8

    return risk_mode, float(buy_factor), float(sell_factor)


def compute_position_bucket(
    last_close: float,
    low_120: float,
    high_120: float,
    mid_band_low: float = 0.3,
    mid_band_high: float = 0.7,
    near_extreme_pct: float = 0.03,
) -> dict:
    """
    v1.92: 原有 pos_ratio / position_bucket / in_mid_band / near_low_120 / near_high_120
    v1.95: 在此基础上增加 pos_zone（五档细分），不改变旧逻辑的含义。
    v2010_PATCH: 修复 near_low_120/near_high_120 判定逻辑
        - 基于 range_width 比例距离
        - 互斥约束（不允许同时为True）
    """
    width = max(high_120 - low_120, 1e-9)
    pos_ratio = (last_close - low_120) / width
    pos_ratio = max(0.0, min(1.0, pos_ratio))

    if pos_ratio < 0.5:
        position_bucket = "LOW_HALF"
    else:
        position_bucket = "UPPER_HALF"

    in_mid_band = (mid_band_low <= pos_ratio <= mid_band_high)
    
    # ===== v2010 PATCH: 修复 near_edge 逻辑 =====
    range_width = high_120 - low_120
    dist_to_low = last_close - low_120
    dist_to_high = high_120 - last_close
    near_edge_pct = near_extreme_pct
    
    near_low_candidate = (dist_to_low <= range_width * near_extreme_pct)
    near_high_candidate = (dist_to_high <= range_width * near_extreme_pct)
    
    near_edge_ambiguous = False
    if near_low_candidate and near_high_candidate:
        if abs(dist_to_low) < abs(dist_to_high):
            near_low_120 = True
            near_high_120 = False
        elif abs(dist_to_high) < abs(dist_to_low):
            near_low_120 = False
            near_high_120 = True
        else:
            near_low_120 = False
            near_high_120 = False
            near_edge_ambiguous = True
    else:
        near_low_120 = near_low_candidate
        near_high_120 = near_high_candidate
    # ===== END v2010 PATCH =====

    pos_zone = classify_pos_zone(pos_ratio)

    return {
        "pos_ratio": pos_ratio,
        "position_bucket": position_bucket,
        "in_mid_band": in_mid_band,
        "near_low_120": near_low_120,
        "near_high_120": near_high_120,
        "pos_zone": pos_zone,
        "range_width": range_width,
        "dist_to_low": dist_to_low,
        "dist_to_high": dist_to_high,
        "near_edge_pct": near_edge_pct,
        "near_edge_ambiguous": near_edge_ambiguous,
    }


def compute_dual_period_position_v3487(ohlcv_bars: list, long_period: int = 120, short_period: int = 20) -> dict:
    """
    v3.487 P2-6: 双周期位置确认

    计算长期位置(120根) + 短期位置(20根)，识别以下场景:
    - PULLBACK_IN_UPTREND: 长期UPPER_HALF + 短期LOWER_HALF → SELL权重-30%
    - RALLY_IN_DOWNTREND: 长期LOWER_HALF + 短期UPPER_HALF → BUY权重-30%
    - ALIGNED: 长期和短期位置一致
    - DIVERGENT: 其他不一致情况

    返回: {
        "long_pos": float,      # 长期位置 (0-1)
        "short_pos": float,     # 短期位置 (0-1)
        "long_bucket": str,     # UPPER_HALF / LOWER_HALF
        "short_bucket": str,    # UPPER_HALF / LOWER_HALF
        "context": str,         # 位置上下文
        "weight_adjustment": dict  # {"BUY": float, "SELL": float}
    }
    """
    if not ohlcv_bars or len(ohlcv_bars) < short_period:
        return {
            "long_pos": 0.5, "short_pos": 0.5,
            "long_bucket": "MIDDLE", "short_bucket": "MIDDLE",
            "context": "INSUFFICIENT_DATA",
            "weight_adjustment": {"BUY": 1.0, "SELL": 1.0}
        }

    # 获取当前收盘价
    last_close = ohlcv_bars[-1].get("close", 0)

    # 计算长期位置 (使用可用的最长数据，最多long_period根)
    long_bars = ohlcv_bars[-min(len(ohlcv_bars), long_period):]
    long_high = max(b.get("high", 0) for b in long_bars)
    long_low = min(b.get("low", float('inf')) for b in long_bars)
    if long_low == float('inf'):
        long_low = 0
    long_range = max(long_high - long_low, 1e-9)
    long_pos = (last_close - long_low) / long_range
    long_pos = max(0.0, min(1.0, long_pos))

    # 计算短期位置 (20根K线)
    short_bars = ohlcv_bars[-short_period:]
    short_high = max(b.get("high", 0) for b in short_bars)
    short_low = min(b.get("low", float('inf')) for b in short_bars)
    if short_low == float('inf'):
        short_low = 0
    short_range = max(short_high - short_low, 1e-9)
    short_pos = (last_close - short_low) / short_range
    short_pos = max(0.0, min(1.0, short_pos))

    # 判断位置桶
    long_bucket = "UPPER_HALF" if long_pos >= 0.5 else "LOWER_HALF"
    short_bucket = "UPPER_HALF" if short_pos >= 0.5 else "LOWER_HALF"

    # 判断上下文和权重调整
    weight_adjustment = {"BUY": 1.0, "SELL": 1.0}

    if long_bucket == "UPPER_HALF" and short_bucket == "LOWER_HALF":
        context = "PULLBACK_IN_UPTREND"
        weight_adjustment["SELL"] = 0.7  # SELL权重-30%
    elif long_bucket == "LOWER_HALF" and short_bucket == "UPPER_HALF":
        context = "RALLY_IN_DOWNTREND"
        weight_adjustment["BUY"] = 0.7  # BUY权重-30%
    elif long_bucket == short_bucket:
        context = "ALIGNED"
    else:
        context = "DIVERGENT"

    return {
        "long_pos": round(long_pos, 3),
        "short_pos": round(short_pos, 3),
        "long_bucket": long_bucket,
        "short_bucket": short_bucket,
        "context": context,
        "weight_adjustment": weight_adjustment
    }


def compute_trend_state(trend_x4: str, trend_x8: str) -> str:
    t4 = (trend_x4 or "unknown").lower()
    t8 = (trend_x8 or "unknown").lower()

    if t8 == "up" and t4 == "up":
        return "STRONG_UP"
    if t8 == "up" and t4 in ["side", "unknown"]:
        return "UP"
    if t8 == "side" and t4 == "up":
        return "UP"

    if t8 == "down" and t4 == "down":
        return "STRONG_DOWN"
    if t8 == "down" and t4 in ["side", "unknown"]:
        return "DOWN"
    if t8 == "side" and t4 == "down":
        return "DOWN"

    if t8 == "side" and t4 == "side":
        return "SIDE"

    return "SIDE"


def can_open_short_here(ctx: dict) -> bool:
    """
    v2.340: 缩小禁止做空范围
    
    修复前:
      - position_bucket = LOW_HALF (0-50%)
      - 禁止做空
    
    修复后:
      - 极低位 (0-10%): 禁止做空
      - 低位 (10-25%): 有强信号时允许
      - 其他 (25-100%): 允许做空
    """
    phase = ctx.get("wyckoff_phase_code", "UNCLEAR")
    last_close = float(ctx.get("last_close", 0.0))
    low_120 = float(ctx.get("low_120", 0.0))
    position_bucket = ctx.get("position_bucket", "UNKNOWN")
    
    # v2.340: 获取 pos_ratio
    high_120 = float(ctx.get("high_120", 0.0))
    if high_120 > low_120 > 0:
        pos_ratio = (last_close - low_120) / (high_120 - low_120)
    else:
        pos_ratio = 0.5  # 默认中位

    # 非特殊阶段，允许做空
    if phase not in ["DISTRIB_RANGE", "REDIST_RANGE", "UNCLEAR"]:
        return True

    # 计算 near_low_120
    near_low_120 = ctx.get("near_low_120")
    if near_low_120 is None and low_120 > 0:
        near_low_120 = (last_close <= low_120 * 1.03)
    near_low_120 = bool(near_low_120)

    # v2.340: 极低位 (0-10%) → 禁止做空
    if near_low_120 or pos_ratio < 0.10:
        return False
    
    # v2.340: 低位 (10-25%) → 有强信号时允许
    if pos_ratio < 0.25:
        # 检查是否有强做空信号
        has_strong_sell = ctx.get("has_strong_sell_signal", False)
        if has_strong_sell:
            return True  # 有强信号，允许
        else:
            return False  # 无强信号，禁止
    
    # v2.340: 其他位置 (25-100%) → 允许做空
    return True


def is_unclear_mid_no_edge(ctx: dict) -> bool:
    phase = ctx.get("wyckoff_phase_code", "UNCLEAR")
    if phase != "UNCLEAR":
        return False

    in_mid_band = bool(ctx.get("in_mid_band", False))
    pa_buy_edge = bool(ctx.get("pa_buy_edge", False))
    pa_sell_edge = bool(ctx.get("pa_sell_edge", False))
    near_low_120 = bool(ctx.get("near_low_120", False))
    near_high_120 = bool(ctx.get("near_high_120", False))

    if in_mid_band and (not pa_buy_edge) and (not pa_sell_edge) and (not near_low_120) and (not near_high_120):
        return True

    return False


def check_unclear_gate_with_log(ctx: dict, symbol: str, final_action: str, l2_reason_tag: str = None) -> tuple:
    """
    v2.300: UNCLEAR Gate 检查 + 详细日志输出
    
    Returns:
        (should_block: bool, reason: str)
    """
    phase = ctx.get("wyckoff_phase_code", "UNCLEAR")
    in_mid_band = bool(ctx.get("in_mid_band", False))
    pa_buy_edge = bool(ctx.get("pa_buy_edge", False))
    pa_sell_edge = bool(ctx.get("pa_sell_edge", False))
    near_low_120 = bool(ctx.get("near_low_120", False))
    near_high_120 = bool(ctx.get("near_high_120", False))
    
    print(f"\n{'='*70}")
    print(f"[UNCLEAR GATE] 结构不清晰门控检查")
    print(f"{'='*70}")
    print(f"Symbol: {symbol}")
    print(f"Current action: {final_action}")
    print(f"")
    print(f"条件检查:")
    print(f"  ① Wyckoff phase:     {phase}")
    print(f"  ② 位于中部区间:      {in_mid_band}")
    print(f"  ③ PA买入edge:        {pa_buy_edge}")
    print(f"  ④ PA卖出edge:        {pa_sell_edge}")
    print(f"  ⑤ 靠近低位120:       {near_low_120}")
    print(f"  ⑥ 靠近高位120:       {near_high_120}")
    print(f"")
    
    # 检查是否不在交易动作中
    if final_action not in ["BUY", "SELL"]:
        print(f"结果: ✓ PASS (当前非交易动作)")
        print(f"{'='*70}\n")
        return False, "not_trade_action"
    
    # 检查是否为 UNCLEAR 阶段
    if phase != "UNCLEAR":
        print(f"结果: ✓ PASS")
        print(f"原因: Wyckoff阶段 = {phase} (不是UNCLEAR)")
        print(f"说明: 结构清晰，允许交易")
        print(f"{'='*70}\n")
        return False, "phase_not_unclear"
    
    # 检查是否为 L2 主动开仓
    if l2_reason_tag in ("L2_INITIATE_BUY", "L2_INITIATE_SELL"):
        print(f"结果: ✓ PASS (L2主动开仓豁免)")
        print(f"原因: L2_INITIATE override")
        print(f"说明: L2主动发起的强信号，绕过UNCLEAR门控")
        print(f"{'='*70}\n")
        return False, "l2_initiate_bypass"
    
    # 检查是否在极端位置
    if near_low_120 or near_high_120:
        extreme_pos = "低位120" if near_low_120 else "高位120"
        print(f"结果: ✓ PASS")
        print(f"原因: 位于极端位置 ({extreme_pos})")
        print(f"说明: 极端位置可尝试，风险可控")
        print(f"{'='*70}\n")
        return False, "extreme_position"
    
    # v2.340: 检查是否有 L2 强信号
    # 即使无 PA edge，如果 L2 有强信号也不拦截
    l2_has_strong_signal = False
    if l2_reason_tag in (
        "L1_L2_AGREE_BUY", "L1_L2_AGREE_SELL",
        "L2_BUY_L1_NEUTRAL", "L2_SELL_L1_NEUTRAL",
        "L1_BUY_L2_NEUTRAL", "L1_SELL_L2_NEUTRAL",
        "L2_NO_SIGNAL_RESPECT_L1"
    ):
        l2_has_strong_signal = True
    
    if l2_has_strong_signal:
        print(f"结果: ✓ PASS (L2有强信号)")
        print(f"原因: l2_reason_tag = {l2_reason_tag}")
        print(f"说明: L2分析提供了明确信号，即使无PA edge也允许")
        print(f"{'='*70}\n")
        return False, "l2_strong_signal"
    
    # 检查是否有PA edge
    if pa_buy_edge or pa_sell_edge:
        edge_type = "买入" if pa_buy_edge else "卖出"
        print(f"结果: ✓ PASS")
        print(f"原因: 有PA edge ({edge_type})")
        print(f"说明: 价格行为提供了明确信号")
        print(f"{'='*70}\n")
        return False, "has_pa_edge"
    
    # v2.340: 缩小中部范围判断
    # 获取 pos_ratio 进行更精确的判断
    pos_ratio = ctx.get("pos_ratio", 0.5)
    is_true_mid = (0.40 <= pos_ratio <= 0.60)  # 真正的中部 (40-60%)
    
    # 检查是否在真正的中部区间
    if not is_true_mid:
        print(f"结果: ✓ PASS")
        print(f"原因: 不在真正的中部区间 (pos_ratio={pos_ratio:.2%})")
        print(f"说明: 中部边缘位置，允许交易")
        print(f"{'='*70}\n")
        return False, "not_true_mid"
    
    # 检查原有的 in_mid_band (作为备用)
    if not in_mid_band:
        print(f"结果: ✓ PASS")
        print(f"原因: 不在中部区间")
        print(f"说明: 位置偏离中部，可以尝试")
        print(f"{'='*70}\n")
        return False, "not_mid_band"
    
    # 全部条件满足 → 触发门控
    print(f"结果: ✗ BLOCK")
    print(f"")
    print(f"⚠️  触发原因:")
    print(f"  • Wyckoff = UNCLEAR (结构不清晰)")
    print(f"  • 位于真正中部区间 (pos_ratio={pos_ratio:.2%}, 40-60%)")  # v2.340
    print(f"  • 无PA买入edge (pa_buy_edge = False)")
    print(f"  • 无PA卖出edge (pa_sell_edge = False)")
    print(f"  • 无L2强信号 (l2_reason_tag = {l2_reason_tag})")  # v2.340
    print(f"  • 非极低位 (near_low_120 = False)")
    print(f"  • 非极高位 (near_high_120 = False)")
    print(f"")
    print(f"风控规则:")
    print(f"  「原则3: 结构不清晰 + 真正中部 → HOLD」")  # v2.340
    print(f"  不在清晰的低位或高位，没有明确的信号")
    print(f"  此时开仓风险过高，强制HOLD保护资金")
    print(f"")
    print(f"强制修改: {final_action} → HOLD")
    print(f"{'='*70}\n")
    return True, "UNCLEAR_MID_NO_EDGE"


# =========================================================
# v2.340: 位置优先级检查
# =========================================================
def check_position_priority(ctx: dict, final_action: str, symbol: str) -> dict:
    """
    v2.340: 位置优先级检查
    
    优先级0 (最高):
      - 极高位 (>95%) + SELL → 强制允许
      - 极低位 (<5%)  + BUY  → 强制允许
    
    优先级1:
      - 高位 (>85%) + SELL → 优先允许
      - 低位 (<15%) + BUY  → 优先允许
    
    Returns:
        {
            "bypass_all_gates": bool,
            "bypass_most_gates": bool,
            "priority_level": int,
            "reason": str,
            "original_action": str,
        }
    """
    pos_ratio = ctx.get("pos_ratio", 0.5)
    
    print(f"\n{'='*70}")
    print(f"[POSITION PRIORITY] 位置优先级检查")
    print(f"{'='*70}")
    print(f"Symbol: {symbol}")
    print(f"Current action: {final_action}")
    print(f"Position ratio: {pos_ratio:.2%}")
    print(f"")
    
    # 非交易动作，跳过
    if final_action not in ["BUY", "SELL"]:
        print(f"结果: 跳过 (当前非交易动作)")
        print(f"{'='*70}\n")
        return {
            "bypass_all_gates": False,
            "bypass_most_gates": False,
            "priority_level": 99,
            "reason": "not_trade_action",
            "original_action": final_action,
        }
    
    # 优先级0: 极端位置 → 强制允许
    if pos_ratio > 0.95 and final_action == "SELL":
        print(f"结果: ✓✓✓ 最高优先级触发 (优先级0)")
        print(f"原因: 极高位 ({pos_ratio:.2%}) + SELL")
        print(f"效果: bypass_all_gates = True")
        print(f"说明: 极高位卖出，强制允许，绕过所有Gates")
        print(f"{'='*70}\n")
        return {
            "bypass_all_gates": True,
            "bypass_most_gates": True,
            "priority_level": 0,
            "reason": "EXTREME_HIGH_SELL",
            "original_action": final_action,
        }
    
    if pos_ratio < 0.05 and final_action == "BUY":
        print(f"结果: ✓✓✓ 最高优先级触发 (优先级0)")
        print(f"原因: 极低位 ({pos_ratio:.2%}) + BUY")
        print(f"效果: bypass_all_gates = True")
        print(f"说明: 极低位买入，强制允许，绕过所有Gates")
        print(f"{'='*70}\n")
        return {
            "bypass_all_gates": True,
            "bypass_most_gates": True,
            "priority_level": 0,
            "reason": "EXTREME_LOW_BUY",
            "original_action": final_action,
        }
    
    # 优先级1: 高/低位 → 优先允许
    if pos_ratio > 0.85 and final_action == "SELL":
        print(f"结果: ✓✓ 高优先级触发 (优先级1)")
        print(f"原因: 高位 ({pos_ratio:.2%}) + SELL")
        print(f"效果: bypass_most_gates = True")
        print(f"说明: 高位卖出，优先允许，绕过大部分Gates")
        print(f"{'='*70}\n")
        return {
            "bypass_all_gates": False,
            "bypass_most_gates": True,
            "priority_level": 1,
            "reason": "HIGH_POSITION_SELL",
            "original_action": final_action,
        }
    
    if pos_ratio < 0.15 and final_action == "BUY":
        print(f"结果: ✓✓ 高优先级触发 (优先级1)")
        print(f"原因: 低位 ({pos_ratio:.2%}) + BUY")
        print(f"效果: bypass_most_gates = True")
        print(f"说明: 低位买入，优先允许，绕过大部分Gates")
        print(f"{'='*70}\n")
        return {
            "bypass_all_gates": False,
            "bypass_most_gates": True,
            "priority_level": 1,
            "reason": "LOW_POSITION_BUY",
            "original_action": final_action,
        }
    
    # 无优先级
    print(f"结果: 无优先级")
    print(f"原因: pos_ratio={pos_ratio:.2%}，不在极端或高低位范围")
    print(f"说明: 正常流程，不绕过Gates")
    print(f"{'='*70}\n")
    return {
        "bypass_all_gates": False,
        "bypass_most_gates": False,
        "priority_level": 99,
        "reason": "no_priority",
        "original_action": final_action,
    }


# =========================================================
# 信号归一化
# =========================================================
def normalize_signal_and_level(raw_signal: str, raw_level: str) -> tuple[str, str, Optional[float]]:
    if raw_signal is None:
        raw_signal = "none"
    if raw_level is None:
        raw_level = "none"

    s = str(raw_signal).strip().lower()
    level_str = str(raw_level).strip()

    if s in ["breakout", "breakout_up", "long", "buy"]:
        signal = "breakout"
    elif s in ["cross_over", "golden_cross", "cross_over_up"]:
        signal = "cross_over"
    elif s in ["breakdown", "breakdown_down", "short", "sell"]:
        signal = "breakdown"
    elif s in ["cross_under", "dead_cross", "cross_below"]:
        signal = "cross_under"
    elif s in ["none", "", "neutral"]:
        signal = "none"
    else:
        signal = "none"

    broken_level: Optional[float] = None
    try:
        v = float(level_str)
        if v > 0:
            broken_level = v
        else:
            broken_level = None
    except Exception:
        broken_level = None

    return signal, level_str, broken_level


# =========================================================
# GCC-0244: Crypto Anchor Signal Detection (人类模式)
# 2连阳线+DC低位 → BUY锚定(units=3)
# 2连阴线+DC高位 → SELL锚定(units=3)
# 锚定持久: 直到反向锚定触发或手动取消
# =========================================================
CRYPTO_ANCHOR_ENABLED = False  # GCC-0244: 加密货币锚定开关 (True=启用, False=休眠)
_CRYPTO_ANCHOR_SYMBOLS = {"BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"}
_CRYPTO_ANCHOR_STATE_FILE = os.path.join(".GCC", "human_anchors.json")
_crypto_anchor_last_trigger = {}  # {symbol: bar_timestamp} dedup


def _load_crypto_anchor_for_symbol(symbol: str) -> dict:
    """读取 .GCC/human_anchors.json 中某个 symbol 的活跃锚定。"""
    try:
        if not os.path.exists(_CRYPTO_ANCHOR_STATE_FILE):
            return {}
        with open(_CRYPTO_ANCHOR_STATE_FILE, encoding="utf-8") as f:
            anchors = json.load(f)
        if not isinstance(anchors, list):
            return {}
        for a in reversed(anchors):
            if a.get("key") == symbol and a.get("tracking_status") == "ACTIVE":
                return a
        return {}
    except Exception:
        return {}


def _detect_crypto_anchor(symbol: str, bars: list, tv_pos_in_channel=None) -> dict | None:
    """
    GCC-0244: 检测加密货币锚定信号。
    条件:
      BUY:  2连阳线 (close > open) + DC位置 < 0.30
      SELL: 2连阴线 (close < open) + DC位置 > 0.70
    返回: {direction, pos_in_channel, trigger_price, bar_timestamp} 或 None
    """
    if symbol not in _CRYPTO_ANCHOR_SYMBOLS or len(bars) < 22:
        return None

    bar_prev = bars[-2]  # 倒数第2根
    bar_last = bars[-1]  # 最后1根

    o1 = float(bar_prev.get("open", bar_prev.get("o", 0)))
    c1 = float(bar_prev.get("close", bar_prev.get("c", 0)))
    o2 = float(bar_last.get("open", bar_last.get("o", 0)))
    c2 = float(bar_last.get("close", bar_last.get("c", 0)))

    bullish_1, bullish_2 = c1 > o1, c2 > o2
    bearish_1, bearish_2 = c1 < o1, c2 < o2

    # DC位置: 优先用TV推送值, 否则从K线计算
    if tv_pos_in_channel is not None:
        pos = tv_pos_in_channel / 100.0 if tv_pos_in_channel > 1 else tv_pos_in_channel
    else:
        highs_20 = [float(b.get("high", b.get("h", 0))) for b in bars[-22:-2]]
        lows_20 = [float(b.get("low", b.get("l", 0))) for b in bars[-22:-2]]
        h20 = max(highs_20) if highs_20 else 0
        l20 = min(lows_20) if lows_20 else 0
        if h20 <= l20:
            return None
        pos = (c2 - l20) / (h20 - l20)

    # Dedup: 同一根K线只触发一次
    bar_ts = bar_last.get("timestamp", 0)
    if _crypto_anchor_last_trigger.get(symbol) == bar_ts and bar_ts > 0:
        return None

    direction = None
    if bullish_1 and bullish_2 and pos < 0.30:
        direction = "BUY"
    elif bearish_1 and bearish_2 and pos > 0.70:
        direction = "SELL"

    if not direction:
        return None

    # 同方向锚定已存在 → 不重复触发
    existing = _load_crypto_anchor_for_symbol(symbol)
    if existing:
        existing_dir = (existing.get("direction") or "").upper()
        if (direction == "BUY" and existing_dir in ("LONG", "BULLISH")) or \
           (direction == "SELL" and existing_dir in ("SHORT", "BEARISH")):
            return None  # 同方向, 跳过

    _crypto_anchor_last_trigger[symbol] = bar_ts
    return {
        "direction": direction,
        "pos_in_channel": pos,
        "trigger_price": c2,
        "bar_timestamp": bar_ts,
    }


def _write_crypto_anchor(symbol: str, direction: str, pos_in_channel: float, trigger_price: float):
    """
    GCC-0244: 写入加密货币锚定到 .GCC/human_anchors.json
    格式兼容 dashboard renderHumanGuidance()
    锚定持久: 直到反向锚定触发或手动取消
    """
    from datetime import datetime, timezone
    try:
        if os.path.exists(_CRYPTO_ANCHOR_STATE_FILE):
            with open(_CRYPTO_ANCHOR_STATE_FILE, encoding="utf-8") as f:
                anchors = json.load(f)
        else:
            anchors = []
        if not isinstance(anchors, list):
            anchors = []

        # 移除该symbol的旧锚定 (反向替换)
        anchors = [a for a in anchors if a.get("key") != symbol]

        now_str = datetime.now(timezone.utc).isoformat()
        anchor_dir = "LONG" if direction == "BUY" else "SHORT"
        candle_type = "阳" if direction == "BUY" else "阴"
        dc_label = "低" if direction == "BUY" else "高"

        anchors.append({
            "anchor_id": f"crypto-{symbol}-{int(datetime.now(timezone.utc).timestamp())}",
            "key": symbol,
            "direction": anchor_dir,
            "main_concern": f"2连{candle_type}线 DC{dc_label}位({pos_in_channel:.0%}) → {direction}锚定 units=3",
            "constraints": [f"{direction} units=3", "persistent until reversed"],
            "expires_after": "until_reversed",
            "created_at": now_str,
            "trigger_price": trigger_price,
            "tracking_status": "ACTIVE",
            "created_by": "CRYPTO_ANCHOR_DETECTOR",
        })

        with open(_CRYPTO_ANCHOR_STATE_FILE, "w", encoding="utf-8") as f:
            json.dump(anchors, f, ensure_ascii=False, indent=2)

        log_to_server(
            f"[GCC-0244][ANCHOR] {symbol} 锚定设置: {anchor_dir} "
            f"price={trigger_price:.2f} DC={pos_in_channel:.1%}"
        )
    except Exception as e:
        log_to_server(f"[GCC-0244][ANCHOR][ERROR] {symbol} 写入失败: {e}")


def _dispatch_crypto_anchor_signal(symbol: str, direction: str, trigger_price: float):
    """
    GCC-0244: 锚定信号发送 units=3
    连续发送3次webhook (每次间隔2秒避免rate-limit)
    """
    import time as _t
    units_target = 3
    units_sent = 0

    for i in range(units_target):
        result = send_3commas_signal(direction, trigger_price, symbol,
                                     signal_type="人类锚定", bypass_cooldown=True, source="gcc_tm")
        if result is True:
            units_sent += 1
            log_to_server(f"[GCC-0244][DISPATCH] {symbol} {direction} unit {i+1}/{units_target} ✓")
        elif result == "COOLDOWN":
            log_to_server(f"[GCC-0244][DISPATCH] {symbol} {direction} unit {i+1}/{units_target} 冷却中")
            break
        elif result is None:
            log_to_server(f"[GCC-0244][DISPATCH] {symbol} {direction} unit {i+1}/{units_target} 门控拦截")
            break
        else:
            log_to_server(f"[GCC-0244][DISPATCH] {symbol} {direction} unit {i+1}/{units_target} 失败")
            break
        if i < units_target - 1:
            _t.sleep(2)  # 2秒间隔避免rate-limit

    log_to_server(f"[GCC-0244][ANCHOR] {symbol} {direction} 发送完成: {units_sent}/{units_target} units")
    return units_sent


# =========================================================
# KEY-001 Human Anchor 冲突检查层
# gcc-evo anchor calibrate 写入 .GCC/human_anchors.json
# =========================================================
_ANCHOR_CRYPTO = {"BTCUSDC", "ETHUSDC", "SOLUSDC", "ZECUSDC"}

def _load_latest_human_anchor() -> dict:
    """读取 .GCC/human_anchors.json 最新有效 anchor（未过期）。"""
    import json, os
    from datetime import datetime, timezone, timedelta
    try:
        path = os.path.join(".GCC", "human_anchors.json")
        if not os.path.exists(path):
            return {}
        with open(path, encoding="utf-8") as f:
            anchors = json.load(f)
        if not isinstance(anchors, list) or not anchors:
            return {}
        now = datetime.now(timezone.utc)
        # 过滤未过期的，取最新
        valid = []
        for a in anchors:
            exp = a.get("expires_after", "")
            created_str = a.get("created_at", "")
            try:
                created = datetime.fromisoformat(created_str.replace("Z", "+00:00"))
            except Exception:
                valid.append(a)
                continue
            days = 5
            if "2_trading" in exp:
                days = 2
            elif "10_sessions" in exp:
                days = 10
            if now - created < timedelta(days=days):
                valid.append(a)
        return valid[-1] if valid else {}
    except Exception:
        return {}


def _check_human_anchor_gate(symbol: str, final_action: str, signal_type: str) -> tuple[bool, str]:
    """
    KEY-001 anchor 冲突检查（Phase1: 观察模式，仅记录不拦截）。
    返回 (should_block, reason)。
    Phase1: 永远返回 False（不拦截），仅输出日志。
    Phase2: 按规则拦截。
    每日纽约8am自动重置：anchor timestamp在今天8am之前视为过期。
    """
    ANCHOR_GATE_PHASE = 1   # Phase1: 观察, Phase2: 拦截
    _exempt = signal_type in ("移动止损", "移动止盈")
    if _exempt:
        return False, "exempt"

    anchor = _load_latest_human_anchor()
    if not anchor:
        return False, "no_anchor"

    # ── 8am NY 自动重置: anchor timestamp在今天8am之前 → 视为过期 ──
    try:
        from datetime import datetime, time as dt_time
        from zoneinfo import ZoneInfo
        _anchor_ts_str = anchor.get("created_at", "")
        if _anchor_ts_str:
            _ny_now = datetime.now(ZoneInfo("America/New_York"))
            _today_8am = _ny_now.replace(hour=8, minute=0, second=0, microsecond=0)
            _anchor_created = datetime.fromisoformat(_anchor_ts_str.replace("Z", "+00:00"))
            _anchor_ny = _anchor_created.astimezone(_ny_now.tzinfo)
            if _ny_now >= _today_8am and _anchor_ny < _today_8am:
                log_to_server(
                    f"[KEY001-ANCHOR][8AM_RESET] {symbol} {final_action}: "
                    f"anchor过期(created={_anchor_ts_str} < today 8am NY) → 中性放行"
                )
                return False, "anchor过期(8am重置)"
    except Exception as _8am_e:
        log_to_server(f"[KEY001-ANCHOR][8AM_RESET][ERROR] {symbol}: {_8am_e}")

    direction = str(anchor.get("direction", "")).upper()
    constraints = anchor.get("constraints", [])
    is_crypto = symbol in _ANCHOR_CRYPTO
    constraint_text = constraints[0] if constraints else ""

    block = False
    reason = ""

    if is_crypto:
        # 加密货币: SHORT anchor → BUY 信号冲突
        if direction == "SHORT" and final_action == "BUY":
            block = True
            reason = f"anchor=SHORT(加密) vs BUY → 冲突"
        # SHORT anchor + 无暴跌风险: SELL 放行
        elif direction == "SHORT" and final_action == "SELL":
            reason = "anchor=SHORT(加密) SELL 对齐"
    else:
        # 美股: NEUTRAL/底仓模式 → 限制来回，BUY 1-2次低位可以，连续BUY后SELL抑制
        if direction == "NEUTRAL" and final_action == "SELL":
            # 底部建仓阶段不应急于卖出
            _pos = get_state_for_symbol(symbol).get("position_units", 0)
            if _pos <= 2:
                block = True
                reason = f"anchor=NEUTRAL(美股底仓) pos={_pos}≤2 vs SELL → 建仓保护"
        elif direction == "SHORT" and final_action == "BUY":
            block = True
            reason = "anchor=SHORT(美股) vs BUY → 冲突"

    # GCC-0258 S3: DA-01~06完整验证 (Phase1仅日志)
    try:
        from gcc_evolution.direction_anchor import DirectionAnchorValidator, DAContext
        _da_ctx = DAContext(
            anchor=anchor,
            proposed_action={"action": final_action, "subject": symbol},
            state={"market_regime": get_state_for_symbol(symbol).get("market_regime", ""),
                   "signal_type": signal_type},
        )
        _da_result = DirectionAnchorValidator().validate(_da_ctx)
        if not _da_result.passed:
            _da_codes = ",".join(v.code.value for v in _da_result.violations)
            _da_reasons = "; ".join(v.reason[:60] for v in _da_result.violations)
            log_to_server(f"[GCC-0258][DA_GATE] {symbol} {final_action} DA BLOCKED: {_da_codes} | {_da_reasons}")
        else:
            log_to_server(f"[GCC-0258][DA_GATE] {symbol} {final_action} DA OK (all 6 passed)")
    except Exception as _da_e:
        log_to_server(f"[GCC-0258][DA_GATE] {symbol} DA验证异常: {_da_e}")

    if ANCHOR_GATE_PHASE == 1:
        # Phase1: 只记录，不真正拦截
        if block:
            log_to_server(
                f"[KEY001-ANCHOR][OBS] {symbol} {final_action} 本应被anchor拦截: {reason} "
                f"| direction={direction} constraint={constraint_text[:50]}"
            )
        else:
            log_to_server(
                f"[KEY001-ANCHOR][OBS] {symbol} {final_action} anchor放行: {reason or '无冲突'} "
                f"| direction={direction}"
            )
        return False, reason   # Phase1 永不拦截
    else:
        return block, reason


# =========================================================
# 3Commas Webhook 下单（加密货币）
# =========================================================
def send_3commas_signal(final_action: str, last_close: float, symbol: str, signal_type: str = "", bypass_cooldown: bool = False, source: str = "main"):
    """v21.18: 补request_id+60s冷却+连续失败熔断; GCC-0194: 去掉重复过滤(已在扫描引擎统一处理)
    返回: True=成功, False=API发送失败, None=被门控/过滤拦截
    v3.680 GCC-0254: source参数 — 加密货币只允许 source='gcc_tm' 实盘下单，主路径观察"""
    if final_action not in ["BUY", "SELL"]:
        log_to_server(f"[3Commas] final_action={final_action} 非 BUY/SELL，跳过。")
        return False

    # v3.660: GCC-TM全量独占 — 所有加密货币只允许gcc_tm/gcc_scalp下单
    if source not in ("gcc_tm", "gcc_scalp"):
        log_to_server(
            f"[BLOCKED][非B1] {symbol} {final_action} price={last_close:.2f} "
            f"source={source} type={signal_type} → 非GCC-TM来源，仅观察"
        )
        return None  # 门控拦截，不实际下单

    # GCC-TM 裁决信号: 已经过Vision门控+8轮决策, 跳过KEY-001/KEY-002二次审查
    _3c_gcc_tm_bypass = (source == "gcc_tm")

    # ── gate block计数器(传入Master Hub blocked_gate_count) ──────────────
    _gate_block_count = 0

    # ── KEY-001 Human Anchor 冲突检查 (Phase1: 纯观察，不拦截) ───────────────
    if not _3c_gcc_tm_bypass:
        try:
            _anchor_block, _anchor_reason = _check_human_anchor_gate(symbol, final_action, signal_type)
            if _anchor_block:
                log_to_server(f"[KEY001-ANCHOR][拦截] {symbol} {final_action}: {_anchor_reason}")
                return None  # 门控拦截，非API失败
        except Exception as _ae:
            log_to_server(f"[KEY001-ANCHOR][ERROR] {symbol}: {_ae}")

    # ── KEY-001 动态门控误杀控制 (Phase2 真实拦截) ──────────────────────────
    _k1_exempt = signal_type in ("移动止损", "移动止盈") or _3c_gcc_tm_bypass
    if not _k1_exempt:
        try:
            from modules.vision_adaptive import apply_key001_gate as _k1_gate
            _k1_allowed, _k1_reason = _k1_gate(symbol, final_action, {})
            log_to_server(
                f"[B1][KEY-001][GATE] {symbol} {final_action} "
                f"allowed={_k1_allowed} reason={_k1_reason}"
            )
            if not _k1_allowed:
                log_to_server(f"[B1][KEY-001][GATE][拦截] {symbol} {final_action}: {_k1_reason}")
                return None  # 门控拦截，非API失败
        except Exception as _k1_e:
            log_to_server(f"[B1][KEY-001][GATE][ERROR] {symbol}: {_k1_e}")

    # ── KEY-001 Vision Cache Gate (GCC-0062: Phase3 full拦截) ──
    # v3.678: 写入点已在llm_decide()内完成, Gate点从缓存读snapshot做校准
    # Phase3: full真拦截(胜率<45%/confidence<0.55→阻止交易)
    KEY001_VCACHE_MODE = "observe"  # GCC-0062: "observe"/"soft"/"full"
    if not _k1_exempt and not _3c_gcc_tm_bypass:
        try:
            from modules.key001_vision_cache import VisionCache as _VCCache, vision_gate as _vc_gate
            _vc_cache = _VCCache()
            if KEY001_VCACHE_MODE == "observe":
                log_to_server(
                    f"[KEY001-VCACHE][GATE] {symbol} {final_action} mode=observe"
                )
            else:
                # soft/full: 从缓存读最近snapshot做校准判断
                _vc_allowed, _vc_reason = _vc_gate(
                    symbol=symbol, action=final_action, chart=None, df=None,
                    cache=_vc_cache, mode=KEY001_VCACHE_MODE,
                )
                log_to_server(
                    f"[KEY001-VCACHE][GATE] {symbol} {final_action} mode={KEY001_VCACHE_MODE} "
                    f"allowed={_vc_allowed} reason={_vc_reason}"
                )
                if not _vc_allowed:
                    log_to_server(f"[KEY001-VCACHE][拦截] {symbol} {final_action}: {_vc_reason}")
                    return None
        except Exception as _vc_e:
            log_to_server(f"[KEY001-VCACHE][GATE][ERROR] {symbol}: {_vc_e}")

    # ── KEY-002 Regime自适应入场门控 (Phase2 真实拦截) ──────────────────────
    _k2_exempt = signal_type in ("移动止损", "移动止盈") or _3c_gcc_tm_bypass
    if not _k2_exempt:
        try:
            from modules.key002_regime import (
                build_features_from_market_regime as _k2_build_feat,
                detect_regime as _k2_detect,
                load_key002_runtime_params as _k2_load_params,
                key002_apply_entry_gate as _k2_gate,
            )
            _k2_state = get_state_for_symbol(symbol)
            _k2_mr    = _k2_state.get("market_regime", {})
            if not isinstance(_k2_mr, dict):
                _k2_mr = {"current_trend": str(_k2_mr)}
            _k2_feat  = _k2_build_feat(symbol, _k2_mr)
            _k2_regime = _k2_detect(_k2_feat)
            _k2_params = _k2_load_params(symbol, _k2_regime)
            # v3.660: 从_last_l1_trend_vision读取真实confidence (market_regime是字符串无confidence键)
            _k2_l1v    = _k2_state.get("_last_l1_trend_vision", {})
            _k2_conf   = float(_k2_l1v.get("confidence", 0.60)) if isinstance(_k2_l1v, dict) else 0.60
            _k2_allowed, _k2_reason = _k2_gate(symbol, _k2_conf, _k2_params)
            log_to_server(
                f"[B1][KEY-002][GATE] {symbol} {final_action} regime={_k2_regime} "
                f"conf={_k2_conf:.3f} threshold={_k2_params.entry_threshold:.3f} "
                f"allowed={_k2_allowed} reason={_k2_reason}"
            )
            if not _k2_allowed:
                log_to_server(f"[B1][KEY-002][GATE][拦截] {symbol} {final_action}: {_k2_reason}")
                return None  # 门控拦截，非API失败
        except Exception as _k2_e:
            log_to_server(f"[B1][KEY-002][GATE][ERROR] {symbol}: {_k2_e}")

    # ── AUD-052 方向翻转冷却门控 (direction_flip_cooldown_bars) ────────────
    _dfc_exempt = signal_type in ("移动止损", "移动止盈") or _3c_gcc_tm_bypass
    if not _dfc_exempt:
        try:
            import time as _dfc_time
            _dfc_bars = get_symbol_param(symbol, "timing", "direction_flip_cooldown_bars", default=0)
            if _dfc_bars > 0:
                _dfc_flip_time = get_state_for_symbol(symbol).get("_last_direction_flip_time", 0)
                _dfc_tf_min = int(get_symbol_param(symbol, "timing", "timeframe_minutes", default=240))
                _dfc_cooldown_secs = _dfc_bars * _dfc_tf_min * 60
                _dfc_elapsed = _dfc_time.time() - _dfc_flip_time
                if _dfc_elapsed < _dfc_cooldown_secs:
                    _dfc_remaining = (_dfc_cooldown_secs - _dfc_elapsed) / 3600
                    _dfc_from = get_state_for_symbol(symbol).get("_last_direction_flip_from", "?")
                    _dfc_to   = get_state_for_symbol(symbol).get("_last_direction_flip_to",   "?")
                    log_to_server(
                        f"[AUD-052][DIR_FLIP_COOL][拦截] {symbol} {final_action}: "
                        f"方向翻转冷却中({_dfc_from}→{_dfc_to}) "
                        f"剩余{_dfc_remaining:.1f}h ({_dfc_bars}根K线)"
                    )
                    return None  # 门控拦截，非API失败
                elif _dfc_flip_time > 0:
                    log_to_server(
                        f"[AUD-052][DIR_FLIP_COOL] {symbol} {final_action}: "
                        f"冷却已过({_dfc_elapsed/3600:.1f}h >= {_dfc_cooldown_secs/3600:.0f}h) 放行"
                    )
        except Exception as _dfc_e:
            log_to_server(f"[AUD-052][DIR_FLIP_COOL][ERROR] {symbol}: {_dfc_e}")

    # ── KEY-001 大师模块 (观察模式: DOWNGRADE只记录不拦截, 异常fail-open) ─────
    MASTER_GATE_ENABLED = True
    if MASTER_GATE_ENABLED and final_action in ("BUY", "SELL") and signal_type not in ("移动止损", "移动止盈") and not _3c_gcc_tm_bypass:
        try:
            from modules.key001_master_validation.hub import MasterValidationHub
            from modules.key001_master_validation.contracts import MasterContext
            from modules.key001_master_validation.audit import MasterAuditLogger

            _mst = get_state_for_symbol(symbol) or {}
            _mmr = _mst.get("market_regime", {})
            _mfd = _mst.get("_last_final_decision", {})
            _m3w = _mfd.get("three_way_signals", {}) if isinstance(_mfd, dict) else {}
            _mmr2 = _m3w.get("market_regime", _mmr)

            _mctx = MasterContext(
                symbol=symbol,
                direction=final_action,
                signal_type=signal_type or "",
                signal_strength=float(_mmr2.get("confidence", 0.5)),
                filter_passed=True,
                blocked_reason=None,
                blocked_gate_count=_gate_block_count,
                market={
                    "pivot_distance_pct": abs(float(_mmr2.get("pos_ratio", 0.5)) - 0.5) * 0.1,
                    "rvol": float(_mmr2.get("volume_ratio", 1.0)),
                    "trend_position_pct": float(_mmr2.get("pos_ratio", 0.5)),
                    "rr_ratio": float(_mmr2.get("atr_ratio", 1.5)),
                    "signal_freq_5d": int(_mst.get("actual_buy_count", 0)) + int(_mst.get("actual_sell_count", 0)),
                    "breakout_distance_pct": 0.01,
                    "pullback_pct": 0.03,
                    "pullback_rvol": 0.9,
                },
                macro={"trend_x4": _mmr2.get("big_trend", _mmr2.get("trend_x4", "side"))},
                stats={},
            )
            _mhub = MasterValidationHub.from_config_files()
            _mdec = _mhub.evaluate(_mctx)
            MasterAuditLogger().log(_mctx, _mdec)
            log_to_server(
                f"[KEY001-MASTER] {symbol} {final_action} "
                f"action={_mdec.action} score={_mdec.final_score:.3f} "
                f"reasons={_mdec.reasons}"
            )
            if _mdec.action == "DOWNGRADE":
                log_to_server(f"[KEY001-MASTER][OBS] {symbol} {final_action}: score={_mdec.final_score:.3f} {_mdec.reasons} (观察模式,不拦截)")
                # 观察模式: 不return None
        except Exception as _me:
            log_to_server(f"[KEY001-MASTER][ERROR] {symbol}: {_me} → fail-open放行")

    # GCC-0256 S1: Coinbase直连模式 (True=直接API下单, False=3Commas webhook)
    COINBASE_DIRECT_MODE = False  # 观察中，验证通过后开启

    cfg = PAIR_CONFIG.get(symbol)
    if not cfg:
        log_to_server(f"[3Commas] 未在 PAIR_CONFIG 中找到 {symbol}，跳过下单。")
        return False

    if not COINBASE_DIRECT_MODE:
        if not THREECOMMAS_WEBHOOK_URL:
            log_to_server("[3Commas] THREECOMMAS_WEBHOOK_URL 未设置，跳过下单。")
            return False
        if not THREECOMMAS_SECRET:
            log_to_server("[3Commas] THREECOMMAS_SECRET 未设置，跳过下单。")
            return False

    # v21.18: 60秒信号冷却 (对齐SignalStack)
    import time as time_module
    current_time = time_module.time()
    state = get_state_for_symbol(symbol)

    SIGNAL_COOLDOWN_SECONDS = 60
    last_signal_key = f"last_{final_action.lower()}_time_3c"
    last_signal_time = state.get(last_signal_key, 0)
    time_since_last = current_time - last_signal_time

    if time_since_last < SIGNAL_COOLDOWN_SECONDS and not bypass_cooldown:
        remaining = SIGNAL_COOLDOWN_SECONDS - time_since_last
        log_to_server(f"[3Commas] {symbol} {final_action} 冷却中，剩余{remaining:.0f}s")
        return "COOLDOWN"

    # v3.670: 乐观锁 — 通过冷却检查后立即写入时间戳，防止同一轮循环多路径重复发送
    if not bypass_cooldown:
        state[last_signal_key] = current_time

    # v21.18: 连续失败熔断 (3次→30min冻结)
    TC_MAX_CONSECUTIVE_FAILS = 3
    TC_FREEZE_SECONDS = 1800
    frozen_until = state.get("tc_frozen_until", 0)
    if current_time < frozen_until:
        remaining_freeze = frozen_until - current_time
        log_to_server(f"[3Commas] {symbol} {final_action} 冻结中(连续失败熔断)，剩余{remaining_freeze:.0f}s")
        return False

    # v21.18: request_id本地去重
    request_id = f"{symbol}_{int(current_time)}_{final_action}"
    if state.get("last_3c_request_id") == request_id:
        log_to_server(f"[3Commas] Duplicate: {request_id}")
        return True

    # ── GCC-0256 S1: Coinbase直连下单 ──────────────────────────────────────
    if COINBASE_DIRECT_MODE:
        try:
            from coinbase_sync_v6 import place_order as _cb_place_order, UNIT_AMOUNTS as _CB_UNIT_AMOUNTS

            # 从coinbase_sync_v6读取标准交易数量，优先于PAIR_CONFIG的unit_size
            _coin_base = symbol.replace("USDC", "") if symbol.endswith("USDC") else symbol
            unit_size = float(_CB_UNIT_AMOUNTS.get(_coin_base, cfg.get("unit_size", 1.0)))
            # 转换品种格式: BTCUSDC → BTC-USDC (仅处理USDC结尾)
            if symbol.endswith("USDC"):
                _coin_product_id = symbol[:-4] + "-USDC"
            else:
                log_to_server(f"[Coinbase直连] {symbol} 品种格式无法转换，跳过")
                return False

            if final_action == "BUY":
                # 零价保护
                if not last_close or last_close <= 0:
                    log_to_server(f"[Coinbase直连] {symbol} BUY 价格异常(last_close={last_close})，跳过")
                    return False
                # 市价买入: quote_size = unit_size * 当前价 (用USDC金额)
                _cb_quote = round(unit_size * last_close, 2)
                log_to_server(
                    f"[Coinbase直连] {symbol} BUY market quote_size={_cb_quote} USDC "
                    f"(unit={unit_size} × price={last_close:.2f})"
                )
                _cb_result = _cb_place_order(
                    product_id=_coin_product_id, side="BUY", quote_size=_cb_quote
                )
            else:
                # 市价卖出: base_size = unit_size (用币数量)
                log_to_server(
                    f"[Coinbase直连] {symbol} SELL market base_size={unit_size}"
                )
                _cb_result = _cb_place_order(
                    product_id=_coin_product_id, side="SELL", base_size=unit_size
                )

            if _cb_result.get("success"):
                state["last_3c_request_id"] = request_id
                state[last_signal_key] = current_time
                state["tc_fail_count"] = 0
                _cb_oid = _cb_result.get("order_id", "")
                log_to_server(
                    f"[Coinbase直连] {symbol} {final_action} 成功 "
                    f"order_id={_cb_oid}"
                )
                return True
            else:
                _cb_err = _cb_result.get("error", "未知错误")
                log_to_server(f"[Coinbase直连] {symbol} {final_action} 失败: {_cb_err}")
                # 继续到失败计数
        except Exception as _cb_e:
            log_to_server(f"[Coinbase直连] {symbol} {final_action} 异常: {_cb_e}")

        # 直连失败: 连续失败计数+熔断
        fail_count = state.get("tc_fail_count", 0) + 1
        state["tc_fail_count"] = fail_count
        if fail_count >= TC_MAX_CONSECUTIVE_FAILS:
            state["tc_frozen_until"] = current_time + TC_FREEZE_SECONDS
            log_to_server(f"[Coinbase直连] {symbol} 连续{fail_count}次失败，冻结{TC_FREEZE_SECONDS//60}分钟")
        else:
            log_to_server(f"[Coinbase直连] {symbol} 失败({fail_count}/{TC_MAX_CONSECUTIVE_FAILS})")
        return False

    # ── 3Commas webhook 模式 (COINBASE_DIRECT_MODE=False 时使用) ───────────
    if final_action == "BUY":
        bot_uuid = cfg.get("long_bot_uuid")
        action = "enter_long"
    else:
        # SELL = 平多仓, long bot + exit_long (实测确认可用)
        bot_uuid = cfg.get("long_bot_uuid")
        action = "exit_long"

    if not bot_uuid:
        log_to_server(f"[3Commas] {symbol} 缺少对应 {final_action} bot_uuid，跳过下单。")
        return False

    payload = {
        "secret": THREECOMMAS_SECRET,
        "max_lag": "300",
        "timestamp": int(time.time()),
        "trigger_price": float(last_close),
        "tv_exchange": cfg.get("exchange", "coinbase"),
        "tv_instrument": symbol,
        "action": action,
        "bot_uuid": bot_uuid,
    }

    # v3.560 P2-4: 3次重试+指数退避
    _safe_payload = {k: v for k, v in payload.items() if k != "secret"}
    log_to_server(f"[3Commas] {symbol} {final_action} sending: {_safe_payload}")
    for attempt in range(3):
        try:
            resp = requests.post(THREECOMMAS_WEBHOOK_URL, json=payload, timeout=5)
            ok_http = 200 <= resp.status_code < 300

            log_to_server(f"[3Commas] {symbol} HTTP status={resp.status_code}")

            ok_logic = True
            resp_body = ""
            try:
                data = resp.json()
                resp_body = str(data)[:300]
                if isinstance(data, dict) and (
                    data.get("error")
                    or str(data.get("status", "")).lower() == "error"
                ):
                    ok_logic = False
            except Exception:
                resp_body = resp.text[:300] if resp.text else "(empty)"
            log_to_server(f"[3Commas] {symbol} {final_action} response: {resp_body}")

            if ok_http and ok_logic:
                state["last_3c_request_id"] = request_id
                state[last_signal_key] = current_time
                state["tc_fail_count"] = 0  # v21.18: 成功→重置
                log_to_server(f"[3Commas] {symbol} {final_action} webhook 成功")
                return True
            log_to_server(f"[3Commas] {symbol} {final_action} webhook ok_http={ok_http}, ok_logic={ok_logic}")

        except Exception as e:
            log_to_server(f"[3Commas] 请求异常(attempt {attempt+1}/3): {e}")

        if attempt < 2:
            time.sleep(1 * (2 ** attempt))

    # v21.18: 连续失败计数+熔断
    fail_count = state.get("tc_fail_count", 0) + 1
    state["tc_fail_count"] = fail_count
    if fail_count >= TC_MAX_CONSECUTIVE_FAILS:
        state["tc_frozen_until"] = current_time + TC_FREEZE_SECONDS
        log_to_server(f"[3Commas] {symbol} 连续{fail_count}次失败，冻结{TC_FREEZE_SECONDS//60}分钟")
    else:
        log_to_server(f"[3Commas] {symbol} 失败({fail_count}/{TC_MAX_CONSECUTIVE_FAILS})")
    return False


