EMAIL_ENABLED = True
EMAIL_SMTP_SERVER = "smtp.gmail.com"
EMAIL_SMTP_PORT = 587
EMAIL_SMTP_TIMEOUT = 30  # v3.002: SMTP 超时时间（秒）
EMAIL_FROM = "aistockllmpro@gmail.com"
EMAIL_PASSWORD = "ficw ovws zvzb qmfs"
EMAIL_TO = ["baodexiang@hotmail.com"]


def send_email_notification(subject: str, body: str, html_body: str = None) -> None:
    """
    发送邮件通知
    v2.982: 支持HTML格式邮件
    v3.002: 添加SMTP超时保护，防止网络问题导致卡死
    """
    if not EMAIL_ENABLED:
        return
    try:
        msg = EmailMessage()
        msg["Subject"] = subject
        msg["From"] = EMAIL_FROM
        msg["To"] = ", ".join(EMAIL_TO)

        if html_body:
            # v2.982: 发送HTML邮件
            msg.set_content(body)  # 纯文本备用
            msg.add_alternative(html_body, subtype='html')
        else:
            msg.set_content(body)

        context = ssl.create_default_context()
        # v3.002: 添加 timeout 参数，防止 SMTP 连接/发送时无限阻塞
        with smtplib.SMTP(EMAIL_SMTP_SERVER, EMAIL_SMTP_PORT, timeout=EMAIL_SMTP_TIMEOUT) as server:
            server.starttls(context=context)
            server.login(EMAIL_FROM, EMAIL_PASSWORD)
            server.send_message(msg)

        print("[EMAIL] 发送成功。")
    except TimeoutError:
        print(f"[EMAIL] 邮件发送超时 ({EMAIL_SMTP_TIMEOUT}秒)")
    except Exception as e:
        print("[EMAIL] 邮件发送失败：", e)


