def format_email_subject_v3510(source: str, symbol: str, action: str, price: float, status: str) -> str:
    """
    v3.510: 统一邮件标题格式

    格式: [{来源}] {品种} {动作} @ {价格} | {状态}
    例: [L1] TSLA BUY @ 250.50 | Executed

    Args:
        source: 触发来源 (L1/L2/P0/Gate等)
        symbol: 交易品种
        action: 交易动作 (BUY/SELL/HOLD)
        price: 当前价格
        status: 执行状态 (Executed/Skipped/Blocked)

    Returns:
        格式化的邮件标题
    """
    return f"[{source}] {symbol} {action} @ {price:.2f} | {status}"


