def send_vision_comparison_email_v3581(
    symbol: str,
    # L1 当前周期
    l1_current_trend: str,
    l1_current_regime: str,
    # L1 x4周期
    l1_big_trend: str,
    # Vision 当前周期
    vision_current_direction: str,
    vision_current_regime: str,
    vision_current_confidence: float,
    # Vision x4周期
    vision_x4_direction: str,
    vision_x4_regime: str,
    vision_x4_confidence: float,
    # 覆盖状态
    override_applied: bool,
    override_from: str = None,
    override_to: str = None,
) -> None:
    """
    v3.581: Vision vs L1 比较结果邮件

    每次TV输入数据时发送，包含：
    1. Vision当前周期 vs L1当前周期 比较
    2. Vision x4周期 vs L1 big_trend 比较
    3. 是否覆盖了L1结论
    4. 是否传递给扫描引擎和L2
    """
    try:
        from datetime import datetime
        import pytz
        ny_tz = pytz.timezone('America/New_York')
        ny_time = datetime.now(ny_tz).strftime("%Y-%m-%d %H:%M:%S")
    except Exception:
        ny_time = "N/A"

    # 当前周期比较
    current_trend_match = (vision_current_direction == l1_current_trend)
    current_regime_match = (vision_current_regime == l1_current_regime)
    current_match = current_trend_match and current_regime_match

    # x4周期比较
    l1_x4_regime = "TRENDING" if l1_big_trend in ["UP", "DOWN"] else "RANGING"
    x4_direction_match = (vision_x4_direction == l1_big_trend)
    x4_regime_match = (vision_x4_regime == l1_x4_regime)
    x4_match = x4_direction_match and x4_regime_match

    # 状态图标
    current_icon = "✅" if current_match else "⚠️"
    x4_icon = "✅" if x4_match else "⚠️"
    override_icon = "🔄" if override_applied else "➖"
    sync_icon = "📡" if override_applied else "➖"

    subject = f"👁️ [Vision] {symbol} {current_icon}当前 {x4_icon}X4 {override_icon}覆盖"

    body = f"""
========================================
👁️ Vision vs L1 比较报告
========================================

时间: {ny_time} (纽约时间)
品种: {symbol}

----------------------------------------
📊 当前周期比较 {current_icon}
----------------------------------------
L1计算:    趋势={l1_current_trend}  状态={l1_current_regime}
Vision:    趋势={vision_current_direction}  状态={vision_current_regime}  置信={vision_current_confidence:.0%}

方向匹配: {"✅ 一致" if current_trend_match else "❌ 不一致"}
状态匹配: {"✅ 一致" if current_regime_match else "❌ 不一致"}

----------------------------------------
📈 X4大周期比较 {x4_icon}
----------------------------------------
L1计算:    趋势={l1_big_trend}  状态={l1_x4_regime}
Vision:    趋势={vision_x4_direction}  状态={vision_x4_regime}  置信={vision_x4_confidence:.0%}

方向匹配: {"✅ 一致" if x4_direction_match else "❌ 不一致"}
状态匹配: {"✅ 一致" if x4_regime_match else "❌ 不一致"}

----------------------------------------
🔄 覆盖状态
----------------------------------------
是否覆盖L1: {"✅ 是" if override_applied else "❌ 否"}
"""

    if override_applied:
        body += f"""覆盖内容: {override_from} → {override_to}
同步扫描引擎: ✅ 已同步
传递给L2: ✅ 已传递
"""
    else:
        body += """覆盖内容: 无 (条件未满足)
同步扫描引擎: ➖ 无需同步
传递给L2: ➖ 使用L1原始结果
"""

    body += f"""
========================================
来源: Vision监控 v3.581
========================================
"""

    send_email_notification(subject, body)
    print(f"[v3.581] {symbol} Vision比较邮件已发送")


