# --- v3.656: HOLD带 唐纳奇中线追踪 ---
def _get_prev_donchian_mid(symbol: str):
    """从global_trend_state读取上次唐纳奇中线"""
    try:
        with _global_trend_lock:
            with open(GLOBAL_TREND_STATE_FILE, "r", encoding="utf-8") as f:
                state = json.load(f)
        return state.get("symbols", {}).get(symbol, {}).get("donchian_mid")
    except Exception:
        return None


def _save_donchian_mid(symbol: str, mid_value: float):
    """保存唐纳奇中线到global_trend_state (线程安全)"""
    with _global_trend_lock:
        try:
            with open(GLOBAL_TREND_STATE_FILE, "r", encoding="utf-8") as f:
                state = json.load(f)
        except Exception:
            state = {"symbols": {}}
        if symbol not in state.get("symbols", {}):
            if "symbols" not in state:
                state["symbols"] = {}
            state["symbols"][symbol] = {}
        state["symbols"][symbol]["donchian_mid"] = mid_value
        state["symbols"][symbol]["hold_band_active"] = _hold_band_active.get(symbol, False)
        try:
            tmp_path = GLOBAL_TREND_STATE_FILE + f".{os.getpid()}.dmid.tmp"
            with open(tmp_path, "w", encoding="utf-8") as f:
                json.dump(state, f, indent=2, ensure_ascii=False)
            os.replace(tmp_path, GLOBAL_TREND_STATE_FILE)
        except Exception as e:
            log_to_server(f"[DONCHIAN_MID][{symbol}] donchian_mid写入失败: {e}")
            try:
                if os.path.exists(tmp_path):
                    os.remove(tmp_path)
            except Exception:
                pass
