# =========================================================
# Markdown 决策快照记录
# =========================================================
def _build_md_snapshot(
    symbol: str,
    timeframe: str,
    now_ny: datetime,
    signal: str,
    level_str: str,
    last_close: float,
    trend_mid: str,
    trend_x4: str,
    trend_x8: str,
    pa_buy_edge: bool,
    pa_sell_edge: bool,
    ai_action: str,
    final_action: str,
    confidence: float,
    bearish_env: bool,
    bearish_gate: bool,
) -> str:
    ts_str = now_ny.strftime("%Y-%m-%d %H:%M:%S %Z")
    lines = [
        f"# {symbol} {timeframe} 决策快照",
        "",
        f"- 时间: **{ts_str}**",
        f"- 版本: **{AIPRO_VERSION}**",
        "",
        "## 价格 & 信号",
        f"- Last close: **{last_close:.4f}**",
        f"- Signal: **{signal} {level_str}**",
        "",
        "## 多周期趋势",
        f"- trend_mid: **{trend_mid}**",
        f"- trend_x4: **{trend_x4}**",
        f"- trend_x8: **{trend_x8}**",
        "",
        "## PA & Bear 环境",
        f"- PA buy_edge: **{pa_buy_edge}**",
        f"- PA sell_edge: **{pa_sell_edge}**",
        f"- bearish_gate: **{bearish_gate}**",
        f"- bearish_env: **{bearish_env}**",
        "",
        "## 决策",
        f"- AI action: **{ai_action}**",
        f"- Final action: **{final_action}**",
        f"- Confidence: **{confidence:.3f}**",
        "",
        "---",
        "",
    ]
    return "\n".join(lines)


def record_decision_snapshot(
    symbol: str,
    timeframe: str,
    now_ny: datetime,
    signal: str,
    level_str: str,
    last_close: float,
    trend_mid: str,
    trend_x4: str,
    trend_x8: str,
    pa_buy_edge: bool,
    pa_sell_edge: bool,
    ai_action: str,
    final_action: str,
    confidence: float,
    bearish_env: bool,
    bearish_gate: bool,
) -> None:
    mark_hour = now_ny.replace(minute=0, second=0, microsecond=0)

    md_text = _build_md_snapshot(
        symbol=symbol,
        timeframe=timeframe,
        now_ny=now_ny,
        signal=signal,
        level_str=level_str,
        last_close=last_close,
        trend_mid=trend_mid,
        trend_x4=trend_x4,
        trend_x8=trend_x8,
        pa_buy_edge=pa_buy_edge,
        pa_sell_edge=pa_sell_edge,
        ai_action=ai_action,
        final_action=final_action,
        confidence=confidence,
        bearish_env=bearish_env,
        bearish_gate=bearish_gate,
    )
    hourly_path = _write_md_file(HOURLY_MD_DIR, md_text, mark_hour, prefix="hourly")
    print(f"[MD] hourly snapshot written: {hourly_path}")

    hour_block = (mark_hour.hour // 8) * 8
    mark_8h = mark_hour.replace(hour=hour_block)
    eight_path = _write_md_file(EIGHT_HOUR_MD_DIR, md_text, mark_8h, prefix="8h")
    print(f"[MD] 8h snapshot written: {eight_path}")

    mark_24h = mark_hour.replace(hour=0)
    daily_path = _write_md_file(DAILY_MD_DIR, md_text, mark_24h, prefix="24h")
    print(f"[MD] 24h snapshot written: {daily_path}")


