# === L2_10M_MICRO_SUPPORT_BEGIN ===
def load_l2_10m_state(path: str = "l2_10m_state.json"):
    """
    读取 10m L2 状态文件（由 tv_l2_10m_server.py 周期写入），返回 dict：
        {
          "BTCUSDT.P": {
            "exec_bias_10m": "STRONG_BUY"|"BUY"|"SELL"|"STRONG_SELL"|"HOLD",
            "micro_reversal_10m": "MICRO_BOTTOM"|"MICRO_TOP"|"NONE",
            ...
          },
          ...
        }
    如果文件不存在或解析失败，返回 {}。
    
    v2.240: 添加详细日志输出，帮助诊断数据丢失问题
    """
    import os
    import json
    import time

    state_path = os.environ.get("L2_10M_STATE_FILE", path)
    abs_path = os.path.abspath(state_path)
    
    # v2.240: 详细日志
    if not os.path.exists(state_path):
        print(f"[L2_10M_LOAD] ✗ 文件不存在: {abs_path}")
        print(f"[L2_10M_LOAD] → 可能需要启动 tv_l2_10m_server.py")
        return {}
    
    try:
        # 获取文件信息
        file_size = os.path.getsize(state_path)
        mtime = os.path.getmtime(state_path)
        age_sec = time.time() - mtime
        age_min = age_sec / 60
        
        with open(state_path, "r", encoding="utf-8") as f:
            data = json.load(f)
        
        if isinstance(data, dict):
            symbol_count = len(data)
            print(f"[L2_10M_LOAD] ✓ 加载成功: {abs_path}")
            print(f"[L2_10M_LOAD]   文件大小: {file_size} bytes")
            print(f"[L2_10M_LOAD]   文件年龄: {age_min:.1f} 分钟")
            print(f"[L2_10M_LOAD]   品种数量: {symbol_count}")
            
            # v2.240: 健康检查
            if age_min > 30:
                print(f"[L2_10M_LOAD] ⚠ 警告: 文件超过30分钟未更新")
                print(f"[L2_10M_LOAD]   可能 10m 服务未正常运行")
            
            return data
        else:
            print(f"[L2_10M_LOAD] ✗ 数据格式错误: 不是dict类型")
            return {}
            
    except json.JSONDecodeError as e:
        print(f"[L2_10M_LOAD] ✗ JSON解析失败: {e}")
        print(f"[L2_10M_LOAD]   文件: {abs_path}")
        return {}
    except Exception as e:
        print(f"[L2_10M_LOAD] ✗ 读取失败: {e}")
        print(f"[L2_10M_LOAD]   文件: {abs_path}")
        return {}
    
    return {}


def get_l2_10m_for_symbol(symbol: str, state_path: str = "l2_10m_state.json"):
    """
    根据 symbol 从 10m 状态中取出该品种的 L2 记录。
    做一点简单的符号兼容（例如 ".P" / 无后缀），取到则返回 dict，否则返回 None。
    """
    state = load_l2_10m_state(path=state_path)
    if not state:
        return None

    # 1. 直接匹配
    if symbol in state:
        return state[symbol]

    # 2. 去掉 ".P" / ".p" 再匹配
    if symbol.endswith(".P") or symbol.endswith(".p"):
        base = symbol[:-2]
        if base in state:
            return state[base]

    # 3. 反向：主程序用无后缀，L2 用带 ".P"
    alt = symbol + ".P"
    if alt in state:
        return state[alt]

    return None


def apply_l2_10m_bias(
    symbol: str,
    final_action: str,
    decision_log: dict,
    state_path: str = "l2_10m_state.json",
):
    """
    10m 小周期 gate：只做“刹车”，不做“油门”。

    - 不会把 HOLD 升级为 BUY/SELL；
    - 只会在 10m 明确顶/底或 exec_bias_10m 和主决策严重冲突时，
      把 BUY/SELL 降级为 HOLD。

    返回：(new_action, new_decision_log)
    """
    micro = get_l2_10m_for_symbol(symbol, state_path=state_path)

    # 在决策里记录原始 10m L2 信息，方便排查
    decision_log = dict(decision_log or {})
    decision_log["l2_10m_raw"] = micro or {}

    if micro is None:
        decision_log["l2_10m_gate"] = {
            "applied": False,
            "blocked": False,
            "original_action": final_action,
            "new_action": final_action,
            "reason": "no_l2_10m_data",
        }
        return final_action, decision_log

    exec_bias = micro.get("exec_bias_10m", "HOLD")
    micro_reversal = micro.get("micro_reversal_10m", "NONE")

    action_is_buy = final_action in ("BUY", "BUY_ENTRY", "BUY_MORE", "OPEN_LONG")
    action_is_sell = final_action in ("SELL", "SELL_ENTRY", "SELL_MORE", "OPEN_SHORT")

    new_action = final_action
    blocked = False
    reasons = []

    # 1）10m 明确看空，而主决策想买 -> 刹车
    if action_is_buy and exec_bias in ("STRONG_SELL", "SELL"):
        new_action = "HOLD"
        blocked = True
        reasons.append("10m_exec_bias_conflicts_buy")

    # 2）10m 明确看多，而主决策想卖 -> 刹车
    if action_is_sell and exec_bias in ("STRONG_BUY", "BUY"):
        new_action = "HOLD"
        blocked = True
        reasons.append("10m_exec_bias_conflicts_sell")

    # 3）微顶/微底额外刹车
    if action_is_buy and micro_reversal == "MICRO_TOP":
        new_action = "HOLD"
        blocked = True
        reasons.append("10m_micro_top_vs_buy")

    if action_is_sell and micro_reversal == "MICRO_BOTTOM":
        new_action = "HOLD"
        blocked = True
        reasons.append("10m_micro_bottom_vs_sell")

    if not reasons:
        reasons.append("10m_exec_bias_aligned_or_neutral")

    decision_log["l2_10m_gate"] = {
        "applied": True,
        "blocked": blocked,
        "original_action": final_action,
        "new_action": new_action,
        "exec_bias_10m": exec_bias,
        "micro_reversal_10m": micro_reversal,
        "reasons": reasons,
    }

    return new_action, decision_log
# === L2_10M_MICRO_SUPPORT_END ===


# /llm_decide — v1.96 主逻辑（日志与可观测性增强版）
