EXEC_BIAS_STRONG_BUY = "STRONG_BUY"
EXEC_BIAS_BUY = "BUY"
EXEC_BIAS_STRONG_SELL = "STRONG_SELL"
EXEC_BIAS_SELL = "SELL"
EXEC_BIAS_HOLD = "HOLD"


def infer_sr_zone_from_level(
    pos_zone: str,
    signal: str,
    level_str: str,
) -> str:
    """
    尽量用已有信息推一个 sr_zone（LOWER/MID/UPPER）。
    1.98 以后如果 TradingView 直接传 sr_zone，就可以完全忽略这里。
    """
    s = (signal or "").lower()
    lv = (level_str or "").lower()
    pz = (pos_zone or "").upper()

    # 先看 level 字符串
    if any(k in lv for k in ["upper", "up", "high", "top"]):
        return "UPPER"
    if any(k in lv for k in ["lower", "down", "low", "bottom"]):
        return "LOWER"

    # 再看 signal 类型
    if "breakout" in s or "cross_over" in s:
        return "UPPER"
    if "breakdown" in s or "cross_under" in s:
        return "LOWER"

    # 再退回 pos_zone
    if pz in ["EXTREME_HIGH", "HIGH"]:
        return "UPPER"
    if pz in ["EXTREME_LOW", "LOW"]:
        return "LOWER"

    return "MID"


def normalize_l2_tag(tag: str, default: str = "NONE") -> str:
    if not tag:
        return default
    return str(tag).upper()


def cjk_width(text: str) -> int:
    """计算字符串的显示宽度（中文=2，英文=1）"""
    width = 0
    for char in str(text):
        if '\u4e00' <= char <= '\u9fff' or '\u3000' <= char <= '\u303f' or '\uff00' <= char <= '\uffef':
            width += 2  # 中文和全角字符
        else:
            width += 1
    return width


def cjk_ljust(text: str, width: int, fillchar: str = ' ') -> str:
    """中英文混合左对齐"""
    text = str(text)
    current_width = cjk_width(text)
    if current_width >= width:
        return text
    return text + fillchar * (width - current_width)


def cjk_rjust(text: str, width: int, fillchar: str = ' ') -> str:
    """中英文混合右对齐"""
    text = str(text)
    current_width = cjk_width(text)
    if current_width >= width:
        return text
    return fillchar * (width - current_width) + text


def compute_exec_bias(
    sr_zone: str,
    pa_tag: str,
    two_b_tag: str,
    volume_state: str,
    trend_state: str,
    bearish_env: bool,
) -> str:
    """
    L2 不打分，只用离散规则：
    - sr_zone: LOWER / MID / UPPER（支撑 / 中线 / 压力）
    - pa_tag: 包含 BULL / BEAR / BUY / SELL / NONE
    - two_b_tag: BULL_2B / BEAR_2B / NONE
    - volume_state: RISING / CLIMAX / NORMAL / FALLING
    - trend_state: STRONG_UP / UP / SIDE / DOWN / STRONG_DOWN
    - bearish_env: 整体熊市环境时偏空
    """

    sz = (sr_zone or "MID").upper()
    pa = normalize_l2_tag(pa_tag, "NONE")
    tb = normalize_l2_tag(two_b_tag, "NONE")
    vol = normalize_l2_tag(volume_state, "NORMAL")
    ts = normalize_l2_tag(trend_state, "SIDE")

    is_bull = ("BULL" in pa) or ("BUY" in pa) or ("BULL" in tb)
    is_bear = ("BEAR" in pa) or ("SELL" in pa) or ("BEAR" in tb)

    # 没有任何明显多/空信号：强制 HOLD
    if not is_bull and not is_bear:
        return EXEC_BIAS_HOLD

    # ===== 多头逻辑 =====
    if is_bull and not is_bear:
        # 下半区/中区 + 放量 + 上升趋势 + 非熊市环境 → 强烈买
        if sz in ["LOWER", "MID"] and vol in ["RISING", "CLIMAX"] and ts in ["UP", "STRONG_UP"] and not bearish_env:
            return EXEC_BIAS_STRONG_BUY

        # 下半区/中区 + 非熊市 → 允许买（BUY）
        if sz in ["LOWER", "MID"] and not bearish_env:
            return EXEC_BIAS_BUY

        # 其他情况（高位追多 / 熊市高位） → 强制 HOLD
        return EXEC_BIAS_HOLD

    # ===== 空头逻辑 =====
    if is_bear and not is_bull:
        # 上半区/中区 + 放量 + 下跌趋势 or 熊市 → 强烈卖
        if sz in ["UPPER", "MID"] and vol in ["RISING", "CLIMAX"] and (ts in ["DOWN", "STRONG_DOWN"] or bearish_env):
            return EXEC_BIAS_STRONG_SELL

        # 上半区/中区 → 允许卖（SELL）
        if sz in ["UPPER", "MID"]:
            return EXEC_BIAS_SELL

        # 低位砸盘 → 强制 HOLD
        return EXEC_BIAS_HOLD

    # 多空信号混杂 → 宁可不做
    return EXEC_BIAS_HOLD







# ===== PATCH: L2_LOCAL_EXEC_BIAS_PATCH =====


