# ==================== P0增强函数 (开始) - 简化版 ====================

def detect_volume_price_divergence_p0(prices, volumes, window=5):
    """
    检测量价背离 (P0增强简化版)
    返回: "BEARISH_DIV" | "BULLISH_DIV" | "NONE"

    只需要 close_prices + volumes，TV现有数据即可
    """
    if not prices or not volumes or len(prices) < window or len(volumes) < window:
        return "NONE"
    
    try:
        p = prices[-window:]
        v = volumes[-window:]
        
        price_change = (p[-1] - p[0]) / max(p[0], 1e-9)
        vol_avg = sum(v) / len(v)
        vol_change = (v[-1] - v[0]) / max(vol_avg, 1e-9)
        
        if price_change > 0.02 and vol_change < -0.2:
            return "BEARISH_DIV"
        elif price_change < -0.02 and vol_change > 0.2:
            return "BULLISH_DIV"
        
        return "NONE"
    
    except Exception as e:
        print(f"[WARN] detect_volume_price_divergence_p0 failed: {e}")
        return "NONE"


def compute_n_swing_time_weight(bars_needed):
    """
    根据触发阈值所需的时间计算权重
    返回: float (0.5 ~ 2.0)
    
    纯计算逻辑，不需要额外数据
    """
    if bars_needed <= 0:
        return 1.0
    
    if bars_needed <= 3:
        return 2.0
    elif bars_needed <= 5:
        return 1.5
    elif bars_needed <= 8:
        return 1.0
    else:
        return 0.5

