# ===== L2 OHLCV 全面升级 v1.0 =====

# v2.730: 阈值常量已移至文件开头 L2Config
# VOL_LOW_THRESHOLD → L2Config.VOL_LOW_THRESHOLD
# VOL_HIGH_THRESHOLD → L2Config.VOL_HIGH_THRESHOLD
# BODY_RATIO_STRONG → L2Config.BODY_RATIO_STRONG
# RANGE_RATIO_BIG → L2Config.RANGE_RATIO_BIG
# WICK_RATIO_SMALL → L2Config.WICK_RATIO_SMALL
# ENGULF_MIN_RATIO → L2Config.ENGULF_MIN_RATIO


def compute_candle_features(ohlcv_bars, n_sma=20):
    """
    K线特征工程
    
    Args:
        ohlcv_bars: list of dict {'open','high','low','close','volume'}
        n_sma: 均值窗口
    
    Returns:
        list of candle_feat dict
    """
    if not ohlcv_bars or len(ohlcv_bars) < 2:
        return []
    
    features = []
    
    # 计算移动均值用于相对分析
    ranges = []
    bodies = []
    
    for bar in ohlcv_bars:
        try:
            o, h, l, c = float(bar['open']), float(bar['high']), float(bar['low']), float(bar['close'])
            rng = max(h - l, 1e-8)
            body = abs(c - o)
            ranges.append(rng)
            bodies.append(body)
        except Exception:
            ranges.append(1.0)
            bodies.append(0.5)
    
    # 计算每根K的特征
    for i, bar in enumerate(ohlcv_bars):
        try:
            o = float(bar['open'])
            h = float(bar['high'])
            l = float(bar['low'])
            c = float(bar['close'])
            v = float(bar.get('volume', 1000))
        except Exception:
            features.append({
                'valid': False,
                'body_ratio': 0.5,
                'range_ratio': 1.0,
                'wick_ratio': 0.3,
                'direction': 'NEUTRAL',
            })
            continue
        
        # 基础计算
        rng = max(h - l, 1e-8)
        body = abs(c - o)
        upper_wick = h - max(o, c)
        lower_wick = min(o, c) - l
        
        body_ratio = body / rng
        wick_ratio = max(upper_wick, lower_wick) / rng
        
        # 方向
        if c > o * 1.001:
            direction = "BULL"
        elif c < o * 0.999:
            direction = "BEAR"
        else:
            direction = "NEUTRAL"
        
        # 相对指标
        start_idx = max(0, i - n_sma + 1)
        avg_rng = sum(ranges[start_idx:i+1]) / max(len(ranges[start_idx:i+1]), 1)
        avg_body = sum(bodies[start_idx:i+1]) / max(len(bodies[start_idx:i+1]), 1)
        
        range_ratio = rng / max(avg_rng, 1e-8)
        body_strength = body / max(avg_body, 1e-8)
        
        features.append({
            'valid': True,
            'body': body,
            'range': rng,
            'upper_wick': upper_wick,
            'lower_wick': lower_wick,
            'body_ratio': body_ratio,
            'wick_ratio': wick_ratio,
            'direction': direction,
            'range_ratio': range_ratio,
            'body_strength': body_strength,
            'close': c,
            'open': o,
            'high': h,
            'low': l,
            'volume': v,
        })
    
    return features


def compute_volume_state(volumes, n_sma=20):
    """
    成交量分层
    
    Returns:
        (vol_ratio, volume_state)
        volume_state ∈ {LOW, NORMAL, HIGH}
    """
    if not volumes or len(volumes) < 2:
        return 1.0, "NORMAL"
    
    try:
        vols = [float(v) for v in volumes]
        v_last = vols[-1]
        
        start_idx = max(0, len(vols) - n_sma)
        avg_vol = sum(vols[start_idx:]) / max(len(vols[start_idx:]), 1)
        
        vol_ratio = v_last / max(avg_vol, 1e-8)
        
        if vol_ratio < VOL_LOW_THRESHOLD:
            return vol_ratio, "LOW"
        elif vol_ratio > VOL_HIGH_THRESHOLD:
            return vol_ratio, "HIGH"
        else:
            return vol_ratio, "NORMAL"
    except Exception:
        return 1.0, "NORMAL"


def detect_pa_advanced(candle_feats):
    """
    高级PA识别 (基于OHLCV特征)
    
    Returns:
        pa_tag ∈ {STRONG_BUY, BUY, NONE, SELL, STRONG_SELL}
    """
    if not candle_feats or len(candle_feats) < 2:
        return "NONE"
    
    last = candle_feats[-1]
    if not last.get('valid'):
        return "NONE"
    
    prev = candle_feats[-2] if len(candle_feats) >= 2 else None
    
    # 1. 强趋势K
    is_strong_trend = (
        last['body_ratio'] > BODY_RATIO_STRONG
        and last['range_ratio'] > RANGE_RATIO_BIG
        and last['wick_ratio'] < WICK_RATIO_SMALL
    )
    
    if is_strong_trend:
        if last['direction'] == "BULL":
            return "STRONG_BUY"
        elif last['direction'] == "BEAR":
            return "STRONG_SELL"
    
    # 2. Pin/Hammer (长下影+收上半区)
    if last['lower_wick'] > last['range'] * 0.5:
        close_position = (last['close'] - last['low']) / max(last['range'], 1e-8)
        if close_position > 0.6:  # 收在上60%
            return "BUY"
    
    # 3. Shooting Star (长上影+收下半区)
    if last['upper_wick'] > last['range'] * 0.5:
        close_position = (last['close'] - last['low']) / max(last['range'], 1e-8)
        if close_position < 0.4:  # 收在下40%
            return "SELL"
    
    # 4. Engulfing (吞没)
    if prev and prev.get('valid'):
        # Bullish Engulfing
        if (last['direction'] == "BULL" and prev['direction'] == "BEAR" and
            last['body'] > prev['body'] * ENGULF_MIN_RATIO and
            last['close'] > prev['open'] and last['open'] < prev['close']):
            return "STRONG_BUY"
        
        # Bearish Engulfing
        if (last['direction'] == "BEAR" and prev['direction'] == "BULL" and
            last['body'] > prev['body'] * ENGULF_MIN_RATIO and
            last['close'] < prev['open'] and last['open'] > prev['close']):
            return "STRONG_SELL"
    
    # 5. 普通多空K
    if last['body_ratio'] > 0.5:
        if last['direction'] == "BULL":
            return "BUY"
        elif last['direction'] == "BEAR":
            return "SELL"
    
    return "NONE"


def detect_2b_advanced(candle_feats, m_swing=10):
    """
    2B假突破检测 (使用真实high/low)
    
    Returns:
        two_b_tag ∈ {TOP, BOTTOM, NONE}
    """
    if not candle_feats or len(candle_feats) < m_swing:
        return "NONE"
    
    last = candle_feats[-1]
    if not last.get('valid'):
        return "NONE"
    
    try:
        # 计算swing high/low
        recent_highs = [f['high'] for f in candle_feats[-m_swing:-1] if f.get('valid')]
        recent_lows = [f['low'] for f in candle_feats[-m_swing:-1] if f.get('valid')]
        
        if not recent_highs or not recent_lows:
            return "NONE"
        
        swing_high = max(recent_highs)
        swing_low = min(recent_lows)
        
        # TOP 2B: high突破但close回落
        if last['high'] > swing_high * 1.001 and last['close'] < swing_high:
            return "TOP"
        
        # BOTTOM 2B: low跌破但close收回
        if last['low'] < swing_low * 0.999 and last['close'] > swing_low:
            return "BOTTOM"
        
        return "NONE"
    except Exception:
        return "NONE"


# =============================================================================
# v3.290: 13买卖点L2增强函数
# =============================================================================

def detect_2b_strict(candle_feats, volumes=None, m_swing=10):
    """
    v3.290: 严格版2B检测 (对标云聪13买卖点-买点1)

    增强条件:
    1. 前5根K线需为连续下跌/上涨趋势（简化五浪）
    2. 拉回K线必须是大阳线/大阴线（body比例>50%）
    3. 不能是十字星（body<15%的排除）
    4. 可选：放量确认（>1.2倍均量）

    Returns:
        dict: {
            "tag": "TOP" | "BOTTOM" | "NONE",
            "strict": bool,  # 是否满足严格条件
            "confidence": float,  # 0-1
            "reasons": list[str]
        }
    """
    result = {"tag": "NONE", "strict": False, "confidence": 0, "reasons": []}

    if not candle_feats or len(candle_feats) < m_swing + 5:
        result["reasons"].append("insufficient_data")
        return result

    last = candle_feats[-1]
    if not last.get('valid'):
        result["reasons"].append("invalid_last_bar")
        return result

    try:
        # 计算swing high/low
        recent_highs = [f['high'] for f in candle_feats[-m_swing:-1] if f.get('valid')]
        recent_lows = [f['low'] for f in candle_feats[-m_swing:-1] if f.get('valid')]

        if not recent_highs or not recent_lows:
            result["reasons"].append("no_swing_data")
            return result

        swing_high = max(recent_highs)
        swing_low = min(recent_lows)

        # 计算当前K线body比例
        bar_range = last['high'] - last['low']
        body = abs(last['close'] - last['open'])
        body_ratio = body / bar_range if bar_range > 0 else 0
        is_bullish = last['close'] > last['open']
        is_bearish = last['close'] < last['open']

        # 检查是否十字星（body<15%）
        is_doji = body_ratio < 0.15

        # 检查是否大K线（body>50%）
        is_big_bar = body_ratio > 0.50

        # 检查前5根K线趋势
        prev_5 = candle_feats[-6:-1]
        down_count = sum(1 for i in range(1, len(prev_5))
                        if prev_5[i].get('close', 0) < prev_5[i-1].get('close', 0))
        up_count = sum(1 for i in range(1, len(prev_5))
                      if prev_5[i].get('close', 0) > prev_5[i-1].get('close', 0))

        # 计算成交量倍数（如果提供）
        vol_ratio = 1.0
        if volumes and len(volumes) >= m_swing:
            avg_vol = sum(volumes[-m_swing:-1]) / (m_swing - 1) if m_swing > 1 else 1
            last_vol = volumes[-1] if volumes[-1] else avg_vol
            vol_ratio = last_vol / avg_vol if avg_vol > 0 else 1.0

        # ========== BOTTOM 2B检测 ==========
        # 条件：跌破前低后大阳线立即收回
        if last['low'] < swing_low * 0.999 and last['close'] > swing_low:
            result["tag"] = "BOTTOM"
            confidence = 0.5

            # 严格条件1：前5根需为下跌趋势（至少3根下跌）
            if down_count >= 3:
                confidence += 0.15
                result["reasons"].append(f"downtrend_before({down_count}/4)")

            # 严格条件2：必须是大阳线
            if is_bullish and is_big_bar:
                confidence += 0.20
                result["reasons"].append(f"big_bullish_bar(body={body_ratio:.0%})")
            elif is_doji:
                confidence -= 0.20
                result["reasons"].append("rejected:doji_no_conviction")

            # 严格条件3：放量确认
            if vol_ratio > 1.2:
                confidence += 0.10
                result["reasons"].append(f"volume_surge({vol_ratio:.1f}x)")

            # 判断是否满足严格条件
            result["strict"] = (down_count >= 3 and is_bullish and is_big_bar and not is_doji)
            result["confidence"] = min(0.95, max(0.1, confidence))
            return result

        # ========== TOP 2B检测 ==========
        # 条件：突破前高后大阴线立即收回
        if last['high'] > swing_high * 1.001 and last['close'] < swing_high:
            result["tag"] = "TOP"
            confidence = 0.5

            # 严格条件1：前5根需为上涨趋势（至少3根上涨）
            if up_count >= 3:
                confidence += 0.15
                result["reasons"].append(f"uptrend_before({up_count}/4)")

            # 严格条件2：必须是大阴线
            if is_bearish and is_big_bar:
                confidence += 0.20
                result["reasons"].append(f"big_bearish_bar(body={body_ratio:.0%})")
            elif is_doji:
                confidence -= 0.20
                result["reasons"].append("rejected:doji_no_conviction")

            # 严格条件3：放量确认
            if vol_ratio > 1.2:
                confidence += 0.10
                result["reasons"].append(f"volume_surge({vol_ratio:.1f}x)")

            # 判断是否满足严格条件
            result["strict"] = (up_count >= 3 and is_bearish and is_big_bar and not is_doji)
            result["confidence"] = min(0.95, max(0.1, confidence))
            return result

        return result
    except Exception as e:
        result["reasons"].append(f"error:{str(e)}")
        return result


def detect_secondary_test(candle_feats, support_level, resistance_level=None, volumes=None):
    """
    v3.290: 二次测试检测 (对标云聪13买卖点-买点3)

    增强条件:
    1. 价格在支撑位±1.5%范围内
    2. 出现明确看涨K线（HAMMER/ENGULF/长下影线）
    3. 不破前低（形成次低点）

    Returns:
        dict: {
            "signal": "BULLISH_RETEST" | "BEARISH_RETEST" | "NONE",
            "at_support": bool,
            "at_resistance": bool,
            "pa_signal": str,  # 触发的PA信号
            "confidence": float,
            "reasons": list[str]
        }
    """
    result = {
        "signal": "NONE",
        "at_support": False,
        "at_resistance": False,
        "pa_signal": "NONE",
        "confidence": 0,
        "reasons": []
    }

    if not candle_feats or len(candle_feats) < 10:
        result["reasons"].append("insufficient_data")
        return result

    if support_level is None or support_level <= 0:
        result["reasons"].append("no_support_level")
        return result

    last = candle_feats[-1]
    prev = candle_feats[-2] if len(candle_feats) >= 2 else None

    if not last.get('valid'):
        result["reasons"].append("invalid_last_bar")
        return result

    try:
        current_low = last['low']
        current_close = last['close']
        current_high = last['high']
        current_open = last['open']

        # 计算K线特征
        bar_range = current_high - current_low
        body = abs(current_close - current_open)
        body_ratio = body / bar_range if bar_range > 0 else 0
        lower_wick = min(current_open, current_close) - current_low
        upper_wick = current_high - max(current_open, current_close)
        lower_wick_ratio = lower_wick / bar_range if bar_range > 0 else 0
        is_bullish = current_close > current_open

        # ========== 支撑位测试检测 ==========
        # 检查是否在支撑位±1.5%范围内
        support_zone_upper = support_level * 1.015
        support_zone_lower = support_level * 0.985

        at_support = support_zone_lower <= current_low <= support_zone_upper

        if at_support:
            result["at_support"] = True
            confidence = 0.4

            # 检查是否形成次低点（不破前低）
            recent_lows = [f['low'] for f in candle_feats[-10:-1] if f.get('valid')]
            prev_swing_low = min(recent_lows) if recent_lows else support_level

            if current_low > prev_swing_low * 0.998:  # 允许0.2%容差
                confidence += 0.15
                result["reasons"].append("higher_low_formed")

            # 检测PA信号类型
            pa_detected = False

            # 1. 锤子线检测（下影线长，实体小且在上部）
            if lower_wick_ratio > 0.5 and body_ratio < 0.4:
                result["pa_signal"] = "HAMMER"
                pa_detected = True
                confidence += 0.25
                result["reasons"].append(f"hammer(lower_wick={lower_wick_ratio:.0%})")

            # 2. 看涨吞没检测
            elif prev and is_bullish:
                prev_body = abs(prev['close'] - prev['open'])
                if body > prev_body * 1.2 and current_close > prev['open'] and current_open < prev['close']:
                    result["pa_signal"] = "BULLISH_ENGULF"
                    pa_detected = True
                    confidence += 0.25
                    result["reasons"].append("bullish_engulf")

            # 3. 长下影线（不是锤子但下影线明显）
            elif lower_wick_ratio > 0.35 and is_bullish:
                result["pa_signal"] = "LONG_LOWER_WICK"
                pa_detected = True
                confidence += 0.15
                result["reasons"].append(f"long_lower_wick({lower_wick_ratio:.0%})")

            # 4. 大阳线反弹
            elif is_bullish and body_ratio > 0.6:
                result["pa_signal"] = "BIG_BULLISH"
                pa_detected = True
                confidence += 0.20
                result["reasons"].append(f"big_bullish(body={body_ratio:.0%})")

            if pa_detected:
                result["signal"] = "BULLISH_RETEST"
                result["confidence"] = min(0.95, confidence)
                result["reasons"].append(f"at_support({current_low:.4f}~{support_level:.4f})")
            else:
                result["reasons"].append("at_support_but_no_pa_signal")

        # ========== 阻力位测试检测 ==========
        if resistance_level and resistance_level > 0:
            resistance_zone_lower = resistance_level * 0.985
            resistance_zone_upper = resistance_level * 1.015

            at_resistance = resistance_zone_lower <= current_high <= resistance_zone_upper

            if at_resistance:
                result["at_resistance"] = True
                confidence = 0.4

                # 检查是否形成次高点
                recent_highs = [f['high'] for f in candle_feats[-10:-1] if f.get('valid')]
                prev_swing_high = max(recent_highs) if recent_highs else resistance_level

                if current_high < prev_swing_high * 1.002:
                    confidence += 0.15
                    result["reasons"].append("lower_high_formed")

                # 检测看跌PA信号
                pa_detected = False
                upper_wick_ratio = upper_wick / bar_range if bar_range > 0 else 0
                is_bearish = current_close < current_open

                # 1. 射击之星
                if upper_wick_ratio > 0.5 and body_ratio < 0.4:
                    result["pa_signal"] = "SHOOTING_STAR"
                    pa_detected = True
                    confidence += 0.25
                    result["reasons"].append(f"shooting_star(upper_wick={upper_wick_ratio:.0%})")

                # 2. 看跌吞没
                elif prev and is_bearish:
                    prev_body = abs(prev['close'] - prev['open'])
                    if body > prev_body * 1.2 and current_close < prev['open'] and current_open > prev['close']:
                        result["pa_signal"] = "BEARISH_ENGULF"
                        pa_detected = True
                        confidence += 0.25
                        result["reasons"].append("bearish_engulf")

                # 3. 大阴线
                elif is_bearish and body_ratio > 0.6:
                    result["pa_signal"] = "BIG_BEARISH"
                    pa_detected = True
                    confidence += 0.20
                    result["reasons"].append(f"big_bearish(body={body_ratio:.0%})")

                if pa_detected:
                    result["signal"] = "BEARISH_RETEST"
                    result["confidence"] = min(0.95, confidence)
                    result["reasons"].append(f"at_resistance({current_high:.4f}~{resistance_level:.4f})")

        return result
    except Exception as e:
        result["reasons"].append(f"error:{str(e)}")
        return result


def detect_sos_strict(candle_feats, volumes, lookback=20):
    """
    v3.290: 严格版SOS强势出现检测 (对标云聪13买卖点-买点4)

    增强条件:
    1. 计算形态中轴（近期高低点均值）
    2. 当前K线需在中轴以上（SOS）或以下（SOW）
    3. 放量确认（>1.5倍均量）
    4. 大阳线/大阴线（body>50%）

    Returns:
        dict: {
            "signal": "SOS" | "SOW" | "NONE",  # Sign of Strength / Sign of Weakness
            "above_mid": bool,  # 是否在中轴以上
            "volume_surge": bool,  # 是否放量
            "big_bar": bool,  # 是否大K线
            "confidence": float,
            "mid_level": float,  # 形态中轴价格
            "reasons": list[str]
        }
    """
    result = {
        "signal": "NONE",
        "above_mid": False,
        "volume_surge": False,
        "big_bar": False,
        "confidence": 0,
        "mid_level": 0,
        "reasons": []
    }

    if not candle_feats or len(candle_feats) < lookback:
        result["reasons"].append("insufficient_candle_data")
        return result

    if not volumes or len(volumes) < lookback:
        result["reasons"].append("insufficient_volume_data")
        return result

    last = candle_feats[-1]
    if not last.get('valid'):
        result["reasons"].append("invalid_last_bar")
        return result

    try:
        # 计算形态边界（近期高低点）
        recent_bars = candle_feats[-lookback:-1]
        recent_highs = [f['high'] for f in recent_bars if f.get('valid')]
        recent_lows = [f['low'] for f in recent_bars if f.get('valid')]

        if not recent_highs or not recent_lows:
            result["reasons"].append("no_range_data")
            return result

        box_high = max(recent_highs)
        box_low = min(recent_lows)
        mid_level = (box_high + box_low) / 2
        result["mid_level"] = mid_level

        # 计算当前K线特征
        current_close = last['close']
        current_open = last['open']
        current_high = last['high']
        current_low = last['low']

        bar_range = current_high - current_low
        body = abs(current_close - current_open)
        body_ratio = body / bar_range if bar_range > 0 else 0
        is_bullish = current_close > current_open
        is_bearish = current_close < current_open

        # 检查是否大K线（body>50%）
        is_big_bar = body_ratio > 0.50
        result["big_bar"] = is_big_bar

        # 计算成交量比率
        avg_vol = sum(volumes[-lookback:-1]) / (lookback - 1) if lookback > 1 else 1
        last_vol = volumes[-1] if volumes[-1] else avg_vol
        vol_ratio = last_vol / avg_vol if avg_vol > 0 else 1.0

        # 检查是否放量（>1.5倍）
        is_volume_surge = vol_ratio > 1.5
        result["volume_surge"] = is_volume_surge

        # 检查位置（相对于中轴）
        above_mid = current_close > mid_level
        below_mid = current_close < mid_level
        result["above_mid"] = above_mid

        # ========== SOS检测（强势出现） ==========
        # 条件：中轴以上 + 放量 + 大阳线
        if above_mid and is_bullish:
            confidence = 0.3
            result["reasons"].append(f"close_above_mid({current_close:.4f}>{mid_level:.4f})")

            if is_big_bar:
                confidence += 0.25
                result["reasons"].append(f"big_bullish_bar(body={body_ratio:.0%})")

            if is_volume_surge:
                confidence += 0.25
                result["reasons"].append(f"volume_surge({vol_ratio:.1f}x)")

            # 额外确认：突破箱体上沿
            if current_close > box_high * 0.995:
                confidence += 0.15
                result["reasons"].append("near_box_breakout")

            # 判断信号强度
            if is_big_bar and is_volume_surge:
                result["signal"] = "SOS"
                result["confidence"] = min(0.95, confidence)
            elif is_big_bar or is_volume_surge:
                result["signal"] = "SOS"
                result["confidence"] = min(0.70, confidence)
                result["reasons"].append("partial_confirmation")

        # ========== SOW检测（弱势出现） ==========
        # 条件：中轴以下 + 放量 + 大阴线
        if below_mid and is_bearish:
            confidence = 0.3
            result["reasons"].append(f"close_below_mid({current_close:.4f}<{mid_level:.4f})")

            if is_big_bar:
                confidence += 0.25
                result["reasons"].append(f"big_bearish_bar(body={body_ratio:.0%})")

            if is_volume_surge:
                confidence += 0.25
                result["reasons"].append(f"volume_surge({vol_ratio:.1f}x)")

            # 额外确认：跌破箱体下沿
            if current_close < box_low * 1.005:
                confidence += 0.15
                result["reasons"].append("near_box_breakdown")

            # 判断信号强度
            if is_big_bar and is_volume_surge:
                result["signal"] = "SOW"
                result["confidence"] = min(0.95, confidence)
            elif is_big_bar or is_volume_surge:
                result["signal"] = "SOW"
                result["confidence"] = min(0.70, confidence)
                result["reasons"].append("partial_confirmation")

        return result
    except Exception as e:
        result["reasons"].append(f"error:{str(e)}")
        return result


def detect_123_with_volume(candle_feats, volumes, m_swing=15):
    """
    v3.290: 带放量确认的123检测 (对标云聪13买卖点-买点10)

    增强条件:
    1. 保留现有Higher lows/Lower highs逻辑
    2. 突破K线需放量（>1.3倍均量）
    3. 返回更详细的结构信息

    Returns:
        dict: {
            "tag": "BULL_123" | "BEAR_123" | "NONE",
            "volume_confirmed": bool,  # 是否放量确认
            "structure_quality": str,  # "STRONG" | "WEAK" | "NONE"
            "pivot_count": int,  # 有效pivot数量
            "confidence": float,
            "reasons": list[str]
        }
    """
    result = {
        "tag": "NONE",
        "volume_confirmed": False,
        "structure_quality": "NONE",
        "pivot_count": 0,
        "confidence": 0,
        "reasons": []
    }

    if not candle_feats or len(candle_feats) < m_swing:
        result["reasons"].append("insufficient_candle_data")
        return result

    try:
        # 提取数据
        lows = [f['low'] for f in candle_feats[-m_swing:] if f.get('valid')]
        highs = [f['high'] for f in candle_feats[-m_swing:] if f.get('valid')]

        if len(lows) < 10 or len(highs) < 10:
            result["reasons"].append("insufficient_price_data")
            return result

        last_close = candle_feats[-1]['close']

        # 计算成交量比率
        vol_ratio = 1.0
        if volumes and len(volumes) >= m_swing:
            avg_vol = sum(volumes[-m_swing:-1]) / (m_swing - 1) if m_swing > 1 else 1
            last_vol = volumes[-1] if volumes[-1] else avg_vol
            vol_ratio = last_vol / avg_vol if avg_vol > 0 else 1.0

        is_volume_confirmed = vol_ratio > 1.3
        result["volume_confirmed"] = is_volume_confirmed

        # ========== BULL_123检测 ==========
        # 分段计算低点
        segment_size = len(lows) // 3
        if segment_size >= 2:
            low_1 = min(lows[:segment_size])
            low_2 = min(lows[segment_size:segment_size*2])
            low_3 = min(lows[segment_size*2:])

            # Higher lows判断
            if low_3 > low_2 > low_1:
                result["reasons"].append(f"higher_lows({low_1:.4f}<{low_2:.4f}<{low_3:.4f})")
                result["pivot_count"] = 3

                # 突破近期高点
                recent_high = max(highs[-5:])
                if last_close > recent_high:
                    result["tag"] = "BULL_123"
                    confidence = 0.55
                    result["reasons"].append(f"breakout({last_close:.4f}>{recent_high:.4f})")

                    # 放量确认加分
                    if is_volume_confirmed:
                        confidence += 0.25
                        result["structure_quality"] = "STRONG"
                        result["reasons"].append(f"volume_confirmed({vol_ratio:.1f}x)")
                    else:
                        result["structure_quality"] = "WEAK"
                        result["reasons"].append(f"no_volume({vol_ratio:.1f}x)")

                    # 结构清晰度加分
                    low_diff_1 = (low_2 - low_1) / low_1 if low_1 > 0 else 0
                    low_diff_2 = (low_3 - low_2) / low_2 if low_2 > 0 else 0
                    if low_diff_1 > 0.01 and low_diff_2 > 0.01:
                        confidence += 0.10
                        result["reasons"].append("clear_structure")

                    result["confidence"] = min(0.95, confidence)
                    return result

        # ========== BEAR_123检测 ==========
        if segment_size >= 2:
            high_1 = max(highs[:segment_size])
            high_2 = max(highs[segment_size:segment_size*2])
            high_3 = max(highs[segment_size*2:])

            # Lower highs判断
            if high_3 < high_2 < high_1:
                result["reasons"].append(f"lower_highs({high_1:.4f}>{high_2:.4f}>{high_3:.4f})")
                result["pivot_count"] = 3

                # 跌破近期低点
                recent_low = min(lows[-5:])
                if last_close < recent_low:
                    result["tag"] = "BEAR_123"
                    confidence = 0.55
                    result["reasons"].append(f"breakdown({last_close:.4f}<{recent_low:.4f})")

                    # 放量确认加分
                    if is_volume_confirmed:
                        confidence += 0.25
                        result["structure_quality"] = "STRONG"
                        result["reasons"].append(f"volume_confirmed({vol_ratio:.1f}x)")
                    else:
                        result["structure_quality"] = "WEAK"
                        result["reasons"].append(f"no_volume({vol_ratio:.1f}x)")

                    # 结构清晰度加分
                    high_diff_1 = (high_1 - high_2) / high_1 if high_1 > 0 else 0
                    high_diff_2 = (high_2 - high_3) / high_2 if high_2 > 0 else 0
                    if high_diff_1 > 0.01 and high_diff_2 > 0.01:
                        confidence += 0.10
                        result["reasons"].append("clear_structure")

                    result["confidence"] = min(0.95, confidence)
                    return result

        return result
    except Exception as e:
        result["reasons"].append(f"error:{str(e)}")
        return result


def compute_13_buypoints_score(candle_feats, volumes, support_level=None, resistance_level=None):
    """
    v3.290: 综合计算13买卖点增强信号的得分

    整合4个增强检测的结果，输出统一的分数和信号

    Returns:
        dict: {
            "score": int,  # -4 to +4
            "signals": list[str],  # 触发的信号列表
            "details": dict,  # 各检测的详细结果
            "exec_bias_adjust": str,  # "BOOST_BUY" | "BOOST_SELL" | "NONE"
        }
    """
    result = {
        "score": 0,
        "signals": [],
        "details": {},
        "exec_bias_adjust": "NONE"
    }

    if not candle_feats or len(candle_feats) < 15:
        return result

    # 1. 严格2B检测
    two_b_result = detect_2b_strict(candle_feats, volumes)
    result["details"]["2b_strict"] = two_b_result

    if two_b_result["tag"] == "BOTTOM" and two_b_result["strict"]:
        result["score"] += 2
        result["signals"].append("2B_BOTTOM_STRICT")
    elif two_b_result["tag"] == "BOTTOM" and two_b_result["confidence"] > 0.5:
        result["score"] += 1
        result["signals"].append("2B_BOTTOM")
    elif two_b_result["tag"] == "TOP" and two_b_result["strict"]:
        result["score"] -= 2
        result["signals"].append("2B_TOP_STRICT")
    elif two_b_result["tag"] == "TOP" and two_b_result["confidence"] > 0.5:
        result["score"] -= 1
        result["signals"].append("2B_TOP")

    # 2. 二次测试检测
    if support_level or resistance_level:
        retest_result = detect_secondary_test(
            candle_feats,
            support_level or 0,
            resistance_level
        )
        result["details"]["secondary_test"] = retest_result

        if retest_result["signal"] == "BULLISH_RETEST" and retest_result["confidence"] > 0.6:
            result["score"] += 2
            result["signals"].append(f"RETEST_SUPPORT_{retest_result['pa_signal']}")
        elif retest_result["signal"] == "BEARISH_RETEST" and retest_result["confidence"] > 0.6:
            result["score"] -= 2
            result["signals"].append(f"RETEST_RESISTANCE_{retest_result['pa_signal']}")

    # 3. SOS/SOW检测
    if volumes:
        sos_result = detect_sos_strict(candle_feats, volumes)
        result["details"]["sos"] = sos_result

        if sos_result["signal"] == "SOS" and sos_result["confidence"] > 0.7:
            result["score"] += 2
            result["signals"].append("SOS_STRONG")
        elif sos_result["signal"] == "SOS":
            result["score"] += 1
            result["signals"].append("SOS")
        elif sos_result["signal"] == "SOW" and sos_result["confidence"] > 0.7:
            result["score"] -= 2
            result["signals"].append("SOW_STRONG")
        elif sos_result["signal"] == "SOW":
            result["score"] -= 1
            result["signals"].append("SOW")

    # 4. 123放量检测
    if volumes:
        p123_result = detect_123_with_volume(candle_feats, volumes)
        result["details"]["123_volume"] = p123_result

        if p123_result["tag"] == "BULL_123" and p123_result["volume_confirmed"]:
            result["score"] += 2
            result["signals"].append("123_BULL_VOL")
        elif p123_result["tag"] == "BULL_123":
            result["score"] += 1
            result["signals"].append("123_BULL")
        elif p123_result["tag"] == "BEAR_123" and p123_result["volume_confirmed"]:
            result["score"] -= 2
            result["signals"].append("123_BEAR_VOL")
        elif p123_result["tag"] == "BEAR_123":
            result["score"] -= 1
            result["signals"].append("123_BEAR")

    # 计算exec_bias调整建议
    if result["score"] >= 3:
        result["exec_bias_adjust"] = "BOOST_BUY"
    elif result["score"] <= -3:
        result["exec_bias_adjust"] = "BOOST_SELL"

    return result


# ============================================================================
# 飞云交易系统 - 双突破系统
# ============================================================================

def fit_trendline(points: List[Tuple[int, float]], is_descending: bool = True) -> Tuple[float, float]:
    """
    拟合趋势线（简单线性回归）

    Args:
        points: [(index, price), ...] - 摆动点列表
        is_descending: True=下降趋势线(连接高点), False=上升趋势线(连接低点)

    Returns:
        Tuple[float, float]: (slope, intercept) - 斜率和截距
        趋势线方程: price = slope * index + intercept
    """
    if len(points) < 2:
        return (0.0, 0.0)

    # 取最近的2-3个点
    recent_points = points[-3:] if len(points) >= 3 else points[-2:]

    # 简单线性回归
    n = len(recent_points)
    sum_x = sum(p[0] for p in recent_points)
    sum_y = sum(p[1] for p in recent_points)
    sum_xy = sum(p[0] * p[1] for p in recent_points)
    sum_x2 = sum(p[0] ** 2 for p in recent_points)

    # 避免除零
    denominator = n * sum_x2 - sum_x ** 2
    if abs(denominator) < 1e-10:
        return (0.0, sum_y / n if n > 0 else 0.0)

    slope = (n * sum_xy - sum_x * sum_y) / denominator
    intercept = (sum_y - slope * sum_x) / n

    return (slope, intercept)


def detect_trendline_break(candle_feats: list, swing_highs: list, swing_lows: list) -> dict:
    """
    检测趋势线突破

    Args:
        candle_feats: K线特征列表
        swing_highs: [(index, price), ...] - 摆动高点
        swing_lows: [(index, price), ...] - 摆动低点

    Returns:
        dict: {
            "break_type": "UP" | "DOWN" | "NONE",
            "trendline_slope": float,
            "trendline_value": float,  # 当前位置趋势线价格
            "price_diff_pct": float,   # 价格偏离趋势线百分比
            "confidence": float,
            "reasons": list
        }
    """
    result = {
        "break_type": "NONE",
        "trendline_slope": 0.0,
        "trendline_value": 0.0,
        "price_diff_pct": 0.0,
        "confidence": 0.0,
        "reasons": []
    }

    if not candle_feats or len(candle_feats) < 10:
        return result

    try:
        current_idx = len(candle_feats) - 1
        current_close = candle_feats[-1].get('close', 0)
        current_high = candle_feats[-1].get('high', 0)
        current_low = candle_feats[-1].get('low', 0)

        if current_close <= 0:
            return result

        # 检查下降趋势线突破（用swing highs拟合）
        if len(swing_highs) >= 2:
            slope_desc, intercept_desc = fit_trendline(swing_highs, is_descending=True)

            # 趋势线必须是下降的（斜率为负）
            if slope_desc < 0:
                trendline_value = slope_desc * current_idx + intercept_desc
                result["trendline_value"] = trendline_value
                result["trendline_slope"] = slope_desc

                # 价格突破下降趋势线（向上突破）
                diff_pct = (current_close - trendline_value) / trendline_value * 100 if trendline_value > 0 else 0
                result["price_diff_pct"] = diff_pct

                if diff_pct > 0.5:  # 突破趋势线0.5%以上
                    result["break_type"] = "UP"
                    result["confidence"] = min(0.9, 0.5 + diff_pct * 0.1)
                    result["reasons"].append(f"break_desc_trendline_{diff_pct:.1f}%")

                    # 额外确认：收盘价高于趋势线
                    if current_low > trendline_value:
                        result["confidence"] = min(0.95, result["confidence"] + 0.1)
                        result["reasons"].append("full_bar_above_trendline")

                    return result
                else:
                    # v3.391: 记录未突破原因
                    result["reasons"].append(f"desc_tl_no_break({diff_pct:.1f}%<0.5%)")
            else:
                # v3.391: 斜率不符合下降趋势线条件
                result["reasons"].append(f"desc_tl_slope_invalid({slope_desc:.4f}>=0)")

        # 检查上升趋势线跌破（用swing lows拟合）
        if len(swing_lows) >= 2:
            slope_asc, intercept_asc = fit_trendline(swing_lows, is_descending=False)

            # 趋势线必须是上升的（斜率为正）
            if slope_asc > 0:
                trendline_value = slope_asc * current_idx + intercept_asc
                result["trendline_value"] = trendline_value
                result["trendline_slope"] = slope_asc

                # 价格跌破上升趋势线（向下突破）
                diff_pct = (trendline_value - current_close) / trendline_value * 100 if trendline_value > 0 else 0
                result["price_diff_pct"] = -diff_pct

                if diff_pct > 0.5:  # 跌破趋势线0.5%以上
                    result["break_type"] = "DOWN"
                    result["confidence"] = min(0.9, 0.5 + diff_pct * 0.1)
                    result["reasons"].append(f"break_asc_trendline_{diff_pct:.1f}%")

                    # 额外确认：最高价也低于趋势线
                    if current_high < trendline_value:
                        result["confidence"] = min(0.95, result["confidence"] + 0.1)
                        result["reasons"].append("full_bar_below_trendline")

                    return result
                else:
                    # v3.391: 记录未跌破原因
                    result["reasons"].append(f"asc_tl_no_break({diff_pct:.1f}%<0.5%)")
            else:
                # v3.391: 斜率不符合上升趋势线条件
                result["reasons"].append(f"asc_tl_slope_invalid({slope_asc:.4f}<=0)")

    except Exception as e:
        result["reasons"].append(f"error:{str(e)[:20]}")

    return result


def detect_pattern_break(candle_feats: list, volumes: list = None, lookback: int = 20) -> dict:
    """
    检测形态突破（箱体/区间突破）

    简化实现：用近期高低点形成的箱体作为"形态"

    Args:
        candle_feats: K线特征列表
        volumes: 成交量列表
        lookback: 回看K线数

    Returns:
        dict: {
            "break_type": "UP" | "DOWN" | "NONE",
            "box_high": float,
            "box_low": float,
            "box_mid": float,
            "volume_confirmed": bool,
            "confidence": float,
            "reasons": list
        }
    """
    result = {
        "break_type": "NONE",
        "box_high": 0.0,
        "box_low": 0.0,
        "box_mid": 0.0,
        "volume_confirmed": False,
        "confidence": 0.0,
        "reasons": []
    }

    if not candle_feats or len(candle_feats) < lookback:
        return result

    try:
        # 计算箱体范围（排除最近2根K线，避免自我引用）
        box_bars = candle_feats[-(lookback):-2]
        if len(box_bars) < 10:
            return result

        highs = [f.get('high', 0) for f in box_bars if f.get('valid', True)]
        lows = [f.get('low', 0) for f in box_bars if f.get('valid', True)]

        if not highs or not lows:
            return result

        box_high = max(highs)
        box_low = min(lows)
        box_mid = (box_high + box_low) / 2
        box_range = box_high - box_low

        result["box_high"] = box_high
        result["box_low"] = box_low
        result["box_mid"] = box_mid

        # 当前K线
        current = candle_feats[-1]
        current_close = current.get('close', 0)
        current_high = current.get('high', 0)
        current_low = current.get('low', 0)

        # 检查放量
        volume_confirmed = False
        if volumes and len(volumes) >= lookback:
            avg_vol = sum(volumes[-(lookback):-2]) / (lookback - 2) if lookback > 2 else 1
            current_vol = volumes[-1] if volumes else 0
            if avg_vol > 0 and current_vol > avg_vol * 1.3:
                volume_confirmed = True
                result["volume_confirmed"] = True
                result["reasons"].append(f"volume_{current_vol/avg_vol:.1f}x")

        # 向上突破箱体
        # v3.391: 突破阈值改进 - 箱体高度2%与价格0.5%取较大值，避免窄箱体假信号
        min_abs_threshold = current_close * 0.005  # 最小0.5%绝对阈值
        break_threshold = max(box_range * 0.02, min_abs_threshold)

        if current_close > box_high + break_threshold:
            result["break_type"] = "UP"
            diff_pct = (current_close - box_high) / box_high * 100 if box_high > 0 else 0
            result["confidence"] = min(0.85, 0.5 + diff_pct * 0.05)
            result["reasons"].append(f"break_box_high_{diff_pct:.1f}%")

            if volume_confirmed:
                result["confidence"] = min(0.95, result["confidence"] + 0.15)

            # 强突破：整根K线都在箱体上方
            if current_low > box_high:
                result["confidence"] = min(0.95, result["confidence"] + 0.1)
                result["reasons"].append("gap_above_box")

            return result

        # 向下突破箱体
        if current_close < box_low - break_threshold:
            result["break_type"] = "DOWN"
            diff_pct = (box_low - current_close) / box_low * 100 if box_low > 0 else 0
            result["confidence"] = min(0.85, 0.5 + diff_pct * 0.05)
            result["reasons"].append(f"break_box_low_{diff_pct:.1f}%")

            if volume_confirmed:
                result["confidence"] = min(0.95, result["confidence"] + 0.15)

            # 强突破：整根K线都在箱体下方
            if current_high < box_low:
                result["confidence"] = min(0.95, result["confidence"] + 0.1)
                result["reasons"].append("gap_below_box")

            return result

    except Exception as e:
        result["reasons"].append(f"error:{str(e)[:20]}")

    return result


def detect_double_breakthrough(candle_feats: list, volumes: list = None, n_swing: int = 2) -> dict:
    """
    双突破系统检测 (飞云交易系统核心)

    核心逻辑：有效信号必须同时满足趋势线突破和形态突破

    Args:
        candle_feats: K线特征列表
        volumes: 成交量列表
        n_swing: 摆动点确认K线数

    Returns:
        dict: {
            "signal": "DOUBLE_BREAK_BUY" | "DOUBLE_BREAK_SELL" | "SINGLE_UP" | "SINGLE_DOWN" | "NONE",
            "trendline_break": dict,  # 趋势线突破详情
            "pattern_break": dict,    # 形态突破详情
            "is_double": bool,        # 是否双突破
            "confidence": float,
            "score": int,             # 用于L2打分: -3 to +3
            "reasons": list
        }
    """
    result = {
        "signal": "NONE",
        "trendline_break": {},
        "pattern_break": {},
        "is_double": False,
        "confidence": 0.0,
        "score": 0,
        "reasons": []
    }

    if not candle_feats or len(candle_feats) < 20:
        return result

    try:
        # 提取高低点序列
        highs = [f.get('high', 0) for f in candle_feats if f.get('valid', True)]
        lows = [f.get('low', 0) for f in candle_feats if f.get('valid', True)]

        if len(highs) < 15 or len(lows) < 15:
            return result

        # 找摆动点
        swing_highs, swing_lows = find_swing_points(highs, lows, n_swing)

        # v3.391: 记录摆动点数量用于诊断
        result["swing_highs_count"] = len(swing_highs)
        result["swing_lows_count"] = len(swing_lows)

        # v3.391: 摆动点不足时记录原因
        if len(swing_highs) < 2:
            result["reasons"].append(f"swing_highs_insufficient({len(swing_highs)}<2)")
        if len(swing_lows) < 2:
            result["reasons"].append(f"swing_lows_insufficient({len(swing_lows)}<2)")

        # 检测趋势线突破
        tl_result = detect_trendline_break(candle_feats, swing_highs, swing_lows)
        result["trendline_break"] = tl_result

        # 检测形态突破
        pt_result = detect_pattern_break(candle_feats, volumes)
        result["pattern_break"] = pt_result

        tl_break = tl_result.get("break_type", "NONE")
        pt_break = pt_result.get("break_type", "NONE")

        # 双突破判断
        if tl_break == "UP" and pt_break == "UP":
            # 双突破买入信号
            result["signal"] = "DOUBLE_BREAK_BUY"
            result["is_double"] = True
            result["confidence"] = min(0.95, (tl_result["confidence"] + pt_result["confidence"]) / 2 + 0.15)
            result["score"] = 3
            result["reasons"].append("double_break_buy")
            result["reasons"].extend([f"tl:{r}" for r in tl_result.get("reasons", [])])
            result["reasons"].extend([f"pt:{r}" for r in pt_result.get("reasons", [])])

            # 放量额外加分（但不超过上限）
            if pt_result.get("volume_confirmed"):
                result["reasons"].append("volume_confirmed")

        elif tl_break == "DOWN" and pt_break == "DOWN":
            # 双突破卖出信号
            result["signal"] = "DOUBLE_BREAK_SELL"
            result["is_double"] = True
            result["confidence"] = min(0.95, (tl_result["confidence"] + pt_result["confidence"]) / 2 + 0.15)
            result["score"] = -3
            result["reasons"].append("double_break_sell")
            result["reasons"].extend([f"tl:{r}" for r in tl_result.get("reasons", [])])
            result["reasons"].extend([f"pt:{r}" for r in pt_result.get("reasons", [])])

            if pt_result.get("volume_confirmed"):
                result["reasons"].append("volume_confirmed")

        elif tl_break == "UP" or pt_break == "UP":
            # 单突破（向上）- 弱信号
            result["signal"] = "SINGLE_UP"
            result["is_double"] = False
            which = "trendline" if tl_break == "UP" else "pattern"
            conf = tl_result["confidence"] if tl_break == "UP" else pt_result["confidence"]
            result["confidence"] = conf * 0.6  # 单突破信心度降低
            result["score"] = 1
            result["reasons"].append(f"single_break_up_{which}")

        elif tl_break == "DOWN" or pt_break == "DOWN":
            # 单突破（向下）- 弱信号
            result["signal"] = "SINGLE_DOWN"
            result["is_double"] = False
            which = "trendline" if tl_break == "DOWN" else "pattern"
            conf = tl_result["confidence"] if tl_break == "DOWN" else pt_result["confidence"]
            result["confidence"] = conf * 0.6
            result["score"] = -1
            result["reasons"].append(f"single_break_down_{which}")

    except Exception as e:
        result["reasons"].append(f"error:{str(e)[:30]}")

    return result


def detect_123_advanced(candle_feats, m_swing=15):
    """
    1-2-3结构检测 (简化版swing-based)

    Returns:
        one_two_three_tag ∈ {BULL_123, BEAR_123, NONE}
    """
    if not candle_feats or len(candle_feats) < m_swing:
        return "NONE"
    
    try:
        # 找最近3个pivot
        lows = [f['low'] for f in candle_feats[-m_swing:] if f.get('valid')]
        highs = [f['high'] for f in candle_feats[-m_swing:] if f.get('valid')]
        
        if len(lows) < 6 or len(highs) < 6:
            return "NONE"
        
        # BULL_123: 低点抬高 + 突破
        low_1 = min(lows[:5])
        low_2 = min(lows[5:10])
        low_3 = min(lows[10:])
        
        if low_3 > low_2 > low_1:  # Higher lows
            last_close = candle_feats[-1]['close']
            if last_close > max(highs[-5:]):  # 突破近期高点
                return "BULL_123"
        
        # BEAR_123: 高点降低 + 跌破
        high_1 = max(highs[:5])
        high_2 = max(highs[5:10])
        high_3 = max(highs[10:])
        
        if high_3 < high_2 < high_1:  # Lower highs
            last_close = candle_feats[-1]['close']
            if last_close < min(lows[-5:]):  # 跌破近期低点
                return "BEAR_123"
        
        return "NONE"
    except Exception:
        return "NONE"


