def compute_l2_exec_bias_advanced(ohlcv_bars, sr_zone=None, trend_state=None, wyckoff_phase=None):
    """
    [废弃] L2 OHLCV高级分析 -> exec_bias

    ⚠️ 此函数已废弃，请勿调用。保留仅供历史参考。
    替代方案: compute_exec_bias_with_scoring() 或 compute_l2_macro_exec_bias_enhanced()

    Args:
        ohlcv_bars: list of dict with OHLCV
        sr_zone: "LOWER"/"MID"/"UPPER" (optional)
        trend_state: "UP"/"DOWN"/"SIDE" (optional)
        wyckoff_phase: Wyckoff阶段 (optional)
    
    Returns:
        dict with exec_bias, scores, reasons
    """
    if not ohlcv_bars or len(ohlcv_bars) < 20:
        return {
            "ready": False,
            "exec_bias": "HOLD",
            "pa_tag": "NONE",
            "two_b_tag": "NONE",
            "one_two_three_tag": "NONE",
            "volume_state": "NORMAL",
            "vol_ratio": 1.0,
            "score": 0,
            "score_breakdown": {},
            "reasons": ["insufficient_data"],
        }
    
    # 1. K线特征
    candle_feats = compute_candle_features(ohlcv_bars[-40:], n_sma=20)
    
    # 2. 成交量
    volumes = [b.get('volume', 1000) for b in ohlcv_bars[-40:]]
    vol_ratio, volume_state = compute_volume_state(volumes, n_sma=20)
    
    # 3. PA识别
    pa_tag = detect_pa_advanced(candle_feats)
    
    # 4. 2B检测
    two_b_tag = detect_2b_advanced(candle_feats, m_swing=10)
    
    # 5. 123检测
    one_two_three_tag = detect_123_advanced(candle_feats, m_swing=15)
    
    # 6. 打分合并
    score = 0
    score_breakdown = {}
    reasons = []
    
    # PA打分 (v2.713: 扩展支持所有 PA 类型)
    # 强多头信号 (+2)
    if pa_tag in ("STRONG_BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING"):
        score += 2
        score_breakdown['pa'] = +2
        reasons.append(f"pa_bull_strong:{pa_tag}")
    # 弱多头信号 (+1)
    elif pa_tag in ("BUY", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL"):
        score += 1
        score_breakdown['pa'] = +1
        reasons.append(f"pa_bull_weak:{pa_tag}")
    # 强空头信号 (-2)
    elif pa_tag in ("STRONG_SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD"):
        score -= 2
        score_breakdown['pa'] = -2
        reasons.append(f"pa_bear_strong:{pa_tag}")
    # 弱空头信号 (-1)
    elif pa_tag in ("SELL", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR"):
        score -= 1
        score_breakdown['pa'] = -1
        reasons.append(f"pa_bear_weak:{pa_tag}")
    
    # 2B打分
    if two_b_tag == "BOTTOM":
        score += 2
        score_breakdown['2b'] = +2
        reasons.append("2b_bottom")
    elif two_b_tag == "TOP":
        score -= 2
        score_breakdown['2b'] = -2
        reasons.append("2b_top")
    
    # 123打分
    if one_two_three_tag == "BULL_123":
        score += 2
        score_breakdown['123'] = +2
        reasons.append("bull_123")
    elif one_two_three_tag == "BEAR_123":
        score -= 2
        score_breakdown['123'] = -2
        reasons.append("bear_123")

    # v3.290: 13买卖点增强信号
    # 计算支撑位和阻力位（用于二次测试检测）
    try:
        recent_lows = [f['low'] for f in candle_feats[-20:] if f.get('valid')]
        recent_highs = [f['high'] for f in candle_feats[-20:] if f.get('valid')]
        support_level = min(recent_lows) if recent_lows else None
        resistance_level = max(recent_highs) if recent_highs else None

        buypoints_result = compute_13_buypoints_score(
            candle_feats, volumes, support_level, resistance_level
        )

        if buypoints_result["score"] != 0:
            bp_score = buypoints_result["score"]
            # 限制增强信号对总分的影响（最多±3分）
            bp_score_capped = max(-3, min(3, bp_score))
            score += bp_score_capped
            score_breakdown['v3290_buypoints'] = bp_score_capped

            for sig in buypoints_result["signals"]:
                reasons.append(f"v3290:{sig}")

            # 记录详细结果供调试
            if buypoints_result["exec_bias_adjust"] != "NONE":
                reasons.append(f"v3290_adjust:{buypoints_result['exec_bias_adjust']}")
    except Exception as e:
        reasons.append(f"v3290_error:{str(e)[:30]}")

    # v3.360: 飞云双突破已移至独立外挂(feiyun_plugin_for_scan)
    # L2专注K线形态分析(PA/2B/123/13买卖点)

    # 成交量打分
    if volume_state == "HIGH":
        if score > 0:
            score += 1
            score_breakdown['volume'] = +1
            reasons.append("vol_high_confirm")
        elif score < 0:
            score -= 1
            score_breakdown['volume'] = -1
            reasons.append("vol_high_confirm")
    elif volume_state == "LOW":
        # 低量弱化信号
        if abs(score) >= 2:
            score = int(score * 0.5)
            reasons.append("vol_low_weaken")
    
    # SR zone打分
    if sr_zone:
        if sr_zone in ("LOWER", "BELOW_SUPPORT") and score > 0:
            score += 1
            score_breakdown['sr'] = +1
            reasons.append("sr_support")
        elif sr_zone in ("UPPER", "ABOVE_RESIST") and score < 0:
            score += -1
            score_breakdown['sr'] = -1
            reasons.append("sr_resistance")
    
    # 冲突检测 (v2.713: 扩展 PA 类型)
    is_conflict = False
    bullish_pa = ("STRONG_BUY", "BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL")
    bearish_pa = ("STRONG_SELL", "SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR")
    
    if pa_tag in bullish_pa and two_b_tag == "TOP":
        is_conflict = True
        reasons.append("conflict_pa_bull_vs_2b_top")
    if pa_tag in bearish_pa and two_b_tag == "BOTTOM":
        is_conflict = True
        reasons.append("conflict_pa_bear_vs_2b_bottom")
    
    if is_conflict:
        score = 0
        reasons.append("forced_hold_due_to_conflict")
    
    # 低量无结构 -> 强制HOLD
    if volume_state == "LOW" and two_b_tag == "NONE" and one_two_three_tag == "NONE":
        if abs(score) < 3:
            score = 0
            reasons.append("low_vol_no_structure")
    
    # 转换成exec_bias
    if score >= 4:
        exec_bias = "STRONG_BUY"
    elif score >= 2:
        exec_bias = "BUY"
    elif score <= -4:
        exec_bias = "STRONG_SELL"
    elif score <= -2:
        exec_bias = "SELL"
    else:
        exec_bias = "HOLD"
    
    return {
        "ready": True,
        "exec_bias": exec_bias,
        "pa_tag": pa_tag,
        "two_b_tag": two_b_tag,
        "one_two_three_tag": one_two_three_tag,
        "volume_state": volume_state,
        "vol_ratio": vol_ratio,
        "score": score,
        "score_breakdown": score_breakdown,
        "reasons": reasons,
        "candle_feat_last": candle_feats[-1] if candle_feats else {},
    }




# ===== v2.040: Base Structural Bias 分类系统 =====

def classify_base_structural_bias(
    pa_tag: str,
    two_b_tag: str,
    one_two_three_tag: str,
    volume_state: str,
    score: int,
    exec_bias: str,
    reasons: list,
    sr_zone: str = None,
) -> dict:
    """
    v2.040: 将L2多维度信号分类为统一的Base Structural Bias
    
    🔒 严格保守原则：
    - 宁可HOLD，不猜测
    - 只在结构清晰时给出方向
    - 转换期/震荡期强制识别
    
    Args:
        pa_tag: PA标签 (STRONG_BUY/BUY/NONE/SELL/STRONG_SELL)
        two_b_tag: 2B标签 (BOTTOM/TOP/NONE)
        one_two_three_tag: 123标签 (BULL_123/BEAR_123/NONE)
        volume_state: 成交量状态 (LOW/NORMAL/HIGH)
        score: 综合打分 (-10 ~ +10)
        exec_bias: 原始exec_bias
        reasons: 原因列表
        sr_zone: SR区域(可选)
    
    Returns:
        {
            "structural_bias": str,      # 5种偏向之一
            "confidence": float,         # 0.0-1.0
            "bias_reasons": list[str],   # 分类原因
        }
    """
    
    bias_reasons = []
    confidence = 0.0
    
    # v2.713: 扩展 PA 类型
    bullish_pa = ("STRONG_BUY", "BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL")
    bearish_pa = ("STRONG_SELL", "SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR")
    
    # ========== 优先级1：检测 STRUCTURE_TRANSITION (转换期) ==========
    # 转换期是最危险的阶段，必须最先识别
    
    # 冲突1：PA多头 + 2B顶部失败
    if pa_tag in bullish_pa and two_b_tag == "TOP":
        bias_reasons.append("PA多头 vs 2B顶部失败")
        bias_reasons.append("多空信号冲突 → 转换期")
        confidence = 0.3  # 转换期置信度低
        return {
            "structural_bias": "STRUCTURE_TRANSITION",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # 冲突2：PA空头 + 2B底部反转
    if pa_tag in bearish_pa and two_b_tag == "BOTTOM":
        bias_reasons.append("PA空头 vs 2B底部反转")
        bias_reasons.append("多空信号冲突 → 转换期")
        confidence = 0.3
        return {
            "structural_bias": "STRUCTURE_TRANSITION",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # 冲突3：分数接近0但有结构 (旧结构被破坏，新结构未确认)
    if -1 <= score <= 1:
        # 有PA或2B信号，但打分接近0 → 说明力量抵消
        if pa_tag != "NONE" or two_b_tag != "NONE":
            bias_reasons.append(f"多空打分平衡(score={score})")
            bias_reasons.append("有结构但方向不明 → 转换期")
            confidence = 0.35
            return {
                "structural_bias": "STRUCTURE_TRANSITION",
                "confidence": confidence,
                "bias_reasons": bias_reasons,
            }
    
    # ========== 优先级2：检测 STRUCTURE_RANGE (震荡区间) ==========
    
    # 震荡1：低量 + 无结构 + 分数接近0
    if volume_state == "LOW" and pa_tag == "NONE" and two_b_tag == "NONE" and abs(score) <= 1:
        bias_reasons.append("低量无结构")
        bias_reasons.append("无方向性 → 震荡区间")
        confidence = 0.4
        return {
            "structural_bias": "STRUCTURE_RANGE",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # 震荡2：普通/高量 + 无明确结构 + exec_bias=HOLD
    if volume_state in ("NORMAL", "HIGH") and exec_bias == "HOLD":
        if abs(score) <= 1 and pa_tag == "NONE" and two_b_tag == "NONE":
            bias_reasons.append("有量但无方向")
            bias_reasons.append("PA/2B全部空转 → 震荡区间")
            confidence = 0.45
            return {
                "structural_bias": "STRUCTURE_RANGE",
                "confidence": confidence,
                "bias_reasons": bias_reasons,
            }
    
    # ========== 优先级3：检测 STRUCTURE_INVALID (无效结构) ==========
    
    # 无效1：所有标签都是NONE
    if pa_tag == "NONE" and two_b_tag == "NONE" and one_two_three_tag == "NONE":
        bias_reasons.append("PA/2B/123全部无效")
        bias_reasons.append("随机波动 → 无效结构")
        confidence = 0.0
        return {
            "structural_bias": "STRUCTURE_INVALID",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # 无效2：exec_bias=HOLD且无明确原因
    if exec_bias == "HOLD" and not reasons:
        bias_reasons.append("强制HOLD但无原因")
        bias_reasons.append("无边缘 → 无效结构")
        confidence = 0.0
        return {
            "structural_bias": "STRUCTURE_INVALID",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # ========== 优先级4：检测 STRUCTURE_BULLISH (多头结构) ==========
    # v2.713: 扩展 PA 类型 (使用前面定义的 bullish_pa/bearish_pa)
    strong_bullish_pa = ("STRONG_BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING")
    weak_bullish_pa = ("BUY", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL")
    strong_bearish_pa = ("STRONG_SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD")
    weak_bearish_pa = ("SELL", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR")
    
    if exec_bias in ("STRONG_BUY", "BUY"):
        # 基础置信度
        conf_base = 0.5 if exec_bias == "BUY" else 0.7
        
        # PA增强 (v2.713: 扩展)
        if pa_tag in strong_bullish_pa:
            conf_base += 0.15
            bias_reasons.append(f"PA强多头:{pa_tag}(+0.15)")
        elif pa_tag in weak_bullish_pa:
            conf_base += 0.08
            bias_reasons.append(f"PA多头:{pa_tag}(+0.08)")
        
        # 2B增强
        if two_b_tag == "BOTTOM":
            conf_base += 0.1
            bias_reasons.append("2B底部反转(+0.1)")
        
        # 123增强
        if one_two_three_tag == "BULL_123":
            conf_base += 0.08
            bias_reasons.append("123多头结构(+0.08)")
        
        # 成交量确认
        if volume_state == "HIGH" and score > 0:
            conf_base += 0.05
            bias_reasons.append("放量确认(+0.05)")
        
        # SR位置加成
        if sr_zone in ("LOWER", "BELOW_SUPPORT"):
            conf_base += 0.05
            bias_reasons.append("低位支撑(+0.05)")
        
        # 成交量背离惩罚
        if volume_state == "LOW" and score > 0:
            conf_base -= 0.1
            bias_reasons.append("缩量上涨背离(-0.1)")
        
        confidence = min(conf_base, 0.95)  # 上限0.95
        
        bias_reasons.insert(0, f"多头结构(exec_bias={exec_bias})")
        
        return {
            "structural_bias": "STRUCTURE_BULLISH",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # ========== 优先级5：检测 STRUCTURE_BEARISH (空头结构) ==========
    
    if exec_bias in ("STRONG_SELL", "SELL"):
        # 基础置信度
        conf_base = 0.5 if exec_bias == "SELL" else 0.7
        
        # PA增强 (v2.713: 扩展)
        if pa_tag in strong_bearish_pa:
            conf_base += 0.15
            bias_reasons.append(f"PA强空头:{pa_tag}(+0.15)")
        elif pa_tag in weak_bearish_pa:
            conf_base += 0.08
            bias_reasons.append(f"PA空头:{pa_tag}(+0.08)")
        
        # 2B增强
        if two_b_tag == "TOP":
            conf_base += 0.1
            bias_reasons.append("2B顶部失败(+0.1)")
        
        # 123增强
        if one_two_three_tag == "BEAR_123":
            conf_base += 0.08
            bias_reasons.append("123空头结构(+0.08)")
        
        # 成交量确认
        if volume_state == "HIGH" and score < 0:
            conf_base += 0.05
            bias_reasons.append("放量确认(+0.05)")
        
        # SR位置加成
        if sr_zone in ("UPPER", "ABOVE_RESIST"):
            conf_base += 0.05
            bias_reasons.append("高位阻力(+0.05)")
        
        # 成交量背离惩罚
        if volume_state == "LOW" and score < 0:
            conf_base -= 0.1
            bias_reasons.append("缩量下跌背离(-0.1)")
        
        confidence = min(conf_base, 0.95)  # 上限0.95
        
        bias_reasons.insert(0, f"空头结构(exec_bias={exec_bias})")
        
        return {
            "structural_bias": "STRUCTURE_BEARISH",
            "confidence": confidence,
            "bias_reasons": bias_reasons,
        }
    
    # ========== 默认：STRUCTURE_INVALID ==========
    bias_reasons.append("未匹配任何明确结构")
    bias_reasons.append("默认 → 无效结构")
    return {
        "structural_bias": "STRUCTURE_INVALID",
        "confidence": 0.0,
        "bias_reasons": bias_reasons,
    }


# ===== v2.040: L2 Final Action 严格保守决策层 =====

def decide_l2_final_action(
    structural_bias: str,
    confidence: float,
    pa_tag: str,
    two_b_tag: str,
    volume_state: str,
    sr_zone: str = None,
) -> dict:
    """
    v2.040: L2最终行为决策
    
    🔒 核心原则：
    1. 宁可HOLD，不猜测
    2. 只在结构清晰时给BUY/SELL
    3. 转换期/震荡期/无效结构 → 强制HOLD
    4. 置信度 < 0.6 → 强制HOLD (硬规则)
    
    Args:
        structural_bias: Base Structural Bias
        confidence: 置信度(0-1)
        pa_tag: PA标签
        two_b_tag: 2B标签
        volume_state: 成交量状态
        sr_zone: SR区域(可选)
    
    Returns:
        {
            "l2_final_action": "BUY" | "SELL" | "HOLD",
            "action_reasons": list[str],
            "confidence_check": bool,  # 是否通过置信度检查
        }
    """
    
    action_reasons = []
    
    # ========== 硬约束1：置信度检查 ==========
    if confidence < 0.6:
        action_reasons.append(f"置信度不足({confidence:.2f} < 0.6)")
        action_reasons.append("硬约束 → 强制HOLD")
        return {
            "l2_final_action": "HOLD",
            "action_reasons": action_reasons,
            "confidence_check": False,
        }
    
    # ========== 硬约束2：STRUCTURE_TRANSITION 强制HOLD ==========
    if structural_bias == "STRUCTURE_TRANSITION":
        action_reasons.append("转换期结构")
        action_reasons.append("旧结构已破坏，新结构未确认")
        action_reasons.append("强制HOLD(禁止BUY/SELL)")
        return {
            "l2_final_action": "HOLD",
            "action_reasons": action_reasons,
            "confidence_check": True,
        }
    
    # ========== 硬约束3：STRUCTURE_RANGE 强制HOLD ==========
    if structural_bias == "STRUCTURE_RANGE":
        action_reasons.append("震荡区间结构")
        action_reasons.append("L2不做区间博弈")
        action_reasons.append("强制HOLD")
        return {
            "l2_final_action": "HOLD",
            "action_reasons": action_reasons,
            "confidence_check": True,
        }
    
    # ========== 硬约束4：STRUCTURE_INVALID 强制HOLD ==========
    if structural_bias == "STRUCTURE_INVALID":
        action_reasons.append("无效结构/无边缘")
        action_reasons.append("随机波动")
        action_reasons.append("强制HOLD")
        return {
            "l2_final_action": "HOLD",
            "action_reasons": action_reasons,
            "confidence_check": True,
        }
    
    # ========== STRUCTURE_BULLISH → 严格检查后允许BUY ==========
    if structural_bias == "STRUCTURE_BULLISH":
        # v2.713: 扩展 PA 类型
        all_bullish_pa = ("STRONG_BUY", "BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL")
        
        # 前提1：PA明确支持上涨(非单根噪音)
        if pa_tag not in all_bullish_pa:
            action_reasons.append("PA不支持上涨")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 前提2：没有被确认的2B失败
        if two_b_tag == "TOP":
            action_reasons.append("2B顶部失败")
            action_reasons.append("多头失败信号")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 前提3：成交量不与方向背离
        if volume_state == "LOW":
            action_reasons.append("缩量上涨")
            action_reasons.append("成交量与方向背离")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 前提4：当前不是明显高位失败K
        if sr_zone in ("ABOVE_RESIST",):
            action_reasons.append("已突破阻力上方")
            action_reasons.append("高位失败风险")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 全部前提通过 → 允许BUY
        action_reasons.append("多头结构清晰")
        action_reasons.append("PA确认")
        action_reasons.append("成交量支持")
        action_reasons.append("非高位失败")
        action_reasons.append("→ BUY")
        return {
            "l2_final_action": "BUY",
            "action_reasons": action_reasons,
            "confidence_check": True,
        }
    
    # ========== STRUCTURE_BEARISH → 严格检查后允许SELL ==========
    if structural_bias == "STRUCTURE_BEARISH":
        # v2.713: 扩展 PA 类型
        all_bearish_pa = ("STRONG_SELL", "SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR")
        
        # 前提1：PA明确支持下行或反弹失败
        if pa_tag not in all_bearish_pa:
            action_reasons.append("PA不支持下行")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 前提2：2B或lower-high结构清晰 (允许无2B，但有则必须是TOP)
        if two_b_tag == "BOTTOM":
            action_reasons.append("2B底部反转")
            action_reasons.append("空头失败信号")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 前提3：成交量支持下行或多头衰竭 (允许缩量，空头可缩量下跌)
        # (无额外检查，空头允许缩量)
        
        # 前提4：当前K线不是恐慌尾端(避免追空)
        if sr_zone in ("BELOW_SUPPORT",):
            action_reasons.append("已跌破支撑下方")
            action_reasons.append("恐慌尾端风险")
            action_reasons.append("HOLD")
            return {
                "l2_final_action": "HOLD",
                "action_reasons": action_reasons,
                "confidence_check": True,
            }
        
        # 全部前提通过 → 允许SELL
        action_reasons.append("空头结构清晰")
        action_reasons.append("PA确认")
        action_reasons.append("非恐慌尾端")
        action_reasons.append("→ SELL")
        return {
            "l2_final_action": "SELL",
            "action_reasons": action_reasons,
            "confidence_check": True,
        }
    
    # ========== 默认：HOLD ==========
    action_reasons.append("未匹配任何允许条件")
    action_reasons.append("默认 → HOLD")
    return {
        "l2_final_action": "HOLD",
        "action_reasons": action_reasons,
        "confidence_check": True,
    }



# ===== L2 OHLCV 全面升级 v2.1 (修复版) =====

# v2.730: 基础阈值已移至文件开头 L2Config (兼容别名保留)
# 以下为 v2.1 新增的专用阈值
PIN_WICK_MIN_RATIO = 0.5
PIN_CLOSE_POSITION_BULL = 0.6
PIN_CLOSE_POSITION_BEAR = 0.4
SWING_LOOKBACK = 10
TWO_B_THRESHOLD = 0.001
SCORE_STRONG_BUY = 4
SCORE_BUY = 2
SCORE_STRONG_SELL = -4
SCORE_SELL = -2


def compute_candle_features_ohlcv(ohlcv_bars, n_sma=20):
    """K线特征工程"""
    if not ohlcv_bars or len(ohlcv_bars) < 2:
        return []
    
    features = []
    ranges = []
    bodies = []
    
    for bar in ohlcv_bars:
        try:
            o = float(bar.get('open', 0))
            h = float(bar.get('high', 0))
            l = float(bar.get('low', 0))
            c = float(bar.get('close', 0))
            rng = max(h - l, 1e-8)
            body = abs(c - o)
            ranges.append(rng)
            bodies.append(body)
        except Exception:
            ranges.append(1.0)
            bodies.append(0.5)
    
    for i, bar in enumerate(ohlcv_bars):
        try:
            o = float(bar.get('open', 0))
            h = float(bar.get('high', 0))
            l = float(bar.get('low', 0))
            c = float(bar.get('close', 0))
            v = float(bar.get('volume', 1000))
        except Exception:
            features.append({'valid': False, 'index': i})
            continue
        
        rng = max(h - l, 1e-8)
        body = abs(c - o)
        upper_wick = h - max(o, c)
        lower_wick = min(o, c) - l
        body_ratio = body / rng
        wick_ratio = max(upper_wick, lower_wick) / rng
        
        if c > o * 1.001:
            direction = "BULL"
        elif c < o * 0.999:
            direction = "BEAR"
        else:
            direction = "NEUTRAL"
        
        start_idx = max(0, i - n_sma + 1)
        avg_rng = sum(ranges[start_idx:i+1]) / max(len(ranges[start_idx:i+1]), 1)
        avg_body = sum(bodies[start_idx:i+1]) / max(len(bodies[start_idx:i+1]), 1)
        range_ratio = rng / max(avg_rng, 1e-8)
        body_strength = body / max(avg_body, 1e-8)
        
        features.append({
            'valid': True,
            'index': i,
            'open': o,
            'high': h,
            'low': l,
            'close': c,
            'volume': v,
            'body': body,
            'range': rng,
            'upper_wick': upper_wick,
            'lower_wick': lower_wick,
            'body_ratio': body_ratio,
            'wick_ratio': wick_ratio,
            'direction': direction,
            'range_ratio': range_ratio,
            'body_strength': body_strength,
        })
    
    return features


def compute_volume_state_ohlcv(volumes, n_sma=20):
    """成交量分层"""
    if not volumes or len(volumes) < 2:
        return 1.0, "NORMAL"
    
    try:
        vols = [float(v) for v in volumes if v is not None]
        if not vols:
            return 1.0, "NORMAL"
        
        v_last = vols[-1]
        start_idx = max(0, len(vols) - n_sma)
        avg_vol = sum(vols[start_idx:]) / max(len(vols[start_idx:]), 1)
        vol_ratio = v_last / max(avg_vol, 1e-8)
        
        if vol_ratio < VOL_LOW_THRESHOLD:
            return vol_ratio, "LOW"
        elif vol_ratio > VOL_HIGH_THRESHOLD:
            return vol_ratio, "HIGH"
        else:
            return vol_ratio, "NORMAL"
    except Exception:
        return 1.0, "NORMAL"


def detect_pa_ohlcv(candle_feats, volume_state, vol_ratio):
    """
    v2.050 完全重写的PA识别
    严格按照传统技术分析识别：
    1. Rejection (Pin/Hammer/Shooting Star)
    2. Engulfing
    3. Higher Low / Lower High
    4. Continuation
    5. 高成交量方向K线
    """
    if not candle_feats or len(candle_feats) < 2:
        return "NONE", ["insufficient_candles"]
    
    last = candle_feats[-1]
    if not last.get('valid'):
        return "NONE", ["invalid_candle"]
    
    prev = candle_feats[-2] if len(candle_feats) >= 2 else None
    reasons = []
    
    # 当前K线特征
    body_ratio = last.get('body_ratio', 0)
    range_val = last.get('range', 0)
    lower_wick = last.get('lower_wick', 0)
    upper_wick = last.get('upper_wick', 0)
    close_position = (last['close'] - last['low']) / max(range_val, 1e-8)
    
    # ────────────────────────────────
    # 1. Rejection（最优先）
    # ────────────────────────────────
    
    # Bullish Rejection (Pin/Hammer)
    if lower_wick > range_val * 0.5:
        if close_position >= 0.70:
            if volume_state in ("HIGH", "CLIMAX", "NORMAL"):
                reasons.append(f"bullish_rejection_wick_{lower_wick/range_val:.2f}")
                return "STRONG_BUY" if volume_state in ("HIGH", "CLIMAX") else "BUY", reasons
    
    # Bearish Rejection (Shooting Star)
    if upper_wick > range_val * 0.5:
        if close_position <= 0.30:
            if volume_state in ("HIGH", "CLIMAX", "NORMAL"):
                reasons.append(f"bearish_rejection_wick_{upper_wick/range_val:.2f}")
                return "STRONG_SELL" if volume_state in ("HIGH", "CLIMAX") else "SELL", reasons
    
    # ────────────────────────────────
    # 2. Engulfing
    # ────────────────────────────────
    
    if prev and prev.get('valid'):
        # Bullish Engulfing
        if (last['direction'] == "BULL" and prev['direction'] == "BEAR" and
            last['body'] > prev['body'] * 1.3 and
            last['close'] > prev['open'] and last['open'] < prev['close']):
            if volume_state in ("NORMAL", "HIGH", "CLIMAX"):
                reasons.append(f"bullish_engulfing_ratio_{last['body']/prev['body']:.2f}")
                return "STRONG_BUY" if volume_state in ("HIGH", "CLIMAX") else "BUY", reasons
        
        # Bearish Engulfing
        if (last['direction'] == "BEAR" and prev['direction'] == "BULL" and
            last['body'] > prev['body'] * 1.3 and
            last['close'] < prev['open'] and last['open'] > prev['close']):
            if volume_state in ("NORMAL", "HIGH", "CLIMAX"):
                reasons.append(f"bearish_engulfing_ratio_{last['body']/prev['body']:.2f}")
                return "STRONG_SELL" if volume_state in ("HIGH", "CLIMAX") else "SELL", reasons
    
    # ────────────────────────────────
    # 3. Higher Low / Lower High（结构）- v2.975重写
    # ────────────────────────────────
    
    if len(candle_feats) >= 10:
        bars = candle_feats[-10:]
        valid_bars = [b for b in bars if b.get('valid')]
        
        if len(valid_bars) >= 5:
            # 找swing点 (局部极值)
            swing_highs = []
            swing_lows = []
            
            for i in range(1, len(valid_bars) - 1):
                curr = valid_bars[i]
                prev_bar = valid_bars[i-1]
                next_bar = valid_bars[i+1]
                
                # Swing High: 比左右都高
                if curr['high'] > prev_bar['high'] and curr['high'] > next_bar['high']:
                    swing_highs.append(curr['high'])
                # Swing Low: 比左右都低
                if curr['low'] < prev_bar['low'] and curr['low'] < next_bar['low']:
                    swing_lows.append(curr['low'])
            
            # Higher Low 检测: 需要至少2个swing low，且递增
            if len(swing_lows) >= 2:
                # 检查最后两个swing low是否递增
                if swing_lows[-1] > swing_lows[-2] * 1.002:  # 后一个比前一个高0.2%
                    # 当前K线是阳线，确认多头
                    if last['direction'] == "BULL" and body_ratio >= 0.4:
                        if volume_state in ("HIGH", "NORMAL"):
                            reasons.append(f"hl_structure_sl1={swing_lows[-2]:.2f}_sl2={swing_lows[-1]:.2f}")
                            return "BUY", reasons
            
            # Lower High 检测: 需要至少2个swing high，且递减
            if len(swing_highs) >= 2:
                # 检查最后两个swing high是否递减
                if swing_highs[-1] < swing_highs[-2] * 0.998:  # 后一个比前一个低0.2%
                    # 当前K线是阴线，确认空头
                    if last['direction'] == "BEAR" and body_ratio >= 0.4:
                        if volume_state in ("HIGH", "NORMAL"):
                            reasons.append(f"lh_structure_sh1={swing_highs[-2]:.2f}_sh2={swing_highs[-1]:.2f}")
                            return "SELL", reasons
    
    # ────────────────────────────────
    # 4. Continuation（趋势延续）
    # ────────────────────────────────
    
    if len(candle_feats) >= 4:
        prev_3_bullish = sum(1 for b in candle_feats[-4:-1] if b.get('direction') == "BULL")
        prev_3_bearish = sum(1 for b in candle_feats[-4:-1] if b.get('direction') == "BEAR")
        
        if prev_3_bullish >= 2 and last['direction'] == "BULL":
            if body_ratio >= 0.4 and volume_state in ("HIGH", "NORMAL"):
                reasons.append(f"bullish_continuation_body_{body_ratio:.2f}")
                return "BUY", reasons
        
        if prev_3_bearish >= 2 and last['direction'] == "BEAR":
            if body_ratio >= 0.4 and volume_state in ("HIGH", "NORMAL"):
                reasons.append(f"bearish_continuation_body_{body_ratio:.2f}")
                return "SELL", reasons
    
    # ────────────────────────────────
    # 5. 高成交量方向K线（放宽条件）
    # ────────────────────────────────
    
    if volume_state in ("HIGH", "CLIMAX") and vol_ratio >= 2.0:
        # 降低实体要求
        if body_ratio >= 0.3:
            if last['direction'] == "BULL":
                reasons.append(f"high_volume_bullish_vol_{vol_ratio:.2f}_body_{body_ratio:.2f}")
                return "BUY", reasons
            elif last['direction'] == "BEAR":
                reasons.append(f"high_volume_bearish_vol_{vol_ratio:.2f}_body_{body_ratio:.2f}")
                return "SELL", reasons
        
        # 或收盘位置偏向
        if close_position >= 0.70:
            reasons.append(f"high_volume_close_upper_{close_position:.2f}_vol_{vol_ratio:.2f}")
            return "BUY", reasons
        elif close_position <= 0.30:
            reasons.append(f"high_volume_close_lower_{close_position:.2f}_vol_{vol_ratio:.2f}")
            return "SELL", reasons
    
    reasons.append("no_clear_pa_structure")
    return "NONE", reasons


def detect_2b_ohlcv(candle_feats, volume_state, m_swing=10):
    """
    v2.050 完全重写的2B检测
    严格验证：破位 → 拉回 → 收盘确认
    """
    if not candle_feats or len(candle_feats) < 15:
        return "NONE", ["insufficient_bars_for_2b"]
    
    last = candle_feats[-1]
    if not last.get('valid'):
        return "NONE", ["invalid_candle"]
    
    reasons = []
    
    try:
        # 找swing点
        recent_bars = [f for f in candle_feats[-(m_swing+1):-1] if f.get('valid')]
        
        if len(recent_bars) < m_swing // 2:
            return "NONE", ["insufficient_swing_data"]
        
        swing_high = max(f['high'] for f in recent_bars)
        swing_low = min(f['low'] for f in recent_bars)
        
        # ────────────────────────────────
        # 2B BUY (底部假突破)
        # ────────────────────────────────
        
        # 1) 价格跌破swing low
        broke_below = last['low'] < swing_low * (1 - 0.002)
        
        # 2) 收盘价拉回swing low之上
        pulled_back = last['close'] > swing_low * (1 + 0.003)
        
        if broke_below and pulled_back:
            if volume_state in ("NORMAL", "HIGH", "CLIMAX"):
                reasons.append(f"2b_buy_broke_{swing_low:.2f}_pulled_back_{last['close']:.2f}")
                return "BOTTOM", reasons
        
        # ────────────────────────────────
        # 2B SELL (顶部假突破)
        # ────────────────────────────────
        
        # 1) 价格突破swing high
        broke_above = last['high'] > swing_high * (1 + 0.002)
        
        # 2) 收盘价回落swing high之下
        pulled_back_down = last['close'] < swing_high * (1 - 0.003)
        
        if broke_above and pulled_back_down:
            if volume_state in ("NORMAL", "HIGH", "CLIMAX"):
                reasons.append(f"2b_sell_broke_{swing_high:.2f}_pulled_back_{last['close']:.2f}")
                return "TOP", reasons
        
        return "NONE", ["no_2b_structure"]
    
    except Exception as e:
        return "NONE", [f"2b_error:{str(e)[:50]}"]


def detect_123_ohlcv(candle_feats, volume_state, m_swing=15):
    """
    v2.975 重写的1-2-3检测
    
    使用真正的swing点识别算法，而非时间分段
    
    BULL 1-2-3 (底部反转确认):
      1. 找到显著低点 Point1
      2. 找到其后的显著高点 Point2  
      3. 找到Point2之后的回撤低点 Point3 (必须高于Point1)
      4. 当前价格突破 Point2 → 确认
    
    BEAR 1-2-3 (顶部反转确认):
      1. 找到显著高点 Point1
      2. 找到其后的显著低点 Point2
      3. 找到Point2之后的反弹高点 Point3 (必须低于Point1)
      4. 当前价格跌破 Point2 → 确认
    """
    if not candle_feats or len(candle_feats) < 15:
        return "NONE", ["insufficient_bars_for_123"]
    
    last = candle_feats[-1]
    if not last.get('valid'):
        return "NONE", ["invalid_candle"]
    
    # 取最近的K线进行分析
    bars = [f for f in candle_feats[-m_swing:] if f.get('valid')]
    if len(bars) < 10:
        return "NONE", ["insufficient_valid_bars"]
    
    highs = [b['high'] for b in bars]
    lows = [b['low'] for b in bars]
    
    # ========== 找Swing点 ==========
    # Swing High: 比左右N根的high都高
    # Swing Low: 比左右N根的low都低
    swing_window = 2  # 左右各看2根
    
    swing_highs = []  # [(index, price), ...]
    swing_lows = []
    
    for i in range(swing_window, len(bars) - swing_window):
        # Swing High
        is_swing_high = True
        for j in range(i - swing_window, i + swing_window + 1):
            if j != i and highs[j] >= highs[i]:
                is_swing_high = False
                break
        if is_swing_high:
            swing_highs.append((i, highs[i]))
        
        # Swing Low
        is_swing_low = True
        for j in range(i - swing_window, i + swing_window + 1):
            if j != i and lows[j] <= lows[i]:
                is_swing_low = False
                break
        if is_swing_low:
            swing_lows.append((i, lows[i]))
    
    # 如果swing点太少，无法形成1-2-3
    if len(swing_highs) < 2 or len(swing_lows) < 2:
        return "NONE", ["insufficient_swing_points"]
    
    # ========== BEAR 1-2-3 检测 ==========
    # Point1: 显著高点
    # Point2: Point1之后的显著低点
    # Point3: Point2之后的反弹高点，且 < Point1
    # 确认: 当前收盘 < Point2
    
    for idx1, p1_high in swing_highs:
        # 找Point1之后的Point2 (低点)
        for idx2, p2_low in swing_lows:
            if idx2 <= idx1:
                continue
            
            # 找Point2之后的Point3 (高点，但低于Point1)
            for idx3, p3_high in swing_highs:
                if idx3 <= idx2:
                    continue
                
                # Point3 必须低于 Point1 (Lower High)
                if p3_high >= p1_high * 0.998:
                    continue
                
                # 当前价格跌破 Point2
                if last['close'] < p2_low * 0.997:
                    reasons = [f"bear_123_p1={p1_high:.2f}@{idx1}_p2={p2_low:.2f}@{idx2}_p3={p3_high:.2f}@{idx3}_break={last['close']:.2f}"]
                    if volume_state in ("NORMAL", "HIGH", "CLIMAX"):
                        return "BEAR_123", reasons
    
    # ========== BULL 1-2-3 检测 ==========
    # Point1: 显著低点
    # Point2: Point1之后的显著高点
    # Point3: Point2之后的回撤低点，且 > Point1
    # 确认: 当前收盘 > Point2
    
    for idx1, p1_low in swing_lows:
        # 找Point1之后的Point2 (高点)
        for idx2, p2_high in swing_highs:
            if idx2 <= idx1:
                continue
            
            # 找Point2之后的Point3 (低点，但高于Point1)
            for idx3, p3_low in swing_lows:
                if idx3 <= idx2:
                    continue
                
                # Point3 必须高于 Point1 (Higher Low)
                if p3_low <= p1_low * 1.002:
                    continue
                
                # 当前价格突破 Point2
                if last['close'] > p2_high * 1.003:
                    reasons = [f"bull_123_p1={p1_low:.2f}@{idx1}_p2={p2_high:.2f}@{idx2}_p3={p3_low:.2f}@{idx3}_break={last['close']:.2f}"]
                    if volume_state in ("NORMAL", "HIGH", "CLIMAX"):
                        return "BULL_123", reasons
    
    return "NONE", ["no_123_structure"]


def merge_to_exec_bias_ohlcv(pa_tag, two_b_tag, one_two_three_tag, 
                             volume_state, vol_ratio,
                             sr_zone=None, trend_state=None, wyckoff_phase=None,
                             pa_edge_buy=False, pa_edge_sell=False):  # v2.520: 添加TV pa_edge参数
    """
    v2.320 基于score的综合决策（冲突保护强化版）
    
    核心改进：
    - score >= 6 → STRONG_BUY（三重确认自动升级，无需放量）
    - score >= 3 → BUY
    - score <= -6 → STRONG_SELL（三重确认自动升级，无需放量）
    - score <= -3 → SELL
    - 成交量作为score的一部分，不再是STRONG的必要条件
    - v2.320: 增加 has_conflict 标记，防止冲突信号被后续逻辑覆盖
    
    严格规则：
    - 至少一个结构清晰 + 成交量不反对 → BUY/SELL
    - 所有结构=NONE → HOLD
    - 结构冲突 → HOLD（强制，不可覆盖）
    - 成交量反对 → 降级或HOLD
    """
    reasons = []
    score = 0
    score_breakdown = {"pa": 0, "2b": 0, "123": 0, "volume": 0}
    has_conflict = False  # v2.320: 冲突标记
    
    # ────────────────────────────────
    # 收集多头/空头信号
    # ────────────────────────────────
    
    bullish_signals = []
    bearish_signals = []
    
    # PA (v2.713: 扩展支持所有 PA 类型)
    # 强多头
    if pa_tag in ("STRONG_BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING"):
        bullish_signals.append("PA_BULLISH")
        score += 2
        score_breakdown["pa"] = 2
    # 弱多头
    elif pa_tag in ("BUY", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL"):
        bullish_signals.append("PA_BULLISH")
        score += 1
        score_breakdown["pa"] = 1
    # 强空头
    elif pa_tag in ("STRONG_SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD"):
        bearish_signals.append("PA_BEARISH")
        score -= 2
        score_breakdown["pa"] = -2
    # 弱空头
    elif pa_tag in ("SELL", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR"):
        bearish_signals.append("PA_BEARISH")
        score -= 1
        score_breakdown["pa"] = -1
    
    # 2B
    if two_b_tag == "BOTTOM":
        bullish_signals.append("2B_BUY")
        score += 2
        score_breakdown["2b"] = 2
    elif two_b_tag == "TOP":
        bearish_signals.append("2B_SELL")
        score -= 2
        score_breakdown["2b"] = -2
    
    # 1-2-3
    if one_two_three_tag == "BULL_123":
        bullish_signals.append("123_BUY")
        score += 2
        score_breakdown["123"] = 2
    elif one_two_three_tag == "BEAR_123":
        bearish_signals.append("123_SELL")
        score -= 2
        score_breakdown["123"] = -2
    
    # ────────────────────────────────
    # 成交量验证
    # ────────────────────────────────
    
    volume_confirm = "NEUTRAL"
    
    if len(bullish_signals) > 0:
        if volume_state in ("HIGH", "CLIMAX") and vol_ratio >= 1.5:
            volume_confirm = "CONFIRM"
            score += 1
            score_breakdown["volume"] = 1
            reasons.append("volume_confirms_bullish")
        elif volume_state == "NORMAL":
            volume_confirm = "WEAK"
            reasons.append("volume_weak_for_bullish")
        elif volume_state == "LOW":
            volume_confirm = "CONTRADICT"
            score -= 1
            score_breakdown["volume"] = -1
            reasons.append("volume_contradicts_bullish")
    
    elif len(bearish_signals) > 0:
        if volume_state in ("HIGH", "CLIMAX") and vol_ratio >= 1.5:
            volume_confirm = "CONFIRM"
            score -= 1
            score_breakdown["volume"] = -1
            reasons.append("volume_confirms_bearish")
        elif volume_state == "NORMAL":
            volume_confirm = "WEAK"
            reasons.append("volume_weak_for_bearish")
        elif volume_state == "LOW":
            volume_confirm = "CONTRADICT"
            score += 1
            score_breakdown["volume"] = 1
            reasons.append("volume_contradicts_bearish")
    
    # ────────────────────────────────
    # 最终决策（v2.320优化：基于score映射 + 冲突检测）
    # ────────────────────────────────
    
    exec_bias = "HOLD"
    
    # 情况1：只有多头信号
    if len(bullish_signals) > 0 and len(bearish_signals) == 0:
        # 优先级1: score >= 6 → STRONG_BUY（无需放量）
        if score >= 6:
            exec_bias = "STRONG_BUY"
            reasons.append(f"strong_multi_confirmation:score={score},signals={','.join(bullish_signals)}")
        # 优先级2: score >= 3 → BUY
        elif score >= 3:
            exec_bias = "BUY"
            reasons.append(f"bullish_ok:score={score},signals={','.join(bullish_signals)}")
        # 优先级3: 缩量拦截
        elif volume_confirm == "CONTRADICT":
            exec_bias = "HOLD"
            reasons.append("bullish_structure_but_volume_blocks")
        # 优先级4: 弱信号
        else:
            exec_bias = "BUY"
            reasons.append(f"bullish_weak:score={score},signals={','.join(bullish_signals)}")
    
    # 情况2：只有空头信号
    elif len(bearish_signals) > 0 and len(bullish_signals) == 0:
        # 优先级1: score <= -6 → STRONG_SELL（无需放量）
        if score <= -6:
            exec_bias = "STRONG_SELL"
            reasons.append(f"strong_multi_confirmation:score={score},signals={','.join(bearish_signals)}")
        # 优先级2: score <= -3 → SELL
        elif score <= -3:
            exec_bias = "SELL"
            reasons.append(f"bearish_ok:score={score},signals={','.join(bearish_signals)}")
        # 优先级3: 缩量拦截
        elif volume_confirm == "CONTRADICT":
            exec_bias = "HOLD"
            reasons.append("bearish_structure_but_volume_blocks")
        # 优先级4: 弱信号
        else:
            exec_bias = "SELL"
            reasons.append(f"bearish_weak:score={score},signals={','.join(bearish_signals)}")
    
    # 情况3：信号冲突 ⚠️ CRITICAL
    elif len(bullish_signals) > 0 and len(bearish_signals) > 0:
        exec_bias = "HOLD"
        has_conflict = True  # v2.320: 设置冲突标记
        reasons.append(f"conflicting_signals_bull={bullish_signals}_bear={bearish_signals}")
        reasons.append("⚠️_CONFLICT_DETECTED_HOLD")  # v2.320: 明确标记
    
    # 情况4：无信号
    else:
        # v2.520: 检查 TV 的 pa_edge
        # 如果 TV 已检测到 edge，L2 应该尊重（返回 NEUTRAL）
        # 只有 TV 也没有 edge 时才真正 HOLD
        if pa_edge_buy or pa_edge_sell:
            exec_bias = "NEUTRAL"  # 尊重 L1/TV 的判断
            reasons.append("no_l2_structure_but_tv_has_pa_edge_respect_l1")
            if pa_edge_buy:
                reasons.append("tv_pa_edge_buy=True")
            if pa_edge_sell:
                reasons.append("tv_pa_edge_sell=True")
        else:
            exec_bias = "HOLD"
            reasons.append("no_clear_structure_all_none_and_no_tv_edge")
    
    # v2.320: 返回冲突标记
    return exec_bias, score, score_breakdown, reasons, has_conflict


def compute_l2_exec_bias_ohlcv_full(ohlcv_bars, sr_zone=None, trend_state=None, wyckoff_phase=None, pa_edge_buy=False, pa_edge_sell=False):
    """L2 OHLCV完整分析主函数 (v2.320: 增加冲突标记)"""
    if not ohlcv_bars or len(ohlcv_bars) < 20:
        return {
            "ready": False,
            "exec_bias": "HOLD",
            "pa_tag": "NONE",
            "two_b_tag": "NONE",
            "one_two_three_tag": "NONE",
            "volume_state": "NORMAL",
            "vol_ratio": 1.0,
            "score": 0,
            "score_breakdown": {},
            "reasons": ["insufficient_data"],
            "candle_feat_last": {},
            "has_conflict": False,  # v2.320
        }
    
    candle_feats = compute_candle_features_ohlcv(ohlcv_bars, n_sma=20)
    
    if not candle_feats:
        return {
            "ready": False,
            "exec_bias": "HOLD",
            "pa_tag": "NONE",
            "two_b_tag": "NONE",
            "one_two_three_tag": "NONE",
            "volume_state": "NORMAL",
            "vol_ratio": 1.0,
            "score": 0,
            "score_breakdown": {},
            "reasons": ["candle_features_failed"],
            "candle_feat_last": {},
            "has_conflict": False,  # v2.320
        }
    
    volumes = [b.get('volume', 1000) for b in ohlcv_bars]
    vol_ratio, volume_state = compute_volume_state_ohlcv(volumes, n_sma=20)
    
    pa_tag, pa_reasons = detect_pa_ohlcv(candle_feats, volume_state, vol_ratio)
    two_b_tag, two_b_reasons = detect_2b_ohlcv(candle_feats, volume_state, m_swing=10)
    one_two_three_tag, one_two_three_reasons = detect_123_ohlcv(candle_feats, volume_state, m_swing=15)
    
    # v2.320: merge函数现在返回5个值
    exec_bias, score, score_breakdown, merge_reasons, has_conflict = merge_to_exec_bias_ohlcv(
        pa_tag=pa_tag,
        two_b_tag=two_b_tag,
        one_two_three_tag=one_two_three_tag,
        volume_state=volume_state,
        vol_ratio=vol_ratio,
        sr_zone=sr_zone,
        trend_state=trend_state,
        wyckoff_phase=wyckoff_phase,
        pa_edge_buy=pa_edge_buy,    # v2.520: 传递TV pa_edge
        pa_edge_sell=pa_edge_sell,  # v2.520: 传递TV pa_edge
    )
    
    all_reasons = pa_reasons + two_b_reasons + one_two_three_reasons + merge_reasons
    
    return {
        "ready": True,
        "exec_bias": exec_bias,
        "pa_tag": pa_tag,
        "two_b_tag": two_b_tag,
        "one_two_three_tag": one_two_three_tag,
        "volume_state": volume_state,
        "vol_ratio": round(vol_ratio, 3),
        "score": score,
        "score_breakdown": score_breakdown,
        "reasons": all_reasons,
        "candle_feat_last": candle_feats[-1] if candle_feats else {},
        "has_conflict": has_conflict,  # v2.320: 返回冲突标记
    }


def compute_l2_local_exec_bias(close_prices, volumes):
    """
    基于最近 10~20 根 K 线分析本地 L2 exec_bias。
    包含：PA（价格行为）+ 2B 结构 + 1-2-3 模式 + 成交量状态。
    """
    if len(close_prices) < 10:
        return {
            "ready": False,
            "exec_bias_local": "HOLD",
            "pa_tag_local": "NONE",
            "two_b_tag_local": "NONE",
            "pattern_tag_local": "NONE",
            "volume_state_local": "NORMAL",
        }

    n_ctx = min(len(close_prices), 20)
    n_pattern = min(n_ctx, 15)
    ctx = close_prices[-n_ctx:]
    vols = volumes[-n_ctx:] if volumes else [1.0]*n_ctx

    def trend_state(series):
        if len(series) < 3: return "SIDE"
        change = (series[-1] - series[0]) / max(series[0], 1e-6)
        if change > 0.05: return "STRONG_UP"
        if change > 0.02: return "UP"
        if change < -0.05: return "STRONG_DOWN"
        if change < -0.02: return "DOWN"
        return "SIDE"

    def detect_pa(series):
        if len(series) < 5: return "NONE"
        recent = series[-5:]
        ups = sum(1 for i in range(1,5) if recent[i]>recent[i-1])
        downs = sum(1 for i in range(1,5) if recent[i]<recent[i-1])
        if ups >= 4: return "BULL_PA"
        if downs >= 4: return "BEAR_PA"
        return "NONE"

    def detect_2b(series):
        if len(series) < 5: return "NONE"
        highs = [max(series[i-1:i+2]) for i in range(1,len(series)-1)]
        lows = [min(series[i-1:i+2]) for i in range(1,len(series)-1)]
        if series[-1] > highs[-2] and series[-2] < highs[-3]:
            return "BULL_2B"
        if series[-1] < lows[-2] and series[-2] > lows[-3]:
            return "BEAR_2B"
        return "NONE"

    def detect_123(series):
        if len(series) < 6: return "NONE"
        a,b,c = series[-6], series[-3], series[-1]
        if a>c and b>c and b<a: return "BEAR_123"
        if a<c and b<c and b>a: return "BULL_123"
        return "NONE"

    def detect_volume(vols):
        vm = float(sum(vols)) / max(len(vols), 1)
        v_last = vols[-1]
        if v_last > 1.8 * vm: return "CLIMAX"
        if v_last > 1.2 * vm: return "RISING"
        if v_last < 0.7 * vm: return "FALLING"
        return "NORMAL"

    pa = detect_pa(ctx[-n_pattern:])
    tb = detect_2b(ctx[-n_pattern:])
    pat = detect_123(ctx[-n_pattern:])
    vol = detect_volume(vols)

    trend = trend_state(ctx)

    # 综合评分逻辑
    if trend in ["STRONG_UP", "UP"]:
        if pa=="BULL_PA" or tb=="BULL_2B" or pat=="BULL_123":
            if vol in ["RISING","CLIMAX"]: bias="STRONG_BUY"
            else: bias="BUY"
        else:
            bias="HOLD"
    elif trend in ["STRONG_DOWN","DOWN"]:
        if pa=="BEAR_PA" or tb=="BEAR_2B" or pat=="BEAR_123":
            if vol in ["RISING","CLIMAX"]: bias="STRONG_SELL"
            else: bias="SELL"
        else:
            bias="HOLD"
    else:
        bias="HOLD"

    return {
        "ready": True,
        "exec_bias_local": bias,
        "pa_tag_local": pa,
        "two_b_tag_local": tb,
        "pattern_tag_local": pat,
        "volume_state_local": vol,
    }
# ===== PATCH END: L2_LOCAL_EXEC_BIAS_PATCH =====

# ===== PATCH: L2_SR_FAKE_BREAK_123_2B_HELPER =====
def classify_l2_sr_event(
    price: float,
    support: float,
    mid: float,
    resistance: float,
    zone_tag: str,
    closes: list,
    volumes: list,
    pa_tag: str,
    two_b_tag: str,
    volume_state: str,
    trend_state: str,
    pattern_tag_local: str = "NONE",
    volume_state_local: str = "NORMAL",
) -> str:
    """
    L2: 在 Donchian 支撑/阻力边缘识别假突破/假跌破。

    返回:
        - "FAKE_BREAKDOWN": 支撑附近假跌破
        - "FAKE_BREAKOUT":  阻力附近假突破
        - "NONE":           未识别
    """
    try:
        closes = list(closes or [])
        volumes = list(volumes or [])
    except Exception:
        return "NONE"

    # 至少 6 根 K 线才有意义
    if len(closes) < 6:
        return "NONE"

    # 使用最近 6~8 根 K 线
    ctx = closes[-8:] if len(closes) >= 8 else closes[:]
    last = float(ctx[-1])
    prev = float(ctx[-2]) if len(ctx) >= 2 else last

    rng = max(float(resistance) - float(support), 1e-8)

    # SR 边缘: 距离支撑/阻力 <= 2%% 区间宽度
    eps = 0.02
    near_support = zone_tag in ("LOWER_HALF", "BELOW_SUPPORT") and abs(last - float(support)) / rng <= eps
    near_resist  = zone_tag in ("UPPER_HALF", "ABOVE_RESIST") and abs(last - float(resistance)) / rng <= eps

    if not (near_support or near_resist):
        return "NONE"

    pa_upper = (pa_tag or "").upper()
    tb_upper = (two_b_tag or "").upper()
    pat_local = (pattern_tag_local or "").upper()
    vol_local = (volume_state_local or volume_state or "").upper()

    def _is_bull_struct() -> bool:
        # 包含 BULL_2B / BULL_123 等标签即可认为是多头结构
        return ("BULL" in pa_upper) or ("BULL" in tb_upper) or ("BULL" in pat_local)

    def _is_bear_struct() -> bool:
        return ("BEAR" in pa_upper) or ("BEAR" in tb_upper) or ("BEAR" in pat_local)

    # 简单量能判断：假突破/假跌破常伴随一腿放量
    def _is_punch_volume() -> bool:
        if not volumes:
            return False
        vm = float(sum(volumes)) / max(len(volumes), 1)
        v_last = float(volumes[-1])
        return v_last > 1.5 * vm

    punch_vol = _is_punch_volume()

    # 假跌破: 向下刺破支撑 + 迅速收回 + 多头结构 + 放量
    if near_support:
        broke_down = min(prev, last) < float(support) * (1.0 - 0.003)
        back_in_range = last > float(support)
        if broke_down and back_in_range and _is_bull_struct() and punch_vol:
            return "FAKE_BREAKDOWN"

    # 假突破: 向上刺破阻力 + 迅速收回 + 空头结构 + 放量
    if near_resist:
        broke_up = max(prev, last) > float(resistance) * (1.0 + 0.003)
        back_below = last < float(resistance)
        if broke_up and back_below and _is_bear_struct() and punch_vol:
            return "FAKE_BREAKOUT"

    return "NONE"

# ===== PATCH END: L2_SR_FAKE_BREAK_123_2B_HELPER =====


# ===== v3.550: L2 SR事件增强版 - 假突破"无法重入"规则 =====
def classify_l2_sr_event_v3550(
    price: float,
    support: float,
    mid: float,
    resistance: float,
    zone_tag: str,
    closes: list,
    volumes: list,
    pa_tag: str,
    two_b_tag: str,
    volume_state: str,
    trend_state: str,
    pattern_tag_local: str = "NONE",
    volume_state_local: str = "NORMAL",
    breakout_bars_lookback: int = 5,
) -> dict:
    """
    v3.550: L2 SR事件增强版 - 添加"无法重入"规则

    鲁本威科夫7.12核心规则:
    - 真突破: 突破后"无法重新进入区间" = 连续收盘在区间外
    - 假突破: 突破后多根K线收盘在区间内

    Returns:
        {
            "sr_event": "FAKE_BREAKDOWN" / "FAKE_BREAKOUT" / "TRUE_BREAKOUT" / "TRUE_BREAKDOWN" / "NONE",
            "breakout_quality": "CONFIRMED" / "PENDING" / "FAILED",
            "reentry_detected": bool,
            "bars_outside": int,
            "bars_inside": int,
            "pattern_score_adj": int  # 形态分调整 (-2 to +2)
        }
    """
    result = {
        "sr_event": "NONE",
        "breakout_quality": "PENDING",
        "reentry_detected": False,
        "bars_outside": 0,
        "bars_inside": 0,
        "pattern_score_adj": 0,
    }

    try:
        closes = list(closes or [])
        volumes = list(volumes or [])
    except Exception:
        return result

    if len(closes) < 6:
        return result

    ctx = closes[-8:] if len(closes) >= 8 else closes[:]
    last = float(ctx[-1])
    prev = float(ctx[-2]) if len(ctx) >= 2 else last

    rng = max(float(resistance) - float(support), 1e-8)

    # SR边缘判断
    eps = 0.02
    near_support = zone_tag in ("LOWER_HALF", "BELOW_SUPPORT") and abs(last - float(support)) / rng <= eps
    near_resist = zone_tag in ("UPPER_HALF", "ABOVE_RESIST") and abs(last - float(resistance)) / rng <= eps

    pa_upper = (pa_tag or "").upper()
    tb_upper = (two_b_tag or "").upper()
    pat_local = (pattern_tag_local or "").upper()

    def _is_bull_struct() -> bool:
        return ("BULL" in pa_upper) or ("BULL" in tb_upper) or ("BULL" in pat_local)

    def _is_bear_struct() -> bool:
        return ("BEAR" in pa_upper) or ("BEAR" in tb_upper) or ("BEAR" in pat_local)

    def _is_punch_volume() -> bool:
        if not volumes:
            return False
        vm = float(sum(volumes)) / max(len(volumes), 1)
        v_last = float(volumes[-1])
        return v_last > 1.5 * vm

    punch_vol = _is_punch_volume()

    # ===== v3.550: "无法重入"规则增强 =====

    # 检查是否有突破行为
    if near_support or zone_tag == "BELOW_SUPPORT":
        # 检查向下突破支撑
        broke_down = min(ctx) < float(support) * 0.997
        if broke_down:
            # 使用"无法重入"规则判断真假突破
            reentry_check = check_breakout_reentry_v3550(
                closes, float(support), "DOWN", breakout_bars_lookback
            )
            result["bars_outside"] = reentry_check["bars_outside"]
            result["bars_inside"] = reentry_check["bars_inside"]
            result["reentry_detected"] = reentry_check["reentry_detected"]
            result["breakout_quality"] = reentry_check["breakout_quality"]

            if reentry_check["breakout_quality"] == "FAILED":
                # 假跌破: 收盘重新回到区间内
                result["sr_event"] = "FAKE_BREAKDOWN"
                result["pattern_score_adj"] = 2  # 假跌破后买入信号+2
                if _is_bull_struct():
                    result["pattern_score_adj"] = 2
                print(f"[v3.550] 假跌破确认: bars_inside={reentry_check['bars_inside']} → 形态分+2")
            elif reentry_check["breakout_quality"] == "CONFIRMED":
                # 真跌破: 无法重新进入区间
                result["sr_event"] = "TRUE_BREAKDOWN"
                result["pattern_score_adj"] = -2  # 真跌破卖出信号
                print(f"[v3.550] 真跌破确认: bars_outside={reentry_check['bars_outside']} → 形态分-2")

    if near_resist or zone_tag == "ABOVE_RESIST":
        # 检查向上突破阻力
        broke_up = max(ctx) > float(resistance) * 1.003
        if broke_up:
            reentry_check = check_breakout_reentry_v3550(
                closes, float(resistance), "UP", breakout_bars_lookback
            )
            result["bars_outside"] = reentry_check["bars_outside"]
            result["bars_inside"] = reentry_check["bars_inside"]
            result["reentry_detected"] = reentry_check["reentry_detected"]
            result["breakout_quality"] = reentry_check["breakout_quality"]

            if reentry_check["breakout_quality"] == "FAILED":
                # 假突破: 收盘重新回到区间内
                result["sr_event"] = "FAKE_BREAKOUT"
                result["pattern_score_adj"] = -2  # 假突破后卖出信号
                if _is_bear_struct():
                    result["pattern_score_adj"] = -2
                print(f"[v3.550] 假突破确认: bars_inside={reentry_check['bars_inside']} → 形态分-2")
            elif reentry_check["breakout_quality"] == "CONFIRMED":
                # 真突破: 无法重新进入区间
                result["sr_event"] = "TRUE_BREAKOUT"
                result["pattern_score_adj"] = 2  # 真突破买入信号
                print(f"[v3.550] 真突破确认: bars_outside={reentry_check['bars_outside']} → 形态分+2")

    return result
# ===== v3.550 END =====


# ============================================================================
# v3.420: L2大周期形态外挂 - 双重底/顶 + 头肩底/顶
# ============================================================================

def find_swing_points_for_pattern(ohlcv_bars: list, window: int = 3) -> tuple:
    """
    v3.420: 识别摆点用于形态检测

    Args:
        ohlcv_bars: K线数据列表
        window: 摆点窗口大小

    Returns:
        (swing_highs, swing_lows) - 每个元素是 (index, price)
    """
    if len(ohlcv_bars) < window * 2 + 1:
        return [], []

    highs = [bar.get("high", bar.get("close", 0)) for bar in ohlcv_bars]
    lows = [bar.get("low", bar.get("close", 0)) for bar in ohlcv_bars]

    swing_highs = []
    swing_lows = []

    for i in range(window, len(ohlcv_bars) - window):
        # Swing High: 比前后window根K线的高点都高
        if highs[i] == max(highs[i-window:i+window+1]):
            swing_highs.append((i, highs[i]))

        # Swing Low: 比前后window根K线的低点都低
        if lows[i] == min(lows[i-window:i+window+1]):
            swing_lows.append((i, lows[i]))

    return swing_highs, swing_lows


def detect_reversal_patterns(ohlcv_bars: list, volumes: list, tolerance: float = 0.05) -> dict:
    """
    v3.420: 形态外挂主函数

    检测顺序（按信号强度）:
    1. 头肩底 - 最强买入信号
    2. 头肩顶 - 最强卖出信号
    3. 双重底 - 次强买入信号
    4. 双重顶 - 次强卖出信号

    Args:
        ohlcv_bars: K线数据列表
        volumes: 成交量列表
        tolerance: 偏差容忍度（默认5%）

    Returns:
        {
            "pattern": "DOUBLE_BOTTOM" | "DOUBLE_TOP" | "HS_BOTTOM" | "HS_TOP" | None,
            "signal": "BUY" | "SELL" | "HOLD",
            "stage": "FORMING" | "BREAKOUT" | "PULLBACK",
            "quality_score": 1-3,
            "neckline": float,
            "target": float,
            "score_adjustment": int,
            "details": {...}
        }
    """
    result = {
        "pattern": None,
        "signal": "HOLD",
        "stage": None,
        "quality_score": 1,
        "neckline": None,
        "target": None,
        "score_adjustment": 0,
        "details": {}
    }

    if not ohlcv_bars or len(ohlcv_bars) < 25:
        return result

    # 只使用最近80根K线，避免检测太老的形态
    max_lookback = 80
    bars = ohlcv_bars[-max_lookback:] if len(ohlcv_bars) > max_lookback else ohlcv_bars
    vols = volumes[-max_lookback:] if volumes and len(volumes) > max_lookback else (volumes or [])

    # 识别摆点
    swing_highs, swing_lows = find_swing_points_for_pattern(bars, window=3)

    closes = [bar.get("close", 0) for bar in bars]
    highs = [bar.get("high", bar.get("close", 0)) for bar in bars]
    lows = [bar.get("low", bar.get("close", 0)) for bar in bars]
    current_price = closes[-1] if closes else 0

    # 按优先级检测

    # 1. 头肩底检测 (最强买入)
    if len(swing_lows) >= 3:
        hs_bottom = _detect_hs_bottom_v3420(
            swing_lows, swing_highs, highs, lows, closes, vols, current_price, tolerance
        )
        if hs_bottom["pattern"]:
            return hs_bottom

    # 2. 头肩顶检测 (最强卖出)
    if len(swing_highs) >= 3:
        hs_top = _detect_hs_top_v3420(
            swing_highs, swing_lows, highs, lows, closes, vols, current_price, tolerance
        )
        if hs_top["pattern"]:
            return hs_top

    # 3. 双重底检测
    if len(swing_lows) >= 2:
        double_bottom = _detect_double_bottom_v3420(
            swing_lows, highs, lows, closes, vols, current_price, tolerance
        )
        if double_bottom["pattern"]:
            return double_bottom

    # 4. 双重顶检测
    if len(swing_highs) >= 2:
        double_top = _detect_double_top_v3420(
            swing_highs, highs, lows, closes, vols, current_price, tolerance
        )
        if double_top["pattern"]:
            return double_top

    return result


# ========================================================================
# v3.440: 形神分析法 (来源: 量价理论第3集)
# ========================================================================
def _analyze_form_spirit_v3440(bars: list, lookback: int = 20) -> dict:
    """
    v3.440: 形神分析法

    来源: 量价理论第3集

    形(K线流畅度):
        - 影线比率 < 0.5 = 流畅
        - 波动率(ATR/价格) < 2% = 稳定

    神(成交量均衡):
        - 变异系数 < 0.3 = 均衡
        - 无爆量(>2倍均量) = 稳定

    四种状态:
        - 形神兼备: 可交易，主力控盘良好
        - 形散神聚: 回避，阶段顶部特征
        - 形不散神散: 回避，诱多出货特征
        - 形神皆散: 观望，无主力控盘

    Returns:
        {
            "form_score": 1-3,
            "spirit_score": 1-3,
            "state": str,
            "tradeable": bool,
            "quality_multiplier": float,
            "warning": str or None
        }
    """
    result = {
        "form_score": 2,
        "spirit_score": 2,
        "state": "形神兼备",
        "tradeable": True,
        "quality_multiplier": 1.0,
        "warning": None
    }

    if not bars or len(bars) < lookback:
        return result

    recent = bars[-lookback:]

    # ===== 形(K线流畅度) =====
    shadow_ratios = []
    true_ranges = []
    closes = []

    for i, bar in enumerate(recent):
        o = float(bar.get('open', bar.get('o', 0)))
        h = float(bar.get('high', bar.get('h', 0)))
        l = float(bar.get('low', bar.get('l', 0)))
        c = float(bar.get('close', bar.get('c', 0)))

        if c <= 0 or h <= 0:
            continue

        closes.append(c)

        # 影线比率
        body = abs(c - o)
        upper_shadow = h - max(c, o)
        lower_shadow = min(c, o) - l
        if body > 0:
            shadow_ratios.append((upper_shadow + lower_shadow) / body)

        # True Range
        if i > 0:
            prev_c = float(recent[i-1].get('close', recent[i-1].get('c', 0)))
            tr = max(h - l, abs(h - prev_c), abs(l - prev_c))
            true_ranges.append(tr)

    # 平均影线比率
    avg_shadow_ratio = sum(shadow_ratios) / len(shadow_ratios) if shadow_ratios else 0

    # 波动率 (ATR / 价格)
    atr = sum(true_ranges) / len(true_ranges) if true_ranges else 0
    avg_price = sum(closes) / len(closes) if closes else 1
    volatility = atr / avg_price if avg_price > 0 else 0

    # 形评分
    if avg_shadow_ratio < 0.5 and volatility < 0.02:
        form_score = 3  # 形不散
    elif avg_shadow_ratio < 1.0 and volatility < 0.04:
        form_score = 2  # 形中等
    else:
        form_score = 1  # 形散

    # ===== 神(成交量均衡) =====
    volumes = []
    for bar in recent:
        v = float(bar.get('volume', bar.get('v', 0)))
        if v > 0:
            volumes.append(v)

    if volumes:
        vol_mean = sum(volumes) / len(volumes)
        vol_variance = sum((v - vol_mean) ** 2 for v in volumes) / len(volumes)
        vol_std = vol_variance ** 0.5
        vol_cv = vol_std / vol_mean if vol_mean > 0 else 0  # 变异系数

        # 检测爆量 (>2倍均量)
        spike_count = sum(1 for v in volumes if v > vol_mean * 2)

        # 神评分
        if vol_cv < 0.3 and spike_count == 0:
            spirit_score = 3  # 神不散
        elif vol_cv < 0.6 and spike_count <= 2:
            spirit_score = 2  # 神中等
        else:
            spirit_score = 1  # 神散
    else:
        spirit_score = 2  # 无量能数据，默认中等

    # ===== 状态判定 =====
    if form_score >= 2 and spirit_score >= 2:
        state = "形神兼备"
        tradeable = True
        quality_multiplier = 1.0 + (form_score + spirit_score - 4) * 0.1  # 1.0 ~ 1.2
        warning = None
    elif form_score <= 1 and spirit_score >= 2:
        state = "形散神聚"
        tradeable = False
        quality_multiplier = 0.5
        warning = "阶段顶部特征，主力失控，回避"
    elif form_score >= 2 and spirit_score <= 1:
        state = "形不散神散"
        tradeable = False
        quality_multiplier = 0.3
        warning = "诱多出货特征，风险极高，回避"
    else:
        state = "形神皆散"
        tradeable = False
        quality_multiplier = 0.5
        warning = "无主力控盘，观望"

    result.update({
        "form_score": form_score,
        "spirit_score": spirit_score,
        "state": state,
        "tradeable": tradeable,
        "quality_multiplier": quality_multiplier,
        "warning": warning,
        "details": {
            "avg_shadow_ratio": round(avg_shadow_ratio, 2),
            "volatility": f"{volatility*100:.2f}%",
            "vol_cv": round(vol_cv, 2) if volumes else "N/A",
            "spike_count": spike_count if volumes else 0
        }
    })

    return result


# ========================================================================
# v3.492: L2量价异常检测 (来源: 量价理论第20-29集、第43-44集)
# ========================================================================

def _detect_volume_anomaly_v3492(bars: list, position: float = 0.5, lookback: int = 20) -> dict:
    """
    v3.492: L2量价异常综合检测

    来源:
        - 第21集: 巨量十字星检测
        - 第21集: "头上三柱香"检测
        - 第29集: 脉冲量陷阱检测
        - 第29集: 量堆式下跌风险检测
        - 第43集: 双重顶量价背离
        - 第28集: 平衡量过滤器

    Args:
        bars: OHLCV K线数据
        position: 当前位置 (0=最低, 1=最高)
        lookback: 回溯K线数量

    Returns:
        {
            "anomalies": list,           # 检测到的异常列表
            "risk_score": 0-100,         # 风险分数
            "buy_penalty": 0-6,          # 买入惩罚分
            "sell_bonus": 0-6,           # 卖出奖励分
            "warning": str or None,      # 警告信息
            "details": dict              # 详细信息
        }
    """
    result = {
        "anomalies": [],
        "risk_score": 0,
        "buy_penalty": 0,
        "sell_bonus": 0,
        "warning": None,
        "details": {}
    }

    if not bars or len(bars) < lookback:
        return result

    recent = bars[-lookback:]

    # 提取OHLCV数据
    opens, highs, lows, closes, volumes = [], [], [], [], []
    for bar in recent:
        o = float(bar.get('open', bar.get('o', 0)))
        h = float(bar.get('high', bar.get('h', 0)))
        l = float(bar.get('low', bar.get('l', 0)))
        c = float(bar.get('close', bar.get('c', 0)))
        v = float(bar.get('volume', bar.get('v', 0)))
        if c > 0 and v > 0:
            opens.append(o)
            highs.append(h)
            lows.append(l)
            closes.append(c)
            volumes.append(v)

    if len(closes) < 10:
        return result

    avg_vol = sum(volumes) / len(volumes)
    anomalies = []
    risk_score = 0
    buy_penalty = 0
    sell_bonus = 0

    # ===== 1. 巨量十字星检测 (第21集) =====
    # 条件: 高位 + 十字星(实体<振幅*0.33) + 巨量(>=2倍均量)
    last_bar = recent[-1]
    last_o = float(last_bar.get('open', last_bar.get('o', 0)))
    last_h = float(last_bar.get('high', last_bar.get('h', 0)))
    last_l = float(last_bar.get('low', last_bar.get('l', 0)))
    last_c = float(last_bar.get('close', last_bar.get('c', 0)))
    last_v = float(last_bar.get('volume', last_bar.get('v', 0)))

    last_body = abs(last_c - last_o)
    last_range = last_h - last_l if last_h > last_l else 0.0001
    is_doji = last_body < last_range * 0.33
    is_huge_volume = last_v >= avg_vol * 2

    if position > 0.8 and is_doji and is_huge_volume:
        anomalies.append("巨量十字星")
        risk_score += 30
        buy_penalty += 3
        sell_bonus += 2
        result["details"]["huge_volume_doji"] = {
            "body_ratio": round(last_body / last_range, 2),
            "volume_ratio": round(last_v / avg_vol, 1)
        }

    # ===== 2. "头上三柱香"检测 (第21集) =====
    # 条件: 高位 + 连续>=3根长上影线(上影线>实体*2)
    if len(recent) >= 3 and position > 0.75:
        long_upper_shadow_count = 0
        for bar in recent[-5:]:  # 检查最近5根
            o = float(bar.get('open', bar.get('o', 0)))
            h = float(bar.get('high', bar.get('h', 0)))
            c = float(bar.get('close', bar.get('c', 0)))
            body = abs(c - o) if abs(c - o) > 0 else 0.0001
            upper_shadow = h - max(c, o)
            if upper_shadow > body * 2:
                long_upper_shadow_count += 1

        if long_upper_shadow_count >= 3:
            anomalies.append("头上三柱香")
            risk_score += 40
            buy_penalty += 4
            sell_bonus += 3
            result["details"]["three_incense"] = {
                "count": long_upper_shadow_count
            }

    # ===== 3. 脉冲量陷阱检测 (第29集) =====
    # 条件: 单根K线巨量(>=3倍均量) + 上涨 + 后续无量堆跟随
    for i in range(max(0, len(recent)-5), len(recent)-1):  # 检查最近5根(不含最后一根)
        bar = recent[i]
        v = float(bar.get('volume', bar.get('v', 0)))
        o = float(bar.get('open', bar.get('o', 0)))
        c = float(bar.get('close', bar.get('c', 0)))

        if v >= avg_vol * 3 and c > o:  # 巨量阳线
            # 检查后续是否有量堆跟随
            subsequent_bars = recent[i+1:]
            if subsequent_bars:
                subsequent_vol_avg = sum(float(b.get('volume', b.get('v', 0))) for b in subsequent_bars) / len(subsequent_bars)
                if subsequent_vol_avg < avg_vol * 1.5:  # 后续量能萎缩
                    anomalies.append("脉冲量陷阱")
                    risk_score += 25
                    buy_penalty += 2
                    result["details"]["pulse_trap"] = {
                        "pulse_volume_ratio": round(v / avg_vol, 1),
                        "subsequent_volume_ratio": round(subsequent_vol_avg / avg_vol, 1)
                    }
                    break

    # ===== 4. 量堆式下跌风险检测 (第29集) =====
    # 条件: 连续>=3根下跌K线 + 成交量呈放大趋势
    if len(recent) >= 3:
        down_count = 0
        vol_increasing = True
        for i in range(len(recent)-3, len(recent)):
            bar = recent[i]
            c = float(bar.get('close', bar.get('c', 0)))
            o = float(bar.get('open', bar.get('o', 0)))
            v = float(bar.get('volume', bar.get('v', 0)))

            if c < o:  # 阴线
                down_count += 1

            if i > len(recent)-3:
                prev_v = float(recent[i-1].get('volume', recent[i-1].get('v', 0)))
                if v < prev_v * 0.9:  # 量能未放大
                    vol_increasing = False

        if down_count >= 3 and vol_increasing:
            anomalies.append("量堆式下跌")
            risk_score += 35
            buy_penalty += 4
            result["details"]["volume_pile_down"] = {
                "consecutive_down": down_count
            }

    # ===== 5. 平衡量过滤器 (第28集) =====
    # 条件: 成交量标准差 > 均值*0.6 = 量能不均衡
    if volumes:
        vol_std = (sum((v - avg_vol) ** 2 for v in volumes) / len(volumes)) ** 0.5
        vol_cv = vol_std / avg_vol if avg_vol > 0 else 0

        if vol_cv > 0.6:
            anomalies.append("量能不均衡")
            risk_score += 15
            buy_penalty += 1
            result["details"]["volume_imbalance"] = {
                "cv": round(vol_cv, 2)
            }

    # ===== 6. 高位巨量阴线 (第2集) =====
    # 条件: 高位 + 巨量(>=2倍均量) + 大阴线(跌幅>=3%)
    if position > 0.75:
        change_pct = (last_c - last_o) / last_o * 100 if last_o > 0 else 0
        if is_huge_volume and change_pct <= -3:
            anomalies.append("高位巨量阴线")
            risk_score += 45
            buy_penalty += 5
            sell_bonus += 3
            result["details"]["huge_volume_red_bar"] = {
                "change_pct": round(change_pct, 1),
                "volume_ratio": round(last_v / avg_vol, 1)
            }

    # ===== 汇总结果 =====
    result["anomalies"] = anomalies
    result["risk_score"] = min(risk_score, 100)
    result["buy_penalty"] = min(buy_penalty, 6)
    result["sell_bonus"] = min(sell_bonus, 6)

    if anomalies:
        result["warning"] = f"检测到量价异常: {', '.join(anomalies)}"

    return result


def _detect_pattern_volume_divergence_v3492(bars: list, pattern_type: str, lookback: int = 30) -> dict:
    """
    v3.492: 形态量价背离检测 (增强双重顶/头肩顶)

    来源:
        - 第43集: 双重顶量价背离 (右峰缩量)
        - 第44集: 头肩顶量能衰竭 (头部/右肩缩量)
        - 第20集: 巨量吞噬线量能验证

    Args:
        bars: OHLCV K线数据
        pattern_type: 形态类型 ("double_top", "head_shoulders_top", "engulfing")
        lookback: 回溯K线数量

    Returns:
        {
            "has_divergence": bool,
            "divergence_strength": 0-1,   # 背离强度
            "quality_adjustment": -3 to 3, # 质量调整分
            "details": dict
        }
    """
    result = {
        "has_divergence": False,
        "divergence_strength": 0,
        "quality_adjustment": 0,
        "details": {}
    }

    if not bars or len(bars) < lookback:
        return result

    recent = bars[-lookback:]

    # 提取数据
    highs, lows, closes, volumes = [], [], [], []
    for bar in recent:
        h = float(bar.get('high', bar.get('h', 0)))
        l = float(bar.get('low', bar.get('l', 0)))
        c = float(bar.get('close', bar.get('c', 0)))
        v = float(bar.get('volume', bar.get('v', 0)))
        if c > 0 and v > 0:
            highs.append(h)
            lows.append(l)
            closes.append(c)
            volumes.append(v)

    if len(highs) < 10:
        return result

    # ===== 双重顶量价背离 (第43集) =====
    if pattern_type == "double_top":
        # 寻找两个高点
        mid = len(highs) // 2
        left_half_max_idx = highs[:mid].index(max(highs[:mid]))
        right_half_max_idx = mid + highs[mid:].index(max(highs[mid:]))

        left_peak_vol = sum(volumes[max(0, left_half_max_idx-2):left_half_max_idx+3]) / 5 if left_half_max_idx >= 2 else volumes[left_half_max_idx]
        right_peak_vol = sum(volumes[max(0, right_half_max_idx-2):right_half_max_idx+3]) / 5 if right_half_max_idx >= 2 else volumes[right_half_max_idx]

        # 右峰缩量 = 量价背离
        if right_peak_vol < left_peak_vol * 0.7:
            result["has_divergence"] = True
            result["divergence_strength"] = 1 - (right_peak_vol / left_peak_vol)
            result["quality_adjustment"] = 2  # 增加SELL信号质量
            result["details"]["double_top_divergence"] = {
                "left_vol": round(left_peak_vol, 0),
                "right_vol": round(right_peak_vol, 0),
                "ratio": round(right_peak_vol / left_peak_vol, 2) if left_peak_vol > 0 else 0
            }

    # ===== 头肩顶量能衰竭 (第44集) =====
    elif pattern_type == "head_shoulders_top":
        # 简化: 分三段检测
        third = len(volumes) // 3
        left_vol = sum(volumes[:third]) / third if third > 0 else 0
        head_vol = sum(volumes[third:2*third]) / third if third > 0 else 0
        right_vol = sum(volumes[2*third:]) / third if third > 0 else 0

        # 量能依次衰竭
        if head_vol < left_vol * 0.8 or right_vol < head_vol * 0.8:
            result["has_divergence"] = True
            result["divergence_strength"] = 1 - min(head_vol / left_vol if left_vol > 0 else 1,
                                                     right_vol / head_vol if head_vol > 0 else 1)
            result["quality_adjustment"] = 2
            result["details"]["hst_volume_decay"] = {
                "left_vol": round(left_vol, 0),
                "head_vol": round(head_vol, 0),
                "right_vol": round(right_vol, 0)
            }

    # ===== 巨量吞噬线量能验证 (第20集) =====
    elif pattern_type == "engulfing":
        avg_vol = sum(volumes) / len(volumes)
        last_vol = volumes[-1] if volumes else 0

        # 做多: 需1.5倍均量; 做空: 需2倍均量
        if last_vol >= avg_vol * 1.5:
            result["has_divergence"] = False  # 量能充足，不是背离
            result["quality_adjustment"] = 1  # 增加信号质量
            result["details"]["engulfing_volume"] = {
                "ratio": round(last_vol / avg_vol, 1),
                "sufficient": True
            }
        else:
            result["has_divergence"] = True  # 量能不足
            result["quality_adjustment"] = -2  # 降低信号质量
            result["details"]["engulfing_volume"] = {
                "ratio": round(last_vol / avg_vol, 1),
                "sufficient": False
            }

    return result


# ========================================================================
# v3.440: MACD背驰检测 (来源: 缠论第11集)
# ========================================================================
def _detect_macd_divergence_v3440(bars: list, trend: str, lookback: int = 30) -> dict:
    """
    v3.440: MACD背驰检测

    来源: 缠论第11集

    关键规则: "无趋势无背驰" - 盘整中不检测背驰

    顶背驰(bearish): 价格新高但MACD未新高 → 趋势可能反转下跌
    底背驰(bullish): 价格新低但MACD未新低 → 趋势可能反转上涨

    Returns:
        {
            "has_divergence": bool,
            "divergence_type": "bullish" / "bearish" / None,
            "strength": 0-1,
            "warning": str or None
        }
    """
    result = {
        "has_divergence": False,
        "divergence_type": None,
        "strength": 0,
        "warning": None
    }

    # 规则: 盘整中不检测背驰 ("无趋势无背驰")
    if trend in ["SIDE", "RANGING", "side", "ranging"]:
        result["warning"] = "盘整中无背驰(缠论规则)"
        return result

    if not bars or len(bars) < 35:  # MACD(12,26,9)需要至少35根K线
        result["warning"] = "K线数据不足，无法计算MACD"
        return result

    # 提取收盘价
    closes = []
    for bar in bars:
        c = float(bar.get('close', bar.get('c', 0)))
        if c > 0:
            closes.append(c)

    if len(closes) < 35:
        result["warning"] = "有效K线数据不足"
        return result

    # 计算MACD (12, 26, 9)
    def ema(data, period):
        if len(data) < period:
            return [sum(data) / len(data)] * len(data)
        multiplier = 2 / (period + 1)
        ema_values = [sum(data[:period]) / period]
        for i in range(period, len(data)):
            ema_values.append((data[i] - ema_values[-1]) * multiplier + ema_values[-1])
        # 补齐前面的值
        return [ema_values[0]] * (period - 1) + ema_values

    ema12 = ema(closes, 12)
    ema26 = ema(closes, 26)
    macd_line = [ema12[i] - ema26[i] for i in range(len(closes))]
    signal_line = ema(macd_line, 9)
    histogram = [macd_line[i] - signal_line[i] for i in range(len(macd_line))]

    # 检测最近lookback根K线的高低点
    recent_closes = closes[-lookback:]
    recent_hist = histogram[-lookback:]

    # 找局部高点和低点 (窗口=5)
    def find_swing_points(data, window=5):
        highs = []
        lows = []
        for i in range(window, len(data) - window):
            if data[i] == max(data[i-window:i+window+1]):
                highs.append((i, data[i]))
            if data[i] == min(data[i-window:i+window+1]):
                lows.append((i, data[i]))
        return highs, lows

    price_highs, price_lows = find_swing_points(recent_closes)
    hist_highs, hist_lows = find_swing_points(recent_hist)

    divergence_type = None
    strength = 0

    # 上涨趋势中检测顶背驰
    if trend.upper() in ["UP", "TREND_UP"]:
        if len(price_highs) >= 2 and len(hist_highs) >= 2:
            # 价格新高
            price_higher = price_highs[-1][1] > price_highs[-2][1]
            # MACD未新高
            macd_higher = hist_highs[-1][1] > hist_highs[-2][1]

            if price_higher and not macd_higher:
                divergence_type = "bearish"
                price_diff = (price_highs[-1][1] - price_highs[-2][1]) / price_highs[-2][1] if price_highs[-2][1] > 0 else 0
                macd_diff = (hist_highs[-2][1] - hist_highs[-1][1]) / abs(hist_highs[-2][1]) if hist_highs[-2][1] != 0 else 0
                strength = min(abs(price_diff) + abs(macd_diff), 1.0)

    # 下跌趋势中检测底背驰
    elif trend.upper() in ["DOWN", "TREND_DOWN"]:
        if len(price_lows) >= 2 and len(hist_lows) >= 2:
            # 价格新低
            price_lower = price_lows[-1][1] < price_lows[-2][1]
            # MACD未新低
            macd_lower = hist_lows[-1][1] < hist_lows[-2][1]

            if price_lower and not macd_lower:
                divergence_type = "bullish"
                price_diff = (price_lows[-2][1] - price_lows[-1][1]) / price_lows[-2][1] if price_lows[-2][1] > 0 else 0
                macd_diff = (hist_lows[-1][1] - hist_lows[-2][1]) / abs(hist_lows[-2][1]) if hist_lows[-2][1] != 0 else 0
                strength = min(abs(price_diff) + abs(macd_diff), 1.0)

    # 生成警告
    warning = None
    if divergence_type == "bearish":
        warning = f"顶背驰预警: 趋势可能反转下跌 (强度{strength*100:.0f}%)"
    elif divergence_type == "bullish":
        warning = f"底背驰预警: 趋势可能反转上涨 (强度{strength*100:.0f}%)"

    result.update({
        "has_divergence": divergence_type is not None,
        "divergence_type": divergence_type,
        "strength": round(strength, 2),
        "warning": warning
    })

    return result


def _detect_double_bottom_v3420(
    swing_lows: list, highs: list, lows: list, closes: list,
    volumes: list, current_price: float, tolerance: float
) -> dict:
    """
    v3.420: 双重底检测

    规则:
    1. 两谷底偏差 ≤ 5%
    2. 右谷相对左谷缩量或持平 → 高质量
    3. 突破颈线温和放量（不过分）
    """
    result = {"pattern": None, "signal": "HOLD", "stage": None, "quality_score": 1,
              "neckline": None, "target": None, "score_adjustment": 0, "details": {}}

    # 取最近两个低点
    left_idx, left_low = swing_lows[-2]
    right_idx, right_low = swing_lows[-1]

    # 摆点间距检查（不超过30根K线）
    if right_idx - left_idx > 30:
        return result

    # 偏差检查
    if left_low <= 0:
        return result
    deviation = abs(right_low - left_low) / left_low
    if deviation > tolerance:
        return result

    # 颈线: 两低点之间最高点
    if right_idx <= left_idx:
        return result
    mid_section = highs[left_idx:right_idx+1]
    if not mid_section:
        return result
    neckline = max(mid_section)

    # 颈线需显著高于谷底（至少3%）
    avg_low = (left_low + right_low) / 2
    if avg_low <= 0 or (neckline - avg_low) / avg_low < 0.03:
        return result

    # ===== v3.440: 右底更圆润检测 (来源: 量价理论第42集) =====
    # 圆润 = 下跌斜率更缓，表示卖压减弱
    right_more_rounded = False
    try:
        # 计算左谷下跌斜率：左谷前3根K线的平均下跌幅度
        if left_idx >= 3:
            left_pre_prices = closes[left_idx-3:left_idx]
            if left_pre_prices and max(left_pre_prices) > left_low:
                left_slope = (max(left_pre_prices) - left_low) / max(left_pre_prices)
            else:
                left_slope = 0
        else:
            left_slope = 0

        # 计算右谷下跌斜率
        if right_idx >= 3:
            right_pre_prices = closes[right_idx-3:right_idx]
            if right_pre_prices and max(right_pre_prices) > right_low:
                right_slope = (max(right_pre_prices) - right_low) / max(right_pre_prices)
            else:
                right_slope = 0
        else:
            right_slope = 0

        # 右底更圆润 = 右侧下跌斜率更小（卖压减弱）
        if left_slope > 0 and right_slope < left_slope * 0.9:  # 右侧斜率比左侧小10%以上
            right_more_rounded = True
    except Exception:
        pass
    # ===== v3.440 END: 右底更圆润检测 =====

    # ===== 量价验证 =====
    vol_ma = sum(volumes[-20:]) / 20 if volumes and len(volumes) >= 20 else (sum(volumes) / len(volumes) if volumes else 1)

    # 左谷量能
    left_vol_start = max(0, left_idx - 3)
    left_vol_end = min(len(volumes), left_idx + 3)
    left_vol = sum(volumes[left_vol_start:left_vol_end]) / max(1, left_vol_end - left_vol_start) if volumes else vol_ma

    # 右谷量能
    right_vol_start = max(0, right_idx - 3)
    right_vol_end = min(len(volumes), right_idx + 3)
    right_vol = sum(volumes[right_vol_start:right_vol_end]) / max(1, right_vol_end - right_vol_start) if volumes else vol_ma

    # 当前量能
    current_vol = volumes[-1] if volumes else vol_ma

    # 右底缩量 = 高质量
    right_shrink = right_vol <= left_vol * 1.1

    # ===== 判断阶段和质量分 =====
    quality_score = 1
    stage = "FORMING"
    signal = "HOLD"
    score_adjustment = 0

    # v3.440: 右底更圆润+缩量 = 高质量
    if right_shrink and right_more_rounded:
        quality_score = 3  # 最高质量
    elif right_shrink:
        quality_score = 2
    elif right_more_rounded:
        quality_score = 2  # 仅圆润也算中等质量

    # 突破颈线
    if current_price > neckline:
        stage = "BREAKOUT"
        breakout_vol = current_vol > vol_ma * 1.3
        not_excessive = current_vol < left_vol * 2.0 if left_vol > 0 else True

        if breakout_vol and not_excessive and right_shrink:
            quality_score = 3
            signal = "BUY"
            score_adjustment = 8  # 高质量突破 +8分
        elif breakout_vol and right_shrink:
            quality_score = 2
            signal = "BUY"
            score_adjustment = 6
        elif right_shrink:
            signal = "BUY"
            score_adjustment = 4
        else:
            signal = "BUY"
            score_adjustment = 3

    # 回踩判断
    elif current_price > neckline * 0.97 and len(closes) >= 10 and max(closes[-10:]) > neckline:
        stage = "PULLBACK"
        pullback_shrink = current_vol < vol_ma * 0.8
        if pullback_shrink:
            quality_score = min(quality_score + 1, 3)
            signal = "BUY"
            score_adjustment = 5
        else:
            signal = "HOLD"
            score_adjustment = 2

    # 形成中
    elif current_price > right_low:
        stage = "FORMING"
        score_adjustment = 2 if right_shrink else 1

    # 目标价: 颈线² / 谷底均价
    target = (neckline ** 2) / avg_low if avg_low > 0 else neckline * 1.1

    result.update({
        "pattern": "DOUBLE_BOTTOM",
        "signal": signal,
        "stage": stage,
        "quality_score": quality_score,
        "neckline": round(neckline, 2),
        "target": round(target, 2),
        "score_adjustment": score_adjustment,
        "details": {
            "left_low": round(left_low, 2),
            "right_low": round(right_low, 2),
            "deviation": f"{deviation*100:.1f}%",
            "right_shrink": right_shrink,
            "right_more_rounded": right_more_rounded,  # v3.440: 右底圆润度
            "vol_ratio": f"{right_vol/left_vol:.1%}" if left_vol > 0 else "N/A"
        }
    })

    return result


def _detect_double_top_v3420(
    swing_highs: list, highs: list, lows: list, closes: list,
    volumes: list, current_price: float, tolerance: float
) -> dict:
    """
    v3.420: 双重顶检测

    规则:
    1. 两峰顶偏差 ≤ 5%
    2. 右峰相对左峰明显缩量 (<70%) - 必须条件
    3. 跌破颈线不需放量
    """
    result = {"pattern": None, "signal": "HOLD", "stage": None, "quality_score": 1,
              "neckline": None, "target": None, "score_adjustment": 0, "details": {}}

    left_idx, left_high = swing_highs[-2]
    right_idx, right_high = swing_highs[-1]

    # 摆点间距检查
    if right_idx - left_idx > 30:
        return result

    if left_high <= 0:
        return result
    deviation = abs(right_high - left_high) / left_high
    if deviation > tolerance:
        return result

    # 颈线
    if right_idx <= left_idx:
        return result
    mid_section = lows[left_idx:right_idx+1]
    if not mid_section:
        return result
    neckline = min(mid_section)

    avg_high = (left_high + right_high) / 2
    if avg_high <= 0 or (avg_high - neckline) / avg_high < 0.03:
        return result

    # ===== 关键: 右峰必须缩量 =====
    left_vol_start = max(0, left_idx - 5)
    left_vol_end = min(len(volumes) if volumes else 0, left_idx + 3)
    left_vol = sum(volumes[left_vol_start:left_vol_end]) if volumes and left_vol_end > left_vol_start else 1

    right_vol_start = max(0, right_idx - 5)
    right_vol_end = min(len(volumes) if volumes else 0, right_idx + 3)
    right_vol = sum(volumes[right_vol_start:right_vol_end]) if volumes and right_vol_end > right_vol_start else 1

    # 右峰没有明显缩量 → 不是有效双顶
    if left_vol > 0 and right_vol >= left_vol * 0.7:
        return result

    # 判断阶段
    quality_score = 2  # 满足缩量条件，基础分2
    stage = "FORMING"
    signal = "HOLD"
    score_adjustment = 0

    if current_price < neckline:
        stage = "BREAKOUT"
        quality_score = 3
        signal = "SELL"
        score_adjustment = -8
    elif current_price < neckline * 1.02:
        stage = "FORMING"
        signal = "SELL"
        score_adjustment = -5
    else:
        # 形神聚散检测
        if len(closes) >= 5:
            recent_bars = closes[-5:]
            price_range = max(recent_bars) - min(recent_bars)
            avg_price = sum(recent_bars) / len(recent_bars)
            price_std = price_range / avg_price if avg_price > 0 else 0
            if price_std > 0.03:  # K线波动大
                signal = "SELL"
                score_adjustment = -3

    mid_point = (left_high + right_high) / 2
    target = (neckline ** 2) / mid_point if mid_point > 0 else neckline * 0.9

    result.update({
        "pattern": "DOUBLE_TOP",
        "signal": signal,
        "stage": stage,
        "quality_score": quality_score,
        "neckline": round(neckline, 2),
        "target": round(target, 2),
        "score_adjustment": score_adjustment,
        "details": {
            "left_high": round(left_high, 2),
            "right_high": round(right_high, 2),
            "deviation": f"{deviation*100:.1f}%",
            "vol_ratio": f"{right_vol/left_vol:.1%}" if left_vol > 0 else "N/A"
        }
    })

    return result


def _detect_hs_bottom_v3420(
    swing_lows: list, swing_highs: list, highs: list, lows: list,
    closes: list, volumes: list, current_price: float, tolerance: float
) -> dict:
    """
    v3.420: 头肩底检测 - 最强买入信号

    规则:
    1. 左肩-头部-右肩结构，头部最低
    2. 左右肩偏差 ≤ 5%
    3. 头部反弹放量
    4. 突破颈线放量
    """
    result = {"pattern": None, "signal": "HOLD", "stage": None, "quality_score": 1,
              "neckline": None, "target": None, "score_adjustment": 0, "details": {}}

    # 取最近三个低点
    left_idx, left_shoulder = swing_lows[-3]
    head_idx, head = swing_lows[-2]
    right_idx, right_shoulder = swing_lows[-1]

    # 摆点间距检查
    if right_idx - left_idx > 40:
        return result

    # 头部必须最低
    if head >= left_shoulder or head >= right_shoulder:
        return result

    # 左右肩偏差
    if left_shoulder <= 0:
        return result
    shoulder_deviation = abs(right_shoulder - left_shoulder) / left_shoulder
    if shoulder_deviation > tolerance:
        return result

    # 颈线（两肩反弹高点平均值）
    left_peak = max(highs[left_idx:head_idx+1]) if head_idx > left_idx else highs[left_idx] if left_idx < len(highs) else 0
    right_peak = max(highs[head_idx:right_idx+1]) if right_idx > head_idx else highs[head_idx] if head_idx < len(highs) else 0

    if left_peak <= 0 or right_peak <= 0:
        return result
    neckline = (left_peak + right_peak) / 2

    # 量价验证
    vol_ma = sum(volumes[-20:]) / 20 if volumes and len(volumes) >= 20 else (sum(volumes) / len(volumes) if volumes else 1)

    # 头部反弹量能
    head_rally_end = min(head_idx + 10, len(volumes) if volumes else 0)
    head_rally_vol = sum(volumes[head_idx:head_rally_end]) / max(1, head_rally_end - head_idx) if volumes and head_rally_end > head_idx else vol_ma
    head_rally_expand = head_rally_vol > vol_ma * 1.2

    quality_score = 2 if head_rally_expand else 1
    stage = "FORMING"
    signal = "HOLD"
    score_adjustment = 0
    current_vol = volumes[-1] if volumes else vol_ma

    if current_price > neckline:
        stage = "BREAKOUT"
        breakout_vol = current_vol > vol_ma * 1.3

        if breakout_vol and head_rally_expand:
            quality_score = 3
            signal = "BUY"
            score_adjustment = 10  # 头肩底突破最高分
        elif breakout_vol:
            quality_score = 2
            signal = "BUY"
            score_adjustment = 8
        else:
            signal = "BUY"
            score_adjustment = 5

    elif current_price > neckline * 0.97 and len(closes) >= 10 and max(closes[-10:]) > neckline:
        stage = "PULLBACK"
        signal = "BUY"
        score_adjustment = 6

    elif current_price > right_shoulder:
        stage = "FORMING"
        score_adjustment = 3 if head_rally_expand else 2

    target = (neckline ** 2) / head if head > 0 else neckline * 1.1

    result.update({
        "pattern": "HS_BOTTOM",
        "signal": signal,
        "stage": stage,
        "quality_score": quality_score,
        "neckline": round(neckline, 2),
        "target": round(target, 2),
        "score_adjustment": score_adjustment,
        "details": {
            "left_shoulder": round(left_shoulder, 2),
            "head": round(head, 2),
            "right_shoulder": round(right_shoulder, 2),
            "shoulder_deviation": f"{shoulder_deviation*100:.1f}%",
            "head_rally_expand": head_rally_expand
        }
    })

    return result


def _detect_hs_top_v3420(
    swing_highs: list, swing_lows: list, highs: list, lows: list,
    closes: list, volumes: list, current_price: float, tolerance: float
) -> dict:
    """
    v3.420: 头肩顶检测 - 最强卖出信号

    规则:
    1. 头部最高，左右肩偏差 ≤ 5%
    2. 量能递减: 左肩 > 头部 ≥ 右肩 (必须条件)
    3. 跌破颈线确认
    """
    result = {"pattern": None, "signal": "HOLD", "stage": None, "quality_score": 1,
              "neckline": None, "target": None, "score_adjustment": 0, "details": {}}

    left_idx, left_shoulder = swing_highs[-3]
    head_idx, head = swing_highs[-2]
    right_idx, right_shoulder = swing_highs[-1]

    # 摆点间距检查
    if right_idx - left_idx > 40:
        return result

    # 头部必须最高
    if head <= left_shoulder or head <= right_shoulder:
        return result

    if left_shoulder <= 0:
        return result
    shoulder_deviation = abs(right_shoulder - left_shoulder) / left_shoulder
    if shoulder_deviation > tolerance:
        return result

    # 颈线
    left_trough = min(lows[left_idx:head_idx+1]) if head_idx > left_idx else lows[left_idx] if left_idx < len(lows) else 0
    right_trough = min(lows[head_idx:right_idx+1]) if right_idx > head_idx else lows[head_idx] if head_idx < len(lows) else 0

    if left_trough <= 0 or right_trough <= 0:
        return result
    neckline = (left_trough + right_trough) / 2

    # 关键量价: 量能递减
    left_vol_start = max(0, left_idx - 5)
    left_vol_end = min(len(volumes) if volumes else 0, left_idx + 3)
    left_vol = sum(volumes[left_vol_start:left_vol_end]) if volumes and left_vol_end > left_vol_start else 1

    head_vol_start = max(0, head_idx - 5)
    head_vol_end = min(len(volumes) if volumes else 0, head_idx + 3)
    head_vol = sum(volumes[head_vol_start:head_vol_end]) if volumes and head_vol_end > head_vol_start else 1

    right_vol_start = max(0, right_idx - 5)
    right_vol_end = min(len(volumes) if volumes else 0, right_idx + 3)
    right_vol = sum(volumes[right_vol_start:right_vol_end]) if volumes and right_vol_end > right_vol_start else 1

    # 量能递减验证
    vol_decreasing = (right_vol < head_vol) and (head_vol <= left_vol * 1.1)

    if not vol_decreasing:
        return result

    quality_score = 2  # 满足量能递减
    stage = "FORMING"
    signal = "HOLD"
    score_adjustment = 0

    if current_price < neckline:
        stage = "BREAKOUT"
        quality_score = 3
        signal = "SELL"
        score_adjustment = -10  # 头肩顶最强卖出
    elif current_price < neckline * 1.03:
        stage = "FORMING"
        signal = "SELL"
        score_adjustment = -6
    else:
        stage = "FORMING"
        score_adjustment = -3

    target = (neckline ** 2) / head if head > 0 else neckline * 0.9

    result.update({
        "pattern": "HS_TOP",
        "signal": signal,
        "stage": stage,
        "quality_score": quality_score,
        "neckline": round(neckline, 2),
        "target": round(target, 2),
        "score_adjustment": score_adjustment,
        "details": {
            "left_shoulder": round(left_shoulder, 2),
            "head": round(head, 2),
            "right_shoulder": round(right_shoulder, 2),
            "vol_pattern": f"L:{left_vol:.0f} H:{head_vol:.0f} R:{right_vol:.0f}"
        }
    })

    return result

# ===== v3.420 END: L2形态外挂 =====


# ============================================================================
# v2.989: L2大周期增强版函数 (移动到此处确保在调用前定义)
# ============================================================================

def compute_l2_macro_exec_bias_enhanced(
    state, last_close, close_prices, volumes,
    sr_zone_hint, pa_tag_raw, two_b_tag_raw, volume_state_raw,
    trend_mid, trend_x4, trend_x8, bearish_env,
    ohlcv_window=None,  # v2.989: 新增真实OHLCV窗口参数
    market_regime=None,  # v2.997: 新增market_regime参数，L1传递的市场状态
    tv_donchian=None,  # v3.472: TV推送的Donchian数据 {upper, lower, basis, pos_in_channel}
    symbol=None,  # v3.487: 品种代码，用于Wyckoff阶段确认
    timeframe_int=None  # v3.600: 周期(分钟)，用于动态回看窗口
):
    """
    L2 大周期增强主函数 v2.989/v2.997

    v2.997改进：
    - 新增 market_regime 参数，接收L1的市场状态判断
    - 传递给compute_exec_bias_with_scoring影响评分

    v2.989改进：
    - 新增 ohlcv_window 参数，优先使用真实OHLCV数据
    - 只有在无真实数据时才降级为close估算

    输入：
    - state: 全局状态
    - last_close: 当前价格
    - close_prices/volumes: 120根K线数据
    - sr_zone_hint/pa_tag_raw等: TV输入的原始信号
    - trend_mid/x4/x8: 多周期趋势
    - bearish_env: 熊市环境标志
    - ohlcv_window: v2.989 真实OHLCV窗口（OHLCVWindow对象）
    - market_regime: v2.997 L1市场状态字典（含regime/direction/strength/l2_strategy等）
    
    输出：
    {
        "exec_bias": str,
        "score_total": int,
        "score_breakdown": dict,
        "donchian_support": float,
        "donchian_mid": float,
        "donchian_resistance": float,
        "dist_to_support_pct": float,
        "dist_to_resistance_pct": float,
        "candle_features": dict,
        "pa_tag": str,
        "two_b_tag": str,
        "one_two_three_tag": str,
        "volume_state": str,
        "swing_points": dict,
        "l2_zone_tag": str,
    }
    """
    
    # v3.600: 动态回看窗口 (不再硬编码120)
    _l2_tf = timeframe_int if timeframe_int else (get_symbol_timeframe(symbol) if symbol else 240)
    _l2_buf = get_timeframe_params(_l2_tf, is_crypto=is_crypto_symbol(symbol) if symbol else True)["ohlcv_buffer_size"]

    # v2.989: 优先使用真实OHLCV窗口数据
    ohlcv_bars = []
    use_real_ohlcv = False
    
    if ohlcv_window is not None:
        if hasattr(ohlcv_window, 'get_bars') and hasattr(ohlcv_window, 'is_ready'):
            if ohlcv_window.size() >= 10:  # v3.320修复: is_ready()要求61根,实际只需10根
                bars_real = ohlcv_window.get_bars()
                if len(bars_real) >= 10:  # v2.989: 降低阈值，10根即可启用
                    ohlcv_bars = bars_real
                    use_real_ohlcv = True
                    print(f"[v2.989] ✅ L2增强版使用真实OHLCV: {len(ohlcv_bars)}根K线")
                else:
                    print(f"[v2.989] ⚠️ OHLCV数据不足: {len(bars_real)}根 < 10根")
            else:
                print(f"[v2.989] ⚠️ OHLCV窗口未就绪")
        else:
            print(f"[v2.989] ⚠️ OHLCV窗口无效")
    else:
        print(f"[v2.989] ⚠️ OHLCV窗口为空")
    
    # 降级：无真实数据时用close估算
    if not use_real_ohlcv:
        print(f"[v2.989] ⚠️ L2增强版降级：使用close估算OHLCV")
        for i, close in enumerate(close_prices):
            vol = volumes[i] if volumes and i < len(volumes) else 1.0
            ohlcv_bars.append({
                "open": close * 0.999,
                "high": close * 1.001,
                "low": close * 0.999,
                "close": close,
                "volume": vol,
            })
    
    # 2. 统一Donchian位置定义 - v3.472: 优先使用TV推送的准确Donchian数据
    use_tv_donchian = False
    if tv_donchian is not None:
        tv_upper = tv_donchian.get("upper")
        tv_lower = tv_donchian.get("lower")
        tv_basis = tv_donchian.get("basis")
        tv_pos = tv_donchian.get("pos_in_channel")

        # 验证TV数据有效性
        if tv_upper is not None and tv_lower is not None and tv_upper > tv_lower:
            donchian_resistance = float(tv_upper)
            donchian_support = float(tv_lower)
            donchian_mid = float(tv_basis) if tv_basis is not None else (donchian_support + donchian_resistance) / 2
            use_tv_donchian = True
            print(f"[v3.472] ✅ L2使用TV Donchian: support={donchian_support:.2f}, mid={donchian_mid:.2f}, resist={donchian_resistance:.2f}")

    # 回退：本地计算 (v3.600: 动态回看窗口)
    if not use_tv_donchian:
        if len(rsi_close_prices) >= _l2_buf:
            donchian_support = min(rsi_close_prices[-_l2_buf:])
            donchian_resistance = max(rsi_close_prices[-_l2_buf:])
        elif len(rsi_close_prices) > 0:
            donchian_support = min(rsi_close_prices)
            donchian_resistance = max(rsi_close_prices)
        else:
            donchian_support = last_close * 0.95
            donchian_resistance = last_close * 1.05
        donchian_mid = (donchian_support + donchian_resistance) / 2
        print(f"[v3.472] ⚠️ L2使用本地计算Donchian: support={donchian_support:.2f}, mid={donchian_mid:.2f}, resist={donchian_resistance:.2f}")

    donchian_range = max(donchian_resistance - donchian_support, 1e-9)

    # v3.472: 优先使用TV的pos_in_channel（更准确）
    if use_tv_donchian and tv_donchian.get("pos_in_channel") is not None:
        tv_pos_pct = float(tv_donchian.get("pos_in_channel")) / 100.0  # 转换为0-1
        dist_to_support_pct = tv_pos_pct
        dist_to_resistance_pct = 1.0 - tv_pos_pct
        dist_to_support = donchian_range * dist_to_support_pct
        dist_to_resistance = donchian_range * dist_to_resistance_pct
        print(f"[v3.472] ✅ L2使用TV位置: {tv_pos_pct*100:.1f}% (support_pct={dist_to_support_pct:.2f}, resist_pct={dist_to_resistance_pct:.2f})")
    else:
        dist_to_support = last_close - donchian_support
        dist_to_resistance = donchian_resistance - last_close
        dist_to_support_pct = dist_to_support / donchian_range
        dist_to_resistance_pct = dist_to_resistance / donchian_range
    
    # 确定zone_tag
    if dist_to_support_pct < 0.1:
        l2_zone_tag = "BELOW_SUPPORT"
    elif dist_to_support_pct < 0.4:
        l2_zone_tag = "LOWER_HALF"
    elif dist_to_resistance_pct < 0.1:
        l2_zone_tag = "ABOVE_RESIST"
    elif dist_to_resistance_pct < 0.4:
        l2_zone_tag = "UPPER_HALF"
    else:
        l2_zone_tag = "MID_ZONE"
    
    # ═══════════════════════════════════════════════════════════════════════
    # P1 改进 #4: SR 突破识别 (v2.480)
    # ═══════════════════════════════════════════════════════════════════════
    
    breakout_type = "NONE"
    breakout_strength = 0
    breakout_score_adjustment = 0
    
    # 需要先获取 volume_state，暂时先定义占位符
    # (volume_state 在后面才计算，这里先用一个临时值)
    
    # 注意：完整的突破识别需要在获取 volume_state 后进行
    # 这里先记录是否在突破区域，后续再调整评分
    
    is_in_breakout_zone = (l2_zone_tag in ("BELOW_SUPPORT", "ABOVE_RESIST"))
    
    # ═══════════════════════════════════════════════════════════════════════
    
    # 3. K线特征
    candle_features = compute_candle_features_enhanced(ohlcv_bars)
    
    # 4. Swing points
    # v2.747: lookback从5改为3
    swing_points = identify_swing_points(ohlcv_bars, lookback=3)
    
    # 5. 增强成交量状态
    volume_state = compute_volume_state_enhanced(volumes) if volumes else "NORMAL"
    
    # 6. v3.400增强PA识别 (返回元组: tag, quality_score, details)
    pa_result = detect_pa_tag_enhanced(
        ohlcv_bars, candle_features, swing_points,
        donchian_support, donchian_resistance
    )
    # v3.400: 解包元组
    pa_tag, pa_quality_score, pa_quality_details = pa_result

    # 7. v3.400增强2B识别 (返回元组: tag, speed_score, details)
    two_b_result = detect_two_b_tag_enhanced(ohlcv_bars, swing_points, volume_state)
    # v3.400: 解包元组
    two_b_tag, two_b_speed_score, two_b_speed_details = two_b_result

    # 8. 增强1-2-3识别
    one_two_three_tag = detect_one_two_three_tag_enhanced(ohlcv_bars, swing_points)

    # v3.401修复: 使用log_to_server确保写入日志文件
    log_to_server(f"[v3.400] L2增强版检测结果:")
    log_to_server(f"[v3.400]   PA形态: {pa_tag} (质量分:{pa_quality_score}, {pa_quality_details.get('quality', 'N/A')})")
    log_to_server(f"[v3.400]   2B形态: {two_b_tag} (速度分:{two_b_speed_score}, {two_b_speed_details.get('speed', 'N/A')})")
    log_to_server(f"[v3.400]   123形态: {one_two_three_tag}")
    log_to_server(f"[v3.400]   成交量: {volume_state}")
    log_to_server(f"[v3.400]   使用真实OHLCV: {use_real_ohlcv}")

    # 9. v3.420 形态外挂检测 (双重底/顶 + 头肩底/顶)
    reversal_pattern = detect_reversal_patterns(ohlcv_bars, volumes, tolerance=0.05)

    # v3.420: 记录形态检测结果
    if reversal_pattern.get("pattern"):
        log_to_server(f"[v3.420] 形态外挂检测:")
        log_to_server(f"[v3.420]   形态: {reversal_pattern['pattern']} (质量分:{reversal_pattern['quality_score']})")
        log_to_server(f"[v3.420]   阶段: {reversal_pattern['stage']}, 信号: {reversal_pattern['signal']}")
        log_to_server(f"[v3.420]   颈线: {reversal_pattern['neckline']}, 目标: {reversal_pattern['target']}")
        log_to_server(f"[v3.420]   评分调整: {reversal_pattern['score_adjustment']}")
        log_to_server(f"[v3.420]   详情: {reversal_pattern['details']}")
    else:
        log_to_server(f"[v3.420] 形态外挂: 未检测到形态")

    # ===== v3.440: 形神分析法 =====
    # 来源: 量价理论第3集
    # 形不散(K线流畅) + 神不散(量能均衡) = 可交易
    form_spirit = {"form_score": 2, "spirit_score": 2, "state": "形神兼备",
                   "tradeable": True, "quality_multiplier": 1.0, "warning": None}
    try:
        if ohlcv_bars and len(ohlcv_bars) >= 20:
            form_spirit = _analyze_form_spirit_v3440(ohlcv_bars, lookback=20)
            fs_state = form_spirit.get('state', 'N/A')
            fs_multiplier = form_spirit.get('quality_multiplier', 1.0)
            fs_warning = form_spirit.get('warning')
            log_to_server(f"[v3.440] 形神分析: {fs_state} (乘数={fs_multiplier:.1f})")
            if form_spirit.get('details'):
                log_to_server(f"[v3.440]   详情: 影线比率={form_spirit['details'].get('avg_shadow_ratio', 'N/A')}, "
                            f"波动率={form_spirit['details'].get('volatility', 'N/A')}, "
                            f"量变异系数={form_spirit['details'].get('vol_cv', 'N/A')}")
            if fs_warning:
                print(f"[v3.440] ⚠️ 形神警告: {fs_warning}")
    except Exception as e:
        log_to_server(f"[v3.440] 形神分析异常: {e}")
    # ===== v3.440 END: 形神分析法 =====

    # ===== v3.492: L2量价异常检测 =====
    # 来源: 量价理论第20-29集、第43-44集
    volume_anomaly = {"anomalies": [], "risk_score": 0, "buy_penalty": 0, "sell_bonus": 0, "warning": None}
    pattern_divergence = {"has_divergence": False, "quality_adjustment": 0}
    try:
        if ohlcv_bars and len(ohlcv_bars) >= 20:
            # 1. 综合量价异常检测
            volume_anomaly = _detect_volume_anomaly_v3492(ohlcv_bars, position=dist_to_support_pct, lookback=20)
            if volume_anomaly.get("anomalies"):
                log_to_server(f"[v3.492] 量价异常: {', '.join(volume_anomaly['anomalies'])}")
                log_to_server(f"[v3.492]   风险分={volume_anomaly['risk_score']}, 买入惩罚={volume_anomaly['buy_penalty']}, 卖出奖励={volume_anomaly['sell_bonus']}")
                if volume_anomaly.get("details"):
                    log_to_server(f"[v3.492]   详情: {volume_anomaly['details']}")
                if volume_anomaly.get("warning"):
                    print(f"[v3.492] ⚠️ {volume_anomaly['warning']}")

            # 2. 形态量价背离检测 (配合v3.420形态外挂)
            if reversal_pattern and reversal_pattern.get("detected"):
                pattern_type_map = {
                    "double_top": "double_top",
                    "double_bottom": "double_top",  # 相同逻辑
                    "head_shoulders_top": "head_shoulders_top",
                    "head_shoulders_bottom": "head_shoulders_top",
                    "engulfing_bearish": "engulfing",
                    "engulfing_bullish": "engulfing"
                }
                detected_pattern = reversal_pattern.get("pattern", "")
                mapped_type = pattern_type_map.get(detected_pattern, None)
                if mapped_type:
                    pattern_divergence = _detect_pattern_volume_divergence_v3492(ohlcv_bars, mapped_type, lookback=30)
                    if pattern_divergence.get("has_divergence"):
                        log_to_server(f"[v3.492] 形态量价背离: {detected_pattern}")
                        log_to_server(f"[v3.492]   背离强度={pattern_divergence['divergence_strength']:.1%}, 质量调整={pattern_divergence['quality_adjustment']}")
                        if pattern_divergence.get("details"):
                            log_to_server(f"[v3.492]   详情: {pattern_divergence['details']}")
    except Exception as e:
        log_to_server(f"[v3.492] 量价异常检测异常: {e}")
    # ===== v3.492 END: L2量价异常检测 =====

    # 10. v3.410打分计算exec_bias (传递质量分+量价理论参数)
    # v3.410: 获取52周高低点用于位置判断
    high_52w = max(bar.get("high", 0) for bar in ohlcv_bars) if ohlcv_bars else None
    low_52w = min(bar.get("low", float('inf')) for bar in ohlcv_bars) if ohlcv_bars else None
    if low_52w == float('inf'):
        low_52w = None

    # v3.491: 计算30根K线价格变化用于Wyckoff一致性检查
    wyckoff_price_change_pct = None
    if ohlcv_bars and len(ohlcv_bars) >= 30:
        try:
            bars_30 = ohlcv_bars[-30:]
            first_c = float(bars_30[0].get('close', bars_30[0].get('c', 0)))
            last_c = float(bars_30[-1].get('close', bars_30[-1].get('c', 0)))
            if first_c > 0:
                wyckoff_price_change_pct = (last_c - first_c) / first_c * 100
        except Exception:  # v3.560 P2-2
            pass

    # v3.491: 使用确认机制的Wyckoff阶段 (防止ZEC等品种跳变) + 位置一致性检查
    if symbol:
        wyckoff_phase, wyckoff_sub_state, wyckoff_confirm_info = get_confirmed_wyckoff_phase_v3487(
            symbol, trend_x4, dist_to_support_pct, wyckoff_price_change_pct)
        print(f"[v3.491] Wyckoff确认: {symbol} trend_x4={trend_x4}, pos={dist_to_support_pct*100:.1f}%, price_chg={wyckoff_price_change_pct or 0:.1f}% → phase={wyckoff_phase}")
        if wyckoff_confirm_info.get("pending"):
            print(f"[v3.491]   待确认阶段: {wyckoff_confirm_info['pending']} ({wyckoff_confirm_info['count']}/2)")
    else:
        # 无symbol时降级为v3.491原始方法
        wyckoff_phase = determine_wyckoff_phase_v3485(trend_x4, dist_to_support_pct, wyckoff_price_change_pct)
        wyckoff_sub_state = "NONE"
        wyckoff_confirm_info = {}
        print(f"[v3.491] L1定位Wyckoff: trend_x4={trend_x4}, pos={dist_to_support_pct*100:.1f}%, price_chg={wyckoff_price_change_pct or 0:.1f}% → phase={wyckoff_phase}")

    # v3.487 P1-3: 检测MARKUP_PULLBACK / MARKDOWN_RALLY子状态
    wyckoff_sub_state, wyckoff_sub_weight = detect_wyckoff_sub_state_v3487(wyckoff_phase, ohlcv_bars)
    if wyckoff_sub_state != "NONE":
        print(f"[v3.487] Wyckoff子状态: {wyckoff_phase}_{wyckoff_sub_state}, 反向权重={wyckoff_sub_weight}")

    l2_strategy = get_wyckoff_l2_strategy(wyckoff_phase)

    # v3.499: 从market_regime提取current_trend用于矛盾检测
    l1_current_trend = None
    if market_regime and isinstance(market_regime, dict):
        l1_current_trend = market_regime.get("current_trend")

    scoring_result = compute_exec_bias_with_scoring(
        pa_tag, two_b_tag, one_two_three_tag,
        volume_state, dist_to_support_pct, dist_to_resistance_pct,
        trend_mid, trend_x4, trend_x8,
        market_regime=market_regime,
        pa_quality_score=pa_quality_score,  # v3.400: 传递PA质量分
        two_b_speed_score=two_b_speed_score,  # v3.400: 传递2B速度分
        # v3.410 量价理论新增参数
        ohlcv_bars=ohlcv_bars,
        closes=close_prices,
        volumes=volumes,
        high_52w=high_52w,
        low_52w=low_52w,
        tv_donchian=tv_donchian,  # v3.480: 传递TV Donchian数据
        wyckoff_phase=wyckoff_phase,  # v3.485: Wyckoff阶段
        l2_strategy=l2_strategy,  # v3.485: L2策略
        symbol=symbol,  # v3.499: 品种代码 (唐纳奇通道反馈)
        current_trend=l1_current_trend  # v3.499: L1当前周期趋势 (矛盾检测)
    )

    # v3.487 P1-3: 应用子状态权重到反向信号
    # PULLBACK时降低SELL权重，RALLY时降低BUY权重
    if wyckoff_sub_state != "NONE" and wyckoff_sub_weight < 1.0:
        original_score = scoring_result.get("score_total", 0)
        original_bias = scoring_result.get("exec_bias", "HOLD")

        # PULLBACK (MARKUP中的回调): 降低空头评分
        if wyckoff_sub_state == "PULLBACK" and original_score < 0:
            adjusted_score = int(original_score * wyckoff_sub_weight)
            scoring_result["score_total"] = adjusted_score
            scoring_result["v3487_sub_state"] = wyckoff_sub_state
            scoring_result["v3487_original_score"] = original_score
            print(f"[v3.487] PULLBACK权重调整: {original_score} → {adjusted_score} (反向SELL权重×{wyckoff_sub_weight})")

        # RALLY (MARKDOWN中的反弹): 降低多头评分
        elif wyckoff_sub_state == "RALLY" and original_score > 0:
            adjusted_score = int(original_score * wyckoff_sub_weight)
            scoring_result["score_total"] = adjusted_score
            scoring_result["v3487_sub_state"] = wyckoff_sub_state
            scoring_result["v3487_original_score"] = original_score
            print(f"[v3.487] RALLY权重调整: {original_score} → {adjusted_score} (反向BUY权重×{wyckoff_sub_weight})")

    # v3.487 P2-6: 双周期位置确认
    dual_pos = compute_dual_period_position_v3487(ohlcv_bars, long_period=_l2_buf, short_period=20)
    scoring_result["dual_position"] = dual_pos
    if dual_pos["context"] not in ("ALIGNED", "INSUFFICIENT_DATA"):
        print(f"[v3.487] 双周期位置: 长期={dual_pos['long_pos']*100:.1f}%({dual_pos['long_bucket']}), "
              f"短期={dual_pos['short_pos']*100:.1f}%({dual_pos['short_bucket']}) → {dual_pos['context']}")
        # 应用权重调整
        current_score = scoring_result.get("score_total", 0)
        exec_bias = scoring_result.get("exec_bias", "HOLD")
        if exec_bias in ("BUY", "STRONG_BUY") and dual_pos["weight_adjustment"]["BUY"] < 1.0:
            adjusted_score = int(current_score * dual_pos["weight_adjustment"]["BUY"])
            scoring_result["score_total"] = adjusted_score
            scoring_result["v3487_dual_pos_original"] = current_score
            print(f"[v3.487] 双周期位置调整BUY: {current_score} → {adjusted_score} (×{dual_pos['weight_adjustment']['BUY']})")
        elif exec_bias in ("SELL", "STRONG_SELL") and dual_pos["weight_adjustment"]["SELL"] < 1.0:
            adjusted_score = int(current_score * dual_pos["weight_adjustment"]["SELL"])
            scoring_result["score_total"] = adjusted_score
            scoring_result["v3487_dual_pos_original"] = current_score
            print(f"[v3.487] 双周期位置调整SELL: {current_score} → {adjusted_score} (×{dual_pos['weight_adjustment']['SELL']})")

    # ========================================================================
    # v3.496: 美股正常亏损高位(>70%)额外减分促进卖出
    # ========================================================================
    if symbol:
        crypto_keywords = ["USDT", "USDC", "BUSD", "BTC", "ETH", "CRYPTO", "PERP", "SWAP"]
        is_stock_v3496 = not any(kw in symbol.upper() for kw in crypto_keywords)

        if is_stock_v3496 and dist_to_support_pct > 0.70:
            pnl_level_v3496, pnl_pct_v3496 = get_pnl_level(symbol)
            if pnl_level_v3496 == "normal" and pnl_pct_v3496 < 0:
                # 正常亏损股票在70%以上额外减1分促进卖出
                current_score_v3496 = scoring_result.get("score_total", 0)
                adjusted_score_v3496 = current_score_v3496 - 1
                scoring_result["score_total"] = adjusted_score_v3496
                scoring_result["v3496_pnl_adj"] = -1
                scoring_result["v3496_pnl_level"] = pnl_level_v3496
                scoring_result["v3496_pnl_pct"] = pnl_pct_v3496
                print(f"[v3.496] 美股正常亏损高位减分: {symbol} 盈亏={pnl_pct_v3496:.1f}%, 位置={dist_to_support_pct*100:.0f}%")
                print(f"[v3.496]   评分调整: {current_score_v3496} → {adjusted_score_v3496} (额外-1促进卖出)")

        # ========================================================================
        # v3.497: 美股成本价格高抛低吸策略评分调整
        # ========================================================================
        if is_stock_v3496:
            cost_adj, cost_reason = get_cost_reduction_score_adj(symbol, last_close, dist_to_support_pct)
            if cost_adj != 0:
                current_score = scoring_result.get("score_total", 0)
                adjusted_score = current_score + cost_adj
                scoring_result["score_total"] = adjusted_score
                scoring_result["v3497_cost_adj"] = cost_adj
                scoring_result["v3497_cost_reason"] = cost_reason

                avg_cost, pos_units, _ = get_avg_cost_price(symbol)
                print(f"[v3.497] 成本拉低: {symbol}")
                print(f"[v3.497]   成本价={avg_cost:.2f}, 仓位={pos_units}单位")
                print(f"[v3.497]   当前价={last_close:.2f}, 位置={dist_to_support_pct*100:.0f}%")
                print(f"[v3.497]   {cost_reason}, 评分调整: {current_score} → {adjusted_score}")

    # ========================================================================
    # v2.480 Complete Enhancements
    # ========================================================================

    # ═══════════════════════════════════════════════════════════════════════
    # v3.499: RSI评分移除 (原v2.480)
    # 原因: RSI与唐纳奇位置分功能重叠，且趋势市钝化问题严重
    # 保留RSI计算用于其他判断，但不再计入评分
    # ═══════════════════════════════════════════════════════════════════════

    # 计算 RSI(14) - 保留用于监控显示和其他判断
    rsi_close_prices = [b.get("close", 0) for b in ohlcv_bars] if ohlcv_bars else close_prices
    rsi14 = calc_rsi(rsi_close_prices, period=14)
    rsi_signal = "HOLD"
    score_rsi = 0  # v3.499: RSI不再计入评分
    rsi_reasons = ["v3.499_rsi_score_disabled"]

    # RSI信号仅用于显示，不影响评分
    if rsi14 is not None:
        if rsi14 <= 35:
            rsi_signal = "BUY"
        elif rsi14 >= 65:
            rsi_signal = "SELL"

    # 更新 scoring_result (score_total不变)
    scoring_result["rsi14"] = rsi14
    scoring_result["rsi_signal"] = rsi_signal
    scoring_result["score_rsi"] = 0  # v3.499: 固定为0
    scoring_result["rsi_reasons"] = rsi_reasons

    # v3.499: score_total不再加RSI分，直接使用当前exec_bias
    score_total_new = scoring_result["score_total"]
    # v3.499: 统一使用新阈值 (>=8/>=4/<=-8/<=-4)
    if score_total_new >= 8:
        exec_bias_new = "STRONG_BUY"
    elif score_total_new >= 4:
        exec_bias_new = "BUY"
    elif score_total_new <= -8:
        exec_bias_new = "STRONG_SELL"
    elif score_total_new <= -4:
        exec_bias_new = "SELL"
    else:
        exec_bias_new = "HOLD"
    
    # ═══════════════════════════════════════════════════════════════════════
    # P0 改进 #3: 智能满仓降级 (v2.480)
    # ═══════════════════════════════════════════════════════════════════════
    
    # 检查满仓高位条件
    position_units = state.get("position_units", 0)
    pos_ratio = dist_to_support_pct  # 使用支撑距离作为位置百分比
    
    position_reduction_applied = False
    
    if exec_bias_new == "HOLD":
        # 满仓高位条件
        is_full_position = (position_units >= 4)  # 80%
        is_high_position = (pos_ratio >= 0.75)    # 75%
        
        if is_full_position and is_high_position:
            # v2.480: 智能判断是否真的是顶部
            pattern_score_temp = scoring_result.get("score_pattern", 0)
            volume_state_temp = scoring_result.get("volume_state", "NORMAL")
            
            # 顶部信号
            has_top_signal = (
                (trend_x8 == "up" and trend_x4 == "side") or  # 趋势转弱
                (trend_x8 == "side") or                        # 震荡
                (volume_state_temp == "DRY_UP") or             # 缩量
                (rsi14 and rsi14 >= 70) or                     # 严重超买
                (pattern_score_temp < 0)                       # 空头形态
            )
            
            # 强势上涨信号
            has_momentum = (
                (trend_x8 == "up" and trend_x4 == "up") and   # 多周期上涨
                (volume_state_temp in ("HIGH", "CLIMAX")) and  # 持续放量
                (pattern_score_temp >= 0)                      # 无空头形态
            )
            
            if has_top_signal and not has_momentum:
                # 确实是顶部 → 降级
                exec_bias_new = "HOLD_SUGGEST"
                position_reduction_applied = True
                rsi_reasons.append(f"position_reduce_top_signal:units={position_units},pos={pos_ratio:.1%}")
            
            elif has_momentum:
                # 强势上涨中 → 不降级
                position_reduction_applied = False
                rsi_reasons.append(f"position_keep_strong_momentum:units={position_units},pos={pos_ratio:.1%}")
            
            else:
                # 不确定 → 保守降级
                exec_bias_new = "HOLD_SUGGEST"
                position_reduction_applied = True
                rsi_reasons.append(f"position_reduce_uncertain:units={position_units},pos={pos_ratio:.1%}")
    
    # 更新最终 exec_bias
    # v3.600fix-B: SR veto保护 - 如果SR veto已触发，保留veto决定
    if not scoring_result.get("veto_applied"):
        scoring_result["exec_bias"] = exec_bias_new
    else:
        print(f"[v3.600fix] SR保护生效，跳过score re-mapping (veto_reason={scoring_result.get('veto_reason')})")
    scoring_result["position_reduction_applied"] = position_reduction_applied

    # ═══════════════════════════════════════════════════════════════════════
    # P1 改进 #4: SR 突破识别应用 (v2.480)
    # ═══════════════════════════════════════════════════════════════════════
    
    breakout_type = "NONE"
    breakout_strength = 0
    breakout_score_adjustment = 0
    
    if l2_zone_tag == "ABOVE_RESIST":
        # 上破阻力
        vol_ratio = volumes[-1] / (sum(volumes[-20:]) / 20) if len(volumes) >= 20 else 1.0
        
        breakout_type, breakout_strength = identify_breakout_type(
            price=last_close,
            sr_level=donchian_resistance,
            direction="UP",
            volume_state=volume_state,
            vol_ratio=vol_ratio,
            trend_state=trend_x4,
            bars_count=1  # 简化，实际需要从历史计算
        )
        
        if breakout_type == "TRUE_BREAKOUT":
            # 真突破 → 追涨信号
            breakout_score_adjustment = breakout_strength  # +3 或 +5
            rsi_reasons.append(f"true_breakout_up:strength={breakout_strength}")
        
        elif breakout_type == "FALSE_BREAKOUT":
            # 假突破 → 反向信号
            breakout_score_adjustment = -breakout_strength  # -1
            rsi_reasons.append(f"false_breakout_reversal:strength={breakout_strength}")
    
    elif l2_zone_tag == "BELOW_SUPPORT":
        # 下破支撑
        vol_ratio = volumes[-1] / (sum(volumes[-20:]) / 20) if len(volumes) >= 20 else 1.0
        
        breakout_type, breakout_strength = identify_breakout_type(
            price=last_close,
            sr_level=donchian_support,
            direction="DOWN",
            volume_state=volume_state,
            vol_ratio=vol_ratio,
            trend_state=trend_x4,
            bars_count=1
        )
        
        if breakout_type == "TRUE_BREAKOUT":
            # 真突破 → 追跌信号
            breakout_score_adjustment = -breakout_strength  # -3 或 -5
            rsi_reasons.append(f"true_breakout_down:strength={breakout_strength}")
        
        elif breakout_type == "FALSE_BREAKOUT":
            # 假突破 → 反向信号
            breakout_score_adjustment = breakout_strength  # +1
            rsi_reasons.append(f"false_breakout_bounce:strength={breakout_strength}")
    
    # 应用突破评分调整
    if breakout_score_adjustment != 0:
        score_total_before_breakout = scoring_result["score_total"]
        score_total_after_breakout = score_total_before_breakout + breakout_score_adjustment
        scoring_result["score_total"] = score_total_after_breakout
        scoring_result["breakout_type"] = breakout_type
        scoring_result["breakout_strength"] = breakout_strength
        scoring_result["breakout_score"] = breakout_score_adjustment
        
        # v3.499: 重新映射 exec_bias (阈值统一为8/4/-4/-8)
        if score_total_after_breakout >= 8:
            exec_bias_new = "STRONG_BUY"
        elif score_total_after_breakout >= 4:
            exec_bias_new = "BUY"
        elif score_total_after_breakout <= -8:
            exec_bias_new = "STRONG_SELL"
        elif score_total_after_breakout <= -4:
            exec_bias_new = "SELL"
        else:
            exec_bias_new = "HOLD"

        # v3.600fix-B: SR veto保护 - 如果SR veto已触发，保留veto决定
        if not scoring_result.get("veto_applied"):
            scoring_result["exec_bias"] = exec_bias_new
        else:
            print(f"[v3.600fix] SR保护生效，跳过突破re-mapping (veto_reason={scoring_result.get('veto_reason')})")
    
    # ═══════════════════════════════════════════════════════════════════════
    
    # ═══════════════════════════════════════════════════════════════════════
    # P0 改进 #3: 智能满仓降级 (v2.480) - 重新检查
    # ═══════════════════════════════════════════════════════════════════════
    
    # 注意：突破识别可能改变了 exec_bias，需要重新检查满仓降级
    exec_bias_final = scoring_result["exec_bias"]
    position_reduction_applied = False
    
    if exec_bias_final == "HOLD":
        # 满仓高位条件（与前面相同的逻辑）
        is_full_position = (position_units >= 4)
        is_high_position = (pos_ratio >= 0.75)
        
        if is_full_position and is_high_position:
            pattern_score_temp = scoring_result.get("score_pattern", 0)
            volume_state_temp = scoring_result.get("volume_state", "NORMAL")
            
            # 顶部信号
            has_top_signal = (
                (trend_x8 == "up" and trend_x4 == "side") or
                (trend_x8 == "side") or
                (volume_state_temp == "DRY_UP") or
                (rsi14 and rsi14 >= 70) or
                (pattern_score_temp < 0)
            )
            
            # 强势上涨信号
            has_momentum = (
                (trend_x8 == "up" and trend_x4 == "up") and
                (volume_state_temp in ("HIGH", "CLIMAX")) and
                (pattern_score_temp >= 0)
            )
            
            if has_top_signal and not has_momentum:
                exec_bias_final = "HOLD_SUGGEST"
                position_reduction_applied = True
                rsi_reasons.append(f"position_reduce_top_signal_final:units={position_units},pos={pos_ratio:.1%}")
            
            elif has_momentum:
                position_reduction_applied = False
                rsi_reasons.append(f"position_keep_strong_momentum_final:units={position_units},pos={pos_ratio:.1%}")
            
            else:
                exec_bias_final = "HOLD_SUGGEST"
                position_reduction_applied = True
                rsi_reasons.append(f"position_reduce_uncertain_final:units={position_units},pos={pos_ratio:.1%}")
    
    # 更新最终结果
    scoring_result["exec_bias"] = exec_bias_final
    scoring_result["position_reduction_applied"] = position_reduction_applied
    
    # ========================================================================
    # End of v2.480 Complete Enhancements
    # ========================================================================
    
    # 10. 调试日志
    if L2_DEBUG_VERBOSE:
        print(f"[L2_DEBUG] Donchian: support={donchian_support:.4f}, "
              f"mid={donchian_mid:.4f}, resistance={donchian_resistance:.4f}")
        print(f"[L2_DEBUG] Dist: support={dist_to_support_pct:.2%}, "
              f"resistance={dist_to_resistance_pct:.2%}")
        print(f"[L2_DEBUG] Candle: {candle_features}")
        print(f"[L2_DEBUG] PA={pa_tag}, 2B={two_b_tag}, 123={one_two_three_tag}, "
              f"VOL={volume_state}")
        print(f"[L2_DEBUG] Score: total={scoring_result['score_total']}, "
              f"breakdown={scoring_result}")
    
    # v3.420: 形态外挂评分计算
    reversal_score = 0
    if reversal_pattern.get("pattern"):
        base_score = reversal_pattern.get("score_adjustment", 0)
        quality = reversal_pattern.get("quality_score", 1)
        quality_multiplier = {1: 0.7, 2: 1.0, 3: 1.3}.get(quality, 1.0)
        reversal_score = int(base_score * quality_multiplier)
        log_to_server(f"[v3.420] 形态评分: {reversal_pattern['pattern']} "
                      f"基础{base_score} x 质量{quality}({quality_multiplier}) = {reversal_score}")

    # v3.420: 更新总分（加入形态评分）
    adjusted_score_total = scoring_result["score_total"] + reversal_score

    # ===== v3.440: 形神分析质量乘数应用 =====
    # 如果形神状态不佳，降低信号强度
    form_spirit_score_adj = 0
    if not form_spirit.get("tradeable", True):
        fs_multiplier = form_spirit.get("quality_multiplier", 1.0)
        fs_state = form_spirit.get("state", "形神兼备")
        if adjusted_score_total > 0:
            # 买入信号被形神不佳削弱
            original_score = adjusted_score_total
            adjusted_score_total = int(adjusted_score_total * fs_multiplier)
            form_spirit_score_adj = adjusted_score_total - original_score
            log_to_server(f"[v3.440] 形神削弱买入信号: {original_score}→{adjusted_score_total} ({fs_state})")
        elif adjusted_score_total < 0:
            # 卖出信号不受影响（形散神聚是顶部特征，卖出应该更强）
            if fs_state == "形散神聚":
                original_score = adjusted_score_total
                adjusted_score_total = int(adjusted_score_total * 1.2)  # 增强卖出
                form_spirit_score_adj = adjusted_score_total - original_score
                log_to_server(f"[v3.440] 形散神聚增强卖出信号: {original_score}→{adjusted_score_total}")
    # ===== v3.440 END: 形神分析乘数应用 =====

    # ===== v3.492: 量价异常评分调整 =====
    v3492_score_adj = 0
    if volume_anomaly.get("anomalies"):
        buy_penalty = volume_anomaly.get("buy_penalty", 0)
        sell_bonus = volume_anomaly.get("sell_bonus", 0)

        # 买入信号被惩罚
        if adjusted_score_total > 0 and buy_penalty > 0:
            original_score = adjusted_score_total
            adjusted_score_total = max(0, adjusted_score_total - buy_penalty)
            v3492_score_adj = adjusted_score_total - original_score
            log_to_server(f"[v3.492] 量价异常惩罚买入: {original_score}→{adjusted_score_total} (惩罚-{buy_penalty})")

        # 卖出信号被增强
        elif adjusted_score_total < 0 and sell_bonus > 0:
            original_score = adjusted_score_total
            adjusted_score_total = adjusted_score_total - sell_bonus
            v3492_score_adj = adjusted_score_total - original_score
            log_to_server(f"[v3.492] 量价异常增强卖出: {original_score}→{adjusted_score_total} (奖励-{sell_bonus})")

    # v3.492: 形态量价背离调整
    if pattern_divergence.get("has_divergence"):
        quality_adj = pattern_divergence.get("quality_adjustment", 0)
        if quality_adj != 0:
            original_score = adjusted_score_total
            # 背离通常意味着反转，调整信号强度
            if adjusted_score_total > 0:  # 买入信号
                adjusted_score_total = adjusted_score_total - abs(quality_adj)  # 削弱
            else:  # 卖出信号
                adjusted_score_total = adjusted_score_total - abs(quality_adj)  # 增强(更负)
            log_to_server(f"[v3.492] 形态量价背离调整: {original_score}→{adjusted_score_total}")
    # ===== v3.492 END: 量价异常评分调整 =====

    # v3.600fix-C: exec_bias与最终adjusted_score_total一致
    _cur_bias = scoring_result.get("exec_bias", "HOLD")
    if not scoring_result.get("veto_applied") and _cur_bias != "HOLD_SUGGEST":
        if adjusted_score_total >= 8:
            scoring_result["exec_bias"] = "STRONG_BUY"
        elif adjusted_score_total >= 4:
            scoring_result["exec_bias"] = "BUY"
        elif adjusted_score_total <= -8:
            scoring_result["exec_bias"] = "STRONG_SELL"
        elif adjusted_score_total <= -4:
            scoring_result["exec_bias"] = "SELL"
        else:
            scoring_result["exec_bias"] = "HOLD"
        if scoring_result["exec_bias"] != _cur_bias:
            print(f"[v3.600fix] exec_bias与分数一致性修正: {_cur_bias}→{scoring_result['exec_bias']} (score={adjusted_score_total})")

    # v3.370: 添加降级追踪信息
    return {
        "exec_bias": scoring_result["exec_bias"],
        "score_total": adjusted_score_total,  # v3.420: 包含形态评分
        "score_breakdown": {
            "position": scoring_result["score_position"],
            "score_position": scoring_result["score_position"],  # v3.485: 兼容键名
            "pattern": scoring_result["score_pattern"],
            "score_pattern": scoring_result["score_pattern"],  # v3.485: 兼容键名
            # v3.391: 添加PA/2B/123单独分数（用于邮件显示）
            "pa": scoring_result.get("score_pa", 0),
            "2b": scoring_result.get("score_2b", 0),
            "123": scoring_result.get("score_123", 0),
            "volume": scoring_result["score_volume"],
            "score_volume": scoring_result["score_volume"],  # v3.485: 兼容键名
            "trend": scoring_result["score_trend"],
            "score_trend": scoring_result["score_trend"],  # v3.485: 兼容键名
            # v3.391: 添加策略分（来自L1市场状态影响）
            "regime": scoring_result.get("score_regime", 0),
            "regime_reason": scoring_result.get("regime_adjustment_reason", ""),
            # v3.420: 形态外挂评分
            "reversal": reversal_score,
            # v3.421: 补充遗漏的分数项（确保总分=各项之和）
            "v3410": scoring_result.get("score_v3410", 0),
            "rsi": scoring_result.get("score_rsi", 0),
            "breakout": scoring_result.get("breakout_score", 0),
            "volume_penalty": scoring_result.get("score_volume_penalty", 0),
            "weighted": scoring_result.get("score_weighted", 0),
            # v3.455: K线形态分
            "candle_shape": scoring_result.get("score_candle_shape", 0),
            # v3.485: Wyckoff策略分
            "score_wyckoff": scoring_result.get("score_wyckoff", 0),
            "wyckoff_phase": scoring_result.get("wyckoff_phase", None),
            "wyckoff_score_reason": scoring_result.get("wyckoff_score_reason", ""),
            "l2_strategy": scoring_result.get("l2_strategy", None),
            # v3.499: 唐纳奇通道分和趋势不稳定
            "score_donchian": scoring_result.get("score_donchian", 0),
            "donchian_reason": scoring_result.get("donchian_reason", ""),
            "trend_instability": scoring_result.get("trend_instability", 0),
            # v3.485: Donchian位置传递
            "pos_in_channel": scoring_result.get("pos_in_channel", 0.5),
            "donchian_multiplier": scoring_result.get("donchian_multiplier", 1.0),
            # v3.492: 量价异常评分
            "v3492_anomaly": v3492_score_adj,
        },
        "donchian_support": donchian_support,
        "donchian_mid": donchian_mid,
        "donchian_resistance": donchian_resistance,
        "dist_to_support_pct": dist_to_support_pct,
        "dist_to_resistance_pct": dist_to_resistance_pct,
        "candle_features": candle_features,
        "pa_tag": pa_tag,
        "two_b_tag": two_b_tag,
        "one_two_three_tag": one_two_three_tag,
        "volume_state": volume_state,
        "swing_points": swing_points,
        "l2_zone_tag": l2_zone_tag,
        # v3.370: 降级追踪
        "veto_applied": scoring_result.get("veto_applied", False),
        "original_exec_bias": scoring_result.get("original_exec_bias", scoring_result["exec_bias"]),
        "downgrade_desc": scoring_result.get("downgrade_desc", None),
        "veto_reason": scoring_result.get("veto_reason", None),
        # v3.420: 形态外挂详情
        "reversal_pattern": reversal_pattern,
        # v3.440: 形神分析结果
        "form_spirit": form_spirit,
        "form_spirit_score_adj": form_spirit_score_adj,
        # v3.455: K线形态名称
        "candle_shape_name": scoring_result.get("candle_shape_name", "-"),
        # v3.492: 量价异常检测结果
        "volume_anomaly": volume_anomaly,
        "pattern_divergence": pattern_divergence,
        "v3492_score_adj": v3492_score_adj,
    }


def compute_l2_macro_exec_bias(
    state: dict,
    last_close: float,
    sr_zone_hint: str,
    pa_tag: str,
    two_b_tag: str,
    volume_state: str,
    trend_state: str,
    bearish_env: bool,
    close_prices: list,
    volumes: list,
    ohlcv_window = None,  # v2.697: 添加真实OHLCV窗口
    pa_buy_edge: bool = False,   # v2.711: TV pa_edge 备用
    pa_sell_edge: bool = False,  # v2.711: TV pa_edge 备用
    tv_rsi14: float = None,      # v2.712: TV RSI 优先
    tv_n_swing_bias: str = None, # v2.712: TV N-Swing 优先
    tv_n_swing_score: int = None,# v2.712: TV N-Swing 优先
) -> tuple:
    """
    v1.998 L2 宏观执行层（大周期 Donchian 箱体逻辑）

    - 使用上一根 K 的 Donchian SR (state['prev_sr']) 作为当前判断基准；
      若 prev_sr 缺失，则回退使用 curr_sr，再不行则回退 compute_exec_bias 原逻辑。
    - 在箱体内部：
        * 支撑 ~ 中线 (LOWER_HALF) 视为“下半区”，偏向多头；
        * 中线 ~ 压力 (UPPER_HALF) 视为“上半区”，偏向空头或止盈；
        * 超出箱体上下沿 (BELOW_SUPPORT/ABOVE_RESIST) 视为假突破或趋势段。
    - 新增：在上涨箱体中，上半区允许 1 次“趋势加仓 BUY”，避免一路只拿不加。
    """
    # ═══════════════════════════════════════════════════════════════════════
    # v2.500: 添加 RSI 计算
    # v2.712: TV RSI 优先
    # v3.499: RSI评分移除，仅保留显示
    # ═══════════════════════════════════════════════════════════════════════
    if tv_rsi14 is not None:
        rsi14 = float(tv_rsi14)
        log_to_server(f"[v2.712] ✅ 使用TV推送的RSI: {rsi14:.2f}")
    else:
        rsi14 = calc_rsi(close_prices, period=14)
        if rsi14 is not None:
            log_to_server(f"[v2.712] 本地计算RSI: {rsi14:.2f}")

    # v3.499: RSI不再计入评分，仅用于显示
    score_rsi = 0
    rsi_signal = "HOLD"
    if rsi14 is not None:
        if rsi14 <= 35:
            rsi_signal = "BUY"
        elif rsi14 >= 65:
            rsi_signal = "SELL"
    # ═══════════════════════════════════════════════════════════════════════
    
    pa = normalize_l2_tag(pa_tag, "NONE")
    tb = normalize_l2_tag(two_b_tag, "NONE")
    vol = normalize_l2_tag(volume_state, "NORMAL")
    ts = normalize_l2_tag(trend_state, "SIDE")

    # ===== PATCH: L2_MACRO_LOCAL_PRIORITY_PATCH =====
    # 使用本地 K 线 + 成交量的 PA/2B/1-2-3 + volume 作为 L2 大周期主导信号
    try:
        # ===== v2.697: 使用真实OHLCV数据 =====
        ohlcv_bars = []
        use_real_ohlcv = False
        
        # 优先使用真实OHLCVWindow数据
        if ohlcv_window is not None:
            if hasattr(ohlcv_window, 'is_ready') and hasattr(ohlcv_window, 'get_bars'):
                if ohlcv_window.size() >= 20:  # v3.320修复: is_ready()要求61根,实际只需20根
                    bars_real = ohlcv_window.get_bars()
                    if len(bars_real) >= 20:  # L2需要20根
                        ohlcv_bars = bars_real
                        use_real_ohlcv = True
                        log_to_server(f"[v2.697] ✅ 使用真实OHLCV: {len(ohlcv_bars)}根K线")
                    else:
                        log_to_server(f"[v2.697] ⚠️  OHLCV不足: {len(bars_real)}根 < 20根，L2降级")
                else:
                    log_to_server(f"[v2.697] ⚠️  OHLCV未就绪 (< 8根)，L2降级")
            else:
                log_to_server(f"[v2.697] ⚠️  OHLCV窗口无效，L2降级")
        else:
            log_to_server(f"[v2.697] ⚠️  OHLCV窗口为空，L2降级")
        
        # 如果无法使用真实OHLCV，使用TV信号做简化打分（v2.711）
        if not use_real_ohlcv:
            log_to_server(f"[v2.711] ℹ️  L2分析降级：使用TV信号做简化打分")
            
            # ===== v2.711: 使用 TV 信号做简化打分 =====
            # ===== v2.713: 修复 PA 标签映射 =====
            # ===== v2.715: 统一 score_breakdown 键名 =====
            tv_score = 0
            tv_score_breakdown = {'pa': 0, '2b': 0, '123': 0, 'volume': 0}  # v2.715: 初始化所有键
            tv_reasons = ["tv_fallback"]
            
            # 1. PA tag 打分 (v2.713: 扩展支持所有 PA 类型)
            # v2.714: 统一键名为 'pa' (与 OHLCV 完整分析一致)
            # 强多头信号 (+2)
            if pa in ("STRONG_BUY", "BULL_PA", "BULL_ENGULF", "HAMMER", "MORNING_STAR", "PIERCING"):
                tv_score += 2
                tv_score_breakdown['pa'] = +2
                tv_reasons.append(f"tv_pa_bull_strong:{pa}")
            # 弱多头信号 (+1)
            elif pa in ("BUY", "BULL_CONTINUATION", "DOJI_BULL", "INSIDE_BULL"):
                tv_score += 1
                tv_score_breakdown['pa'] = +1
                tv_reasons.append(f"tv_pa_bull_weak:{pa}")
            # 强空头信号 (-2)
            elif pa in ("STRONG_SELL", "BEAR_PA", "BEAR_ENGULF", "SHOOTING_STAR", "EVENING_STAR", "DARK_CLOUD"):
                tv_score -= 2
                tv_score_breakdown['pa'] = -2
                tv_reasons.append(f"tv_pa_bear_strong:{pa}")
            # 弱空头信号 (-1)
            elif pa in ("SELL", "BEAR_CONTINUATION", "DOJI_BEAR", "INSIDE_BEAR"):
                tv_score -= 1
                tv_score_breakdown['pa'] = -1
                tv_reasons.append(f"tv_pa_bear_weak:{pa}")
            
            # 2. 如果 pa_tag 无信号，使用 pa_edge（v2.711新增）
            # v2.714: 统一键名为 'pa'
            # v2.715: 修复条件判断（检查 pa 分数是否为 0）
            if tv_score_breakdown['pa'] == 0:
                if pa_sell_edge:
                    tv_score -= 1
                    tv_score_breakdown['pa'] = -1
                    tv_reasons.append("tv_pa_edge_sell")
                elif pa_buy_edge:
                    tv_score += 1
                    tv_score_breakdown['pa'] = +1
                    tv_reasons.append("tv_pa_edge_buy")
            
            # 3. 2B tag 打分
            if tb == "BOTTOM":
                tv_score += 2
                tv_score_breakdown['2b'] = +2
                tv_reasons.append("tv_2b_bottom")
            elif tb == "TOP":
                tv_score -= 2
                tv_score_breakdown['2b'] = -2
                tv_reasons.append("tv_2b_top")
            
            # 4. Volume 辅助打分（方向确认）
            if vol in ("RISING", "CLIMAX"):
                if tv_score > 0:
                    tv_score += 1
                    tv_score_breakdown['volume'] = +1
                elif tv_score < 0:
                    tv_score -= 1
                    tv_score_breakdown['volume'] = -1
            
            # 5. 根据 score 确定 exec_bias
            if tv_score >= 2:
                tv_exec_bias = "STRONG_BUY"
            elif tv_score == 1:
                tv_exec_bias = "BUY"
            elif tv_score <= -2:
                tv_exec_bias = "STRONG_SELL"
            elif tv_score == -1:
                tv_exec_bias = "SELL"
            else:
                tv_exec_bias = "HOLD"
            
            log_to_server(f"[v2.713] TV信号打分: score={tv_score}, breakdown={tv_score_breakdown}")
            log_to_server(f"[v2.713] TV exec_bias: {tv_exec_bias}")
            
            local_info_new = {
                "ready": True,  # v2.745: TV降级模式也标记为ready，让TV信号能触发交易
                "exec_bias": tv_exec_bias,
                "pa_tag": pa,
                "two_b_tag": tb,
                "one_two_three_tag": "NONE",
                "volume_state": vol,
                "vol_ratio": 1.0,
                "score": tv_score,
                "score_breakdown": tv_score_breakdown,
                "reasons": tv_reasons,
                "candle_feat_last": {},
                "has_conflict": False,
            }
        else:
            # 使用真实OHLCV进行完整分析
            local_info_new = compute_l2_exec_bias_ohlcv_full(
                ohlcv_bars=ohlcv_bars,
                sr_zone=sr_zone_hint,
                trend_state=ts,
                wyckoff_phase=None,
                pa_edge_buy=pa_buy_edge,    # v2.520: 传递 TV pa_edge
                pa_edge_sell=pa_sell_edge,  # v2.520: 传递 TV pa_edge
            )
            
        # 适配字段名（新->旧）
        local_info = {
            "ready": local_info_new.get("ready", False),
            "exec_bias_local": local_info_new.get("exec_bias", "HOLD"),
            "pa_tag_local": local_info_new.get("pa_tag", "NONE"),
            "two_b_tag_local": local_info_new.get("two_b_tag", "NONE"),
            "pattern_tag_local": local_info_new.get("one_two_three_tag", "NONE"),
            "volume_state_local": local_info_new.get("volume_state", "NORMAL"),
            # 新增字段（供日志使用）
            "vol_ratio": local_info_new.get("vol_ratio", 1.0),
            "score": local_info_new.get("score", 0),
            "score_breakdown": local_info_new.get("score_breakdown", {}),
            "reasons": local_info_new.get("reasons", []),
            "candle_feat_last": local_info_new.get("candle_feat_last", {}),
            "has_conflict": local_info_new.get("has_conflict", False),  # v2.320
        }
        
    except Exception as e:
        # v2.745: 添加异常日志，方便诊断
        import traceback
        print(f"[L2 OHLCV] ❌ 分析异常: {e}")
        traceback.print_exc()
        # 防御性兜底：本地分析异常时，不影响原有逻辑
        local_info = {
            "ready": False,
            "exec_bias_local": "HOLD",
            "pa_tag_local": "NONE",
            "two_b_tag_local": "NONE",
            "pattern_tag_local": "NONE",
            "volume_state_local": "NORMAL",
            "has_conflict": False,  # v2.320
        }

    pa_local = local_info.get("pa_tag_local", "NONE")
    two_b_local = local_info.get("two_b_tag_local", "NONE")
    pattern_local = local_info.get("pattern_tag_local", "NONE")
    vol_local = local_info.get("volume_state_local", "NORMAL")
    exec_bias_local = local_info.get("exec_bias_local", "HOLD")
    l2_local_ready = bool(local_info.get("ready", False))

    # 有本地信号时，用本地标签覆盖 TV/LLM 提供的标签（本地为主，TV 为辅）
    if l2_local_ready:
        if pa_local != "NONE":
            pa = normalize_l2_tag(pa_local, "NONE")
        if two_b_local != "NONE":
            tb = normalize_l2_tag(two_b_local, "NONE")
        if vol_local not in ("", "NORMAL"):
            vol = normalize_l2_tag(vol_local, "NORMAL")
    # ===== PATCH END: L2_MACRO_LOCAL_PRIORITY_PATCH =====

    # 先尝试从状态中取上一根/当前 SR
    base_sr = None
    if isinstance(state, dict):
        base_sr = state.get("prev_sr") or state.get("curr_sr")

    if not base_sr:
        # 没有 SR 信息，退回旧的 sr_zone 逻辑
        eb = compute_exec_bias(
            sr_zone=sr_zone_hint,
            pa_tag=pa,
            two_b_tag=tb,
            volume_state=vol,
            trend_state=ts,
            bearish_env=bearish_env,
        )
        return eb, "NO_SR"

    try:
        support = float(base_sr.get("support"))
        mid = float(base_sr.get("mid"))
        resistance = float(base_sr.get("resistance"))
        price = float(last_close)
    except Exception:
        eb = compute_exec_bias(
            sr_zone=sr_zone_hint,
            pa_tag=pa,
            two_b_tag=tb,
            volume_state=vol,
            trend_state=ts,
            bearish_env=bearish_env,
        )
        return eb, "NO_SR"

    # ========= 维护箱体 ID 与“上半区趋势加仓”计数 =========
    box_id = f"{support:.4f}-{resistance:.4f}"
    trend_add_box_id = None
    trend_add_buy_cnt = 0
    wyckoff_phase_code = "UNCLEAR"

    if isinstance(state, dict):
        trend_add_box_id = state.get("trend_add_buy_box_id")
        trend_add_buy_cnt = int(state.get("trend_add_buy_cnt", 0) or 0)
        wyckoff_phase_code = state.get("wyckoff_phase_code", "UNCLEAR")

    # 箱体发生变化 → 重置趋势加仓次数
    if trend_add_box_id != box_id:
        trend_add_box_id = box_id
        trend_add_buy_cnt = 0
        if isinstance(state, dict):
            state["trend_add_buy_box_id"] = trend_add_box_id
            state["trend_add_buy_cnt"] = trend_add_buy_cnt

    # ========= 基于 Donchian 箱体划分区域 =========
    zone_tag = "UNKNOWN"
    if price <= support:
        zone_tag = "BELOW_SUPPORT"
    elif price <= mid:
        zone_tag = "LOWER_HALF"
    elif price <= resistance:
        zone_tag = "UPPER_HALF"
    else:
        zone_tag = "ABOVE_RESIST"

    # 用 Donchian 区域推一个 sr_zone_macro，交给原 compute_exec_bias 做细节判断
    if zone_tag in ("LOWER_HALF", "BELOW_SUPPORT"):
        sr_zone_macro = "LOWER"
    elif zone_tag in ("UPPER_HALF", "ABOVE_RESIST"):
        sr_zone_macro = "UPPER"
    else:
        sr_zone_macro = sr_zone_hint or "MID"

    # 先基于 SR 区域生成一个宏观 sr_zone_macro，然后结合 SR 事件与原 compute_exec_bias 结果
    sr_event_tag = classify_l2_sr_event(
        price=price,
        support=support,
        mid=mid,
        resistance=resistance,
        zone_tag=zone_tag,
        closes=close_prices,
        volumes=volumes,
        pa_tag=pa,
        two_b_tag=tb,
        volume_state=vol,
        trend_state=ts,
        pattern_tag_local=pattern_local if "pattern_local" in locals() else "NONE",
        volume_state_local=vol_local if "vol_local" in locals() else "NORMAL",
    )

    if sr_event_tag == "FAKE_BREAKDOWN":
        base_exec_bias = EXEC_BIAS_STRONG_BUY
    elif sr_event_tag == "FAKE_BREAKOUT":
        base_exec_bias = EXEC_BIAS_STRONG_SELL
    else:
        base_exec_bias = compute_exec_bias(
            sr_zone=sr_zone_macro,
            pa_tag=pa,
            two_b_tag=tb,
            volume_state=vol,
            trend_state=ts,
            bearish_env=bearish_env,
        )

    # ===== PATCH: L2_MACRO_LOCAL_PRIORITY_APPLY =====
    # v2.320: 修复 - OHLCV 分析强制优先级
    # 
    # 旧逻辑问题:
    #   if exec_bias_local != EXEC_BIAS_HOLD:
    #       base_exec_bias = exec_bias_local
    # 
    # 问题: 当 OHLCV 返回 HOLD（信号冲突）时，不会覆盖 compute_exec_bias 的结果
    #       导致旧的 base_exec_bias（可能是 BUY）被保留
    # 
    # 修复: OHLCV 分析完成时，无论结果如何，都优先使用
    # v2.520: 但如果是 NEUTRAL，表示 L2 尊重 L1，不覆盖
    # 
    if "exec_bias_local" in locals() and "l2_local_ready" in locals():
        if l2_local_ready:
            # v2.520: NEUTRAL = L2 不确定，尊重 L1/TV，不覆盖 base_exec_bias
            if exec_bias_local != "NEUTRAL":
                # v2.320: 强制使用 OHLCV 分析结果
                base_exec_bias = exec_bias_local
                print(f"[L2-OHLCV-PRIORITY] OHLCV分析优先: base_exec_bias = {base_exec_bias}")
                
                # v2.320: 如果有冲突，额外标记
                if local_info.get("has_conflict", False):
                    print(f"[L2-OHLCV-CONFLICT] ⚠️  检测到信号冲突，base_exec_bias = HOLD")
            else:
                # v2.520: NEUTRAL - L2 尊重 L1/TV 的判断
                print(f"[L2-OHLCV-NEUTRAL] L2 无明确结构但 TV 有 pa_edge，尊重 L1: base_exec_bias 保持 {base_exec_bias}")
    # ===== PATCH END: L2_MACRO_LOCAL_PRIORITY_APPLY =====

    # ========= 上涨箱体上半区域：允许 1 次趋势加仓 BUY =========
    # v2.320: 增加冲突检查 - 信号冲突时不允许加仓
    allow_upper_bull_once = False
    
    # v2.320: 检查是否有信号冲突
    has_ohlcv_conflict = local_info.get("has_conflict", False) if 'local_info' in locals() else False

    is_bull = ("BULL" in pa) or ("BUY" in pa) or ("BULL" in tb)
    is_up_trend_phase = wyckoff_phase_code in ("MARKUP_TREND", "ACCUM_RANGE_B")
    is_strong_up = ts in ("UP", "STRONG_UP")
    is_upper_zone = zone_tag in ("UPPER_HALF", "ABOVE_RESIST")
    volume_ok = vol in ("RISING", "NORMAL")
    not_bearish = not bearish_env

    if (
        base_exec_bias == EXEC_BIAS_HOLD
        and is_upper_zone
        and is_bull
        and is_up_trend_phase
        and is_strong_up
        and volume_ok
        and not_bearish
        and trend_add_buy_cnt < 1
        and not has_ohlcv_conflict  # v2.320: 信号冲突时不加仓
    ):
        # 在上涨箱体上半区，给 1 次 BUY 的趋势加仓机会
        base_exec_bias = EXEC_BIAS_BUY
        allow_upper_bull_once = True
        trend_add_buy_cnt += 1
        if isinstance(state, dict):
            state["trend_add_buy_cnt"] = trend_add_buy_cnt
        print(f"[TREND-ADD-BUY] 上涨箱体上半区趋势加仓: HOLD → BUY (count={trend_add_buy_cnt})")
    elif base_exec_bias == EXEC_BIAS_HOLD and is_upper_zone and is_bull and has_ohlcv_conflict:
        # v2.320: 冲突拦截日志
        print(f"[TREND-ADD-BUY] ⚠️  信号冲突拦截: 不允许上涨箱体加仓")

    # ===== PATCH: N-SWING AUTO-ANCHOR (Fixed Position) =====
    # N-swing 自动锚点：基于最近波段的 2%/3% 突破判断
    # v2.712: TV 推送优先
    try:
        # ===== v2.712: TV N-Swing 优先 =====
        tv_n_swing_used = False
        if tv_n_swing_bias and tv_n_swing_bias != "NONE":
            # 映射 TV 格式到本地格式
            tv_to_local_bias = {
                "BUY_STRONG": "N_BUY_STRONG",
                "BUY_WEAK": "N_BUY_WEAK", 
                "SELL_STRONG": "N_SELL_STRONG",
                "SELL_WEAK": "N_SELL_WEAK",
                "NONE": "N_NONE"
            }
            n_bias = tv_to_local_bias.get(tv_n_swing_bias, "N_NONE")
            n_score = int(tv_n_swing_score) if tv_n_swing_score is not None else 0
            tv_n_swing_used = True
            log_to_server(f"[v2.712] ✅ 使用TV推送的N-Swing: bias={n_bias}, score={n_score}")
            
            # 设置占位变量（用于后续逻辑）
            up_after_low = None
            down_after_high = None
            last_up_end = None
            last_down_end = None
            closes_nswing = []
        # ===== v2.712 END =====
        
        if not tv_n_swing_used and isinstance(close_prices, list) and len(close_prices) >= 10:
            closes_nswing = list(close_prices)  # 已经是 旧→新 顺序
            if len(closes_nswing) > _l2_buf:
                closes_nswing = closes_nswing[-_l2_buf:]
            
            # 计算方向变化
            dirs = [1 if closes_nswing[i] > closes_nswing[i-1] else -1 
                    for i in range(1, len(closes_nswing))]
            
            # 找最近的上涨段和下跌段结束点
            last_up_end, last_down_end = None, None
            for i in range(len(dirs)-2, 1, -1):
                if dirs[i] < 0 and dirs[i-1] > 0 and last_up_end is None:
                    last_up_end = i
                if dirs[i] > 0 and dirs[i-1] < 0 and last_down_end is None:
                    last_down_end = i
                if last_up_end is not None and last_down_end is not None:
                    break
            
            # 计算上涨后的低点 & 下跌后的高点
            up_after_low = None
            down_after_high = None
            
            if last_up_end is not None and last_up_end < len(closes_nswing):
                segment = closes_nswing[last_up_end:]
                if segment:
                    up_after_low = min(segment)
            
            if last_down_end is not None and last_down_end < len(closes_nswing):
                segment = closes_nswing[last_down_end:]
                if segment:
                    down_after_high = max(segment)
            
            # 判断 N-swing 偏向
            n_bias = 'N_NONE'
            n_score = 0
            
            if up_after_low and up_after_low > 0:
                up_ratio = last_close / up_after_low
                if 1.02 <= up_ratio < 1.03:
                    n_bias, n_score = 'N_BUY_WEAK', 1
                elif up_ratio >= 1.03:
                    n_bias, n_score = 'N_BUY_STRONG', 2
            
            if down_after_high and down_after_high > 0:
                down_ratio = last_close / down_after_high
                if 0.98 >= down_ratio > 0.97:
                    n_bias, n_score = 'N_SELL_WEAK', -1
                elif down_ratio <= 0.97:
                    n_bias, n_score = 'N_SELL_STRONG', -2
            

            
            # ===== P0增强 (简化版): 只用现有数据的2项过滤 =====
            # 注意: K线实体验证需要OHLC数据，暂不启用
            
            # P0增强1: 量价背离检测
            if n_score != 0:
                if n_score > 0 and 'last_up_end' in locals() and last_up_end is not None:
                    segment_closes = closes_nswing[last_up_end:] if 'closes_nswing' in locals() else []
                    segment_vols = volumes[last_up_end:] if volumes and len(volumes) > last_up_end else None
                    
                    if segment_closes and segment_vols:
                        divergence = detect_volume_price_divergence_p0(segment_closes, segment_vols, window=5)
                        if divergence == "BEARISH_DIV":
                            print(f'[N-SWING-P0] 检测到顶背离 (价涨量缩), 取消多头增强')
                            n_score = 0
                            n_bias = 'N_NONE'

                elif n_score < 0 and 'last_down_end' in locals() and last_down_end is not None:
                    segment_closes = closes_nswing[last_down_end:] if 'closes_nswing' in locals() else []
                    segment_vols = volumes[last_down_end:] if volumes and len(volumes) > last_down_end else None

                    if segment_closes and segment_vols:
                        divergence = detect_volume_price_divergence_p0(segment_closes, segment_vols, window=5)
                        if divergence == "BULLISH_DIV":
                            print(f'[N-SWING-P0] 检测到底背离 (价跌量增), 取消空头增强')
                            n_score = 0
                            n_bias = 'N_NONE'
            
            # P0增强2: 时间权重
            if n_score != 0:
                bars_needed = 0
                if n_score > 0 and 'last_up_end' in locals() and last_up_end is not None and 'closes_nswing' in locals():
                    bars_needed = len(closes_nswing) - last_up_end
                elif n_score < 0 and 'last_down_end' in locals() and last_down_end is not None and 'closes_nswing' in locals():
                    bars_needed = len(closes_nswing) - last_down_end
                
                if bars_needed > 0:
                    time_weight = compute_n_swing_time_weight(bars_needed)
                    n_score_original = n_score
                    n_score_weighted = int(n_score * time_weight)
                    
                    if abs(n_score_weighted) >= 2:
                        pass  # 保持强信号
                    elif abs(n_score_weighted) >= 1:
                        n_score = 1 if n_score > 0 else -1
                        n_bias = 'N_BUY_WEAK' if n_score > 0 else 'N_SELL_WEAK'
                    else:
                        n_score = 0
                        n_bias = 'N_NONE'
                    
                    if n_score_weighted != n_score_original:
                        print(f'[N-SWING-P0] 时间权重调整: bars={bars_needed}, weight={time_weight:.1f}, score: {n_score_original} -> {n_score_weighted}')
            
            # P0增强3: K线实体验证 (需要OHLC数据，暂不启用)
            # 提示: 如果后续更新TV脚本添加OHLC，可启用此功能

            # 应用 N-swing 增强(只在原信号已有方向时加强)
            n_swing_applied = False
            up_ratio_val = float(last_close / up_after_low) if up_after_low and up_after_low > 0 else None
            down_ratio_val = float(last_close / down_after_high) if down_after_high and down_after_high > 0 else None
            
            # [PATCHED v2.050] N-swing增强规则修正：
            # 规则1: 只能增强同方向（BUY→STRONG_BUY, SELL→STRONG_SELL）
            # 规则2: 禁止从HOLD变为交易（HOLD不能升级）
            # 规则3: 只有STRONG信号(score=±2)才能升级
            
            if abs(n_score) >= 2:  # 只有强信号才处理
                # 多头强信号：只能升级BUY，不能从HOLD变BUY
                if n_score > 0 and base_exec_bias == EXEC_BIAS_BUY:
                    base_exec_bias = EXEC_BIAS_STRONG_BUY
                    n_swing_applied = True
                    print(f'[N-SWING] 多头增强: {n_bias}, score={n_score}, BUY→STRONG_BUY, up_ratio={up_ratio_val:.4f}' if up_ratio_val else f'[N-SWING] 多头增强: {n_bias}, score={n_score}, BUY→STRONG_BUY')
                
                # 空头强信号：只能升级SELL，不能从HOLD变SELL
                elif n_score < 0 and base_exec_bias == EXEC_BIAS_SELL:
                    base_exec_bias = EXEC_BIAS_STRONG_SELL
                    n_swing_applied = True
                    print(f'[N-SWING] 空头增强: {n_bias}, score={n_score}, SELL→STRONG_SELL, down_ratio={down_ratio_val:.4f}' if down_ratio_val else f'[N-SWING] 空头增强: {n_bias}, score={n_score}, SELL→STRONG_SELL')
                
                # 禁止修改的情况
                elif n_score > 0 and base_exec_bias in [EXEC_BIAS_HOLD, EXEC_BIAS_SELL, EXEC_BIAS_STRONG_SELL]:
                    print(f'[N-SWING] 多头信号被忽略: base_exec_bias={base_exec_bias}与N-swing方向不符或为HOLD，不修改')
                
                elif n_score < 0 and base_exec_bias in [EXEC_BIAS_HOLD, EXEC_BIAS_BUY, EXEC_BIAS_STRONG_BUY]:
                    print(f'[N-SWING] 空头信号被忽略: base_exec_bias={base_exec_bias}与N-swing方向不符或为HOLD，不修改')
            
            else:
                # 弱信号(score=±1)或无信号(score=0)：完全不修改
                if n_score != 0:
                    print(f'[N-SWING] 弱信号被忽略: {n_bias}, score={n_score}, 不修改base_exec_bias')
            
            # [PATCH v2.049] 保存N-swing信息到state，增加优先级标记
            if isinstance(state, dict):
                state['_n_swing_info'] = {
                    'applied': n_swing_applied,
                    'bias': n_bias,
                    'score': n_score,
                    'is_strong': abs(n_score) >= 2,  # v2.049新增
                    'priority_level': 'HIGH' if abs(n_score) >= 2 else 'NORMAL',  # v2.049新增
                    'up_after_low': float(up_after_low) if up_after_low else None,
                    'down_after_high': float(down_after_high) if down_after_high else None,
                    'up_ratio': up_ratio_val,
                    'down_ratio': down_ratio_val,
                }
            
    except Exception as e:
        print(f'[WARN] N-swing autoanchor failed: {e}')
    # ===== PATCH END: N-SWING AUTO-ANCHOR =====
    # ===== v2.049: Direction Gate 逻辑优化 =====
    # ===== v2.985: 放宽位置保护，只在极端位置拦截 =====
    # 原则：N-Swing STRONG 信号应该保留方向判断，但仍可被Gate降级
    
    dir_tag = _exec_bias_dir_tag(base_exec_bias)
    n_swing_strong = bool(
        state.get('_n_swing_info', {}).get('applied') and 
        abs(state.get('_n_swing_info', {}).get('score', 0)) >= 2
    )
    
    # v3.503: 极端位置禁止规则 - 统一pos_ratio判断
    # 问题: zone_tag用price<=support，l2_zone_tag用dist_to_support<10%，判断不一致
    # 案例: HIMS price=32.08 > support=31.4 → zone_tag=LOWER_HALF，但pos_ratio=7.47%是极低位
    # 解决: 增加pos_ratio检查，极低位(<10%)禁空，极高位(>90%)禁多
    pos_ratio_local = (price - support) / (resistance - support) if resistance > support else 0.5
    is_extreme_low = zone_tag == "BELOW_SUPPORT" or pos_ratio_local < 0.10
    is_extreme_high = zone_tag == "ABOVE_RESIST" or pos_ratio_local > 0.90

    if is_extreme_low and dir_tag == "BEAR":  # v3.503: 极低位(<10%)禁止做空
        if n_swing_strong:
            # N-Swing STRONG 信号：降级但保留方向
            final_exec_bias = EXEC_BIAS_SELL  # 从STRONG_SELL降到SELL
            print(f"[DIR-GATE] 极低位禁空(pos={pos_ratio_local:.1%})，但N-Swing STRONG保留: STRONG_SELL → SELL")
        else:
            # 非N-Swing或弱信号：完全拦截
            final_exec_bias = EXEC_BIAS_HOLD
            print(f"[DIR-GATE] 极低位禁空(pos={pos_ratio_local:.1%}): {base_exec_bias} → HOLD")

    elif is_extreme_high and dir_tag == "BULL" and not allow_upper_bull_once:  # v3.503: 极高位(>90%)禁止做多
        if n_swing_strong:
            # N-Swing STRONG 信号：降级但保留方向
            final_exec_bias = EXEC_BIAS_BUY  # 从STRONG_BUY降到BUY
            print(f"[DIR-GATE] 极高位禁多(pos={pos_ratio_local:.1%})，但N-Swing STRONG保留: STRONG_BUY → BUY")
        else:
            # 非N-Swing或弱信号：完全拦截
            final_exec_bias = EXEC_BIAS_HOLD
            print(f"[DIR-GATE] 极高位禁多(pos={pos_ratio_local:.1%}): {base_exec_bias} → HOLD")

    else:
        # 在箱体内正常交易，完全保留N-Swing增强
        final_exec_bias = base_exec_bias
    # ===== END v2.049 / v2.985 =====
    
    # ===== v2.320: 最终冲突保护层 =====
    # 即使前面所有逻辑都执行了，如果 OHLCV 检测到信号冲突，
    # 最终仍然强制 HOLD，防止被任何逻辑覆盖
    has_ohlcv_conflict = local_info.get("has_conflict", False) if 'local_info' in locals() else False
    if has_ohlcv_conflict and final_exec_bias != EXEC_BIAS_HOLD:
        print(f"\n{'='*70}")
        print(f"[L2-CONFLICT-PROTECTION] ⚠️  最终冲突保护层触发")
        print(f"{'='*70}")
        print(f"OHLCV 分析检测到信号冲突:")
        print(f"  PA tag:  {local_info.get('pa_tag_local', 'N/A')}")
        print(f"  2B tag:  {local_info.get('two_b_tag_local', 'N/A')}")
        print(f"  123 tag: {local_info.get('pattern_tag_local', 'N/A')}")
        print(f"  Score:   {local_info.get('score', 0)}")
        print(f"")
        print(f"原 final_exec_bias: {final_exec_bias}")
        print(f"强制修改为:        HOLD")
        print(f"")
        print(f"⚠️  信号冲突时必须 HOLD，不可交易！")
        print(f"{'='*70}\n")
        final_exec_bias = EXEC_BIAS_HOLD
    # ===== END v2.320 =====

    # v2.048: 返回L2详细分析结果
    # v2.250: 添加SR信息到返回值
    # v2.320: 添加has_conflict标记
    # v2.500: 添加RSI信息
    l2_detail = {
        "pa_tag_local": local_info.get("pa_tag_local", "NONE") if 'local_info' in locals() else "NONE",
        "two_b_tag_local": local_info.get("two_b_tag_local", "NONE") if 'local_info' in locals() else "NONE",
        "pattern_tag_local": local_info.get("pattern_tag_local", "NONE") if 'local_info' in locals() else "NONE",
        "volume_state_local": local_info.get("volume_state_local", "NORMAL") if 'local_info' in locals() else "NORMAL",
        "vol_ratio": local_info.get("vol_ratio", 1.0) if 'local_info' in locals() else 1.0,
        "score": local_info.get("score", 0) if 'local_info' in locals() else 0,
        "score_breakdown": local_info.get("score_breakdown", {}) if 'local_info' in locals() else {},
        "reasons": local_info.get("reasons", []) if 'local_info' in locals() else [],
        "ready": local_info.get("ready", False) if 'local_info' in locals() else False,
        "has_conflict": has_ohlcv_conflict,  # v2.320
        # v2.250: 添加SR信息
        "sr_support": base_sr.get("support") if base_sr else None,
        "sr_mid": base_sr.get("mid") if base_sr else None,
        "sr_resistance": base_sr.get("resistance") if base_sr else None,
        # v2.500: 添加RSI信息
        "rsi14": rsi14,
        "rsi_signal": rsi_signal,
        "score_rsi": score_rsi,
    }
    
    return final_exec_bias, zone_tag, l2_detail

def check_sell_direction_lock(
    llm_raw_action: str, 
    l1_action: str, 
    l2_exec_bias: str,
    llm_confidence: float = 0.0,
    l2_score: int = 0,
    l2_has_conflict: bool = False
) -> dict:
    """
    SELL 方向锁定检查 v2.570 (修复版)
    
    v2.570 核心改进:
    1. 添加LLM置信度门槛：>= 0.70 才触发锁定
    2. 添加L2评分检查：Score > 0 或无冲突时才锁定
    3. 分级保护：高/中/低置信度不同处理
    
    触发条件（必须同时满足）：
    - LLM = SELL
    - L1 = SELL  
    - LLM confidence >= 0.60 (基础门槛)
    - L2 Score > 0 或 无冲突 (质量门槛)
    
    Args:
        llm_raw_action: LLM 原始输出
        l1_action: L1 最终方向
        l2_exec_bias: L2 执行偏好
        llm_confidence: LLM 置信度 (0.0-1.0)
        l2_score: L2 评分 (-10 到 +10)
        l2_has_conflict: L2 是否检测到信号冲突
        
    Returns:
        {
            "locked": bool,
            "lock_level": str,  # NONE/LOW/MEDIUM/HIGH
            "original_l1": str,
            "reason": str,
            "intensity_adjust": str,
        }
    """
    lock_result = {
        "locked": False,
        "lock_level": "NONE",
        "original_l1": l1_action,
        "reason": "",
        "intensity_adjust": "",
    }
    
    # 标准化输入
    llm_raw = (llm_raw_action or "HOLD").upper()
    l1 = (l1_action or "HOLD").upper()
    l2 = (l2_exec_bias or "HOLD").upper()
    
    # ========================================================================
    # 阶段1: 基础条件检查
    # ========================================================================
    
    if not (llm_raw == "SELL" and l1 == "SELL"):
        # 不是双SELL，直接返回
        return lock_result
    
    # ========================================================================
    # 阶段2: 置信度分级检查 (v2.570核心改进)
    # ========================================================================
    
    # 2.1: 极低置信度 (< 0.60) - 不触发锁定
    if llm_confidence < 0.60:
        lock_result["reason"] = f"SELL信号置信度过低({llm_confidence:.2f} < 0.60)，不触发锁定"
        print(f"[SELL_LOCK] ✗ 置信度过低: conf={llm_confidence:.2f} < 0.60，放弃锁定")
        return lock_result
    
    # 2.2: 低置信度 (0.60-0.70) - 仅在L2强支持时锁定
    if 0.60 <= llm_confidence < 0.70:
        if l2_score >= 3:
            # L2强支持，触发弱锁定
            lock_result["locked"] = True
            lock_result["lock_level"] = "LOW"
            lock_result["reason"] = f"低置信度({llm_confidence:.2f})但L2强支持(score={l2_score})"
            lock_result["intensity_adjust"] = "LOCKED_WEAK_SELL"
            print(f"[SELL_LOCK] △ 弱锁定: conf={llm_confidence:.2f}, L2_score={l2_score}")
            return lock_result
        else:
            lock_result["reason"] = f"低置信度({llm_confidence:.2f})且L2弱支持(score={l2_score})，不锁定"
            print(f"[SELL_LOCK] ✗ L2支持不足: conf={llm_confidence:.2f}, score={l2_score}")
            return lock_result
    
    # 2.3: 中置信度 (0.70-0.85) - 需要L2无冲突
    if 0.70 <= llm_confidence < 0.85:
        if l2_has_conflict:
            # L2检测到冲突，不锁定
            lock_result["reason"] = f"中置信度({llm_confidence:.2f})但L2检测到信号冲突，不锁定"
            print(f"[SELL_LOCK] ✗ L2冲突: conf={llm_confidence:.2f}, conflict=True")
            return lock_result
        else:
            # 无冲突，触发中等锁定
            lock_result["locked"] = True
            lock_result["lock_level"] = "MEDIUM"
            lock_result["reason"] = f"中置信度({llm_confidence:.2f})且L2无冲突"
            lock_result["intensity_adjust"] = "LOCKED_STANDARD_SELL"
            print(f"[SELL_LOCK] ○ 标准锁定: conf={llm_confidence:.2f}, no_conflict")
            return lock_result
    
    # 2.4: 高置信度 (>= 0.85) - 强制锁定（除非L2强烈反对）
    if llm_confidence >= 0.85:
        if l2_has_conflict and l2_score < -3:
            # L2强烈反对（冲突+负分），降级锁定
            lock_result["locked"] = True
            lock_result["lock_level"] = "MEDIUM"
            lock_result["reason"] = f"高置信度({llm_confidence:.2f})但L2强烈反对(score={l2_score})"
            lock_result["intensity_adjust"] = "LOCKED_STANDARD_SELL"
            print(f"[SELL_LOCK] ○ 降级锁定: conf={llm_confidence:.2f}, L2_oppose")
            return lock_result
        else:
            # 强制锁定
            lock_result["locked"] = True
            lock_result["lock_level"] = "HIGH"
            lock_result["reason"] = f"高置信度({llm_confidence:.2f})强制锁定"
            
            # 根据L2判断强度
            if l2 in ["STRONG_SELL", "SELL"]:
                lock_result["intensity_adjust"] = f"ALIGNED_{l2}"
            else:
                lock_result["intensity_adjust"] = "LOCKED_STRONG_SELL"
            
            print(f"[SELL_LOCK] ✓ 强锁定: conf={llm_confidence:.2f}, level=HIGH")
            return lock_result
    
    # 默认返回（不应该到这里）
    return lock_result


def apply_exec_bias_on_action(l1_action: str, exec_bias: str, has_conflict: bool = False, pos_ratio: float = None):
    """
    L1-L2 双向尊重合并逻辑 (v2.330重构)
    
    v2.330 核心改进:
    - 区分"L2无信号"和"L2信号冲突"
    - HOLD + 无冲突 → 尊重L1
    - HOLD + 有冲突 → 强制HOLD
    - 完善L1/L2互相尊重逻辑
    
    核心规则：
    1. L2 信号冲突 → 强制 HOLD（最高优先级）
    2. L2 无信号 → 尊重 L1
    3. L1=SELL 且 L2≠BUY → 执行 SELL
    4. L1=BUY  且 L2≠SELL → 执行 BUY
    5. L2=BUY  且 L1≠SELL → 执行 BUY
    6. L2=SELL 且 L1≠BUY  → 执行 SELL
    7. L1 和 L2 明确反向 → HOLD
    
    参数:
        l1_action: L1决策 (BUY/SELL/HOLD)
        exec_bias: L2执行偏好 (STRONG_BUY/BUY/SELL/STRONG_SELL/HOLD)
        has_conflict: L2是否检测到信号冲突 (v2.330新增)
    
    返回: (new_action, reason_tag)
    """
    # 标准化输入
    l1 = (l1_action or "HOLD").upper()
    l2_bias = (exec_bias or "HOLD").upper()
    
    # ========================================================================
    # v2.470: HOLD_SUGGEST 处理 (满仓高位减仓优化)
    # ========================================================================
    if l2_bias == "HOLD_SUGGEST":
        # HOLD_SUGGEST: 建议 HOLD，但允许 L1 的 SELL 通过
        if l1 == "SELL":
            print(f"\n{'='*70}")
            print(f"[v2.470 Position Reduce] HOLD_SUGGEST → 允许 L1 SELL")
            print(f"{'='*70}")
            print(f"L1 action:     {l1}")
            print(f"L2 exec_bias:  {l2_bias}")
            print(f"结果: SELL (满仓高位允许减仓)")
            print(f"理由: POSITION_REDUCE_ALLOW_SELL")
            print(f"{'='*70}\n")
            return "SELL", "POSITION_REDUCE_ALLOW_SELL"
        else:
            print(f"\n{'='*70}")
            print(f"[v2.470 Position Reduce] HOLD_SUGGEST → HOLD")
            print(f"{'='*70}")
            print(f"L1 action:     {l1}")
            print(f"L2 exec_bias:  {l2_bias}")
            print(f"结果: HOLD (建议持有)")
            print(f"理由: HOLD_SUGGESTED")
            print(f"{'='*70}\n")
            return "HOLD", "HOLD_SUGGESTED"
    # ========================================================================
    # End of v2.470 HOLD_SUGGEST
    # ========================================================================
    
    # 将 L2 exec_bias 转换为方向
    if l2_bias in ["STRONG_BUY", "BUY"]:
        l2_direction = "BUY"
    elif l2_bias in ["STRONG_SELL", "SELL"]:
        l2_direction = "SELL"
    else:  # HOLD 或其他
        l2_direction = "HOLD"
    
    # v2.300: 增强日志输出
    print(f"\n{'='*70}")
    print(f"[L2→L1 MAPPING] 决策映射 (v2.330)")
    print(f"{'='*70}")
    print(f"输入:")
    print(f"  L1 action:     {l1}")
    print(f"  L2 exec_bias:  {l2_bias}")
    print(f"  L2 direction:  {l2_direction}")
    print(f"  L2 has_conflict: {has_conflict}")  # v2.330
    print(f"")
    
    # ===== v2.330/v2.395: 优先级0 - L2 信号冲突 → 需要协商 =====
    if l2_bias == "HOLD" and has_conflict:
        # v2.698: 极端位置豁免冲突锁定
        if pos_ratio is not None:
            if pos_ratio < 0.10 and l1 == "BUY":
                print(f"[CONFLICT_EXEMPT] ⚡ 极低位({pos_ratio:.1%})豁免冲突，允许BUY")
                print(f"{'='*70}\n")
                return l1, "CONFLICT_EXEMPT_LOW_POSITION_BUY"
            if pos_ratio > 0.90 and l1 == "SELL":
                print(f"[CONFLICT_EXEMPT] ⚡ 极高位({pos_ratio:.1%})豁免冲突，允许SELL")
                print(f"{'='*70}\n")
                return l1, "CONFLICT_EXEMPT_HIGH_POSITION_SELL"
        
        # v2.395: 这里需要检查 L1 置信度
        # 但由于函数签名限制，暂时保持原有逻辑
        # TODO: 在调用处集成 merge_l2_with_l1_action
        print(f"⚠️  最高优先级: L2信号冲突")
        print(f"匹配规则: L2 CONFLICT → 强制 HOLD")
        print(f"结果: HOLD (信号冲突，风控保护)")
        print(f"理由: L2_CONFLICT_HOLD")
        print(f"说明: L2检测到多空信号冲突，为保护资金强制HOLD")
        print(f"说明: v2.395: 如需L1高置信度覆盖，请在调用处使用merge_l2_with_l1_action")
        print(f"{'='*70}\n")
        return "HOLD", "L2_CONFLICT_HOLD"
    
    # ===== v2.330: 优先级1 - L2 无信号 (HOLD) → 尊重 L1 =====
    # v2.395: 增加置信度判断
    if l2_bias == "HOLD" and not has_conflict:
        # v2.395: 检查是否需要协商
        # 从 decision 获取 L1 置信度 (需要在调用处传递)
        # 为了向后兼容，这里先用简单逻辑
        print(f"匹配规则: L2无信号 → 尊重L1")
        print(f"结果: {l1} (L1主导)")
        print(f"理由: L2_NO_SIGNAL_RESPECT_L1")
        print(f"说明: L2无明确信号(PA=NONE,2B=NONE,123=NONE)，尊重L1判断")
        print(f"{'='*70}\n")
        return l1, "L2_NO_SIGNAL_RESPECT_L1"
    
    # ===== 规则2: L1=SELL 且 L2≠BUY → 执行 SELL =====
    if l1 == "SELL" and l2_direction != "BUY":
        if l2_direction == "SELL":
            print(f"匹配规则: 规则2 - L1=SELL 且 L2=SELL")
            print(f"结果: SELL (双方同意)")
            print(f"理由: L1_L2_AGREE_SELL")
            print(f"{'='*70}\n")
            return "SELL", "L1_L2_AGREE_SELL"  # 双方同意
        else:  # L2=HOLD (但不是因为冲突)
            print(f"匹配规则: 规则2 - L1=SELL 且 L2=HOLD")
            print(f"结果: SELL (L1主导)")
            print(f"理由: L1_SELL_L2_NEUTRAL")
            print(f"{'='*70}\n")
            return "SELL", "L1_SELL_L2_NEUTRAL"  # L1主导
    
    # ===== 规则3: L1=BUY 且 L2≠SELL → 执行 BUY =====
    if l1 == "BUY" and l2_direction != "SELL":
        if l2_direction == "BUY":
            print(f"匹配规则: 规则3 - L1=BUY 且 L2=BUY")
            print(f"结果: BUY (双方同意)")
            print(f"理由: L1_L2_AGREE_BUY")
            print(f"{'='*70}\n")
            return "BUY", "L1_L2_AGREE_BUY"  # 双方同意
        else:  # L2=HOLD (但不是因为冲突)
            print(f"匹配规则: 规则3 - L1=BUY 且 L2=HOLD")
            print(f"结果: BUY (L1主导)")
            print(f"理由: L1_BUY_L2_NEUTRAL")
            print(f"{'='*70}\n")
            return "BUY", "L1_BUY_L2_NEUTRAL"  # L1主导
    
    # ===== 规则4: L2=BUY 且 L1≠SELL → 执行 BUY =====
    if l2_direction == "BUY" and l1 != "SELL":
        if l1 == "BUY":
            print(f"匹配规则: 规则4 - L2=BUY 且 L1=BUY")
            print(f"结果: BUY (双方同意)")
            print(f"理由: L1_L2_AGREE_BUY")
            print(f"{'='*70}\n")
            return "BUY", "L1_L2_AGREE_BUY"  # 已在上面处理
        else:  # L1=HOLD
            print(f"匹配规则: 规则4 - L2=BUY 且 L1=HOLD")
            print(f"结果: BUY (L2主导)")
            print(f"理由: L2_BUY_L1_NEUTRAL")
            print(f"说明: L2分析发现买入机会，L1未反对")
            print(f"{'='*70}\n")
            return "BUY", "L2_BUY_L1_NEUTRAL"  # L2主导
    
    # ===== 规则5: L2=SELL 且 L1≠BUY → 执行 SELL =====
    if l2_direction == "SELL" and l1 != "BUY":
        if l1 == "SELL":
            print(f"匹配规则: 规则5 - L2=SELL 且 L1=SELL")
            print(f"结果: SELL (双方同意)")
            print(f"理由: L1_L2_AGREE_SELL")
            print(f"{'='*70}\n")
            return "SELL", "L1_L2_AGREE_SELL"  # 已在上面处理
        else:  # L1=HOLD
            print(f"匹配规则: 规则5 - L2=SELL 且 L1=HOLD")
            print(f"结果: SELL (L2主导)")
            print(f"理由: L2_SELL_L1_NEUTRAL")
            print(f"说明: L2分析发现卖出机会，L1未反对")
            print(f"{'='*70}\n")
            return "SELL", "L2_SELL_L1_NEUTRAL"  # L2主导
    
    # ===== 冲突情况：L1 和 L2 明确反向 =====
    if l1 == "BUY" and l2_direction == "SELL":
        print(f"⚠️  冲突检测: L1=BUY vs L2=SELL")
        print(f"结果: HOLD (方向冲突)")
        print(f"理由: L1_BUY_L2_SELL_CONFLICT")
        print(f"{'='*70}\n")
        return "HOLD", "L1_BUY_L2_SELL_CONFLICT"
    
    if l1 == "SELL" and l2_direction == "BUY":
        print(f"⚠️  冲突检测: L1=SELL vs L2=BUY")
        print(f"结果: HOLD (方向冲突)")
        print(f"理由: L1_SELL_L2_BUY_CONFLICT")
        print(f"{'='*70}\n")
        return "HOLD", "L1_SELL_L2_BUY_CONFLICT"
    
    # ===== 默认：双方都是 HOLD =====
    print(f"匹配规则: 默认 - 双方都是 HOLD")
    print(f"结果: HOLD")
    print(f"理由: L1_L2_BOTH_HOLD")
    print(f"{'='*70}\n")
    return "HOLD", "L1_L2_BOTH_HOLD"

# === MICRO_TIMING_GATE v1.983 ===
def _exec_bias_dir_tag(exec_bias: str) -> str:
    """
    将 exec_bias 映射为方向标签：
    - STRONG_BUY / BUY   → BULL
    - STRONG_SELL / SELL → BEAR
    - 其它                  → NEUTRAL
    """
    eb = (exec_bias or "").upper()
    if eb in (EXEC_BIAS_STRONG_BUY, EXEC_BIAS_BUY):
        return "BULL"
    if eb in (EXEC_BIAS_STRONG_SELL, EXEC_BIAS_SELL):
        return "BEAR"
    return "NEUTRAL"

def _append_unique_reason(reasons_list: list, reason: str):
    """防止 fallback_reasons 重复添加"""
    if reason not in reasons_list:
        reasons_list.append(reason)

def apply_micro_timing_gate(
    symbol: str,
    l1_action: str,
    exec_bias: str,
    state: dict,
    max_age_sec: float = 1800.0  # 30分钟有效期,
):
    """
    # [DEPRECATED v2.910] 此函数已失效，计数器从未递增导致永远跳过检查
    MICRO_TIMING_GATE v1.992:
    - 仅对“新开仓”动作做刹车；
    - 不会把 HOLD 升级为 BUY/SELL；
    - 若当前方向开仓次数 < 3，则跳过 micro gate 直接放行；
    - 从第4次开仓起才执行10m信号检查；
    - 平仓/减仓不受影响。

    gate_log 结构:
    {
      "applied": True/False,
      "pass": True/False,
      "original_action": ...,
      "new_action": ...,
      "entry_type": ...,
      "mid_exec_bias": exec_bias,
      "micro_exec_bias_10m": exec_bias_10m,
      "micro_reversal_10m": micro_reversal_10m,
      "combo_tag": ...,
      "skip_micro_by_count": True/False,
      "reasons": [...],
    }
    """
    from time import time as _time

    original_action = (l1_action or "HOLD").upper()
    open_buys = state.get("open_buys", []) or []
    open_sells = state.get("open_sells", []) or []

    gate_log = {
        "applied": True,
        "pass": True,
        "original_action": original_action,
        "new_action": original_action,
        "entry_type": "NONE",
        "mid_exec_bias": exec_bias,
        "micro_exec_bias_10m": None,
        "micro_reversal_10m": None,
        "combo_tag": "",
        "skip_micro_by_count": False,
        "reasons": [],
    }

    if original_action not in ("BUY", "SELL"):
        gate_log["applied"] = False
        gate_log["reasons"].append("no_trade_action")
        return original_action, gate_log

    # 判定开仓/平仓
    if original_action == "BUY":
        entry_type = "LONG_ENTRY" if len(open_sells) == 0 else "LONG_EXIT_OR_REDUCE"
    else:
        entry_type = "SHORT_ENTRY" if len(open_buys) == 0 else "SHORT_EXIT_OR_REDUCE"

    gate_log["entry_type"] = entry_type
    is_entry = entry_type in ("LONG_ENTRY", "SHORT_ENTRY")

    # 非开仓动作，直接放行
    if not is_entry:
        gate_log["reasons"].append("not_entry_action_no_micro_block")
        return original_action, gate_log

    # 获取开仓计数
    open_buys_cnt = int(state.get("open_buys_cnt", 0))
    open_sells_cnt = int(state.get("open_sells_cnt", 0))

    # ---------------- 前三次开仓直接跳过 micro gate ----------------
    if (original_action == "BUY" and open_buys_cnt < 3) or        (original_action == "SELL" and open_sells_cnt < 3):
        gate_log["skip_micro_by_count"] = True
        gate_log["reasons"].append("first_3_entries_skip_micro_gate")
        return original_action, gate_log
    # ----------------------------------------------------------------

    # 读取10m层
    try:
        l2_10m = get_l2_10m_for_symbol(symbol)
    except Exception:
        l2_10m = None

    micro_exec_bias = None
    micro_reversal = None
    has_fresh = False
    age_sec = None

    if isinstance(l2_10m, dict) and l2_10m:
        micro_exec_bias = l2_10m.get("exec_bias_10m")
        micro_reversal = l2_10m.get("micro_reversal_10m") or "NONE"
        ts_ms = l2_10m.get("time_ms")
        if ts_ms is not None:
            try:
                age_sec = _time() - (float(ts_ms) / 1000.0)
                has_fresh = age_sec <= max_age_sec
            except Exception:
                has_fresh = True
        else:
            has_fresh = True
    else:
        has_fresh = False

    gate_log["micro_exec_bias_10m"] = micro_exec_bias
    gate_log["micro_reversal_10m"] = micro_reversal

    if not has_fresh:
        gate_log["pass"] = False
        gate_log["new_action"] = "HOLD"
        gate_log["reasons"].append("no_fresh_10m_data_for_entry")
        return "HOLD", gate_log

    # 中周期方向
    mid_dir = _exec_bias_dir_tag(exec_bias)

    # 10m方向
    micro_dir = "NEUTRAL"
    mr = (micro_reversal or "NONE").upper()
    if mr == "MICRO_BOTTOM":
        micro_dir = "BULL"
    elif mr == "MICRO_TOP":
        micro_dir = "BEAR"
    else:
        eb10 = (micro_exec_bias or "").upper()
        if eb10 in ("STRONG_BUY", "BUY"):
            micro_dir = "BULL"
        elif eb10 in ("STRONG_SELL", "SELL"):
            micro_dir = "BEAR"

    combo_tag = f"L1_{original_action}|MID_{mid_dir}|MICRO_{micro_dir}"
    gate_log["combo_tag"] = combo_tag

    # ---- 原始刹车逻辑 ----
    if original_action == "BUY":
        if micro_dir == "BEAR":
            gate_log["pass"] = False
            gate_log["new_action"] = "HOLD"
            gate_log["reasons"].append("micro_bear_vs_buy")
            return "HOLD", gate_log
        if micro_dir == "NEUTRAL":
            gate_log["pass"] = False
            gate_log["new_action"] = "HOLD"
            gate_log["reasons"].append("micro_neutral_for_buy")
            return "HOLD", gate_log
        if mid_dir == "BEAR":
            gate_log["pass"] = False
            gate_log["new_action"] = "HOLD"
            gate_log["reasons"].append("mid_bear_vs_buy")
            return "HOLD", gate_log
        gate_log["reasons"].append("micro_confirm_buy")
        return original_action, gate_log

    if original_action == "SELL":
        if micro_dir == "BULL":
            gate_log["pass"] = False
            gate_log["new_action"] = "HOLD"
            gate_log["reasons"].append("micro_bull_vs_sell")
            return "HOLD", gate_log
        if micro_dir == "NEUTRAL":
            gate_log["pass"] = False
            gate_log["new_action"] = "HOLD"
            gate_log["reasons"].append("micro_neutral_for_sell")
            return "HOLD", gate_log
        if mid_dir == "BULL":
            gate_log["pass"] = False
            gate_log["new_action"] = "HOLD"
            gate_log["reasons"].append("mid_bull_vs_sell")
            return "HOLD", gate_log
        gate_log["reasons"].append("micro_confirm_sell")
        return original_action, gate_log

    return original_action, gate_log


def apply_breakout_extension(
    symbol: str,
    final_action: str,
    state: dict,
    last_close: float,
    low_120: float,
    high_120: float,
    pos_zone: str,
    trend_state: str,
    exec_bias: str,
    bearish_env: bool,
):
    """
    v1.99: 突破/跌破后的额外 3 次顺势交易扩展（3+3）。

    设计原则：
      - 只在原始 final_action == "HOLD" 时尝试把 HOLD 升级为 BUY/SELL，
        用于避免长期低仓位错过单边趋势。
      - 仍然服从：
          * MAX_UNITS_PER_SYMBOL 持仓上限；
          * GLOBAL_MAX_BUYS_PER_CYCLE / GLOBAL_MAX_SELLS_PER_CYCLE 总次数上限；
          * 10m MICRO_TIMING_GATE（二次检查，apply_micro_timing_gate）。
      - 多头扩展：在强势上涨 + 突破前一根 high_120 之后，给最多 3 次额外 BUY；
      - 空头扩展：在强势下跌 + 跌破前一根 low_120 之后，给最多 3 次额外 SELL。
    """
    new_action = final_action or "HOLD"
    breakout_log = {
        "applied": True,
        "used": False,
        "reason_tag": None,
        "direction": None,
        "original_action": final_action,
        "new_action": new_action,
        "prev_sr": None,
    }

    # 只有在当前没有计划交易时，才尝试扩展
    if new_action != "HOLD":
        breakout_log["applied"] = False
        breakout_log["reason_tag"] = "non_hold_no_extension"
        return new_action, breakout_log

    pos_units = int(state.get("position_units", 0) or 0)
    open_buys = state.get("open_buys", []) or []
    open_sells = state.get("open_sells", []) or []
    prev_sr = state.get("prev_sr") or None
    breakout_long_used = int(state.get("breakout_long_used", 0) or 0)
    breakout_short_used = int(state.get("breakout_short_used", 0) or 0)
    actual_buy_count = int(state.get("actual_buy_count", 0) or 0)
    actual_sell_count = int(state.get("actual_sell_count", 0) or 0)

    breakout_log["prev_sr"] = prev_sr

    # 没有前一根的 SR 参考，无法判断突破/跌破
    if not prev_sr or not isinstance(prev_sr, dict):
        breakout_log["reason_tag"] = "no_prev_sr"
        return new_action, breakout_log

    prev_support = float(prev_sr.get("support", 0.0) or 0.0)
    prev_resistance = float(prev_sr.get("resistance", 0.0) or 0.0)

    if prev_support <= 0.0 or prev_resistance <= 0.0:
        breakout_log["reason_tag"] = "invalid_prev_sr"
        return new_action, breakout_log

    # 轻微容差，避免浮点抖动
    breakout_eps = 0.002  # 约 0.2%

    # ===== 多头突破扩展 =====
    core_units_threshold = 3
    max_extra_per_side = 3

    # 多头趋势环境判定
    is_trend_up = (trend_state in ("UP", "STRONG_UP")) and (not bearish_env)
    exec_bull = _exec_bias_dir_tag(exec_bias) == "BULL"

    if (
        is_trend_up
        and exec_bull
        and pos_units > 0
        and len(open_sells) == 0
        and pos_units >= core_units_threshold
        and breakout_long_used < max_extra_per_side
        and last_close >= prev_resistance * (1.0 + breakout_eps)
        and actual_buy_count < GLOBAL_MAX_BUYS_PER_CYCLE
        and pos_units < MAX_UNITS_PER_SYMBOL
    ):
        # 先做一次 10m 微观 gate（把这次扩展当作新的 BUY 提案）
        proposed_action = "BUY"
        gated_action, gate_log = apply_micro_timing_gate(
            symbol=symbol,
            l1_action=proposed_action,
            exec_bias=exec_bias,
            state=state,
        )
        breakout_log["micro_gate_for_extension"] = gate_log

        if gated_action == "BUY":
            state["breakout_long_used"] = breakout_long_used + 1
            new_action = "BUY"
            breakout_log["used"] = True
            breakout_log["reason_tag"] = "long_breakout_extension"
            breakout_log["direction"] = "LONG"
            breakout_log["new_action"] = new_action
            return new_action, breakout_log
        else:
            breakout_log["reason_tag"] = "micro_gate_block_long_extension"
            return new_action, breakout_log

    # ===== 空头跌破扩展 =====
    is_trend_down = (trend_state in ("DOWN", "STRONG_DOWN")) or bearish_env
    exec_bear = _exec_bias_dir_tag(exec_bias) == "BEAR"

    if (
        is_trend_down
        and exec_bear
        and pos_units < 0
        and len(open_buys) == 0
        and abs(pos_units) >= core_units_threshold
        and breakout_short_used < max_extra_per_side
        and last_close <= prev_support * (1.0 - breakout_eps)
        and actual_sell_count < GLOBAL_MAX_SELLS_PER_CYCLE
        and abs(pos_units) < MAX_UNITS_PER_SYMBOL
    ):
        proposed_action = "SELL"
        gated_action, gate_log = apply_micro_timing_gate(
            symbol=symbol,
            l1_action=proposed_action,
            exec_bias=exec_bias,
            state=state,
        )
        breakout_log["micro_gate_for_extension"] = gate_log

        if gated_action == "SELL":
            state["breakout_short_used"] = breakout_short_used + 1
            new_action = "SELL"
            breakout_log["used"] = True
            breakout_log["reason_tag"] = "short_breakdown_extension"
            breakout_log["direction"] = "SHORT"
            breakout_log["new_action"] = new_action
            return new_action, breakout_log
        else:
            breakout_log["reason_tag"] = "micro_gate_block_short_extension"
            return new_action, breakout_log

    breakout_log["reason_tag"] = "no_extension_condition"
    return new_action, breakout_log
# === END_BREAKOUT_EXTENSION_v1_99 ===


# === EXECUTION_RHYTHM_GATE_v1_999 ===
# [DEPRECATED v2.910] 此函数已失效，条件极端苛刻几乎不触发
def apply_execution_rhythm_gate(
    symbol: str,
    final_action: str,
    state: dict,
    time_ms: int,
    last_close: float,
    position_priority: dict = None,  # v2.380: 新增参数
) -> tuple:
    """
    执行节奏门控（TWO_BUY/TWO_SELL）
    
    规则：
    - TWO_BUY阶段：突破prev_sr后最多3次BUY (v2.370)
    - TWO_SELL阶段：回撤后最多3次SELL (v2.370)
    - 超限后强制HOLD
    
    v2.380: 添加 Position Priority 检查
    - 极端位置 bypass_all_gates 可以绕过配额限制
    
    Returns:
        (new_action, rhythm_log)
    """
    from time import time as _time
    
    # v2.380: 优先检查 Position Priority
    if position_priority and position_priority.get("bypass_all_gates"):
        rhythm_log = {
            "applied": True,
            "original_action": final_action,
            "new_action": final_action,
            "rhythm_effect": "BYPASSED_BY_POSITION_PRIORITY",
            "bypass_reason": position_priority.get("reason"),
        }
        print(f"[RHYTHM_GATE] {symbol}: BYPASSED by POSITION_PRIORITY ({position_priority.get('reason')})")
        return final_action, rhythm_log
    
    rhythm_log = {
        "applied": True,
        "original_action": final_action,
        "new_action": final_action,
        "execution_rhythm": state.get("execution_rhythm", "NONE"),
        "rhythm_status": state.get("rhythm_status", "READY"),
        "two_buy_used_before": state.get("two_buy_used", 0),
        "two_sell_used_before": state.get("two_sell_used", 0),
        "two_buy_used_after": state.get("two_buy_used", 0),
        "two_sell_used_after": state.get("two_sell_used", 0),
        "rhythm_effect": "NONE",
        "block_reason": "",
        "idempotency_key": None,
        "idempotency_hit": False,
        "breakout_confirmed": state.get("breakout_confirmed", False),
        "zone_return_confirmed": state.get("zone_return_confirmed", False),
    }
    
    if final_action not in ("BUY", "SELL"):
        rhythm_log["applied"] = False
        return final_action, rhythm_log
    
    # 构建幂等键
    execution_rhythm = state.get("execution_rhythm", "NONE")
    idem_key = f"{symbol}:{time_ms}:{execution_rhythm}:{final_action}"
    rhythm_log["idempotency_key"] = idem_key
    
    # 幂等检查
    idem_dict = state.get("rhythm_idem", {})
    if idem_key in idem_dict:
        rhythm_log["idempotency_hit"] = True
        rhythm_log["new_action"] = "HOLD"
        rhythm_log["rhythm_effect"] = "BLOCK_IDEMPOTENT"
        rhythm_log["block_reason"] = f"幂等键已处理：{idem_key}"
        print(f"[RHYTHM_GATE] {symbol} 幂等阻断：{idem_key}")
        return "HOLD", rhythm_log
    
    # 读取当前计数
    two_buy_used = int(state.get("two_buy_used", 0) or 0)
    two_sell_used = int(state.get("two_sell_used", 0) or 0)
    
    # 判断是否为开仓动作
    is_entry = False
    if final_action == "BUY":
        is_entry = len(state.get("open_sells", [])) == 0
    elif final_action == "SELL":
        is_entry = len(state.get("open_buys", [])) == 0
    
    # 仅对开仓动作应用节奏限制
    if not is_entry:
        rhythm_log["rhythm_effect"] = "ALLOW_EXIT"
        return final_action, rhythm_log
    
    # TWO_BUY 阶段检查
    if execution_rhythm == "TWO_BUY" and final_action == "BUY":
        if two_buy_used >= 3:
            # v2.360: 强信号豁免检查 (Bug Fix #1)
            exec_bias = state.get("exec_bias", "")
            fallback_reasons = state.get("fallback_reasons", [])
            
            is_strong_signal = (
                exec_bias in ["STRONG_BUY"] or
                any("TRUST_L2_BUY" in r for r in fallback_reasons) or
                any("L2_INITIATE_BUY" in r for r in fallback_reasons)
            )
            
            if is_strong_signal:
                # 强信号豁免
                rhythm_log["rhythm_effect"] = "ALLOW_BUY"
                rhythm_log["block_reason"] = f"三买已用完（{two_buy_used}/3），但检测到强信号，豁免执行"
                print(f"[RHYTHM_GATE] {symbol} 三买3/3，但强信号豁免: exec_bias={exec_bias}")
                print(f"  fallback_reasons: {fallback_reasons}")
                return final_action, rhythm_log  # 允许执行
            
            # 普通信号拦截
            rhythm_log["new_action"] = "HOLD"
            rhythm_log["rhythm_effect"] = "BLOCK_BUY"
            rhythm_log["block_reason"] = f"三买结构已完成（{two_buy_used}/3），本轮结构内不再允许新增BUY"
            print(f"[RHYTHM_GATE] {symbol} 三买超限阻断：{two_buy_used}/3")
            return "HOLD", rhythm_log
    
    # TWO_SELL 阶段检查
    if execution_rhythm == "TWO_SELL" and final_action == "SELL":
        if two_sell_used >= 3:
            # v2.360: 强信号豁免检查 (Bug Fix #1)
            exec_bias = state.get("exec_bias", "")
            fallback_reasons = state.get("fallback_reasons", [])
            
            is_strong_signal = (
                exec_bias in ["STRONG_SELL"] or
                any("TRUST_L2_SELL" in r for r in fallback_reasons) or
                any("L2_INITIATE_SELL" in r for r in fallback_reasons)
            )
            
            if is_strong_signal:
                # 强信号豁免
                rhythm_log["rhythm_effect"] = "ALLOW_SELL"
                rhythm_log["block_reason"] = f"三卖已用完（{two_sell_used}/3），但检测到强信号，豁免执行"
                print(f"[RHYTHM_GATE] {symbol} 三卖3/3，但强信号豁免: exec_bias={exec_bias}")
                print(f"  fallback_reasons: {fallback_reasons}")
                return final_action, rhythm_log  # 允许执行
            
            # 普通信号拦截
            rhythm_log["new_action"] = "HOLD"
            rhythm_log["rhythm_effect"] = "BLOCK_SELL"
            rhythm_log["block_reason"] = f"三卖结构已完成（{two_sell_used}/3），本轮结构内不再允许新增SELL"
            print(f"[RHYTHM_GATE] {symbol} 三卖超限阻断：{two_sell_used}/3")
            return "HOLD", rhythm_log
    
    # 状态枚举检查
    rhythm_status = state.get("rhythm_status", "READY")
    if rhythm_status == "EXHAUSTED":
        rhythm_log["new_action"] = "HOLD"
        rhythm_log["rhythm_effect"] = "BLOCK_EXHAUSTED"
        rhythm_log["block_reason"] = "节奏状态为EXHAUSTED，不允许新增开仓"
        return "HOLD", rhythm_log
    
    # 通过检查
    rhythm_log["rhythm_effect"] = "ALLOW"
    return final_action, rhythm_log
# === END_EXECUTION_RHYTHM_GATE_v1_999 ===



