# v2.400: L1-L2 映射详细函数
# 函数代码见: v2400_new_functions.py
# 手动复制 format_l1_l2_mapping_detail_v2420() 函数到此处

def format_step5a_l2_10m_report(symbol, correction_log):
    """v2.575: Enhanced 10m report with detailed analysis"""
    result = []
    
    # 检查数据可用性
    if not correction_log:
        result.append("10m小周期数据: ✗ 不可用（未初始化）")
        result.append("影响: 本次决策未使用10m小周期修正")
        return "\n".join(result)
    
    if not correction_log.get("applied"):
        result.append("10m小周期数据: ✗ 不可用（数据不足）")
        result.append(f"原因: {correction_log.get('reason', '未知')}")
        result.append("影响: 本次决策未使用10m小周期修正")
        return "\n".join(result)
    
    # ========================================================================
    # [1] 窗口分析详情
    # ========================================================================
    wa = correction_log.get("window_analysis", {})
    sig = correction_log.get("10m_signals", {})
    
    result.append("━━━ [4.2.1] 10m Window Analysis / 窗口分析详情 ━━━")
    result.append("")
    result.append(f"窗口大小:   {wa.get('window_size',0)}根10m K线")
    result.append(f"时间跨度:   {wa.get('window_size',0) * 10}分钟")
    result.append("")
    
    # 趋势分析
    result.append("趋势分析:")
    result.append(f"  趋势方向:   {wa.get('trend','N/A')}")
    result.append(f"  趋势强度:   {wa.get('trend_strength','N/A')}")
    result.append(f"  趋势置信度: {wa.get('trend_confidence','N/A')}")
    result.append("")
    
    # PA形态分析
    result.append("Price Action:")
    result.append(f"  PA形态:     {wa.get('pa','N/A')}")
    result.append(f"  PA强度:     {wa.get('pa_strength','N/A')}")
    result.append(f"  PA置信度:   {wa.get('pa_confidence','N/A')}")
    result.append("")
    
    # 成交量分析
    result.append("成交量分析:")
    result.append(f"  量能状态:   {wa.get('volume','N/A')}")
    result.append(f"  量比:       {wa.get('volume_ratio','N/A')}")
    result.append(f"  量能确认:   {wa.get('volume_confirmation','N/A')}")
    result.append("")
    
    # 综合置信度
    result.append(f"综合置信度:  {wa.get('confidence','N/A')}")
    result.append("")
    
    # ========================================================================
    # [2] 信号检测
    # ========================================================================
    result.append("━━━ [4.2.2] 10m Signals / 信号检测 ━━━")
    result.append("")
    
    # 假突破/假跌破检测
    fake = sig.get("fake_break", "NONE")
    if fake == "CAN_SELL":
        result.append(f"⚠️  假突破检测: 检测到假突破")
        result.append(f"   置信度: {sig.get('fake_conf','LOW')}")
        result.append(f"   建议: 可考虑卖出")
    elif fake == "CAN_BUY":
        result.append(f"⚠️  假跌破检测: 检测到假跌破")
        result.append(f"   置信度: {sig.get('fake_conf','LOW')}")
        result.append(f"   建议: 可考虑买入")
    else:
        result.append("✓ 无异常信号")
    result.append("")
    
    # 其他信号
    if sig.get("signals"):
        result.append("其他信号:")
        for s in sig.get("signals", []):
            result.append(f"  - {s}")
        result.append("")
    
    # ========================================================================
    # [3] 修正决策
    # ========================================================================
    result.append("━━━ [4.2.3] 10m Correction / 修正决策 ━━━")
    result.append("")
    result.append(f"L2原始判断:  {correction_log.get('base_exec_bias','N/A')}")
    result.append(f"10m修正后:   {correction_log.get('final_exec_bias','N/A')}")
    result.append("")
    
    if correction_log.get("modified"):
        result.append("✓ 已修正")
        result.append("")
        result.append("修正内容:")
        for i, m in enumerate(correction_log.get("modifications", []), 1):
            result.append(f"  {i}. {m.get('action','')}")
            if m.get('reason'):
                result.append(f"     原因: {m.get('reason','')}")
        result.append("")
    else:
        result.append("○ 未修正（10m分析结果与L2一致）")
        result.append("")
    
    # ========================================================================
    # [4] 数据质量
    # ========================================================================
    result.append("━━━ [4.2.4] Data Quality / 数据质量 ━━━")
    result.append("")
    result.append(f"数据完整性:  {wa.get('data_completeness','N/A')}")
    result.append(f"数据可靠性:  {wa.get('data_reliability','N/A')}")
    result.append(f"分析耗时:    {correction_log.get('analysis_time_ms','N/A')}ms")
    result.append("")
    
    return "\n".join(result)


# ============================================================================
# v2.470: RSI Calculation Function
# ============================================================================

def calc_rsi(closes, period=14):
    """
    计算 Wilder RSI(14)
    
    Args:
        closes: 收盘价序列 (list/array)
        period: RSI 周期，默认 14
        
    Returns:
        float or None: RSI 值 (0-100)，数据不足返回 None
    """
    if closes is None or len(closes) < period + 1:
        return None
    
    try:
        import numpy as np
        closes = np.array(closes, dtype=float)
        
        # 计算价格变化
        deltas = np.diff(closes)
        
        # 分离涨跌
        gains = np.where(deltas > 0, deltas, 0)
        losses = np.where(deltas < 0, -deltas, 0)
        
        # Wilder 平滑法
        avg_gain = np.mean(gains[:period])
        avg_loss = np.mean(losses[:period])
        
        # 递推计算
        for i in range(period, len(gains)):
            avg_gain = (avg_gain * (period - 1) + gains[i]) / period
            avg_loss = (avg_loss * (period - 1) + losses[i]) / period
        
        # 计算 RS 和 RSI
        if avg_loss == 0:
            return 100.0
        
        rs = avg_gain / avg_loss
        rsi = 100.0 - (100.0 / (1.0 + rs))
        
        return round(rsi, 2)
        
    except Exception as e:
        print(f"[RSI] Calculation failed: {e}")
        return None

# ============================================================================
# End of v2.470 RSI Function
# ============================================================================


