# ============================================================================
# v2.575: Swing SR Trading Function (顶底保险机制)
# ============================================================================

def check_swing_sr_trading(
    ohlcv_bars: list,
    last_close: float,
    position_units: int,
    state: dict
) -> dict:
    """
    v2.575: Swing高低点支撑阻力买卖检查（顶底保险）
    
    核心逻辑:
    1. 双重筛选找锚点：
       - 最接近前K线的支撑阻力区
       - 距离当前K线最近
    2. 范围限制：2.5% - 3.5%
       - 小于2.5%: 不执行
       - 2.5%-3.5%: 执行两次
       - 大于3.5%: 不执行
    3. 最高优先级：无条件执行
    
    Args:
        ohlcv_bars: OHLCV K线数据
        last_close: 当前收盘价
        position_units: 当前持仓单位
        state: 状态字典
        
    Returns:
        {
            "action": "BUY"/"SELL"/"HOLD",
            "reason": str,
            "swing_resistance": float,      # swing阻力位
            "swing_support": float,         # swing支撑位
            "resistance_index": int,        # 阻力位K线索引
            "support_index": int,           # 支撑位K线索引
            "prev_resistance_ref": float,   # 前K线阻力参考
            "prev_support_ref": float,      # 前K线支撑参考
            "drop_from_resistance_pct": float,  # 从阻力跌幅%
            "rise_from_support_pct": float,     # 从支撑涨幅%
            "in_range": bool,               # 是否在2.5%-3.5%范围
            "sr_sell_count": int,           # 卖出次数
            "sr_buy_count": int,            # 买入次数
            "triggered": bool,
            "selection_process": list,      # 筛选过程详情
        }
    """
    result = {
        "action": "HOLD",
        "reason": "",
        "swing_resistance": 0.0,
        "swing_support": 0.0,
        "resistance_index": -1,
        "support_index": -1,
        "prev_resistance_ref": 0.0,
        "prev_support_ref": 0.0,
        "drop_from_resistance_pct": 0.0,
        "rise_from_support_pct": 0.0,
        "in_range": False,
        "sr_sell_count": state.get("swing_sr_sell_count", 0),
        "sr_buy_count": state.get("swing_sr_buy_count", 0),
        "triggered": False,
        "selection_process": [],
    }
    
    # 检查数据
    if not ohlcv_bars or len(ohlcv_bars) < 10:
        result["reason"] = "数据不足（需要至少10根K线）"
        return result
    
    # ========================================================================
    # 第一步：前K线参考区
    # ========================================================================
    prev_bar = ohlcv_bars[-2]  # 前一根K线
    resistance_ref = prev_bar["high"]  # 阻力参考
    support_ref = prev_bar["low"]      # 支撑参考
    
    result["prev_resistance_ref"] = resistance_ref
    result["prev_support_ref"] = support_ref
    
    result["selection_process"].append(f"前K线参考区: 阻力={resistance_ref:.2f}, 支撑={support_ref:.2f}")
    
    # ========================================================================
    # 第二步：识别所有swing points
    # v2.747: lookback从5改为3，更容易识别震荡市场的swing点
    # ========================================================================
    swing_points = identify_swing_points(ohlcv_bars, lookback=3)
    
    swing_highs = swing_points.get("swing_highs", [])
    swing_lows = swing_points.get("swing_lows", [])
    
    if not swing_highs or not swing_lows:
        result["reason"] = "未找到有效的swing高低点"
        return result
    
    result["selection_process"].append(f"找到{len(swing_highs)}个swing highs, {len(swing_lows)}个swing lows")
    
    # ========================================================================
    # 第三步：双重筛选 - 找最佳阻力位
    # ========================================================================
    best_resistance = None
    best_resistance_index = -1
    min_dist_resistance = float('inf')
    
    for swing_high in swing_highs:
        index, price = swing_high
        
        # 距离参考区的差值
        dist_to_ref = abs(price - resistance_ref)
        
        # 优先选择最接近参考区的
        if dist_to_ref < min_dist_resistance:
            min_dist_resistance = dist_to_ref
            best_resistance = price
            best_resistance_index = index
    
    result["swing_resistance"] = best_resistance if best_resistance else 0.0
    result["resistance_index"] = best_resistance_index
    
    if best_resistance:
        bars_to_current = len(ohlcv_bars) - 1 - best_resistance_index
        result["selection_process"].append(
            f"最佳阻力: {best_resistance:.2f} (bars[-{bars_to_current}], "
            f"距参考区{min_dist_resistance:.2f})"
        )
    
    # ========================================================================
    # 第四步：双重筛选 - 找最佳支撑位
    # ========================================================================
    best_support = None
    best_support_index = -1
    min_dist_support = float('inf')
    
    for swing_low in swing_lows:
        index, price = swing_low
        
        # 距离参考区的差值
        dist_to_ref = abs(price - support_ref)
        
        # 优先选择最接近参考区的
        if dist_to_ref < min_dist_support:
            min_dist_support = dist_to_ref
            best_support = price
            best_support_index = index
    
    result["swing_support"] = best_support if best_support else 0.0
    result["support_index"] = best_support_index
    
    if best_support:
        bars_to_current = len(ohlcv_bars) - 1 - best_support_index
        result["selection_process"].append(
            f"最佳支撑: {best_support:.2f} (bars[-{bars_to_current}], "
            f"距参考区{min_dist_support:.2f})"
        )
    
    # ========================================================================
    # 第五步：计算跌幅/涨幅
    # ========================================================================
    if best_resistance and best_resistance > 0:
        result["drop_from_resistance_pct"] = (best_resistance - last_close) / best_resistance
    
    if best_support and best_support > 0:
        result["rise_from_support_pct"] = (last_close - best_support) / best_support
    
    # ========================================================================
    # 第六步：检查卖出（逃顶）
    # ========================================================================
    if best_resistance and best_resistance > 0:
        drop_pct = result["drop_from_resistance_pct"]
        
        # 范围检查：必须在2.5%-3.5%之间
        if 0.025 <= drop_pct <= 0.035:
            result["in_range"] = True
            result["selection_process"].append(f"✓ 在范围内: 跌幅{drop_pct*100:.2f}%")
            
            sr_sell_count = state.get("swing_sr_sell_count", 0)
            
            # 第一次：跌2.5%
            if sr_sell_count == 0 and drop_pct >= 0.025:
                result["action"] = "SELL"
                result["reason"] = f"逃顶: 从swing高点{best_resistance:.2f}跌{drop_pct*100:.2f}% (第1次)"
                result["sr_sell_count"] = 1
                result["triggered"] = True
                print(f"[SWING_SR] 🔴 逃顶信号: 从{best_resistance:.2f}跌{drop_pct*100:.2f}% (第1/2次)")
                return result
            
            # 第二次：跌3.5%
            elif sr_sell_count == 1 and drop_pct >= 0.035:
                result["action"] = "SELL"
                result["reason"] = f"逃顶: 从swing高点{best_resistance:.2f}跌{drop_pct*100:.2f}% (第2次)"
                result["sr_sell_count"] = 2
                result["triggered"] = True
                print(f"[SWING_SR] 🔴 逃顶信号: 从{best_resistance:.2f}跌{drop_pct*100:.2f}% (第2/2次)")
                return result
            
            else:
                result["reason"] = f"在范围内但已用完次数 (count={sr_sell_count})"
        
        elif drop_pct < 0.025:
            result["reason"] = f"跌幅{drop_pct*100:.2f}%未达2.5%阈值"
        
        elif drop_pct > 0.035:
            result["reason"] = f"跌幅{drop_pct*100:.2f}%超出3.5%范围，不执行"
            result["selection_process"].append(f"✗ 超出范围: 跌幅{drop_pct*100:.2f}% > 3.5%")
    
    # 重置卖出计数器（价格恢复）
    if best_resistance and last_close >= best_resistance * 0.99:
        if state.get("swing_sr_sell_count", 0) > 0:
            state["swing_sr_sell_count"] = 0
            result["sr_sell_count"] = 0
            print(f"[SWING_SR] ○ 重置卖出计数器: 价格恢复到{best_resistance:.2f}附近")
    
    # ========================================================================
    # 第七步：检查买入（抄底）
    # ========================================================================
    if best_support and best_support > 0:
        rise_pct = result["rise_from_support_pct"]
        
        # 范围检查：必须在2.5%-3.5%之间
        if 0.025 <= rise_pct <= 0.035:
            result["in_range"] = True
            result["selection_process"].append(f"✓ 在范围内: 涨幅{rise_pct*100:.2f}%")
            
            sr_buy_count = state.get("swing_sr_buy_count", 0)
            
            # 第一次：涨2.5%
            if sr_buy_count == 0 and rise_pct >= 0.025:
                result["action"] = "BUY"
                result["reason"] = f"抄底: 从swing低点{best_support:.2f}涨{rise_pct*100:.2f}% (第1次)"
                result["sr_buy_count"] = 1
                result["triggered"] = True
                print(f"[SWING_SR] 🟢 抄底信号: 从{best_support:.2f}涨{rise_pct*100:.2f}% (第1/2次)")
                return result
            
            # 第二次：涨3.5%
            elif sr_buy_count == 1 and rise_pct >= 0.035:
                result["action"] = "BUY"
                result["reason"] = f"抄底: 从swing低点{best_support:.2f}涨{rise_pct*100:.2f}% (第2次)"
                result["sr_buy_count"] = 2
                result["triggered"] = True
                print(f"[SWING_SR] 🟢 抄底信号: 从{best_support:.2f}涨{rise_pct*100:.2f}% (第2/2次)")
                return result
            
            else:
                result["reason"] = f"在范围内但已用完次数 (count={sr_buy_count})"
        
        elif rise_pct < 0.025:
            result["reason"] = f"涨幅{rise_pct*100:.2f}%未达2.5%阈值"
        
        elif rise_pct > 0.035:
            result["reason"] = f"涨幅{rise_pct*100:.2f}%超出3.5%范围，不执行"
            result["selection_process"].append(f"✗ 超出范围: 涨幅{rise_pct*100:.2f}% > 3.5%")
    
    # 重置买入计数器（价格回落）
    if best_support and last_close <= best_support * 1.01:
        if state.get("swing_sr_buy_count", 0) > 0:
            state["swing_sr_buy_count"] = 0
            result["sr_buy_count"] = 0
            print(f"[SWING_SR] ○ 重置买入计数器: 价格回到{best_support:.2f}附近")
    
    # 如果没有触发，返回原因
    if not result["triggered"] and not result["reason"]:
        result["reason"] = "未达到Swing SR触发条件"
    
    return result

# ============================================================================
# End of v2.575 Swing SR Trading Function
# ============================================================================


