# v2.700 FULL_ASSET_PATCH: 极端风控熔断器
# ============================================================================

# v2.730: 熔断器配置使用 RiskConfig
CIRCUIT_BREAKER_CONFIG = {
    "single_loss_threshold": RiskConfig.CIRCUIT_BREAKER_LOSS_PCT,
    "total_drawdown_threshold": RiskConfig.CIRCUIT_BREAKER_DRAWDOWN,
    "force_action": RiskConfig.CIRCUIT_BREAKER_FORCE_ACTION,
    "enabled": RiskConfig.CIRCUIT_BREAKER_ENABLED,
}

def check_circuit_breaker(symbol: str, pnl_pct: float, position_units: int = 0) -> dict:
    """
    v2.700 FULL_ASSET_PATCH: 极端风控熔断器
    
    触发条件：
    1. 单币种浮亏 > 15%
    
    触发后果：
    - 强制 REDUCE_ONLY 模式（只允许减仓）
    - 无视所有 L1/L2 决策
    
    Args:
        symbol: 交易对
        pnl_pct: 浮亏百分比（如 -18.5 表示亏损18.5%）
        position_units: 当前持仓单位
    
    Returns:
        {
            "triggered": bool,
            "trigger_reason": str,
            "force_action": str,  # "REDUCE_ONLY" or None
            "allow_buy": bool,
            "allow_sell": bool,
        }
    """
    cfg = CIRCUIT_BREAKER_CONFIG
    
    result = {
        "triggered": False,
        "trigger_reason": None,
        "force_action": None,
        "allow_buy": True,
        "allow_sell": True,
    }
    
    if not cfg.get("enabled", True):
        return result
    
    # 检查单币种浮亏
    if pnl_pct is not None and pnl_pct < cfg["single_loss_threshold"]:
        result["triggered"] = True
        result["trigger_reason"] = f"SINGLE_LOSS:{pnl_pct:.1f}%"
        result["force_action"] = cfg["force_action"]
        result["allow_buy"] = False  # 禁止买入
        result["allow_sell"] = True  # 允许卖出（减仓）
        
        log_to_server(f"[CIRCUIT_BREAKER] {symbol} 熔断触发! 浮亏: {pnl_pct:.1f}% < 阈值 {cfg['single_loss_threshold']:.0f}% 模式: {cfg['force_action']} (禁止新开仓)")

        if position_units > 0:
            log_to_server(f"[CIRCUIT_BREAKER] {symbol} 建议: 当前持仓 {position_units} 单位，考虑减仓")
    
    return result


# v3.654: 组合级连续亏损熔断 (SYS-017)
# ============================================================================
_portfolio_breaker_state = {
    "consecutive_losses": 0,
    "daily_pnl_pct": 0.0,
    "daily_trades": 0,
    "last_trade_date": "",
    "tier1_until": 0.0,   # timestamp: 限tier<=2
    "tier2_until": 0.0,   # timestamp: 停BUY
    "daily_halt": False,
}


def portfolio_breaker_record_trade(action: str, pnl_pct: float = 0.0) -> None:
    """v3.654: 记录交易结果，更新组合熔断状态"""
    state = _portfolio_breaker_state
    today = datetime.now(ZoneInfo("America/New_York")).strftime("%Y-%m-%d")
    if state["last_trade_date"] != today:
        state["consecutive_losses"] = 0
        state["daily_pnl_pct"] = 0.0
        state["daily_trades"] = 0
        state["daily_halt"] = False
        state["last_trade_date"] = today

    state["daily_trades"] += 1
    state["daily_pnl_pct"] += pnl_pct

    if action == "SELL" and pnl_pct < 0:
        state["consecutive_losses"] += 1
    elif action == "SELL" and pnl_pct >= 0:
        state["consecutive_losses"] = 0  # 盈利SELL重置连亏

    now_ts = time.time()
    cfg = RiskConfig

    # Tier 1: 3连亏 → 限tier
    if state["consecutive_losses"] >= cfg.PORTFOLIO_BREAKER_TIER1_LOSSES:
        state["tier1_until"] = now_ts + cfg.PORTFOLIO_BREAKER_TIER1_HOURS * 3600
        tag = "[生效]" if cfg.PORTFOLIO_BREAKER_ENABLED else "[观察]"
        log_to_server(f"[PORTFOLIO_BREAKER] {tag} Tier1触发: {state['consecutive_losses']}连亏 → 限tier<=2 {cfg.PORTFOLIO_BREAKER_TIER1_HOURS}h")

    # Tier 2: 5连亏 → 停BUY
    if state["consecutive_losses"] >= cfg.PORTFOLIO_BREAKER_TIER2_LOSSES:
        state["tier2_until"] = now_ts + cfg.PORTFOLIO_BREAKER_TIER2_HOURS * 3600
        tag = "[生效]" if cfg.PORTFOLIO_BREAKER_ENABLED else "[观察]"
        log_to_server(f"[PORTFOLIO_BREAKER] {tag} Tier2触发: {state['consecutive_losses']}连亏 → 停BUY {cfg.PORTFOLIO_BREAKER_TIER2_HOURS}h")

    # Tier 3: 日亏>3%
    if state["daily_pnl_pct"] <= cfg.PORTFOLIO_BREAKER_DAILY_LOSS_PCT:
        state["daily_halt"] = True
        tag = "[生效]" if cfg.PORTFOLIO_BREAKER_ENABLED else "[观察]"
        log_to_server(f"[PORTFOLIO_BREAKER] {tag} Tier3触发: 日亏{state['daily_pnl_pct']:.1f}% → 全停到次日")


def portfolio_breaker_check(action: str) -> tuple:
    """
    v3.654: 检查组合熔断状态
    Returns: (allowed: bool, reason: str)
    """
    if not RiskConfig.PORTFOLIO_BREAKER_ENABLED:
        return (True, "")

    state = _portfolio_breaker_state
    now_ts = time.time()

    # Tier 3: 日亏全停
    if state["daily_halt"]:
        return (False, f"组合熔断Tier3: 日亏{state['daily_pnl_pct']:.1f}%全停")

    # Tier 2: 停BUY
    if action == "BUY" and now_ts < state["tier2_until"]:
        remaining = (state["tier2_until"] - now_ts) / 3600
        return (False, f"组合熔断Tier2: {state['consecutive_losses']}连亏停BUY(剩{remaining:.1f}h)")

    return (True, "")


def portfolio_breaker_get_max_tier() -> int:
    """v3.654: 获取当前允许的最大tier (Tier1限制)"""
    if not RiskConfig.PORTFOLIO_BREAKER_ENABLED:
        return 99
    state = _portfolio_breaker_state
    if time.time() < state["tier1_until"]:
        return 2  # Tier1: 限tier<=2
    return 99


def portfolio_breaker_get_state() -> dict:
    """v3.654: 获取状态(供monitor读取)"""
    state = _portfolio_breaker_state
    now_ts = time.time()
    return {
        "consecutive_losses": state["consecutive_losses"],
        "daily_pnl_pct": round(state["daily_pnl_pct"], 2),
        "daily_trades": state["daily_trades"],
        "tier1_active": now_ts < state["tier1_until"],
        "tier2_active": now_ts < state["tier2_until"],
        "daily_halt": state["daily_halt"],
        "enabled": RiskConfig.PORTFOLIO_BREAKER_ENABLED,
    }


# ============================================================================
# v3.654 SYS-012: 系统可用度指标 (Phase 1 仅记录)
# ============================================================================

_system_availability_counters = {
    "api_calls": 0,          # API调用总数
    "api_failures": 0,       # API失败次数
    "signal_conflicts": 0,   # L1/L2信号冲突次数
    "signal_total": 0,       # 信号总数
    "exec_success": 0,       # 执行成功次数
    "exec_total": 0,         # 执行总次数
    "data_stale": 0,         # 数据陈旧次数
    "data_checks": 0,        # 数据检查总次数
    "last_reset": time.time(),
}

SYSTEM_AVAILABILITY_ENABLED = False  # Phase 1: 仅记录


def system_availability_record(category: str, success: bool = True) -> None:
    """v3.654 SYS-012: 记录系统事件用于可用度计算"""
    c = _system_availability_counters
    if category == "api":
        c["api_calls"] += 1
        if not success:
            c["api_failures"] += 1
    elif category == "signal":
        c["signal_total"] += 1
        if not success:  # conflict
            c["signal_conflicts"] += 1
    elif category == "exec":
        c["exec_total"] += 1
        if success:
            c["exec_success"] += 1
    elif category == "data":
        c["data_checks"] += 1
        if not success:  # stale
            c["data_stale"] += 1


def system_availability_score() -> dict:
    """
    v3.654 SYS-012: 计算系统综合可用度 [0-100]

    权重:
    - API成功率: 30% (api_calls > 0时)
    - 信号一致率: 25% (signal_total > 0时)
    - 执行成功率: 30% (exec_total > 0时)
    - 数据新鲜度: 15% (data_checks > 0时)

    Returns:
        {"score": float, "grade": str, "components": dict}
    """
    c = _system_availability_counters

    components = {}
    weights = []
    scores = []

    # API成功率
    if c["api_calls"] > 0:
        api_rate = 1.0 - c["api_failures"] / c["api_calls"]
        components["api_success_rate"] = round(api_rate, 4)
        weights.append(0.30)
        scores.append(api_rate)

    # 信号一致率
    if c["signal_total"] > 0:
        signal_rate = 1.0 - c["signal_conflicts"] / c["signal_total"]
        components["signal_consistency"] = round(signal_rate, 4)
        weights.append(0.25)
        scores.append(signal_rate)

    # 执行成功率
    if c["exec_total"] > 0:
        exec_rate = c["exec_success"] / c["exec_total"]
        components["exec_success_rate"] = round(exec_rate, 4)
        weights.append(0.30)
        scores.append(exec_rate)

    # 数据新鲜度
    if c["data_checks"] > 0:
        fresh_rate = 1.0 - c["data_stale"] / c["data_checks"]
        components["data_freshness"] = round(fresh_rate, 4)
        weights.append(0.15)
        scores.append(fresh_rate)

    # 加权平均
    if weights:
        total_weight = sum(weights)
        score = sum(s * w for s, w in zip(scores, weights)) / total_weight * 100
    else:
        score = 100.0  # 无数据时默认满分

    score = round(score, 1)
    if score >= 90:
        grade = "HEALTHY"
    elif score >= 70:
        grade = "DEGRADED"
    else:
        grade = "CRITICAL"

    uptime_hours = (time.time() - c["last_reset"]) / 3600

    return {
        "score": score,
        "grade": grade,
        "components": components,
        "uptime_hours": round(uptime_hours, 1),
        "enabled": SYSTEM_AVAILABILITY_ENABLED,
    }


def system_availability_reset() -> None:
    """v3.654: 每日重置计数器 (8AM NY)"""
    for k in _system_availability_counters:
        if k != "last_reset":
            _system_availability_counters[k] = 0
    _system_availability_counters["last_reset"] = time.time()


# ============================================================================
# v3.654 SYS-024: 滑点与成交质量追踪 (Phase 1)
# ============================================================================

_slippage_records = []  # [(symbol, action, signal_price, fill_price, slippage_bps, ts)]
SLIPPAGE_ALERT_BPS = {"stock": 10, "crypto": 20}  # 告警阈值(bps)


def slippage_tracker_record(symbol: str, action: str, signal_price: float, fill_price: float) -> None:
    """v3.654: 记录信号价 vs 成交价"""
    if signal_price <= 0:
        return
    slippage_bps = abs(fill_price - signal_price) / signal_price * 10000
    _slippage_records.append({
        "symbol": symbol,
        "action": action,
        "signal_price": signal_price,
        "fill_price": fill_price,
        "slippage_bps": round(slippage_bps, 2),
        "ts": time.time(),
    })
    # 保留最近200条
    if len(_slippage_records) > 200:
        _slippage_records.pop(0)
    # 告警
    asset_type = "crypto" if symbol.endswith("USDC") or symbol.endswith("USDT") or symbol.endswith("USD") else "stock"
    threshold = SLIPPAGE_ALERT_BPS.get(asset_type, 10)
    if slippage_bps > threshold:
        log_to_server(f"[SLIPPAGE][{symbol}] 滑点告警: {action} signal={signal_price:.2f} fill={fill_price:.2f} "
              f"slippage={slippage_bps:.1f}bps>{threshold}bps")


def slippage_tracker_summary() -> dict:
    """v3.654: 滑点统计摘要"""
    if not _slippage_records:
        return {"count": 0, "avg_bps": 0, "max_bps": 0, "alerts": 0}
    bps_list = [r["slippage_bps"] for r in _slippage_records]
    alerts = sum(1 for r in _slippage_records
                 if r["slippage_bps"] > SLIPPAGE_ALERT_BPS.get(
                     "crypto" if r["symbol"].endswith(("USDC", "USDT", "USD")) else "stock", 10))
    return {
        "count": len(bps_list),
        "avg_bps": round(sum(bps_list) / len(bps_list), 2),
        "max_bps": round(max(bps_list), 2),
        "alerts": alerts,
    }


# v2.580: Supreme Position Protection (P0 最高优先级)
# ============================================================================

def check_supreme_position_protection(
    pos_ratio: float,
    action: str,
    last_close: float,
    low_120: float,
    high_120: float,
    dynamic_thresholds: dict = None,  # v2.650新增
    state: dict = None,  # v2.697: 添加state以显示浮亏
) -> dict:
    """
    v2.697: Supreme位置保护（ATR自适应版本 + 浮亏显示）
    
    v2.697 新增:
    - 显示用户持仓成本
    - 显示当前浮盈/浮亏
    - 低位+大浮亏时警告提示
    
    v2.650 核心改进:
    - 低位阈值: 不再固定5%，使用ATR动态计算 [2%, 10%]
    - 高位阈值: 不再固定95%，使用ATR动态计算 [90%, 98%]
    - Regime联动: UPTREND_RIDE时放宽高位限制+20%
    
    Args:
        pos_ratio: 位置比例 (0.0-1.0)
        action: 建议动作 (BUY/SELL/HOLD)
        last_close: 当前价格
        low_120: 120根最低点
        high_120: 120根最高点
        dynamic_thresholds: v2.650动态阈值字典（可选）
        state: v2.697状态字典，用于计算浮亏（可选）
        
    Returns:
        {
            "protected": bool,
            "final_action": str,
            "original_action": str,
            "protection_type": str,
            "reason": str,
            "pos_ratio": float,
            "thresholds_used": dict,
        }
    """
    
    # v2.720: 先初始化 result，避免熔断器分支中使用未定义变量
    # v2.650: 获取动态阈值 (提前计算)
    if dynamic_thresholds and dynamic_thresholds.get("status") == "SUCCESS":
        supreme_low = dynamic_thresholds["dynamic_supreme_low"]
        supreme_high = dynamic_thresholds["dynamic_supreme_high"]
        vol_mult = dynamic_thresholds.get("volatility_multiplier", 1.0)
        atr_pct = dynamic_thresholds.get("atr_pct", 0.02)
        is_adaptive = True
    else:
        # 回退到v2.630固定阈值
        supreme_low = 0.05
        supreme_high = 0.95
        vol_mult = 1.0
        atr_pct = 0.02
        is_adaptive = False
    
    result = {
        "protected": False,
        "final_action": action,
        "original_action": action,
        "protection_type": "NONE",
        "reason": "",
        "pos_ratio": pos_ratio,
        "thresholds_used": {
            "supreme_low": supreme_low,
            "supreme_high": supreme_high,
            "volatility_multiplier": vol_mult,
            "atr_pct": atr_pct,
            "adaptive": is_adaptive,
        }
    }
    
    # v2.697: 计算并显示用户浮亏
    avg_cost = None
    pnl_pct = None
    
    # v2.700: 熔断器检查结果
    circuit_breaker_result = None
    if state and last_close > 0:
        open_buys = state.get("open_buys", [])
        if open_buys and len(open_buys) > 0:
            try:
                # v2.865: 兼容处理 - open_buys元素可能是dict或float
                total_cost = 0
                total_size = 0
                for b in open_buys:
                    if isinstance(b, dict):
                        total_cost += float(b.get("price", 0)) * float(b.get("size", 0))
                        total_size += float(b.get("size", 0))
                    elif isinstance(b, (int, float)):
                        # 如果是简单数值，假设是价格，size=1
                        total_cost += float(b)
                        total_size += 1
                
                if total_size > 0:
                    avg_cost = total_cost / total_size
                    # v3.472: 防止avg_cost为0导致除零错误
                    if avg_cost > 0:
                        pnl_pct = (last_close - avg_cost) / avg_cost * 100
                    else:
                        pnl_pct = 0
                        print(f"[SUPREME_P0] ⚠️  持仓成本为0，跳过浮亏计算")

                    print(f"[SUPREME_P0] 💰 持仓信息:")
                    print(f"[SUPREME_P0]    持仓成本: {avg_cost:.2f}")
                    print(f"[SUPREME_P0]    当前价格: {last_close:.2f}")
                    print(f"[SUPREME_P0]    浮动盈亏: {pnl_pct:+.1f}%")
                    print(f"[SUPREME_P0]    市场位置: {pos_ratio*100:.1f}% (in {low_120:.2f}-{high_120:.2f})")
            except Exception as e:
                print(f"[SUPREME_P0] ⚠️  浮亏计算异常: {e}")
    
    # v2.700 FULL_ASSET_PATCH: 熔断器检查
    position_units = 0
    if state:
        position_units = state.get("position", 0)
    
    circuit_breaker_result = check_circuit_breaker(
        symbol="UNKNOWN",  # symbol 在此函数中不可用
        pnl_pct=pnl_pct,
        position_units=position_units
    )
    
    if circuit_breaker_result and circuit_breaker_result["triggered"]:
        # 熔断触发，根据当前action决定
        if action == "BUY":
            result["protected"] = True
            result["final_action"] = "HOLD"
            result["protection_type"] = "CIRCUIT_BREAKER_BLOCK_BUY"
            result["reason"] = f"熔断器触发: {circuit_breaker_result['trigger_reason']}, 禁止买入"
            result["circuit_breaker"] = circuit_breaker_result
            log_to_server(f"[CIRCUIT_BREAKER] 阻止BUY: 熔断模式下禁止新开仓")
            return result
        elif action == "SELL" and position_units > 0:
            # 熔断模式下允许卖出减仓
            log_to_server(f"[CIRCUIT_BREAKER] 允许SELL: 熔断模式下鼓励减仓")
    
    # v2.720: 日志输出移到这里（result已初始化）
    if is_adaptive:
        print(f"[SUPREME_P0] 🎯 ATR自适应: Low={supreme_low:.2%}, High={supreme_high:.2%}, Vol_Mult={vol_mult:.2f}")
    else:
        print(f"[SUPREME_P0] ⚠️  ATR不可用，回退到v2.630固定阈值: Low=5.0%, High=95.0%")
    
    # 极低位保护: 禁止SELL + v2.698强制允许BUY
    if pos_ratio < supreme_low:
        if action == "SELL":
            result["protected"] = True
            result["final_action"] = "HOLD"
            result["protection_type"] = "SUPREME_LOW_BLOCK_SELL"
            
            adaptive_tag = f"[ATR{supreme_low*100:.1f}%]" if is_adaptive else "[固定5%]"
            result["reason"] = (
                f"极低位保护: pos_ratio={pos_ratio:.2%} < {supreme_low:.2%}{adaptive_tag}, "
                f"价格{last_close:.2f}接近低点{low_120:.2f}, 禁止SELL"
            )
            print(f"[SUPREME_P0] 🛡️  极低位保护{adaptive_tag}: 阻止SELL (pos={pos_ratio:.2%})")
            
            # v2.697: 浮亏警告
            if pnl_pct is not None and pnl_pct < -5:
                print(f"[SUPREME_P0] ⚠️  注意: 虽在低位({pos_ratio:.1%})，但浮亏{pnl_pct:.1f}%")
                print(f"[SUPREME_P0]    建议: 考虑风险承受能力，可能需要手动止损")
        elif action == "BUY":
            # v2.698: 强制允许层 - 极低位强制允许买入（覆盖其他Gate）
            result["protected"] = False
            result["final_action"] = "BUY"
            result["protection_type"] = "SUPREME_LOW_FORCE_BUY"
            result["supreme_override"] = True
            adaptive_tag = f"[ATR{supreme_low*100:.1f}%]" if is_adaptive else "[固定5%]"
            result["reason"] = f"极低位强制允许: pos_ratio={pos_ratio:.2%} < {supreme_low:.2%}{adaptive_tag}, 强制BUY"
            print(f"[SUPREME_P0] ⚡ 极低位强制允许{adaptive_tag}: BUY (pos={pos_ratio:.2%})")
        else:
            result["reason"] = f"极低位({pos_ratio:.2%})允许{action}"
    
    # 极高位保护: 禁止BUY + v2.698强制允许SELL
    elif pos_ratio > supreme_high:
        if action == "BUY":
            result["protected"] = True
            result["final_action"] = "HOLD"
            result["protection_type"] = "SUPREME_HIGH_BLOCK_BUY"
            
            adaptive_tag = f"[ATR{supreme_high*100:.1f}%]" if is_adaptive else "[固定95%]"
            result["reason"] = (
                f"极高位保护: pos_ratio={pos_ratio:.2%} > {supreme_high:.2%}{adaptive_tag}, "
                f"价格{last_close:.2f}接近高点{high_120:.2f}, 禁止BUY"
            )
            print(f"[SUPREME_P0] 🛡️  极高位保护{adaptive_tag}: 阻止BUY (pos={pos_ratio:.2%})")
        elif action == "SELL":
            # v2.698: 强制允许层 - 极高位强制允许卖出（覆盖其他Gate）
            result["protected"] = False
            result["final_action"] = "SELL"
            result["protection_type"] = "SUPREME_HIGH_FORCE_SELL"
            result["supreme_override"] = True
            adaptive_tag = f"[ATR{supreme_high*100:.1f}%]" if is_adaptive else "[固定95%]"
            result["reason"] = f"极高位强制允许: pos_ratio={pos_ratio:.2%} > {supreme_high:.2%}{adaptive_tag}, 强制SELL"
            print(f"[SUPREME_P0] ⚡ 极高位强制允许{adaptive_tag}: SELL (pos={pos_ratio:.2%})")
        else:
            result["reason"] = f"极高位({pos_ratio:.2%})允许{action}"
    
    else:
        result["reason"] = f"正常位置({pos_ratio:.2%})不需要保护"
    
    return result


# ============================================================================
# End of v2.580 Supreme Position Protection
