# ============================================================================
# v2.935: 突破/跌破豁免检查
# ============================================================================

def check_breakout_exemption(
    l2_zone_tag: str,
    breakout_confirmed: bool,
    pa_edge_buy: bool,
    pa_edge_sell: bool,
    l1_action: str,
) -> dict:
    """
    v2.935: 检查是否满足突破/跌破豁免条件
    
    满足3/4核心条件时，豁免Supreme高位/低位保护
    
    多头突破条件:
    ① zone = ABOVE_RESIST
    ② breakout_confirmed = True
    ③ pa_edge_buy = True  
    ④ L1 = BUY
    
    空头跌破条件:
    ① zone = BELOW_SUPPORT
    ② breakout_confirmed = True
    ③ pa_edge_sell = True
    ④ L1 = SELL
    
    Returns:
        {
            "exempt": bool,           # 是否豁免
            "direction": str,         # "BULL_BREAKOUT" / "BEAR_BREAKDOWN" / "NONE"
            "conditions_met": int,    # 满足的条件数
            "conditions_detail": dict,# 各条件详情
            "score_adjustment": int,  # L2 Score调整值 (+2/-2/0)
        }
    """
    result = {
        "exempt": False,
        "direction": "NONE",
        "conditions_met": 0,
        "conditions_detail": {},
        "score_adjustment": 0,
    }
    
    # 检查多头突破条件
    bull_conditions = {
        "zone_above_resist": l2_zone_tag == "ABOVE_RESIST",
        "breakout_confirmed": breakout_confirmed,
        "pa_edge_buy": pa_edge_buy,
        "l1_buy": l1_action == "BUY",
    }
    bull_met = sum(1 for v in bull_conditions.values() if v)
    
    # 检查空头跌破条件
    bear_conditions = {
        "zone_below_support": l2_zone_tag == "BELOW_SUPPORT",
        "breakout_confirmed": breakout_confirmed,  # breakout_confirmed也用于跌破确认
        "pa_edge_sell": pa_edge_sell,
        "l1_sell": l1_action == "SELL",
    }
    bear_met = sum(1 for v in bear_conditions.values() if v)
    
    # 多头突破豁免: 满足3/4条件
    if bull_met >= 3:
        result["exempt"] = True
        result["direction"] = "BULL_BREAKOUT"
        result["conditions_met"] = bull_met
        result["conditions_detail"] = bull_conditions
        result["score_adjustment"] = 2  # L2 Score +2
        print(f"\n{'='*60}")
        print(f"[v2.935] ⚡ 多头突破豁免触发!")
        print(f"         条件满足: {bull_met}/4")
        print(f"         ① zone=ABOVE_RESIST: {bull_conditions['zone_above_resist']}")
        print(f"         ② breakout_confirmed: {bull_conditions['breakout_confirmed']}")
        print(f"         ③ pa_edge_buy: {bull_conditions['pa_edge_buy']}")
        print(f"         ④ L1=BUY: {bull_conditions['l1_buy']}")
        print(f"         → Supreme高位保护豁免, L2 Score +2")
        print(f"{'='*60}\n")
    
    # 空头跌破豁免: 满足3/4条件
    elif bear_met >= 3:
        result["exempt"] = True
        result["direction"] = "BEAR_BREAKDOWN"
        result["conditions_met"] = bear_met
        result["conditions_detail"] = bear_conditions
        result["score_adjustment"] = -2  # L2 Score -2
        print(f"\n{'='*60}")
        print(f"[v2.935] ⚡ 空头跌破豁免触发!")
        print(f"         条件满足: {bear_met}/4")
        print(f"         ① zone=BELOW_SUPPORT: {bear_conditions['zone_below_support']}")
        print(f"         ② breakout_confirmed: {bear_conditions['breakout_confirmed']}")
        print(f"         ③ pa_edge_sell: {bear_conditions['pa_edge_sell']}")
        print(f"         ④ L1=SELL: {bear_conditions['l1_sell']}")
        print(f"         → Supreme低位保护豁免, L2 Score -2")
        print(f"{'='*60}\n")
    
    return result

