# ============================================================================
# v2.660: Bollinger Band Ride Detection (布林带贴边检测)
# ============================================================================

def calculate_bollinger_bands(bars, period=20, std_dev=2.0):
    """
    v2.660: 计算布林带
    
    Args:
        bars: K线数据列表 [{open, high, low, close, volume}, ...]
        period: 均线周期（默认20）
        std_dev: 标准差倍数（默认2.0）
    
    Returns:
        {
            'ma': 中轨（移动平均）,
            'upper': 上轨,
            'lower': 下轨,
            'bandwidth': 带宽百分比,
            'last_close': 最后收盘价,
            'position_pct': 价格在带内位置(0-1),
            'upper_distance_pct': 距离上轨的百分比,
            'lower_distance_pct': 距离下轨的百分比,
            'std': 标准差,
        }
        或 None（数据不足）
    """
    if not bars or len(bars) < period:
        return None
    
    # 取最近period根K线的收盘价
    closes = [float(bar.get('close', 0)) for bar in bars[-period:]]
    
    # 计算移动平均
    ma = sum(closes) / period
    
    # 计算标准差
    variance = sum((x - ma) ** 2 for x in closes) / period
    std = variance ** 0.5
    
    # 计算上下轨
    upper_band = ma + std_dev * std
    lower_band = ma - std_dev * std
    
    # 最后收盘价
    last_close = closes[-1]
    
    # 带宽（相对于中轨的百分比）
    bandwidth = (upper_band - lower_band) / ma if ma > 0 else 0
    
    # 计算距离上轨/下轨的百分比
    if upper_band > lower_band:
        # 价格在带内的位置（0%=下轨，50%=中轨，100%=上轨）
        position_pct = (last_close - lower_band) / (upper_band - lower_band)
        upper_distance_pct = abs(last_close - upper_band) / upper_band  # 距离上轨
        lower_distance_pct = abs(last_close - lower_band) / lower_band  # 距离下轨
    else:
        position_pct = 0.5
        upper_distance_pct = 0.0
        lower_distance_pct = 0.0
    
    return {
        'ma': ma,
        'upper': upper_band,
        'lower': lower_band,
        'bandwidth': bandwidth,
        'last_close': last_close,
        'position_pct': position_pct,
        'upper_distance_pct': upper_distance_pct,
        'lower_distance_pct': lower_distance_pct,
        'std': std,
    }


def detect_bollinger_ride(bars, period=20, std_dev=2.0, threshold_pct=0.05, window=5):
    """
    v2.660: 检测布林带贴边
    
    核心逻辑:
        - 统计最近N根K线中有多少根"贴着"上轨或下轨
        - "贴着"定义：距离轨道小于threshold_pct（默认5%）
        - 如果window根中有3根以上贴轨 → 判定为贴边
    
    Args:
        bars: K线数据列表
        period: 布林带周期（默认20）
        std_dev: 标准差倍数（默认2.0）
        threshold_pct: 贴边阈值（默认5%，即距离轨道5%以内算贴边）
        window: 检测窗口（默认最近5根）
    
    Returns:
        {
            'ride_type': "BB_UPPER_RIDE" / "BB_LOWER_RIDE" / "BB_MIDDLE",
            'upper_ride_count': 贴上轨数量,
            'lower_ride_count': 贴下轨数量,
            'bb_data': 布林带数据,
            'reason': 判定原因,
        }
    """
    result = {
        'ride_type': "BB_MIDDLE",
        'upper_ride_count': 0,
        'lower_ride_count': 0,
        'bb_data': None,
        'reason': "",
    }
    
    # 至少需要period + window根数据
    if not bars or len(bars) < period + window:
        result['reason'] = "insufficient data"
        return result
    
    # 计算布林带
    bb_data = calculate_bollinger_bands(bars, period, std_dev)
    if not bb_data:
        result['reason'] = "BB calculation failed"
        return result
    
    result['bb_data'] = bb_data
    
    # 取最近window根K线
    recent_bars = bars[-window:]
    
    # 统计贴上轨和贴下轨的数量
    upper_ride_count = 0
    lower_ride_count = 0
    
    for bar in recent_bars:
        close = float(bar.get('close', 0))
        
        # 距离上轨的百分比
        upper_distance_pct = abs(close - bb_data['upper']) / bb_data['upper']
        # 距离下轨的百分比
        lower_distance_pct = abs(close - bb_data['lower']) / bb_data['lower']
        
        # 判断是否贴上轨（距离上轨小于阈值）
        if close >= bb_data['upper'] * (1 - threshold_pct):
            upper_ride_count += 1
        
        # 判断是否贴下轨（距离下轨小于阈值）
        if close <= bb_data['lower'] * (1 + threshold_pct):
            lower_ride_count += 1
    
    result['upper_ride_count'] = upper_ride_count
    result['lower_ride_count'] = lower_ride_count
    
    # 判定：window根中有3根以上贴边
    ride_threshold = max(3, window // 2 + 1)  # 至少3根，或超过一半
    
    if upper_ride_count >= ride_threshold:
        result['ride_type'] = "BB_UPPER_RIDE"
        result['reason'] = f"{upper_ride_count}/{window} bars riding upper band"
    elif lower_ride_count >= ride_threshold:
        result['ride_type'] = "BB_LOWER_RIDE"
        result['reason'] = f"{lower_ride_count}/{window} bars riding lower band"
    else:
        result['ride_type'] = "BB_MIDDLE"
        result['reason'] = f"upper:{upper_ride_count}, lower:{lower_ride_count}, threshold:{ride_threshold}"
    
    return result


# v2.700 FULL_ASSET_PATCH: 动量激增检测
def _detect_momentum_surge(ohlcv_bars: list, atr: float = None) -> dict:
    """
    v2.700: 检测动量激增
    
    条件：连续3根K线大幅波动 + 成交量激增
    触发后降低 Hysteresis 系数实现更快趋势识别
    
    Returns:
        {
            "detected": bool,
            "break_count": int,
            "volume_ratio": float,
            "reduce_hysteresis": bool,
        }
    """
    result = {
        "detected": False,
        "break_count": 0,
        "volume_ratio": 1.0,
        "reduce_hysteresis": False,
    }
    
    if not ohlcv_bars or len(ohlcv_bars) < 6:
        return result
    
    # 计算ATR（如果未提供）
    if atr is None or atr <= 0:
        ranges = [abs(b.get("high", 0) - b.get("low", 0)) for b in ohlcv_bars[-14:]]
        atr = sum(ranges) / len(ranges) if ranges else 0
    
    if atr <= 0:
        return result
    
    recent_3 = ohlcv_bars[-3:]
    
    # 检查连续3根大幅波动（超过1.5倍ATR）
    breaks = 0
    for bar in recent_3:
        move = abs(bar.get("close", 0) - bar.get("open", 0))
        if move > atr * 1.5:
            breaks += 1
    
    result["break_count"] = breaks
    
    # 检查成交量激增
    if len(ohlcv_bars) >= 6:
        prev_vols = [b.get("volume", 0) for b in ohlcv_bars[-6:-3]]
        recent_vols = [b.get("volume", 0) for b in recent_3]
        avg_prev = sum(prev_vols) / len(prev_vols) if prev_vols else 1
        avg_recent = sum(recent_vols) / len(recent_vols) if recent_vols else 0
        
        if avg_prev > 0:
            result["volume_ratio"] = avg_recent / avg_prev
    
    # 判断是否触发
    if breaks >= 2 and result["volume_ratio"] > 1.8:
        result["detected"] = True
        result["reduce_hysteresis"] = True
        print(f"[MOMENTUM_SURGE] 🔥 检测到动量激增: {breaks}根大幅波动, 成交量{result['volume_ratio']:.1f}x")
    
    return result


def detect_market_regime_v2660(ohlcv_window, prev_sr_support, prev_sr_resistance, last_close):
    """
    v2.660: 增强版Regime检测（集成布林带贴边）
    
    检测优先级:
        1. 布林带贴边检测（最优先，最准确）
        2. prev_sr通道检测（备用，数据不足时）
    """
    result = {
        "regime": "RANGE", 
        "upper_ride_count": 0, 
        "lower_ride_count": 0,
        "recent_n": REGIME_RECENT_N, 
        "width_pct": 0.0,
        "prev_sr_support": prev_sr_support, 
        "prev_sr_resistance": prev_sr_resistance,
        "prev_sr_mid": 0.0, 
        "last_close": last_close, 
        "reason": "",
        "bb_ride": False,  # 是否使用布林带检测
        "bb_data": None,   # 布林带数据
    }
    
    # 检查数据充足性（降低到8根）
    if not ohlcv_window or len(ohlcv_window) < 8:
        result["reason"] = "insufficient data"
        return result
    
    # ========================================================================
    # 优先：布林带贴边检测（如果数据足够）
    # ========================================================================
    if len(ohlcv_window) >= 25:  # 20周期 + 5检测窗口
        bb_ride_result = detect_bollinger_ride(
            ohlcv_window, 
            period=20, 
            std_dev=2.0, 
            threshold_pct=0.05,  # 5%以内算贴边
            window=5             # 最近5根
        )
        
        if bb_ride_result['ride_type'] == "BB_UPPER_RIDE":
            result["regime"] = "UPTREND_RIDE"
            result["upper_ride_count"] = bb_ride_result['upper_ride_count']
            result["lower_ride_count"] = bb_ride_result['lower_ride_count']
            result["reason"] = f"BB贴边上行: {bb_ride_result['reason']}"
            result["bb_ride"] = True
            result["bb_data"] = bb_ride_result['bb_data']
            return result  # 直接返回，不再检查prev_sr
        
        elif bb_ride_result['ride_type'] == "BB_LOWER_RIDE":
            result["regime"] = "DOWNTREND_RIDE"
            result["upper_ride_count"] = bb_ride_result['upper_ride_count']
            result["lower_ride_count"] = bb_ride_result['lower_ride_count']
            result["reason"] = f"BB贴边下行: {bb_ride_result['reason']}"
            result["bb_ride"] = True
            result["bb_data"] = bb_ride_result['bb_data']
            return result
        
        # 如果不是明显贴边，继续用prev_sr检查
        result["bb_data"] = bb_ride_result['bb_data']
    
    # ========================================================================
    # 备用：prev_sr通道检测（原有逻辑）
    # ========================================================================
    if prev_sr_resistance <= prev_sr_support or prev_sr_support <= 0:
        result["reason"] = "invalid SR"
        return result
    
    prev_sr_mid = (prev_sr_support + prev_sr_resistance) / 2
    width_pct = (prev_sr_resistance - prev_sr_support) / prev_sr_support
    result["prev_sr_mid"] = prev_sr_mid
    result["width_pct"] = width_pct
    
    if width_pct < REGIME_WIDTH_PCT_MIN:
        result["reason"] = "channel too narrow"
        return result
    
    # 确保有足够数据
    if len(ohlcv_window) < REGIME_RECENT_N + 1:
        result["reason"] = "insufficient data for prev_sr check"
        return result
    
    recent_bars = ohlcv_window[-(REGIME_RECENT_N+1):-1]
    upper_count = sum(1 for bar in recent_bars if bar.get("close", 0) > prev_sr_mid)
    lower_count = len(recent_bars) - upper_count
    result["upper_ride_count"] = upper_count
    result["lower_ride_count"] = lower_count
    
    # v2.698: Hysteresis防抖动 + 最小持续K线
    # v2.700: 动态调整（动量激增时降低）
    momentum_result = _detect_momentum_surge(ohlcv_window)
    
    if momentum_result["reduce_hysteresis"]:
        REGIME_ENTER_THRESHOLD = 6   # 动量激增时降低进入阈值
        REGIME_EXIT_THRESHOLD = 4    # 动量激增时降低退出阈值
        print(f"[REGIME_HYSTERESIS] ⚡ 动态调整: Enter={REGIME_ENTER_THRESHOLD}, Exit={REGIME_EXIT_THRESHOLD}")
    else:
        REGIME_ENTER_THRESHOLD = 8   # 正常进入阈值
        REGIME_EXIT_THRESHOLD = 5    # 正常退出阈值
    
    # 获取上一次regime状态（从result中获取，调用方需要传入）
    prev_regime = result.get("_prev_regime", "RANGE")
    
    if prev_regime == "RANGE":
        # 当前是RANGE，需要高阈值才能进入TREND
        if upper_count >= REGIME_ENTER_THRESHOLD:
            result["regime"] = "UPTREND_RIDE"
            result["reason"] = f"prev_sr上行(进入): {upper_count}/{REGIME_RECENT_N} >= {REGIME_ENTER_THRESHOLD}"
        elif lower_count >= REGIME_ENTER_THRESHOLD:
            result["regime"] = "DOWNTREND_RIDE"
            result["reason"] = f"prev_sr下行(进入): {lower_count}/{REGIME_RECENT_N} >= {REGIME_ENTER_THRESHOLD}"
        else:
            result["regime"] = "RANGE"
            result["reason"] = f"平衡震荡: upper={upper_count}, lower={lower_count}"
    else:
        # 当前是TREND，需要低阈值才能退出
        if prev_regime == "UPTREND_RIDE":
            if upper_count < REGIME_EXIT_THRESHOLD:
                result["regime"] = "RANGE"
                result["reason"] = f"上行趋势退出: {upper_count}/{REGIME_RECENT_N} < {REGIME_EXIT_THRESHOLD}"
            else:
                result["regime"] = "UPTREND_RIDE"
                result["reason"] = f"上行趋势保持: {upper_count}/{REGIME_RECENT_N}"
        elif prev_regime == "DOWNTREND_RIDE":
            if lower_count < REGIME_EXIT_THRESHOLD:
                result["regime"] = "RANGE"
                result["reason"] = f"下行趋势退出: {lower_count}/{REGIME_RECENT_N} < {REGIME_EXIT_THRESHOLD}"
            else:
                result["regime"] = "DOWNTREND_RIDE"
                result["reason"] = f"下行趋势保持: {lower_count}/{REGIME_RECENT_N}"
        else:
            result["regime"] = "RANGE"
            result["reason"] = f"平衡震荡: upper={upper_count}, lower={lower_count}"
    
    return result

def apply_regime_aware_l2_bias_v2660(regime, zone, base_exec_bias, last_close, prev_sr_mid, pa_tag, two_b_tag, score, bb_data=None):
    """
    v2.660: 增强版Regime感知的L2 bias调整
    
    新增: 布林带贴边时的特殊处理
    """
    # 原有RANGE逻辑不变
    if regime == "RANGE":
        return base_exec_bias
    
    # ========================================================================
    # v2.660: 布林带贴边上行的特殊处理
    # ========================================================================
    elif regime == "UPTREND_RIDE":
        # 如果是布林带检测的贴边上行
        if bb_data and bb_data.get('position_pct', 0) > 0.8:  # 价格在带内80%以上
            # 高位区域（上半区、上部、中部）
            if zone in ["UPPER_HALF", "UPPER", "MID"]:
                # 允许高位买入（这是关键！）
                if base_exec_bias == "HOLD":
                    print(f"[v2.660] 🔥 BB贴边上行高位买入: HOLD → BUY (BB位置:{bb_data['position_pct']*100:.1f}%)")
                    return "BUY"
                
                # 高位不卖（持有待涨）
                elif base_exec_bias in ["SELL", "FORCE_SELL"]:
                    if score > 0:  # LLM看多
                        print(f"[v2.660] 🔥 BB贴边上行高位持有: {base_exec_bias} → HOLD (score={score:.2f})")
                        return "HOLD"
        
        # 原有prev_sr逻辑（作为备用）
        # v3.499修复: 只有当L2评分>0(看多)时才允许HOLD升级为BUY
        # L2评分=0(无明确信号)时尊重评分系统判断，不随意升级
        else:
            if zone == "MID" or (zone == "LOWER_HALF" and last_close >= prev_sr_mid * 0.98):
                if base_exec_bias == "HOLD" and score > 0:
                    print(f"[v3.499] UPTREND_RIDE + {zone} + score={score}>0 → HOLD升级为BUY")
                    return "BUY"
                elif base_exec_bias == "HOLD" and score <= 0:
                    print(f"[v3.499] UPTREND_RIDE + {zone}但score={score}<=0 → 维持HOLD")
            elif zone in ["UPPER_HALF", "UPPER"]:
                if base_exec_bias in ["SELL", "FORCE_SELL"]:
                    if last_close >= prev_sr_mid and score > 0:
                        return "HOLD"
    
    # ========================================================================
    # v2.660: 布林带贴边下行的特殊处理
    # ========================================================================
    elif regime == "DOWNTREND_RIDE":
        # 如果是布林带检测的贴边下行
        if bb_data and bb_data.get('position_pct', 0) < 0.2:  # 价格在带内20%以下
            # 低位区域（下半区、下部、中部）
            if zone in ["LOWER_HALF", "LOWER", "MID"]:
                # 允许低位卖出
                if base_exec_bias == "HOLD":
                    print(f"[v2.660] 🔥 BB贴边下行低位卖出: HOLD → SELL (BB位置:{bb_data['position_pct']*100:.1f}%)")
                    return "SELL"
                
                # 低位不买（等待更低）
                elif base_exec_bias in ["BUY", "FORCE_BUY"]:
                    if score < 0:  # LLM看空
                        print(f"[v2.660] 🔥 BB贴边下行低位持有: {base_exec_bias} → HOLD (score={score:.2f})")
                        return "HOLD"
        
        # 原有prev_sr逻辑（作为备用）
        # v3.499修复: 只有当L2评分<0(看空)时才允许HOLD升级为SELL
        # L2评分=0(无明确信号)时尊重评分系统判断，不随意升级
        else:
            if zone == "MID" or (zone == "UPPER_HALF" and last_close <= prev_sr_mid * 1.02):
                if base_exec_bias == "HOLD" and score < 0:
                    print(f"[v3.499] DOWNTREND_RIDE + {zone} + score={score}<0 → HOLD升级为SELL")
                    return "SELL"
                elif base_exec_bias == "HOLD" and score >= 0:
                    print(f"[v3.499] DOWNTREND_RIDE + {zone}但score={score}>=0 → 维持HOLD")
            elif zone in ["LOWER_HALF", "LOWER"]:
                if base_exec_bias in ["BUY", "FORCE_BUY"]:
                    if last_close <= prev_sr_mid and score < 0:
                        return "HOLD"

    return base_exec_bias

def apply_rhythm_time_decay(state: dict) -> dict:
    """
    v2.580: Rhythm配额时间衰减机制
    
    核心规则:
    - 如果配额已用完（>=3）
    - 且距离上次下单超过8小时
    - 自动释放1个配额
    - 防止横盘期系统"离线"
    
    Args:
        state: 状态字典（包含配额和时间戳）
        
    Returns:
        更新后的state字典
    """
    import time
    current_time = time.time()
    
    changed = False
    
    # ========================================================================
    # 买入配额时间衰减
    # ========================================================================
    two_buy_used = state.get("two_buy_used", 0)
    
    if two_buy_used >= 3:
        last_buy_time = state.get("last_buy_timestamp", current_time)
        hours_elapsed = (current_time - last_buy_time) / 3600
        
        if hours_elapsed >= 4:  # v2.670: 加速
            state["two_buy_used"] = 2  # 释放1个配额
            changed = True
            print(f"[RHYTHM_DECAY] ⏰ 买入配额时间衰减: {two_buy_used} → 2 "
                  f"(经过{hours_elapsed:.1f}小时)")
    
    # ========================================================================
    # 卖出配额时间衰减
    # ========================================================================
    two_sell_used = state.get("two_sell_used", 0)
    
    if two_sell_used >= 3:
        last_sell_time = state.get("last_sell_timestamp", current_time)
        hours_elapsed = (current_time - last_sell_time) / 3600
        
        if hours_elapsed >= 4:  # v2.670: 加速
            state["two_sell_used"] = 2  # 释放1个配额
            changed = True
            print(f"[RHYTHM_DECAY] ⏰ 卖出配额时间衰减: {two_sell_used} → 2 "
                  f"(经过{hours_elapsed:.1f}小时)")
    
    if changed:
        # 记录衰减时间
        state["last_decay_time"] = current_time
    
    return state

# ============================================================================
# End of v2.580 Rhythm Time Decay
# ============================================================================


