# ============================================================================
# v2.480: Smooth Position Score Function (P0 改进 #2)
# ============================================================================

def compute_position_score_smooth(dist_to_support_pct):
    """
    平滑位置评分函数 (v2.480)
    
    消除评分断层，提供连续平滑的位置评分
    
    评分曲线:
      0%:    +3.0  (极低位)
      10%:   +2.0
      20%:   +1.0
      30%:   +0.5  (低中位)
      40%:    0.0
      50%:    0.0  (正中)
      60%:    0.0
      70%:   -0.5  (中高位)
      80%:   -1.0
      90%:   -2.0
      100%:  -3.0  (极高位)
    
    Args:
        dist_to_support_pct: 距支撑的距离百分比 (0.0-1.0)
        
    Returns:
        float: 平滑位置评分 (-3.0 到 +3.0)
    """
    
    if dist_to_support_pct <= 0.30:
        # 低位区 (0-30%): +3.0 → +0.5
        # 线性插值: y = 3.0 - (x / 0.30) * 2.5
        score = 3.0 - (dist_to_support_pct / 0.30) * 2.5
        return round(score, 1)
    
    elif dist_to_support_pct >= 0.70:
        # 高位区 (70-100%): -0.5 → -3.0
        # 线性插值: y = -0.5 - ((x - 0.70) / 0.30) * 2.5
        normalized = (dist_to_support_pct - 0.70) / 0.30
        score = -0.5 - normalized * 2.5
        return round(score, 1)
    
    else:
        # 中部区 (30-70%): 0.0
        return 0.0


# ============================================================================
# End of v2.480 Smooth Position Score Function
# ============================================================================


# ============================================================================
# v2.480: SR Breakout Detection Function (P1 改进 #4)
# ============================================================================

def identify_breakout_type(price, sr_level, direction, volume_state, vol_ratio, 
                          trend_state, bars_count=1):
    """
    识别 SR 突破类型 (v2.480)
    
    通过成交量、趋势、幅度等多维度判断是真突破还是假突破
    
    Args:
        price: 当前价格
        sr_level: SR 水平 (support/resistance)
        direction: 突破方向 ("UP"/"DOWN")
        volume_state: 成交量状态 (CLIMAX/HIGH/NORMAL/LOW/DRY_UP)
        vol_ratio: 成交量比率
        trend_state: 趋势状态 (up/down/side)
        bars_count: 突破后持续K线数 (默认1)
        
    Returns:
        tuple: (breakout_type, breakout_strength)
            breakout_type: "TRUE_BREAKOUT" / "FALSE_BREAKOUT" / "PENDING"
            breakout_strength: 1-5 (强度评分)
    """
    
    # 计算突破幅度
    if direction == "UP":
        breakout_pct = (price - sr_level) / max(sr_level, 1e-6)
    else:  # DOWN
        breakout_pct = (sr_level - price) / max(sr_level, 1e-6)
    
    # 突破强度评分系统
    score = 0
    
    # 1. 成交量确认 (权重 40% = 4分)
    if volume_state in ("CLIMAX", "HIGH") and vol_ratio >= 1.5:
        score += 4  # 放量突破
    elif volume_state == "NORMAL" or (volume_state == "HIGH" and vol_ratio < 1.5):
        score += 2  # 正常量
    else:  # LOW, DRY_UP
        score += 0  # 缩量 (可疑)
    
    # 2. 趋势确认 (权重 30% = 3分)
    if direction == "UP":
        if trend_state == "up":
            score += 3  # 顺势突破
        elif trend_state == "side":
            score += 1  # 震荡突破
        else:  # down
            score += 0  # 逆势突破 (可疑)
    else:  # DOWN
        if trend_state == "down":
            score += 3  # 顺势突破
        elif trend_state == "side":
            score += 1  # 震荡突破
        else:  # up
            score += 0  # 逆势突破 (可疑)
    
    # 3. 突破幅度 (权重 20% = 2分)
    if breakout_pct >= 0.03:  # >= 3%
        score += 2  # 明显突破
    elif breakout_pct >= 0.01:  # 1-3%
        score += 1  # 轻微突破
    else:  # < 1%
        score += 0  # 刚突破
    
    # 4. 持续性 (权重 10% = 1分)
    if bars_count >= 3:
        score += 1  # 持续 3 根以上
    elif bars_count >= 1:
        score += 0  # 刚突破
    
    # 判断突破类型和强度
    if score >= 7:
        # 强真突破 (7-10 分)
        breakout_type = "TRUE_BREAKOUT"
        breakout_strength = 5
    elif score >= 5:
        # 弱真突破 (5-6 分)
        breakout_type = "TRUE_BREAKOUT"
        breakout_strength = 3
    elif score <= 3:
        # 假突破 (0-3 分)
        breakout_type = "FALSE_BREAKOUT"
        breakout_strength = 1
    else:
        # 待确认 (4 分)
        breakout_type = "PENDING"
        breakout_strength = 2
    
    return breakout_type, breakout_strength


# ============================================================================
# End of v2.480 SR Breakout Detection Function
# ============================================================================


    # v2.095: 修复判断逻辑 - 只要有correction_log且applied=True就说明10m在工作
    if not correction_log:
        result.append("10m小周期数据: ✗ 不可用（未初始化）")
