    # ===== v2.121: K线数据持久化方法 =====
    
    def _save_klines_to_disk(self):
        """保存K线数据到磁盘"""
        import json
        import time
        import os
        
        try:
            data = {
                "timestamp": time.time(),
                "version": "v3.250",  # v3.250: 版本号更新
                "kline_windows": self.kline_windows,
                "reference_closes": self.reference_closes,  # v2.910: 持久化基准价格
                "freeze_until": self.freeze_until,  # v3.250: 持久化L2-10m冻结时间
            }
            
            # 临时文件写入，然后原子性替换
            temp_file = self.state_file + ".tmp"
            with open(temp_file, 'w') as f:
                json.dump(data, f, indent=2)
            
            os.replace(temp_file, self.state_file)
            
            total_klines = sum(len(klines) for klines in self.kline_windows.values())
            print(f"[L2-10m] ✓ K线数据已保存: {len(self.kline_windows)} 个symbol, "
                  f"{total_klines} 根K线, {len(self.reference_closes)} 个基准价格")
            
            # v2.260: 同时生成 l2_10m_state.json 用于兼容性
            self._save_l2_10m_state()
            
        except Exception as e:
            print(f"[L2-10m ERROR] 保存K线数据失败: {e}")
    
    def _save_l2_10m_state(self):
        """
        v2.260: 生成 l2_10m_state.json 文件
        
        将内部K线窗口数据转换为兼容格式，供外部查询使用
        """
        import json
        import os
        
        try:
            state_data = {}
            
            for symbol, klines in self.kline_windows.items():
                if not klines or len(klines) < 3:
                    continue
                
                # 提取最近的K线数据
                recent_klines = klines[-10:] if len(klines) >= 10 else klines
                
                # 简单的趋势判断
                if len(recent_klines) >= 3:
                    first_close = recent_klines[0].get("close", 0)
                    last_close = recent_klines[-1].get("close", 0)
                    
                    if first_close > 0:
                        change_pct = (last_close - first_close) / first_close
                        
                        if change_pct > 0.01:  # 上涨超过1%
                            exec_bias_10m = "BUY"
                            if change_pct > 0.02:  # 上涨超过2%
                                exec_bias_10m = "STRONG_BUY"
                        elif change_pct < -0.01:  # 下跌超过1%
                            exec_bias_10m = "SELL"
                            if change_pct < -0.02:  # 下跌超过2%
                                exec_bias_10m = "STRONG_SELL"
                        else:
                            exec_bias_10m = "HOLD"
                    else:
                        exec_bias_10m = "HOLD"
                else:
                    exec_bias_10m = "HOLD"
                
                # 微顶/微底判断（简化版）
                if len(recent_klines) >= 5:
                    closes = [k.get("close", 0) for k in recent_klines]
                    mid_idx = len(closes) // 2
                    
                    # 检查中间点是否是极值
                    is_peak = closes[mid_idx] > closes[mid_idx-1] and closes[mid_idx] > closes[mid_idx+1]
                    is_valley = closes[mid_idx] < closes[mid_idx-1] and closes[mid_idx] < closes[mid_idx+1]
                    
                    if is_peak:
                        micro_reversal_10m = "MICRO_TOP"
                    elif is_valley:
                        micro_reversal_10m = "MICRO_BOTTOM"
                    else:
                        micro_reversal_10m = "NONE"
                else:
                    micro_reversal_10m = "NONE"
                
                # 构造状态数据
                state_data[symbol] = {
                    "exec_bias_10m": exec_bias_10m,
                    "micro_reversal_10m": micro_reversal_10m,
                    "time_ms": int(recent_klines[-1].get("timestamp", 0) * 1000),
                    "kline_count": len(recent_klines),
                    "last_close": recent_klines[-1].get("close", 0),
                }
            
            # 保存到文件 (v3.410: Windows文件锁定重试)
            state_file = "l2_10m_state.json"
            temp_file = state_file + ".tmp"

            with open(temp_file, 'w') as f:
                json.dump(state_data, f, indent=2)

            import time as _time
            for attempt in range(3):
                try:
                    os.replace(temp_file, state_file)
                    break
                except PermissionError:
                    if attempt < 2:
                        _time.sleep(0.1 * (attempt + 1))
                    else:
                        if os.path.exists(state_file):
                            os.remove(state_file)
                        os.rename(temp_file, state_file)

            print(f"[L2-10m] ✓ 状态文件已生成: {len(state_data)} 个symbol → l2_10m_state.json")

        except Exception as e:
            print(f"[L2-10m ERROR] 生成状态文件失败: {e}")
    
    def _load_klines_from_disk(self):
        """从磁盘加载K线数据"""
        import json
        import time
        import os
        
        abs_path = os.path.abspath(self.state_file)
        
        if not os.path.exists(self.state_file):
            print(f"[L2-10m] 未找到历史K线数据文件")
            print(f"         路径: {abs_path}")
            print(f"         状态: 首次运行或文件已删除")
            print(f"[L2-10m] 使用空窗口，将在收到新K线后开始分析")
            return
        
        try:
            with open(self.state_file, 'r') as f:
                data = json.load(f)
            
            self.kline_windows = data.get("kline_windows", {})
            self.reference_closes = data.get("reference_closes", {})  # v2.910: 恢复基准价格
            self.freeze_until = data.get("freeze_until", {})  # v3.250: 恢复L2-10m冻结时间
            saved_time = data.get("timestamp", 0)
            saved_version = data.get("version", "unknown")
            
            # v2.200: 清理过期数据（改为7天）
            current_time = time.time()
            age_hours = (current_time - saved_time) / 3600
            age_days = age_hours / 24
            
            if age_hours > 168:  # 7天 = 168小时
                print(f"[L2-10m] ⚠ 历史数据过期")
                print(f"         年龄: {age_days:.1f} 天（> 7天）")
                print(f"         清空数据")
                self.kline_windows = {}
                self.reference_closes = {}  # v2.910: 同时清空基准价格
                self.freeze_until = {}  # v3.250: 同时清空冻结时间
                return
            
            total_klines = sum(len(klines) for klines in self.kline_windows.values())
            print(f"[L2-10m] ✓ 已加载历史K线数据:")
            print(f"         文件: {abs_path}")
            print(f"         版本: {saved_version}")
            print(f"         年龄: {age_days:.1f} 天 ({age_hours:.1f} 小时)")
            print(f"         Symbol数: {len(self.kline_windows)}")
            print(f"         K线总数: {total_klines}")
            print(f"         基准价格数: {len(self.reference_closes)}")  # v2.910: 显示基准价格数量
            print(f"         冻结中: {len(self.freeze_until)}")  # v3.250: 显示冻结数量

            # 显示每个symbol的K线数量
            if self.kline_windows:
                print(f"         详情:")
                for symbol, klines in sorted(self.kline_windows.items()):
                    if klines:
                        print(f"           - {symbol}: {len(klines)} 根K线")
            
        except Exception as e:
            print(f"[L2-10m ERROR] 加载K线数据失败: {e}")
            import traceback
            traceback.print_exc()
            self.kline_windows = {}
            self.reference_closes = {}  # v2.910: 同时清空
            self.freeze_until = {}  # v3.250: 同时清空
    
    def force_save(self):
        """强制保存（程序退出时调用）"""
        try:
            print()
            print("[L2-10m] 程序退出，强制保存K线数据...")
            self._save_klines_to_disk()
            print("[L2-10m] ✓ 保存完成")
        except Exception as e:
            print(f"[L2-10m ERROR] 退出保存失败: {e}")
            import traceback
            traceback.print_exc()
    
    # ===== 持久化方法结束 =====
    
    def update_kline(self, symbol: str, kline: dict):
        """
        更新10m K线数据
        
        Args:
            symbol: 交易对
            kline: {
                "open": float,
                "high": float,
                "low": float,
                "close": float,
                "volume": float,
                "timestamp": int
            }
        """
        if symbol not in self.kline_windows:
            self.kline_windows[symbol] = []
        
        self.kline_windows[symbol].append(kline)
        
        # 保持窗口大小
        if len(self.kline_windows[symbol]) > self.max_window_size:
            self.kline_windows[symbol].pop(0)
        
        # v2.121: 定期保存
        import time
        current_time = time.time()
        if current_time - self.last_save_time > self.save_interval:
            self._save_klines_to_disk()
            self.last_save_time = current_time
    
    # ===== v2.856: 实时暴涨暴跌检测 =====
    
    def set_reference_close(self, symbol: str, close_price: float):
        """
        v2.856: 设置基准收盘价（大周期收盘时调用）
        
        Args:
            symbol: 交易对
            close_price: 上周期最后一根10m K线的收盘价
        """
        self.reference_closes[symbol] = close_price
        print(f"[L2-10m] {symbol} 基准价格已设置: {close_price:.4f}")
    
    def reset_cycle(self, symbol: str):
        """
        v2.856: 重置周期计数器（大周期收盘时调用）
        """
        if symbol in self.cycle_triggers:
            del self.cycle_triggers[symbol]
        print(f"[L2-10m] {symbol} 周期计数器已重置")
    
    def detect_realtime_signal(self, symbol: str, current_close: float) -> dict:
        """
        v2.856: 实时检测暴涨暴跌信号
        
        用当前10m K线收盘价与基准价格比较：
        - 美股: ±2.0% 触发
        - 加密: ±2.5% 触发
        
        Args:
            symbol: 交易对
            current_close: 当前10m K线收盘价
            
        Returns:
            {
                "signal": "CRASH_SELL" | "SURGE_BUY" | "NONE",
                "change_pct": float,
                "threshold": float,
                "reference_close": float,
                "can_trigger": bool,  # 本周期是否还能触发
                "reason": str
            }
        """
        result = {
            "signal": "NONE",
            "change_pct": 0.0,
            "threshold": 0.0,
            "reference_close": 0.0,
            "can_trigger": False,
            "reason": ""
        }
        
        # v3.250: 检查加密货币是否在L2-10m冻结期内
        if symbol in self.freeze_until:
            freeze_ts = self.freeze_until[symbol]
            now = time.time()
            if now < freeze_ts:
                remaining_hours = (freeze_ts - now) / 3600
                result["reason"] = f"frozen_l2_10m (剩余{remaining_hours:.1f}h)"
                print(f"[L2-10m] {symbol} L2-10m冻结中，剩余{remaining_hours:.1f}小时")
                return result
            else:
                # 冻结已过期，清理
                del self.freeze_until[symbol]
                print(f"[L2-10m] {symbol} L2-10m冻结已解除")

        # 检查是否有基准价格
        if symbol not in self.reference_closes:
            # v2.935: 添加调试日志
            print(f"[L2-10m WARNING] {symbol} 无基准价格，跳过检测")
            print(f"[L2-10m WARNING]   已有基准的symbols: {list(self.reference_closes.keys())}")
            result["reason"] = "no_reference_close"
            return result

        reference_close = self.reference_closes[symbol]
        result["reference_close"] = reference_close
        
        if reference_close <= 0:
            print(f"[L2-10m WARNING] {symbol} 基准价格无效: {reference_close}")
            result["reason"] = "invalid_reference_close"
            return result
        
        # 计算涨跌幅
        change_pct = (current_close - reference_close) / reference_close
        result["change_pct"] = change_pct
        
        # v2.900: 根据资产类型选择阈值（降低门槛）
        # v2.856原阈值: CRYPTO=3%, STOCKS=2% 太高，错过很多机会
        # v2.900新阈值: CRYPTO=2.5%, STOCKS=2.5%
        asset_type = self._get_asset_type(symbol)
        if asset_type == "CRYPTO":
            threshold = 0.025  # 2.5% (原3%，降低以捕捉更多机会)
        else:
            threshold = 0.025  # 2.5% (美股与加密货币统一阈值)
        result["threshold"] = threshold
        
        # 初始化周期计数器
        if symbol not in self.cycle_triggers:
            self.cycle_triggers[symbol] = {"sold": False, "bought": False}
        
        triggers = self.cycle_triggers[symbol]
        
        # 检测暴跌 → 卖出信号
        if change_pct < -threshold:
            if not triggers["sold"]:
                result["signal"] = "CRASH_SELL"
                result["can_trigger"] = True
                result["reason"] = f"暴跌{change_pct:.2%} < -{threshold:.1%}"
                print(f"\n{'='*60}")
                print(f"[L2-10m] ⚡ {symbol} 暴跌信号!")
                print(f"         基准价: {reference_close:.4f}")
                print(f"         当前价: {current_close:.4f}")
                print(f"         跌幅: {change_pct:.2%} (阈值: -{threshold:.1%})")
                print(f"{'='*60}\n")
            else:
                result["reason"] = "already_sold_this_cycle"
        
        # 检测暴涨 → 买入信号
        elif change_pct > threshold:
            if not triggers["bought"]:
                result["signal"] = "SURGE_BUY"
                result["can_trigger"] = True
                result["reason"] = f"暴涨{change_pct:.2%} > +{threshold:.1%}"
                print(f"\n{'='*60}")
                print(f"[L2-10m] ⚡ {symbol} 暴涨信号!")
                print(f"         基准价: {reference_close:.4f}")
                print(f"         当前价: {current_close:.4f}")
                print(f"         涨幅: {change_pct:.2%} (阈值: +{threshold:.1%})")
                print(f"{'='*60}\n")
            else:
                result["reason"] = "already_bought_this_cycle"
        else:
            result["reason"] = f"within_threshold ({change_pct:.2%})"
        
        return result
    
    def mark_triggered(self, symbol: str, action: str):
        """
        v2.856: 标记本周期已触发买/卖
        v3.250: 加密货币增加8小时固定冻结

        Args:
            symbol: 交易对
            action: "BUY" | "SELL"
        """
        if symbol not in self.cycle_triggers:
            self.cycle_triggers[symbol] = {"sold": False, "bought": False}

        if action == "SELL":
            self.cycle_triggers[symbol]["sold"] = True
            print(f"[L2-10m] {symbol} 本周期已标记: 卖出完成")
        elif action == "BUY":
            self.cycle_triggers[symbol]["bought"] = True
            print(f"[L2-10m] {symbol} 本周期已标记: 买入完成")

        # v3.250: 加密货币设置8小时固定冻结
        asset_type = self._get_asset_type(symbol)
        if asset_type == "CRYPTO":
            freeze_until_ts = time.time() + self.FREEZE_HOURS_CRYPTO * 3600
            self.freeze_until[symbol] = freeze_until_ts
            freeze_until_str = datetime.fromtimestamp(freeze_until_ts).strftime("%Y-%m-%d %H:%M:%S")
            print(f"[L2-10m] {symbol} 加密货币L2-10m冻结{self.FREEZE_HOURS_CRYPTO}小时至 {freeze_until_str}")
    
    def get_cycle_status(self, symbol: str) -> dict:
        """
        v2.856: 获取周期触发状态
        """
        if symbol not in self.cycle_triggers:
            return {"sold": False, "bought": False}
        return self.cycle_triggers[symbol].copy()

    def get_klines(self, symbol: str) -> list:
        """
        v3.472: 获取指定symbol的K线缓存数据

        Args:
            symbol: 交易品种

        Returns:
            K线列表，每个元素包含 {open, high, low, close, volume, timestamp}
            如果没有数据返回空列表
        """
        if symbol not in self.kline_windows:
            return []
        return self.kline_windows[symbol].copy()

    # ===== v2.856 实时检测结束 =====
    
    def _is_us_stock(self, symbol: str) -> bool:
        """判断是否为美股"""
        return not any(x in symbol.upper() for x in ["USDT", "BUSD", "BTC", "ETH", "CRYPTO"])
    
    # v2.700 FULL_ASSET_PATCH: 资产类型识别
    def _get_asset_type(self, symbol: str) -> str:
        """
        识别资产类型
        Returns: "CRYPTO" | "STOCKS"
        """
        # v2.935: 添加USDC支持
        crypto_keywords = ["USDT", "USDC", "BUSD", "BTC", "ETH", "CRYPTO", "PERP", "SWAP"]
        if any(x in symbol.upper() for x in crypto_keywords):
            return "CRYPTO"
        return "STOCKS"
    
    # ========== v2.095新增：窗口分析方法 ==========
    
    def analyze_window(self, symbol: str, window_size: int = 3) -> dict:
        """
        分析最近N根10m K线的整体特征
        
        Args:
            symbol: 交易对
            window_size: 窗口大小（默认3，对应30m主周期）
        
        Returns:
            {
                "window_trend": "BULLISH/BEARISH/NEUTRAL",
                "window_pa_signal": "BULL_*/BEAR_*/NONE",
                "window_volume_state": "EXPANDING/CLIMAX/CONTRACTING/NORMAL",
                "fake_break_tag": "FAKE_BREAKOUT/FAKE_BREAKDOWN/NONE",
                "fake_break_signal": "CAN_SELL/CAN_BUY/NONE",
                "fake_break_confidence": "HIGH/MEDIUM/LOW",
                "crash_alert": {...},
                "confidence": "HIGH/MEDIUM/LOW",
                "has_data": bool
            }
        """
        if symbol not in self.kline_windows:
            return self._empty_analysis()
        
        klines = self.kline_windows[symbol]
        
        # v2.200: 放宽要求，只要有数据就分析
        if len(klines) < 1:
            return self._empty_analysis()
        
        # 使用实际可用的数据
        actual_size = min(len(klines), window_size)
        recent_klines = klines[-actual_size:]
        
        print(f"[L2-10m] {symbol} 窗口分析: {actual_size}/{window_size} 根")
        
        # 1. 窗口趋势分析
        window_trend = self._analyze_window_trend(recent_klines)
        
        # 2. 窗口PA信号
        window_pa = self._analyze_window_pa(recent_klines)
        
        # 3. 窗口成交量状态
        window_volume = self._analyze_window_volume(recent_klines)
        
        # 4. 假突破/假跌破（基于全部历史）
        all_closes = [k["close"] for k in klines]
        all_highs = [k["high"] for k in klines]
        all_lows = [k["low"] for k in klines]
        all_volumes = [k["volume"] for k in klines]
        fake_break = self._detect_fake_break(all_closes, all_highs, all_lows, all_volumes)
        
        # 5. 暴跌预警
        crash_alert = self._detect_crash(symbol, all_closes)
        
        # 6. 综合置信度
        confidence = self._compute_confidence(
            window_trend, window_pa, window_volume, fake_break
        )
        
        # v2.200: 根据实际数据量调整基础置信度
        actual_size = len(recent_klines)
        if actual_size >= window_size:
            base_confidence = "HIGH"  # 完整数据
        elif actual_size >= 2:
            base_confidence = "MEDIUM"  # 部分数据
        else:
            base_confidence = "LOW"  # 仅1根数据
        
        # 综合原有置信度和数据质量
        if confidence == "HIGH" and base_confidence != "HIGH":
            confidence = "MEDIUM"  # 降级
        elif confidence == "MEDIUM" and base_confidence == "LOW":
            confidence = "LOW"  # 降级
        
        return {
            "window_trend": window_trend,
            "window_pa_signal": window_pa,
            "window_volume_state": window_volume,
            "fake_break_tag": fake_break["tag"],
            "fake_break_signal": fake_break["signal"],
            "fake_break_confidence": fake_break["confidence"],
            "fake_break_details": fake_break.get("details", {}),
            "crash_alert": crash_alert,
            "confidence": confidence,
            "window_size": actual_size,  # v2.200: 实际使用的数据量
            "required_size": window_size,  # v2.200: 要求的数据量
            "total_bars": len(klines),
            "data_quality": base_confidence,  # v2.200: 数据质量
            "has_data": True
        }
    

    
    def analyze(self, symbol: str) -> dict:
        """
        兼容旧版analyze()方法（向后兼容）
        
        直接调用analyze_window()使用默认窗口大小
        
        Args:
            symbol: 交易对
        
        Returns:
            窗口分析结果
        """
        return self.analyze_window(symbol, window_size=3)
    
    def _empty_analysis(self) -> dict:
        """空分析结果"""
        return {
            "window_trend": "NEUTRAL",
            "window_pa_signal": "NONE",
            "window_volume_state": "NORMAL",
            "fake_break_tag": "NONE",
            "fake_break_signal": "NONE",
            "fake_break_confidence": "LOW",
            "crash_alert": {"crash_level": "NONE"},
            "confidence": "LOW",
            "has_data": False
        }
    
    def _analyze_window_trend(self, klines: list) -> str:
        """
        分析窗口内趋势
        
        Returns:
            BULLISH: 上升趋势
            BEARISH: 下降趋势
            NEUTRAL: 中性/震荡
        """
        if len(klines) < 2:
            return "NEUTRAL"
        
        first_close = klines[0]["close"]
        last_close = klines[-1]["close"]
        
        price_change = (last_close - first_close) / first_close
        
        highs = [k["high"] for k in klines]
        lows = [k["low"] for k in klines]
        
        # Higher High, Higher Low
        if highs[-1] > highs[0] and lows[-1] > lows[0]:
            return "BULLISH"
        
        # Lower High, Lower Low
        elif highs[-1] < highs[0] and lows[-1] < lows[0]:
            return "BEARISH"
        
        # 价格变化显著
        threshold = self.config["window_analysis"]["trend_threshold"]
        if price_change > threshold:
            return "BULLISH"
        elif price_change < -threshold:
            return "BEARISH"
        
        return "NEUTRAL"
    
    def _analyze_window_pa(self, klines: list) -> str:
        """
        分析窗口内PA结构
        
        Returns:
            BULL_HAMMER: 锤子线（底部反转）
            BEAR_SHOOTING_STAR: 射击之星（顶部反转）
            BULL_ENGULF: 看涨吞没
            BEAR_ENGULF: 看跌吞没
            BULL_CONTINUATION: 多头延续
            BEAR_CONTINUATION: 空头延续
            NONE: 无明显形态
        """
        if len(klines) < 2:
            return "NONE"
        
        last = klines[-1]
        last_body = abs(last["close"] - last["open"])
        last_range = last["high"] - last["low"]
        
        if last_range == 0:
            return "NONE"
        
        last_body_ratio = last_body / last_range
        
        # 锤子线
        lower_shadow = min(last["open"], last["close"]) - last["low"]
        if lower_shadow > last_body * 2 and last_body_ratio < 0.3:
            return "BULL_HAMMER"
        
        # 射击之星
        upper_shadow = last["high"] - max(last["open"], last["close"])
        if upper_shadow > last_body * 2 and last_body_ratio < 0.3:
            return "BEAR_SHOOTING_STAR"
        
        # 吞没形态
        if len(klines) >= 2:
            prev = klines[-2]
            prev_body = abs(prev["close"] - prev["open"])
            
            if prev["close"] < prev["open"] and last["close"] > last["open"]:
                if last_body > prev_body * 1.5:
                    return "BULL_ENGULF"
            
            if prev["close"] > prev["open"] and last["close"] < last["open"]:
                if last_body > prev_body * 1.5:
                    return "BEAR_ENGULF"
        
        # 连续阳线/阴线
        bullish_count = sum(1 for k in klines if k["close"] > k["open"])
        bearish_count = sum(1 for k in klines if k["close"] < k["open"])
        
        if bullish_count >= len(klines) - 1:
            return "BULL_CONTINUATION"
        
        if bearish_count >= len(klines) - 1:
            return "BEAR_CONTINUATION"
        
        return "NONE"
    
    def _analyze_window_volume(self, klines: list) -> str:
        """
        分析窗口内成交量状态
        
        Returns:
            EXPANDING: 逐步放量
            CLIMAX: 突然放量
            CONTRACTING: 逐步缩量
            NORMAL: 正常波动
        """
        if len(klines) < 2:
            return "NORMAL"
        
        volumes = [k["volume"] for k in klines]
        avg_vol = sum(volumes) / len(volumes)
        last_vol = volumes[-1]
        
        # 突然放量
        climax_ratio = self.config["window_analysis"]["volume_climax_ratio"]
        if last_vol > avg_vol * climax_ratio:
            return "CLIMAX"
        
        # 逐步放量
        is_expanding = all(
            volumes[i] * 0.9 <= volumes[i+1] 
            for i in range(len(volumes)-1)
        )
        if is_expanding:
            return "EXPANDING"
        
        # 缩量
        contract_ratio = self.config["window_analysis"]["volume_contract_ratio"]
        if last_vol < avg_vol * contract_ratio:
            return "CONTRACTING"
        
        return "NORMAL"
    
    def _compute_confidence(self, trend: str, pa: str, volume: str, 
                           fake_break: dict) -> str:
        """
        综合置信度计算
        
        Returns:
            HIGH: 多个信号一致
            MEDIUM: 部分信号一致
            LOW: 信号冲突或不明确
        """
        signals = []
        
        if trend == "BULLISH":
            signals.append("BULL")
        elif trend == "BEARISH":
            signals.append("BEAR")
        
        if "BULL" in pa:
            signals.append("BULL")
        elif "BEAR" in pa:
            signals.append("BEAR")
        
        if volume in ["EXPANDING", "CLIMAX"]:
            signals.append("CONFIRM")
        
        if fake_break["signal"] == "CAN_SELL":
            signals.append("BEAR")
        elif fake_break["signal"] == "CAN_BUY":
            signals.append("BULL")
        
        bull_count = signals.count("BULL")
        bear_count = signals.count("BEAR")
        confirm_count = signals.count("CONFIRM")
        
        if (bull_count >= 2 or bear_count >= 2) and confirm_count >= 1:
            return "HIGH"
        elif bull_count >= 2 or bear_count >= 2:
            return "MEDIUM"
        elif (bull_count >= 1 or bear_count >= 1) and confirm_count >= 1:
            return "MEDIUM"
        else:
            return "LOW"
    
    def _detect_fake_break(self, closes: list, highs: list, lows: list, volumes: list) -> dict:
        """检测假突破/假跌破"""
        if len(closes) < 3:
            return {"tag": "NONE", "signal": "NONE", "confidence": "LOW"}
        
        prev_highs = highs[:-1]
        prev_lows = lows[:-1]
        prev_high = max(prev_highs) if prev_highs else 0
        prev_low = min(prev_lows) if prev_lows else 0
        
        last_high = highs[-1]
        last_low = lows[-1]
        last_close = closes[-1]
        
        volume_spike = 1.0
        if volumes and len(volumes) >= 10:
            recent_vol = volumes[-1]
            avg_vol = sum(volumes[-10:-1]) / max(len(volumes[-10:-1]), 1)
            if avg_vol > 0:
                volume_spike = recent_vol / avg_vol
        
        cfg = self.config["fake_break"]
        
        # 假突破
        if last_high > prev_high * cfg["breakout_threshold"]:
            breakout_extent = last_high - prev_high
            pullback_extent = last_high - last_close
            
            if last_close < prev_high and pullback_extent >= breakout_extent * cfg["pullback_ratio"]:
                confidence = "LOW"
                if volume_spike >= cfg["volume_spike_min"]:
                    confidence = "MEDIUM"
                    if volume_spike >= 1.8:
                        confidence = "HIGH"
                
                return {
                    "tag": "FAKE_BREAKOUT",
                    "signal": "CAN_SELL",
                    "confidence": confidence,
                    "details": {
                        "prev_high": prev_high,
                        "last_high": last_high,
                        "last_close": last_close,
                        "volume_spike": volume_spike
                    }
                }
        
        # 假跌破
        if last_low < prev_low * cfg["breakdown_threshold"]:
            breakdown_extent = prev_low - last_low
            bounce_extent = last_close - last_low
            
            if last_close > prev_low and bounce_extent >= breakdown_extent * cfg["pullback_ratio"]:
                confidence = "LOW"
                if volume_spike >= cfg["volume_spike_min"]:
                    confidence = "MEDIUM"
                    if volume_spike >= 1.8:
                        confidence = "HIGH"
                
                return {
                    "tag": "FAKE_BREAKDOWN",
                    "signal": "CAN_BUY",
                    "confidence": confidence,
                    "details": {
                        "prev_low": prev_low,
                        "last_low": last_low,
                        "last_close": last_close,
                        "volume_spike": volume_spike
                    }
                }
        
        return {"tag": "NONE", "signal": "NONE", "confidence": "LOW"}
    
    def _detect_crash(self, symbol: str, closes: list) -> dict:
        """
        v2.700 FULL_ASSET_PATCH: 检测暴跌预警（全资产支持）
        
        解除品种限制，根据资产类型选择阈值：
        - STOCKS: Warn 1.5% | Crash 3% | Panic 5%
        - CRYPTO: Warn 4% | Crash 8% | Panic 12%
        """
        if len(closes) < 4:
            return {"crash_level": "NONE", "crash_reason": "insufficient_data", "asset_type": "UNKNOWN"}
        
        # v2.700: 识别资产类型并选择对应阈值
        asset_type = self._get_asset_type(symbol)
        
        if asset_type == "CRYPTO":
            cfg = self.config.get("crash_crypto", self.config["crash_us_stock"])
        else:
            cfg = self.config["crash_us_stock"]
        
        if not cfg.get("enabled", True):
            return {"crash_level": "NONE", "crash_reason": "disabled", "asset_type": asset_type}
        
        ret_3bar = (closes[-1] - closes[-4]) / max(closes[-4], 1e-8)
        
        # 确定暴跌级别
        if ret_3bar < cfg["panic_threshold"]:
            crash_level = "PANIC"
        elif ret_3bar < cfg["crash_threshold"]:
            crash_level = "CRASH"
        elif ret_3bar < cfg["warn_threshold"]:
            crash_level = "WARN"
        else:
            crash_level = "NONE"
        
        # v2.700: 详细日志
        print(f"[CRASH_CHECK] Asset: {asset_type} | Symbol: {symbol} | Level: {crash_level} | Ret: {ret_3bar:.2%}")
        
        return {
            "crash_level": crash_level,
            "crash_reason": f"10m累计跌幅{ret_3bar:.1%}" if crash_level != "NONE" else "normal",
            "ret_3bar": ret_3bar,
            "asset_type": asset_type,
            "thresholds": {
                "warn": cfg["warn_threshold"],
                "crash": cfg["crash_threshold"],
                "panic": cfg["panic_threshold"],
            }
        }
    
    # ========================================================================
    # v2.975 新增: 差异化分析方法
    # ========================================================================
    
    def _detect_surge(self, symbol: str, closes: list) -> dict:
        """
        v2.975 新增: 检测暴涨信号（与暴跌对称）
        
        根据资产类型选择阈值：
        - STOCKS: Mild 1.5% | Surge 3% | Rocket 5%
        - CRYPTO: Mild 4% | Surge 8% | Rocket 12%
        """
        if len(closes) < 4:
            return {"surge_level": "NONE", "surge_reason": "insufficient_data", "asset_type": "UNKNOWN"}
        
        asset_type = self._get_asset_type(symbol)
        
        if asset_type == "CRYPTO":
            cfg = self.config.get("surge_crypto", self.config["surge_us_stock"])
        else:
            cfg = self.config["surge_us_stock"]
        
        if not cfg.get("enabled", True):
            return {"surge_level": "NONE", "surge_reason": "disabled", "asset_type": asset_type}
        
        ret_3bar = (closes[-1] - closes[-4]) / max(closes[-4], 1e-8)
        
        # 确定暴涨级别
        if ret_3bar > cfg["rocket_threshold"]:
            surge_level = "ROCKET"
        elif ret_3bar > cfg["surge_threshold"]:
            surge_level = "SURGE"
        elif ret_3bar > cfg["mild_threshold"]:
            surge_level = "MILD"
        else:
            surge_level = "NONE"
        
        print(f"[SURGE_CHECK] Asset: {asset_type} | Symbol: {symbol} | Level: {surge_level} | Ret: {ret_3bar:.2%}")
        
        return {
            "surge_level": surge_level,
            "surge_reason": f"10m累计涨幅{ret_3bar:.1%}" if surge_level != "NONE" else "normal",
            "ret_3bar": ret_3bar,
            "asset_type": asset_type,
            "thresholds": {
                "mild": cfg["mild_threshold"],
                "surge": cfg["surge_threshold"],
                "rocket": cfg["rocket_threshold"],
            }
        }
    
    def _analyze_momentum(self, klines: list) -> dict:
        """
        v3.400 改进: 动量分析 - M3改进加入影线分析

        改进内容:
        - M3: 加入上下影线分析 (长上影阳线=上涨动量减弱)
        - 影线修正: 阳线带长上影扣分，阴线带长下影加分

        Returns:
            {
                "momentum_state": "ACCELERATING" | "DECELERATING" | "STABLE",
                "body_trend": "EXPANDING" | "CONTRACTING" | "FLAT",
                "direction_consistency": 0.0-1.0,
                "dominant_direction": "BULL" | "BEAR" | "NEUTRAL",
                "momentum_score": -2 to +2,
                "shadow_warning": str | None,  # v3.400新增
                "shadow_adjusted": bool  # v3.400新增
            }
        """
        if len(klines) < 3:
            return {
                "momentum_state": "STABLE",
                "body_trend": "FLAT",
                "direction_consistency": 0.5,
                "momentum_score": 0,
                "dominant_direction": "NEUTRAL",
                "shadow_warning": None,
                "shadow_adjusted": False
            }

        # 计算每根K线的实体大小和方向
        bodies = []
        directions = []
        momentum_adjustments = []  # v3.400: 影线修正值

        for k in klines:
            body = abs(k["close"] - k["open"])
            total_range = k["high"] - k["low"]
            bodies.append(body)

            # v3.400 M3: 计算影线
            upper_shadow = k["high"] - max(k["open"], k["close"])
            lower_shadow = min(k["open"], k["close"]) - k["low"]

            is_bull = k["close"] > k["open"]

            if k["close"] > k["open"] * 1.001:
                directions.append(1)   # 阳线
            elif k["close"] < k["open"] * 0.999:
                directions.append(-1)  # 阴线
            else:
                directions.append(0)   # 十字

            # v3.400 M3: 影线修正计算
            adjustment = 0
            if total_range > 0:
                upper_ratio = upper_shadow / total_range
                lower_ratio = lower_shadow / total_range

                # 阳线带长上影 = 上涨动量受阻
                if is_bull and upper_ratio > 0.5:
                    adjustment = -0.5  # 扣分

                # 阴线带长下影 = 下跌动量受阻
                if not is_bull and lower_ratio > 0.5:
                    adjustment = +0.5  # 加分

            momentum_adjustments.append(adjustment)

        # 判断实体趋势
        n = len(bodies)
        if n >= 3:
            recent_avg = sum(bodies[-2:]) / 2
            earlier_avg = sum(bodies[:-2]) / max(n - 2, 1)

            if earlier_avg > 0:
                ratio = recent_avg / earlier_avg
                if ratio > 1.3:
                    body_trend = "EXPANDING"
                elif ratio < 0.7:
                    body_trend = "CONTRACTING"
                else:
                    body_trend = "FLAT"
            else:
                body_trend = "FLAT"
        else:
            body_trend = "FLAT"

        # 方向一致性
        bull_count = sum(1 for d in directions if d > 0)
        bear_count = sum(1 for d in directions if d < 0)
        dominant = max(bull_count, bear_count)
        direction_consistency = dominant / len(directions) if directions else 0.5

        # 主导方向
        if bull_count > bear_count:
            dominant_direction = "BULL"
        elif bear_count > bull_count:
            dominant_direction = "BEAR"
        else:
            dominant_direction = "NEUTRAL"

        # 综合判断
        if body_trend == "EXPANDING" and direction_consistency >= 0.7:
            momentum_state = "ACCELERATING"
            momentum_score = +2 if dominant_direction == "BULL" else -2
        elif body_trend == "CONTRACTING":
            momentum_state = "DECELERATING"
            momentum_score = 0
        else:
            momentum_state = "STABLE"
            momentum_score = 0

        # v3.400 M3: 影线修正
        shadow_warning = None
        shadow_adjusted = False

        # 计算最近几根K线的影线修正总和
        recent_adjustments = momentum_adjustments[-3:] if len(momentum_adjustments) >= 3 else momentum_adjustments
        total_adjustment = sum(recent_adjustments)

        # 影线警告检测
        if dominant_direction == "BULL" and total_adjustment < -1.0:
            shadow_warning = "BULL_UPPER_SHADOW_WARNING"
            shadow_adjusted = True
            # 连续阳线带长上影，动量减弱信号
            if momentum_state == "ACCELERATING":
                momentum_state = "STABLE"
                momentum_score = max(momentum_score - 1, 0)

        elif dominant_direction == "BEAR" and total_adjustment > 1.0:
            shadow_warning = "BEAR_LOWER_SHADOW_WARNING"
            shadow_adjusted = True
            # 连续阴线带长下影，动量减弱信号
            if momentum_state == "ACCELERATING":
                momentum_state = "STABLE"
                momentum_score = min(momentum_score + 1, 0)

        return {
            "momentum_state": momentum_state,
            "body_trend": body_trend,
            "direction_consistency": round(direction_consistency, 2),
            "momentum_score": momentum_score,
            "dominant_direction": dominant_direction,
            "shadow_warning": shadow_warning,
            "shadow_adjusted": shadow_adjusted
        }
    
    def _analyze_path(self, klines: list) -> dict:
        """
        v3.400 改进: 走势路径分析 - M1+M4改进

        改进内容:
        - M1: 用真实High/Low找极值点，而非Close
        - M4: 加入量能确认 (V底反弹放量/倒V顶下跌放量)

        Returns:
            {
                "path_type": "V_BOTTOM" | "INVERTED_V_TOP" | "ONE_SIDE_UP" | "ONE_SIDE_DOWN" | "CHOPPY",
                "path_strength": "STRONG" | "WEAK",
                "turning_point_idx": int | None,
                "path_score": -2 to +2,
                "vol_confirmed": bool  # v3.400新增
            }
        """
        if len(klines) < 3:
            return {
                "path_type": "CHOPPY",
                "path_strength": "WEAK",
                "turning_point_idx": None,
                "path_score": 0,
                "vol_confirmed": False
            }

        # v3.400 M1改进: 提取完整OHLCV
        closes = [k["close"] for k in klines]
        highs = [k["high"] for k in klines]
        lows = [k["low"] for k in klines]
        volumes = [k.get("volume", 0) for k in klines]
        n = len(closes)

        first_close = closes[0]
        last_close = closes[-1]

        # v3.400 M1: 用真实High/Low找极值点
        max_high = max(highs)
        min_low = min(lows)
        max_high_idx = highs.index(max_high)
        min_low_idx = lows.index(min_low)

        total_change = (last_close - first_close) / first_close if first_close > 0 else 0

        # 计算平均成交量
        avg_vol = sum(volumes) / len(volumes) if volumes else 1

        # ═══════════════════════════════════════════════════════════════════════
        # V型底: 最低点在中间，先跌后涨，收盘高于开盘
        # v3.400: 用真实Low找底，加入量能确认
        # ═══════════════════════════════════════════════════════════════════════
        if 0 < min_low_idx < n - 1:
            drop = (min_low - first_close) / first_close if first_close > 0 else 0
            rise = (last_close - min_low) / min_low if min_low > 0 else 0

            if drop < -0.003 and rise > 0.003 and last_close > first_close:
                # v3.400 M4: 量能确认 - 反弹段应该放量
                rise_volumes = volumes[min_low_idx:] if min_low_idx < len(volumes) else []
                pre_volumes = volumes[:min_low_idx] if min_low_idx > 0 else [avg_vol]

                rise_avg_vol = sum(rise_volumes) / len(rise_volumes) if rise_volumes else 0
                pre_avg_vol = sum(pre_volumes) / len(pre_volumes) if pre_volumes else 1

                vol_confirmed = rise_avg_vol > pre_avg_vol * 1.2  # 反弹放量20%以上

                # 基础强度判断
                base_strength = "STRONG" if rise > abs(drop) * 0.7 else "WEAK"

                # 量能加成
                if vol_confirmed and base_strength == "WEAK":
                    base_strength = "STRONG"  # 放量可提升强度

                return {
                    "path_type": "V_BOTTOM",
                    "path_strength": base_strength,
                    "turning_point_idx": min_low_idx,
                    "path_score": +2 if base_strength == "STRONG" else +1,
                    "vol_confirmed": vol_confirmed,
                    "min_low": min_low,
                    "rise_vol_ratio": round(rise_avg_vol / pre_avg_vol, 2) if pre_avg_vol > 0 else 1
                }

        # ═══════════════════════════════════════════════════════════════════════
        # 倒V型顶: 最高点在中间，先涨后跌，收盘低于开盘
        # v3.400: 用真实High找顶，加入量能确认
        # ═══════════════════════════════════════════════════════════════════════
        if 0 < max_high_idx < n - 1:
            rise = (max_high - first_close) / first_close if first_close > 0 else 0
            drop = (last_close - max_high) / max_high if max_high > 0 else 0

            if rise > 0.003 and drop < -0.003 and last_close < first_close:
                # v3.400 M4: 量能确认 - 下跌段应该放量(恐慌抛售)
                drop_volumes = volumes[max_high_idx:] if max_high_idx < len(volumes) else []
                pre_volumes = volumes[:max_high_idx] if max_high_idx > 0 else [avg_vol]

                drop_avg_vol = sum(drop_volumes) / len(drop_volumes) if drop_volumes else 0
                pre_avg_vol = sum(pre_volumes) / len(pre_volumes) if pre_volumes else 1

                vol_confirmed = drop_avg_vol > pre_avg_vol * 1.2  # 下跌放量20%以上

                base_strength = "STRONG" if abs(drop) > rise * 0.7 else "WEAK"

                if vol_confirmed and base_strength == "WEAK":
                    base_strength = "STRONG"

                return {
                    "path_type": "INVERTED_V_TOP",
                    "path_strength": base_strength,
                    "turning_point_idx": max_high_idx,
                    "path_score": -2 if base_strength == "STRONG" else -1,
                    "vol_confirmed": vol_confirmed,
                    "max_high": max_high,
                    "drop_vol_ratio": round(drop_avg_vol / pre_avg_vol, 2) if pre_avg_vol > 0 else 1
                }

        # 单边上涨: 最高点在末尾附近
        if max_high_idx >= n - 2 and total_change > 0.005:
            return {
                "path_type": "ONE_SIDE_UP",
                "path_strength": "STRONG" if total_change > 0.01 else "WEAK",
                "turning_point_idx": None,
                "path_score": +1,
                "vol_confirmed": False
            }

        # 单边下跌: 最低点在末尾附近
        if min_low_idx >= n - 2 and total_change < -0.005:
            return {
                "path_type": "ONE_SIDE_DOWN",
                "path_strength": "STRONG" if total_change < -0.01 else "WEAK",
                "turning_point_idx": None,
                "path_score": -1,
                "vol_confirmed": False
            }

        # 震荡
        return {
            "path_type": "CHOPPY",
            "path_strength": "WEAK",
            "turning_point_idx": None,
            "path_score": 0,
            "vol_confirmed": False  # v3.400: 保持返回格式一致
        }

    def _detect_micro_structure(self, klines: list) -> dict:
        """
        v3.400 改进: 微结构检测 - M2改进加入量能验证+射击之星检测

        改进内容:
        - M2: 加入量能验证 (顶部放量+射击之星=高确信)
        - 新增: 射击之星/锤子线检测
        - 综合评分: 量能+K线形态

        Returns:
            {
                "micro_pattern": "MICRO_TOP" | "MICRO_BOTTOM" | "MICRO_2B_TOP" | "MICRO_2B_BOTTOM" | "NONE",
                "pattern_confidence": "HIGH" | "MEDIUM" | "LOW",
                "pattern_price": float | None,
                "micro_score": -3 to +3,  # v3.400: 扩展范围
                "vol_ratio": float,  # v3.400新增
                "candle_type": str  # v3.400新增: SHOOTING_STAR/HAMMER/NORMAL
            }
        """
        if len(klines) < 4:
            return {
                "micro_pattern": "NONE",
                "pattern_confidence": "LOW",
                "pattern_price": None,
                "micro_score": 0,
                "vol_ratio": 1.0,
                "candle_type": "NORMAL"
            }

        # v3.400 M2: 提取完整OHLCV
        opens = [k["open"] for k in klines]
        highs = [k["high"] for k in klines]
        lows = [k["low"] for k in klines]
        closes = [k["close"] for k in klines]
        volumes = [k.get("volume", 0) for k in klines]
        n = len(klines)

        avg_vol = sum(volumes) / len(volumes) if volumes else 1

        # ═══════════════════════════════════════════════════════════════════════
        # 微顶检测 + 量能验证 + 射击之星
        # ═══════════════════════════════════════════════════════════════════════
        for i in range(1, n - 1):
            # 局部最高点
            if highs[i] >= highs[i-1] and highs[i] >= highs[i+1]:
                # 检查后续是否回落
                if closes[-1] < highs[i] * 0.995:
                    # v3.400 M2: 量能验证
                    vol_ratio = volumes[i] / avg_vol if avg_vol > 0 else 1.0

                    # v3.400: 射击之星检测 (上影线>2倍实体)
                    k = klines[i]
                    body = abs(k["close"] - k["open"])
                    upper_shadow = k["high"] - max(k["open"], k["close"])
                    lower_shadow = min(k["open"], k["close"]) - k["low"]
                    total_range = k["high"] - k["low"]

                    is_shooting_star = (
                        total_range > 0 and
                        upper_shadow > body * 2 and
                        lower_shadow < body * 0.5
                    )

                    candle_type = "SHOOTING_STAR" if is_shooting_star else "NORMAL"

                    # 检查是否是2B顶 (突破前高后回落)
                    prev_high = max(highs[:i]) if i > 0 else highs[i]
                    if highs[i] > prev_high * 1.001 and closes[-1] < prev_high:
                        # 2B顶基础分数
                        base_score = -2

                        # 量能加成
                        if vol_ratio > 1.5:
                            base_score -= 1  # 放量2B顶更可靠

                        # 射击之星加成
                        if is_shooting_star:
                            base_score -= 0.5

                        confidence = "HIGH"
                        if vol_ratio > 1.3 and is_shooting_star:
                            confidence = "VERY_HIGH"

                        return {
                            "micro_pattern": "MICRO_2B_TOP",
                            "pattern_confidence": confidence,
                            "pattern_price": highs[i],
                            "micro_score": int(max(base_score, -3)),
                            "vol_ratio": round(vol_ratio, 2),
                            "candle_type": candle_type
                        }
                    else:
                        # 普通微顶
                        base_score = -1

                        if vol_ratio > 1.3:
                            base_score -= 0.5
                        if is_shooting_star:
                            base_score -= 0.5

                        confidence = "MEDIUM"
                        if vol_ratio > 1.3 or is_shooting_star:
                            confidence = "HIGH"

                        return {
                            "micro_pattern": "MICRO_TOP",
                            "pattern_confidence": confidence,
                            "pattern_price": highs[i],
                            "micro_score": int(max(base_score, -2)),
                            "vol_ratio": round(vol_ratio, 2),
                            "candle_type": candle_type
                        }

        # ═══════════════════════════════════════════════════════════════════════
        # 微底检测 + 量能验证 + 锤子线
        # ═══════════════════════════════════════════════════════════════════════
        for i in range(1, n - 1):
            # 局部最低点
            if lows[i] <= lows[i-1] and lows[i] <= lows[i+1]:
                # 检查后续是否反弹
                if closes[-1] > lows[i] * 1.005:
                    # v3.400 M2: 量能验证
                    vol_ratio = volumes[i] / avg_vol if avg_vol > 0 else 1.0

                    # v3.400: 锤子线检测 (下影线>2倍实体)
                    k = klines[i]
                    body = abs(k["close"] - k["open"])
                    upper_shadow = k["high"] - max(k["open"], k["close"])
                    lower_shadow = min(k["open"], k["close"]) - k["low"]
                    total_range = k["high"] - k["low"]

                    is_hammer = (
                        total_range > 0 and
                        lower_shadow > body * 2 and
                        upper_shadow < body * 0.5
                    )

                    candle_type = "HAMMER" if is_hammer else "NORMAL"

                    # 检查是否是2B底 (跌破前低后反弹)
                    prev_low = min(lows[:i]) if i > 0 else lows[i]
                    if lows[i] < prev_low * 0.999 and closes[-1] > prev_low:
                        base_score = +2

                        if vol_ratio > 1.5:
                            base_score += 1  # 放量2B底更可靠

                        if is_hammer:
                            base_score += 0.5

                        confidence = "HIGH"
                        if vol_ratio > 1.3 and is_hammer:
                            confidence = "VERY_HIGH"

                        return {
                            "micro_pattern": "MICRO_2B_BOTTOM",
                            "pattern_confidence": confidence,
                            "pattern_price": lows[i],
                            "micro_score": int(min(base_score, 3)),
                            "vol_ratio": round(vol_ratio, 2),
                            "candle_type": candle_type
                        }
                    else:
                        base_score = +1

                        if vol_ratio > 1.3:
                            base_score += 0.5
                        if is_hammer:
                            base_score += 0.5

                        confidence = "MEDIUM"
                        if vol_ratio > 1.3 or is_hammer:
                            confidence = "HIGH"

                        return {
                            "micro_pattern": "MICRO_BOTTOM",
                            "pattern_confidence": confidence,
                            "pattern_price": lows[i],
                            "micro_score": int(min(base_score, 2)),
                            "vol_ratio": round(vol_ratio, 2),
                            "candle_type": candle_type
                        }

        return {
            "micro_pattern": "NONE",
            "pattern_confidence": "LOW",
            "pattern_price": None,
            "micro_score": 0,
            "vol_ratio": 1.0,
            "candle_type": "NORMAL"
        }
    
    def _analyze_volume_timing(self, klines: list) -> dict:
        """
        v2.975 新增: 成交量时机分析 - 放量在涨还是跌
        
        Returns:
            {
                "volume_timing": "VOLUME_ON_RISE" | "VOLUME_ON_DROP" | "VOLUME_BALANCED" | "LOW_VOLUME",
                "volume_direction_score": float,  # -1到+1
                "climax_detected": bool,
                "volume_score": -2 to +2
            }
        """
        if len(klines) < 2:
            return {
                "volume_timing": "LOW_VOLUME",
                "volume_direction_score": 0,
                "climax_detected": False,
                "volume_score": 0
            }
        
        volumes = [k.get("volume", 0) for k in klines]
        avg_vol = sum(volumes) / len(volumes) if volumes else 1
        
        # 计算带方向成交量
        directional_volumes = []
        for k in klines:
            vol = k.get("volume", 0)
            if k["close"] > k["open"]:
                directional_volumes.append(vol)
            elif k["close"] < k["open"]:
                directional_volumes.append(-vol)
            else:
                directional_volumes.append(0)
        
        total_directional = sum(directional_volumes)
        total_volume = sum(volumes)
        
        # 归一化
        if total_volume > 0:
            volume_direction_score = total_directional / total_volume
        else:
            volume_direction_score = 0
        
        # 量能高潮检测
        climax_detected = volumes[-1] > avg_vol * 2.0 if volumes else False
        
        # 判断类型
        if max(volumes) < avg_vol * 0.5:
            volume_timing = "LOW_VOLUME"
            volume_score = 0
        elif volume_direction_score > 0.3:
            volume_timing = "VOLUME_ON_RISE"
            volume_score = +2 if climax_detected else +1
        elif volume_direction_score < -0.3:
            volume_timing = "VOLUME_ON_DROP"
            volume_score = -2 if climax_detected else -1
        else:
            volume_timing = "VOLUME_BALANCED"
            volume_score = 0
        
        return {
            "volume_timing": volume_timing,
            "volume_direction_score": round(volume_direction_score, 2),
            "climax_detected": climax_detected,
            "volume_score": volume_score
        }

    def _get_score_label(self, score: int) -> str:
        """
        v3.165: 将L2分数转换为语义标签
        用于日志和决策链追踪，澄清分数含义
        """
        if score >= 5:
            return "STRONG_BUY_SIGNAL"
        elif score >= 2:
            return "BUY_SIGNAL"
        elif score <= -5:
            return "STRONG_SELL_SIGNAL"
        elif score <= -2:
            return "SELL_SIGNAL"
        else:
            return "NEUTRAL_SIGNAL"

    def _bias_to_action_recommendation(self, exec_bias: str) -> str:
        """
        v3.165: 将exec_bias转换为明确的动作建议
        澄清SELL等模糊语义

        语义澄清:
        - STRONG_BUY: 强烈建议买入
        - BUY: 允许买入(非强制)
        - SELL: 允许卖出(非强制) - 注意: 这不是"卖出信号",而是"如果有其他卖出理由,可以执行"
        - STRONG_SELL: 强烈建议卖出
        - HOLD: 强制持有,禁止任何交易
        """
        mapping = {
            "STRONG_BUY": "RECOMMEND_BUY",
            "BUY": "PERMIT_BUY",
            "SELL": "PERMIT_SELL",  # 允许卖出,不是建议卖出
            "STRONG_SELL": "RECOMMEND_SELL",
            "HOLD": "PROHIBIT_TRADE",
        }
        return mapping.get(exec_bias, "UNKNOWN")

    def apply_corrections_to_l2(self, symbol: str, base_exec_bias: str,
                                l1_action: str, position_units: int = 0,
                                main_cycle_minutes: int = 30,
                                l2_score: int = 0,
                                market_regime: dict = None,
                                trend_state: str = "SIDE") -> tuple:
        """
        v2.975 重写: 应用10m窗口分析修正L2 exec_bias
        v3.165: 新增一致性保护规则
        v3.220: 新增规则D大周期趋势保护(顺大逆小)

        核心改进:
        1. 新增4个差异化分析: 动量/路径/微结构/成交量时机
        2. 综合10m分数: -8 到 +8
        3. 高分(≥6/-6)直接覆盖大周期决策
        4. 增强激活能力: 暴涨/微2B/V型底可激活买入
        5. [v3.165] 一致性保护规则A/B/C
        6. [v3.220] 规则D: 大周期趋势保护(顺大逆小)

        Args:
            symbol: 交易对
            base_exec_bias: L2原始判断
            l1_action: L1方向
            position_units: 当前持仓
            main_cycle_minutes: 主周期长度（分钟）
            l2_score: L2大周期分数 (v3.165新增)
            market_regime: 市场状态字典 (v3.165新增)
            trend_state: 大周期趋势状态 (v3.220新增) STRONG_UP/UP/SIDE/DOWN/STRONG_DOWN

        Returns:
            (final_exec_bias, correction_log)
        """
        # v2.095: 强制确保main_cycle_minutes是整数
        try:
            main_cycle_minutes = int(main_cycle_minutes)
        except Exception as e:
            print(f"[L2错误] main_cycle_minutes类型转换失败: {main_cycle_minutes}, 使用30")
            main_cycle_minutes = 30

        # ============== v3.165: 一致性保护规则 ==============
        # 规则A: score→action必须单调 (score≥5保持买入倾向，score≤-5保持卖出倾向)
        # 规则B: 外挂覆盖优先级明确 (在调用点处理)
        # 规则C: L1=HOLD + TRENDING + UP → 禁止触发SELL

        # 解析market_regime
        regime = market_regime.get("regime", "UNKNOWN") if market_regime else "UNKNOWN"
        direction = market_regime.get("direction", "SIDE") if market_regime else "SIDE"

        # 一致性保护标志
        consistency_protection = {
            "rule_a_active": False,  # score→action单调保护
            "rule_c_active": False,  # L1+TRENDING+UP保护
            "rule_d_active": False,  # v3.220: 大周期趋势保护(顺大逆小)
            "original_l2_score": l2_score,
            "score_label": self._get_score_label(l2_score),  # 分数语义标签
            "trend_state": trend_state,  # v3.220: 记录大周期趋势状态
        }

        # 规则A: 高分保护 (score≥5不能变成SELL相关)
        if l2_score >= 5:
            consistency_protection["rule_a_active"] = True
            consistency_protection["rule_a_protection"] = "PROHIBIT_SELL"
            print(f"[v3.165] 规则A激活: L2 score={l2_score}(STRONG_BUY), 禁止任何规则将结果改为SELL")
        elif l2_score <= -5:
            consistency_protection["rule_a_active"] = True
            consistency_protection["rule_a_protection"] = "PROHIBIT_BUY"
            print(f"[v3.165] 规则A激活: L2 score={l2_score}(STRONG_SELL), 禁止任何规则将结果改为BUY")

        # 规则C: L1=HOLD + TRENDING + direction=UP → 禁止SELL
        if l1_action == "HOLD" and regime == "TRENDING" and direction == "UP":
            consistency_protection["rule_c_active"] = True
            print(f"[v3.165] 规则C激活: L1=HOLD + 市场={regime}/{direction}, 禁止触发SELL")
        
        # v3.230 规则D: 大周期趋势保护(顺大逆小) — GCC-0049: 已取消拦截
        # 原逻辑: UP禁止SELL, DOWN禁止BUY
        # GCC-0049: 取消x4顺大逆小门禁, 仅观察记录
        trend_state_upper = trend_state.upper() if trend_state else "SIDE"
        if trend_state_upper in ("STRONG_UP", "UP", "STRONG_DOWN", "DOWN"):
            log_to_server(f"[GCC-0049][观察] 规则D: {symbol} trend_state={trend_state_upper} (不拦截)")
        
        # v3.230 规则E: SIDE市场冷却期
        # 当trend_state是SIDE且在冷却期内，禁止任何交易
        if trend_state_upper == "SIDE":
            can_trade, remaining_hours = check_side_market_cooldown(symbol, trend_state_upper)
            if not can_trade:
                consistency_protection["rule_e_active"] = True
                consistency_protection["rule_e_protection"] = "SIDE_COOLDOWN"
                consistency_protection["rule_e_remaining_hours"] = remaining_hours
                log_to_server(f"[v3.230] 规则E激活: {symbol} SIDE市场冷却期中, 剩余{remaining_hours:.1f}小时")
        # ============== 一致性保护规则 结束 ==============

        # v3.280: 注释掉过于频繁的调试日志
        # log_to_server(f"[v2.975] apply_corrections_to_l2 被调用")
        # log_to_server(f"[v2.975]   symbol={symbol}, base_exec_bias={base_exec_bias}, l2_score={l2_score}")
        
        # 计算窗口大小
        # v3.393: 最小4根(满足micro_structure需要4根K线)
        window_size = max(4, main_cycle_minutes // 10)
        
        # 获取K线数据
        if symbol not in self.kline_windows or len(self.kline_windows[symbol]) < 3:
            log_to_server(f"[v2.975]   ✗ K线数据不足")
            return base_exec_bias, {"applied": False, "reason": "no_10m_data"}
        
        all_klines = self.kline_windows[symbol]
        recent_klines = all_klines[-window_size:] if len(all_klines) >= window_size else all_klines
        
        # 提取数据
        all_closes = [k["close"] for k in all_klines]
        all_highs = [k["high"] for k in all_klines]
        all_lows = [k["low"] for k in all_klines]
        all_volumes = [k.get("volume", 0) for k in all_klines]
        
        # ========== v2.975: 新增4个差异化分析 ==========
        momentum = self._analyze_momentum(recent_klines)
        path = self._analyze_path(recent_klines)
        micro = self._detect_micro_structure(recent_klines)
        vol_timing = self._analyze_volume_timing(recent_klines)
        
        # ========== 保留原有检测 ==========
        crash_alert = self._detect_crash(symbol, all_closes)
        surge_alert = self._detect_surge(symbol, all_closes)  # v2.975新增
        fake_break = self._detect_fake_break(all_closes, all_highs, all_lows, all_volumes)
        
        # ========== 计算综合10m分数 ==========
        total_10m_score = (
            momentum["momentum_score"] +
            path["path_score"] +
            micro["micro_score"] +
            vol_timing["volume_score"]
        )
        
        crash_level = crash_alert.get("crash_level", "NONE")
        surge_level = surge_alert.get("surge_level", "NONE")
        fake_signal = fake_break.get("signal", "NONE")
        fake_conf = fake_break.get("confidence", "LOW")
        
        final_bias = base_exec_bias
        modifications = []
        
        log_to_server(f"[v2.975]   10m综合分数: {total_10m_score} (动量{momentum['momentum_score']} + 路径{path['path_score']} + 微结构{micro['micro_score']} + 成交量{vol_timing['volume_score']})")
        
        # ========== 优先级1: 暴跌预警 (v3.392屏蔽 - P0扫描引擎已覆盖此功能) ==========
        # if crash_level in ["CRASH", "PANIC"]:
        #     if final_bias in ["STRONG_BUY", "BUY"]:
        #         final_bias = "HOLD"
        #         modifications.append({
        #             "type": "P1_crash_alert",
        #             "level": crash_level,
        #             "action": f"暴跌{crash_level}阻止买入 → HOLD"
        #         })
        #         log_to_server(f"[v2.975] P1 暴跌{crash_level}，阻止买入")

        # ========== 优先级2: 暴涨处理 (v3.392屏蔽 - P0扫描引擎已覆盖此功能) ==========
        # elif surge_level in ["SURGE", "ROCKET"]:
        #     # v3.200: 激活买入逻辑受开关控制
        #     if L2_10M_ACTIVE_TRADING and final_bias == "HOLD":
        #         final_bias = "BUY"
        #         modifications.append({
        #             "type": "P2_surge_alert",
        #             "level": surge_level,
        #             "action": f"暴涨{surge_level}激活买入 HOLD → BUY"
        #         })
        #         log_to_server(f"[v2.975] P2 暴涨{surge_level}，激活买入")
        #     # 阻止卖出逻辑保留（这是过滤功能）
        #     elif final_bias in ["SELL", "STRONG_SELL"]:
        #         final_bias = "HOLD"
        #         modifications.append({
        #             "type": "P2_surge_alert",
        #             "level": surge_level,
        #             "action": f"暴涨{surge_level}阻止卖出 → HOLD"
        #         })
        #         log_to_server(f"[v2.975] P2 暴涨{surge_level}，阻止卖出")
        
        # ========== 优先级3: 微结构2B (v2.975新增, v3.200调整) ==========
        if micro["micro_pattern"] == "MICRO_2B_TOP" and micro["pattern_confidence"] == "HIGH":
            # 阻止买入逻辑保留
            if final_bias in ["STRONG_BUY", "BUY"]:
                final_bias = "HOLD"
                modifications.append({
                    "type": "P3_micro_2b_top",
                    "action": f"微2B顶阻止买入 → HOLD"
                })
                log_to_server(f"[v2.975] P3 微2B顶，阻止买入")
            # v3.200: 激活卖出逻辑受开关控制
            elif L2_10M_ACTIVE_TRADING and final_bias == "HOLD" and position_units > 0:
                final_bias = "SELL"
                modifications.append({
                    "type": "P3_micro_2b_top",
                    "action": f"微2B顶+持仓激活卖出 HOLD → SELL"
                })
                log_to_server(f"[v2.975] P3 微2B顶+持仓，激活卖出")

        # v3.200: 微2B底激活买入逻辑受开关控制
        elif L2_10M_ACTIVE_TRADING and micro["micro_pattern"] == "MICRO_2B_BOTTOM" and micro["pattern_confidence"] == "HIGH":
            if final_bias == "HOLD":
                final_bias = "BUY"
                modifications.append({
                    "type": "P3_micro_2b_bottom",
                    "action": f"微2B底激活买入 HOLD → BUY"
                })
                log_to_server(f"[v2.975] P3 微2B底，激活买入")
        
        # ========== 优先级4: 假突破/假跌破 (v3.200调整) ==========
        if fake_signal == "CAN_SELL" and fake_conf in ["HIGH", "MEDIUM"]:
            # 假突破阻止买入 - 核心功能保留
            if final_bias in ["STRONG_BUY", "BUY"]:
                final_bias = "HOLD"
                modifications.append({
                    "type": "P4_fake_breakout",
                    "confidence": fake_conf,
                    "action": f"假突破{fake_conf}阻止买入 → HOLD"
                })
                log_to_server(f"[v2.975] P4 假突破，阻止买入")
            # v3.200: 假突破+持仓激活卖出逻辑受开关控制
            elif L2_10M_ACTIVE_TRADING and final_bias == "HOLD" and position_units > 0:
                final_bias = "SELL"
                modifications.append({
                    "type": "P4_fake_breakout_sell",
                    "confidence": fake_conf,
                    "action": f"假突破{fake_conf}+持仓激活卖出 HOLD → SELL"
                })
                log_to_server(f"[v2.975] P4 假突破+持仓，激活卖出")

        # v3.200: 假跌破激活买入逻辑受开关控制
        elif L2_10M_ACTIVE_TRADING and fake_signal == "CAN_BUY" and fake_conf in ["HIGH", "MEDIUM"]:
            if final_bias == "HOLD":
                final_bias = "BUY"
                modifications.append({
                    "type": "P4_fake_breakdown",
                    "confidence": fake_conf,
                    "action": f"假跌破{fake_conf}激活买入 HOLD → BUY"
                })
                log_to_server(f"[v2.975] P4 假跌破，激活买入")
        
        # ========== 优先级5: 走势路径 (v2.975新增, v3.200调整) ==========
        # v3.200: V型底激活/增强买入逻辑受开关控制
        if L2_10M_ACTIVE_TRADING and path["path_type"] == "V_BOTTOM" and path["path_strength"] == "STRONG":
            if final_bias == "HOLD":
                final_bias = "BUY"
                modifications.append({
                    "type": "P5_v_bottom",
                    "action": f"V型底激活买入 HOLD → BUY"
                })
                log_to_server(f"[v2.975] P5 强V型底，激活买入")
            elif final_bias == "BUY":
                final_bias = "STRONG_BUY"
                modifications.append({
                    "type": "P5_v_bottom",
                    "action": f"V型底增强买入 BUY → STRONG_BUY"
                })
                log_to_server(f"[v2.975] P5 强V型底，增强买入")

        elif path["path_type"] == "INVERTED_V_TOP" and path["path_strength"] == "STRONG":
            # 倒V顶阻止买入 - 保留
            if final_bias in ["STRONG_BUY", "BUY"]:
                final_bias = "HOLD"
                modifications.append({
                    "type": "P5_inverted_v_top",
                    "action": f"倒V顶阻止买入 → HOLD"
                })
                log_to_server(f"[v2.975] P5 强倒V顶，阻止买入")
            # v3.200: 倒V顶+持仓激活卖出逻辑受开关控制
            elif L2_10M_ACTIVE_TRADING and final_bias == "HOLD" and position_units > 0:
                final_bias = "SELL"
                modifications.append({
                    "type": "P5_inverted_v_top",
                    "action": f"倒V顶+持仓激活卖出 HOLD → SELL"
                })
                log_to_server(f"[v2.975] P5 强倒V顶+持仓，激活卖出")
        
        # ========== 优先级6: 动量加速/减速 (v2.975新增, v3.200调整) ==========
        # v3.200: 动量加速增强逻辑受开关控制
        if L2_10M_ACTIVE_TRADING and momentum["momentum_state"] == "ACCELERATING":
            if momentum["dominant_direction"] == "BULL" and final_bias == "BUY":
                final_bias = "STRONG_BUY"
                modifications.append({
                    "type": "P6_momentum_bull_accel",
                    "action": f"多头加速增强 BUY → STRONG_BUY"
                })
                log_to_server(f"[v2.975] P6 多头加速，增强买入")
            elif momentum["dominant_direction"] == "BEAR" and final_bias == "SELL":
                final_bias = "STRONG_SELL"
                modifications.append({
                    "type": "P6_momentum_bear_accel",
                    "action": f"空头加速增强 SELL → STRONG_SELL"
                })
                log_to_server(f"[v2.975] P6 空头加速，增强卖出")

        # 动量减速降级 - 保留（只是降级信号强度，不是主动触发）
        # v3.391: 保护STRONG级别信号 - 当L2大周期得分达到STRONG级别时不降级
        # v3.499: STRONG阈值从±6调整为±8
        # 原因: 降级后L1=HOLD可以否决，导致有效信号被错误拦截
        elif momentum["momentum_state"] == "DECELERATING":
            if final_bias == "STRONG_BUY":
                # v3.499: 只有大周期得分<8时才降级，>=8说明是真正的STRONG信号
                if l2_score < 8:
                    final_bias = "BUY"
                    modifications.append({
                        "type": "P6_momentum_decel",
                        "action": f"动量减速降级 STRONG_BUY → BUY (l2_score={l2_score}<8)"
                    })
                    log_to_server(f"[v2.975] P6 动量减速，降级买入 (l2_score={l2_score}<8)")
                else:
                    print(f"[v3.391] P6 动量减速但保护STRONG_BUY (l2_score={l2_score}>=8)")
            elif final_bias == "STRONG_SELL":
                # v3.499: 只有大周期得分>-8时才降级，<=-8说明是真正的STRONG信号
                if l2_score > -8:
                    final_bias = "SELL"
                    modifications.append({
                        "type": "P6_momentum_decel",
                        "action": f"动量减速降级 STRONG_SELL → SELL (l2_score={l2_score}>-8)"
                    })
                    log_to_server(f"[v2.975] P6 动量减速，降级卖出 (l2_score={l2_score}>-8)")
                else:
                    print(f"[v3.391] P6 动量减速但保护STRONG_SELL (l2_score={l2_score}<=-8)")

        # ========== 优先级7: 成交量时机 (v2.975新增, v3.200调整) ==========
        # v3.200: 放量上涨增强逻辑受开关控制
        if L2_10M_ACTIVE_TRADING and vol_timing["volume_timing"] == "VOLUME_ON_RISE" and vol_timing["climax_detected"]:
            if final_bias == "BUY":
                final_bias = "STRONG_BUY"
                modifications.append({
                    "type": "P7_volume_climax_rise",
                    "action": f"放量上涨增强 BUY → STRONG_BUY"
                })
                log_to_server(f"[v2.975] P7 放量上涨，增强买入")

        # 放量下跌阻止买入 - 保留
        elif vol_timing["volume_timing"] == "VOLUME_ON_DROP" and vol_timing["climax_detected"]:
            if final_bias in ["STRONG_BUY", "BUY"]:
                final_bias = "HOLD"
                modifications.append({
                    "type": "P7_volume_climax_drop",
                    "action": f"放量下跌阻止买入 → HOLD"
                })
                log_to_server(f"[v2.975] P7 放量下跌，阻止买入")
        
        # ========== 优先级8: 综合分数覆盖 (v2.975新增核心) ==========
        # v3.200: 整个P8都是主动交易逻辑，受开关控制
        if L2_10M_ACTIVE_TRADING:
            if total_10m_score >= 6:
                if final_bias not in ["STRONG_BUY"]:
                    original = final_bias
                    final_bias = "STRONG_BUY"
                    modifications.append({
                        "type": "P8_score_override",
                        "score": total_10m_score,
                        "action": f"10m高分({total_10m_score})强制买入 {original} → STRONG_BUY"
                    })
                    log_to_server(f"[v2.975] P8 综合分数{total_10m_score}≥6，强制STRONG_BUY")

            elif total_10m_score <= -6:
                if final_bias not in ["STRONG_SELL"]:
                    original = final_bias
                    final_bias = "STRONG_SELL"
                    modifications.append({
                        "type": "P8_score_override",
                        "score": total_10m_score,
                        "action": f"10m低分({total_10m_score})强制卖出 {original} → STRONG_SELL"
                    })
                    log_to_server(f"[v2.975] P8 综合分数{total_10m_score}≤-6，强制STRONG_SELL")

            elif total_10m_score >= 4:
                if final_bias == "HOLD":
                    final_bias = "BUY"
                    modifications.append({
                        "type": "P8_score_activate",
                        "score": total_10m_score,
                        "action": f"10m分数({total_10m_score})激活买入 HOLD → BUY"
                    })
                    log_to_server(f"[v2.975] P8 综合分数{total_10m_score}≥4，激活买入")

            elif total_10m_score <= -4:
                if final_bias == "HOLD" and position_units > 0:
                    final_bias = "SELL"
                    modifications.append({
                        "type": "P8_score_activate",
                        "score": total_10m_score,
                        "action": f"10m分数({total_10m_score})+持仓激活卖出 HOLD → SELL"
                    })
                    log_to_server(f"[v2.975] P8 综合分数{total_10m_score}≤-4+持仓，激活卖出")
        
        # ========== 优先级9: L1一致性检查 (保留) ==========
        if l1_action == "SELL" and final_bias in ["STRONG_BUY", "BUY"]:
            original = final_bias
            final_bias = "HOLD"
            modifications.append({
                "type": "P9_l1_consistency",
                "action": f"与L1冲突 {original} → HOLD"
            })
            log_to_server(f"[v2.975] P9 与L1(SELL)冲突，阻止买入")
        
        elif l1_action == "BUY" and final_bias in ["STRONG_SELL", "SELL"]:
            if position_units <= 0:
                original = final_bias
                final_bias = "HOLD"
                modifications.append({
                    "type": "P9_l1_consistency",
                    "action": f"与L1冲突且无持仓 {original} → HOLD"
                })
                log_to_server(f"[v2.975] P9 与L1(BUY)冲突且无持仓，阻止卖出")
        
        # ============== v3.165: 一致性保护最终检查 ==============
        pre_protection_bias = final_bias
        override_applied = False
        override_reason = ""

        # 规则A: score≥5(STRONG_BUY) 禁止变成SELL相关
        if consistency_protection.get("rule_a_active") and consistency_protection.get("rule_a_protection") == "PROHIBIT_SELL":
            if final_bias in ["SELL", "STRONG_SELL"]:
                final_bias = "HOLD"  # 降级到HOLD而非保持STRONG_BUY,给予风控一定空间
                override_applied = True
                override_reason = f"规则A保护: L2 score={l2_score}(强买信号), 禁止输出{pre_protection_bias}"
                modifications.append({
                    "type": "v3165_consistency_rule_a",
                    "action": f"一致性保护 {pre_protection_bias} → {final_bias}",
                    "reason": override_reason
                })
                print(f"[v3.165] ⚠️ 一致性规则A介入: {pre_protection_bias} → {final_bias}")
                print(f"[v3.165]    原因: L2大周期score={l2_score}, 不应该输出SELL相关信号")

        # 规则A: score≤-5(STRONG_SELL) 禁止变成BUY相关
        elif consistency_protection.get("rule_a_active") and consistency_protection.get("rule_a_protection") == "PROHIBIT_BUY":
            if final_bias in ["BUY", "STRONG_BUY"]:
                final_bias = "HOLD"
                override_applied = True
                override_reason = f"规则A保护: L2 score={l2_score}(强卖信号), 禁止输出{pre_protection_bias}"
                modifications.append({
                    "type": "v3165_consistency_rule_a",
                    "action": f"一致性保护 {pre_protection_bias} → {final_bias}",
                    "reason": override_reason
                })
                print(f"[v3.165] ⚠️ 一致性规则A介入: {pre_protection_bias} → {final_bias}")
                print(f"[v3.165]    原因: L2大周期score={l2_score}, 不应该输出BUY相关信号")

        # 规则C: L1=HOLD + TRENDING + UP → 禁止SELL
        if consistency_protection.get("rule_c_active") and final_bias in ["SELL", "STRONG_SELL"]:
            final_bias = "HOLD"
            override_applied = True
            override_reason = f"规则C保护: L1=HOLD + 市场={regime}/{direction}, 禁止SELL"
            modifications.append({
                "type": "v3165_consistency_rule_c",
                "action": f"一致性保护 {pre_protection_bias} → {final_bias}",
                "reason": override_reason
            })
            print(f"[v3.165] ⚠️ 一致性规则C介入: {pre_protection_bias} → {final_bias}")
            print(f"[v3.165]    原因: L1=HOLD + 趋势市场向上, 不应该触发SELL")

        # v3.220 规则D: 大周期趋势保护(顺大逆小) — GCC-0049: 已取消
        # rule_d_active不再设置, 此段代码不会触发

        # v3.230 规则E: SIDE市场冷却期执行
        if consistency_protection.get("rule_e_active"):
            if final_bias in ["BUY", "STRONG_BUY", "SELL", "STRONG_SELL"]:
                remaining_hours = consistency_protection.get("rule_e_remaining_hours", 0)
                final_bias = "HOLD"
                override_applied = True
                override_reason = f"规则E保护: SIDE市场冷却期, 剩余{remaining_hours:.1f}小时"
                modifications.append({
                    "type": "v3230_consistency_rule_e",
                    "action": f"SIDE冷却保护 {pre_protection_bias} → {final_bias}",
                    "reason": override_reason
                })
                print(f"[v3.230] ⚠️ 一致性规则E介入: {pre_protection_bias} → {final_bias}")
                print(f"[v3.230]    原因: SIDE市场冷却期, 剩余{remaining_hours:.1f}小时, 禁止交易")
        
        # v3.230: 如果最终执行了交易，记录SIDE市场交易时间
        if final_bias in ["BUY", "STRONG_BUY", "SELL", "STRONG_SELL"]:
            trend_state_upper = trend_state.upper() if trend_state else "SIDE"
            if trend_state_upper == "SIDE":
                record_side_market_trade(symbol, trend_state_upper)

        # 更新一致性保护记录
        consistency_protection["override_applied"] = override_applied
        consistency_protection["override_reason"] = override_reason
        consistency_protection["final_bias_after_protection"] = final_bias
        # ============== 一致性保护最终检查 结束 ==============

        # ========== 构建返回日志 ==========
        correction_log = {
            "applied": True,
            "base_exec_bias": base_exec_bias,
            "final_exec_bias": final_bias,
            "modified": (final_bias != base_exec_bias),
            "modifications": modifications,
            "v2975_analysis": {
                "momentum": momentum,
                "path": path,
                "micro": micro,
                "volume_timing": vol_timing,
                "total_10m_score": total_10m_score
            },
            "10m_signals": {
                "crash": crash_level,
                "surge": surge_level,
                "fake_break": fake_signal,
                "fake_conf": fake_conf
            },
            "window_info": {
                "window_size": len(recent_klines),
                "total_bars": len(all_klines)
            },
            # v3.165: 新增一致性保护日志
            "consistency_protection": consistency_protection,
            "v3165_enhanced_log": {
                "l2_score": l2_score,
                "score_label": consistency_protection.get("score_label", "UNKNOWN"),
                "market_regime": regime,
                "market_direction": direction,
                "action_recommendation": self._bias_to_action_recommendation(final_bias),
                "override_applied": override_applied,
                "override_reason": override_reason,
            }
        }
        
        # ===== v3.401修复: 使用log_to_server确保写入日志文件 =====
        if len(modifications) > 0:
            log_to_server(f"\n{'='*70}")
            log_to_server(f"[v2.975 L2-10m 修正] {symbol}")
            log_to_server(f"{'='*70}")
            log_to_server(f"差异化分析 ({len(recent_klines)}根 10m K线):")
            log_to_server(f"  - 动量: {momentum['momentum_state']} (分数{momentum['momentum_score']})")
            log_to_server(f"  - 路径: {path['path_type']} {path['path_strength']} (分数{path['path_score']})")
            log_to_server(f"  - 微结构: {micro['micro_pattern']} (分数{micro['micro_score']})")
            log_to_server(f"  - 成交量: {vol_timing['volume_timing']} (分数{vol_timing['volume_score']})")
            log_to_server(f"  - 综合10m分数: {total_10m_score}")
            log_to_server(f"风控信号:")
            log_to_server(f"  - 暴跌: {crash_level} | 暴涨: {surge_level}")
            log_to_server(f"  - 假突破: {fake_signal} ({fake_conf})")
            log_to_server(f"修正决策:")
            log_to_server(f"  - 原始 exec_bias: {base_exec_bias}")
            log_to_server(f"  - 最终 exec_bias: {final_bias}")
            log_to_server(f"  - 修正次数: {len(modifications)}")
            log_to_server(f"修正详情:")
            for i, mod in enumerate(modifications, 1):
                log_to_server(f"  {i}. [{mod.get('type', 'unknown')}] {mod.get('action', 'N/A')}")
            log_to_server(f"{'='*70}\n")
        else:
            log_to_server(f"[v2.975] {symbol}: 10m分析完成，无需修正 (exec_bias={base_exec_bias}, 10m分数={total_10m_score})")

        return final_bias, correction_log


