from typing import Dict, List, Tuple, Optional
from enum import Enum


class ConflictType(Enum):
    """冲突类型枚举"""
    VOLUME_DIVERGENCE = "volume_divergence"
    RSI_EXTREME = "rsi_extreme"
    ZONE_RESISTANCE = "zone_resistance"
    TREND_CONFLICT = "trend_conflict"
    PA_CONFLICT = "pa_conflict"
    TWO_B_REVERSAL = "two_b_reversal"
    POSITION_EXTREME = "position_extreme"
    WYCKOFF_RISK = "wyckoff_risk"
    VOLUME_LOW = "volume_low"
    UPPER_ZONE_WEAK = "upper_zone_weak"




# ============================================================================
# v2.650: ATR Adaptive Threshold System
# Date: 2025-12-21
# ============================================================================

def calculate_volatility_adjusted_metrics(
    ohlcv_window,
    current_price: float,
    market_regime: str = "RANGE",
    regime_info: dict = None,
    atr_period: int = 14,
    baseline_atr_pct: float = 0.02,
) -> dict:
    """
    v2.650: 计算ATR自适应的动态阈值
    
    核心算法:
        ATR_pct = ATR / Current_Price
        Volatility_Multiplier = ATR_pct / Baseline_ATR_pct
        Dynamic_Supreme_Low = Clamp(5% * Vol_Mult, 2%, 10%)
        Dynamic_Supreme_High = Clamp(95% - 5% * Vol_Mult, 90%, 98%)
        Dynamic_Rhythm_Reset = Clamp(10% * Vol_Mult, 5%, 20%)
    
    Returns:
        {
            "atr": float,
            "atr_pct": float,
            "volatility_multiplier": float,
            "dynamic_supreme_low": float,
            "dynamic_supreme_high": float,
            "dynamic_rhythm_reset": float,
            "baseline_used": float,
            "regime": str,
            "regime_adjustment": dict,
            "status": str,
        }
    """
    
    # 默认返回值（ATR不可用时回退到v2.630固定值）
    default_result = {
        "atr": 0.0,
        "atr_pct": baseline_atr_pct,
        "volatility_multiplier": 1.0,
        "dynamic_supreme_low": 0.05,
        "dynamic_supreme_high": 0.95,
        "dynamic_rhythm_reset": 0.10,
        "baseline_used": baseline_atr_pct,
        "regime": market_regime,
        "regime_adjustment": {},
        "status": "ATR_NOT_AVAILABLE",
    }
    
    # 验证OHLCV窗口
    if not ohlcv_window:
        print("[VOL_ADAPTIVE] ⚠️  OHLCV窗口为空，回退到v2.630固定阈值")
        return default_result
    
    if hasattr(ohlcv_window, 'size') and ohlcv_window.size() < 15:  # v3.320修复: is_ready()要求61根,实际只需15根
        print("[VOL_ADAPTIVE] ⚠️  OHLCV窗口未就绪（<15根），回退到v2.630固定阈值")
        return default_result
    
    if hasattr(ohlcv_window, 'get_bars'):
        bars = ohlcv_window.get_bars()
    else:
        print("[VOL_ADAPTIVE] ⚠️  OHLCV窗口无get_bars方法，回退到v2.630固定阈值")
        return default_result
    
    if not bars or len(bars) < atr_period + 1:
        print(f"[VOL_ADAPTIVE] ⚠️  K线不足({len(bars) if bars else 0}<{atr_period+1})，回退到v2.630固定阈值")
        return default_result
    
    # 计算True Range序列
    tr_list = []
    for i in range(1, len(bars)):
        high = bars[i].get('high', 0)
        low = bars[i].get('low', 0)
        prev_close = bars[i-1].get('close', 0)
        
        if high == 0 or low == 0 or prev_close == 0:
            continue
        
        tr = max(high - low, abs(high - prev_close), abs(low - prev_close))
        tr_list.append(tr)
    
    if len(tr_list) < atr_period:
        print(f"[VOL_ADAPTIVE] ⚠️  有效TR数据不足({len(tr_list)}<{atr_period})，回退到v2.630固定阈值")
        return default_result
    
    # 计算ATR
    atr = sum(tr_list[-atr_period:]) / atr_period
    
    # 计算ATR百分比
    if current_price <= 0:
        print(f"[VOL_ADAPTIVE] ⚠️  价格无效({current_price})，回退到v2.630固定阈值")
        return default_result
    
    atr_pct = atr / current_price
    
    # 计算波动率乘数
    volatility_multiplier = atr_pct / baseline_atr_pct
    
    # 计算动态Supreme阈值
    dynamic_supreme_low_raw = 0.05 * volatility_multiplier
    dynamic_supreme_low = max(0.02, min(dynamic_supreme_low_raw, 0.10))
    
    gap_raw = 0.05 * volatility_multiplier
    gap_clamped = max(0.02, min(gap_raw, 0.10))
    dynamic_supreme_high = max(0.90, min(1.0 - gap_clamped, 0.98))
    
    # Regime联动调整
    regime_adjustment = {
        "applied": False,
        "regime": market_regime,
        "adjustments": []
    }
    
    if market_regime == "UPTREND_RIDE":
        original_high = dynamic_supreme_high
        current_gap = 1.0 - original_high
        adjusted_gap = current_gap * 0.80
        dynamic_supreme_high = min(1.0 - adjusted_gap, 0.98)
        
        regime_adjustment["applied"] = True
        regime_adjustment["adjustments"].append({
            "type": "UPTREND_SUPREME_HIGH_RELAX",
            "original": f"{original_high:.2%}",
            "adjusted": f"{dynamic_supreme_high:.2%}",
            "reason": "上涨趋势中放宽高位买入限制20%，避免踏空"
        })
    
    # 计算动态Rhythm重置阈值
    dynamic_rhythm_reset_raw = 0.10 * volatility_multiplier
    dynamic_rhythm_reset = max(0.05, min(dynamic_rhythm_reset_raw, 0.20))
    
    result = {
        "atr": atr,
        "atr_pct": atr_pct,
        "volatility_multiplier": volatility_multiplier,
        "dynamic_supreme_low": dynamic_supreme_low,
        "dynamic_supreme_high": dynamic_supreme_high,
        "dynamic_rhythm_reset": dynamic_rhythm_reset,
        "baseline_used": baseline_atr_pct,
        "regime": market_regime,
        "regime_adjustment": regime_adjustment,
        "status": "SUCCESS",
    }
    
    # 诊断日志
    print(f"\n{'='*80}")
    print(f"[VOL_ADAPTIVE] ✅ ATR自适应阈值计算成功")
    print(f"{'='*80}")
    print(f"ATR:          {atr:.4f}")
    print(f"ATR_pct:      {atr_pct*100:.2f}%")
    print(f"Vol_Mult:     {volatility_multiplier:.2f}x")
    print(f"-" * 80)
    print(f"Supreme_Low:  {dynamic_supreme_low*100:.1f}% (v2.630: 5.0%)")
    print(f"Supreme_High: {dynamic_supreme_high*100:.1f}% (v2.630: 95.0%)")
    print(f"Rhythm_Reset: {dynamic_rhythm_reset*100:.1f}% (v2.630: 10.0%)")
    
    if regime_adjustment["applied"]:
        print(f"-" * 80)
        print(f"Regime调整:   {market_regime}")
        for adj in regime_adjustment["adjustments"]:
            print(f"  {adj['type']}: {adj['original']} → {adj['adjusted']}")
    
    print(f"{'='*80}\n")
    
    return result


