def build_conflict_matrix_v2630(
    l2_detail: Dict,
    pa_tag: str,
    two_b_tag: str,
    volume_state: str,
    rsi_value: Optional[float],
    sr_zone: str,
    pos_ratio: float,
    trend_state: str,
    wyckoff_phase: str,
    ai_action: str,
) -> List[Tuple[ConflictType, bool, str]]:
    """构建冲突矩阵v2.630"""
    
    conflicts = []
    
    # 1. 量价背离
    has_volume_divergence = False
    volume_div_desc = "无量价背离"
    if ai_action in ["BUY", "SELL"]:
        if (ai_action == "BUY" and volume_state == "SHRINKING") or            (ai_action == "SELL" and volume_state == "EXPANDING"):
            has_volume_divergence = True
            volume_div_desc = f"{ai_action}但成交量{volume_state}"
    conflicts.append((ConflictType.VOLUME_DIVERGENCE, has_volume_divergence, volume_div_desc))
    
    # 2. RSI极值
    has_rsi_extreme = False
    rsi_desc = "RSI正常"
    if rsi_value is not None:
        if ai_action == "BUY" and rsi_value >= 70:
            has_rsi_extreme = True
            rsi_desc = f"BUY但RSI={rsi_value:.1f}超买"
        elif ai_action == "SELL" and rsi_value <= 30:
            has_rsi_extreme = True
            rsi_desc = f"SELL但RSI={rsi_value:.1f}超卖"
    conflicts.append((ConflictType.RSI_EXTREME, has_rsi_extreme, rsi_desc))
    
    # 3. 区域阻力
    has_zone_resistance = False
    zone_desc = "区域合理"
    upper_zones = ["UPPER", "UPPER_HALF", "HIGH"]
    lower_zones = ["LOWER", "LOWER_HALF", "LOW"]
    if ai_action == "BUY" and sr_zone in upper_zones:
        has_zone_resistance = True
        zone_desc = f"BUY在{sr_zone}可能遇阻"
    elif ai_action == "SELL" and sr_zone in lower_zones:
        has_zone_resistance = True
        zone_desc = f"SELL在{sr_zone}可能有支撑"
    conflicts.append((ConflictType.ZONE_RESISTANCE, has_zone_resistance, zone_desc))
    
    # 4. 趋势冲突
    has_trend_conflict = False
    trend_desc = "趋势一致"
    if (ai_action == "BUY" and trend_state == "DOWN") or        (ai_action == "SELL" and trend_state == "UP"):
        has_trend_conflict = True
        trend_desc = f"{ai_action}但趋势{trend_state}"
    conflicts.append((ConflictType.TREND_CONFLICT, has_trend_conflict, trend_desc))
    
    # 5. PA冲突
    has_pa_conflict = False
    pa_desc = "PA支持"
    if (ai_action == "BUY" and pa_tag == "SELL_EDGE") or        (ai_action == "SELL" and pa_tag == "BUY_EDGE"):
        has_pa_conflict = True
        pa_desc = f"{ai_action}但PA={pa_tag}"
    conflicts.append((ConflictType.PA_CONFLICT, has_pa_conflict, pa_desc))
    
    # 6. 2B反转
    has_two_b = False
    two_b_desc = "无2B"
    if (ai_action == "BUY" and "SELL" in two_b_tag) or        (ai_action == "SELL" and "BUY" in two_b_tag):
        has_two_b = True
        two_b_desc = f"{ai_action}但{two_b_tag}"
    conflicts.append((ConflictType.TWO_B_REVERSAL, has_two_b, two_b_desc))
    
    # 7. 仓位极值
    has_pos_extreme = False
    pos_desc = "仓位正常"
    if ai_action == "BUY" and pos_ratio > 0.85:
        has_pos_extreme = True
        pos_desc = f"BUY但仓位{pos_ratio:.1%}"
    elif ai_action == "SELL" and pos_ratio < 0.15:
        has_pos_extreme = True
        pos_desc = f"SELL但仓位{pos_ratio:.1%}"
    conflicts.append((ConflictType.POSITION_EXTREME, has_pos_extreme, pos_desc))
    
    # 8. Wyckoff风险
    has_wyckoff_risk = False
    wyckoff_desc = "Wyckoff正常"
    risk_phases = ["DISTRIBUTION", "MARKDOWN", "UNCLEAR"]
    if ai_action == "BUY" and wyckoff_phase in risk_phases:
        has_wyckoff_risk = True
        wyckoff_desc = f"BUY在{wyckoff_phase}"
    elif ai_action == "SELL" and wyckoff_phase in ["ACCUMULATION", "MARKUP"]:
        has_wyckoff_risk = True
        wyckoff_desc = f"SELL在{wyckoff_phase}"
    conflicts.append((ConflictType.WYCKOFF_RISK, has_wyckoff_risk, wyckoff_desc))
    
    # 9. 低量
    is_volume_low = (volume_state == "SHRINKING")
    vol_low_desc = f"量{volume_state}" if is_volume_low else "量正常"
    conflicts.append((ConflictType.VOLUME_LOW, is_volume_low, vol_low_desc))
    
    # 10. 上半区弱势
    is_upper_weak = (sr_zone in ["UPPER_HALF", "HIGH"] and ai_action == "BUY")
    upper_desc = f"{sr_zone}做BUY略弱" if is_upper_weak else "位置可接受"
    conflicts.append((ConflictType.UPPER_ZONE_WEAK, is_upper_weak, upper_desc))
    
    return conflicts


def calculate_conflict_adjusted_confidence_v2630(
    ai_confidence: float,
    conflict_matrix: List[Tuple[ConflictType, bool, str]],
    market_regime: str,
    debug: bool = True
) -> Dict:
    """连续冲突评分核心算法v2.630"""
    
    try:
        regime_enum = MarketRegime(market_regime)
    except (ValueError, KeyError):
        regime_enum = MarketRegime.RANGE
    
    regime_factors = REGIME_ADJUSTMENT_FACTORS.get(regime_enum, {})
    
    total_penalty = 0.0
    penalty_details = []
    active_conflicts_count = 0
    
    for conflict_type, is_active, description in conflict_matrix:
        if not is_active:
            continue
        
        base_weight = BASE_PENALTY_WEIGHTS.get(conflict_type, 0.0)
        regime_factor = regime_factors.get(conflict_type, 1.0)
        adjusted_penalty = base_weight * regime_factor
        
        total_penalty += adjusted_penalty
        active_conflicts_count += 1
        
        penalty_details.append({
            "conflict": conflict_type.value,
            "description": description,
            "base_weight": base_weight,
            "regime_factor": regime_factor,
            "adjusted_penalty": adjusted_penalty,
        })
    
    final_confidence = max(0.0, ai_confidence - total_penalty)
    threshold = CONFIDENCE_THRESHOLD
    threshold_triggered = (final_confidence < threshold)
    
    result = {
        "original_confidence": ai_confidence,
        "final_confidence": final_confidence,
        "total_penalty": total_penalty,
        "active_conflicts": active_conflicts_count,
        "penalty_details": penalty_details,
        "regime": market_regime,
        "threshold": threshold,
        "threshold_triggered": threshold_triggered,
    }
    
    if debug:
        print(f"\n{'='*80}")
        print(f"[v2.630] 连续冲突评分")
        print(f"{'='*80}")
        print(f"Regime: {market_regime}")
        print(f"Original: {ai_confidence:.3f}")
        print(f"Conflicts: {active_conflicts_count}")
        if active_conflicts_count > 0:
            print(f"Penalties:")
            for d in penalty_details:
                print(f"  • {d['conflict']:20s} penalty={d['adjusted_penalty']:.3f}")
        print(f"Total Penalty: {total_penalty:.3f}")
        print(f"Final: {final_confidence:.3f}")
        print(f"Threshold: {'TRIGGERED' if threshold_triggered else 'OK'}")
        print(f"{'='*80}\n")
    
    return result


# ============================================================================
# v2.855: 全局仓位门控 - 最高优先级
# ============================================================================

def apply_global_position_gate(
    final_action: str,
    position_units: int,
    max_units: int,
    symbol: str,
) -> dict:
    """
    v2.855: 全局仓位门控 - 最高优先级
    
    规则:
    - 满仓(position >= max_units)时:
      - BUY → HOLD (禁止加仓)
      - HOLD → HOLD (保持)
      - SELL → SELL (允许减仓)
    
    Args:
        final_action: 决策引擎输出的最终动作
        position_units: 当前仓位
        max_units: 最大仓位
        symbol: 交易标的
    
    Returns:
        {
            "final_action": str,      # 门控后的最终动作
            "original_action": str,   # 原始动作
            "gate_applied": bool,     # 是否触发门控
            "gate_reason": str,       # 门控原因
            "position_status": str,   # FULL/NORMAL
        }
    """
    is_full = position_units >= max_units
    
    result = {
        "final_action": final_action,
        "original_action": final_action,
        "gate_applied": False,
        "gate_reason": "",
        "position_status": "FULL" if is_full else "NORMAL",
        "position_units": position_units,
        "max_units": max_units,
    }
    
    if is_full:
        if final_action == "BUY":
            # 满仓时禁止加仓
            result["final_action"] = "HOLD"
            result["gate_applied"] = True
            result["gate_reason"] = f"满仓禁止加仓({position_units}/{max_units})"
            print(f"[v2.855] ⚠️ 全局仓位门控 [{symbol}]: BUY → HOLD ({result['gate_reason']})")
        elif final_action == "HOLD":
            # 满仓保持HOLD
            result["gate_applied"] = True
            result["gate_reason"] = f"满仓保持({position_units}/{max_units})"
        elif final_action == "SELL":
            # 满仓允许减仓
            result["gate_applied"] = True
            result["gate_reason"] = f"满仓允许减仓({position_units}/{max_units})"
    
    return result


def final_decision_engine_v2630_enhanced(
    llm_action: str,
    llm_confidence: float,
    swing_sr_result: dict,
    sell_lock_result: dict,
    supreme_result: dict,
    pos_ratio: float,
    state: dict,
    l2_detail: dict = None,
    pa_tag: str = "NONE",
    two_b_tag: str = "NONE",
    volume_state: str = "NORMAL",
    rsi_value: Optional[float] = None,
    sr_zone: str = "MID",
    trend_state: str = "SIDE",
    wyckoff_phase: str = "UNCLEAR",
    market_regime: str = "RANGE",
    regime_info: dict = None,
    l2_exec_bias: str = "HOLD",  # v2.749: 添加L2 exec_bias参数
    candle_signal: dict = None,  # v2.750: 添加K线强信号参数
    l1_trend_vision: dict = None,  # v2.800: 添加L1趋势视觉参数
    plugin_mode: str = None,  # v3.080: 外挂模式参数
) -> dict:
    """
    v3.080统一决策引擎增强版

    优先级体系:
        P-1: 外挂放行（PLUGIN_AGREE/PLUGIN_CONFLICT直接执行）← v3.080新增！
        P0: Supreme Protection（极端仓位保护）
        P1: K线强信号（V反转/震荡顶底）
        P2: L1 STRONG信号（趋势视觉强信号）
        P3: Swing SR（顶底保险）
        P4: Sell Lock
        P5: L1-L2协商 + 冲突评分

    v2.749: 添加L2 STRONG信号+趋势覆盖逻辑
    v2.750: 添加K线强信号优先级
    v2.800: 添加L1趋势视觉系统 + L1-L2协商矩阵
    v3.080: 外挂信号放行逻辑（跳过L1否决检查）
    """
    
    decision_trace = []
    protection_active = False
    conflict_score = None
    l1_vision_used = False  # v2.865: 标记是否使用了Vision

    if l2_detail is None:
        l2_detail = {}
    if regime_info is None:
        regime_info = {}
    if l1_trend_vision is None:
        l1_trend_vision = {"l1_bias": "HOLD", "action_bias": "HOLD", "confidence": 0.5, "candle": {}}

    # v3.370: 使用L1五模块信号替代LLM原始信号作为基础
    # l1_bias是L1五模块框架的输出，llm_action是历史遗留的LLM原始返回
    l1_bias = l1_trend_vision.get("l1_bias", "HOLD")
    l1_conf = l1_trend_vision.get("confidence", 0.5)

    # v3.370: 将5级l1_bias转换为3级action作为初始值
    if l1_bias in ("STRONG_BUY", "BUY"):
        l1_action = "BUY"
    elif l1_bias in ("STRONG_SELL", "SELL"):
        l1_action = "SELL"
    else:
        l1_action = "HOLD"

    final_action = l1_action  # v3.370: 使用L1五模块信号，不再使用llm_action
    final_confidence = l1_conf  # v3.370: 使用L1置信度
    override_by = "L1_FIVE_MODULE"  # v3.370: 重命名，明确是L1五模块

    # ========================================================================
    # P-1: 外挂放行 (v3.080/v3.391) - STRONG信号才直接放行，非STRONG需协商
    # ========================================================================
    # v3.391修复: 之前BUY/SELL也直接放行，导致L1=HOLD无法否决L2=SELL
    # 现在只有STRONG_BUY/STRONG_SELL才直接放行，普通BUY/SELL需走协商矩阵
    if plugin_mode in ("PLUGIN_AGREE", "PLUGIN_CONFLICT"):
        # v3.391: 只有STRONG信号才直接放行
        if l2_exec_bias == "STRONG_BUY":
            final_action = "BUY"
            override_by = f"PLUGIN_{plugin_mode}"
            decision_trace.append(
                f"[P-1-PLUGIN] ⚡ 外挂STRONG放行: mode={plugin_mode}, exec_bias={l2_exec_bias} → {final_action}"
            )
            print(f"[v3.391] ⚡ 外挂STRONG_BUY放行: {plugin_mode} → BUY")
            return {
                "final_action": final_action,
                "decision_trace": decision_trace,
                "override_by": override_by,
                "confidence": 0.95,
                "protection_active": False,
                "conflict_score": None,
                "market_regime": market_regime,
                "regime_info": regime_info,
                "l1_trend_vision": l1_trend_vision,
                "plugin_bypass": True,
            }
        elif l2_exec_bias == "STRONG_SELL":
            final_action = "SELL"
            override_by = f"PLUGIN_{plugin_mode}"
            decision_trace.append(
                f"[P-1-PLUGIN] ⚡ 外挂STRONG放行: mode={plugin_mode}, exec_bias={l2_exec_bias} → {final_action}"
            )
            print(f"[v3.391] ⚡ 外挂STRONG_SELL放行: {plugin_mode} → SELL")
            return {
                "final_action": final_action,
                "decision_trace": decision_trace,
                "override_by": override_by,
                "confidence": 0.95,
                "protection_active": False,
                "conflict_score": None,
                "market_regime": market_regime,
                "regime_info": regime_info,
                "l1_trend_vision": l1_trend_vision,
                "plugin_bypass": True,
            }
        elif l2_exec_bias in ("BUY", "SELL"):
            # v3.660: 普通BUY/SELL外挂信号也放行，降低confidence
            # v3.391原逻辑让L1=HOLD否决所有普通外挂→9次PLUGIN_CONFLICT全HOLD
            final_action = l2_exec_bias
            override_by = f"PLUGIN_{plugin_mode}"
            decision_trace.append(
                f"[P-1-PLUGIN] 外挂放行: mode={plugin_mode}, exec_bias={l2_exec_bias} → {final_action} (conf=0.70)"
            )
            log_to_server(f"[v3.660] 外挂{l2_exec_bias}放行: {plugin_mode} → {final_action}")
            return {
                "final_action": final_action,
                "decision_trace": decision_trace,
                "override_by": override_by,
                "confidence": 0.70,
                "protection_active": False,
                "conflict_score": None,
                "market_regime": market_regime,
                "regime_info": regime_info,
                "l1_trend_vision": l1_trend_vision,
                "plugin_bypass": True,
            }
        else:
            # HOLD exec_bias → 继续走协商矩阵
            decision_trace.append(
                f"[P-1-PLUGIN] 外挂HOLD: mode={plugin_mode}, exec_bias={l2_exec_bias} → 继续协商"
            )
            # 不return，继续执行后续P0-P5逻辑

    # P0: Supreme Protection
    if supreme_result.get("protected"):
        final_action = supreme_result["final_action"]
        override_by = supreme_result["protection_type"]
        protection_active = True
        decision_trace.append(
            f"[P0-SUPREME] {supreme_result['protection_type']}: "
            f"{supreme_result['original_action']} → {final_action}"
        )
        return {
            "final_action": final_action,
            "decision_trace": decision_trace,
            "override_by": override_by,
            "confidence": final_confidence,
            "protection_active": protection_active,
            "conflict_score": None,
            "market_regime": market_regime,
            "regime_info": regime_info,
            "l1_trend_vision": l1_trend_vision,  # v2.865
        }
    else:
        decision_trace.append(f"[P0-SUPREME] 通过: pos_ratio={pos_ratio:.2%}")
    
    # ========================================================================
    # P1: Vision覆盖 (v2.865: K线形态已整合到Vision中)
    # ========================================================================
    # Vision包含: K线形态35% + 斜率25% + 量价20% + 阶段20%
    # 当Vision给出强信号时，可以覆盖L1五模块决策
    # v3.370: l1_bias和l1_conf已在前面定义
    # ========================================================================

    l1_score = l1_trend_vision.get("score", 0.0)
    l1_reasons = l1_trend_vision.get("reasons", [])
    l1_candle = l1_trend_vision.get("candle", {})
    candle_signal_name = l1_candle.get("signal", "NONE")
    
    # v2.865: Vision STRONG信号覆盖
    if l1_bias in ["STRONG_BUY", "STRONG_SELL"]:
        # 使用L1-L2协商矩阵
        negotiate_result = l1_l2_negotiate(l1_bias, l2_exec_bias, l1_conf)
        
        # L1 STRONG 胜出的情况
        if negotiate_result["l1_wins"] or negotiate_result["agreement"] in [
            "DOUBLE_CONFIRM_BUY", "DOUBLE_CONFIRM_SELL",
            "L1_STRONG_L2_OK", "L1_STRONG_OVERRIDE"
        ]:
            final_action = negotiate_result["final_action"]
            override_by = f"VISION_{l1_bias}"
            l1_vision_used = True
            final_confidence = negotiate_result["confidence"]
            
            reason_str = f"K线:{candle_signal_name}" if candle_signal_name != "NONE" else ', '.join(l1_reasons[:2])
            decision_trace.append(
                f"[P1-VISION] ⚡ {l1_bias}: {reason_str} → {final_action} "
                f"(score:{l1_score:.2f}, 协商:{negotiate_result['agreement']})"
            )
            print(f"[v2.865 P1] ⚡ Vision覆盖: {l1_bias}(score={l1_score:.2f}) + L2={l2_exec_bias} → {final_action}")
            
            # Vision STRONG信号触发，直接返回
            return {
                "final_action": final_action,
                "decision_trace": decision_trace,
                "override_by": override_by,
                "confidence": final_confidence,
                "protection_active": False,
                "conflict_score": None,
                "market_regime": market_regime,
                "regime_info": regime_info,
                "l1_trend_vision": l1_trend_vision,
            }
        else:
            decision_trace.append(
                f"[P1-VISION] {l1_bias} 被L2否决: {negotiate_result['agreement']}"
            )
    else:
        decision_trace.append(f"[P1-VISION] 通过: {l1_bias}(score={l1_score:.2f})")
    
    # P2: Swing SR
    if swing_sr_result.get("triggered"):
        final_action = swing_sr_result["action"]
        override_by = "SWING_SR"
        decision_trace.append(f"[P2-SWING_SR] 触发: {swing_sr_result['reason']} → {final_action}")
    elif swing_sr_result.get("in_range") is False:
        decision_trace.append(f"[P2-SWING_SR] 未触发")
    
    # P3: Sell Lock
    if sell_lock_result.get("locked"):
        if pos_ratio < 0.25:
            decision_trace.append(f"[P3-SELL_LOCK] 低位豁免: {pos_ratio:.2%}")
        else:
            if override_by != "SWING_SR":
                final_action = "HOLD"
                override_by = f"SELL_LOCK_{sell_lock_result.get('lock_level', 'UNKNOWN')}"
                decision_trace.append(f"[P3-SELL_LOCK] 锁定 → HOLD")
            else:
                decision_trace.append(f"[P3-SELL_LOCK] 被P2覆盖")
    else:
        decision_trace.append(f"[P3-SELL_LOCK] 通过")
    
    # P4: 连续冲突评分 + L1-L2协商
    # P5: 连续冲突评分 + L1-L2协商 (v2.800改进)
    # v3.370: 使用l1_action替代llm_action，使用L1_FIVE_MODULE替代LLM
    if override_by == "L1_FIVE_MODULE" and l1_action in ["BUY", "SELL"]:
        conflict_matrix = build_conflict_matrix_v2630(
            l2_detail=l2_detail,
            pa_tag=pa_tag,
            two_b_tag=two_b_tag,
            volume_state=volume_state,
            rsi_value=rsi_value,
            sr_zone=sr_zone,
            pos_ratio=pos_ratio,
            trend_state=trend_state,
            wyckoff_phase=wyckoff_phase,
            ai_action=l1_action,  # v3.370: 使用l1_action替代llm_action
        )

        conflict_score = calculate_conflict_adjusted_confidence_v2630(
            ai_confidence=l1_conf,  # v3.370: 使用l1_conf替代llm_confidence
            conflict_matrix=conflict_matrix,
            market_regime=market_regime,
            debug=True,
        )
        
        final_confidence = conflict_score["final_confidence"]

        # v3.360: 双向确认bypass冲突评分 - 修复L1+L2一致却被CONFLICT_PENALTY改HOLD的bug
        is_double_confirm_buy = (l1_bias in ("BUY", "STRONG_BUY") and l2_exec_bias in ("BUY", "STRONG_BUY"))
        is_double_confirm_sell = (l1_bias in ("SELL", "STRONG_SELL") and l2_exec_bias in ("SELL", "STRONG_SELL"))
        is_double_confirm = is_double_confirm_buy or is_double_confirm_sell

        if is_double_confirm:
            # v3.360: 双向确认有最高优先级，bypass所有冲突评分
            negotiate_result = l1_l2_negotiate(l1_bias, l2_exec_bias, l1_conf)
            final_action = negotiate_result["final_action"]
            override_by = "L1_L2_DOUBLE_CONFIRM"
            decision_trace.append(
                f"[P5-DOUBLE_CONFIRM] ✅ L1={l1_bias}+L2={l2_exec_bias} bypass冲突评分 → {final_action} "
                f"(原conf={conflict_score['original_confidence']:.3f}, 罚={conflict_score['total_penalty']:.3f})"
            )
            print(f"[v3.360] 双向确认bypass: L1={l1_bias}+L2={l2_exec_bias} → {final_action} (冲突评分被忽略)")
        elif conflict_score["threshold_triggered"]:
            final_action = "HOLD"
            override_by = "CONFLICT_PENALTY"
            decision_trace.append(
                f"[P5-CONFLICT] 降级: 原={conflict_score['original_confidence']:.3f}, "
                f"罚={conflict_score['total_penalty']:.3f}, "
                f"终={final_confidence:.3f} → HOLD"
            )
        else:
            # v3.340: 对于非STRONG信号，使用L1-L2协商 (统一格式)
            if l1_bias in ["BUY", "SELL", "HOLD"]:
                negotiate_result = l1_l2_negotiate(l1_bias, l2_exec_bias, l1_conf)
                negotiated_action = negotiate_result["final_action"]
                
                if negotiated_action != l1_action:  # v3.370: 使用l1_action
                    final_action = negotiated_action
                    override_by = f"L1_L2_NEGOTIATE"
                    decision_trace.append(
                        f"[P5-NEGOTIATE] L1={l1_bias}+L2={l2_exec_bias} → {negotiated_action} "
                        f"({negotiate_result['agreement']})"
                    )
                else:
                    decision_trace.append(
                        f"[P5-L1] 通过: 终={final_confidence:.3f}, L1={l1_bias}"  # v3.370: LLM→L1
                    )
            else:
                decision_trace.append(
                    f"[P5-L1] 通过: 终={final_confidence:.3f} ≥ {conflict_score['threshold']:.2f}"  # v3.370: LLM→L1
                )
    elif override_by == "L1_FIVE_MODULE" and l1_action == "HOLD":  # v3.370: LLM→L1_FIVE_MODULE
        # ========================================================================
        # v3.370: L1=HOLD时，统一使用L1-L2协商矩阵决定最终动作
        #
        # 核心原则：
        #   - L1=STRONG + L2不是相反方向 → 遵守L1
        #   - L2=STRONG + L1不是相反方向 → 遵守L2
        #   - L1和L2方向明确相反 → HOLD（冲突）
        #   - HOLD不否决对方的STRONG信号
        # ========================================================================

        # v3.340: 统一走协商矩阵 (L1格式已统一为STRONG_BUY/BUY/HOLD/SELL/STRONG_SELL)
        # 不再需要映射
        if l1_bias in ["BUY", "SELL", "HOLD", "STRONG_BUY", "STRONG_SELL"]:
            # v3.370: 双向确认Bypass也适用于LLM=HOLD的情况
            # 当LLM返回HOLD但L1+L2双向确认时，应该执行交易
            is_double_confirm_buy = (l1_bias in ("BUY", "STRONG_BUY") and l2_exec_bias in ("BUY", "STRONG_BUY"))
            is_double_confirm_sell = (l1_bias in ("SELL", "STRONG_SELL") and l2_exec_bias in ("SELL", "STRONG_SELL"))
            is_double_confirm = is_double_confirm_buy or is_double_confirm_sell

            if is_double_confirm:
                # v3.370: LLM=HOLD但L1+L2双向确认，直接执行
                negotiate_result = l1_l2_negotiate(l1_bias, l2_exec_bias, l1_conf)
                final_action = negotiate_result["final_action"]
                override_by = "L1_L2_DOUBLE_CONFIRM"
                decision_trace.append(
                    f"[P5-DOUBLE_CONFIRM] ✅ LLM=HOLD但L1={l1_bias}+L2={l2_exec_bias}双向确认 → {final_action}"
                )
                print(f"[v3.370] 双向确认(LLM=HOLD): L1={l1_bias}+L2={l2_exec_bias} → {final_action}")
            else:
                negotiate_result = l1_l2_negotiate(l1_bias, l2_exec_bias, l1_conf)

            # v3.370: 双向确认已处理，跳过后续逻辑
            if not is_double_confirm:
                # v3.370: 震荡市高抛低吸特殊处理
                # 当big_trend=SIDE时，允许低位买入、高位卖出
                _five_module = l1_trend_vision.get("v3300_five_module", {}) if l1_trend_vision else {}
                _big_trend = _five_module.get("ai_module", {}).get("big_trend", "SIDE")
                _grid_pos = _five_module.get("grid_module", {}).get("detail", {}).get("relative_pos", 0.5)

                # 震荡市+位置+L2信号 → 高抛低吸
                range_trade_override = False
                if _big_trend == "SIDE" and negotiate_result["final_action"] == "HOLD":
                    # 低位买入: 位置<35% + L2给买入信号
                    if _grid_pos < 0.35 and l2_exec_bias in ("BUY", "STRONG_BUY"):
                        range_trade_override = True
                        final_action = "BUY"
                        override_by = "RANGE_LOW_BUY"
                        decision_trace.append(
                            f"[P5-RANGE_TRADE] 📈 震荡低吸: big_trend=SIDE + 位置={_grid_pos:.0%} + L2={l2_exec_bias} → BUY"
                        )
                        print(f"[v3.370] 震荡低吸: SIDE + pos={_grid_pos:.0%} + L2={l2_exec_bias} → BUY")
                    # 高位卖出: 位置>65% + L2给卖出信号
                    elif _grid_pos > 0.65 and l2_exec_bias in ("SELL", "STRONG_SELL"):
                        range_trade_override = True
                        final_action = "SELL"
                        override_by = "RANGE_HIGH_SELL"
                        decision_trace.append(
                            f"[P5-RANGE_TRADE] 📉 震荡高抛: big_trend=SIDE + 位置={_grid_pos:.0%} + L2={l2_exec_bias} → SELL"
                        )
                        print(f"[v3.370] 震荡高抛: SIDE + pos={_grid_pos:.0%} + L2={l2_exec_bias} → SELL")

                if not range_trade_override:
                    if negotiate_result["final_action"] != "HOLD":
                        final_action = negotiate_result["final_action"]
                        override_by = "L1_L2_NEGOTIATE"
                        # v3.340: 格式已统一，不再需要映射显示
                        decision_trace.append(
                            f"[P5-NEGOTIATE] L1={l1_bias}+L2={l2_exec_bias} → {final_action} "
                            f"({negotiate_result['agreement']})"
                        )
                        print(f"[v3.340] 协商矩阵: L1={l1_bias}+L2={l2_exec_bias} → {final_action}")
                    else:
                        decision_trace.append(
                            f"[P5-NEGOTIATE] L1={l1_bias}+L2={l2_exec_bias} → HOLD"
                        )

        # v3.370: 没有覆盖条件，保持L1的HOLD
        else:
            decision_trace.append(
                f"[P5-L1] HOLD (conf={l1_conf:.2f}, L1={l1_bias}, L2={l2_exec_bias})"  # v3.370: LLM→L1
            )
    
    return {
        "final_action": final_action,
        "decision_trace": decision_trace,
        "override_by": override_by,
        "confidence": final_confidence,
        "protection_active": protection_active,
        "conflict_score": conflict_score,
        "market_regime": market_regime,
        "regime_info": regime_info,
        "candle_signal": candle_signal,  # v2.750
        "l1_trend_vision": l1_trend_vision,  # v2.800: 添加L1趋势视觉
    }



