# v3.672: Vision 预过滤模块懒加载缓存
_VISION_PRE_FILTER_MOD = None

def _get_vision_pre_filter():
    """懒加载 vision_pre_filter 模块（只加载一次）"""
    global _VISION_PRE_FILTER_MOD
    if _VISION_PRE_FILTER_MOD is not None:
        return _VISION_PRE_FILTER_MOD
    try:
        import importlib.util, os
        _path = os.path.join(os.path.dirname(__file__), ".GCC", "scripts", "vision_pre_filter.py")
        _spec = importlib.util.spec_from_file_location("vision_pre_filter", _path)
        _mod = importlib.util.module_from_spec(_spec)
        _spec.loader.exec_module(_mod)
        _VISION_PRE_FILTER_MOD = _mod
        log_to_server("[VISION_FILTER] 模块加载成功")
    except Exception as e:
        log_to_server(f"[VISION_FILTER] 模块加载失败: {e}")
        _VISION_PRE_FILTER_MOD = None
    return _VISION_PRE_FILTER_MOD

