# =========================================================
# SignalStack 下单函数（美股专用）
# =========================================================
def send_signalstack_order(final_action: str, symbol: str, signal_type: str = "", source: str = "main"):
    """v3.411: 幂等性 + 重试 + 60秒信号冷却; v3.641: 连续失败熔断; v3.663: KEY-003价值限买; GCC-0194: 去掉重复过滤
    返回: True=成功, False=API发送失败, None=被门控/过滤拦截
    v3.680 GCC-0254: source参数 — GCC-TM白名单美股只允许 source='gcc_tm' 实盘下单"""
    if final_action not in ["BUY", "SELL"]:
        return False

    # ═══ 最高级别: 人类禁卖拦截 (优先于一切门控, 包括gcc_tm) ═══
    if final_action == "SELL":
        try:
            _hsb_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "state", "human_sell_block.json")
            if os.path.exists(_hsb_path):
                import json as _hsb_json
                from datetime import datetime as _hsb_dt
                from zoneinfo import ZoneInfo as _hsb_zi
                with open(_hsb_path, "r", encoding="utf-8") as _hsb_f:
                    _hsb = _hsb_json.load(_hsb_f)
                _sb = _hsb.get("sell_block", {})
                if _sb.get("enabled") and symbol in _sb.get("symbols", []):
                    _hsb_tz = _hsb_zi(_sb.get("timezone", "America/New_York"))
                    _hsb_now = _hsb_dt.now(_hsb_tz)
                    _hsb_start = _hsb_dt.fromisoformat(_sb["start"]).replace(tzinfo=_hsb_tz)
                    _hsb_end = _hsb_dt.fromisoformat(_sb["end"]).replace(tzinfo=_hsb_tz)
                    if _hsb_start <= _hsb_now <= _hsb_end:
                        log_to_server(
                            f"[HUMAN-BLOCK][最高级别] {symbol} SELL 被禁止 — "
                            f"{_sb['start']}~{_sb['end']} source={source} "
                            f"原因: {_sb.get('reason','')}"
                        )
                        return None
        except Exception as _hsb_err:
            log_to_server(f"[HUMAN-BLOCK] 检查异常(不拦截): {_hsb_err}")

    # TSLA期权通道: 双通道(任意来源+GCC-TM都可触发)
    TSLA_OPTIONS_ENABLED = True
    if symbol == "TSLA":
        if TSLA_OPTIONS_ENABLED:
            try:
                from qqq_options import execute_signal as _qqq_execute
                _qqq_result = _qqq_execute(final_action, dry_run=False)
                _opt_info = _qqq_result.get('option', {})
                log_to_server(
                    f"[B2][TSLA-OPT] {source} {final_action} → "
                    f"success={_qqq_result.get('success')} "
                    f"type={_opt_info.get('type', 'N/A')} strike={_opt_info.get('strike', 'N/A')}"
                )
                try:
                    send_email_notification(
                        f"[TSLA期权] {source} {final_action}",
                        f"来源: {source}\n方向: {final_action}\n"
                        f"合约: {_opt_info.get('type','N/A')} {_opt_info.get('strike','N/A')} "
                        f"x{_opt_info.get('contracts','N/A')}\n"
                        f"成功: {_qqq_result.get('success')}"
                    )
                except Exception:
                    pass
                return _qqq_result.get("success", False)
            except Exception as _qqq_e:
                log_to_server(f"[B2][TSLA-OPT][ERROR] {final_action}: {_qqq_e}")
                return False

    # v3.660: GCC-TM全量独占 — 所有美股只允许gcc_tm下单
    if source not in ("gcc_tm",):
        log_to_server(
            f"[BLOCKED][非B1] {symbol} {final_action} "
            f"source={source} type={signal_type} → 非GCC-TM来源，仅观察"
        )
        return None  # 门控拦截，不实际下单

    # GCC-TM 裁决信号: 已经过Vision门控+8轮决策, 跳过KEY-001/KEY-002/KEY-003二次审查
    _ss_gcc_tm_bypass = (source == "gcc_tm")

    # ── gate block计数器(传入Master Hub blocked_gate_count) ──────────────
    _ss_gate_block_count = 0

    # ── KEY-001 Human Anchor 冲突检查 ─────────────────────────────────────
    if not _ss_gcc_tm_bypass:
        try:
            _ss_anchor_block, _ss_anchor_reason = _check_human_anchor_gate(symbol, final_action, signal_type)
            if _ss_anchor_block:
                log_to_server(f"[KEY001-ANCHOR][拦截] {symbol} {final_action}: {_ss_anchor_reason}")
                return None  # 门控拦截，非API失败
        except Exception as _ss_ae:
            log_to_server(f"[KEY001-ANCHOR][ERROR] {symbol}: {_ss_ae}")

    # ── KEY-001 动态门控误杀控制 (Phase2 真实拦截) ──────────────────────────
    _ss_k1_exempt = signal_type in ("移动止损", "移动止盈") or _ss_gcc_tm_bypass
    if not _ss_k1_exempt:
        try:
            from modules.vision_adaptive import apply_key001_gate as _ss_k1_gate
            _ss_k1_allowed, _ss_k1_reason = _ss_k1_gate(symbol, final_action, {})
            log_to_server(
                f"[B1][KEY-001][GATE] {symbol} {final_action} "
                f"allowed={_ss_k1_allowed} reason={_ss_k1_reason}"
            )
            if not _ss_k1_allowed:
                log_to_server(f"[B1][KEY-001][GATE][拦截] {symbol} {final_action}: {_ss_k1_reason}")
                return None  # 门控拦截，非API失败
        except Exception as _ss_k1_e:
            log_to_server(f"[B1][KEY-001][GATE][ERROR] {symbol}: {_ss_k1_e}")

    # ── KEY-001 Vision Cache Gate (GCC-0062: Phase3 full拦截) ──────────────
    KEY001_VCACHE_MODE_SS = "observe"  # GCC-0062: "observe"/"soft"/"full"
    if not _ss_k1_exempt and not _ss_gcc_tm_bypass:
        try:
            from modules.key001_vision_cache import VisionCache as _SS_VCCache, vision_gate as _ss_vc_gate
            _ss_vc_cache = _SS_VCCache()
            if KEY001_VCACHE_MODE_SS == "observe":
                log_to_server(
                    f"[KEY001-VCACHE][GATE] {symbol} {final_action} mode=observe"
                )
            else:
                _ss_vc_allowed, _ss_vc_reason = _ss_vc_gate(
                    symbol=symbol, action=final_action, chart=None, df=None,
                    cache=_ss_vc_cache, mode=KEY001_VCACHE_MODE_SS,
                )
                log_to_server(
                    f"[KEY001-VCACHE][GATE] {symbol} {final_action} mode={KEY001_VCACHE_MODE_SS} "
                    f"allowed={_ss_vc_allowed} reason={_ss_vc_reason}"
                )
                if not _ss_vc_allowed:
                    log_to_server(f"[KEY001-VCACHE][拦截] {symbol} {final_action}: {_ss_vc_reason}")
                    return None
        except Exception as _ss_vc_e:
            log_to_server(f"[KEY001-VCACHE][GATE][ERROR] {symbol}: {_ss_vc_e}")

    # ── KEY-002 Regime自适应入场门控 (Phase2 真实拦截) ──────────────────────
    _ss_k2_exempt = signal_type in ("移动止损", "移动止盈") or _ss_gcc_tm_bypass
    if not _ss_k2_exempt:
        try:
            from modules.key002_regime import (
                build_features_from_market_regime as _ss_k2_build_feat,
                detect_regime as _ss_k2_detect,
                load_key002_runtime_params as _ss_k2_load_params,
                key002_apply_entry_gate as _ss_k2_gate,
            )
            _ss_k2_state = get_state_for_symbol(symbol)
            _ss_k2_mr    = _ss_k2_state.get("market_regime", {})
            _ss_k2_feat  = _ss_k2_build_feat(symbol, _ss_k2_mr)
            _ss_k2_regime = _ss_k2_detect(_ss_k2_feat)
            _ss_k2_params = _ss_k2_load_params(symbol, _ss_k2_regime)
            # v3.660: 从_last_l1_trend_vision读取真实confidence
            _ss_k2_l1v    = _ss_k2_state.get("_last_l1_trend_vision", {})
            _ss_k2_conf   = float(_ss_k2_l1v.get("confidence", 0.60)) if isinstance(_ss_k2_l1v, dict) else 0.60
            _ss_k2_allowed, _ss_k2_reason = _ss_k2_gate(symbol, _ss_k2_conf, _ss_k2_params)
            log_to_server(
                f"[B1][KEY-002][GATE] {symbol} {final_action} regime={_ss_k2_regime} "
                f"conf={_ss_k2_conf:.3f} threshold={_ss_k2_params.entry_threshold:.3f} "
                f"allowed={_ss_k2_allowed} reason={_ss_k2_reason}"
            )
            if not _ss_k2_allowed:
                log_to_server(f"[B1][KEY-002][GATE][拦截] {symbol} {final_action}: {_ss_k2_reason}")
                return None  # 门控拦截，非API失败
        except Exception as _ss_k2_e:
            log_to_server(f"[B1][KEY-002][GATE][ERROR] {symbol}: {_ss_k2_e}")

    # ── AUD-052 方向翻转冷却门控 (direction_flip_cooldown_bars) ────────────
    _ss_dfc_exempt = signal_type in ("移动止损", "移动止盈") or _ss_gcc_tm_bypass
    if not _ss_dfc_exempt:
        try:
            import time as _ss_dfc_time
            _ss_dfc_bars = get_symbol_param(symbol, "timing", "direction_flip_cooldown_bars", default=0)
            if _ss_dfc_bars > 0:
                _ss_dfc_flip_time = get_state_for_symbol(symbol).get("_last_direction_flip_time", 0)
                _ss_dfc_tf_min = int(get_symbol_param(symbol, "timing", "timeframe_minutes", default=240))
                _ss_dfc_cooldown_secs = _ss_dfc_bars * _ss_dfc_tf_min * 60
                _ss_dfc_elapsed = _ss_dfc_time.time() - _ss_dfc_flip_time
                if _ss_dfc_elapsed < _ss_dfc_cooldown_secs:
                    _ss_dfc_remaining = (_ss_dfc_cooldown_secs - _ss_dfc_elapsed) / 3600
                    _ss_dfc_from = get_state_for_symbol(symbol).get("_last_direction_flip_from", "?")
                    _ss_dfc_to   = get_state_for_symbol(symbol).get("_last_direction_flip_to",   "?")
                    log_to_server(
                        f"[AUD-052][DIR_FLIP_COOL][拦截] {symbol} {final_action}: "
                        f"方向翻转冷却中({_ss_dfc_from}→{_ss_dfc_to}) "
                        f"剩余{_ss_dfc_remaining:.1f}h ({_ss_dfc_bars}根K线)"
                    )
                    return None  # 门控拦截，非API失败
                elif _ss_dfc_flip_time > 0:
                    log_to_server(
                        f"[AUD-052][DIR_FLIP_COOL] {symbol} {final_action}: "
                        f"冷却已过({_ss_dfc_elapsed/3600:.1f}h >= {_ss_dfc_cooldown_secs/3600:.0f}h) 放行"
                    )
        except Exception as _ss_dfc_e:
            log_to_server(f"[AUD-052][DIR_FLIP_COOL][ERROR] {symbol}: {_ss_dfc_e}")

    # ── KEY-001 大师模块 (观察模式, 异常fail-open) ─────────────────────────
    MASTER_GATE_SS_ENABLED = True
    if MASTER_GATE_SS_ENABLED and final_action in ("BUY", "SELL") and signal_type not in ("移动止损", "移动止盈") and not _ss_gcc_tm_bypass:
        try:
            from modules.key001_master_validation.hub import MasterValidationHub
            from modules.key001_master_validation.contracts import MasterContext
            from modules.key001_master_validation.audit import MasterAuditLogger

            _mst_ss = get_state_for_symbol(symbol) or {}
            _mmr_ss = _mst_ss.get("market_regime", {})
            _mfd_ss = _mst_ss.get("_last_final_decision", {})
            _m3w_ss = _mfd_ss.get("three_way_signals", {}) if isinstance(_mfd_ss, dict) else {}
            _mmr2_ss = _m3w_ss.get("market_regime", _mmr_ss)

            _mctx_ss = MasterContext(
                symbol=symbol,
                direction=final_action,
                signal_type=signal_type or "",
                signal_strength=float(_mmr2_ss.get("confidence", 0.5)),
                filter_passed=True,
                blocked_reason=None,
                blocked_gate_count=_ss_gate_block_count,
                market={
                    "pivot_distance_pct": abs(float(_mmr2_ss.get("pos_ratio", 0.5)) - 0.5) * 0.1,
                    "rvol": float(_mmr2_ss.get("volume_ratio", 1.0)),
                    "trend_position_pct": float(_mmr2_ss.get("pos_ratio", 0.5)),
                    "rr_ratio": float(_mmr2_ss.get("atr_ratio", 1.5)),
                    "signal_freq_5d": int(_mst_ss.get("actual_buy_count", 0)) + int(_mst_ss.get("actual_sell_count", 0)),
                    "breakout_distance_pct": 0.01,
                    "pullback_pct": 0.03,
                    "pullback_rvol": 0.9,
                },
                macro={"trend_x4": _mmr2_ss.get("big_trend", _mmr2_ss.get("trend_x4", "side"))},
                stats={},
            )
            _mhub_ss = MasterValidationHub.from_config_files()
            _mdec_ss = _mhub_ss.evaluate(_mctx_ss)
            MasterAuditLogger().log(_mctx_ss, _mdec_ss)
            log_to_server(
                f"[KEY001-MASTER] {symbol} {final_action} "
                f"action={_mdec_ss.action} score={_mdec_ss.final_score:.3f} "
                f"reasons={_mdec_ss.reasons}"
            )
            if _mdec_ss.action == "DOWNGRADE":
                log_to_server(f"[KEY001-MASTER][OBS] {symbol} {final_action}: score={_mdec_ss.final_score:.3f} {_mdec_ss.reasons} (观察模式,不拦截)")
                # 观察模式: 不return None
        except Exception as _me_ss:
            log_to_server(f"[KEY001-MASTER][ERROR] {symbol}: {_me_ss} → fail-open放行")

    # v3.663 KEY-003: 后5名美股每天限买1次
    if final_action == "BUY" and not _ss_gcc_tm_bypass:
        allowed, reason = _key003_check_buy_allowed(symbol)
        if not allowed:
            log_to_server(f"[KEY-003][VALUE-GUARD][拦截] {symbol} BUY被拦截: {reason}")
            return None  # 门控拦截，非API失败

    # GCC-0256 S2: Schwab直连模式 (True=schwab-py SDK直接下单, False=SignalStack webhook)
    SCHWAB_DIRECT_MODE = False  # 观察中，验证通过后开启

    if not SCHWAB_DIRECT_MODE and not SIGNALSTACK_WEBHOOK_URL:
        log_to_server("[SignalStack] SIGNALSTACK_WEBHOOK_URL 未设置，跳过下单。")
        return False

    import time as time_module
    current_time = time_module.time()

    state = get_state_for_symbol(symbol)

    # v3.411: 60秒信号冷却 - 防止同一标的短时间内重复下单
    SIGNAL_COOLDOWN_SECONDS = 60
    last_signal_key = f"last_{final_action.lower()}_time"
    last_signal_time = state.get(last_signal_key, 0)
    time_since_last = current_time - last_signal_time

    if time_since_last < SIGNAL_COOLDOWN_SECONDS:
        remaining = SIGNAL_COOLDOWN_SECONDS - time_since_last
        log_to_server(f"[SignalStack] {symbol} {final_action} 冷却中，剩余{remaining:.0f}s")
        return "COOLDOWN"  # v3.560 P2-1: 返回COOLDOWN标识，区分冷却和成功

    # v3.670: 乐观锁 — 通过冷却检查后立即写入时间戳，防止同一轮循环多路径重复发送
    state[last_signal_key] = current_time

    # v3.641: 连续失败熔断 - 3次连续失败后冻结30分钟
    SS_MAX_CONSECUTIVE_FAILS = 3
    SS_FREEZE_SECONDS = 1800  # 30分钟
    frozen_until = state.get("ss_frozen_until", 0)
    if current_time < frozen_until:
        remaining_freeze = frozen_until - current_time
        log_to_server(f"[SignalStack] {symbol} {final_action} 冻结中(连续失败熔断)，剩余{remaining_freeze:.0f}s")
        return False

    request_id = f"{symbol}_{int(current_time)}_{final_action}"

    if state.get("last_request_id") == request_id:
        log_to_server(f"[SignalStack] Duplicate: {request_id}")
        return True

    cfg = US_STOCK_CONFIG.get(symbol, {})
    qty = int(cfg.get("quantity", 0))
    if qty <= 0:
        log_to_server(f"[SignalStack] {symbol} 未配置quantity或为0，跳过下单")
        return False

    # ── GCC-0256 S2: Schwab直连下单 ───────────────────────────────────────
    if SCHWAB_DIRECT_MODE:
        try:
            from schwab_data_provider import get_provider as _schwab_get_provider

            _schwab_prov = _schwab_get_provider()
            log_to_server(
                f"[Schwab直连] {symbol} {final_action} qty={qty} 提交中..."
            )
            _schwab_result = _schwab_prov.place_equity_order(
                symbol=symbol, action=final_action, quantity=qty
            )

            if _schwab_result.get("success"):
                state["last_request_id"] = request_id
                state["last_order_time"] = current_time
                state[last_signal_key] = current_time
                state["ss_fail_count"] = 0
                if final_action == "BUY":
                    _key003_record_buy_sent(symbol)
                _schwab_oid = _schwab_result.get("order_id", "")
                log_to_server(
                    f"[Schwab直连] {symbol} {final_action} qty={qty} 成功 "
                    f"order_id={_schwab_oid}"
                )
                return True
            else:
                _schwab_err = _schwab_result.get("error", "未知错误")
                log_to_server(f"[Schwab直连] {symbol} {final_action} 失败: {_schwab_err}")
        except Exception as _schwab_e:
            log_to_server(f"[Schwab直连] {symbol} {final_action} 异常: {_schwab_e}")

        # 直连失败: 连续失败计数+熔断
        fail_count = state.get("ss_fail_count", 0) + 1
        state["ss_fail_count"] = fail_count
        if fail_count >= SS_MAX_CONSECUTIVE_FAILS:
            state["ss_frozen_until"] = current_time + SS_FREEZE_SECONDS
            log_to_server(f"[Schwab直连] {symbol} 连续{fail_count}次失败，冻结{SS_FREEZE_SECONDS//60}分钟")
        else:
            log_to_server(f"[Schwab直连] {symbol} 失败({fail_count}/{SS_MAX_CONSECUTIVE_FAILS})")

        # Schwab Token过期检测 — 连续2次失败发邮件
        if fail_count == 2:
            try:
                _ss_alert_key = "ss_reconnect_alert_ts"
                _ss_last_alert = getattr(send_signalstack_order, _ss_alert_key, 0)
                if current_time - _ss_last_alert > 3600:
                    send_email_notification(
                        "⚠️ Schwab直连失败 — 请刷新Token",
                        f"品种: {symbol} {final_action}\n"
                        f"连续失败: {fail_count}次\n\n"
                        f"Schwab Token每7天需重新授权。\n"
                        f"运行: python schwab_data_provider.py 重新授权。\n\n"
                        f"冻结机制: 再失败1次将冻结{SS_FREEZE_SECONDS//60}分钟。"
                    )
                    setattr(send_signalstack_order, _ss_alert_key, current_time)
                    log_to_server(f"[Schwab直连][ALERT] 已发送Token刷新提醒邮件")
            except Exception as _ss_alert_e:
                log_to_server(f"[Schwab直连][ALERT] 邮件发送失败: {_ss_alert_e}")
        return False

    # ── SignalStack webhook 模式 (SCHWAB_DIRECT_MODE=False 时使用) ─────────
    payload = {
        "symbol": symbol,
        "action": "Buy" if final_action == "BUY" else "Sell",
        "order_type": "MARKET",
        "quantity": qty,
        "time_in_force": "GTC",
        "auto_bracket": None,
        "comment": "AI LLM US Stock order",
        "request_id": request_id,
    }

    for attempt in range(3):
        try:
            resp = requests.post(SIGNALSTACK_WEBHOOK_URL, json=payload, timeout=15)
            if 200 <= resp.status_code < 300:
                state["last_request_id"] = request_id
                state["last_order_time"] = current_time
                state[last_signal_key] = current_time
                state["ss_fail_count"] = 0
                if final_action == "BUY":
                    _key003_record_buy_sent(symbol)
                log_to_server(f"[SignalStack] {symbol} {payload['action']} qty={qty} 成功")
                return True
            _ss_body = resp.text[:200] if resp.text else ""
            log_to_server(f"[SignalStack] {symbol} HTTP {resp.status_code} body={_ss_body}")
            if attempt < 2:
                time_module.sleep(2 ** attempt)
        except Exception as e:
            log_to_server(f"[SignalStack] {symbol} Attempt {attempt+1} 失败: {e}")
            if attempt < 2:
                time_module.sleep(2 ** attempt)
                continue
    # v3.641: 连续失败计数+熔断
    fail_count = state.get("ss_fail_count", 0) + 1
    state["ss_fail_count"] = fail_count
    if fail_count >= SS_MAX_CONSECUTIVE_FAILS:
        state["ss_frozen_until"] = current_time + SS_FREEZE_SECONDS
        log_to_server(f"[SignalStack] {symbol} 连续{fail_count}次失败，冻结{SS_FREEZE_SECONDS//60}分钟")
    else:
        log_to_server(f"[SignalStack] {symbol} 失败({fail_count}/{SS_MAX_CONSECUTIVE_FAILS})")

    # v3.680: Schwab连接过期检测 — 连续2次失败发邮件提醒重连
    if fail_count == 2:
        try:
            _ss_alert_key = "ss_reconnect_alert_ts"
            _ss_last_alert = getattr(send_signalstack_order, _ss_alert_key, 0)
            if current_time - _ss_last_alert > 3600:
                send_email_notification(
                    "⚠️ SignalStack连续失败 — 请重连Schwab",
                    f"品种: {symbol} {final_action}\n"
                    f"连续失败: {fail_count}次\n\n"
                    f"Schwab broker连接每7天需重新授权。\n"
                    f"请登录 SignalStack → Connections → 重连 Schwab。\n\n"
                    f"冻结机制: 再失败1次将冻结{SS_FREEZE_SECONDS//60}分钟。"
                )
                setattr(send_signalstack_order, _ss_alert_key, current_time)
                log_to_server(f"[SignalStack][ALERT] 已发送Schwab重连提醒邮件")
        except Exception as _ss_alert_e:
            log_to_server(f"[SignalStack][ALERT] 邮件发送失败: {_ss_alert_e}")
    return False


