_state_locks = {}  # per-symbol locks for thread safety
_state_locks_meta = threading.Lock()  # v2.992: 元锁，保护_state_locks字典的创建

def _get_state_lock(symbol: str):
    """
    获取指定 symbol 的专属锁
    v2.992: 添加元锁保护，解决竞态条件
    """
    with _state_locks_meta:
        if symbol not in _state_locks:
            _state_locks[symbol] = threading.Lock()
        return _state_locks[symbol]

TRADE_HISTORY_PATH = os.path.join(LOG_DIR, "trade_history.json")
