def _sanitize_rhythm_counters(state: dict, symbol: str) -> None:
    """清洗执行节奏计数器的脏数据"""
    # v2.670.1: 添加None检查
    if state is None:
        print(f"[RHYTHM_SANITIZE] {symbol}: state is None, skipping")
        return
    
    dirty = False
    old_buy = state.get("two_buy_used", 0)
    old_sell = state.get("two_sell_used", 0)
    
    if old_buy > 2:
        state["two_buy_used"] = 2
        dirty = True
        print(f"[RHYTHM_SANITIZE] {symbol}: two_buy_used {old_buy} -> 2 (clamped)")
    
    if old_sell > 2:
        state["two_sell_used"] = 2
        dirty = True
        print(f"[RHYTHM_SANITIZE] {symbol}: two_sell_used {old_sell} -> 2 (clamped)")
    
    if old_buy < 0:
        state["two_buy_used"] = 0
        dirty = True
    
    if old_sell < 0:
        state["two_sell_used"] = 0
        dirty = True
    
    # 清理过期幂等记录（保留最近100条）
    idem_dict = state.get("rhythm_idem", {})
    if len(idem_dict) > 100:
        sorted_keys = sorted(idem_dict.keys(), key=lambda k: idem_dict[k], reverse=True)
        keep_keys = sorted_keys[:100]
        state["rhythm_idem"] = {k: idem_dict[k] for k in keep_keys}
        dirty = True
        print(f"[RHYTHM_SANITIZE] {symbol}: cleaned rhythm_idem {len(idem_dict)} -> 100")
    
    if dirty:
        _save_state_to_disk()





def _reset_rhythm_on_sr_change(state: dict, symbol: str, new_sr: dict) -> None:
    """当SR区间变化时，重置执行节奏计数器"""
    # v2.675: 添加None检查
    if state is None:
        print(f"[RHYTHM_RESET] {symbol}: state is None, skipping")
        return
    
    if not new_sr or not isinstance(new_sr, dict):
        return
    
    prev_sr = state.get("prev_sr")
    if not prev_sr or not isinstance(prev_sr, dict):
        # 首次设置SR，不需要重置
        return
    
    # 提取关键SR值
    try:
        old_support = float(prev_sr.get("support", 0))
        old_resistance = float(prev_sr.get("resistance", 0))
        new_support = float(new_sr.get("support", 0))
        new_resistance = float(new_sr.get("resistance", 0))
    except (TypeError, ValueError):
        return
    
    # 判断SR是否发生实质性变化（超过1%视为新SR）
    support_change_pct = abs(new_support - old_support) / max(old_support, 1e-9)
    resistance_change_pct = abs(new_resistance - old_resistance) / max(old_resistance, 1e-9)
    
    SR_CHANGE_THRESHOLD = 0.01  # 1%
    
    if support_change_pct > SR_CHANGE_THRESHOLD or resistance_change_pct > SR_CHANGE_THRESHOLD:
        # SR发生变化，重置节奏计数器
        old_buy = state.get("two_buy_used", 0)
        old_sell = state.get("two_sell_used", 0)
        old_rhythm = state.get("execution_rhythm", "NONE")
        
        state["two_buy_used"] = 0
        state["two_sell_used"] = 0
        state["rhythm_status"] = "READY"
        state["execution_rhythm"] = "NONE"
        state["breakout_confirmed"] = False
        state["zone_return_confirmed"] = False
        
        # 清空本SR周期的幂等记录
        state["rhythm_idem"] = {}
        
        print(f"[RHYTHM_SR_RESET] {symbol}: SR变化 "
              f"support {old_support:.2f}->{new_support:.2f} ({support_change_pct:.2%}), "
              f"resistance {old_resistance:.2f}->{new_resistance:.2f} ({resistance_change_pct:.2%})")
        print(f"[RHYTHM_SR_RESET] {symbol}: 重置计数器 "
              f"two_buy {old_buy}->0, two_sell {old_sell}->0, "
              f"rhythm {old_rhythm}->NONE")
        
        _save_state_to_disk()

def _load_state_from_disk() -> None:
    global symbol_state
    if not os.path.exists(STATE_PATH):
        print("[STATE_LOADED] false, reason: file_not_found")
        return
    try:
        with open(STATE_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            symbol_state = data
            for s in list(symbol_state.keys()):
                if isinstance(symbol_state[s], dict):
                    symbol_state[s] = _ensure_state_fields(symbol_state[s])
            
            # v2.746: 增强OHLCV恢复日志
            print("\n" + "="*60)
            print("[OHLCV_RESTORE] 启动时K线窗口恢复")
            print("="*60)
            ohlcv_restore_count = 0
            ohlcv_total_bars = 0
            for sym_key, state_dict in symbol_state.items():
                if isinstance(state_dict, dict):
                    bars = state_dict.get("ohlcv_bars", [])
                    tv_signals = state_dict.get("ohlcv_tv_signals", [])
                    if bars:
                        window = get_ohlcv_window(sym_key)
                        window.bars = bars
                        if tv_signals:
                            window.tv_signals = tv_signals
                        ohlcv_restore_count += 1
                        ohlcv_total_bars += len(bars)
                        status = "✅" if len(bars) >= 20 else "⚠️ "
                        print(f"  {status} {sym_key}: {len(bars)}根K线 (需20根)")
                    else:
                        print(f"  ❌ {sym_key}: 无K线数据，需要热身")
            
            if ohlcv_restore_count > 0:
                print(f"\n汇总: 恢复 {ohlcv_restore_count} 个symbol，共 {ohlcv_total_bars} 根K线")
            else:
                print(f"\n⚠️  无OHLCV数据可恢复，所有symbol需要热身")
            print("="*60 + "\n")
            
            print(f"[STATE_LOADED] true, from={STATE_PATH}, symbols={len(symbol_state)}")
            
            # v2.675: 启动时健康检查
            print("[HEALTH_CHECK] 检查状态完整性...")
            corrupted_symbols = []
            for sym, state_dict in symbol_state.items():
                if state_dict is None:
                    corrupted_symbols.append(sym)
                    print(f"[HEALTH_CHECK] ⚠️  {sym}: state is None")
            
            if corrupted_symbols:
                print(f"[HEALTH_CHECK] ⚠️  发现 {len(corrupted_symbols)} 个损坏状态，将重新初始化")
                for sym in corrupted_symbols:
                    symbol_state[sym] = {
                        "position": 0,
                        "max_units": 5,
                        "open_buys": [],
                        "open_sells": [],
                    }
                    symbol_state[sym] = _ensure_state_fields(symbol_state[sym])
                _save_state_to_disk()
            else:
                print(f"[HEALTH_CHECK] ✅ 所有状态完整")
            
            
    except Exception as e:
        print("[STATE] load failed:", e)


def _save_state_to_disk() -> None:
    """v2.670: 原子性保存, v2.992: 添加全局锁保护, v2.995: 添加Enum序列化支持, v3.410: Windows文件锁定重试"""
    with _state_lock:
        tmp_path = STATE_PATH + ".tmp"
        try:
            # 保存OHLCV数据
            for sym_key, window in _ohlcv_windows.items():
                if sym_key in symbol_state:
                    symbol_state[sym_key]["ohlcv_bars"] = window.get_bars()
                    symbol_state[sym_key]["ohlcv_tv_signals"] = window.get_tv_signals()

            # v2.995: 自定义JSON编码器处理Enum和其他不可序列化对象
            def json_serializer(obj):
                if isinstance(obj, Enum):
                    return obj.value
                return str(obj)

            with open(tmp_path, "w", encoding="utf-8") as f:
                json.dump(symbol_state, f, ensure_ascii=False, indent=2, default=json_serializer)
                f.flush()
                os.fsync(f.fileno())

            # v3.560 P2-10: 5次os.replace重试，移除remove+rename危险窗口
            import time as _time
            for attempt in range(5):
                try:
                    os.replace(tmp_path, STATE_PATH)
                    break
                except PermissionError:
                    if attempt < 4:
                        _time.sleep(0.1 * (attempt + 1))
                    else:
                        print(f"[CRITICAL] state.json写入失败(5次重试)，保留旧文件")
                        # 清理tmp文件
                        if os.path.exists(tmp_path):
                            try:
                                os.remove(tmp_path)
                            except Exception:
                                pass
                        return

            print(f"[STATE] ✅ Saved ({len(symbol_state)} symbols)")
        except Exception as e:
            print(f"[STATE] ❌ Failed: {e}")
            if os.path.exists(tmp_path):
                try:
                    os.remove(tmp_path)
                except Exception as e2:
                    print(f"[STATE] 删除临时文件失败: {e2}")



# ===================================================================
# 三买三卖（3 Buy / 3 Sell）节奏控制模块 v2.002
# ===================================================================

def detect_reference_zone_from_prev_kline(prev_sr: dict, current_close: float) -> dict:
    """
    从前一根K线的SR信息中提取参考结构区间（v2.025: 缩短至1/3区间）
    
    Args:
        prev_sr: state['prev_sr'] 包含前一根K线的support/mid/resistance
        current_close: 当前K线收盘价
    
    Returns:
        {
            "zone_low": float,
            "zone_high": float,
            "zone_type": "SUPPORT" | "RESISTANCE" | "UNKNOWN",
            "zone_desc": str
        }
    
    改造说明（v2.025）:
        旧逻辑（过于保守）:
            二买区间: [support, mid]
            二卖区间: [mid, resistance]
        
        新逻辑（更激进）:
            二买区间: [support, support + (mid-support)/3]  ← 下方1/3区域
            二卖区间: [resistance - (resistance-mid)/3, resistance]  ← 上方1/3区域
    """
    if not prev_sr or not isinstance(prev_sr, dict):
        return {
            "zone_low": None,
            "zone_high": None,
            "zone_type": "UNKNOWN",
            "zone_desc": "无前序K线参考"
        }
    
    try:
        support = float(prev_sr.get('support', 0) or 0)
        mid = float(prev_sr.get('mid', 0) or 0)
        resistance = float(prev_sr.get('resistance', 0) or 0)
        
        if support <= 0 or resistance <= 0:
            return {
                "zone_low": None,
                "zone_high": None,
                "zone_type": "UNKNOWN",
                "zone_desc": "前序K线SR无效"
            }
        
        # ===== v2.025: 根据当前价格位置动态选择区间 =====
        
        if current_close <= mid:
            # 当前价格在下半区 → 使用二买区间（下方1/3）
            # 旧: [support, mid]
            # 新: [support, support + (mid-support)/3]
            zone_low = support
            zone_high = support + (mid - support) / 3.0
            zone_type = "SUPPORT"
            zone_desc = f"三买区间-下方1/3 ({zone_low:.2f} - {zone_high:.2f})"
        
        else:
            # 当前价格在上半区 → 使用二卖区间（上方1/3）
            # 旧: [mid, resistance]
            # 新: [resistance - (resistance-mid)/3, resistance]
            zone_low = resistance - (resistance - mid) / 3.0
            zone_high = resistance
            zone_type = "RESISTANCE"
            zone_desc = f"三卖区间-上方1/3 ({zone_low:.2f} - {zone_high:.2f})"
        
        return {
            "zone_low": zone_low,
            "zone_high": zone_high,
            "zone_type": zone_type,
            "zone_desc": zone_desc
        }
    except Exception as e:
        return {
            "zone_low": None,
            "zone_high": None,
            "zone_type": "UNKNOWN",
            "zone_desc": f"解析失败: {e}"
        }


def check_breakout_confirmed(current_close: float, reference_zone: dict) -> bool:
    """
    检查是否有效突破参考区间
    
    v2.045: 新增突破距离上限检查
    - 必须突破区间上沿（下限）
    - 不能远离区间（上限5%）
    - 防止追高二买
    
    Args:
        current_close: 当前K线收盘价
        reference_zone: detect_reference_zone_from_prev_kline 返回的结构
    
    Returns:
        True if 突破确认 且 未远离，False otherwise
    """
    if not reference_zone:
        return False
    
    zone_high = reference_zone.get('zone_high')
    if zone_high is None or zone_high <= 0:
        return False
    
    # 下限：必须突破区间上沿
    breakout_threshold_low = zone_high * 1.001  # 0.1% 余量，避免噪音
    
    # 🔥 v2.045: 上限：不能远离区间（防止追高二买）
    breakout_threshold_high = zone_high * (1.0 + 0.03)  # 3% 上限
    
    # 必须同时满足：突破 且 未远离
    is_above_zone = current_close > breakout_threshold_low
    is_not_too_far = current_close <= breakout_threshold_high
    
    if is_above_zone and not is_not_too_far:
        # 日志：价格已远离二买区间
        print(f"[TWO_BUY] 价格{current_close:.2f}已远离区间上沿{zone_high:.2f} "
              f"({((current_close-zone_high)/zone_high*100):.1f}% > {TWO_BUY_MAX_DISTANCE_PCT*100}%)，不触发二买")
    
    return is_above_zone and is_not_too_far


def check_zone_return_confirmed(current_close: float, reference_zone: dict) -> bool:
    """
    检查是否回到参考区间内
    
    v2.045: 新增距离下限检查（二卖对称）
    - 必须回到区间下沿（上限）
    - 不能远离区间（下限5%）
    - 防止追空二卖
    
    Args:
        current_close: 当前K线收盘价
        reference_zone: 参考区间
    
    Returns:
        True if 回到区间内 且 未远离，False otherwise
    """
    if not reference_zone:
        return False
    
    zone_low = reference_zone.get('zone_low')
    zone_high = reference_zone.get('zone_high')
    
    if zone_low is None or zone_high is None:
        return False
    
    # 🔥 v2.045: 对称处理二卖距离限制
    
    # 上限：必须回到区间内
    is_below_zone_high = current_close <= zone_high
    
    # 下限：不能远离区间下沿（防止追空二卖）
    zone_return_threshold_low = zone_low * (1.0 - 0.03)  # -3% 下限
    is_not_too_far_below = current_close >= zone_return_threshold_low
    
    # 回到区间：价格在 [zone_low * 0.95, zone_high] 范围内
    is_in_zone = zone_low <= current_close <= zone_high
    
    if is_below_zone_high and not is_not_too_far_below:
        # 日志：价格已远离二卖区间
        print(f"[TWO_SELL] 价格{current_close:.2f}已远离区间下沿{zone_low:.2f} "
              f"({((zone_low-current_close)/zone_low*100):.1f}% > {TWO_SELL_MAX_DISTANCE_PCT*100}%)，不触发二卖")
    
    return is_in_zone or (is_below_zone_high and is_not_too_far_below)


def check_high_downgrade(current_high: float, prev_high_in_zone: float) -> bool:
    """
    检查区间内高点是否降低
    
    Args:
        current_high: 当前K线最高价
        prev_high_in_zone: 区间内前序最高价
    
    Returns:
        True if 高点降低，False otherwise
    """
    if prev_high_in_zone is None or prev_high_in_zone <= 0:
        return False
    
    # 高点降低判定：当前高点 < 前序高点
    return current_high < prev_high_in_zone * 0.999  # 0.1% 余量


def compute_rhythm_status(
    state: dict,
    current_close: float,
    current_high: float,
    final_action_before_rhythm: str,
    dynamic_thresholds: dict = None,  # v2.650新增
) -> dict:
    """
    计算当前执行节奏状态
    
    Args:
        state: symbol_state
        current_close: 当前K线收盘价
        current_high: 当前K线最高价
        final_action_before_rhythm: 经过其他Gate后的动作（进入节奏判断前）
    
    Returns:
        {
            "execution_rhythm": "TWO_BUY" | "TWO_SELL" | "NONE",
            "rhythm_status": "READY" | "ACTIVE" | "EXHAUSTED" | "INACTIVE",
            "two_buy_used": int,
            "two_sell_used": int,
            "reference_zone": dict,
            "structure_confirmed": {
                "breakout_confirmed": bool,
                "zone_return_confirmed": bool,
                "high_downgrade_confirmed": bool
            },
            "rhythm_effect": "ALLOW_BUY" | "BLOCK_BUY" | "ALLOW_SELL" | "BLOCK_SELL" | "NEUTRAL",
            "block_reason": str or None
        }
    """
    # 初始化返回结构
    result = {
        "execution_rhythm": "NONE",
        "rhythm_status": "INACTIVE",
        "two_buy_used": state.get('two_buy_used', 0),
        "two_sell_used": state.get('two_sell_used', 0),
        "reference_zone": None,
        "structure_confirmed": {
            "breakout_confirmed": False,
            "zone_return_confirmed": False,
            "high_downgrade_confirmed": False
        },
        "rhythm_effect": "NEUTRAL",
        "block_reason": None
    }

    # 获取参考区间
    prev_sr = state.get('prev_sr')
    reference_zone = detect_reference_zone_from_prev_kline(prev_sr, current_close)
    result["reference_zone"] = reference_zone

    # 检查结构确认
    breakout_ok = check_breakout_confirmed(current_close, reference_zone)
    zone_return_ok = check_zone_return_confirmed(current_close, reference_zone)
    
    # ========================================================================
    # v2.190: 多条件节奏计数器重置
    # ========================================================================
    # 问题: 只有 SR 变化才清零，导致长期震荡时永久锁死
    # 改进: 添加反向结构和远离区间的清零条件
    # ========================================================================
    
    prev_rhythm = state.get("execution_rhythm", "NONE")
    two_buy_used = state.get("two_buy_used", 0)
    two_sell_used = state.get("two_sell_used", 0)
    
    # 条件 1: 反向结构重置 (最重要) ⭐⭐⭐⭐⭐
    # 从二卖切换到二买时，清零二卖
    if breakout_ok and prev_rhythm == "TWO_SELL":
        if two_sell_used > 0:
            state["two_sell_used"] = 0
            print(f"[RHYTHM_RESET] 反向结构: 三卖 → 三买，清零三卖计数器 ({two_sell_used} → 0)")
    
    # 从二买切换到二卖时，清零二买
    elif zone_return_ok and prev_rhythm == "TWO_BUY":
        if two_buy_used > 0:
            state["two_buy_used"] = 0
            print(f"[RHYTHM_RESET] 反向结构: 三买 → 三卖，清零三买计数器 ({two_buy_used} → 0)")
    
    # 条件 2: 远离区间重置 (防止永久锁死) - v2.650 ATR自适应
    if reference_zone:
        zone_low = reference_zone.get("low", 0)
        zone_high = reference_zone.get("high", 0)
        
        # v2.650: 获取动态重置阈值
        if dynamic_thresholds and dynamic_thresholds.get("status") == "SUCCESS":
            reset_threshold_pct = dynamic_thresholds["dynamic_rhythm_reset"]
            is_adaptive = True
            vol_mult = dynamic_thresholds.get("volatility_multiplier", 1.0)
        else:
            reset_threshold_pct = 0.10  # 回退到v2.630固定值
            is_adaptive = False
            vol_mult = 1.0
        
        upper_multiplier = 1.0 + reset_threshold_pct
        lower_multiplier = 1.0 - reset_threshold_pct
        
        # v2.370: 只在计数器已用完时才触发远离重置（避免过度重置）
        if two_buy_used >= 3 or two_sell_used >= 3:
            # v2.650: 使用动态阈值 - 远离上沿
            if zone_high > 0 and current_close > zone_high * upper_multiplier:
                state["two_buy_used"] = 0
                state["two_sell_used"] = 0
                distance_pct = (current_close / zone_high - 1) * 100
                
                adaptive_tag = f"[ATR{reset_threshold_pct*100:.1f}%]" if is_adaptive else "[固定10%]"
                print(f"[RHYTHM_RESET] 远离区间上沿 ({distance_pct:.1f}%){adaptive_tag}，重置计数器")
            
            # v2.650: 使用动态阈值 - 远离下沿
            elif zone_low > 0 and current_close < zone_low * lower_multiplier:
                state["two_buy_used"] = 0
                state["two_sell_used"] = 0
                distance_pct = (current_close / zone_low - 1) * 100
                
                adaptive_tag = f"[ATR{reset_threshold_pct*100:.1f}%]" if is_adaptive else "[固定10%]"
                print(f"[RHYTHM_RESET] 远离区间下沿 ({distance_pct:.1f}%){adaptive_tag}，重置计数器")
    
    # 重新读取（可能已被修改）
    two_buy_used = state.get("two_buy_used", 0)
    two_sell_used = state.get("two_sell_used", 0)
    
    # ========================================================================
    
    result["structure_confirmed"]["breakout_confirmed"] = breakout_ok
    result["structure_confirmed"]["zone_return_confirmed"] = zone_return_ok
    
    # ===== 二买规则 =====
    if breakout_ok and final_action_before_rhythm == "BUY":
        two_buy_used = result["two_buy_used"]
        
        result["execution_rhythm"] = "TWO_BUY"
        
        if two_buy_used >= 3:
            result["rhythm_status"] = "EXHAUSTED"
            
            # v2.210: 强信号豁免机制
            # 检查是否为强信号：STRONG_BUY、Trust L2、L2 主动开仓
            exec_bias = state.get("exec_bias", "")
            fallback_reasons = state.get("fallback_reasons", [])
            
            is_strong_signal = (
                exec_bias in ["STRONG_BUY"] or
                any("TRUST_L2_BUY" in r for r in fallback_reasons) or
                any("L2_INITIATE_BUY" in r for r in fallback_reasons)
            )
            
            if is_strong_signal:
                # 强信号：豁免限制
                result["rhythm_effect"] = "ALLOW_BUY"
                result["block_reason"] = "三买已用完(3/3)，但检测到强信号，豁免执行"
                print(f"[RHYTHM_OVERRIDE] 三买3/3，但强信号豁免: exec_bias={exec_bias}, "
                      f"trust_l2={'TRUST_L2_BUY' in str(fallback_reasons)}, "
                      f"l2_initiate={'L2_INITIATE_BUY' in str(fallback_reasons)}")
            else:
                # 普通信号：正常限制
                result["rhythm_effect"] = "BLOCK_BUY"
                result["block_reason"] = "三买结构已完成（3/3），本轮结构内不再允许新增BUY"
        elif two_buy_used == 2:
            result["rhythm_status"] = "ACTIVE"
            result["rhythm_effect"] = "ALLOW_BUY"
            # 注意：本次允许，但会变成3/3
        elif two_buy_used == 1:
            result["rhythm_status"] = "ACTIVE"
            result["rhythm_effect"] = "ALLOW_BUY"
            # 注意：本次允许，但会变成2/2
        else:
            result["rhythm_status"] = "READY"
            result["rhythm_effect"] = "ALLOW_BUY"
    
    # ===== 二卖规则 =====
    elif zone_return_ok and final_action_before_rhythm == "SELL":
        two_sell_used = result["two_sell_used"]
        
        # 简化版：只要回到区间就视为失败结构
        # 实际可以加上 high_downgrade 判断
        result["execution_rhythm"] = "TWO_SELL"
        
        if two_sell_used >= 3:
            result["rhythm_status"] = "EXHAUSTED"
            
            # v2.210: 强信号豁免机制
            # 检查是否为强信号：STRONG_SELL、Trust L2、L2 主动开仓
            exec_bias = state.get("exec_bias", "")
            fallback_reasons = state.get("fallback_reasons", [])
            
            is_strong_signal = (
                exec_bias in ["STRONG_SELL"] or
                any("TRUST_L2_SELL" in r for r in fallback_reasons) or
                any("L2_INITIATE_SELL" in r for r in fallback_reasons)
            )
            
            if is_strong_signal:
                # 强信号：豁免限制
                result["rhythm_effect"] = "ALLOW_SELL"
                result["block_reason"] = "三卖已用完(3/3)，但检测到强信号，豁免执行"
                print(f"[RHYTHM_OVERRIDE] 三卖3/3，但强信号豁免: exec_bias={exec_bias}, "
                      f"trust_l2={'TRUST_L2_SELL' in str(fallback_reasons)}, "
                      f"l2_initiate={'L2_INITIATE_SELL' in str(fallback_reasons)}")
            else:
                # 普通信号：正常限制
                result["rhythm_effect"] = "BLOCK_SELL"
                result["block_reason"] = "三卖次数已用尽（3/3），剩余信号仅允许HOLD"
        elif two_sell_used == 2:
            result["rhythm_status"] = "ACTIVE"
            result["rhythm_effect"] = "ALLOW_SELL"
            # 注意：本次允许，但会变成3/3
        elif two_sell_used == 1:
            result["rhythm_status"] = "ACTIVE"
            result["rhythm_effect"] = "ALLOW_SELL"
        else:
            result["rhythm_status"] = "READY"
            result["rhythm_effect"] = "ALLOW_SELL"

    return result


# =========================================================
# v2.440: SR 变化触发配额重置
# =========================================================

def update_rhythm_quota_on_sr_change(state, prev_sr, current_price):
    """
    基于 prev_sr 的实质变化自动重置节奏门配额
    
    v2.440 核心改进:
      - 解决无对冲功能导致的配额长期锁死问题
      - 当 SR 结构发生实质性变化时自动重置
      - 基于市场结构，不依赖仓位清零
      - 完全自动，适应不同品种和周期
    
    关键设计:
      - 使用 prev_sr (前一根K线的SR，固定值)
      - 不使用 curr_sr (当前K线的SR，一直在变)
      - 只在 prev_sr 本身发生变化时触发
      - 避免死循环，保持配额限制有效性
    
    触发条件:
      1. SR 边界移动超过阈值 (10% 区间范围)
      2. SR 区间范围变化超过 15%
      3. 价格突破旧 SR 边界 (0.5% 缓冲)
    
    Args:
        state: 交易状态字典
        prev_sr: 前一根K线的SR (用于节奏门的固定SR)
        current_price: 当前价格
        
    Returns:
        (should_reset, reset_reason): (是否重置, 重置原因)
    """
    
    # ===== 1. 获取上次重置时的 SR 基线 =====
    baseline_sr = state.get('rhythm_sr_baseline')
    
    # 首次运行，初始化基线
    if not baseline_sr:
        state['rhythm_sr_baseline'] = {
            'support': prev_sr['support'],
            'resistance': prev_sr['resistance'],
            'mid': prev_sr['mid'],
            'timestamp': state.get('current_timestamp', 0),
            'bar_index': state.get('bar_index', 0)
        }
        print(f"[RHYTHM_SR] 初始化 SR 基线: support={prev_sr['support']:.2f}, resistance={prev_sr['resistance']:.2f}")
        return False, None
    
    # ===== 2. 计算 prev_sr 的变化 =====
    # 注意: 比较的是 "当前的 prev_sr" vs "上次重置时的 prev_sr"
    
    support_shift = abs(prev_sr['support'] - baseline_sr['support'])
    resistance_shift = abs(prev_sr['resistance'] - baseline_sr['resistance'])
    
    # 计算区间范围
    baseline_range = baseline_sr['resistance'] - baseline_sr['support']
    current_range = prev_sr['resistance'] - prev_sr['support']
    
    # 阈值计算
    boundary_threshold = baseline_range * 0.10  # 10% 的基线区间
    
    # 区间范围变化百分比
    range_change_pct = abs(current_range - baseline_range) / baseline_range if baseline_range > 0 else 0
    
    # ===== 3. 判断是否应该重置 =====
    should_reset = False
    reset_reason = None
    reset_details = {}
    
    # 条件 1: SR 边界移动超过阈值
    if support_shift > boundary_threshold or resistance_shift > boundary_threshold:
        should_reset = True
        reset_reason = "SR_BOUNDARY_SHIFT"
        reset_details = {
            'support_shift': support_shift,
            'resistance_shift': resistance_shift,
            'threshold': boundary_threshold,
            'baseline_range': baseline_range
        }
    
    # 条件 2: 区间范围变化超过 15%
    elif range_change_pct > 0.15:
        should_reset = True
        reset_reason = "SR_RANGE_CHANGE"
        reset_details = {
            'range_change_pct': range_change_pct,
            'baseline_range': baseline_range,
            'current_range': current_range
        }
    
    # 条件 3: 价格突破旧 SR 边界
    elif current_price > baseline_sr['resistance'] * 1.005:  # 0.5% 缓冲
        should_reset = True
        reset_reason = "BREAKOUT_RESISTANCE"
        reset_details = {
            'current_price': current_price,
            'old_resistance': baseline_sr['resistance'],
            'breakout_pct': ((current_price / baseline_sr['resistance']) - 1) * 100
        }
    
    elif current_price < baseline_sr['support'] * 0.995:  # 0.5% 缓冲
        should_reset = True
        reset_reason = "BREAKDOWN_SUPPORT"
        reset_details = {
            'current_price': current_price,
            'old_support': baseline_sr['support'],
            'breakdown_pct': ((baseline_sr['support'] / current_price) - 1) * 100
        }
    
    # ===== 4. 执行重置 =====
    if should_reset:
        old_buy = state.get('two_buy_used', 0)
        old_sell = state.get('two_sell_used', 0)
        
        # 重置配额
        state['two_buy_used'] = 0
        state['two_sell_used'] = 0
        
        # 重置节奏状态
        state['execution_rhythm'] = 'NONE'
        state['rhythm_status'] = 'READY'
        state['breakout_confirmed'] = False
        state['zone_return_confirmed'] = False
        
        # 更新 SR 基线为当前的 prev_sr
        state['rhythm_sr_baseline'] = {
            'support': prev_sr['support'],
            'resistance': prev_sr['resistance'],
            'mid': prev_sr['mid'],
            'timestamp': state.get('current_timestamp', 0),
            'bar_index': state.get('bar_index', 0)
        }
        
        # 详细日志
        print(f"[RHYTHM_SR] ✓ SR 结构变化，配额重置")
        print(f"[RHYTHM_SR]   触发条件: {reset_reason}")
        
        if reset_reason == "SR_BOUNDARY_SHIFT":
            print(f"[RHYTHM_SR]   support_shift: {reset_details['support_shift']:.2f}")
            print(f"[RHYTHM_SR]   resistance_shift: {reset_details['resistance_shift']:.2f}")
            print(f"[RHYTHM_SR]   threshold: {reset_details['threshold']:.2f} (10% of {reset_details['baseline_range']:.2f})")
        
        elif reset_reason == "SR_RANGE_CHANGE":
            print(f"[RHYTHM_SR]   range_change: {reset_details['range_change_pct']*100:.1f}%")
            print(f"[RHYTHM_SR]   baseline_range: {reset_details['baseline_range']:.2f}")
            print(f"[RHYTHM_SR]   current_range: {reset_details['current_range']:.2f}")
        
        elif reset_reason in ["BREAKOUT_RESISTANCE", "BREAKDOWN_SUPPORT"]:
            print(f"[RHYTHM_SR]   current_price: {reset_details['current_price']:.2f}")
            if reset_reason == "BREAKOUT_RESISTANCE":
                print(f"[RHYTHM_SR]   old_resistance: {reset_details['old_resistance']:.2f}")
                print(f"[RHYTHM_SR]   breakout: +{reset_details['breakout_pct']:.2f}%")
            else:
                print(f"[RHYTHM_SR]   old_support: {reset_details['old_support']:.2f}")
                print(f"[RHYTHM_SR]   breakdown: -{reset_details['breakdown_pct']:.2f}%")
        
        print(f"[RHYTHM_SR]   三买配额: {old_buy}/3 → 0/3")
        print(f"[RHYTHM_SR]   三卖配额: {old_sell}/3 → 0/3")
        print(f"[RHYTHM_SR]   旧基线 SR: support={baseline_sr['support']:.2f}, resistance={baseline_sr['resistance']:.2f}")
        print(f"[RHYTHM_SR]   新基线 SR: support={prev_sr['support']:.2f}, resistance={prev_sr['resistance']:.2f}")
        
        # 构造详细的重置原因字符串
        reason_str = f"{reset_reason}"
        if reset_reason == "SR_BOUNDARY_SHIFT":
            reason_str += f" (support: {reset_details['support_shift']:.2f}, resist: {reset_details['resistance_shift']:.2f}, threshold: {reset_details['threshold']:.2f})"
        elif reset_reason == "SR_RANGE_CHANGE":
            reason_str += f" ({reset_details['range_change_pct']*100:.1f}%, {reset_details['baseline_range']:.2f} → {reset_details['current_range']:.2f})"
        elif reset_reason == "BREAKOUT_RESISTANCE":
            reason_str += f" ({reset_details['current_price']:.2f} > {reset_details['old_resistance']:.2f})"
        elif reset_reason == "BREAKDOWN_SUPPORT":
            reason_str += f" ({reset_details['current_price']:.2f} < {reset_details['old_support']:.2f})"
        
        return True, reason_str
    
    # 未触发重置
    return False, None


# [DEPRECATED v2.910] 此函数结果被final_decision_engine覆盖，实际无效
def apply_rhythm_gate(
    final_action: str,
    rhythm_status: dict,
    state: dict
) -> tuple:
    """
    v2.035: 应用节奏Gate，三买三卖拥有最高决策权限
    
    【最高权限规则】
    - TWO_BUY + ALLOW_BUY  → 强制BUY（覆盖所有其他Gate）
    - TWO_SELL + ALLOW_SELL → 强制SELL（覆盖所有其他Gate）
    - 其他情况按原逻辑执行
    
    Args:
        final_action: 经过其他Gate后的动作
        rhythm_status: compute_rhythm_status 返回的结果
        state: symbol_state（会修改计数器）
    
    Returns:
        (new_action, gate_log)
    """
    
    original_action = final_action
    rhythm_effect = rhythm_status.get('rhythm_effect', 'NEUTRAL')
    execution_rhythm = rhythm_status.get('execution_rhythm', 'NONE')
    
    gate_log = {
        "applied": True,
        "pass": True,
        "original_action": original_action,
        "new_action": original_action,
        "rhythm_type": execution_rhythm,
        "rhythm_status": rhythm_status.get('rhythm_status'),
        "block_reason": rhythm_status.get('block_reason'),
        "supreme_override": False,  # v2.035: 标记是否使用最高权限
    }
    
    # ========== v2.035: 最高权限判定 ==========
    # 二买信号 + 允许买入 → 强制BUY（无视原始动作）
    if execution_rhythm == "TWO_BUY" and rhythm_effect == "ALLOW_BUY":
        if original_action != "BUY":
            gate_log["supreme_override"] = True
            gate_log["override_reason"] = f"TWO_BUY最高权限: {original_action} → BUY"
            gate_log["new_action"] = "BUY"
            print(f"[RHYTHM SUPREME] TWO_BUY强制覆盖: {original_action} → BUY")
            return "BUY", gate_log
        else:
            # 原本就是BUY，标记为最高权限确认
            gate_log["supreme_override"] = True
            gate_log["override_reason"] = "TWO_BUY最高权限确认"
            gate_log["will_increment"] = "two_buy_used"
            return "BUY", gate_log
    
    # 二卖信号 + 允许卖出 → 强制SELL（无视原始动作）
    if execution_rhythm == "TWO_SELL" and rhythm_effect == "ALLOW_SELL":
        if original_action != "SELL":
            gate_log["supreme_override"] = True
            gate_log["override_reason"] = f"TWO_SELL最高权限: {original_action} → SELL"
            gate_log["new_action"] = "SELL"
            print(f"[RHYTHM SUPREME] TWO_SELL强制覆盖: {original_action} → SELL")
            return "SELL", gate_log
        else:
            # 原本就是SELL，标记为最高权限确认
            gate_log["supreme_override"] = True
            gate_log["override_reason"] = "TWO_SELL最高权限确认"
            gate_log["will_increment"] = "two_sell_used"
            return "SELL", gate_log
    
    # ========== 原有逻辑：拦截规则 ==========
    # 如果已经是HOLD，不需要节奏判断
    if original_action == "HOLD":
        gate_log["applied"] = False
        gate_log["reason"] = "original_action_is_hold"
        return original_action, gate_log
    
    # 应用节奏拦截（仅在非最高权限时生效）
    if rhythm_effect == "BLOCK_BUY" and original_action == "BUY":
        gate_log["pass"] = False
        gate_log["new_action"] = "HOLD"
        return "HOLD", gate_log
    
    if rhythm_effect == "BLOCK_SELL" and original_action == "SELL":
        gate_log["pass"] = False
        gate_log["new_action"] = "HOLD"
        return "HOLD", gate_log
    
    # 允许执行（非最高权限的普通允许）
    if rhythm_effect == "ALLOW_BUY" and original_action == "BUY":
        gate_log["pass"] = True
        gate_log["will_increment"] = "two_buy_used"
    
    if rhythm_effect == "ALLOW_SELL" and original_action == "SELL":
        gate_log["pass"] = True
        gate_log["will_increment"] = "two_sell_used"
    
    return original_action, gate_log

def get_rule_tier_label(confidence: float) -> str:
    """
    根据Grid规则置信度返回质量等级标签
    """
    if confidence >= 0.75:
        return "TIER_1 (GOLD)"
    elif confidence >= 0.60:
        return "TIER_2 (SILVER)"
    elif confidence >= 0.45:
        return "TIER_3 (BRONZE)"
    else:
        return "TIER_4 (IRON)"

def get_grid_rule_stats_text(grid_key) -> str:
    """
    获取Grid规则的历史统计信息文本
    """
    try:
        if grid_key is None:
            return "N/A"
        
        tracker = get_grid_tracker()
        stats = tracker.get_rule_stats(grid_key)
        
        if stats is None:
            return "No historical data"
        
        wins = stats.get('wins', 0)
        total = stats.get('total', 0)
        win_rate = stats.get('win_rate', 0.0)
        
        return f"Wins={wins}/{total}, WinRate={win_rate:.1%}"
    except Exception as e:
        return f"Error: {str(e)}"

def get_state_for_symbol(symbol: str) -> dict:
    with _state_lock:
        if symbol not in symbol_state:
            symbol_state[symbol] = {
                "position_units": 0,
                "buy_count": 0,
                "sell_count": 0,
                "cycle_id": 1,
                "rally_active": False,
                "rally_bars": 0,
                "rally_entry_level": None,
                "open_buys": [],
                "open_sells": [],
                "cycle_realized_pnl": 0.0,
                "cycle_fees": 0.0,
                "cycle_cost_basis": 0.0,
                "cycle_trades": 0,
                "signal_buy_count": 0,
                "signal_sell_count": 0,
                "actual_buy_count": 0,
                "actual_sell_count": 0,
                "wyckoff_phase_code": "UNCLEAR",
                "phase_buy_count": 0,
                "phase_sell_count": 0,
                "bear_rebound_buy_count": 0,
                "phase_short_used": 0,
                "breakout_long_used": 0,
                "breakout_short_used": 0,
                "prev_sr": None,
                "wyckoff_phase_age_bars": 0,

                # === v2.002: 三买三卖节奏控制 ===
                "two_buy_used": 0,              # 当前二买周期已用次数
                "two_sell_used": 0,             # 当前二卖周期已用次数
                "rhythm_reference_zone": None,   # 参考结构区间
                "rhythm_breakout_bar": None,     # 突破确认K线索引
                "rhythm_zone_return_bar": None,  # 回到区间K线索引

            }
            _save_state_to_disk()
        else:
            symbol_state[symbol] = _ensure_state_fields(symbol_state[symbol])
            # v2.670.1: 确保state非None
            if symbol in symbol_state and symbol_state[symbol] is not None:
                _sanitize_rhythm_counters(symbol_state[symbol], symbol)
            else:
                print(f"[STATE] {symbol}: state is None or missing, initializing...")
        return symbol_state[symbol]


# =========================================================
# v3.496: 美股盈亏级别计算 - 动态策略调整
# =========================================================
def get_pnl_level(symbol: str) -> tuple:
    """
    v3.496: 计算股票盈亏级别，用于动态调整交易策略

    返回: (级别, 盈亏百分比)
    级别:
        "normal"  - 亏损<20%: 正常策略
        "warning" - 亏损20-35%: 强制高抛低吸模式
        "severe"  - 亏损>35%: 降低仓位上限，只允许低位加仓
    """
    state = get_state_for_symbol(symbol)
    if not state:
        return ("normal", 0.0)

    cycle_realized_pnl = state.get("cycle_realized_pnl", 0)
    cycle_cost_basis = state.get("cycle_cost_basis", 0)

    if cycle_cost_basis <= 0:
        return ("normal", 0.0)

    pnl_pct = (cycle_realized_pnl / cycle_cost_basis) * 100

    if pnl_pct < -35:
        return ("severe", pnl_pct)
    elif pnl_pct < -20:
        return ("warning", pnl_pct)
    else:
        return ("normal", pnl_pct)


def get_max_position_units(symbol: str, is_stock: bool = False) -> int:
    """
    v3.496: 获取最大仓位单位，严重亏损股票降低仓位上限
    v3.661: PARAM_YAML品种参数化
    """
    base_max = get_symbol_param(symbol, "risk", "max_position_units", default=2)

    if is_stock:
        pnl_level, _ = get_pnl_level(symbol)
        if pnl_level == "severe":
            return 1  # 严重亏损股票最多1个单位

    return base_max


# ============================================================================
# v3.663 KEY-003: 价值分析后5名 BUY 限制 (每天最多买1次, 卖不限)
# ============================================================================
_key003_bottom_stocks: list = []           # 当前后5名股票列表
_KEY003_BOTTOM_N = 5                       # 排名后N名
_KEY003_MAX_POSITION = 4                   # v3.662: 后5名仓位上限(不允许满仓, 买不限次数)

def _key003_load_bottom_stocks() -> list:
    """从 state/value_analysis_latest.json 读取排名后5名美股"""
    global _key003_bottom_stocks
    try:
        import json as _json003
        va_path = os.path.join("state", "value_analysis_latest.json")
        if not os.path.exists(va_path):
            return _key003_bottom_stocks
        with open(va_path, "r", encoding="utf-8") as f:
            data = _json003.load(f)
        results = data.get("results", [])
        # 过滤有效结果(有composite_score且非加密)
        valid = [r for r in results if "composite_score" in r
                 and not r["ticker"].endswith("USDC")]
        # 按composite_score升序(最差在前), 取后N名
        valid.sort(key=lambda x: x["composite_score"])
        old_bottom = set(_key003_bottom_stocks)
        _key003_bottom_stocks = [r["ticker"] for r in valid[:_KEY003_BOTTOM_N]]
        new_bottom = set(_key003_bottom_stocks)
        all_tickers = set(r["ticker"] for r in valid)

        # v3.662: 同步更新state中的max_units
        global symbol_state
        for sym in all_tickers:
            if sym in symbol_state:
                if sym in new_bottom:
                    symbol_state[sym]["max_units"] = _KEY003_MAX_POSITION
                else:
                    symbol_state[sym]["max_units"] = 5  # 恢复默认
        # 日志: 显示变化
        added = new_bottom - old_bottom
        removed = old_bottom - new_bottom
        change_log = ""
        if added:
            change_log += f" 新增:{list(added)}"
        if removed:
            change_log += f" 移出:{list(removed)}"
        log_to_server(f"[KEY-003][VALUE-GUARD] 后{_KEY003_BOTTOM_N}名更新: {_key003_bottom_stocks} max_units={_KEY003_MAX_POSITION}{change_log}")
    except Exception as e:
        log_to_server(f"[KEY-003][VALUE-GUARD] 加载排名异常: {e}")
    return _key003_bottom_stocks

def _key003_check_buy_allowed(symbol: str) -> tuple:
    """
    v3.662: 检查BUY是否允许。返回 (allowed: bool, reason: str)
    后5名仓位上限4, 买入次数不限, 卖不限。
    """
    # 不在后5名 → 不限制
    if symbol not in _key003_bottom_stocks:
        return (True, "")

    # 后5名仓位上限
    _state003 = get_state_for_symbol(symbol)
    _pos003 = _state003.get("position_units", 0) if _state003 else 0
    if _pos003 >= _KEY003_MAX_POSITION:
        return (False, f"KEY-003后{_KEY003_BOTTOM_N}名仓位上限{_KEY003_MAX_POSITION}: {symbol}当前仓位{_pos003}")

    return (True, "")

def _key003_record_buy_sent(symbol: str) -> None:
    """v3.662: 后5名买入记录(仅日志, 不限次数)"""
    if symbol in _key003_bottom_stocks:
        log_to_server(f"[KEY-003][VALUE-GUARD] {symbol} BUY执行(后{_KEY003_BOTTOM_N}名, 仓位上限{_KEY003_MAX_POSITION})")

def _key003_run_daily_batch() -> None:
    """收盘后运行价值分析批量评估, 更新后5名列表"""
    try:
        from value_analysis.main import run_batch_query
        from datetime import datetime
        from zoneinfo import ZoneInfo
        today = datetime.now(ZoneInfo("America/New_York")).strftime("%Y-%m-%d")
        stock_symbols = [s for s in US_STOCK_CONFIG.keys()]
        log_to_server(f"[KEY-003][DAILY-BATCH] 开始收盘价值分析: {len(stock_symbols)}只")
        run_batch_query(
            tickers=stock_symbols,
            as_of=today,
            pretty=False,
            source="live",   # v3.678: live模式(OpenBB失败自动回落yfinance), 避免template数据失效KEY-003
            strict_live=False,
        )
        _key003_load_bottom_stocks()
        log_to_server(f"[KEY-003][DAILY-BATCH] 完成, 后{_KEY003_BOTTOM_N}名: {_key003_bottom_stocks}")
    except Exception as e:
        log_to_server(f"[KEY-003][DAILY-BATCH] 异常: {e}")


# ──────────────────────────────────────────────
# KEY-005: 行为金融数据采集管线 (OpenBB + 公开API)
# ──────────────────────────────────────────────
_KEY005_CRYPTO_MAP = {
    "BTCUSDC": "BTC-USD",   # Coinbase Exchange product ID
    "ETHUSDC": "ETH-USD",
    "SOLUSDC": "SOL-USD",
    "ZECUSDC": "ZEC-USD",
}

def _key005_fetch_all_sources():
    """v3.665: OpenBB+公开API采集行为金融数据源, 写入state/behavior_sources/"""
    import json as _j5
    import os as _os5
    from datetime import datetime as _dt5, timedelta as _td5
    from urllib.request import urlopen as _urlopen5
    from urllib.error import URLError as _URLError5

    base = _os5.path.join("state", "behavior_sources")
    _os5.makedirs(base, exist_ok=True)
    _now_str = _dt5.now().isoformat()
    _fg_value = 50.0  # fallback for herding proxy

    # ── 1. VIX (OpenBB, 失败时用默认值27.5) ──
    # v3.672: openbb失败时fallback yfinance直连
    _vix_val = 27.5  # 中性默认 (VIX 27.5 = 适度波动)
    try:
        from openbb import obb
        _vix_hist = obb.equity.price.historical("^VIX", provider="yfinance")
        if _vix_hist and hasattr(_vix_hist, "results") and _vix_hist.results:
            _vix_val = float(_vix_hist.results[-1].close)
        log_to_server(f"[KEY-005] VIX={_vix_val:.1f} (openbb)")
    except Exception as _e_openbb:
        try:
            import yfinance as _yf5
            _vix_h = _yf5.Ticker("^VIX").history(period="2d")
            if not _vix_h.empty:
                _vix_val = float(_vix_h["Close"].iloc[-1])
            log_to_server(f"[KEY-005] VIX={_vix_val:.1f} (yfinance fallback)")
        except Exception as _e_yf:
            log_to_server(f"[KEY-005] VIX采集失败(用默认{_vix_val:.1f}): openbb={_e_openbb} yf={_e_yf}")
    try:
        with open(_os5.path.join(base, "vix.json"), "w") as _f:
            _j5.dump({"value": _vix_val, "updated": _now_str}, _f)
    except Exception:
        pass

    # ── 2. Fear & Greed (alternative.me 公开API, 加密市场) ──
    # v3.668: 无论采集成功/失败，都写入磁盘
    try:
        _resp = _urlopen5("https://api.alternative.me/fng/", timeout=15)
        _fg_raw = _j5.loads(_resp.read())
        _fg_arr = _fg_raw.get("data", []) if isinstance(_fg_raw, dict) else []
        if _fg_arr and isinstance(_fg_arr[0], dict):
            _fg_value = float(_fg_arr[0].get("value", 50))
        log_to_server(f"[KEY-005] FearGreed={_fg_value:.0f}")
    except Exception as _e:
        log_to_server(f"[KEY-005] FearGreed采集失败(用默认{_fg_value:.0f}): {_e}")
    try:
        with open(_os5.path.join(base, "fear_greed.json"), "w") as _f:
            _j5.dump({"value": _fg_value, "updated": _now_str}, _f)
    except Exception:
        pass

    # ── 3. Funding Rate (Coinbase无公开funding, 全品种中性=0) ──
    _funding = {"symbols": {}}
    for _s in list(_KEY005_CRYPTO_MAP.keys()) + list(US_STOCK_CONFIG.keys()):
        _funding["symbols"][_s] = 0.0
    _funding["updated"] = _now_str
    try:
        with open(_os5.path.join(base, "funding_rate.json"), "w") as _f:
            _j5.dump(_funding, _f, indent=2)
    except Exception:
        pass

    # ── 4. Long/Short Ratio (Coinbase无公开LSR, 全品种中性=1.1) ──
    _lsr = {"symbols": {}}
    for _s in list(_KEY005_CRYPTO_MAP.keys()) + list(US_STOCK_CONFIG.keys()):
        _lsr["symbols"][_s] = 1.1
    _lsr["updated"] = _now_str
    try:
        with open(_os5.path.join(base, "lsr.json"), "w") as _f:
            _j5.dump(_lsr, _f, indent=2)
    except Exception:
        pass

    # ── 5. Anchor inputs: 52w high/low + current_price ──
    # 美股=OpenBB, 加密=Coinbase Exchange公开API
    _anchor = {"symbols": {}}
    try:
        from openbb import obb as _obb5
        _start_52w = (_dt5.now() - _td5(days=365)).strftime("%Y-%m-%d")

        # 美股 (OpenBB)
        for _sym in US_STOCK_CONFIG.keys():
            try:
                _hist = _obb5.equity.price.historical(_sym, provider="yfinance",
                                                       start_date=_start_52w)
                if _hist and hasattr(_hist, "results") and _hist.results:
                    _highs = [float(r.high) for r in _hist.results]
                    _lows = [float(r.low) for r in _hist.results]
                    _cur = float(_hist.results[-1].close)
                    _avg_c, _, _has_c = get_avg_cost_price(_sym)
                    _anchor["symbols"][_sym] = {
                        "current_price": _cur,
                        "high_52w": max(_highs),
                        "low_52w": min(_lows),
                        "cost_basis": _avg_c if _has_c else _cur,
                    }
            except Exception:
                pass
    except Exception as _e:
        log_to_server(f"[KEY-005] Anchor美股采集失败: {_e}")

    # 加密 (Coinbase Exchange公开API, 无需认证)
    for _our_sym, _cb_prod in _KEY005_CRYPTO_MAP.items():
        try:
            import time as _t5
            _end_ts = int(_t5.time())
            _start_ts = _end_ts - 365 * 86400
            _cb_url = (f"https://api.exchange.coinbase.com/products/{_cb_prod}"
                       f"/candles?granularity=86400&start={_start_ts}&end={_end_ts}")
            _req5 = __import__("urllib.request", fromlist=["Request"]).Request(
                _cb_url, headers={"User-Agent": "AIPro/3.665"})
            _resp = _urlopen5(_req5, timeout=15)
            _candles = _j5.loads(_resp.read())
            # Coinbase格式: [[timestamp, low, high, open, close, volume], ...]
            if isinstance(_candles, list) and _candles:
                _highs = [float(c[2]) for c in _candles if len(c) >= 5]
                _lows = [float(c[1]) for c in _candles if len(c) >= 5]
                _cur = float(_candles[0][4])  # 最新一根的close
                if _highs and _lows:
                    _avg_c, _, _has_c = get_avg_cost_price(_our_sym)
                    _anchor["symbols"][_our_sym] = {
                        "current_price": _cur,
                        "high_52w": max(_highs),
                        "low_52w": min(_lows),
                        "cost_basis": _avg_c if _has_c else _cur,
                    }
        except Exception:
            pass

    _anchor["updated"] = _now_str
    try:
        with open(_os5.path.join(base, "anchor_inputs.json"), "w") as _f:
            _j5.dump(_anchor, _f, indent=2)
        log_to_server(f"[KEY-005] Anchor: {len(_anchor['symbols'])}品种 52w数据 (美股OpenBB+加密Coinbase)")
    except Exception as _e:
        log_to_server(f"[KEY-005] Anchor写入失败: {_e}")

    # ── 6. Herding inputs (Fear&Greed代理 + 量能偏差) ──
    # ── 7. Bias inputs (内部状态衍生) ──
    _herding = {"symbols": {}}
    _bias = {"symbols": {}}
    try:
        with _state_lock:
            _snap = {k: dict(v) for k, v in symbol_state.items()}
        for _sym, _st in _snap.items():
            # herding
            _vol = _st.get("last_volume", 0)
            _avg_vol = max(_st.get("avg_volume", 1), 1)
            _vol_ratio = min(_vol / _avg_vol, 2.0)
            _ffb = round(min(_vol_ratio * 50.0, 100.0), 1)
            _herding["symbols"][_sym] = {
                "social_sentiment": _fg_value,
                "fund_flow_bias": _ffb,
            }
            # bias
            _td_val = round(_vol / _avg_vol, 4)
            _vd_val = round(max(0.0, _td_val - 1.0), 4)
            _pos = _st.get("position_units", 0)
            _max_u = max(_st.get("max_units", 5), 1)
            _di_val = round(_pos / _max_u, 4)
            _avg_c, _, _hc = get_avg_cost_price(_sym)
            _flr = 0.0
            if _hc and _avg_c > 0:
                _cur_p = _anchor.get("symbols", {}).get(_sym, {}).get("current_price", _avg_c)
                if _cur_p < _avg_c:
                    _flr = round((_avg_c - _cur_p) / _avg_c, 4)
            _bias["symbols"][_sym] = {
                "turnover_deviation": _td_val,
                "volume_deviation": _vd_val,
                "iv_hv_spread": 0.0,
                "disposition_index": _di_val,
                "floating_loss_ratio": _flr,
                "state_age_ratio": 1.0,
            }
        _herding["updated"] = _now_str
        _bias["updated"] = _now_str
        with open(_os5.path.join(base, "herding_inputs.json"), "w") as _f:
            _j5.dump(_herding, _f, indent=2)
        with open(_os5.path.join(base, "bias_inputs.json"), "w") as _f:
            _j5.dump(_bias, _f, indent=2)
    except Exception:
        pass

    log_to_server(f"[KEY-005] 行为金融数据采集完成: VIX={_vix_val:.1f} FG={_fg_value:.0f} Anchor={len(_anchor.get('symbols', {}))}品种")


def get_avg_cost_price(symbol: str) -> tuple:
    """
    v3.497: 计算平均成本价格
    返回: (avg_cost, position_units, has_valid_cost)
    """
    state = get_state_for_symbol(symbol)
    if not state:
        return (0.0, 0, False)

    position_units = state.get("position_units", 0)
    open_buys = state.get("open_buys", [])

    if not open_buys or position_units <= 0:
        return (0.0, position_units, False)

    # 兼容两种格式: list of floats 或 list of dicts
    prices = []
    for entry in open_buys:
        if isinstance(entry, dict):
            p = entry.get('price', 0)
        else:
            p = entry
        if p and p > 0:
            prices.append(float(p))

    if not prices:
        # open_buys都是price=0时，从cycle_cost_basis计算
        cycle_cost_basis = state.get("cycle_cost_basis", 0)
        if cycle_cost_basis > 0 and position_units > 0:
            avg_cost = cycle_cost_basis / position_units
            return (avg_cost, position_units, True)
        return (0.0, position_units, False)

    avg_cost = sum(prices) / len(prices)
    return (avg_cost, position_units, True)


def get_cost_reduction_score_adj(symbol: str, current_price: float, pos_in_channel: float) -> tuple:
    """
    v3.497: 成本拉低策略评分调整
    返回: (score_adj, reason)
    """
    avg_cost, position_units, has_valid_cost = get_avg_cost_price(symbol)

    if not has_valid_cost or avg_cost <= 0 or current_price <= 0:
        return (0, "无有效成本数据")

    # 浮盈亏比例
    unrealized_pct = (current_price - avg_cost) / avg_cost * 100

    # 浮亏: 低位加仓拉低成本，高位减仓止损
    if unrealized_pct < 0:
        if pos_in_channel < 0.30:
            return (1, f"低位浮亏{unrealized_pct:.1f}%，加仓拉低成本")
        elif pos_in_channel > 0.70:
            return (-1, f"高位浮亏{unrealized_pct:.1f}%，减仓止损")
        else:
            return (0, f"中位浮亏{unrealized_pct:.1f}%，等待时机")

    # 浮盈: 高位锁定利润
    else:
        if pos_in_channel > 0.70:
            return (-1, f"高位浮盈{unrealized_pct:.1f}%，锁定利润")
        else:
            return (0, f"浮盈{unrealized_pct:.1f}%，正常策略")


# =========================================================
# v1.94: 启动时应用初始仓位配置表
# =========================================================
def _apply_single_initial_position(symbol: str, state: dict, cfg: dict, is_crypto: bool) -> None:
    """
    将 INITIAL_CRYPTO_POSITIONS / INITIAL_US_STOCK_POSITIONS 中的配置
    应用到给定 symbol 的 state 上。
    
    v2.856: 如果检测到coinbase_sync已同步，则跳过position_units覆盖
    """
    # v2.680: 防御性None检查
    if state is None:
        print(f"[INIT_POS] ❌ {symbol}: state is None, cannot apply initial position")
        return
    
    if not isinstance(cfg, dict) or not cfg:
        return

    _ensure_state_fields(state)
    
    # v2.856: 检查是否有coinbase_sync同步标记
    coinbase_sync = state.get("_coinbase_sync", {})
    has_coinbase_sync = coinbase_sync.get("last_sync") is not None
    
    if has_coinbase_sync:
        # coinbase_sync已同步，保留其仓位数据，不用配置表覆盖
        print(f"[INIT_POS] ⏭️  {symbol}: coinbase_sync已同步({coinbase_sync.get('last_sync')}), 跳过配置表覆盖 (position_units={state.get('position_units', 0)})")
        return

    # 1) 处理 position_units
    pos_units = cfg.get("position_units")
    if pos_units is not None:
        try:
            pos_units = int(pos_units)
        except Exception:
            pos_units = state.get("position_units", 0)
        pos_units = max(min(pos_units, MAX_UNITS_PER_SYMBOL), -MAX_UNITS_PER_SYMBOL)
    else:
        pos_units = state.get("position_units", 0)

    # 2) 处理 avg_price -> open_buys/open_sells & cycle_cost_basis
    avg_price = cfg.get("avg_price")
    if avg_price is not None:
        try:
            avg_price = float(avg_price)
        except Exception:
            avg_price = None

    unit_size = 1.0
    if is_crypto:
        unit_size = float(PAIR_CONFIG.get(symbol, {}).get("unit_size", 1.0))

    if avg_price is not None:
        state["open_buys"] = []
        state["open_sells"] = []

        if pos_units > 0:
            state["open_buys"] = [avg_price] * pos_units
            state["open_sells"] = []
            state["cycle_cost_basis"] = avg_price * pos_units * unit_size
        elif pos_units < 0:
            n = abs(pos_units)
            state["open_buys"] = []
            state["open_sells"] = [avg_price] * n
            state["cycle_cost_basis"] = cfg.get("cycle_cost_basis", 0.0)
        else:
            state["open_buys"] = []
            state["open_sells"] = []
            state["cycle_cost_basis"] = cfg.get("cycle_cost_basis", 0.0)

    # 3) 最终写入 position_units
    state["position_units"] = pos_units

    # 4) 覆盖各类计数和 cycle 统计（仅在 cfg 显式给出时才覆盖）
    int_keys = [
        "signal_buy_count",
        "signal_sell_count",
        "actual_buy_count",
        "actual_sell_count",
        "buy_count",
        "sell_count",
        "phase_buy_count",
        "phase_sell_count",
        "bear_rebound_buy_count",
        "phase_short_used",
        "cycle_id",
        "cycle_trades",
        "wyckoff_phase_age_bars",
    ]
    float_keys = [
        "cycle_realized_pnl",
        "cycle_fees",
        "cycle_cost_basis",
    ]

    for k in int_keys:
        if k in cfg:
            try:
                state[k] = int(cfg[k])
            except Exception:
                state[k] = state.get(k, 0)

    for k in float_keys:
        if k in cfg:
            try:
                state[k] = float(cfg[k])
            except Exception:
                state[k] = state.get(k, 0.0)

    print(f"[INIT] applied initial position for {symbol}: pos_units={state['position_units']}, "
          f"open_buys={len(state['open_buys'])}, open_sells={len(state['open_sells'])}")


def _apply_initial_positions() -> None:
    any_change = False

    for symbol, cfg in INITIAL_CRYPTO_POSITIONS.items():
        state = get_state_for_symbol(symbol)
        # v2.680: 确保state不为None
        if state is None:
            print(f"[INIT] ⚠️  {symbol}: get_state_for_symbol returned None, reinitializing...")
            symbol_state[symbol] = {
                "position": 0,
                "max_units": 5,
                "open_buys": [],
                "open_sells": []
            }
            symbol_state[symbol] = _ensure_state_fields(symbol_state[symbol])
            state = symbol_state[symbol]
        
        _apply_single_initial_position(symbol, state, cfg, is_crypto=True)
        any_change = True

    for symbol, cfg in INITIAL_US_STOCK_POSITIONS.items():
        state = get_state_for_symbol(symbol)
        # v2.680: 确保state不为None
        if state is None:
            print(f"[INIT] ⚠️  {symbol}: get_state_for_symbol returned None, reinitializing...")
            symbol_state[symbol] = {
                "position": 0,
                "max_units": 5,
                "open_buys": [],
                "open_sells": []
            }
            symbol_state[symbol] = _ensure_state_fields(symbol_state[symbol])
            state = symbol_state[symbol]
        
        _apply_single_initial_position(symbol, state, cfg, is_crypto=False)
        any_change = True

    if any_change:
        print("[INIT] initial positions applied, saving state.json")
        _save_state_to_disk()


# =========================================================
# v1.94: 每次真实成交后的状态纠偏
# =========================================================
def reconcile_state_after_trade(symbol: str, state: dict) -> None:
    _ensure_state_fields(state)

    ob = state.get("open_buys", [])
    osell = state.get("open_sells", [])

    if not isinstance(ob, list):
        ob = []
        state["open_buys"] = ob
    if not isinstance(osell, list):
        osell = []
        state["open_sells"] = osell

    computed_units = len(ob) - len(osell)
    old_units = state.get("position_units", 0)

    if computed_units != old_units:
        clamped_units = max(min(computed_units, MAX_UNITS_PER_SYMBOL), -MAX_UNITS_PER_SYMBOL)
        print(f"[RECONCILE] {symbol}: position_units {old_units} -> {clamped_units} "
              f"(from open_buys={len(ob)}, open_sells={len(osell)})")
        state["position_units"] = clamped_units

    int_keys = [
        "signal_buy_count",
        "signal_sell_count",
        "actual_buy_count",
        "actual_sell_count",
        "buy_count",
        "sell_count",
        "phase_buy_count",
        "phase_sell_count",
        "bear_rebound_buy_count",
        "phase_short_used",
        "cycle_trades",
        "cycle_id",
        "wyckoff_phase_age_bars",
    ]
    for k in int_keys:
        v = state.get(k, 0)
        try:
            iv = int(v)
        except Exception:
            iv = 0
        if iv < 0:
            iv = 0
        state[k] = iv

    float_keys = [
        "cycle_realized_pnl",
        "cycle_fees",
        "cycle_cost_basis",
    ]
    for k in float_keys:
        v = state.get(k, 0.0)
        try:
            fv = float(v)
        except Exception:
            fv = 0.0
        state[k] = fv


def append_log(text: str, symbol: Optional[str] = None) -> None:
    # v3.000: 日志轮转 - 超过20MB自动备份，防止文件过大导致性能问题
    MAX_LOG_SIZE = 20 * 1024 * 1024  # 20MB
    try:
        if os.path.exists(SERVER_LOG_PATH) and os.path.getsize(SERVER_LOG_PATH) > MAX_LOG_SIZE:
            backup_path = SERVER_LOG_PATH + f".{datetime.now().strftime('%Y%m%d_%H%M%S')}.bak"
            os.rename(SERVER_LOG_PATH, backup_path)
            print(f"[LOG_ROTATE] server.log 已轮转到 {backup_path}")
    except Exception as e:
        print(f"[LOG_ROTATE] 轮转失败: {e}")

    with open(SERVER_LOG_PATH, "a", encoding="utf-8") as f:
        f.write(text + "\n")

    if symbol:
        sym_path = os.path.join(LOG_DIR, f"{symbol}.log")
        # v3.000: 单币种日志也做轮转
        try:
            if os.path.exists(sym_path) and os.path.getsize(sym_path) > MAX_LOG_SIZE:
                backup_path = sym_path + f".{datetime.now().strftime('%Y%m%d_%H%M%S')}.bak"
                os.rename(sym_path, backup_path)
        except Exception:  # v3.560 P2-2
            pass
        with open(sym_path, "a", encoding="utf-8") as f:
            f.write(text + "\n")


def _write_md_file(md_dir: str, md_text: str, mark: datetime, prefix: str) -> str:
    if prefix == "hourly":
        fname = mark.strftime("%Y-%m-%d_%H00.md")
    elif prefix == "8h":
        fname = mark.strftime("%Y-%m-%d_%H00_8h.md")
    else:
        fname = mark.strftime("%Y-%m-%d_%H00_24h.md")

    path = os.path.join(md_dir, fname)
    with open(path, "w", encoding="utf-8") as f:
        f.write(md_text)
    return path


