        f"bearish_buy_gate.pass : {gates['bearish_buy_gate']['pass']}, reason_cn : {gates['bearish_buy_gate']['reason_cn']}",
        "",
        "STEP7 - 最终决策 & 执行",
        "------ LLM 决策 & Fallback (v1.96) ------",
        f"llm_raw_action : {llm_raw_action}",
        f"ai_action(after Grid) : {ai_action}",
        f"final_action : {final_action}",
        f"confidence : {confidence:.2f}",
        f"behavior_csi : {behavior_result.get('csi', 50.0):.1f} ({behavior_result.get('csi_state', 'NEUTRAL')})",
        f"behavior_dqs : {behavior_result.get('dqs', 50.0):.1f} gate={behavior_result.get('dqs_gate', {})}",
        f"llm_fallback : {llm_fallback}",
