# =========================================================
# KEY-009: 审计Dashboard
# =========================================================
ROOT = Path(__file__).resolve().parent  # KEY-009路径基准（固定到主程序目录）


def _read_key009_cache():
    _candidates = [ROOT / "state" / "key009_audit.json", ROOT / "state" / "key009_audit.latest.json"]
    _best = None
    _best_mtime = -1
    for _path in _candidates:
        try:
            if _path.exists():
                _mtime = _path.stat().st_mtime
                if _mtime > _best_mtime:
                    _best = _path
                    _best_mtime = _mtime
        except Exception:
            pass
    if not _best:
        return None, None
    try:
        return json.loads(_best.read_text(encoding="utf-8")), _best
    except Exception:
        return None, _best


@app.route("/key009", methods=["GET"])
def key009_dashboard():
    """KEY-009审计dashboard — 优先用缓存数据(后台5分钟刷新)，fallback实时计算"""
    def _repair_text_mojibake(value):
        if not isinstance(value, str) or not value:
            return value
        cp1252_map = {
            0x20AC: 0x80, 0x201A: 0x82, 0x0192: 0x83, 0x201E: 0x84, 0x2026: 0x85,
            0x2020: 0x86, 0x2021: 0x87, 0x02C6: 0x88, 0x2030: 0x89, 0x0160: 0x8A,
            0x2039: 0x8B, 0x0152: 0x8C, 0x017D: 0x8E, 0x2018: 0x91, 0x2019: 0x92,
            0x201C: 0x93, 0x201D: 0x94, 0x2022: 0x95, 0x2013: 0x96, 0x2014: 0x97,
            0x02DC: 0x98, 0x2122: 0x99, 0x0161: 0x9A, 0x203A: 0x9B, 0x0153: 0x9C,
            0x017E: 0x9E, 0x0178: 0x9F,
        }
        def _score(s):
            _cjk = len(re.findall(r"[\u3400-\u9fff]", s))
            _bad = len(re.findall(r"[ÃÂâ€œâ€â€™â€”çåäéèêëï¼½œ™]", s))
            return _cjk * 2 - _bad * 3
        def _to_cp1252_bytes(s):
            out = bytearray()
            for ch in s:
                cp = ord(ch)
                if cp <= 0xFF:
                    out.append(cp)
                elif cp in cp1252_map:
                    out.append(cp1252_map[cp])
                else:
                    out.append(0x3F)
            return bytes(out)
        best = value
        best_score = _score(value)
        current = value
        for _ in range(2):
            try:
                candidate = _to_cp1252_bytes(current).decode("utf-8", errors="ignore").replace("\x00", "").strip()
            except Exception:
                break
            if not candidate or candidate == current:
                break
            cand_score = _score(candidate)
            if cand_score > best_score:
                best = candidate
                best_score = cand_score
            current = candidate
        return best

    def _repair_key009_evo_memory(payload):
        try:
            _fresh_memory = None
            try:
                from key009_audit import _parse_evolution_memory as _parse_fresh_evolution_memory
                _fresh_memory = _parse_fresh_evolution_memory()
            except Exception:
                _fresh_memory = None
            for _rk in ("24h", "1w", "1m"):
                _d = payload.get(_rk)
                if not isinstance(_d, dict):
                    continue
                _evo = _d.get("system_evo")
                if not isinstance(_evo, dict):
                    continue
                if isinstance(_fresh_memory, list) and _fresh_memory:
                    _evo["memory_history"] = [dict(_m) for _m in _fresh_memory]
                _mems = _evo.get("memory_history")
                if not isinstance(_mems, list):
                    continue
                for _m in _mems:
                    if not isinstance(_m, dict):
                        continue
                    _m["title"] = _repair_text_mojibake(_m.get("title", ""))
                    _fields = _m.get("fields")
                    if isinstance(_fields, dict):
                        _m["fields"] = {
                            _repair_text_mojibake(str(k)): _repair_text_mojibake(str(v))
                            for k, v in _fields.items()
                        }
        except Exception:
            pass
        return payload

    def _get_signal_filter_mode():
        try:
            if not signal_filter:
                return "OFF"
            _gm = getattr(signal_filter, "get_mode", None)
            if callable(_gm):
                _mode = str(_gm()).upper()
                if _mode in ("OBSERVE", "ENFORCE"):
                    return _mode
            _obs = getattr(signal_filter, "observe_only", None)
            if isinstance(_obs, bool):
                return "OBSERVE" if _obs else "ENFORCE"
            try:
                from AIPro import signal_direction_filter as _sdf
            except Exception:
                import signal_direction_filter as _sdf
            return "OBSERVE" if getattr(_sdf, "OBSERVE_ONLY", True) else "ENFORCE"
        except Exception:
            return "OFF"

    # 优先读缓存(后台线程每5分钟刷新)
    multi_data = None
    stale_multi_data = None
    try:
        stale_multi_data, _cache_path = _read_key009_cache()
        if stale_multi_data is not None and _cache_path is not None:
            _mtime = _cache_path.stat().st_mtime
            import time as _t_k9d
            if (_t_k9d.time() - _mtime) < 600:  # 10分钟内有效
                multi_data = stale_multi_data
    except Exception:
        pass

    # fallback: 实时计算
    if not multi_data or "24h" not in multi_data:
        try:
            from key009_audit import audit
            from datetime import datetime, timedelta
            import pytz as _tz
            _ny = _tz.timezone("America/New_York")
            _now = datetime.now(_ny)
            _today_8 = _now.replace(hour=8, minute=0, second=0, microsecond=0)
            _day_start = (_today_8 - timedelta(days=1)) if _now < _today_8 else _today_8
            _week_start = _now.replace(hour=8, minute=0, second=0, microsecond=0) - timedelta(days=_now.weekday())
            if _now < _week_start:
                _week_start -= timedelta(weeks=1)
            _month_start = _now.replace(day=1, hour=8, minute=0, second=0, microsecond=0)
            if _now < _month_start:
                _lm = (_now.replace(day=1) - timedelta(days=1))
                _month_start = _lm.replace(day=1, hour=8, minute=0, second=0, microsecond=0)
            _h_24 = max(int((_now - _day_start).total_seconds() / 3600), 1)
            _h_1w = max(int((_now - _week_start).total_seconds() / 3600), 1)
            _h_1m = max(int((_now - _month_start).total_seconds() / 3600), 1)
            ranges = {"24h": _h_24, "1w": _h_1w, "1m": _h_1m}
            _log_paths = "logs/server.log,logs/price_scan_engine.log,logs/deepseek_arbiter.log,logs/macd_divergence.log,logs/rob_hoffman_plugin.log,logs/l1_module_diagnosis.log,logs/value_analysis.log"
            multi_data = {}
            for label, h in ranges.items():
                d = audit(_log_paths, hours=h)
                for t in d.get("tasks", {}).values():
                    t.pop("recent", None)
                multi_data[label] = d
        except Exception as e:
            if isinstance(stale_multi_data, dict) and stale_multi_data.get("24h"):
                multi_data = stale_multi_data
                for _rk in ("24h", "1w", "1m"):
                    if isinstance(multi_data.get(_rk), dict):
                        multi_data[_rk]["cache_fallback"] = True
                        multi_data[_rk]["cache_fallback_reason"] = str(e)
            else:
                data = {"error": str(e), "tasks": {}, "metrics": {}, "issues": [],
                        "total_events": 0, "total_errors": 0, "hours": 24,
                        "generated_at": "error", "plugins": {}, "macd": {},
                        "brooks_vision": {}, "gates": {}}
                multi_data = {"24h": data, "1w": data, "1m": data}

    # 附加Claude复查状态
    try:
        _phase = getattr(_autosave_worker, "_k9_phase", "IDLE") if callable(_autosave_worker) else "UNKNOWN"
        _slot = getattr(_autosave_worker, "_k9_last_slot", "") if callable(_autosave_worker) else ""
        _retries = getattr(_autosave_worker, "_k9_collect_retries", 0) if callable(_autosave_worker) else 0
    except NameError:
        _phase, _slot, _retries = "UNKNOWN", "", 0
    _sf_mode = _get_signal_filter_mode()
    _ds_health = _get_data_source_health_snapshot()
    # KEY-010: 方向过滤器实时状态
    def _build_signal_filter_symbol_stats():
        try:
            from datetime import datetime as _dt_sf, timedelta as _td_sf, timezone as _tz_sf
            _now_ny = datetime.now(ZoneInfo("America/New_York"))
            _cut_4h = _now_ny - _td_sf(hours=4)
            _cut_1w = _now_ny - _td_sf(days=7)
            _sf_root = ROOT / ".GCC" / "signal_filter"
            _valid = _sf_root / "valid_signals.jsonl"
            _filtered = _sf_root / "filtered_signals.jsonl"
            _stats = {}

            def _bucket(sym):
                if not sym:
                    return None
                sym = str(sym).upper().strip()
                if not sym:
                    return None
                if sym not in _stats:
                    _stats[sym] = {
                        "symbol": sym,
                        "mode": _sf_mode,
                        "buy_4h": 0, "sell_4h": 0,
                        "buy_1w": 0, "sell_1w": 0,
                        "blocked_4h": 0, "blocked_1w": 0,
                    }
                return _stats[sym]

            def _parse_ts(raw):
                if not raw:
                    return None
                try:
                    raw = str(raw).strip().replace("Z", "+00:00")
                    dt = _dt_sf.fromisoformat(raw)
                    if dt.tzinfo is None:
                        dt = dt.replace(tzinfo=_tz_sf.utc)
                    return dt.astimezone(ZoneInfo("America/New_York"))
                except Exception:
                    return None

            if _valid.exists():
                for _ln in _valid.read_text(encoding="utf-8", errors="ignore").splitlines():
                    _ln = _ln.strip()
                    if not _ln:
                        continue
                    try:
                        _rec = json.loads(_ln)
                    except Exception:
                        continue
                    _dt = _parse_ts(_rec.get("timestamp"))
                    if not _dt:
                        continue
                    _b = _bucket(_rec.get("symbol"))
                    if not _b:
                        continue
                    _dir = str(_rec.get("direction", "")).lower()
                    if _dt >= _cut_1w:
                        if _dir == "buy":
                            _b["buy_1w"] += 1
                        elif _dir == "sell":
                            _b["sell_1w"] += 1
                    if _dt >= _cut_4h:
                        if _dir == "buy":
                            _b["buy_4h"] += 1
                        elif _dir == "sell":
                            _b["sell_4h"] += 1

            if _filtered.exists():
                for _ln in _filtered.read_text(encoding="utf-8", errors="ignore").splitlines():
                    _ln = _ln.strip()
                    if not _ln:
                        continue
                    try:
                        _rec = json.loads(_ln)
                    except Exception:
                        continue
                    if not (_rec.get("blocked") or _rec.get("would_block")):
                        continue
                    _dt = _parse_ts(_rec.get("timestamp"))
                    if not _dt:
                        continue
                    _b = _bucket(_rec.get("symbol"))
                    if not _b:
                        continue
                    if _dt >= _cut_1w:
                        _b["blocked_1w"] += 1
                    if _dt >= _cut_4h:
                        _b["blocked_4h"] += 1

            _out = []
            for _sym, _b in sorted(_stats.items()):
                _tot_4h = _b["buy_4h"] + _b["sell_4h"]
                _tot_1w = _b["buy_1w"] + _b["sell_1w"]
                if _b["buy_4h"] > _b["sell_4h"] and _b["buy_4h"] > 0:
                    _dir = "BUY_DOMINANT"
                elif _b["sell_4h"] > _b["buy_4h"] and _b["sell_4h"] > 0:
                    _dir = "SELL_DOMINANT"
                elif _tot_4h > 0:
                    _dir = "NEUTRAL"
                else:
                    _dir = "NO_ANSWER"
                _out.append({
                    "symbol": _sym,
                    "mode": _b["mode"],
                    "direction": _dir,
                    "buy_ratio_4h": round((_b["buy_4h"] / _tot_4h), 3) if _tot_4h else 0.0,
                    "sell_ratio_4h": round((_b["sell_4h"] / _tot_4h), 3) if _tot_4h else 0.0,
                    "buy_ratio_week": round((_b["buy_1w"] / _tot_1w), 3) if _tot_1w else 0.0,
                    "sell_ratio_week": round((_b["sell_1w"] / _tot_1w), 3) if _tot_1w else 0.0,
                    "sample_4h": _tot_4h,
                    "sample_week": _tot_1w,
                    "blocked_4h": _b["blocked_4h"],
                    "blocked_week": _b["blocked_1w"],
                })
            return _out
        except Exception:
            return []

    _sf_detail = {"mode": _sf_mode}
    if signal_filter:
        try:
            _dir_result = signal_filter.evaluate_direction()
            _sf_detail.update({
                "direction": _dir_result.direction,
                "reason": _dir_result.reason,
                "buy_ratio_4h": round(_dir_result.buy_ratio_4h, 3),
                "sell_ratio_4h": round(_dir_result.sell_ratio_4h, 3),
                "buy_ratio_week": round(_dir_result.buy_ratio_week, 3),
                "sell_ratio_week": round(_dir_result.sell_ratio_week, 3),
                "sample_4h": _dir_result.sample_4h,
                "sample_week": _dir_result.sample_week,
            })
        except Exception:
            pass
    _sf_detail["by_symbol"] = _build_signal_filter_symbol_stats()
    for _rk in ("24h", "1w", "1m"):
        d = multi_data.get(_rk)
        if isinstance(d, dict):
            d["review_status"] = {
                "phase": _phase,
                "slot": _slot,
                "collect_retries": _retries,
                "signal_filter": _sf_mode
            }
            d["data_source_health"] = _ds_health
            d["signal_direction_filter"] = _sf_detail
    multi_data = _repair_key009_evo_memory(multi_data)

    # 读取dashboard HTML模板并注入多范围数据
    try:
        html = (ROOT / "key009_dashboard.html").read_text(encoding="utf-8")
        inject = (
            f"<script>window.MULTI_DATA = {json.dumps(multi_data, ensure_ascii=False)};"
            f"window.EMBEDDED_DATA = window.MULTI_DATA['24h'];</script>"
            "<script>"
            "(function(){"
            "function renderSigaccLeaders(){"
            "  try {"
            "    const data = (window.MULTI_DATA && window.MULTI_DATA['24h']) || {};"
            "    const pa = data.plugin_accuracy || {};"
            "    const host = document.getElementById('sigacc-summary');"
            "    if (!host || host.dataset.leaderCards === '1') return;"
            "    const ranked = Object.entries(pa).map(([src, syms]) => {"
            "      const ov = (syms && syms._overall) || {};"
            "      const total = Number(ov.total || 0);"
            "      const correct = Number(ov.correct || 0);"
            "      const acc = ov.acc != null ? Number(ov.acc) : (total > 0 ? correct / total : null);"
            "      return { src, total, acc };"
            "    }).filter(x => x.acc != null).sort((a,b) => (b.acc - a.acc) || (b.total - a.total));"
            "    if (!ranked.length) return;"
            "    const cards = ranked.slice(0, 2).map((item, idx) => {"
            "      const color = item.acc >= 0.55 ? '#1a7f37' : (item.acc < 0.5 ? '#cf222e' : '#9a6700');"
            "      const label = idx === 0 ? '最强外挂' : '第二名';"
            "      return `<div class=\"card\"><div class=\"label\">${label}</div><div class=\"value\" style=\"color:${color}\">${item.src} ${(item.acc*100).toFixed(1)}%</div><div class=\"sub\">${item.total} decisive</div></div>`;"
            "    }).join('');"
            "    host.insertAdjacentHTML('beforeend', cards);"
            "    host.dataset.leaderCards = '1';"
            "  } catch (e) {}"
            "}"
            "document.addEventListener('DOMContentLoaded', function(){"
            "  setTimeout(renderSigaccLeaders, 0);"
            "  setTimeout(renderSigaccLeaders, 300);"
            "});"
            "})();"
            "</script>"
        )
        html = html.replace("</head>", inject + "\n</head>")
        return html
    except Exception:
        return jsonify(multi_data.get("24h", {}))


@app.route("/key009/json", methods=["GET"])
def key009_json():
    """KEY-009审计数据 — JSON API"""
    def _get_signal_filter_mode():
        try:
            if not signal_filter:
                return "OFF"
            _gm = getattr(signal_filter, "get_mode", None)
            if callable(_gm):
                _mode = str(_gm()).upper()
                if _mode in ("OBSERVE", "ENFORCE"):
                    return _mode
            _obs = getattr(signal_filter, "observe_only", None)
            if isinstance(_obs, bool):
                return "OBSERVE" if _obs else "ENFORCE"
            try:
                from AIPro import signal_direction_filter as _sdf
            except Exception:
                import signal_direction_filter as _sdf
            return "OBSERVE" if getattr(_sdf, "OBSERVE_ONLY", True) else "ENFORCE"
        except Exception:
            return "OFF"

    try:
        hours = int(request.args.get("hours", 24))
        from key009_audit import audit
        data = audit("logs/server.log,logs/price_scan_engine.log,logs/deepseek_arbiter.log,logs/macd_divergence.log,logs/rob_hoffman_plugin.log,logs/l1_module_diagnosis.log,logs/value_analysis.log", hours=hours)
        for t in data.get("tasks", {}).values():
            t.pop("recent", None)
        # 附加Claude复查状态
        try:
            _phase = getattr(_autosave_worker, "_k9_phase", "IDLE") if callable(_autosave_worker) else "UNKNOWN"
            _slot = getattr(_autosave_worker, "_k9_last_slot", "") if callable(_autosave_worker) else ""
            _retries = getattr(_autosave_worker, "_k9_collect_retries", 0) if callable(_autosave_worker) else 0
        except NameError:
            _phase, _slot, _retries = "UNKNOWN", "", 0
        data["review_status"] = {
            "phase": _phase,
            "slot": _slot,
            "collect_retries": _retries,
            "signal_filter": _get_signal_filter_mode()
        }
        data["data_source_health"] = _get_data_source_health_snapshot()
        return jsonify(data)
    except Exception as e:
        try:
            _cache, _ = _read_key009_cache()
            if _cache is None:
                raise FileNotFoundError("no key009 cache available")
            data = _cache.get("24h", _cache) if isinstance(_cache, dict) else {}
            if isinstance(data, dict):
                data["cache_fallback"] = True
                data["cache_fallback_reason"] = str(e)
            return jsonify(data)
        except Exception:
            return jsonify({"error": str(e)})


@app.route("/key009/rule-transition", methods=["POST"])
def key009_rule_transition():
    """KEY-009 L5: 规则状态转换 DISCOVERED→ACTIVE→DEPRECATED"""
    try:
        data = request.get_json(force=True) or {}
        rule_id = data.get("rule_id", "")
        new_status = data.get("new_status", "")
        if not rule_id or not new_status:
            return jsonify({"ok": False, "error": "missing rule_id or new_status"}), 400
        from key009_audit import rule_transition
        result = rule_transition(rule_id, new_status)
        if result.get("ok"):
            log_to_server(f"[KEY-009][L5][TRANSITION] {rule_id}: {result['old_status']}→{new_status}")
            # 清除规则缓存使下次加载获取新状态
            _key009_rules_cache["data"] = None
        return jsonify(result)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


