@app.route("/key009/gcctm", methods=["GET"])
def key009_gcctm():
    """KEY-011 GCC-TM: 返回最近决策日志 + KNN经验条目 + pipeline任务"""
    decisions = []
    knn_entries = []
    pipeline_tasks = []
    dec_path = ROOT / "state" / "gcc_trading_decisions.jsonl"
    knn_path = ROOT / "state" / "gcc_knn_experience.jsonl"
    tasks_path = ROOT / ".GCC" / "pipeline" / "tasks.json"
    try:
        if dec_path.exists():
            lines = dec_path.read_text(encoding="utf-8").splitlines()
            for line in lines[-100:]:
                try:
                    decisions.append(json.loads(line))
                except Exception:
                    pass
    except Exception:
        pass
    try:
        if knn_path.exists():
            lines = knn_path.read_text(encoding="utf-8").splitlines()
            for line in lines[-50:]:
                try:
                    knn_entries.append(json.loads(line))
                except Exception:
                    pass
    except Exception:
        pass
    try:
        if tasks_path.exists():
            payload = json.loads(tasks_path.read_text(encoding="utf-8"))
            all_tasks = payload.get("tasks", []) if isinstance(payload, dict) else []
            for task in all_tasks:
                if task.get("key") != "KEY-011":
                    continue
                if task.get("task_id") not in ("GCC-0244", "GCC-0251", "GCC-0252"):
                    continue
                steps = task.get("steps", []) if isinstance(task.get("steps"), list) else []
                layer_counts = {"L1": 0, "L2": 0, "L3": 0}
                for step in steps:
                    sid = str(step.get("id", ""))
                    title = str(step.get("title", ""))
                    if sid.startswith("L1-") or "[L1]" in title:
                        layer_counts["L1"] += 1
                    elif sid.startswith("L2-") or "[L2]" in title:
                        layer_counts["L2"] += 1
                    elif sid.startswith("L3-") or "[L3]" in title:
                        layer_counts["L3"] += 1
                pipeline_tasks.append({
                    "task_id": task.get("task_id"),
                    "title": task.get("title"),
                    "status": task.get("status", "pending"),
                    "stage": task.get("stage", ""),
                    "priority": task.get("priority", ""),
                    "description": task.get("description", ""),
                    "updated_at": task.get("updated_at", ""),
                    "dependencies": task.get("dependencies", []),
                    "steps": steps,
                    "layer_counts": layer_counts,
                })
            pipeline_tasks.sort(key=lambda x: x.get("task_id", ""))
    except Exception:
        pass
    # 管线对比: gcc_trading_accuracy.json
    accuracy = {}
    acc_path = ROOT / "state" / "gcc_trading_accuracy.json"
    try:
        if acc_path.exists():
            accuracy = json.loads(acc_path.read_text(encoding="utf-8"))
    except Exception:
        pass

    # 模拟交易: gcc_sim_trades.jsonl
    sim_trades = []
    sim_path = ROOT / "state" / "gcc_sim_trades.jsonl"
    try:
        if sim_path.exists():
            for line in sim_path.read_text(encoding="utf-8").splitlines()[-100:]:
                try:
                    sim_trades.append(json.loads(line))
                except Exception:
                    pass
    except Exception:
        pass

    # K线实时状态: gcc_candle_state_{symbol}.json
    candle_states = {}
    import glob as _gcctm_glob
    for _cs_path in _gcctm_glob.glob(str(ROOT / "state" / "gcc_candle_state_*.json")):
        try:
            _cs_data = json.loads(open(_cs_path, encoding="utf-8").read())
            _cs_sym = _cs_data.get("symbol", "")
            if _cs_sym:
                candle_states[_cs_sym] = _cs_data
        except Exception:
            pass

    # K线汇总(上一根完成的K线): gcc_candle_summary_{symbol}.json
    candle_summaries = {}
    for _csm_path in _gcctm_glob.glob(str(ROOT / "state" / "gcc_candle_summary_*.json")):
        try:
            _csm_name = os.path.basename(_csm_path)
            if "-" in _csm_name.replace("gcc_candle_summary_", ""):
                continue  # skip MSI/BaoPCS copies
            _csm_data = json.loads(open(_csm_path, encoding="utf-8").read())
            _csm_sym = _csm_name.replace("gcc_candle_summary_", "").replace(".json", "")
            if _csm_sym:
                candle_summaries[_csm_sym] = _csm_data
        except Exception:
            pass

    # 轮次决策明细: gcc_round_decisions.jsonl
    round_decisions = []
    rd_path = ROOT / "state" / "gcc_round_decisions.jsonl"
    try:
        if rd_path.exists():
            for line in rd_path.read_text(encoding="utf-8").splitlines()[-200:]:
                try:
                    round_decisions.append(json.loads(line))
                except Exception:
                    pass
    except Exception:
        pass

    # 信号池实时状态: gcc_signal_pool.json
    signal_pool = {}
    _sp_path = ROOT / "state" / "gcc_signal_pool.json"
    try:
        if _sp_path.exists():
            signal_pool = json.loads(_sp_path.read_text(encoding="utf-8"))
    except Exception:
        pass

    # 方向锁实时状态: gcc_direction_lock.json
    direction_locks = {}
    _dl_path = ROOT / "state" / "gcc_direction_lock.json"
    try:
        if _dl_path.exists():
            direction_locks = json.loads(_dl_path.read_text(encoding="utf-8"))
    except Exception:
        pass

    # v3.679: 错误分类扫描 — 最近24h日志按通道归类
    error_classify = []
    _ec_cache_key = "_ec_cache"
    _ec_cache_ts = getattr(key009_gcctm, "_ec_ts", 0)
    import time as _ec_time
    if _ec_time.time() - _ec_cache_ts > 120:  # 2分钟缓存
        try:
            import re as _ec_re
            _EC_CHANNEL_RULES = [
                # B1/B2/B3 通道标签 (优先匹配)
                ("B1", [r"\[B1\]"]),
                ("B2", [r"\[B2\]"]),
                ("B3", [r"\[B3\]"]),
                # 旧标签兼容
                ("S5", [r"\[GCC-TM\]", r"\[GCC-TRADE\]", r"gcc_trading", r"\[PUCT\]"]),
                ("S3", [r"\[S3.*MACD\]", r"\[MACD.L2\]", r"\[L2_MACD\]", r"macd.*divergence"]),
                ("S4", [r"\[S4.*Gate\]", r"\[L2.Gate\]", r"\[L2_Gate\]", r"\[L2门卫\]"]),
                ("S2", [r"\[S2外挂\]", r"plugin.*bypass", r"\[RobHoffman\]", r"\[DoublePattern\]", r"\[ChanBS\]", r"\[SuperTrend\]"]),
                ("S1", [r"\[v3\.6[5-9]\d\].*L1", r"\[L1[_\s]", r"L1参考"]),
                ("P0", [r"\[P0\]", r"\[CycleSwitch\]", r"\[P0-", r"scan.engine", r"price_scan", r"扫描.*异常"]),
                ("SYS", [r"Schwab", r"yfinance", r"Coinbase", r"SignalStack", r"3Commas", r"\[API\]", r"\[NETWORK\]",
                         r"possibly delisted", r"SIGNAL_GATE_WORKER", r"KEY004-PCACHE"]),
            ]
            _EC_ERROR_RE = _ec_re.compile(
                r"(ERROR|CRITICAL|Exception|Traceback|失败|NameError|TypeError|KeyError|ValueError|AttributeError|ImportError|ZeroDivision|ConnectionError|Timeout)",
                _ec_re.IGNORECASE
            )
            _EC_TS_RE = _ec_re.compile(r"(\d{4}-\d{2}-\d{2})[T\s](\d{2}:\d{2}:\d{2})")
            _ec_cutoff = datetime.now().strftime("%Y-%m-%d")  # 今天
            _ec_errors = []
            _EC_LOG_SOURCES = {
                "server.log": "server",
                "filter_chain_worker.log": "server",
                "price_scan_engine.log": "scan",
            }
            # 主日志 + 备份目录中包含今日日期的备份文件
            _ec_log_paths = []
            for _ec_name, _ec_src in _EC_LOG_SOURCES.items():
                _ec_log_paths.append((ROOT / "logs" / _ec_name, _ec_src))
            # 回退: 备份文件中可能包含今日数据(备份刚发生时)
            _ec_backup_dir = ROOT / "logs" / "backup"
            if _ec_backup_dir.exists():
                import glob as _ec_glob
                for _ec_bp in sorted(_ec_backup_dir.glob("*.log"), reverse=True)[:6]:
                    _ec_bp_name = _ec_bp.name
                    # 文件名格式: server_2026-03-07_2026-03-13.log
                    if _ec_cutoff in _ec_bp_name or _ec_cutoff.replace("-", "") in _ec_bp_name:
                        _ec_bp_src = "server" if "server" in _ec_bp_name or "worker" in _ec_bp_name else "scan"
                        _ec_log_paths.append((_ec_bp, _ec_bp_src))
            for _ec_logpath, _ec_source in _ec_log_paths:
                if not _ec_logpath.exists():
                    continue
                try:
                    _ec_lines = _ec_logpath.read_text(encoding="utf-8", errors="ignore").splitlines()
                    for _ecl in _ec_lines[-5000:]:  # 最近5000行
                        if _ec_cutoff not in _ecl:
                            continue
                        if not _EC_ERROR_RE.search(_ecl):
                            continue
                        # 提取时间
                        _ec_ts_m = _EC_TS_RE.search(_ecl)
                        _ec_ts = _ec_ts_m.group(1) + " " + _ec_ts_m.group(2) if _ec_ts_m else ""
                        # 分类通道
                        _ec_ch = "OTHER"
                        for _ch_name, _ch_pats in _EC_CHANNEL_RULES:
                            for _cp in _ch_pats:
                                if _ec_re.search(_cp, _ecl, _ec_re.IGNORECASE):
                                    _ec_ch = _ch_name
                                    break
                            if _ec_ch != "OTHER":
                                break
                        # 提取品种
                        _ec_sym_m = _ec_re.search(r"\$(\w+)|(?:^|\s)(\b(?:TSLA|COIN|RDDT|NBIS|CRWV|RKLB|HIMS|OPEN|AMD|ONDS|PLTR|BTCUSDC|ETHUSDC|SOLUSDC|ZECUSDC|XRPUSDC)\b)", _ecl)
                        _ec_sym = (_ec_sym_m.group(1) or _ec_sym_m.group(2)) if _ec_sym_m else ""
                        # 截短错误消息
                        _ec_msg = _ecl.strip()
                        if len(_ec_msg) > 200:
                            _ec_msg = _ec_msg[:200] + "..."
                        _ec_errors.append({
                            "ts": _ec_ts,
                            "channel": _ec_ch,
                            "symbol": _ec_sym,
                            "msg": _ec_msg,
                            "source": _ec_source,
                        })
                except Exception:
                    pass
            # 去重(备份和主文件可能有重叠行)
            _ec_seen = set()
            _ec_dedup = []
            for _ece in _ec_errors:
                _ece_key = (_ece["ts"], _ece["msg"][:80])
                if _ece_key not in _ec_seen:
                    _ec_seen.add(_ece_key)
                    _ec_dedup.append(_ece)
            _ec_errors = _ec_dedup
            error_classify = _ec_errors[-200:]  # 最多200条
            key009_gcctm._ec_cache = error_classify
            key009_gcctm._ec_ts = _ec_time.time()
        except Exception:
            pass
    else:
        error_classify = getattr(key009_gcctm, "_ec_cache", [])

    # v3.679: 观察模式信号日志 — 最近500条
    observe_signals = []
    _obs_path = ROOT / "state" / "gcc_observe_log.jsonl"
    try:
        if _obs_path.exists():
            _obs_lines = _obs_path.read_text(encoding="utf-8").splitlines()
            for _ol in _obs_lines[-500:]:
                try:
                    observe_signals.append(json.loads(_ol))
                except Exception:
                    pass
    except Exception:
        pass

    decisions = list(reversed(decisions))
    knn_entries = list(reversed(knn_entries))
    sim_trades = list(reversed(sim_trades))
    round_decisions = list(reversed(round_decisions))

    # GCC-0256 S5: OP剥头皮P&L汇总
    scalp_pnl = {}
    try:
        from gcc_trading_module import scalp_get_pnl_summary as _scalp_pnl_fn
        scalp_pnl = _scalp_pnl_fn()
    except Exception:
        pass
    # TSLA期权数据
    def _load_options_data():
        _oh, _op = [], {}
        try:
            _oh_p = ROOT / "state" / "tsla_options_history.json"
            if _oh_p.exists():
                _oh = json.loads(_oh_p.read_text(encoding="utf-8"))
        except Exception:
            pass
        try:
            _op_p = ROOT / "state" / "tsla_options_position.json"
            if _op_p.exists():
                _op = json.loads(_op_p.read_text(encoding="utf-8"))
        except Exception:
            pass
        return _oh, _op

    # 剥头皮完整数据(state + trades + summary)供dashboard面板
    scalp_full = {"state": {}, "trades": [], "summary": {}}
    try:
        _scalp_st_path = ROOT / "state" / "gcc_scalp_state.json"
        _scalp_tr_path = ROOT / "state" / "gcc_scalp_trades.jsonl"
        if _scalp_st_path.exists():
            scalp_full["state"] = json.loads(_scalp_st_path.read_text(encoding="utf-8"))
        if _scalp_tr_path.exists():
            _str_lines = [json.loads(l) for l in _scalp_tr_path.read_text(encoding="utf-8").strip().split("\n") if l.strip()]
            scalp_full["trades"] = _str_lines[-50:]
            _stotal = len(_str_lines)
            _swins = sum(1 for t in _str_lines if t.get("net_pnl_usd", 0) > 0)
            scalp_full["summary"] = {
                "total": _stotal, "wins": _swins, "losses": _stotal - _swins,
                "win_rate": round(_swins / _stotal * 100, 1) if _stotal else 0,
                "total_pnl_usd": round(sum(t.get("net_pnl_usd", 0) for t in _str_lines), 2),
            }
    except Exception:
        pass

    _opt_hist, _opt_pos = _load_options_data()

    return app.response_class(
        json.dumps(
            {
                "decisions": decisions,
                "knn_entries": knn_entries,
                "pipeline_tasks": pipeline_tasks,
                "accuracy": accuracy,
                "sim_trades": sim_trades,
                "candle_states": candle_states,
                "candle_summaries": candle_summaries,
                "round_decisions": round_decisions,
                "signal_pool": signal_pool,
                "direction_locks": direction_locks,
                "observe_signals": list(reversed(observe_signals)),
                "error_classify": error_classify,
                "scalp_pnl": scalp_pnl,
                "scalp": scalp_full,
                "options_history": _opt_hist,
                "options_position": _opt_pos,
            },
            ensure_ascii=False,
        ),
        mimetype="application/json"
    )


