# =========================================================
# v3.499: 剥头皮每日偏向管理端点
# =========================================================
@app.route("/scalp_bias", methods=["GET", "POST"])
def scalp_bias_endpoint():
    """
    v3.499: 查看或设置剥头皮每日偏向

    GET /scalp_bias
        返回所有品种的当日偏向

    GET /scalp_bias?symbol=BTCUSDC
        返回指定品种的当日偏向

    POST /scalp_bias
        Body: {"symbol": "BTCUSDC", "trend": "UP"}
        强制设置指定品种的偏向 (trend: UP/DOWN/SIDE)

    POST /scalp_bias
        Body: {"reset": true}
        重置所有品种的偏向
    """
    try:
        if request.method == "GET":
            symbol = request.args.get("symbol")
            if symbol:
                bias = get_scalp_daily_bias(symbol)
                return jsonify({
                    "symbol": symbol,
                    "daily_bias": bias
                })
            else:
                # 返回所有偏向
                return jsonify({
                    "all_bias": _scalp_daily_bias,
                    "count": len(_scalp_daily_bias)
                })

        elif request.method == "POST":
            data = request.json or {}

            if data.get("reset"):
                # 重置所有
                result = reset_scalp_daily_bias(None)
                return jsonify(result)

            if data.get("save"):
                # 保存当前偏向到文件
                return save_daily_bias_to_file()

            if data.get("batch"):
                # 批量设置: {"batch": {"BTCUSDC": "DOWN", "TSLA": "UP"}, "save": true}
                batch_config = data.get("batch", {})
                results = []
                for sym, trend in batch_config.items():
                    r = reset_scalp_daily_bias(sym, force_trend=trend)
                    results.append({"symbol": sym, "bias": r.get("bias")})

                # 如果同时指定save，保存到文件
                if data.get("save_file"):
                    save_daily_bias_to_file()

                return jsonify({
                    "batch_results": results,
                    "count": len(results)
                })

            symbol = data.get("symbol")
            if not symbol:
                return jsonify({"error": "需要指定symbol"}), 400

            trend = data.get("trend")  # UP/DOWN/SIDE
            result = reset_scalp_daily_bias(symbol, force_trend=trend)
            return jsonify({
                "symbol": symbol,
                "daily_bias": result
            })

    except Exception as e:
        return jsonify({"error": str(e)}), 500


def save_daily_bias_to_file():
    """保存当前偏向配置到 daily_bias.json"""
    from datetime import datetime
    from zoneinfo import ZoneInfo

    now_ny = datetime.now(ZoneInfo("America/New_York"))
    today_str = now_ny.strftime("%Y-%m-%d")

    # 构建配置
    bias_config = {}
    for symbol, data in _scalp_daily_bias.items():
        if data.get("date") == today_str:
            bias_config[symbol] = data.get("trend", "SIDE")

    config = {
        "date": today_str,
        "bias": bias_config,
        "updated": now_ny.strftime("%Y-%m-%d %H:%M:%S")
    }

    try:
        with open(DAILY_BIAS_FILE, "w", encoding="utf-8") as f:
            json.dump(config, f, ensure_ascii=False, indent=2)

        print(f"[v3.499] ✅ daily_bias.json 保存成功: {len(bias_config)}个品种")
        return jsonify({
            "success": True,
            "file": DAILY_BIAS_FILE,
            "date": today_str,
            "count": len(bias_config),
            "symbols": list(bias_config.keys())
        })
    except Exception as e:
        print(f"[v3.499] ⚠️ daily_bias.json 保存失败: {e}")
        return jsonify({"error": str(e)}), 500


# =========================================================
# v3.450: P0-CycleSwitch 手动触发端点
# =========================================================
@app.route("/trigger_cycle_switch", methods=["POST", "GET"])
def trigger_cycle_switch():
    """
    v3.450: 手动触发周期切换分析

    用法:
    GET  /trigger_cycle_switch?symbol=BTCUSDC&timeframe=240
    POST /trigger_cycle_switch  Body: {"symbol": "BTCUSDC", "timeframe": 240}

    功能:
    1. 预加载指定周期的OHLCV数据
    2. 运行完整三方协商分析
    3. 执行交易(如果有信号)
    4. 发送邮件通知
    """
    try:
        # 获取参数
        if request.method == "GET":
            symbol = request.args.get("symbol")
            timeframe = request.args.get("timeframe")
        else:
            data = request.get_json() or {}
            symbol = data.get("symbol")
            timeframe = data.get("timeframe") or data.get("new_timeframe")

        if not symbol:
            return jsonify({"error": "missing symbol parameter"}), 400
        if not timeframe:
            return jsonify({"error": "missing timeframe parameter"}), 400

        try:
            timeframe_int = int(timeframe)
        except ValueError:
            return jsonify({"error": f"invalid timeframe: {timeframe}"}), 400

        print(f"\n{'='*70}")
        print(f"[v3.450] 手动触发P0-CycleSwitch: {symbol} → {timeframe_int}min")
        print(f"{'='*70}")

        # 异步执行预加载+分析
        import threading
        def _async_cycle_switch():
            try:
                # 1. 预加载新周期数据
                print(f"[v3.450] {symbol}: 开始预加载 {timeframe_int}min K线...")
                _preload_single_symbol(symbol, timeframe_int)

                # 2. 运行P0-CycleSwitch分析
                print(f"[v3.450] {symbol}: 预加载完成，触发P0-CycleSwitch分析...")
                _run_cycle_switch_analysis(symbol, timeframe_int)

            except Exception as e:
                print(f"[v3.450] {symbol}: 周期切换分析失败 - {e}")
                import traceback
                traceback.print_exc()

        t = threading.Thread(target=_async_cycle_switch, daemon=True)
        t.start()

        return jsonify({
            "status": "ok",
            "message": f"P0-CycleSwitch triggered for {symbol} ({timeframe_int}min)",
            "symbol": symbol,
            "timeframe": timeframe_int,
        })

    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({"error": str(e)}), 500


@app.route("/trigger_cycle_switch_all", methods=["POST", "GET"])
def trigger_cycle_switch_all():
    """
    v3.450: 批量触发所有品种的周期切换分析

    用法:
    GET  /trigger_cycle_switch_all
    POST /trigger_cycle_switch_all

    使用SYMBOL_TIMEFRAMES配置的周期
    """
    try:
        print(f"\n{'='*70}")
        print(f"[v3.450] 批量触发P0-CycleSwitch: 所有品种")
        print(f"{'='*70}")

        triggered = []
        for symbol, timeframe in SYMBOL_TIMEFRAMES.items():
            print(f"[v3.450] 触发: {symbol} → {timeframe}min")

            # 异步执行
            import threading
            def _async_cycle_switch(sym=symbol, tf=timeframe):
                try:
                    _preload_single_symbol(sym, tf)
                    _run_cycle_switch_analysis(sym, tf)
                except Exception as e:
                    print(f"[v3.450] {sym}: 失败 - {e}")

            t = threading.Thread(target=_async_cycle_switch, daemon=True)
            t.start()
            triggered.append({"symbol": symbol, "timeframe": timeframe})

            # 间隔1秒避免API限流
            import time
            time.sleep(1)

        return jsonify({
            "status": "ok",
            "message": f"P0-CycleSwitch triggered for {len(triggered)} symbols",
            "triggered": triggered,
        })

    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({"error": str(e)}), 500


# =========================================================
# v2.830: 热修改仓位接口
# =========================================================
@app.route("/fix_position", methods=["POST"])
def fix_position():
    """
    热修改仓位接口 (v2.830)
    
    POST /fix_position
    Body: {"symbol": "TSLA", "position_units": 3}
    
    或批量修改:
    Body: {"positions": {"TSLA": 3, "AMD": 2, "COIN": 0}}
    """
    try:
        data = request.get_json()
        
        results = []
        
        # 批量模式
        if "positions" in data:
            positions = data["positions"]
            for symbol, new_units in positions.items():
                result = _fix_single_position(symbol, int(new_units))
                results.append(result)
        # 单个模式
        else:
            symbol = data.get("symbol")
            new_units = int(data.get("position_units", 0))
            
            if not symbol:
                return jsonify({"error": "missing symbol"}), 400
            
            result = _fix_single_position(symbol, new_units)
            results.append(result)
        
        # 保存到磁盘
        _save_state_to_disk()
        
        return jsonify({
            "status": "ok",
            "results": results
        })
    except Exception as e:
        print(f"[FIX_POSITION] ❌ 错误: {e}")
        return jsonify({"error": str(e)}), 500


def _fix_single_position(symbol: str, new_units: int) -> dict:
    """修改单个symbol的仓位"""
    if symbol not in symbol_state:
        # 初始化新symbol
        symbol_state[symbol] = _ensure_state_fields({})
    
    old_units = symbol_state[symbol].get("position_units", 0)
    
    # 更新仓位
    symbol_state[symbol]["position_units"] = new_units
    
    # 重建 open_buys
    if new_units > 0:
        symbol_state[symbol]["open_buys"] = [
            {"price": 0, "size": 1, "time": datetime.now().isoformat(), "note": "manual_fix"}
            for _ in range(new_units)
        ]
    else:
        symbol_state[symbol]["open_buys"] = []
    
    # 清空 open_sells
    symbol_state[symbol]["open_sells"] = []
    
    print(f"[FIX_POSITION] ✅ {symbol}: {old_units} → {new_units}")
    
    return {
        "symbol": symbol,
        "old_units": old_units,
        "new_units": new_units
    }


@app.route("/get_positions", methods=["GET"])
def get_positions():
    """
    获取所有仓位信息 (v2.830)
    
    GET /get_positions
    """
    try:
        positions = {}
        for symbol, state in symbol_state.items():
            if isinstance(state, dict):
                positions[symbol] = {
                    "position_units": state.get("position_units", 0),
                    "open_buys_count": len(state.get("open_buys", []) or []),
                    "open_sells_count": len(state.get("open_sells", []) or []),
                    "max_units": state.get("max_units", 5),
                }
        
        return jsonify({
            "status": "ok",
            "positions": positions
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


