# L2 大周期核心逻辑 (v1.99-patched)
# =========================================================

def compute_n_swing_bias(ohlcv_list, last_close):
    """
    N-swing 自动锚点逻辑 (2% / 3%)
    
    Args:
        ohlcv_list: K线数据列表 [{'close': float, 'high': float, 'low': float}, ...]
        last_close: 当前收盘价
    
    Returns:
        {'bias': str, 'score': int, 'up_after_low': float, 'down_after_high': float}
    """
    result = {
        'bias': 'N_NONE',
        'score': 0,
        'up_after_low': None,
        'down_after_high': None
    }
    
    try:
        if len(ohlcv_list) < 10 or not last_close:
            return result
        
        closes = [float(x.get('close', 0)) for x in ohlcv_list]
        highs = [float(x.get('high', 0)) for x in ohlcv_list]
        lows = [float(x.get('low', 0)) for x in ohlcv_list]
        
        # 找方向变化
        dirs = [1 if closes[i] > closes[i-1] else -1 for i in range(1, len(closes))]
        last_up_end, last_down_end = None, None
        
        for i in range(len(dirs)-2, 1, -1):
            if dirs[i] < 0 and dirs[i-1] > 0 and last_up_end is None:
                last_up_end = i
            if dirs[i] > 0 and dirs[i-1] < 0 and last_down_end is None:
                last_down_end = i
            if last_up_end is not None and last_down_end is not None:
                break
        
        # 计算摆动水平
        up_after_low = None
        down_after_high = None
        
        if last_up_end is not None and last_up_end < len(lows):
            up_after_low = min(lows[last_up_end:])
            result['up_after_low'] = up_after_low
        
        if last_down_end is not None and last_down_end < len(highs):
            down_after_high = max(highs[last_down_end:])
            result['down_after_high'] = down_after_high
        
        # 判断 N-swing 偏向
        if up_after_low and up_after_low > 0:
            up_ratio = last_close / up_after_low
            if N_SWING_WEAK_BUY_THRESHOLD <= up_ratio < N_SWING_STRONG_BUY_THRESHOLD:
                result['bias'] = 'N_BUY_WEAK'
                result['score'] = 1
            elif up_ratio >= N_SWING_STRONG_BUY_THRESHOLD:
                result['bias'] = 'N_BUY_STRONG'
                result['score'] = 2
        
        if down_after_high and down_after_high > 0:
            down_ratio = last_close / down_after_high
            if N_SWING_STRONG_SELL_THRESHOLD < down_ratio <= N_SWING_WEAK_SELL_THRESHOLD:
                result['bias'] = 'N_SELL_WEAK'
                result['score'] = -1
            elif down_ratio <= N_SWING_STRONG_SELL_THRESHOLD:
                result['bias'] = 'N_SELL_STRONG'
                result['score'] = -2
        
        print(f'[N-SWING] bias={result["bias"]}, score={result["score"]}')
        
    except Exception as e:
        print(f'[警告] N-swing 计算失败: {e}')
    
    return result


# ============================================================================
# v3.370 废弃函数: compute_l2_exec_bias
# ============================================================================
# 废弃原因:
#   1. 此函数从未被调用 (已确认无任何调用点)
#   2. 与 compute_exec_bias_with_scoring 功能重复
#   3. 使用简化的位置逻辑，缺少评分系统
#   4. 保留代码供参考，但不应使用
#
# 替代方案:
#   使用 compute_exec_bias_with_scoring() 或 compute_l2_macro_exec_bias_enhanced()
#
# 保留日期: 2026-01-10
# 代码行数: ~106行 (36960-37065)
# ============================================================================

def compute_l2_exec_bias(sr_zone, pa_edge_buy, pa_edge_sell, volume_state,
                        ohlcv_list=None, last_close=None):
    """
    [废弃] 根据位置 + PA Edge + 成交量状态输出 L2 执行层倾向

    ⚠️ 此函数已废弃，请勿调用。保留仅供历史参考。
    替代方案: compute_exec_bias_with_scoring() 或 compute_l2_macro_exec_bias_enhanced()

    Args:
        sr_zone: 支撑阻力区域标识
        pa_edge_buy: PA买入边缘信号
        pa_edge_sell: PA卖出边缘信号
        volume_state: 量能状态
        ohlcv_list: 可选，K线数据用于N-swing增强
        last_close: 可选，当前价格
    
    Returns:
        dict: {
            'exec_bias': str,           # 执行偏向
            'n_swing_override': bool,   # 是否为N-swing强信号
            'n_swing_score': int        # N-swing分数
        }
    """
    try:
        if not sr_zone:
            return {'exec_bias': "HOLD", 'n_swing_override': False, 'n_swing_score': 0}  # [PATCHED]

        vol_boost = volume_state in ("RISING", "CLIMAX")
        exec_bias = "HOLD"
        
        # ========================================================================
        # v2.540: L2 执行层逻辑优化 - 修复过度保守问题
        # ========================================================================
        # 核心改进:
        # 1. 支撑位无 PA Edge 时允许 BUY（降级但不阻断）
        # 2. 阻力位无 PA Edge 时允许 SELL（降级但不阻断）
        # 3. 中部不再直接 HOLD，基于 PA Edge 判断
        # ========================================================================
        
        if sr_zone in ("LOW", "LOW_HALF", "SUPPORT"):
            # 支撑位逻辑
            if pa_edge_buy:
                exec_bias = "STRONG_BUY" if vol_boost else "BUY"
                print(f"[L2-EXEC] 支撑位+PA买入: {exec_bias} (vol_boost={vol_boost})")
            else:
                # v2.540 修复: 支撑位即使无 PA Edge 也允许买入（降级）
                exec_bias = "BUY"
                print(f"[L2-EXEC] 支撑位无PA但允许买入: BUY (降级)")
                
        elif sr_zone in ("HIGH", "UPPER", "UPPER_HALF", "RESISTANCE"):
            # 阻力位逻辑
            if pa_edge_sell:
                exec_bias = "STRONG_SELL" if vol_boost else "SELL"
                print(f"[L2-EXEC] 阻力位+PA卖出: {exec_bias} (vol_boost={vol_boost})")
            else:
                # v2.540 修复: 阻力位即使无 PA Edge 也允许卖出（降级）
                exec_bias = "SELL"
                print(f"[L2-EXEC] 阻力位无PA但允许卖出: SELL (降级)")
                
        else:
            # v2.540 修复: 中部不再直接 HOLD，基于 PA Edge 判断
            if pa_edge_buy and vol_boost:
                exec_bias = "BUY"
                print(f"[L2-EXEC] 中部+放量+PA买入: BUY")
            elif pa_edge_sell and vol_boost:
                exec_bias = "SELL"
                print(f"[L2-EXEC] 中部+放量+PA卖出: SELL")
            elif pa_edge_buy:
                exec_bias = "BUY"
                print(f"[L2-EXEC] 中部+PA买入: BUY (无放量)")
            elif pa_edge_sell:
                exec_bias = "SELL"
                print(f"[L2-EXEC] 中部+PA卖出: SELL (无放量)")
            else:
                exec_bias = "HOLD"
                print(f"[L2-EXEC] 中部无明确信号: HOLD")
        
        # N-swing 增强逻辑
        if ohlcv_list and last_close and len(ohlcv_list) >= 10:
            n_swing = compute_n_swing_bias(ohlcv_list, last_close)
            n_score = n_swing['score']
            
            if n_score > 0 and exec_bias in ['BUY', 'HOLD']:
                exec_bias = 'STRONG_BUY'
                print(f'[L2-EXEC] N-swing增强买入: {n_swing["bias"]}')
            elif n_score < 0 and exec_bias in ['SELL', 'HOLD']:
                exec_bias = 'STRONG_SELL'
                print(f'[L2-EXEC] N-swing增强卖出: {n_swing["bias"]}')
        
        # [PATCHED] 判断是否为N-swing强信号
        n_swing_override = False
        n_swing_score = 0
        if 'n_swing' in locals() and 'n_score' in locals():
            n_swing_score = n_score
            # 强信号阈值：score绝对值 >= 2
            if abs(n_score) >= 2:
                n_swing_override = True
                print(f'[N-SWING] 强信号触发: score={n_score}, override=True')
        
        # [PATCHED] 返回dict而非字符串
        return {
            'exec_bias': exec_bias,
            'n_swing_override': n_swing_override,
            'n_swing_score': n_swing_score,
        }
    
    except Exception as e:
        print(f'[L2-EXEC] 计算失败: {e}')
        return {'exec_bias': "HOLD", 'n_swing_override': False, 'n_swing_score': 0}  # [PATCHED]


def apply_l2_macro_logic(support, mid, resistance, last_close, pa_bias, volume_state):
    """
    L2 大周期决策逻辑
    
    Args:
        support: 支撑位
        mid: 中轴位
        resistance: 阻力位
        last_close: 当前价格
        pa_bias: PA偏向 ('BULL' | 'BEAR' | ...)
        volume_state: 量能状态
    
    Returns:
        'BUY' | 'SELL' | 'HOLD'
    """
    try:
        if None in (support, mid, resistance, last_close):
            return "HOLD"

        # 判断当前K线所处区域
        zone = "LOW_HALF" if last_close <= mid else "UPPER_HALF"

        # 放量提升信号置信度
        vol_boost = volume_state in ("RISING", "CLIMAX")

        # 决策逻辑
        if zone == "LOW_HALF":
            if pa_bias == "BULL" and vol_boost:
                action = "BUY"
            else:
                action = "HOLD"
        else:
            if pa_bias == "BEAR" and vol_boost:
                action = "SELL"
            else:
                action = "HOLD"

        print(f"[L2-MACRO] zone={zone}, pa={pa_bias}, vol={volume_state} -> {action}")
        return action
    
    except Exception as e:
        print(f"[L2-MACRO] 计算失败: {e}")
        return "HOLD"


# ==========================================
# v2.550: Grid 动态置信度系统
# ==========================================

import json
import os
import time
import threading
from collections import defaultdict
from typing import Dict, Optional, Tuple

# Grid 规则表现文件路径
GRID_RULE_PERFORMANCE_FILE = "state/grid_rule_performance.json"

class GridRuleTracker:
    """
    Grid 规则追踪器 (v2.550)
    
    功能:
    1. 追踪每条 Grid 规则的历史表现
    2. 基于实际胜率动态更新置信度
    3. 持久化到磁盘
    4. 规则质量分级（TIER 1-4）
    
    设计思路:
    - 初始置信度从 GRID_CONFIDENCE_TABLE 加载
    - 样本不足（<5）时使用初始值
    - 样本充足时使用 EMA 算法更新
    - 置信度范围限制在 [0.50, 0.95]
    """
    
    def __init__(self, filepath: str = GRID_RULE_PERFORMANCE_FILE):
        self.filepath = filepath
        self.lock = threading.Lock()
        
        # 规则表现记录
        # {grid_key_str: {"total": N, "win": M, "confidence": X, "initial_confidence": Y}}
        self.rule_performance: Dict[str, dict] = {}
        
        # 统计
        self.total_rules = 0
        self.rules_with_data = 0
        self.last_updated_ts = 0
        
        # 初始化
        self._initialize()
        self.load()
    
    def _grid_key_to_str(self, grid_key: tuple) -> str:
        """将 tuple 转为字符串用作 key"""
        return str(grid_key)
    
    def _initialize(self):
        """初始化规则表现记录"""
        print(f"[GRID_TRACKER] 初始化 Grid 规则追踪器")
        
        # 从 GRID_CONFIDENCE_TABLE 加载初始置信度
        for grid_key, initial_conf in GRID_CONFIDENCE_TABLE.items():
            key_str = self._grid_key_to_str(grid_key)
            if key_str not in self.rule_performance:
                self.rule_performance[key_str] = {
                    "total": 0,
                    "win": 0,
                    "loss": 0,
                    "confidence": initial_conf,
                    "initial_confidence": initial_conf,
                    "last_updated": 0,
                }
        
        self.total_rules = len(self.rule_performance)
        print(f"[GRID_TRACKER] ✓ 加载 {self.total_rules} 条初始规则")
    
    def get_confidence(self, grid_key: tuple) -> float:
        """
        获取规则当前置信度（动态）
        
        Args:
            grid_key: Grid 查询键
        
        Returns:
            当前置信度 (0.5-0.95)
        """
        key_str = self._grid_key_to_str(grid_key)
        
        with self.lock:
            if key_str not in self.rule_performance:
                # 新规则，使用默认值
                default_conf = 0.60
                print(f"[GRID_TRACKER] 新规则，使用默认置信度: {default_conf:.2f}")
                return default_conf
            
            data = self.rule_performance[key_str]
            
            # 样本不足，使用初始值
            if data["total"] < 5:
                return data["initial_confidence"]
            
            # 样本充足，返回动态置信度
            return data["confidence"]
    
    def update_performance(
        self,
        grid_key: tuple,
        success: bool,
    ):
        """
        更新规则表现（交易完成后调用）
        
        Args:
            grid_key: Grid 查询键
            success: 是否成功 (True=赢, False=输)
        """
        key_str = self._grid_key_to_str(grid_key)
        
        with self.lock:
            if key_str not in self.rule_performance:
                # 初始化新规则
                initial_conf = GRID_CONFIDENCE_TABLE.get(grid_key, 0.60)
                self.rule_performance[key_str] = {
                    "total": 0,
                    "win": 0,
                    "loss": 0,
                    "confidence": initial_conf,
                    "initial_confidence": initial_conf,
                    "last_updated": 0,
                }
            
            data = self.rule_performance[key_str]
            data["total"] += 1
            
            if success:
                data["win"] += 1
            else:
                data["loss"] += 1
            
            data["last_updated"] = time.time()
            
            # 重新计算置信度（样本充足时）
            if data["total"] >= 5:
                win_rate = data["win"] / data["total"]
                
                # EMA 更新: 新 = 70% 实际胜率 + 30% 旧置信度
                alpha = 0.7
                old_conf = data["confidence"]
                new_conf = alpha * win_rate + (1 - alpha) * old_conf
                
                # 限制范围 [0.50, 0.95]
                new_conf = max(0.50, min(0.95, new_conf))
                
                data["confidence"] = new_conf
                
                # 日志
                print(f"[GRID_TRACKER] 规则更新:")
                print(f"  Key: {grid_key}")
                print(f"  Samples: {data['total']} (W:{data['win']} L:{data['loss']})")
                print(f"  Win Rate: {win_rate:.2%}")
                print(f"  Confidence: {old_conf:.3f} → {new_conf:.3f}")
                print(f"  Tier: {self._get_tier(new_conf)}")
                
                # 更新统计
                self.rules_with_data = sum(
                    1 for v in self.rule_performance.values() if v["total"] >= 5
                )
            
            self.last_updated_ts = time.time()
    
    def _get_tier(self, confidence: float) -> str:
        """
        获取规则分级
        
        Args:
            confidence: 置信度
        
        Returns:
            "TIER_1_GOLD" / "TIER_2_SILVER" / "TIER_3_BRONZE" / "TIER_4_IRON"
        """
        if confidence >= 0.85:
            return "TIER_1_GOLD"
        elif confidence >= 0.75:
            return "TIER_2_SILVER"
        elif confidence >= 0.65:
            return "TIER_3_BRONZE"
        else:
            return "TIER_4_IRON"
    
    def should_use_rule(
        self,
        grid_confidence: float,
        llm_confidence: float,
    ) -> bool:
        """
        判断是否应该使用 Grid 规则
        
        低质量规则（IRON）在特定条件下禁用
        
        Args:
            grid_confidence: Grid 置信度
            llm_confidence: LLM 置信度
        
        Returns:
            是否使用规则
        """
        tier = self._get_tier(grid_confidence)
        
        # TIER 4 (IRON) 规则: 低质量，谨慎使用
        if tier == "TIER_4_IRON":
            # 如果 LLM 很确定，忽略低质量 Grid 规则
            if llm_confidence > 0.80:
                print(f"[GRID_TRACKER] IRON 规则被 LLM 高置信度({llm_confidence:.2f})覆盖")
                return False
        
        return True
    
    def get_stats(self) -> dict:
        """获取统计信息"""
        with self.lock:
            tier_counts = {
                "TIER_1_GOLD": 0,
                "TIER_2_SILVER": 0,
                "TIER_3_BRONZE": 0,
                "TIER_4_IRON": 0,
            }
            
            for data in self.rule_performance.values():
                if data["total"] >= 5:
                    tier = self._get_tier(data["confidence"])
                    tier_counts[tier] += 1
            
            return {
                "total_rules": len(self.rule_performance),
                "rules_with_data": sum(1 for v in self.rule_performance.values() if v["total"] >= 5),
                "tier_distribution": tier_counts,
                "last_updated": self.last_updated_ts,
            }
    
    def save(self):
        """保存到磁盘"""
        with self.lock:
            try:
                os.makedirs(os.path.dirname(self.filepath), exist_ok=True)
                
                data_to_save = {
                    "rule_performance": self.rule_performance,
                    "last_updated": self.last_updated_ts,
                    "total_rules": len(self.rule_performance),
                }
                
                with open(self.filepath, 'w') as f:
                    json.dump(data_to_save, f, indent=2)
                
                print(f"[GRID_TRACKER] ✓ 保存成功: {self.filepath}")
            except Exception as e:
                print(f"[GRID_TRACKER] ✗ 保存失败: {e}")
    
    def load(self):
        """从磁盘加载"""
        try:
            if not os.path.exists(self.filepath):
                print(f"[GRID_TRACKER] 初始化新文件: {self.filepath}")
                self.save()
                return
            
            with open(self.filepath, 'r') as f:
                data = json.load(f)
            
            self.rule_performance = data.get("rule_performance", {})
            self.last_updated_ts = data.get("last_updated", 0)
            
            # 更新统计
            self.total_rules = len(self.rule_performance)
            self.rules_with_data = sum(
                1 for v in self.rule_performance.values() if v["total"] >= 5
            )
            
            stats = self.get_stats()
            
            print(f"[GRID_TRACKER] ✓ 加载成功:")
            print(f"  总规则数: {stats['total_rules']}")
            print(f"  有数据规则: {stats['rules_with_data']}")
            print(f"  分级分布: GOLD={stats['tier_distribution']['TIER_1_GOLD']} "
                  f"SILVER={stats['tier_distribution']['TIER_2_SILVER']} "
                  f"BRONZE={stats['tier_distribution']['TIER_3_BRONZE']} "
                  f"IRON={stats['tier_distribution']['TIER_4_IRON']}")
        except Exception as e:
            print(f"[GRID_TRACKER] ⚠️ 加载失败: {e}, 使用初始配置")

# 全局 Grid 追踪器实例
_grid_tracker_instance: Optional[GridRuleTracker] = None

def get_grid_tracker() -> GridRuleTracker:
    """获取全局 Grid 追踪器实例（单例）"""
    global _grid_tracker_instance
    if _grid_tracker_instance is None:
        _grid_tracker_instance = GridRuleTracker()
    return _grid_tracker_instance


# ==========================================
# v2.530: LLM 置信度校准器
# ==========================================

import json
import os
import time
import threading
from collections import defaultdict
from typing import Dict, Optional, Tuple

class LLMConfidenceCalibrator:
    """
    LLM 置信度校准器
    
    功能:
    1. 维护分桶校准表（raw_confidence → calibrated_confidence）
    2. 基于实际胜率更新校准
    3. 持久化到磁盘
    """
    
    def __init__(self, filepath: str = CALIBRATION_FILE):
        self.filepath = filepath
        self.lock = threading.Lock()
        
        # 分桶表: {bucket_key: {"count": int, "win": int, "calibrated": float}}
        self.calibration_table: Dict[str, dict] = {}
        
        # 统计
        self.total_samples = 0
        self.last_updated_ts = 0
        
        # 决策追踪: {symbol: (raw_confidence, timestamp, decision_id)}
        self.decision_tracker: Dict[str, Tuple[float, float, str]] = {}
        
        # 初始化
        self._initialize_buckets()
        self.load()
    
    def _initialize_buckets(self):
        """初始化分桶"""
        buckets = [
            "0.0-0.1", "0.1-0.2", "0.2-0.3", "0.3-0.4", "0.4-0.5",
            "0.5-0.6", "0.6-0.7", "0.7-0.8", "0.8-0.9", "0.9-1.0"
        ]
        for bucket in buckets:
            if bucket not in self.calibration_table:
                self.calibration_table[bucket] = {
                    "count": 0,
                    "win": 0,
                    "calibrated": float(bucket.split("-")[0])  # 默认使用桶下限
                }
    
    def _get_bucket_key(self, raw_confidence: float) -> str:
        """获取桶键"""
        raw_confidence = max(0.0, min(1.0, raw_confidence))
        bucket_idx = int(raw_confidence * 10)
        if bucket_idx == 10:  # 处理 1.0 的情况
            bucket_idx = 9
        
        buckets = [
            "0.0-0.1", "0.1-0.2", "0.2-0.3", "0.3-0.4", "0.4-0.5",
            "0.5-0.6", "0.6-0.7", "0.7-0.8", "0.8-0.9", "0.9-1.0"
        ]
        return buckets[bucket_idx]
    
    def calibrate(self, raw_confidence: float) -> Tuple[float, dict]:
        """
        校准置信度
        
        Args:
            raw_confidence: 原始置信度 (0.0-1.0)
        
        Returns:
            (calibrated_confidence, stats_dict)
        """
        if not ENABLE_CALIBRATION:
            return raw_confidence, {"method": "disabled"}
        
        with self.lock:
            bucket_key = self._get_bucket_key(raw_confidence)
            bucket = self.calibration_table.get(bucket_key, {})
            
            count = bucket.get("count", 0)
            calibrated = bucket.get("calibrated", raw_confidence)
            
            # 校准逻辑
            if count >= CALIBRATION_MIN_SAMPLES:
                # 有足够样本，使用校准值
                final = calibrated
                method = "calibrated"
            elif count > 0:
                # 样本不足，轻微降低
                final = raw_confidence * 0.95
                method = "partial"
            else:
                # 无样本，保守降低
                final = raw_confidence * 0.90
                method = "fallback"
            
            # Clamp
            final = max(CALIBRATION_CLAMP_MIN, min(CALIBRATION_CLAMP_MAX, final))
            
            stats = {
                "bucket": bucket_key,
                "count": count,
                "win_rate": bucket.get("win", 0) / count if count > 0 else 0.0,
                "method": method,
                "calibrated": final
            }
            
            return final, stats
    
    def track_decision(self, symbol: str, raw_confidence: float, decision_id: str = None):
        """
        追踪决策
        
        Args:
            symbol: 交易标的
            raw_confidence: 原始置信度
            decision_id: 决策ID（可选）
        """
        if not ENABLE_CALIBRATION:
            return
        
        with self.lock:
            timestamp = time.time()
            if decision_id is None:
                decision_id = f"{symbol}_{int(timestamp * 1000)}"
            
            self.decision_tracker[symbol] = (raw_confidence, timestamp, decision_id)
            
            # 清理过期追踪（超过1小时）
            cutoff = timestamp - 3600
            expired = [
                sym for sym, (_, ts, _) in self.decision_tracker.items()
                if ts < cutoff
            ]
            for sym in expired:
                del self.decision_tracker[sym]
    
    def update(self, symbol: str, result: bool, raw_confidence: float = None) -> Optional[dict]:
        """
        更新校准器
        
        Args:
            symbol: 交易标的
            result: 交易结果（True=盈利, False=亏损）
            raw_confidence: 原始置信度（可选，如果不提供则从追踪中获取）
        
        Returns:
            更新信息 dict 或 None
        """
        if not ENABLE_CALIBRATION:
            return None
        
        with self.lock:
            # 获取 raw_confidence
            weak_link = False
            if raw_confidence is None:
                if symbol in self.decision_tracker:
                    raw_confidence, _, decision_id = self.decision_tracker[symbol]
                    # 清除追踪
                    del self.decision_tracker[symbol]
                else:
                    # 无法关联，跳过
                    print(f"[CALIBRATION UPDATE] ⚠️ No tracked decision for {symbol}, skipping")
                    return None
            else:
                weak_link = True
            
            # 更新桶
            bucket_key = self._get_bucket_key(raw_confidence)
            bucket = self.calibration_table[bucket_key]
            
            bucket["count"] += 1
            if result:
                bucket["win"] += 1
            
            # 重新计算校准值
            if bucket["count"] >= CALIBRATION_MIN_SAMPLES:
                bucket["calibrated"] = bucket["win"] / bucket["count"]
                # Clamp
                bucket["calibrated"] = max(
                    CALIBRATION_CLAMP_MIN,
                    min(CALIBRATION_CLAMP_MAX, bucket["calibrated"])
                )
            
            self.total_samples += 1
            self.last_updated_ts = time.time()
            
            # 保存
            self.save()
            
            update_info = {
                "bucket": bucket_key,
                "count": bucket["count"],
                "win": bucket["win"],
                "win_rate": bucket["win"] / bucket["count"],
                "calibrated": bucket["calibrated"],
                "result": "WIN" if result else "LOSS",
                "weak_link": weak_link
            }
            
            return update_info
    
    def load(self):
        """从磁盘加载"""
        try:
            if not os.path.exists(self.filepath):
                print(f"[CALIBRATION] 初始化新的校准文件: {self.filepath}")
                self.save()
                return
            
            with open(self.filepath, 'r', encoding='utf-8') as f:
                data = json.load(f)
            
            self.calibration_table = data.get("calibration_table", {})
            self.total_samples = data.get("total_samples", 0)
            self.last_updated_ts = data.get("last_updated_ts", 0)
            
            # 确保所有桶都存在
            self._initialize_buckets()
            
            print(f"[CALIBRATION] ✓ 加载成功: {self.total_samples} 样本")
            
        except json.JSONDecodeError as e:
            print(f"[CALIBRATION] ⚠️ 文件损坏: {e}")
            # 备份损坏文件
            backup_path = f"{self.filepath}.corrupted.{int(time.time())}"
            try:
                import shutil
                shutil.copy2(self.filepath, backup_path)
                print(f"[CALIBRATION] 已备份损坏文件: {backup_path}")
            except Exception as e2:
                print(f"[CALIBRATION] 备份失败: {e2}")
            # 重置
            self._initialize_buckets()
            self.save()
        except Exception as e:
            print(f"[CALIBRATION] ⚠️ 加载失败: {e}")
            self._initialize_buckets()
    
    def save(self):
        """保存到磁盘（原子写入）"""
        try:
            # 确保目录存在
            os.makedirs(os.path.dirname(self.filepath) if os.path.dirname(self.filepath) else ".", exist_ok=True)
            
            data = {
                "calibration_table": self.calibration_table,
                "total_samples": self.total_samples,
                "last_updated_ts": self.last_updated_ts,
                "version": AIPRO_VERSION
            }
            
            # 原子写入
            temp_path = f"{self.filepath}.tmp"
            with open(temp_path, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2)
            
            # 替换
            os.replace(temp_path, self.filepath)
            
        except Exception as e:
            print(f"[CALIBRATION] ⚠️ 保存失败: {e}")


# 全局校准器实例
_global_calibrator = None

def get_calibrator() -> LLMConfidenceCalibrator:
    """获取全局校准器实例"""
    global _global_calibrator
    if _global_calibrator is None:
        _global_calibrator = LLMConfidenceCalibrator()
    return _global_calibrator


# ==========================================
# v2.530: LLM 缓存系统
# ==========================================

class LLMCache:
    """
    LLM 响应缓存
    
    基于市场状态（trend/pos_zone/wyckoff/pa_edge/pos_ratio）生成缓存键
    缓存有效期 5 分钟
    """
    
    def __init__(self, ttl: int = CACHE_TTL_SECONDS, max_size: int = CACHE_MAX_SIZE):
        self.ttl = ttl
        self.max_size = max_size
        self.cache: Dict[str, Tuple[dict, float]] = {}  # {key: (response, timestamp)}
        self.lock = threading.Lock()
    
    def _make_key(self, symbol: str, market_data: dict) -> str:
        """生成缓存键（粗粒度）"""
        # 提取关键特征
        trend = market_data.get("trend_state", "UNKNOWN")
        pos_zone = market_data.get("pos_zone", "UNKNOWN")
        wyckoff = market_data.get("wyckoff_phase", "UNKNOWN")
        pa_buy = market_data.get("pa_edge_buy", False)
        pa_sell = market_data.get("pa_edge_sell", False)
        pos_ratio = market_data.get("pos_ratio", 0.0)
        
        # 粗粒度位置（0-25-50-75-100）
        pos_bucket = int(pos_ratio * 4) * 25  # 0, 25, 50, 75, 100
        
        key = f"{symbol}:{trend}:{pos_zone}:{wyckoff}:pa_buy={pa_buy}:pa_sell={pa_sell}:pos={pos_bucket}"
        return key
    
    def get(self, symbol: str, market_data: dict) -> Optional[dict]:
        """获取缓存"""
        if not ENABLE_LLM_CACHE:
            return None
        
        with self.lock:
            key = self._make_key(symbol, market_data)
            
            if key in self.cache:
                response, timestamp = self.cache[key]
                
                # 检查是否过期
                if time.time() - timestamp < self.ttl:
                    print(f"[LLM_CACHE] ✓ HIT key={key}")
                    # 标记为缓存
                    cached_response = response.copy()
                    cached_response["llm_cached"] = True
                    cached_response["cache_age"] = time.time() - timestamp
                    return cached_response
                else:
                    # 过期，删除
                    del self.cache[key]
            
            return None
    
    def set(self, symbol: str, market_data: dict, response: dict):
        """设置缓存"""
        if not ENABLE_LLM_CACHE:
            return
        
        with self.lock:
            key = self._make_key(symbol, market_data)
            
            # 检查大小限制
            if len(self.cache) >= self.max_size:
                # 删除最旧的
                oldest_key = min(self.cache.items(), key=lambda x: x[1][1])[0]
                del self.cache[oldest_key]
            
            self.cache[key] = (response, time.time())
    
    def clear(self):
        """清空缓存"""
        with self.lock:
            self.cache.clear()


# 全局缓存实例
_global_llm_cache = None

def get_llm_cache() -> LLMCache:
    """获取全局缓存实例"""
    global _global_llm_cache
    if _global_llm_cache is None:
        _global_llm_cache = LLMCache()
    return _global_llm_cache


