    # v3.660: Signal Gate 本地预热线程 (仅在有OpenBB的机器上生效)
    def _signal_gate_worker_loop():
        """后台循环运行 signal gate 预热，每4小时刷新一次。
        远程服务器无OpenBB → import失败 → 静默退出。"""
        try:
            import sys as _sgsys
            _sg_base = os.path.join(os.path.dirname(os.path.abspath(__file__)), ".GCC", "improvement", "key-010", "_unsorted")
            if _sg_base not in _sgsys.path:
                _sgsys.path.insert(0, _sg_base)
            from signal_gate import SignalGate
        except ImportError:
            log_to_server("[SIGNAL_GATE_WORKER] OpenBB未安装，尝试自动安装...")
            try:
                import subprocess as _sgsp
                _sgsp.check_call(
                    [_sgsys.executable, "-m", "pip", "install", "-q",
                     "--no-build-isolation",
                     "openbb-yfinance", "numpy", "scipy", "pandas"],
                    timeout=300
                )
                from signal_gate import SignalGate
                log_to_server("[SIGNAL_GATE_WORKER] OpenBB安装成功")
            except Exception as _install_e:
                log_to_server(f"[SIGNAL_GATE_WORKER] OpenBB安装失败，跳过预热: {_install_e}")
                return
        except Exception as _sge:
            log_to_server(f"[SIGNAL_GATE_WORKER] 初始化失败，跳过预热: {_sge}")
            return

        import json as _sgj
        import time as _sgt

        _SG_CRYPTO = {
            "BTCUSDC": ("BTC-USD", "crypto"),
            "ETHUSDC": ("ETH-USD", "crypto"),
            "SOLUSDC": ("SOL-USD", "crypto"),
            "ZECUSDC": ("ZEC-USD", "crypto"),
        }
        _SG_STOCKS = ["TSLA", "COIN", "RDDT", "NBIS", "CRWV",
                      "RKLB", "HIMS", "OPEN", "AMD", "ONDS", "PLTR"]
        _SG_INTERVAL = 4 * 3600

        while True:
            try:
                gate_eq = SignalGate(provider="yfinance", fallback="yfinance",
                                     lookback_days=30, cache_ttl=_SG_INTERVAL, asset_type="equity")
                gate_cr = SignalGate(provider="yfinance", fallback="yfinance",
                                     lookback_days=30, cache_ttl=_SG_INTERVAL, asset_type="crypto")
                from datetime import datetime, timezone as _tz
                _ts = datetime.now(_tz.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
                out = {}
                for _main_sym, (_yf_sym, _atype) in _SG_CRYPTO.items():
                    out[_main_sym] = {}
                    _gate = gate_cr
                    for _dir in ("BUY", "SELL"):
                        try:
                            _r = _gate.check(_yf_sym, _dir.lower())
                            out[_main_sym][_dir] = {
                                "go": _r.go, "regime": _r.regime,
                                "vr": round(_r.variance_ratio, 4) if _r.variance_ratio == _r.variance_ratio else None,
                                "flow": _r.flow_direction, "alignment": _r.alignment,
                                "reason": _r.reason, "ts": _ts,
                            }
                        except Exception as _e:
                            out[_main_sym][_dir] = {"go": None, "regime": "error", "reason": str(_e), "ts": _ts}
                for _sym in _SG_STOCKS:
                    out[_sym] = {}
                    for _dir in ("BUY", "SELL"):
                        try:
                            _r = gate_eq.check(_sym, _dir.lower())
                            out[_sym][_dir] = {
                                "go": _r.go, "regime": _r.regime,
                                "vr": round(_r.variance_ratio, 4) if _r.variance_ratio == _r.variance_ratio else None,
                                "flow": _r.flow_direction, "alignment": _r.alignment,
                                "reason": _r.reason, "ts": _ts,
                            }
                        except Exception as _e:
                            out[_sym][_dir] = {"go": None, "regime": "error", "reason": str(_e), "ts": _ts}
                out["_meta"] = {"updated_at": _ts, "version": "v3"}
                os.makedirs("state", exist_ok=True)
                _sg_path = os.path.join("state", "signal_gate_state.json")
                with open(_sg_path, "w", encoding="utf-8") as _f:
                    _sgj.dump(out, _f, indent=2, ensure_ascii=False)
                log_to_server(f"[SIGNAL_GATE_WORKER] 预热完成 {_ts}, 写入 {_sg_path}")
            except Exception as _ex:
                log_to_server(f"[SIGNAL_GATE_WORKER] 预热失败: {_ex}")
            _sgt.sleep(_SG_INTERVAL)

    _sg_thread = threading.Thread(target=_signal_gate_worker_loop, daemon=True, name="SignalGateWorker")
    _sg_thread.start()
    print("[v3.660] ✅ 已启动Signal Gate预热线程 (有OpenBB则生效, 否则静默跳过)")
