# ============================================================================
# v2.700 FULL_ASSET_PATCH: 幂等性存储管理
# ============================================================================

IDEMPOTENCY_MAX_SIZE = 1000      # 最大存储条数
IDEMPOTENCY_TTL_SECONDS = 86400  # 24小时过期

def _cleanup_idempotency_stores():
    """
    v2.700: 清理所有symbol的幂等性存储
    
    清理策略：
    1. 删除超过24小时的旧记录
    2. 超过1000条时删除最旧的记录
    """
    import time
    global symbol_state
    
    now = time.time()
    total_cleaned = 0
    
    for sym, state in symbol_state.items():
        if not isinstance(state, dict):
            continue
        
        idem_dict = state.get("rhythm_idem", {})
        if not idem_dict:
            continue
        
        original_size = len(idem_dict)
        
        # 1. 删除过期记录（超过24小时）
        expired_keys = [k for k, v in idem_dict.items() 
                       if isinstance(v, (int, float)) and now - v > IDEMPOTENCY_TTL_SECONDS]
        for k in expired_keys:
            del idem_dict[k]
        
        # 2. 超过上限则删除最旧的
        if len(idem_dict) > IDEMPOTENCY_MAX_SIZE:
            # 按时间戳排序，保留最新的
            sorted_items = sorted(idem_dict.items(), key=lambda x: x[1] if isinstance(x[1], (int, float)) else 0)
            keep_count = IDEMPOTENCY_MAX_SIZE
            idem_dict.clear()
            for k, v in sorted_items[-keep_count:]:
                idem_dict[k] = v
        
        state["rhythm_idem"] = idem_dict
        cleaned = original_size - len(idem_dict)
        if cleaned > 0:
            total_cleaned += cleaned
    
    if total_cleaned > 0:
        print(f"[IDEMPOTENCY_CLEANUP] 🧹 清理了 {total_cleaned} 条过期幂等键")

_autosave_thread = None
_autosave_stop_event = threading.Event()
_AUTOSAVE_INTERVAL = 300  # 5分钟
_l1_tracker_last_daily_date = {"value": None}  # v3.160: 使用可变对象保存日报日期状态
_key003_last_batch_date = {"value": None}      # v3.663: KEY-003每日批量运行日期
