                        from key009_audit import audit as _k9_audit, format_text as _k9_fmt

                        # 24h窗口 + 8am slot做覆盖率检查
                        _k9_is_8am = (_slot_k9 == 0)  # slot 0 = 8am~12pm
                        _k9_data = _k9_audit("logs/server.log,logs/price_scan_engine.log,logs/deepseek_arbiter.log,logs/macd_divergence.log,logs/rob_hoffman_plugin.log,logs/l1_module_diagnosis.log,logs/value_analysis.log",
                                             hours=24, check_coverage=_k9_is_8am)
                        for _t in _k9_data.get("tasks", {}).values():
                            _t.pop("recent", None)

                        _k9_risks = [i for i in _k9_data.get("issues", []) if i["type"] in ("ERROR", "RISK")]

                        # --- 修正检测: 上轮问题本轮消失 → 已修正 ---
                        _SKIP_RESOLVE = {"GATE-SignalStack", "DATA-STALE", "GATE-DATA-STALE"}
                        _k9_resolved = []
