def _baseline_scheduler_worker():
    """独立baseline调度器：启动后执行一次，随后每4小时执行一次。"""
    while not _baseline_scheduler_stop_event.is_set():
        try:
            try:
                os.makedirs("state", exist_ok=True)
                with open(os.path.join("state", "baseline_scheduler_heartbeat.txt"), "w", encoding="utf-8") as _hb:
                    _hb.write(str(time.time()))
            except Exception:
                pass

            _now_bl = time.time()
            _is_first_boot = (_baseline_vision_last_run["value"] == 0.0)
            _need_periodic_refresh = (
                (not _is_first_boot)
                and ((_now_bl - _baseline_vision_last_run["value"]) >= _BASELINE_VISION_INTERVAL_SECONDS)
            )
            if _is_first_boot or _need_periodic_refresh:
                _prev_bl = _baseline_vision_last_run["value"]
                from baseline_vision_task import update_all_symbols
                update_all_symbols(symbol_state, log_fn=log_to_server)
                _baseline_vision_last_run["value"] = _now_bl
                try:
                    with open(os.path.join("state", "baseline_scheduler_last_run.txt"), "w", encoding="utf-8") as _rf:
                        _rf.write(str(_now_bl))
                except Exception:
                    pass
                if _is_first_boot:
                    log_to_server("[BASELINE] 基准K线识别完成(启动首次)")
                else:
                    _gap_h = (_now_bl - _prev_bl) / 3600.0
                    log_to_server(f"[BASELINE] 基准K线识别完成(4h刷新, gap={_gap_h:.1f}h)")
        except Exception as _e_bl_sched:
            log_to_server(f"[BASELINE][SCHED][ERROR] {_e_bl_sched}")

        _baseline_scheduler_stop_event.wait(60)

def start_baseline_scheduler():
    global _baseline_scheduler_thread
    if not _BASELINE_SCHEDULER_ENABLED:
        return
    if _baseline_scheduler_thread is None or not _baseline_scheduler_thread.is_alive():
        _baseline_scheduler_stop_event.clear()
        _baseline_scheduler_thread = threading.Thread(
            target=_baseline_scheduler_worker,
            daemon=True,
            name="BaselineScheduler",
        )
        _baseline_scheduler_thread.start()
        try:
            log_to_server("[BASELINE][SCHED] 独立调度线程已启动")
        except Exception:
            pass

start_baseline_scheduler()

