def _brooks_confirm(symbol: str, vision_direction: str, tag: str) -> bool:
    """Brooks确认: Vision方向必须与Brooks信号一致才放行

    Args:
        symbol: 品种名 (TSLA / BTCUSDC)
        vision_direction: Vision判断的方向 "BUY"/"SELL"
        tag: 日志标签 (TSLA_OPT / BTC_PERP)
    Returns:
        True = Brooks同意, False = Brooks不同意或无数据
    """
    try:
        from brooks_vision import radar_scan
        bv_result = radar_scan(symbol, {})
        if not bv_result:
            log_to_server(f"[{tag}][BROOKS] {symbol} 无Brooks数据，跳过确认")
            return False
        bv_signal = bv_result.get("signal", "NONE")
        bv_conf = bv_result.get("confidence", 0)
        bv_pattern = bv_result.get("brooks_pattern", "NONE")
        if bv_signal == vision_direction:
            log_to_server(
                f"[{tag}][BROOKS] 确认通过: Vision={vision_direction} Brooks={bv_signal} "
                f"pattern={bv_pattern} conf={bv_conf}"
            )
            return True
        else:
            log_to_server(
                f"[{tag}][BROOKS] 方向不一致: Vision={vision_direction} Brooks={bv_signal} "
                f"pattern={bv_pattern} → 跳过"
            )
            return False
    except Exception as _e:
        log_to_server(f"[{tag}][BROOKS] 检查异常: {_e}")
        return False


def _volume_confirm(symbol: str, direction: str, tag: str) -> bool:
    """量价确认: VolumeAnalyzer检查量价关系, REJECT则拦截

    Returns:
        True = 量价放行(PASS/UPGRADE), False = 量价拒绝(REJECT/DOWNGRADE)
    """
    try:
        from models.volume_analyzer import VolumeAnalyzer
        bars = fetch_ohlcv_from_api(symbol, 240, limit=30)
        if not bars or len(bars) < 5:
            log_to_server(f"[{tag}][VOL] {symbol} OHLCV不足，跳过量价检查")
            return True  # 数据不足不拦截

        va = VolumeAnalyzer()
        vf_result = va.volume_filter(direction, bars)
        rel_vol = va.get_relative_volume(bars)
        sqs = va.get_signal_quality(bars, direction)

        log_to_server(
            f"[{tag}][VOL] {symbol} {direction}: filter={vf_result} "
            f"rel_vol={rel_vol:.2f} SQS={sqs:.2f}"
        )

        if vf_result == "REJECT":
            log_to_server(f"[{tag}][VOL] 极度缩量REJECT → 拦截")
            return False
        if vf_result == "DOWNGRADE" and sqs < 0.3:
            log_to_server(f"[{tag}][VOL] CVD背离+SQS={sqs:.2f}<0.3 → 拦截")
            return False
        return True
    except Exception as _e:
        log_to_server(f"[{tag}][VOL] 量价检查异常: {_e}")
        return True  # 异常不拦截


def _qqq_detect_trend() -> Optional[str]:
    """Vision(Claude RADAR_PROMPT V2) + Brooks + 量价 三重确认判断TSLA趋势

    v3.683: 升级为GCC-0262标注图+RADAR_PROMPT V2 (Brooks 5步分析框架)
    流程: 标注图生成 → Claude RADAR分析 → Brooks确认 → 量价确认 → 返回信号
    """
    try:
        bars = fetch_ohlcv_from_api("TSLA", 240, limit=50)
        if not bars or len(bars) < 15:
            log_to_server("[B2][TSLA-OPT][VISION] K线不足，跳过")
            return None

        # 1. 生成GCC-0262标注图 (Swing H/L + EMA9/21 + NOW标记)
        from vision_analyzer import generate_clean_chart, call_claude_vision, bars_to_dataframe
        from timeframe_params import read_symbol_timeframe, get_timeframe_params
        _tf = read_symbol_timeframe("TSLA", default=240)
        _params = get_timeframe_params(_tf, is_crypto=False)
        _current_label = _params["current_label"]

        chart_b64 = generate_clean_chart(bars, f"TSLA - Options Trend ({len(bars)} bars)", timeframe=_current_label)
        if not chart_b64:
            log_to_server("[B2][TSLA-OPT][VISION] 标注图生成失败，回退极简图")
            from vision_analyzer import generate_simple_trend_chart
            chart_b64 = generate_simple_trend_chart(bars[-30:], f"TSLA - {len(bars[-30:])} bars")
            if not chart_b64:
                return None
            # 回退时用老prompt
            _vision_mem_cache.pop("TSLA", None)
            result = read_vision_result("TSLA", ohlcv_bars=bars)
            if not result or not result.get("current"):
                return None
            current = result["current"]
            direction = current.get("direction", "").upper()
            confidence = current.get("confidence", 0)
            if confidence < 0.6:
                return None
            if direction in ("UP", "BULLISH"):
                vision_dir = "BUY"
            elif direction in ("DOWN", "BEARISH"):
                vision_dir = "SELL"
            else:
                return None
            log_to_server(f"[B2][TSLA-OPT][VISION] (回退) TSLA趋势={direction} conf={confidence:.0%}")
            if not _brooks_confirm("TSLA", vision_dir, "TSLA_OPT"):
                return None
            if not _volume_confirm("TSLA", vision_dir, "TSLA_OPT"):
                return None
            return vision_dir

        # 2. RADAR_PROMPT V2 + 动态swing距离注入
        from brooks_vision import RADAR_PROMPT
        prompt = RADAR_PROMPT

        _current_price = bars[-1].get("close", 0) if bars else 0
        if _current_price > 0:
            _df_tmp = bars_to_dataframe(bars)
            _nearest_sh, _nearest_sl = 0.0, 0.0
            if _df_tmp is not None and len(_df_tmp) >= 7:
                _hc, _lc = _df_tmp['High'].values, _df_tmp['Low'].values
                for i in range(3, len(_df_tmp) - 3):
                    if all(_hc[i] > _hc[i-j] for j in range(1, 4)) and all(_hc[i] > _hc[i+j] for j in range(1, 4)):
                        _nearest_sh = float(_hc[i])
                    if all(_lc[i] < _lc[i-j] for j in range(1, 4)) and all(_lc[i] < _lc[i+j] for j in range(1, 4)):
                        _nearest_sl = float(_lc[i])
            _user_ctx = f"\n\nChart: TSLA | Timeframe: {_current_label} | Current Price: {_current_price:.2f}"
            if _nearest_sh > 0:
                _sh_dist = (_nearest_sh - _current_price) / _current_price * 100
                _user_ctx += f"\nNearest Swing High (red dashed): {_nearest_sh:.2f} ({_sh_dist:+.2f}%)"
            if _nearest_sl > 0:
                _sl_dist = (_current_price - _nearest_sl) / _current_price * 100
                _user_ctx += f"\nNearest Swing Low (green dashed): {_nearest_sl:.2f} (-{_sl_dist:.2f}%)"
            _user_ctx += "\nPlease analyze the annotated chart and return the JSON assessment."
            prompt = prompt + _user_ctx

        # 3. 调用Claude Vision API (RADAR_PROMPT输出)
        log_to_server(f"[B2][TSLA-OPT][VISION] 调Claude RADAR V2分析TSLA趋势 ({_current_label})...")
        result = call_claude_vision(chart_b64, prompt, max_retries=2, expected_mode="trend", symbol="TSLA")

        if not result:
            log_to_server("[B2][TSLA-OPT][VISION] Claude RADAR返回空")
            return None

        # 4. 解析RADAR_PROMPT输出 (confidence 0-100整数, direction UP/DOWN/SIDE)
        direction = result.get("direction", "SIDE").upper()
        conf_raw = result.get("confidence", 0)
        try:
            conf_raw = float(conf_raw)
        except (TypeError, ValueError):
            conf_raw = 0
        confidence = conf_raw / 100.0 if conf_raw > 1.0 else conf_raw
        wait_signal = result.get("wait_signal", False)
        failed_breakout = result.get("failed_breakout", False)
        brooks_pattern = result.get("brooks_pattern", "NONE")
        market_structure = result.get("market_structure", "UNKNOWN")

        # wait_signal=true → Vision建议观望
        if wait_signal:
            log_to_server(f"[B2][TSLA-OPT][VISION] wait_signal=true, 观望 (conf={confidence:.0%} pattern={brooks_pattern})")
            return None

        if confidence < 0.6:
            log_to_server(f"[B2][TSLA-OPT][VISION] 置信度不足 {confidence:.0%}<60% (pattern={brooks_pattern})")
            return None

        if direction in ("UP",):
            vision_dir = "BUY"
        elif direction in ("DOWN",):
            vision_dir = "SELL"
        else:
            log_to_server(f"[B2][TSLA-OPT][VISION] direction=SIDE, 无方向")
            return None

        log_to_server(
            f"[B2][TSLA-OPT][VISION] TSLA趋势={direction} conf={confidence:.0%} "
            f"pattern={brooks_pattern} struct={market_structure} "
            f"failed_break={failed_breakout}"
        )

        # Brooks确认
        if not _brooks_confirm("TSLA", vision_dir, "TSLA_OPT"):
            return None

        # 量价确认
        if not _volume_confirm("TSLA", vision_dir, "TSLA_OPT"):
            return None

        return vision_dir
    except Exception as _e:
        log_to_server(f"[B2][TSLA-OPT][VISION] 调API异常: {_e}")
        return None

_qqq_vision_last_check = {"time": 0}  # Vision读取频率控制
_QQQ_VISION_INTERVAL = 3600  # 每1小时读一次Vision (美股盘中约6.5小时, 每天最多7次)

def _qqq_options_manager_worker():
    """后台线程: 盘中每5分钟循环

    进场: Vision(Claude RADAR V2) 每1小时检测TSLA趋势 → 开仓
    出场: 每5分钟检查4条出场规则 + Vision反转检测(每1小时)
    确认: 每5分钟确认pending_close订单是否FILLED

    v3.683: Vision升级为GCC-0262标注图+RADAR_PROMPT V2 (Brooks 5步分析)
    流程设计:
      - 进场调用一次Vision(Claude)判断方向 → 开仓
      - 出场调用一次Vision确认反转 → 平仓
      - 价格止盈/止损/时间止损不需要Vision
      - 反转时只平仓不立即开新仓(等pending_close确认后下轮再开)
    """
    import time as _t
    _t.sleep(60)  # 启动延迟1分钟
    while not _qqq_opt_stop.is_set():
        try:
            # 只在美股盘中运行 (9:30-15:50 ET, 留10分钟给平仓成交)
            _now_et = datetime.now(ZoneInfo("America/New_York"))
            _mkt_open = _now_et.replace(hour=9, minute=30, second=0)
            _mkt_close = _now_et.replace(hour=15, minute=50, second=0)
            _is_weekday = _now_et.weekday() < 5
            if _is_weekday and _mkt_open <= _now_et <= _mkt_close:
                from qqq_options import (
                    auto_manage as _qqq_auto, _load_position as _qqq_pos,
                    close_option as _qqq_close, check_pending_close as _qqq_check_pending,
                    place_option as _qqq_place, select_option as _qqq_select,
                    get_option_chain as _qqq_chain,
                )

                TSLA_OPTIONS_ENABLED = True  # 实盘已开启

                # ── (1) 确认平仓成交 ──────────────────────────────────
                pending_status = _qqq_check_pending()
                if pending_status == "PENDING":
                    _qqq_opt_stop.wait(_QQQ_OPT_CHECK_INTERVAL)
                    continue
                elif pending_status == "FAILED":
                    log_to_server("[B2][TSLA-OPT][AUTO] 平仓订单失败，恢复open等下轮重试")

                # GCC-0016 S0: 手工平仓检测 (每轮检查Schwab实际持仓)
                try:
                    from qqq_options import sync_manual_close as _qqq_sync
                    if _qqq_sync():
                        log_to_server("[B2][TSLA-OPT] 手工平仓检测: 已同步清除内部state")
                except Exception:
                    pass

                pos = _qqq_pos()

                # ── (2) 有仓: 检查出场 ────────────────────────────────
                if pos:
                    # 2a. 价格止盈/止损/时间止损 (每5分钟, 不需要Vision)
                    exit_result = _qqq_auto(dry_run=False)
                    if exit_result:
                        _exit_msg = (
                            f"[B2][TSLA-OPT][EXIT] {exit_result['action']}: {exit_result['reason']} "
                            f"PnL=${exit_result.get('pnl', 0):.0f} "
                            f"success={exit_result['result'].get('success')}"
                        )
                        log_to_server(_exit_msg)
                        try:
                            _opt_d2 = pos.get("option") or pos.get("spread") or {}
                            send_email_notification(
                                f"[TSLA期权] {exit_result['action']} PnL=${exit_result.get('pnl', 0):.0f}",
                                f"动作: {exit_result['action']}\n"
                                f"原因: {exit_result['reason']}\n"
                                f"PnL: ${exit_result.get('pnl', 0):.0f}\n"
                                f"合约: {_opt_d2.get('type','')} {_opt_d2.get('strike','')} "
                                f"x{_opt_d2.get('contracts','')}\n"
                                f"成功: {exit_result['result'].get('success')}"
                            )
                        except Exception:
                            pass
                    else:
                        # 2b. Vision反转检测 (每1小时)
                        _now_ts = _t.time()
                        if TSLA_OPTIONS_ENABLED and _now_ts - _qqq_vision_last_check["time"] >= _QQQ_VISION_INTERVAL:
                            _qqq_vision_last_check["time"] = _now_ts
                            vision_dir = _qqq_detect_trend()
                            if vision_dir:
                                _opt_d = pos.get("option") or pos.get("spread") or {}
                                opt_type = _opt_d.get("type", "")
                                is_reversal = (
                                    (vision_dir == "SELL" and opt_type in ("CALL", "BULL_CALL")) or
                                    (vision_dir == "BUY" and opt_type in ("PUT", "BEAR_PUT"))
                                )
                                if is_reversal:
                                    _rev_msg = (
                                        f"[B2][TSLA-OPT][REVERSAL] Vision={vision_dir} 但持仓={opt_type}"
                                        f" → 平仓(下轮再开新方向)"
                                    )
                                    log_to_server(_rev_msg)
                                    # 写入exit信息供交易历史记录
                                    from qqq_options import STATE_FILE as _qsf, _position_lock as _qpl
                                    try:
                                        with _qpl:
                                            _qd = json.loads(_qsf.read_text(encoding="utf-8"))
                                            _qd["exit_action"] = "REVERSAL"
                                            _qd["exit_reason"] = f"Vision={vision_dir} 反转 {opt_type}"
                                            _qsf.write_text(json.dumps(_qd, indent=2, ensure_ascii=False), encoding="utf-8")
                                    except Exception:
                                        pass
                                    _qqq_close(_opt_d, dry_run=False, market_order=True)
                                    try:
                                        send_email_notification(
                                            f"[TSLA期权] 反转平仓 {opt_type}→{vision_dir}",
                                            f"Vision检测到趋势反转\n"
                                            f"原持仓: {opt_type} {_opt_d.get('strike','')} "
                                            f"x{_opt_d.get('contracts','')}\n"
                                            f"Vision方向: {vision_dir}\n"
                                            f"动作: 全部平仓"
                                        )
                                    except Exception:
                                        pass
                                    # 不立即开新仓! 等pending_close确认后下轮step(3)开

                # ── (3) 无仓: 检查进场 ────────────────────────────────
                elif TSLA_OPTIONS_ENABLED:
                    _now_ts = _t.time()
                    if _now_ts - _qqq_vision_last_check["time"] >= _QQQ_VISION_INTERVAL:
                        _qqq_vision_last_check["time"] = _now_ts
                        direction = _qqq_detect_trend()
                        if direction:
                            # 信号去重: 同方向30分钟内不重复
                            if (direction != _qqq_last_signal["direction"] or
                                    _now_ts - _qqq_last_signal["time"] > 1800):
                                log_to_server(f"[B2][TSLA-OPT][ENTRY] Vision={direction}，开始选期权开仓")
                                chain = _qqq_chain()
                                if chain:
                                    opt = _qqq_select(direction, chain)
                                    if opt:
                                        result = _qqq_place(opt, dry_run=False)
                                        _entry_msg = (
                                            f"[B2][TSLA-OPT][ENTRY] {opt['type']} "
                                            f"{opt['strike']} "
                                            f"x{opt['contracts']} cost=${opt['total_cost']:.0f} "
                                            f"success={result.get('success')}"
                                        )
                                        log_to_server(_entry_msg)
                                        try:
                                            send_email_notification(
                                                f"[TSLA期权] 开仓 {opt['type']} {opt['strike']}",
                                                f"方向: {direction}\n"
                                                f"合约: {opt['type']} Strike={opt['strike']} "
                                                f"DTE={opt.get('dte','?')}\n"
                                                f"数量: x{opt['contracts']}\n"
                                                f"成本: ${opt['total_cost']:.0f}\n"
                                                f"Delta: {opt.get('delta','?')}\n"
                                                f"成功: {result.get('success')}"
                                            )
                                        except Exception:
                                            pass
                                        _qqq_last_signal["direction"] = direction
                                        _qqq_last_signal["time"] = _now_ts

        except Exception as _e_qqq:
            log_to_server(f"[B2][TSLA-OPT][AUTO][ERROR] {_e_qqq}")
        _qqq_opt_stop.wait(_QQQ_OPT_CHECK_INTERVAL)

def _start_qqq_options_manager():
    global _qqq_opt_thread
    if _qqq_opt_thread is None or not _qqq_opt_thread.is_alive():
        _qqq_opt_stop.clear()
        _qqq_opt_thread = threading.Thread(
            target=_qqq_options_manager_worker,
            daemon=True,
            name="TSLAOptionsManager",
        )
        _qqq_opt_thread.start()
        log_to_server("[B2][TSLA-OPT] 自动管理线程已启动 (每5分钟检查持仓出场规则)")

_start_qqq_options_manager()

